window.bibleReaderData = window.bibleReaderData || {chapters:{}};
window.bibleReaderData.chapters = window.bibleReaderData.chapters || {};
(function(chapters){ for (const b in chapters){ window.bibleReaderData.chapters[b]=window.bibleReaderData.chapters[b]||{}; for (const c in chapters[b]){ window.bibleReaderData.chapters[b][c]=window.bibleReaderData.chapters[b][c]||{}; Object.assign(window.bibleReaderData.chapters[b][c], chapters[b][c]); } } })({"MAT":{"1":{"hr":[{"v":1,"t":"Rodoslovlje Isusa Krista, sina Davidova, sina Abrahamova."},{"v":2,"t":"Abrahamu se rodi Izak. Izaku se rodi Jakov. Jakovu se rodi Juda i njegova braća."},{"v":3,"t":"Judi Tamara rodi Peresa i Zeraha. Peresu se rodi Hesron. Hesronu se rodi Ram."},{"v":4,"t":"Ramu se rodi Aminadab. Aminadabu se rodi Nahšon. Nahšonu se rodi Salma."},{"v":5,"t":"Salmi Rahaba rodi Boaza. Boazu Ruta rodi Obeda. Obedu se rodi Jišaj."},{"v":6,"t":"Jišaju se rodi David kralj. Davidu bivša žena Urijina rodi Salomona."},{"v":7,"t":"Salomonu se rodi Roboam. Roboamu se rodi Abija. Abiji se rodi Asa."},{"v":8,"t":"Asi se rodi Jozafat. Jozafatu se rodi Joram. Joramu se rodi Ahazja."},{"v":9,"t":"Ahazji se rodi Jotam. Jotamu se rodi Ahaz. Ahazu se rodi Ezekija."},{"v":10,"t":"Ezekiji se rodi Manaše. Manašeu se rodi Amon. Amonu se rodi Jošija."},{"v":11,"t":"Jošiji se rodi Jehonija i njegova braća u vrijeme progonstva u Babilon."},{"v":12,"t":"Poslije progonstva u Babilon Jehoniji se rodi Šealtiel. Šealtielu se rodi Zerubabel."},{"v":13,"t":"Zerubabelu se rodi Abiud. Abiudu se rodi Elijakim. Elijakimu se rodi Azor."},{"v":14,"t":"Azoru se rodi Sadok. Sadoku se rodi Akim. Akimu se rodi Elijud."},{"v":15,"t":"Elijudu se rodi Eleazar. Eleazaru se rodi Matan. Matanu se rodi Jakov."},{"v":16,"t":"Jakovu se rodi Josip, muž Marije, od koje se rodio Isus koji se zove Krist."},{"v":17,"t":"U svemu dakle: od Abrahama do Davida četrnaest naraštaja; od Davida do progonstva u Babilon četrnaest naraštaja; poslije progonstva u Babilon do Krista četrnaest naraštaja."},{"v":18,"t":"A rođenje Isusa Krista zbilo se ovako. Njegova majka Marija, zaručena s Josipom, prije nego se sastadoše, nađe se trudna po Duhu Svetom."},{"v":19,"t":"A Josip, muž njezin, pravedan, ne htjede je izvrgnuti sramoti, nego naumi da je potajice napusti."},{"v":20,"t":"Dok je on to snovao, gle, anđeo mu se Gospodnji ukaza u snu i reče: “Josipe, sine Davidov, ne boj se uzeti k sebi Mariju, ženu svoju. Što je u njoj začeto, doista je od Duha Svetoga."},{"v":21,"t":"Rodit će sina, a ti ćeš mu nadjenuti ime Isus jer će on spasiti narod svoj od grijeha njegovih.”"},{"v":22,"t":"Sve se to dogodilo da se ispuni što Gospodin reče po proroku:"},{"v":23,"t":"Evo, Djevica će začeti i roditi sina i nadjenut će mu se ime Emanuel - što znači: S nama Bog!"},{"v":24,"t":"Kad se Josip probudi oda sna, učini kako mu naredi anđeo Gospodnji: uze k sebi svoju ženu."},{"v":25,"t":"I ne upozna je dok ne rodi sina. I nadjenu mu ime Isus."}]},"2":{"hr":[{"v":1,"t":"Kad se Isus rodio u Betlehemu judejskome u dane Heroda kralja, gle, mudraci se s Istoka pojaviše u Jeruzalemu"},{"v":2,"t":"raspitujući se: “Gdje je taj novorođeni kralj židovski? Vidjesmo gdje izlazi zvijezda njegova pa mu se dođosmo pokloniti.”"},{"v":3,"t":"Kada to doču kralj Herod, uznemiri se on i sav Jeruzalem s njime."},{"v":4,"t":"Sazva sve glavare svećeničke i pismoznance narodne pa ih ispitivaše gdje se Krist ima roditi."},{"v":5,"t":"Oni mu odgovoriše: “U Betlehemu judejskome jer ovako piše prorok:"},{"v":6,"t":"A ti, Betleheme, zemljo Judina! Nipošto nisi najmanji među kneževstvima Judinim jer iz tebe će izaći vladalac koji će pasti narod moj - Izraela!"},{"v":7,"t":"Tada Herod potajno dozva mudrace i razazna od njih vrijeme kad se pojavila zvijezda."},{"v":8,"t":"Zatim ih posla u Betlehem: “Pođite, reče, i pomno se raspitajte za dijete. Kad ga nađete, javite mi da i ja pođem te mu se poklonim.”"},{"v":9,"t":"Oni saslušavši kralja, pođoše. I gle, zvijezda kojoj vidješe izlazak iđaše pred njima sve dok ne stiže i zaustavi se povrh mjesta gdje bijaše dijete."},{"v":10,"t":"Kad ugledaše zvijezdu, obradovaše se radošću veoma velikom."},{"v":11,"t":"Uđu u kuću, ugledaju dijete s Marijom, majkom njegovom, padnu ničice i poklone mu se. Otvore zatim svoje blago i prinesu mu darove: zlato, tamjan i smirnu."},{"v":12,"t":"Upućeni zatim u snu da se ne vraćaju Herodu, otiđoše drugim putem u svoju zemlju."},{"v":13,"t":"A pošto oni otiđoše, gle, anđeo se Gospodnji u snu javi Josipu: “Ustani, reče, uzmi dijete i majku njegovu te bježi u Egipat i ostani ondje dok ti ne reknem jer će Herod tražiti dijete da ga pogubi."},{"v":14,"t":"On ustane, uzme noću dijete i majku njegovu te krene u Egipat."},{"v":15,"t":"I osta ondje do Herodova skončanja - da se ispuni što Gospodin reče po proroku: Iz Egipta dozvah Sina svoga."},{"v":16,"t":"Vidjevši da su ga mudraci izigrali, Herod se silno rasrdi i posla poubijati sve dječake u Betlehemu i po svoj okolici, od dvije godine naniže - prema vremenu što ga razazna od mudraca."},{"v":17,"t":"Tada se ispuni što je rečeno po proroku Jeremiji:"},{"v":18,"t":"U Rami se glas čuje, kuknjava i plač gorak: Rahela oplakuje sinove svoje i neće da se utješi jer više ih nema."},{"v":19,"t":"Nakon Herodova skončanja, gle, anđeo se Gospodnji javi u snu Josipu u Egiptu:"},{"v":20,"t":"“Ustani, reče, uzmi dijete i njegovu majku te pođi u zemlju izraelsku jer su umrli oni koji su djetetu o glavi radili.”"},{"v":21,"t":"On ustane, uzme dijete i njegovu majku te uđe u zemlju izraelsku."},{"v":22,"t":"Ali saznavši da Arhelaj vlada Judejom namjesto svoga oca Heroda, bojao se poći onamo pa, upućen u snu, ode u kraj galilejski."},{"v":23,"t":"Dođe i nastani se u gradu zvanu Nazaret - da se ispuni što je rečeno po prorocima: Zvat će se Nazarećanin."}]},"3":{"hr":[{"v":1,"t":"U one dane pojavi se Ivan Krstitelj propovijedajući u Judejskoj pustinji:"},{"v":2,"t":"“Obratite se jer približilo se kraljevstvo nebesko!”"},{"v":3,"t":"Ovo je uistinu onaj o kom proreče Izaija prorok: Glas viče u pustinji: Pripravite put Gospodinu, poravnite mu staze!"},{"v":4,"t":"Ivan je imao odjeću od devine dlake i kožnat pojas oko bokova; hranom mu bijahu skakavci i divlji med."},{"v":5,"t":"Grnuo k njemu Jeruzalem, sva Judeja i sva okolica jordanska."},{"v":6,"t":"Primali su od njega krštenje u rijeci Jordanu ispovijedajući svoje grijehe."},{"v":7,"t":"Kad ugleda mnoge farizeje i saduceje gdje mu dolaze na krštenje, reče im: “Leglo gujinje! Tko li vas je samo upozorio da bježite od skore srdžbe?"},{"v":8,"t":"Donosite dakle plod dostojan obraćenja."},{"v":9,"t":"I ne usudite se govoriti u sebi: 'Imamo oca Abrahama!' Jer, kažem vam, Bog iz ovoga kamenja može podići djecu Abrahamovu."},{"v":10,"t":"Već je sjekira položena na korijen stablima. Svako dakle stablo koje ne donosi dobroga roda, siječe se i u oganj baca.”"},{"v":11,"t":"“Ja vas, istina, krstim vodom na obraćenje, ali onaj koji za mnom dolazi jači je od mene. Ja nisam dostojan obuće mu nositi. On će vas krstiti Duhom Svetim i ognjem."},{"v":12,"t":"U ruci mu vijača, pročistit će svoje gumno i skupiti žito u svoju žitnicu, a pljevu spaliti ognjem neugasivim.”"},{"v":13,"t":"Tada dođe Isus iz Galileje na Jordan Ivanu da ga on krsti."},{"v":14,"t":"Ivan ga odvraćaše: “Ti mene treba da krstiš, a ti da k meni dolaziš?”"},{"v":15,"t":"Ali mu Isus odgovori: “Pusti sada! Ta dolikuje nam da tako ispunimo svu pravednost!” Tada mu popusti."},{"v":16,"t":"Odmah nakon krštenja izađe Isus iz vode. I gle! Otvoriše se nebesa i ugleda Duha Božjega gdje silazi kao golub i spušta se na nj."},{"v":17,"t":"I eto glasa s neba: “Ovo je Sin moj, Ljubljeni! U njemu mi sva milina!”"}]},"4":{"hr":[{"v":1,"t":"Duh tada odvede Isusa u pustinju da ga đavao iskuša."},{"v":2,"t":"I propostivši četrdeset dana i četrdeset noći, napokon ogladnje."},{"v":3,"t":"Tada mu pristupi napasnik i reče: “Ako si Sin Božji, reci da ovo kamenje postane kruhom.”"},{"v":4,"t":"A on odgovori: “Pisano je: Ne živi čovjek samo o kruhu, nego o svakoj riječi što izlazi iz Božjih usta.”"},{"v":5,"t":"Ðavao ga tada povede u Sveti grad, postavi ga na vrh Hrama"},{"v":6,"t":"i reče mu: “Ako si Sin Božji, baci se dolje! Ta pisano je: Anđelima će svojim zapovjediti za tebe i na rukama će te nositi da se gdje nogom ne spotakneš o kamen.”"},{"v":7,"t":"Isus mu kaza: “Pisano je također: Ne iskušavaj Gospodina, Boga svojega!”"},{"v":8,"t":"Ðavao ga onda povede na goru vrlo visoku i pokaza mu sva kraljevstva svijeta i slavu njihovu"},{"v":9,"t":"pa mu reče: “Sve ću ti to dati ako mi se ničice pokloniš.”"},{"v":10,"t":"Tada mu reče Isus: “Odlazi, Sotono! Ta pisano je: Gospodinu, Bogu svom se klanjaj i njemu jedinom služi!”"},{"v":11,"t":"Tada ga pusti đavao. I gle, anđeli pristupili i služili mu."},{"v":12,"t":"A čuvši da je Ivan predan, povuče se u Galileju."},{"v":13,"t":"Ostavi Nazaret te ode i nastani se u Kafarnaumu, uz more, na području Zebulunovu i Naftalijevu"},{"v":14,"t":"da se ispuni što je rečeno po proroku Izaiji:"},{"v":15,"t":"Zemlja Zebulunova i zemlja Naftalijeva, Put uz more, s one strane Jordana, Galileja poganska -"},{"v":16,"t":"narod što je sjedio u tmini svjetlost vidje veliku; onima što mrkli kraj smrti obitavahu svjetlost jarka osvanu."},{"v":17,"t":"Otada je Isus počeo propovijedati: “Obratite se jer približilo se kraljevstvo nebesko!”"},{"v":18,"t":"Prolazeći uz Galilejsko more, ugleda dva brata, Šimuna zvanog Petar i brata mu Andriju, gdje bacaju mrežu u more; bijahu ribari."},{"v":19,"t":"I kaže im: “Hajdete za mnom, učinit ću vas ribarima ljudi!”"},{"v":20,"t":"Oni brzo ostave mreže i pođu za njim."},{"v":21,"t":"Pošavši odande, ugleda druga dva brata, Jakova Zebedejeva i brata mu Ivana: u lađi su sa Zebedejem, ocem svojim, krpali mreže. Pozva i njih."},{"v":22,"t":"Oni brzo ostave lađu i oca te pođu za njim."},{"v":23,"t":"I obilazio je Isus svom Galilejom naučavajući po njihovim sinagogama, propovijedajući Evanđelje o Kraljevstvu i liječeći svaku bolest i svaku nemoć u narodu."},{"v":24,"t":"I glas se o njemu pronese svom Sirijom. I donosili su mu sve koji bolovahu od najrazličitijih bolesti i patnja - opsjednute, mjesečare, uzete - i on ih ozdravljaše."},{"v":25,"t":"Za njim je pohrlio silan svijet iz Galileje, Dekapola, Jeruzalema, Judeje i Transjordanije."}]},"5":{"hr":[{"v":1,"t":"Ugledavši mnoštvo, uziđe na goru. I kad sjede, pristupe mu učenici."},{"v":2,"t":"On progovori i stane ih naučavati:"},{"v":3,"t":"“Blago siromasima duhom: njihovo je kraljevstvo nebesko!"},{"v":4,"t":"Blago ožalošćenima: oni će se utješiti!"},{"v":5,"t":"Blago krotkima: oni će baštiniti zemlju!"},{"v":6,"t":"Blago gladnima i žednima pravednosti: oni će se nasititi!"},{"v":7,"t":"Blago milosrdnima: oni će zadobiti milosrđe!"},{"v":8,"t":"Blago čistima srcem: oni će Boga gledati!"},{"v":9,"t":"Blago mirotvorcima: oni će se sinovima Božjim zvati!"},{"v":10,"t":"Blago progonjenima zbog pravednosti: njihovo je kraljevstvo nebesko!”"},{"v":11,"t":"“Blago vama kad vas - zbog mene - pogrde i prognaju i sve zlo slažu protiv vas!"},{"v":12,"t":"Radujte se i kličite: velika je plaća vaša na nebesima! Ta progonili su tako proroke prije vas!”"},{"v":13,"t":"“Vi ste sol zemlje. Ali ako sol obljutavi, čime će se ona osoliti? Nije više ni za što, nego da se baci van i da ljudi po njoj gaze.”"},{"v":14,"t":"“Vi ste svjetlost svijeta. Ne može se sakriti grad što leži na gori."},{"v":15,"t":"Niti se užiže svjetiljka da se stavi pod posudu, nego na svijećnjak da svijetli svima u kući."},{"v":16,"t":"Tako neka svijetli vaša svjetlost pred ljudima da vide vaša dobra djela i slave Oca vašega koji je na nebesima.”"},{"v":17,"t":"“Ne mislite da sam došao ukinuti Zakon ili Proroke. Nisam došao ukinuti, nego ispuniti."},{"v":18,"t":"Zaista, kažem vam, dok ne prođe nebo i zemlja, ne, ni jedno slovce, ni jedan potezić iz Zakona neće proći, dok se sve ne zbude."},{"v":19,"t":"Tko dakle ukine jednu od tih, pa i najmanjih zapovijedi i tako nauči ljude, najmanji će biti u kraljevstvu nebeskom. A tko ih bude vršio i druge učio, taj će biti velik u kraljevstvu nebeskom.”"},{"v":20,"t":"“Uistinu kažem vam: ne bude li pravednost vaša veća od pravednosti pismoznanaca i farizeja, ne, nećete ući u kraljevstvo nebesko.”"},{"v":21,"t":"“Čuli ste da je rečeno starima: Ne ubij! Tko ubije, bit će podvrgnut sudu."},{"v":22,"t":"A ja vam kažem: Svaki koji se srdi na brata svoga, bit će podvrgnut sudu. A tko bratu rekne 'Glupane!', bit će podvrgnut Vijeću. A tko reče: 'Luđače!', bit će podvrgnut ognju paklenomu.”"},{"v":23,"t":"“Ako dakle prinosiš dar na žrtvenik pa se ondje sjetiš da tvoj brat ima nešto protiv tebe,"},{"v":24,"t":"ostavi dar ondje pred žrtvenikom, idi i najprije se izmiri s bratom, a onda dođi i prinesi dar.”"},{"v":25,"t":"“Nagodi se brzo s protivnikom dok si još s njim na putu, da te protivnik ne preda sucu, a sudac tamničaru, pa da te ne bace u tamnicu."},{"v":26,"t":"Zaita, kažem ti, nećeš izići odande dok ne isplatiš do posljednjeg novčića.”"},{"v":27,"t":"“Čuli ste da je rečeno: Ne čini preljuba!"},{"v":28,"t":"A ja vam kažem: Tko god s požudom pogleda ženu, već je s njome učinio preljub u srcu."},{"v":29,"t":"Ako te desno oko sablažnjava, iskopaj ga i baci od sebe. Ta bolje je da ti propadne jedan od udova, nego da ti cijelo tijelo bude bačeno u pakao."},{"v":30,"t":"Ako te desnica tvoja sablažnjava, odsijeci je i baci od sebe. Ta bolje je da ti propadne jedan od udova, nego da ti cijelo tijelo ode u pakao.”"},{"v":31,"t":"“Rečeno je također: Tko otpusti svoju ženu, neka joj dade otpusnicu."},{"v":32,"t":"A ja vam kažem: Tko god otpusti svoju ženu - osim zbog bludništva - navodi je na preljub i tko se god otpuštenom oženi, čini preljub.”"},{"v":33,"t":"“Čuli ste još da je rečeno starima: Ne zaklinji se krivo, nego izvrši Gospodinu svoje zakletve."},{"v":34,"t":"A ja vam kažem: Ne kunite se nikako! Ni nebom jer je prijestolje Božje."},{"v":35,"t":"Ni zemljom jer je podnožje njegovim nogama. Ni Jeruzalemom jer grad je Kralja velikoga!"},{"v":36,"t":"Ni svojom se glavom ne zaklinji jer ni jedne vlasi ne možeš učiniti bijelom ili crnom."},{"v":37,"t":"Vaša riječ neka bude: 'Da, da, - ne, ne!' Što je više od toga, od Zloga je.”"},{"v":38,"t":"“Čuli ste da je rečeno: Oko za oko, zub za zub!"},{"v":39,"t":"A ja vam kažem: Ne opirite se Zlomu! Naprotiv, pljusne li te tko po desnom obrazu, okreni mu i drugi."},{"v":40,"t":"Onomu tko bi se htio s tobom parničiti da bi se domogao tvoje donje haljine prepusti i gornju."},{"v":41,"t":"Ako te tko prisili jednu milju, pođi s njim dvije."},{"v":42,"t":"Tko od tebe što zaište, podaj mu! I ne okreni se od onoga koji hoće da mu pozajmiš.”"},{"v":43,"t":"“Čuli ste da je rečeno: Ljubi svoga bližnjega, a mrzi neprijatelja."},{"v":44,"t":"A ja vam kažem: Ljubite neprijatelje, molite za one koji vas progone"},{"v":45,"t":"da budete sinovi svoga oca koji je na nebesima, jer on daje da sunce njegovo izlazi nad zlima i dobrima i da kiša pada pravednicima i nepravednicima."},{"v":46,"t":"Jer ako ljubite one koji vas ljube, kakva li vam plaća? Zar to isto ne čine i carinici?"},{"v":47,"t":"I ako pozdravljate samo braću, što osobito činite? Zar to isto ne čine i pogani?”"},{"v":48,"t":"“Budite dakle savršeni kao što je savršen Otac vaš nebeski!”"}]},"6":{"hr":[{"v":1,"t":"“Pazite da svoje pravednosti ne činite pred ljudima da vas oni vide. Inače, nema vam plaće u vašeg Oca koji je na nebesima."},{"v":2,"t":"Kada dakle dijeliš milostinju, ne trubi pred sobom, kako to u sinagogama i na ulicama čine licemjeri da bi ih ljudi hvalili. Zaista, kažem vam, primili su svoju plaću."},{"v":3,"t":"Ti naprotiv, kada daješ milostinju - neka ti ne zna ljevica što čini desnica,"},{"v":4,"t":"da tvoja milostinja bude u skrovitosti. I Otac tvoj, koji vidi u skrovitosti, uzvratit će ti!”"},{"v":5,"t":"“Tako i kad molite, ne budite kao licemjeri. Vole moliti stojeći u sinagogama i na raskršćima ulica da se pokažu ljudima. Zaista, kažem vam, primili su svoju plaću."},{"v":6,"t":"Ti naprotiv, kad moliš, uđi u svoju sobu, zatvori vrata i pomoli se svomu Ocu, koji je u skrovitosti. I Otac tvoj, koji vidi u skrovitosti, uzvratit će ti.”"},{"v":7,"t":"“Kad molite, ne blebećite kao pogani. Misle da će s mnoštva riječi biti uslišani."},{"v":8,"t":"Ne nalikujte na njih. Ta zna vaš Otac što vam treba i prije negoli ga zaištete."},{"v":9,"t":"Vi, dakle, ovako molite: 'Oče naš, koji jesi na nebesima! Sveti se ime tvoje!"},{"v":10,"t":"Dođi kraljevstvo tvoje! Budi volja tvoja kako na nebu tako i na zemlji!"},{"v":11,"t":"Kruh naš svagdanji daj nam danas!"},{"v":12,"t":"I opusti nam duge naše kako i mi otpustismo dužnicima svojim!"},{"v":13,"t":"I ne uvedi nas u napast, nego izbavi nas od Zloga!'”"},{"v":14,"t":"“Doista, ako vi otpustite ljudima njihove prijestupke, otpustit će i vama Otac vaš nebeski."},{"v":15,"t":"Ako li vi ne otpustite ljudima, ni Otac vaš neće otpustiti vaših prijestupaka.”"},{"v":16,"t":"“I kad postite, ne budite smrknuti kao licemjeri. Izobličuju lica da pokažu ljudima kako poste. Zaista, kažem vam, primili su svoju plaću."},{"v":17,"t":"Ti naprotiv, kad postiš, pomaži glavu i umij lice"},{"v":18,"t":"da ne zapaze ljudi kako postiš, nego Otac tvoj, koji je u skrovitosti. I Otac tvoj, koji vidi u skrovitosti, uzvratit će ti.”"},{"v":19,"t":"“Ne zgrćite sebi blago na zemlji, gdje ga moljac i rđa nagrizaju i gdje ga kradljivci potkapaju i kradu."},{"v":20,"t":"Zgrćite sebi blago na nebu, gdje ga ni moljac ni rđa ne nagrizaju i gdje kradljivci ne potkapaju niti kradu."},{"v":21,"t":"Doista, gdje ti je blago, ondje će ti biti i srce.”"},{"v":22,"t":"“Oko je tijelu svjetiljka. Ako ti je dakle oko bistro, sve će tijelo tvoje biti svijetlo."},{"v":23,"t":"Ako ti je pak oko nevaljalo, sve će tijelo tvoje biti tamno. Ako je dakle svjetlost koja je u tebi - tamna, kolika će istom tama biti?”"},{"v":24,"t":"“Nitko ne može služiti dvojici gospodara. Ili će jednoga mrziti, a drugoga ljubiti; ili će uz jednoga prianjati, a drugoga prezirati. Ne možete služiti Bogu i bogatstvu.”"},{"v":25,"t":"“Zato vam kažem: Ne budite zabrinuti za život svoj: što ćete jesti, što ćete piti; ni za tijelo svoje: u što ćete se obući. Zar život nije vredniji od jela i tijelo od odijela?”"},{"v":26,"t":"“Pogledajte ptice nebeske! Ne siju, ne žanju niti sabiru u žitnice, pa ipak ih hrani vaš nebeski Otac. Zar niste vi vredniji od njih?"},{"v":27,"t":"A tko od vas zabrinutošću može svome stasu dodati jedan lakat?"},{"v":28,"t":"I za odijelo što ste zabrinuti? Promotrite poljske ljiljane, kako rastu! Ne muče se niti predu."},{"v":29,"t":"A kažem vam: ni Salomon se u svoj svojoj slavi ne zaodjenu kao jedan od njih."},{"v":30,"t":"Pa ako travu poljsku, koja danas jest a sutra se u peć baca, Bog tako odijeva, neće li još više vas, malovjerni?”"},{"v":31,"t":"“Nemojte dakle zabrinuto govoriti: 'Što ćemo jesti?' ili: 'Što ćemo piti?' ili: 'U što ćemo se obući?'"},{"v":32,"t":"Ta sve to pogani ištu. Zna Otac vaš nebeski da vam je sve to potrebno."},{"v":33,"t":"Tražite stoga najprije Kraljevstvo i pravednost njegovu, a sve će vam se ostalo dodati."},{"v":34,"t":"Ne budite dakle zabrinuti za sutra. Sutra će se samo brinuti za se. Dosta je svakom danu zla njegova.”"}]},"7":{"hr":[{"v":1,"t":"“Ne sudite da ne budete suđeni!"},{"v":2,"t":"Jer sudom kojim sudite bit ćete suđeni. I mjerom kojom mjerite mjerit će vam se."},{"v":3,"t":"Što gledaš trun u oku brata svojega, a brvna u oku svome ne opažaš?"},{"v":4,"t":"Ili kako možeš reći bratu svomu: 'De da ti izvadim trun iz oka', a eto brvna u oku tvom?"},{"v":5,"t":"Licemjere, izvadi najprije brvno iz oka svoga pa ćeš onda dobro vidjeti izvaditi trun iz oka bratova!”"},{"v":6,"t":"“Ne dajte svetinje psima! Niti svoga biserja bacajte pred svinje da ga ne pogaze nogama pa se okrenu i rastrgaju vas.”"},{"v":7,"t":"“Ištite i dat će vam se! Tražite i naći ćete! Kucajte i otvorit će vam se!"},{"v":8,"t":"Doista, tko god ište, prima; i tko traži, nalazi; i onomu koji kuca otvorit će se."},{"v":9,"t":"Ta ima li koga među vama da bi svojemu sinu, ako ga zaište kruha, kamen dao?"},{"v":10,"t":"Ili ako ribu zaište, zar će mu zmiju dati?"},{"v":11,"t":"Ako dakle vi, iako zli, znate dobrim darima darivati djecu svoju, koliko li će više Otac vaš, koji je na nebesima, dobrima obdariti one koji ga zaištu!”"},{"v":12,"t":"“Sve, dakle, što želite da ljudi vama čine, činite i vi njima. To je, doista, Zakon i Proroci.”"},{"v":13,"t":"“Uđite na uska vrata! Jer široka su vrata i prostran put koji vodi u propast i mnogo ih je koji njime idu."},{"v":14,"t":"O kako su uska vrata i tijesan put koji vodi u Život i malo ih je koji ga nalaze!”"},{"v":15,"t":"“Čuvajte se lažnih proroka koji dolaze k vama u ovčjem odijelu, a iznutra su vuci grabežljivi."},{"v":16,"t":"Po njihovim ćete ih plodovima prepoznati. Bere li se s trnja grožđe ili s bodljike smokve?"},{"v":17,"t":"Tako svako dobro stablo rađa dobrim plodovima, a nevaljalo stablo rađa plodovima zlim."},{"v":18,"t":"Ne može dobro stablo donijeti zlih plodova niti nevaljalo stablo dobrih plodova."},{"v":19,"t":"Svako stablo koje ne rađa dobrim plodom siječe se i u oganj baca."},{"v":20,"t":"Dakle: po plodovima ćete ih njihovim prepoznati.”"},{"v":21,"t":"“Neće u kraljevstvo nebesko ući svaki koji mi govori: 'Gospodine, Gospodine!', nego onaj koji vrši volju Oca mojega, koji je na nebesima."},{"v":22,"t":"Mnogi će me u onaj dan pitati: 'Gospodine, Gospodine! Nismo li mi u tvoje ime prorokovali, u tvoje ime đavle izgonili, u tvoje ime mnoga čudesa činili?'"},{"v":23,"t":"Tada ću im kazati: 'Nikad vas nisam poznavao! Nosite se od mene, vi bezakonici!'”"},{"v":24,"t":"“Stoga, tko god sluša ove moje riječi i izvršava ih, bit će kao mudar čovjek koji sagradi kuću na stijeni."},{"v":25,"t":"Zapljušti kiša, navale bujice, duhnu vjetrovi i sruče se na tu kuću, ali ona ne pada. Jer - utemeljena je na stijeni.”"},{"v":26,"t":"“Naprotiv, tko god sluša ove moje riječi, a ne vrši ih, bit će kao lud čovjek koji sagradi kuću na pijesku."},{"v":27,"t":"Zapljušti kiša, navale bujice, duhnu vjetrovi i sruče se na tu kuću i ona se sruši. I bijaše to ruševina velika.”"},{"v":28,"t":"Kad Isus završi ove svoje besjede, mnoštvo osta zaneseno njegovim naukom."},{"v":29,"t":"Ta učio ih kao onaj koji ima vlast, a ne kao njihovi pismoznanci."}]},"8":{"hr":[{"v":1,"t":"Kad je Isus sišao s gore, pohrli za njim silan svijet."},{"v":2,"t":"I gle, pristupi neki gubavac, pokloni mu se do zemlje i reče: “Gospodine, ako hoćeš, možeš me očistiti.”"},{"v":3,"t":"Isus pruži ruku i dotakne ga se govoreći: “Hoću, očisti se!” I odmah se očisti od gube."},{"v":4,"t":"Kaže mu Isus: “Pazi, nikomu ne kazuj, nego idi, pokaži se svećeniku i prinesi dar što ga propisa Mojsije, njima za svjedočanstvo.”"},{"v":5,"t":"Kad uđe u Kafarnaum, pristupi mu satnik pa ga zamoli:"},{"v":6,"t":"“Gospodine, sluga mi leži kod kuće uzet, u strašnim mukama.”"},{"v":7,"t":"Kaže mu: “Ja ću doći izliječiti ga.”"},{"v":8,"t":"Odgovori satnik: “Gospodine, nisam dostojan da uđeš pod krov moj, nego samo reci riječ i izliječen će biti sluga moj."},{"v":9,"t":"Ta i ja, premda sam čovjek pod vlašću, imam pod sobom vojnike pa reknem jednomu: 'Idi!' - i ode, drugomu: 'Dođi!' - i dođe, a sluzi svomu: 'Učini to' - i učini.”"},{"v":10,"t":"Čuvši to, zadivi se Isus i reče onima koji su išli za njim: “Zaista, kažem vam, ni u koga u Izraelu ne nađoh tolike vjere."},{"v":11,"t":"A kažem vam: Mnogi će s istoka i zapada doći i sjesti za stol s Abrahamom, Izakom i Jakovom u kraljevstvu nebeskom,"},{"v":12,"t":"a sinovi će kraljevstva biti izbačeni van u tamu. Ondje će biti plač i škrgut zubi.”"},{"v":13,"t":"I reče Isus satniku: “Idi, neka ti bude kako si vjerovao!” I ozdravi sluga u taj čas."},{"v":14,"t":"Ušavši u kuću Petrovu, Isus ugleda njegovu punicu koja ležaše u ognjici."},{"v":15,"t":"Dotače joj se ruke i pusti je ognjica. Ona ustade i posluživaše mu."},{"v":16,"t":"A uvečer mu doniješe mnoge opsjednute. On izagna duhove riječju i sve bolesnike ozdravi -"},{"v":17,"t":"da se ispuni što je rečeno po Izaiji proroku: On slabosti naše uze i boli ponese."},{"v":18,"t":"Kad Isus vidje mnoštvo oko sebe, zapovjedi da se prijeđe prijeko."},{"v":19,"t":"I pristupi jedan pismoznanac te mu reče: “Učitelju, za tobom ću kamo god ti pošao.”"},{"v":20,"t":"Kaže mu Isus: “Lisice imaju jazbine i ptice nebeske gnijezda, a Sin Čovječji nema gdje bi glavu naslonio.”"},{"v":21,"t":"Drugi mu od učenika reče: “Gospodine, dopusti mi da prije odem i pokopam svoga oca.”"},{"v":22,"t":"Isus mu kaže: “Hajde za mnom i pusti neka mrtvi pokapaju svoje mrtve.”"},{"v":23,"t":"Kad uđe u lađu, pođoše za njim njegovi učenici."},{"v":24,"t":"I gle, žestok vihor nasta na moru tako da lađu prekrivahu valovi. A on je spavao."},{"v":25,"t":"Oni pristupiše i probudiše ga govoreći: “Gospodine, spasi, pogibosmo!”"},{"v":26,"t":"Kaže im: “Što ste plašljivi, malovjerni?” Tada ustade i zaprijeti vjetrovima i moru te nasta velika utiha."},{"v":27,"t":"A ljudi su u čudu pitali: “Tko je taj da mu se i vjetrovi i more pokoravaju?”"},{"v":28,"t":"I kada dođe prijeko, u gadarski kraj, eto mu u susret dvaju opsjednutih: izlazili su iz grobnica, silno goropadni, te nitko nije mogao proći onim putem."},{"v":29,"t":"I gle, povikaše: “Što ti imaš s nama, Sine Božji? Došao si ovamo prije vremena mučiti nas?”"},{"v":30,"t":"A podalje od njih paslo je veliko krdo svinja."},{"v":31,"t":"Zlodusi ga zaklinjahu: “Ako nas istjeraš, pošalji nas u ovo krdo svinja.”"},{"v":32,"t":"On im reče: “Idite!” Oni iziđoše i uđoše u svinje. I gle, sve krdo jurnu niz obronak u more i podavi se u vodama."},{"v":33,"t":"A svinjari pobjegoše, odoše u grad te razglasiše sve, napose o opsjednutima."},{"v":34,"t":"I gle, sav grad iziđe u susret Isusu. Kad ga ugledaše, zamole ga da ode iz njihova kraja."}]},"9":{"hr":[{"v":1,"t":"I ušavši u lađu, preplovi i dođe u svoj grad."},{"v":2,"t":"Kad gle, doniješe mu uzetoga koji je ležao na nosiljci. Vidjevši njihovu vjeru, reče Isus uzetomu: “Hrabro, sinko, otpuštaju ti se grijesi!”"},{"v":3,"t":"A gle, neki od pismoznanaca rekoše u sebi: “Ovaj huli!”"},{"v":4,"t":"Prozrevši njihove misli, Isus reče: “Zašto snujete zlo u srcima?"},{"v":5,"t":"Ta što je lakše reći: 'Otpuštaju ti se grijesi' ili reći: 'Ustani i hodi'?"},{"v":6,"t":"Ali da znate: vlastan je Sin Čovječji na zemlji otpuštati grijehe!” Tada reče uzetomu: “Ustani, uzmi nosiljku i pođi kući!”"},{"v":7,"t":"I on usta te ode kući."},{"v":8,"t":"Kad mnoštvo to vidje, zaprepasti se i poda slavu Bogu koji takvu vlast dade ljudima."},{"v":9,"t":"Odlazeći odande, ugleda Isus čovjeka zvanog Matej gdje sjedi u carinarnici. I kaže mu: “Pođi za mnom!” On usta i pođe za njim."},{"v":10,"t":"Dok je Isus bio u kući za stolom, gle, mnogi carinici i grešnici dođoše za stol s njime i njegovim učenicima."},{"v":11,"t":"Vidjevši to, farizeji stanu govoriti: “Zašto vaš učitelj jede s carinicima i grešnicima?”"},{"v":12,"t":"A on, čuvši to, reče: “Ne treba zdravima liječnika, nego bolesnima."},{"v":13,"t":"Hajdete i proučite što znači: Milosrđe mi je milo, a ne žrtva. Ta ne dođoh zvati pravednike, nego grešnike.”"},{"v":14,"t":"Tada pristupe k njemu Ivanovi učenici govoreći: “Zašto mi i farizeji postimo, a učenici tvoji ne poste?”"},{"v":15,"t":"Nato im Isus reče: “Mogu li svatovi tugovati dok je s njima zaručnik? Doći će već dani kad će im se ugrabiti zaručnik, i tada će postiti!”"},{"v":16,"t":"“A nitko ne stavlja krpe od sirova sukna na staro odijelo, jer zakrpa vuče s odijela pa nastane još veća rupa.”"},{"v":17,"t":"“I ne ulijeva se novo vino u stare mješine. Inače se mješine proderu, vino prolije, a mješine propadnu. Nego, novo se vino ulijeva u nove mješine pa se oboje sačuva.”"},{"v":18,"t":"Dok im on to govoraše, gle, pristupi neki glavar, pokloni mu se do zemlje i reče: “Kći mi, evo, umrije, ali dođi, stavi ruku na nju, i oživjet će.”"},{"v":19,"t":"Isus usta te s učenicima pođe za njim."},{"v":20,"t":"I gle, neka žena koja bolovaše dvanaest godina od krvarenja priđe odostraga i dotaknu se skuta njegove haljine."},{"v":21,"t":"Mislila je: “Dotaknem li se samo njegove haljine, spasit ću se.”"},{"v":22,"t":"A Isus se okrenu i vidjevši je reče: “Hrabro, kćeri, vjera te tvoja spasila.” I žena bi spašena od toga časa."},{"v":23,"t":"I uđe Isus u kuću glavarovu. Ugleda svirače i bučno mnoštvo pa"},{"v":24,"t":"reče: “Odstupite! Djevojka nije umrla, nego spava.” Oni mu se podsmjehivahu."},{"v":25,"t":"A kad je svijet bio izbačen, uđe on, primi djevojku za ruku i ona bi uskrišena."},{"v":26,"t":"I razglasi se to po svem onom kraju."},{"v":27,"t":"Kad je Isus odlazio odande, pođu za njim dva slijepca vičući: “Smiluj nam se, Sine Davidov!”"},{"v":28,"t":"A kad uđe u kuću, pristupe mu slijepci. Isus im kaže: “Vjerujete li da mogu to učiniti?” Kažu mu: “Da, Gospodine!”"},{"v":29,"t":"Tada se dotače njihovih očiju govoreći: “Neka vam bude po vašoj vjeri.”"},{"v":30,"t":"I otvoriše im se oči. A Isus im poprijeti: “Pazite da nitko ne dozna!”"},{"v":31,"t":"Ali oni, izišavši, razniješe glas o njemu po svem onom kraju."},{"v":32,"t":"Tek što oni iziđoše, gle, doniješe mu njemaka opsjednuta."},{"v":33,"t":"Pošto izagna đavla, progovori njemak. Mnoštvo se čudom čudilo i govorilo: “Nikada se takvo što ne vidje u Izraelu!”"},{"v":34,"t":"A farizeji govorahu: “Po poglavici đavolskome izgoni đavle.”"},{"v":35,"t":"I obilazio je Isus sve gradove i sela učeći po njihovim sinagogama, propovijedajući Evanđelje o Kraljevstvu i liječeći svaku bolest i svaku nemoć."},{"v":36,"t":"Vidjevši mnoštvo, sažali mu se nad njim jer bijahu izmučeni i ophrvani kao ovce bez pastira."},{"v":37,"t":"Tada reče svojim učenicima: “Žetve je mnogo, a radnika malo."},{"v":38,"t":"Molite dakle gospodara žetve da pošalje radnike u žetvu svoju.”"}]},"10":{"hr":[{"v":1,"t":"Dozva dvanaestoricu svojih učenika i dade im vlast nad nečistim dusima: da ih izgone i da liječe svaku bolest i svaku nemoć."},{"v":2,"t":"A ovo su imena dvanaestorice apostola: prvi Šimun, zvani Petar, i Andrija, brat njegov; i Jakov, sin Zebedejev, i Ivan brat njegov;"},{"v":3,"t":"Filip i Bartolomej; Toma i Matej carinik; Jakov Alfejev i Tadej;"},{"v":4,"t":"Šimun Kananaj i Juda Iškariotski, koji ga izda."},{"v":5,"t":"Tu dvanaestoricu posla Isus uputivši ih: “K poganima ne idite i ni u koji samarijski grad ne ulazite!"},{"v":6,"t":"Pođite radije k izgubljenim ovcama doma Izraelova!"},{"v":7,"t":"Putom propovijedajte: 'Približilo se kraljevstvo nebesko!'"},{"v":8,"t":"Bolesne liječite, mrtve uskrisujte, gubave čistite, zloduhe izgonite! Besplatno primiste, besplatno dajte!"},{"v":9,"t":"Ne stječite zlata, ni srebra, ni mjedi sebi u pojase,"},{"v":10,"t":"ni putne torbe, ni dviju haljina, ni obuće, ni štapa. Ta vrijedan je radnik hrane svoje.”"},{"v":11,"t":"“U koji god grad ili selo uđete, razvidite tko je u njemu dostojan: ondje ostanite sve dok ne odete."},{"v":12,"t":"Ulazeći u kuću, zaželite joj mir."},{"v":13,"t":"Bude li kuća dostojna, neka mir vaš siđe na nju. Ne bude li dostojna, neka se mir vaš k vama vrati."},{"v":14,"t":"Gdje vas ne prime i ne poslušaju riječi vaših, iziđite iz kuće ili grada toga i prašinu otresite sa svojih nogu."},{"v":15,"t":"Zaista, kažem vam, lakše će biti zemlji sodomskoj i gomorskoj na Dan sudnji negoli gradu tomu.”"},{"v":16,"t":"“Evo, ja vas šaljem kao ovce među vukove. Budite dakle mudri kao zmije, a bezazleni kao golubovi!"},{"v":17,"t":"Čuvajte se ljudi, jer će vas predavati vijećima i po svojim će vas sinagogama bičevati."},{"v":18,"t":"Pred upravitelje i kraljeve vodit će vas poradi mene, za svjedočanstvo njima i poganima."},{"v":19,"t":"Kad vas predadu, ne budite zabrinuti kako ili što ćete govoriti. Dat će vam se u onaj čas što ćete govoriti."},{"v":20,"t":"Ta ne govorite to vi, nego Duh Oca vašega govori u vama!”"},{"v":21,"t":"“Brat će brata predavati na smrt i otac dijete. Djeca će ustajati na roditelje i ubijati ih."},{"v":22,"t":"Svi će vas zamrziti zbog imena moga. Ali tko ustraje do svršetka, bit će spašen.”"},{"v":23,"t":"“Kad vas stanu progoniti u jednom gradu, bježite u drugi. Zaista, kažem vam, nećete obići gradova izraelskih prije nego što dođe Sin Čovječji.”"},{"v":24,"t":"“Nije učenik nad učiteljem niti sluga nad gospodarom svojim."},{"v":25,"t":"Dosta je da učenik bude kao njegov učitelj i sluga kao njegov gospodar. Ako su domaćina Beelzebulom nazvali, koliko će više njegove ukućane?”"},{"v":26,"t":"“Ne bojte ih se dakle. Ta ništa nije skriveno što se neće otkriti ni tajno što se neće doznati."},{"v":27,"t":"Što vam govorim u tami, recite na svjetlu; i što na uho čujete, propovijedajte na krovovima.”"},{"v":28,"t":"“Ne bojte se onih koji ubijaju tijelo, ali duše ne mogu ubiti. Bojte se više onoga koji može i dušu i tijelo pogubiti u paklu.”"},{"v":29,"t":"“Ne prodaju li se dva vrapca za novčić? Pa ipak ni jedan od njih ne pada na zemlju bez Oca vašega."},{"v":30,"t":"A vama su i vlasi na glavi sve izbrojene."},{"v":31,"t":"Ne bojte se dakle! Vredniji ste nego mnogo vrabaca.”"},{"v":32,"t":"“Tko god se, dakle, prizna mojim pred ljudima, priznat ću se i ja njegovim pred Ocem, koji je na nebesima."},{"v":33,"t":"A tko se odreče mene pred ljudima, odreći ću se i ja njega pred svojim Ocem, koji je na nebesima.”"},{"v":34,"t":"“Ne mislite da sam došao mir donijeti na zemlju. Ne, nisam došao donijeti mir, nego mač."},{"v":35,"t":"Ta došao sam rastaviti čovjeka od oca njegova i kćer od majke njezine i snahu od svekrve njezine;"},{"v":36,"t":"i neprijatelji će čovjeku biti ukućani njegovi."},{"v":37,"t":"“Tko ljubi oca ili majku više nego mene, nije mene dostojan. Tko ljubi sina ili kćer više nego mene, nije mene dostojan."},{"v":38,"t":"Tko ne uzme svoga križa i ne pođe za mnom, nije mene dostojan."},{"v":39,"t":"Tko nađe život svoj, izgubit će ga, a tko izgubi svoj život poradi mene, naći će ga.”"},{"v":40,"t":"“Tko vas prima, mene prima; a tko prima mene, prima onoga koji je mene poslao."},{"v":41,"t":"Tko prima proroka jer je prorok, primit će plaću proročku; tko prima pravednika jer je pravednik, primit će plaću pravedničku."},{"v":42,"t":"Tko napoji jednoga od ovih najmanjih samo čašom hladne vode zato što je moj učenik, zaista, kažem vam, neće mu propasti plaća.”"}]},"11":{"hr":[{"v":1,"t":"Pošto Isus završi upućivati dvanaestoricu učenika, ode odande naučavati i propovijedati po njihovim gradovima."},{"v":2,"t":"A kad Ivan u tamnici doču za djela Kristova, posla svoje učenike"},{"v":3,"t":"da ga upitaju: “Jesi li ti Onaj koji ima doći ili drugoga da čekamo?”"},{"v":4,"t":"Isus im odgovori: “Pođite i javite Ivanu što ste čuli i vidjeli:"},{"v":5,"t":"Slijepi progledaju, hromi hode, gubavi se čiste, gluhi čuju, mrtvi ustaju, siromasima se navješćuje Evanđelje."},{"v":6,"t":"I blago onom tko se ne sablazni o mene.”"},{"v":7,"t":"Kad oni odoše, poče Isus govoriti mnoštvu o Ivanu: “Što ste izišli u pustinju gledati? Trsku koju vjetar ljulja?"},{"v":8,"t":"Ili što ste izišli vidjeti? Čovjeka u mekušasto odjevena? Eno, oni što se mekušasto nose po kraljevskim su dvorima."},{"v":9,"t":"Ili što ste izišli? Vidjeti proroka? Da, kažem vam, i više nego proroka."},{"v":10,"t":"On je onaj o kome je pisano: Evo, ja šaljem glasnika svoga pred licem tvojim da pripravi put pred tobom."},{"v":11,"t":"Zaista, kažem vam, između rođenih od žene ne usta veći od Ivana Krstitelja. A ipak, i najmanji u kraljevstvu nebeskom veći je od njega!"},{"v":12,"t":"A od dana Ivana Krstitelja do sada kraljevstvo nebesko silom se probija i siloviti ga grabe."},{"v":13,"t":"Uistinu, svi proroci i Zakon prorokovahu do Ivana."},{"v":14,"t":"Zapravo ako hoćete: on je Ilija koji ima doći.”"},{"v":15,"t":"“Tko ima uši, neka čuje.”"},{"v":16,"t":"“A komu da prispodobim ovaj naraštaj? Nalik je djeci što sjede na trgovima pa jedni drugima dovikuju:"},{"v":17,"t":"'Zasvirasmo vam i ne zaigraste, zakukasmo i ne zaplakaste.'”"},{"v":18,"t":"“Doista, dođe Ivan. Nije jeo ni pio, a govori se: 'Ðavla ima.'"},{"v":19,"t":"Dođe Sin Čovječji koji jede i pije, a govori se: 'Gle, izjelice i vinopije, prijatelja carinika i grešnika!' Ali opravda se Mudrost djelima svojim.”"},{"v":20,"t":"Tada stane prekoravati gradove u kojima se dogodilo najviše njegovih čudesa, a oni se ne obratiše:"},{"v":21,"t":"“Jao tebi, Korozaine! Jao tebi, Betsaido! Da su se u Tiru i Sidonu zbila čudesa koja su se dogodila u vama, odavna bi se već oni u kostrijeti i pepelu bili obratili."},{"v":22,"t":"Ali kažem vam: Tiru i Sidonu bit će na Dan sudnji lakše negoli vama.”"},{"v":23,"t":"“I ti, Kafarnaume! Zar ćeš se do neba uzvisiti? Do u Podzemlje ćeš se strovaliti! Doista, da su se u Sodomi zbila čudesa koja su se dogodila u tebi, ostala bi ona do danas."},{"v":24,"t":"Ali kažem vam: Zemlji će sodomskoj biti na Dan sudnji lakše nego tebi.”"},{"v":25,"t":"U ono vrijeme reče Isus: “Slavim te, Oče, Gospodaru neba i zemlje, što si ovo sakrio od mudrih i umnih, a objavio malenima."},{"v":26,"t":"Da, Oče, tako se tebi svidjelo."},{"v":27,"t":"Sve je meni predao Otac moj i nitko ne pozna Sina doli Otac niti tko pozna Oca doli Sin i onaj kome Sin hoće objaviti.”"},{"v":28,"t":"“Dođite k meni svi koji ste izmoreni i opterećeni i ja ću vas odmoriti."},{"v":29,"t":"Uzmite jaram moj na sebe, učite se od mene jer sam krotka i ponizna srca i naći ćete spokoj dušama svojim."},{"v":30,"t":"Uistinu, jaram je moj sladak i breme moje lako.”"}]},"12":{"hr":[{"v":1,"t":"U ono vrijeme prolazio je Isus subotom kroz usjeve. Učenici su njegovi ogladnjeli te počeli trgati klasje i jesti."},{"v":2,"t":"Vidjevši to, farizeji mu rekoše: “Gle, učenici tvoji čine što nije dopušteno činiti subotom.”"},{"v":3,"t":"On im reče: “Niste li čitali što učini David kad ogladnje on i njegovi pratioci?"},{"v":4,"t":"Kako uđe u Dom Božji te pojedoše prinesene kruhove, a to ne bijaše slobodno jesti ni njemu ni njegovim pratiocima, nego samo svećenicima?"},{"v":5,"t":"Ili zar niste čitali u Zakonu da subotom svećenici u Hramu krše subotu, a bez krivnje su?"},{"v":6,"t":"A velim vam: veće od Hrama jest ovdje!"},{"v":7,"t":"I kad biste razumjeli što ono znači: Milosrđe mi je milo, a ne žrtva, ne biste osudili ove nekrive."},{"v":8,"t":"Ta Sin Čovječji gospodar je subote!”"},{"v":9,"t":"Otišavši odande, dođe u njihovu sinagogu,"},{"v":10,"t":"kad gle čovjeka s usahlom rukom. A oni upitaše Isusa da bi ga mogli optužiti: “Je li dopušteno subotom liječiti?”"},{"v":11,"t":"On im reče: “Tko to od vas jedinu ovcu koju ima ne bi subotom prihvatio i izvadio kad bi mu upala u jamu?"},{"v":12,"t":"A koliko je čovjek vredniji od ovce! Tako, slobodno je subotom činiti dobro!”"},{"v":13,"t":"Tada reče čovjeku: “Ispruži ruku!” On je ispruži, i - ruka mu zdrava kao i druga!"},{"v":14,"t":"A farizeji iziđoše i održaše vijećanje protiv njega, kako da ga pogube."},{"v":15,"t":"Kad Isus to dozna, ukloni se odande. Za njim je išlo mnoštvo. On ih sve ozdravi"},{"v":16,"t":"i poprijeti im da ga ne prokazuju -"},{"v":17,"t":"da se ispuni što je rečeno po Izaiji proroku:"},{"v":18,"t":"Evo Sluge mojega, koga sebi izabrah: mog ljubimca, miljenika duše moje! Stavit ću Duha svoga na njega: naviještat će pravo narodima;"},{"v":19,"t":"preti se neće, neće bučiti, glas mu se neće čuti po trgovima;"},{"v":20,"t":"trske stučene prelomiti neće, stijenja što tek tinja neće ugasiti - sve dok do pobjede ne izvede pravo."},{"v":21,"t":"Ime njegovo nada je narodima!"},{"v":22,"t":"Tada mu donesoše opsjednuta, slijepa i nijema. I ozdravi ga te njemak progovori i progleda."},{"v":23,"t":"I sve ono mnoštvo zapanjeno govoraše: “Da ovo nije Sin Davidov?”"},{"v":24,"t":"A farizeji čuvši to rekoše: “Ne može ovaj izgoniti đavle osim po Beelzebulu, poglavici đavolskom.”"},{"v":25,"t":"A on, znajući njihove misli, reče im: “Svako kraljevstvo u sebi razdijeljeno opustjet će i svaki grad ili kuća u sebi razdijeljena neće opstati."},{"v":26,"t":"Ako Sotona Sotonu izgoni, u sebi je razdijeljen. Kako će dakle opstati kraljevstvo njegovo?"},{"v":27,"t":"I ako ja po Beelzebulu izgonim đavle, po kome ih sinovi vaši izgone? Zato će vam oni biti suci."},{"v":28,"t":"Ali ako ja po Duhu Božjem izgonim đavle, zbilja je došlo k vama kraljevstvo Božje.”"},{"v":29,"t":"“Ili kako bi tko mogao ući u kuću jakoga i oplijeniti mu pokućstvo ako prije ne sveže jakoga? Tada će mu kuću oplijeniti.”"},{"v":30,"t":"“Tko nije sa mnom, protiv mene je, i tko ne sabire sa mnom, rasipa.”"},{"v":31,"t":"“Zato kažem vam: svaki će se grijeh i bogohulstvo oprostiti ljudima, ali rekne li tko bogohulstvo protiv Duha, neće se oprostiti."},{"v":32,"t":"I rekne li tko riječ protiv Sina Čovječjega, oprostit će mu se. Ali tko rekne protiv Duha Svetoga, neće mu se oprostiti ni na ovom svijetu ni u budućem.”"},{"v":33,"t":"“Ili uzmite: dobro stablo i plod mu je dobar. Ili uzmite: trulo stablo i plod mu je truo. Ta po plodu se stablo poznaje."},{"v":34,"t":"Leglo gujinje! Kako možete govoriti dobro kad ste opaki. Ta iz obilja srca usta govore!"},{"v":35,"t":"Dobar čovjek iz riznice dobre vadi dobro, a zao čovjek iz riznice zle vadi zlo."},{"v":36,"t":"A kažem vam: za svaku bezrazložnu riječ koju ljudi reknu dat će račun na Dan sudnji."},{"v":37,"t":"Doista, tvoje će te riječi opravdati i tvoje će te riječi osuditi.”"},{"v":38,"t":"Jednom zapodjenuše s njime razgovor neki pismoznanci i farizeji: “Učitelju, htjeli bismo od tebe vidjeti znak.”"},{"v":39,"t":"A on im odgovori: “Naraštaj opak i preljubnički znak traži, ali mu se znak neće dati doli znak Jone proroka."},{"v":40,"t":"Doista, kao što Jona bijaše u utrobi kitovoj tri dana i tri noći, tako će i Sin Čovječji biti u srcu zemlje tri dana i tri noći."},{"v":41,"t":"Ninivljani će ustati na Sudu zajedno s ovim naraštajem i osuditi ga jer se oni na propovijed Joninu obratiše, a evo, ovdje je i više od Jone!"},{"v":42,"t":"Kraljica će Juga ustati na Sudu zajedno s ovim naraštajem i osuditi ga jer je s krajeva zemlje došla čuti mudrost Salomonovu, a evo, ovdje je i više od Salomona!”"},{"v":43,"t":"“A kad nečisti duh iziđe iz čovjeka, luta bezvodnim mjestima tražeći spokoja, ali ne nalazi!"},{"v":44,"t":"Tada rekne: 'Vratit ću se u kuću odakle iziđoh.' I došavši, nađe je praznu, pometenu i uređenu."},{"v":45,"t":"Tada ode i uzme sa sobom sedam drugih duhova, gorih od sebe, te uđu i nastane se ondje. Na kraju bude s onim čovjekom gore nego na početku. Tako će biti i s ovim opakim naraštajem.”"},{"v":46,"t":"Dok on još govoraše mnoštvu, eto majke i braće njegove. Stajahu vani tražeći da s njime govore."},{"v":47,"t":"Reče mu netko: “Evo majke tvoje i braće tvoje, vani stoje i traže da s tobom govore.”"},{"v":48,"t":"Tomu koji mu to javi on odgovori: “Tko je majka moja, tko li braća moja?”"},{"v":49,"t":"I pruži ruku prema učenicima: “Evo, reče, majke moje i braće moje!"},{"v":50,"t":"Doista, tko god vrši volju Oca mojega, koji je na nebesima, taj mi je brat i sestra i majka.”"}]},"13":{"hr":[{"v":1,"t":"Onoga dana Isus iziđe iz kuće i sjede uz more."},{"v":2,"t":"I nagrnu k njemu silan svijet te je morao ući u lađu: sjede, a sve ono mnoštvo stajaše na obali."},{"v":3,"t":"I zborio im je mnogo u prispodobama: “Gle, iziđe sijač sijati."},{"v":4,"t":"I dok je sijao, nešto zrnja pade uz put, dođoše ptice i pozobaše ga."},{"v":5,"t":"Nešto opet pade na kamenito tlo, gdje nemaše dosta zemlje, i odmah izniknu jer nemaše duboke zemlje."},{"v":6,"t":"A kad sunce ogranu, izgorje i jer nemaše korijena, osuši se."},{"v":7,"t":"Nešto opet pade u trnje, trnje uzraste i uguši ga."},{"v":8,"t":"Nešto napokon pade na dobru zemlju i davaše plod: jedno stostruk, drugo šezdesetostruk, treće tridesetostruk.”"},{"v":9,"t":"“Tko ima uši, neka čuje!”"},{"v":10,"t":"I pristupe učenici pa ga zapitaju: “Zašto im zboriš u prispodobama?”"},{"v":11,"t":"On im odgovori: “Zato što je vama dano znati otajstva kraljevstva nebeskoga, a njima nije dano."},{"v":12,"t":"Doista, onomu tko ima dat će se i obilovat će, a onomu tko nema oduzet će se i ono što ima."},{"v":13,"t":"U prispodobama im zborim zato što gledajući ne vide i slušajući ne čuju i ne razumiju.”"},{"v":14,"t":"“Tako se ispunja na njima proroštvo Izaijino koje govori: Slušat ćete, slušati - i nećete razumjeti; gledat ćete, gledati - i nećete vidjeti!"},{"v":15,"t":"Jer usalilo se srce naroda ovoga: uši začepiše, oči zatvoriše da očima ne vide, ušima ne čuju, srcem ne razumiju te se ne obrate pa ih izliječim."},{"v":16,"t":"A blago vašim očima što vide, i ušima što slušaju."},{"v":17,"t":"Zaista, kažem vam, mnogi su proroci i pravednici željeli vidjeti što vi gledate, ali nisu vidjeli; i čuti što vi slušate, ali nisu čuli.”"},{"v":18,"t":"“Vi, dakle, poslušajte prispodobu o sijaču."},{"v":19,"t":"Svakomu koji sluša Riječ o Kraljevstvu, a ne razumije, dolazi Zli te otima što mu je u srcu posijano. To je onaj uz put zasijan."},{"v":20,"t":"A zasijani na tlo kamenito - to je onaj koji čuje Riječ i odmah je s radošću prima,"},{"v":21,"t":"ali nema u sebi korijena, nego je nestalan: kad zbog Riječi nastane nevolja ili progonstvo, odmah se pokoleba."},{"v":22,"t":"Zasijani u trnje - to je onaj koji sluša Riječ, ali briga vremenita i zavodljivost bogatstva uguše Riječ, te ona ostane bez ploda."},{"v":23,"t":"Zasijani na dobru zemlju - to je onaj koji Riječ sluša i razumije, pa onda, dakako, urodi i daje: jedan stostruko, jedan šezdesetostruko, a jedan tridesetostruko.”"},{"v":24,"t":"Drugu im prispodobu iznese: “Kraljevstvo je nebesko kao kad čovjek posije dobro sjeme na svojoj njivi."},{"v":25,"t":"Dok su njegovi ljudi spavali, dođe njegov neprijatelj, posije posred žita kukolj i ode."},{"v":26,"t":"Kad usjev uzraste i isklasa, tada se pokaza i kukolj."},{"v":27,"t":"Sluge pristupe domaćinu pa mu reknu: 'Gospodaru, nisi li ti dobro sjeme posijao na svojoj njivi? Odakle onda kukolj?'"},{"v":28,"t":"On im odgovori: 'Neprijatelj čovjek to učini.' Nato mu sluge kažu: 'Hoćeš li, dakle, da odemo pa da ga pokupimo?'"},{"v":29,"t":"A on reče: 'Ne! Da ne biste sabirući kukolj iščupali zajedno s njim i pšenicu."},{"v":30,"t":"Pustite nek oboje raste do žetve. U vrijeme žetve reći ću žeteocima: Pokupite najprije kukolj i svežite ga u snopove da se spali, a žito skupite u moju žitnicu.'”"},{"v":31,"t":"I drugu im prispodobu iznese: “Kraljevstvo je nebesko kao kad čovjek uze gorušičino zrno i posija ga na svojoj njivi."},{"v":32,"t":"Ono je doduše najmanje od svega sjemenja, ali kad uzraste, veće je od svega povrća. Razvije se u stablo te dolaze ptice nebeske i gnijezde mu se po granama.”"},{"v":33,"t":"I drugu im kaza prispodobu: “Kraljevstvo je nebesko kao kad žena uze kvasac i zamijesi ga u tri mjere brašna dok sve ne uskisne.”"},{"v":34,"t":"Sve je to Isus mnoštvu zborio u prispodobama. I ništa im nije zborio bez prispodoba -"},{"v":35,"t":"da se ispuni što je rečeno po proroku: Otvorit ću u prispodobama usta svoja, iznijet ću što je sakriveno od postanka svijeta."},{"v":36,"t":"Tada otpusti mnoštvo i uđe u kuću. Pristupe mu učenici govoreći: “Razjasni nam prispodobu o kukolju na njivi.”"},{"v":37,"t":"On odgovori: “Sijač dobroga sjemena jest Sin Čovječji."},{"v":38,"t":"Njiva je svijet. Dobro sjeme sinovi su Kraljevstva, a kukolj sinovi Zloga."},{"v":39,"t":"Neprijatelj koji ga posija jest đavao. Žetva je svršetak svijeta, a žeteoci anđeli."},{"v":40,"t":"Kao što se kukolj sabire i ognjem sažiže, tako će biti na svršetku svijeta."},{"v":41,"t":"Sin će Čovječji poslati svoje anđele da pokupe iz njegova kraljevstva sve zavodnike i bezakonike"},{"v":42,"t":"i bace ih u peć ognjenu, gdje će biti plač i škrgut zubi."},{"v":43,"t":"Tada će pravednici zasjati poput sunca u kraljevstvu Oca svojega.” “Tko ima uši, neka čuje!”"},{"v":44,"t":"“Kraljevstvo je nebesko kao kad je blago skriveno na njivi: čovjek ga pronađe, sakrije, sav radostan ode, proda sve što ima i kupi tu njivu.”"},{"v":45,"t":"“Nadalje, kraljevstvo je nebesko kao kad trgovac traga za lijepim biserjem:"},{"v":46,"t":"pronađe jedan dragocjeni biser, ode, rasproda sve što ima i kupi ga.”"},{"v":47,"t":"“Nadalje, kraljevstvo je nebesko kao kad mreža bačena u more zahvati svakovrsne ribe."},{"v":48,"t":"Kad se napuni, izvuku je na obalu, sjednu i skupe dobre u posude, a loše izbace."},{"v":49,"t":"Tako će biti na svršetku svijeta. Izići će anđeli, odijeliti zle od pravednih"},{"v":50,"t":"i baciti ih u peć ognjenu, gdje će biti plač i škrgut zubi.”"},{"v":51,"t":"“Jeste li sve ovo razumjeli?” Odgovore mu: “Jesmo.”"},{"v":52,"t":"A on će im: “Stoga svaki pismoznanac upućen u kraljevstvo nebesko sličan je čovjeku domaćinu koji iz svoje riznice iznosi novo i staro.”"},{"v":53,"t":"Kad Isus završi sve ove prispodobe, ode odande."},{"v":54,"t":"I dođe u svoj zavičaj. Naučavaše ih u njihovoj sinagogi te zapanjeni govorahu: “Odakle ovomu ta mudrost i te čudesne sile?"},{"v":55,"t":"Nije li ovo drvodjeljin sin? Nije li mu majka Marija, a braća Jakov, i Josip, i Šimun, i Juda?"},{"v":56,"t":"I sestre mu nisu li sve među nama? Odakle mu sve to?”"},{"v":57,"t":"I sablažnjavahu se o njega. A Isus im reče: “Nije prorok bez časti doli u svom zavičaju i u svom domu.”"},{"v":58,"t":"I ne učini ondje mnogo čudesa zbog njihove nevjere."}]},"14":{"hr":[{"v":1,"t":"U ono vrijeme doču Herod tetrarh za Isusa"},{"v":2,"t":"pa reče svojim slugama: “To je Ivan Krstitelj! On uskrsnu od mrtvih i zato čudesne sile djeluju u njemu.”"},{"v":3,"t":"Herod doista bijaše uhitio Ivana te ga svezana bacio u tamnicu zbog Herodijade, žene brata svoga Filipa."},{"v":4,"t":"Jer Ivan mu govoraše: “Ne smiješ je imati!”"},{"v":5,"t":"Htjede ga ubiti, ali se bojao naroda jer su ga smatrali prorokom."},{"v":6,"t":"Na Herodov rođendan zaplesa kći Herodijadina pred svima i svidje se Herodu."},{"v":7,"t":"Zato se zakle dati joj što god zaište."},{"v":8,"t":"A ona nagovorena od matere: “Daj mi, reče, ovdje na pladnju glavu Ivana Krstitelja.”"},{"v":9,"t":"Ražalosti se kralj, ali zbog zakletve i sustolnika zapovjedi da se dade."},{"v":10,"t":"Posla odrubiti glavu Ivanu u tamnici."},{"v":11,"t":"I doniješe glavu njegovu na pladnju, dadoše djevojci, a ona je odnije materi."},{"v":12,"t":"A učenici njegovi dođu, uzmu njegovo tijelo i pokopaju ga pa odu i jave Isusu."},{"v":13,"t":"Kad je Isus to čuo, povuče se odande lađom na samotno mjesto, u osamu. Dočuo to narod pa pohrli pješice za njim iz gradova."},{"v":14,"t":"Kad on iziđe, vidje silan svijet, sažali mu se nad njim te izliječi njegove bolesnike."},{"v":15,"t":"Uvečer mu pristupe učenici pa mu reknu: “Pust je ovo kraj i već je kasno. Otpusti dakle svijet: neka odu po selima kupiti hrane.”"},{"v":16,"t":"A Isus im reče: “Ne treba da idu, dajte im vi jesti.”"},{"v":17,"t":"Oni mu kažu: “Nemamo ovdje ništa osim pet kruhova i dvije ribe.”"},{"v":18,"t":"A on će im: “Donesite mi ih ovamo.”"},{"v":19,"t":"I zapovjedi da mnoštvo posjeda po travi. On uze pet kruhova i dvije ribe, pogleda na nebo, izreče blagoslov pa razlomi i dade kruhove učenicima, a učenici mnoštvu."},{"v":20,"t":"I jeli su svi i nasitili se. Od preteklih ulomaka nakupiše dvanaest punih košara."},{"v":21,"t":"A blagovalo je oko pet tisuća muškaraca, osim žena i djece."},{"v":22,"t":"I odmah prisili učenike da uđu u lađu i da se prebace prijeko dok on otpusti mnoštvo."},{"v":23,"t":"A pošto otpusti mnoštvo, uziđe na goru, nasamo, da se pomoli. Uvečer bijaše ondje sam."},{"v":24,"t":"Lađa se već mnogo stadija bila ostisla od kraja, šibana valovima. Bijaše protivan vjetar."},{"v":25,"t":"O četvrtoj noćnoj straži dođe on k njima hodeći po moru."},{"v":26,"t":"A učenici ugledavši ga kako hodi po moru, prestrašeni rekoše: “Utvara!” I od straha kriknuše."},{"v":27,"t":"Isus im odmah progovori: “Hrabro samo! Ja sam! Ne bojte se!”"},{"v":28,"t":"Petar prihvati i reče: “Gospodine, ako si ti, zapovjedi mi da dođem k tebi po vodi!”"},{"v":29,"t":"A on mu reče: “Dođi!” I Petar siđe s lađe te, hodeći po vodi, pođe k Isusu."},{"v":30,"t":"Ali kad spazi vjetar, poplaši se, počne tonuti te krikne: “Gospodine, spasi me!”"},{"v":31,"t":"Isus odmah pruži ruku, dohvati ga i kaže mu: “Malovjerni, zašto si posumnjao?”"},{"v":32,"t":"Kad uđoše u lađu, utihnu vjetar."},{"v":33,"t":"A oni na lađi poklone mu se ničice govoreći: “Uistinu, ti si Sin Božji!”"},{"v":34,"t":"Pošto preploviše, dođu na kraj, u Genezaret."},{"v":35,"t":"I ljudi ga onoga kraja prepoznaju pa razglase po svoj onoj okolici. I donošahu mu sve bolesnike"},{"v":36,"t":"te ga moljahu da se samo dotaknu skuta njegove haljine. I koji bi se dotakli, ozdravili bi."}]},"15":{"hr":[{"v":1,"t":"Tada pristupe Isusu farizeji i pismoznanci iz Jeruzalema govoreći:"},{"v":2,"t":"“Zašto tvoji učenici prestupaju predaju starih? Ne umivaju ruku prije jela!”"},{"v":3,"t":"On im odgovori: “A zašto vi prestupate zapovijed Božju radi svoje predaje?"},{"v":4,"t":"Ta reče Bog: Poštuj oca i majku! I: Tko prokune oca ili majku, smrću neka se kazni!"},{"v":5,"t":"A vi velite: 'Rekne li tko ocu ili majci: Pomoć koja te od mene ide neka bude sveti dar,"},{"v":6,"t":"ne treba da poštuje oca svoga ni majku svoju.' Tako dokinuste riječ Božju radi svoje predaje."},{"v":7,"t":"Licemjeri, dobro prorokova o vama Izaija:"},{"v":8,"t":"Narod me ovaj usnama časti, a srce mu je daleko od mene."},{"v":9,"t":"Uzalud me štuju naučavajući nauke - uredbe ljudske.”"},{"v":10,"t":"Tada dozove mnoštvo i reče: “Slušajte i razumijte!"},{"v":11,"t":"Ne onečišćuje čovjeka što ulazi u usta, nego što iz usta izlazi - to čovjeka onečišćuje.”"},{"v":12,"t":"Tada pristupe k njemu učenici i kažu mu: “Znaš li da su se farizeji sablaznili kad su čuli tu riječ?”"},{"v":13,"t":"On im odgovori: “Svaki nasad koji ne posadi Otac moj nebeski iskorijenit će se."},{"v":14,"t":"Pustite ih! Slijepi su, vođe slijepaca! A ako slijepac slijepca vodi, obojica će u jamu pasti.”"},{"v":15,"t":"Petar prihvati i reče mu: “Protumači nam tu prispodobu!”"},{"v":16,"t":"A on reče: “I vi još uvijek ne razumijete?"},{"v":17,"t":"Ne shvaćate li: sve što ulazi na usta, ide u trbuh te se izbacuje u zahod."},{"v":18,"t":"Naprotiv, što iz usta izlazi, iz srca izvire i to onečišćuje čovjeka."},{"v":19,"t":"Ta iz srca izviru opake namisli, ubojstva, preljubi, bludništva, krađe, lažna svjedočanstva, psovke."},{"v":20,"t":"To onečišćuje čovjeka; a jesti neopranih ruku ne onečišćuje čovjeka.”"},{"v":21,"t":"Isus zatim ode odande i povuče se u krajeve tirske i sidonske."},{"v":22,"t":"I gle: žena neka, Kanaanka iz onih krajeva, iziđe vičući: “Smiluj mi se, Gospodine, Sine Davidov! Kći mi je teško opsjednuta!”"},{"v":23,"t":"Ali on joj ne uzvrati ni riječi. Pristupe mu na to učenici te ga moljahu: “Udovolji joj jer viče za nama.”"},{"v":24,"t":"On odgovori: “Poslan sam samo k izgubljenim ovcama doma Izraelova.”"},{"v":25,"t":"Ali ona priđe, pokloni mu se ničice i kaže: “Gospodine, pomozi mi!”"},{"v":26,"t":"On odgovori: “Ne priliči uzeti kruh djeci i baciti ga psićima.”"},{"v":27,"t":"A ona će: “Da, Gospodine! Ali psići jedu od mrvica što padaju sa stola njihovih gospodara!”"},{"v":28,"t":"Tada joj Isus reče: “O ženo! Velika je vjera tvoja! Neka ti bude kako želiš.” I ozdravi joj kći toga časa."},{"v":29,"t":"Otišavši odande, dođe Isus do Galilejskog mora, uziđe na goru i sjede ondje."},{"v":30,"t":"Tada nagrnu k njemu silan svijet s hromima, kljastima, slijepima, nijemima i mnogima drugima. Polože mu ih do nogu, a on ih izliječi."},{"v":31,"t":"Gledajući kako su nijemi progovorili, kljasti ozdravili, hromi prohodali, slijepi progledali, divilo se mnoštvo i slavilo Boga Izraelova."},{"v":32,"t":"A Isus dozva svoje učenike pa im reče: “Žao mi je naroda jer su već tri dana uza me, a nemaju što jesti. Otpraviti ih gladne neću da ne klonu putem.”"},{"v":33,"t":"Kažu mu učenici: “Odakle nam u pustinji toliko kruha da nahranimo toliko mnoštvo?”"},{"v":34,"t":"A Isus im reče: “Koliko kruhova imate?” Oni će: “Sedam, i malo riba.”"},{"v":35,"t":"Nato zapovjedi mnoštvu da posjeda po zemlji,"},{"v":36,"t":"uze sedam kruhova i ribe, zahvali, razlomi i davaše učenicima, a učenici mnoštvu."},{"v":37,"t":"I jeli su i nasitili se. A od preteklih ulomaka nakupiše sedam punih košara."},{"v":38,"t":"A blagovalo je četiri tisuće muškaraca, osim žena i djece."},{"v":39,"t":"Tada otpusti mnoštvo, uđe u lađu i ode u kraj magadanski."}]},"16":{"hr":[{"v":1,"t":"Pristupe k njemu farizeji i saduceji. Iskušavajući ga, zatraže da im pokaže kakav znak s neba."},{"v":2,"t":"On im odgovori: “Uvečer govorite: 'Bit će vedro, nebo se žari.'"},{"v":3,"t":"A ujutro: 'Danas će nevrijeme, nebo se tamno zacrvenjelo.' Lice neba znadete rasuditi, a znakove vremena ne znate."},{"v":4,"t":"Naraštaj opak i preljubnički znak traži, ali mu se znak neće dati doli znak Jonin.” Tada ih ostavi i ode."},{"v":5,"t":"Učenici dođoše prijeko, a zaboraviše ponijeti kruha."},{"v":6,"t":"A Isus im reče: “Pazite, čuvajte se kvasca farizejskog i saducejskog!”"},{"v":7,"t":"Oni zamišljeni među sobom govorahu: “Kruha ne ponijesmo.”"},{"v":8,"t":"Zamijetio to Isus pa reče: “Što ste zamišljeni, malovjerni, da kruha nemate?"},{"v":9,"t":"Zar još ne shvaćate, ne sjećate li se onih pet kruhova na pet tisuća i koliko košara nakupiste?"},{"v":10,"t":"I onih sedam kruhova na četiri tisuće i koliko košara nakupiste?"},{"v":11,"t":"Kako onda ne shvaćate da vam to ne rekoh o kruhu? Nego, čuvajte se kvasca farizejskog i saducejskog.”"},{"v":12,"t":"Tada razumješe kako im ne reče da se čuvaju kvasca krušnoga, nego nauka farizejskog i saducejskoga."},{"v":13,"t":"Kad Isus dođe u krajeve Cezareje Filipove, upita učenike: “Što govore ljudi, tko je Sin Čovječji?”"},{"v":14,"t":"Oni rekoše: “Jedni da je Ivan Krstitelj; drugi da je Ilija; treći opet da je Jeremija ili koji od proroka.”"},{"v":15,"t":"Kaže im: “A vi, što vi kažete, tko sam ja?”"},{"v":16,"t":"Šimun Petar prihvati i reče: “Ti si Krist-Pomazanik, Sin Boga živoga.”"},{"v":17,"t":"Nato Isus reče njemu: “Blago tebi, Šimune, sine Jonin, jer ti to ne objavi tijelo i krv, nego Otac moj, koji je na nebesima."},{"v":18,"t":"A ja tebi kažem: Ti si Petar-Stijena i na toj stijeni sagradit ću Crkvu svoju i vrata paklena neće je nadvladati."},{"v":19,"t":"Tebi ću dati ključeve kraljevstva nebeskoga, pa što god svežeš na zemlji, bit će svezano na nebesima; a što god odriješiš na zemlji, bit će odriješeno na nebesima.”"},{"v":20,"t":"Tada zaprijeti učenicima neka nikomu ne reknu da je on Krist."},{"v":21,"t":"Otada poče Isus upućivati učenike kako treba da pođe u Jeruzalem, da mnogo pretrpi od starješina, glavara svećeničkih i pismoznanaca, da bude ubijen i treći dan da uskrsne."},{"v":22,"t":"Petar ga uze na stranu i poče odvraćati: “Bože sačuvaj, Gospodine! Ne, to se tebi ne smije dogoditi!”"},{"v":23,"t":"Isus se okrene i reče Petru: “Nosi se od mene, sotono! Sablazan si mi jer ti nije na pameti što je Božje, nego što je ljudsko!”"},{"v":24,"t":"Tada Isus reče svojim učenicima: “Hoće li tko za mnom, neka se odrekne samoga sebe, neka uzme svoj križ i neka ide za mnom."},{"v":25,"t":"Tko hoće život svoj spasiti, izgubit će ga, a tko izgubi život svoj poradi mena, naći će ga."},{"v":26,"t":"Ta što će koristiti čovjeku ako sav svijet stekne, a životu svojemu naudi? Ili što će čovjek dati u zamjenu za život svoj?"},{"v":27,"t":"Doći će, doista, Sin Čovječji u slavi Oca svoga s anđelima svojim i tada će naplatiti svakomu po djelima njegovim.”"},{"v":28,"t":"“Zaista, kažem vam, neki od ovdje nazočnih neće okusiti smrti dok ne vide Sina Čovječjega gdje dolazi sa svojim kraljevstvom.”"}]},"17":{"hr":[{"v":1,"t":"Nakon šest dana uze Isus sa sobom Petra, Jakova i Ivana, brata njegova, te ih povede na goru visoku, u osamu,"},{"v":2,"t":"i preobrazi se pred njima. I zasja mu lice kao sunce, a haljine mu postadoše bijele kao svjetlost."},{"v":3,"t":"I gle: ukazaše im se Mojsije i Ilija te razgovarahu s njime."},{"v":4,"t":"A Petar prihvati i reče Isusu: “Gospodine, dobro nam je ovdje biti. Ako hoćeš, načinit ću ovdje tri sjenice, tebi jednu, Mojsiju jednu i Iliji jednu.”"},{"v":5,"t":"Dok je on još govorio, gle, svijetao ih oblak zasjeni, a glas iz oblaka govoraše: “Ovo je Sin moj, Ljubljeni! U njemu mi sva milina! Slušajte ga!”"},{"v":6,"t":"Čuvši glas, učenici padoše licem na zemlju i silno se prestrašiše."},{"v":7,"t":"Pristupi k njima Isus, dotakne ih i reče: “Ustanite, ne bojte se!”"},{"v":8,"t":"Podigoše oči, ali ne vidješe nikoga doli Isusa sama."},{"v":9,"t":"Dok su silazili s gore, zapovjedi im Isus: “Nikomu ne kazujte viđenje dok Sin Čovječji od mrtvih ne uskrsne.”"},{"v":10,"t":"Upitaše ga učenici: “Što dakle pismoznanci govore da prije treba da dođe Ilija?”"},{"v":11,"t":"On im odgovori: “Ilija će doduše doći i sve obnoviti."},{"v":12,"t":"No velim vam: Ilija je već došao, ali ga ne upoznaše, već učiniše s njim što im se prohtjelo. Tako je i Sinu Čovječjemu trpjeti od njih.”"},{"v":13,"t":"Tada razumješe učenici da im to reče o Ivanu Krstitelju."},{"v":14,"t":"Kada dođoše k mnoštvu, pristupi mu čovjek, padne pred njim na koljena"},{"v":15,"t":"i reče: “Gospodine, smiluj se sinu mojemu jer je mjesečar i zlo mu je. Često doista pada u oganj i često u vodu."},{"v":16,"t":"Dovedoh ga tvojim učenicima i ne mogoše ga izliječiti.”"},{"v":17,"t":"A Isus odgovori: “O rode nevjerni i opaki! Dokle mi je biti s vama! Dokle li vas podnositi! Dovedite mi ga ovamo!”"},{"v":18,"t":"I zaprijeti Isus zloduhu te on iziđe iz njega. I ozdravi dječak toga časa."},{"v":19,"t":"Tada učenici pristupiše nasamo k Isusu i rekoše: “Zašto ga mi ne mogosmo izagnati?”"},{"v":20,"t":"Kaže im: “Zbog vaše malovjernosti. Zaista, kažem vam, ako imadnete vjere koliko je zrno gorušičino te reknete ovoj gori: 'Premjesti se odavde onamo!', premjestit će se i ništa vam neće biti nemoguće.”"},{"v":21,"t":"#"},{"v":22,"t":"A kad su se skupili u Galileji, reče im Isus: “Sin Čovječji ima biti predan ljudima u ruke"},{"v":23,"t":"i ubit će ga, ali on će treći dan uskrsnuti.” I ožalostiše se silno."},{"v":24,"t":"Kad stigoše u Kafarnaum, pristupe Petru oni što ubiru dvodrahme pa mu rekoše: “Učitelj vaš ne plaća dvodrahme?”"},{"v":25,"t":"“Plaća”, odgovori. A kad on uđe u kuću, pretekne ga Isus: “Što ti se čini, Šimune? Kraljevi zemaljski od koga ubiru carinu ili porez? Od svojih sinova ili od tuđih?”"},{"v":26,"t":"Kad on odgovori: “Od tuđih!”, reče mu Isus: “Sinovi su, dakle, oslobođeni."},{"v":27,"t":"Ali da ih ne sablaznimo, pođi k moru, baci udicu i prvu ribu koja naiđe uzmi, otvori joj usta i naći ćeš stater. Uzmi ga pa im ga podaj za me i za se.”"}]},"18":{"hr":[{"v":1,"t":"U onaj čas pristupe učenici Isusu pa ga zapitaju: “Tko je, dakle, najveći u kraljevstvu nebeskom?”"},{"v":2,"t":"On dozove dijete, postavi ga posred njih"},{"v":3,"t":"i reče: “Zaista, kažem vam, ako se ne obratite i ne postanete kao djeca, nećete ući u kraljevstvo nebesko."},{"v":4,"t":"Tko god se dakle ponizi kao ovo dijete, taj je najveći u kraljevstvu nebeskom."},{"v":5,"t":"I tko primi jedno ovakvo dijete u moje ime, mene prima.”"},{"v":6,"t":"“Onomu, naprotiv, tko bi sablaznio jednoga od ovih najmanjih što vjeruju u mene bilo bi bolje da mu se o vrat objesi mlinski kamen pa da potone u dubinu morsku.”"},{"v":7,"t":"“Jao svijetu od sablazni! Neizbježivo dolaze sablazni, ali jao čovjeku po kom dolazi sablazan."},{"v":8,"t":"Pa ako te ruka ili noga sablažnjava, odsijeci je i baci od sebe. Bolje ti je ući u život kljastu ili hromu, nego s obje ruke ili s obje noge biti bačen u oganj vječni."},{"v":9,"t":"I ako te oko sablažnjava, izvadi ga i baci od sebe. Bolje ti je jednooku u život ući, nego s oba oka biti bačen u pakao ognjeni.”"},{"v":10,"t":"“Pazite da ne prezrete ni jednoga od ovih najmanjih jer, kažem vam, anđeli njihovi na nebu uvijek gledaju lice Oca mojega, koji je na nebesima.”"},{"v":11,"t":"#"},{"v":12,"t":"“Što vam se čini? Ako neki čovjek imadne sto ovaca i jedna od njih zaluta, neće li on ostaviti onih devedeset i devet u gorama i poći u potragu za zalutalom?"},{"v":13,"t":"Posreći li mu se te je nađe, zaista, kažem vam, raduje se zbog nje više nego zbog onih devedeset i devet koje nisu zalutale."},{"v":14,"t":"Tako ni Otac vaš, koji je na nebesima, neće da propadne ni jedan od ovih malenih.”"},{"v":15,"t":"“Pogriješi li tvoj brat, idi i pokaraj ga nasamo."},{"v":16,"t":"Ako te posluša, stekao si brata. Ne posluša li te, uzmi sa sobom još jednoga ili dvojicu, neka na iskazu dvojice ili trojice svjedoka počiva svaka tvrdnja."},{"v":17,"t":"Ako ni njih ne posluša, reci Crkvi. Ako pak ni Crkve ne posluša, neka ti bude kao poganin i carinik.”"},{"v":18,"t":"“Zaista, kažem vam, što god svežete na zemlji, bit će svezano na nebu; i što god odriješite na zemlji, bit će odriješeno na nebu.”"},{"v":19,"t":"“Nadalje, kažem vam, ako dvojica od vas na zemlji jednodušno zaištu što mu drago, dat će im Otac moj, koji je na nebesima."},{"v":20,"t":"Jer gdje su dvojica ili trojica sabrana u moje ime, tu sam i ja među njima.”"},{"v":21,"t":"Tada pristupi k njemu Petar i reče: “Gospodine, koliko puta da oprostim bratu svomu ako se ogriješi o mene? Do sedam puta?”"},{"v":22,"t":"Kaže mu Isus: “Ne kažem ti do sedam puta, nego do sedamdeset puta sedam.”"},{"v":23,"t":"“Stoga je kraljevstvo nebesko kao kad kralj odluči urediti račune sa slugama."},{"v":24,"t":"Kad započe obračunavati, dovedoše mu jednoga koji mu dugovaše deset tisuća talenata."},{"v":25,"t":"Kako nije imao odakle vratiti, zapovjedi gospodar da se proda on, žena mu i djeca i sve što ima te se podmiri dug."},{"v":26,"t":"Nato sluga padne ničice preda nj govoreći: 'Strpljenja imaj sa mnom, i sve ću ti vratiti.'"},{"v":27,"t":"Gospodar se smilova tomu sluzi, otpusti ga i dug mu oprosti.”"},{"v":28,"t":"“A kad taj isti sluga izađe, naiđe na jednoga svoga druga koji mu dugovaše sto denara. Uhvati ga i stane ga daviti govoreći: 'Vrati što si dužan!'"},{"v":29,"t":"Drug padne preda nj i stane ga zaklinjati: 'Strpljenja imaj sa mnom i vratit ću ti.'"},{"v":30,"t":"Ali on ne htjede, nego ode i baci ga u tamnicu dok mu ne vrati duga.”"},{"v":31,"t":"“Kad njegovi drugovi vidješe što se dogodilo, silno ražalošćeni odoše i sve to dojaviše gospodaru."},{"v":32,"t":"Tada ga gospodar dozva i reče mu: 'Slugo opaki, sav sam ti onaj dug oprostio jer si me zamolio."},{"v":33,"t":"Nije li trebalo da se i ti smiluješ svome drugu, kao što sam se i ja tebi smilovao?'"},{"v":34,"t":"I gospodar ga, rasrđen, preda mučiteljima dok mu ne vrati svega duga."},{"v":35,"t":"Tako će i Otac moj nebeski učiniti s vama ako svatko od srca ne oprosti svomu bratu.”"}]},"19":{"hr":[{"v":1,"t":"Kad Isus završi ove besjede, ode iz Galileje i dođe u judejski kraj s onu stranu Jordana."},{"v":2,"t":"Za njim je išao silan svijet. Ondje ih izliječi."},{"v":3,"t":"Pristupe mu tada farizeji pa, da ga iskušaju, kažu: “Je li dopušteno otpustiti ženu s kojega god razloga?”"},{"v":4,"t":"On odgovori: “Zar niste čitali: Stvoritelj od početka muško i žensko stvori ih"},{"v":5,"t":"i reče: Stoga će čovjek ostaviti oca i majku da prione uza svoju ženu; i dvoje njih bit će jedno tijelo?"},{"v":6,"t":"Tako više nisu dvoje, nego jedno tijelo. Što, dakle, Bog združi, čovjek neka ne rastavlja.”"},{"v":7,"t":"Kažu mu: “Zašto onda Mojsije zapovjedi dati otpusno pismo i - otpustiti?”"},{"v":8,"t":"Odgovori im: “Zbog tvrdoće srca vašega dopusti vam Mojsije otpustiti žene, ali od početka ne bijaše tako."},{"v":9,"t":"A ja vam kažem: Tko otpusti svoju ženu - osim zbog bludništva - pa se oženi drugom, čini preljub.”"},{"v":10,"t":"Kažu mu učenici: “Ako je tako između muža i žene, bolje je ne ženiti se.”"},{"v":11,"t":"A on im reče: “Ne shvaćaju toga svi, nego samo oni kojima je dano."},{"v":12,"t":"Doista, ima za ženidbu nesposobnih koji se takvi iz utrobe materine rodiše. Ima nesposobnih koje ljudi onesposobiše. A ima nesposobnih koji sami sebe onesposobiše poradi kraljevstva nebeskoga. Tko može shvatiti, neka shvati.”"},{"v":13,"t":"Tada mu doniješe dječicu da na njih stavi ruke i pomoli se. A učenici im branili."},{"v":14,"t":"Nato će im Isus: “Pustite dječicu i ne priječite im k meni jer takvih je kraljevstvo nebesko!”"},{"v":15,"t":"I položi ruke na njih pa krene odande."},{"v":16,"t":"I gle, pristupi mu netko i reče: “Učitelju, koje mi je dobro činiti da imam život vječni?”"},{"v":17,"t":"A on mu reče: “Što me pitaš o dobrome? Jedan je samo dobar! Ali ako hoćeš u život ući, čuvaj zapovijedi.”"},{"v":18,"t":"Upita ga: “Koje?” A Isus reče: Ne ubij! Ne čini preljuba! Ne ukradi! Ne svjedoči lažno!"},{"v":19,"t":"Poštuj oca i majku! I ljubi svoga bližnjega kao sebe samoga!”"},{"v":20,"t":"Kaže mu mladić: “Sve sam to čuvao. Što mi još nedostaje?”"},{"v":21,"t":"Reče mu Isus: “Hoćeš li biti savršen, idi, prodaj što imaš i podaj siromasima pa ćeš imati blago na nebu. A onda dođi i idi za mnom.”"},{"v":22,"t":"Na tu riječ ode mladić žalostan jer imaše velik imetak."},{"v":23,"t":"A Isus reče svojim učenicima: “Zaista, kažem vas, teško će bogataš u kraljevstvo nebesko."},{"v":24,"t":"Ponovno vam velim: Lakše je devi kroz uši iglene nego bogatašu u kraljevstvo Božje.”"},{"v":25,"t":"Čuvši to, učenici se silno snebivahu govoreći: “Tko se onda može spasiti?”"},{"v":26,"t":"A Isus upre u njih pogled pa im reče: “Ljudima je to nemoguće, ali Bogu je sve moguće.”"},{"v":27,"t":"Tada Petar prihvati pa upita: “Evo, mi sve ostavismo i pođosmo za tobom. Što ćemo za to dobiti?”"},{"v":28,"t":"Reče im Isus: “Zaista, kažem vam, vi koji pođoste za mnom, o preporodu, kad Sin Čovječji sjedne na prijestolje svoje slave, i vi ćete sjediti na dvanaest prijestolja i suditi dvanaest plemena Izraelovih."},{"v":29,"t":"I tko god ostavi kuće, ili braću, ili sestre, ili oca, ili majku, ili ženu, ili djecu, ili polja poradi imena mojega, stostruko će primiti i život vječni baštiniti.”"},{"v":30,"t":"“A mnogi prvi bit će posljednji, i posljednji prvi.”"}]},"20":{"hr":[{"v":1,"t":"“Kraljevstvo je nebesko kao kad domaćin rano ujutro izađe najmiti radnike u svoj vinograd."},{"v":2,"t":"Pogodi se s radnicima po denar na dan i pošalje ih u svoj vinograd."},{"v":3,"t":"Izađe i o trećoj uri i vidje druge gdje stoje na trgu besposleni"},{"v":4,"t":"pa i njima reče: 'Idite i vi u moj vinograd pa što bude pravo, dat ću vam.'"},{"v":5,"t":"I oni odoše. Izađe opet o šestoj i devetoj uri te učini isto tako."},{"v":6,"t":"A kad izađe o jedanaestoj uri, nađe druge gdje stoje i reče im: 'Zašto ovdje stojite vazdan besposleni?'"},{"v":7,"t":"Kažu mu: 'Jer nas nitko ne najmi.' Reče im: 'Idite i vi u vinograd.'”"},{"v":8,"t":"“Uvečer kaže gospodar vinograda svojemu upravitelju: 'Pozovi radnike i podaj im plaću počevši od posljednjih pa sve do prvih.'"},{"v":9,"t":"Dođu tako oni od jedanaeste ure i prime po denar."},{"v":10,"t":"Pa kada dođu oni prvi, pomisle da će primiti više, ali i oni prime po denar."},{"v":11,"t":"A kad primiše, počeše mrmljati protiv domaćina:"},{"v":12,"t":"'Ovi posljednji jednu su uru radili i izjednačio si ih s nama, koji smo podnosili svu tegobu dana i žegu.'”"},{"v":13,"t":"“Nato on odgovori jednomu od njih: 'Prijatelju, ne činim ti krivo. Nisi li se pogodio sa mnom po denar?"},{"v":14,"t":"Uzmi svoje pa idi. A ja hoću i ovomu posljednjemu dati kao i tebi."},{"v":15,"t":"Nije li mi slobodno činiti sa svojim što hoću? Ili zar je oko tvoje zlo što sam ja dobar?'”"},{"v":16,"t":"“Tako će posljednji biti prvi, a prvi posljednji.”"},{"v":17,"t":"Dok je Isus uzlazio u Jeruzalem, uze dvanaestoricu nasamo te im putem reče:"},{"v":18,"t":"“Evo, uzlazimo u Jeruzalem i Sin Čovječji bit će predan glavarima svećeničkim i pismoznancima. Osudit će ga na smrt"},{"v":19,"t":"i predati poganima da ga izrugaju, izbičuju i razapnu, ali on će treći dan uskrsnuti.”"},{"v":20,"t":"Tada mu pristupi mati sinova Zebedejevih zajedno sa sinovima, pade ničice da od njega nešto zaište."},{"v":21,"t":"A on će joj: “Što želiš?” Kaže mu: “Reci da ova moja dva sina u tvome kraljevstvu sjednu uza te, jedan tebi zdesna, drugi slijeva.”"},{"v":22,"t":"Isus odgovori: “Ne znate što ištete. Možete li piti čašu koju ću ja piti?” Kažu mu: “Možemo!”"},{"v":23,"t":"A on im reče: “Čašu ćete moju doduše piti, ali sjesti meni zdesna ili slijeva - to nisam ja vlastan dati, to je onih kojima je pripravio moj Otac.”"},{"v":24,"t":"Kada su to čula ostala desetorica, razgnjeve se na dva brata."},{"v":25,"t":"Zato ih Isus dozva i reče: “Znate da vladari gospoduju svojim narodima i velikaši njihovi drže ih pod vlašću."},{"v":26,"t":"Neće tako biti među vama! Naprotiv, tko hoće da među vama bude najveći, neka vam bude poslužitelj."},{"v":27,"t":"I tko god hoće da među vama bude prvi, neka vam bude sluga.”"},{"v":28,"t":"“Tako i Sin Čovječji nije došao da bude služen, nego da služi i život svoj dade kao otkupninu za mnoge.”"},{"v":29,"t":"Kad su izlazili iz Jerihona, pođe za njim silan svijet."},{"v":30,"t":"I gle, dva slijepca sjeđahu kraj puta. Čuvši da Isus prolazi, povikaše: “Gospodine, smiluj nam se, Sine Davidov!”"},{"v":31,"t":"Mnoštvo ih ušutkivalo, ali oni još jače viknuše: “Gospodine, smiluj nam se, Sine Davidov!”"},{"v":32,"t":"Isus se zaustavi, dozove ih i reče: “Što hoćete da vam učinim?”"},{"v":33,"t":"Kažu mu: “Gospodine, da nam se otvore oči.”"},{"v":34,"t":"Isus se ganut dotače njihovim očiju i oni odmah progledaše. I pođoše za njim."}]},"21":{"hr":[{"v":1,"t":"Kad se približiše Jeruzalemu te dođoše u Betfagu, na Maslinskoj gori, posla Isus dvojicu učenika"},{"v":2,"t":"govoreći: “Pođite u selo pred vama i odmah ćete naći privezanu magaricu i uz nju magare. Odriješite ih i dovedite k meni."},{"v":3,"t":"Ako vam tko što rekne, recite: 'Gospodinu trebaju', i odmah će ih pustiti.”"},{"v":4,"t":"To se dogodi da se ispuni što je rečeno po proroku:"},{"v":5,"t":"Recite kćeri Sionskoj: Evo kralj ti tvoj dolazi, krotak, jašuć na magarcu, na magaretu, mladetu magaričinu."},{"v":6,"t":"Učenici odu i učine kako im naredi Isus."},{"v":7,"t":"Dovedu magaricu i magare te stave na njih haljine i Isus uzjaha na njih."},{"v":8,"t":"Silan svijet prostrije svoje haljine po putu, a drugi rezahu grane sa stabala i sterahu ih po putu."},{"v":9,"t":"Mnoštvo pak pred njim i za njim klicaše: “Hosana Sinu Davidovu! Blagoslovljen Onaj koji dolazi u ime Gospodnje! Hosana u visinama!”"},{"v":10,"t":"Kad uđe u Jeruzalem, uskomešao se sav grad i govorio: “Tko je ovaj?”"},{"v":11,"t":"A mnoštvo odgovaraše: “To je Prorok, Isus iz Nazareta galilejskoga.”"},{"v":12,"t":"Isus uđe u Hram i izagna sve koji su prodavali i kupovali u Hramu. Mjenjačima isprevrta stolove i prodavačima golubova klupe."},{"v":13,"t":"Kaže im: “Pisamo je: Dom će se moj zvati Dom molitve, a vi od njega činite pećinu razbojničku.”"},{"v":14,"t":"U Hramu mu priđoše slijepi i hromi i on ih ozdravi."},{"v":15,"t":"A kad glavari svećenički i pismoznanci vidješe čudesa koja učini i djecu što viču Hramom: “Hosana Sinu Davidovu!”, gnjevni"},{"v":16,"t":"mu rekoše: “Čuješ li što ovi govore?” Kaže im Isus: “Da! A niste li čitali: Iz usta djece i dojenčadi sebi si pripravio hvalu?”"},{"v":17,"t":"On ih ostavi, pođe iz grada u Betaniju te ondje prenoći."},{"v":18,"t":"Ujutro se vraćao u grad i ogladnje."},{"v":19,"t":"Ugleda smokvu kraj puta i priđe k njoj, ali ne nađe na njoj ništa osim lišća pa joj kaže: “Ne bilo više ploda s tebe dovijeka!” I smokva umah usahnu."},{"v":20,"t":"Vidjevši to, učenici se začude: “Kako umah smokva usahnu!”"},{"v":21,"t":"Isus im odvrati: “Zaista, kažem vam, ako budete imali vjeru i ne posumnjate, činit ćete ne samo ovo sa smokvom, nego - reknete li i ovoj gori: 'Digni se i baci u more!', bit će tako."},{"v":22,"t":"I sve što zaištete u molitvi vjerujući, primit ćete.”"},{"v":23,"t":"I uđe u Hram. Dok je naučavao, pristupiše mu glavari svećenički i starješine narodne te ga upitaše: “Kojom vlašću to činiš? Tko ti dade tu vlast?”"},{"v":24,"t":"Isus im odgovori: “I ja ću vas jedno upitati. Ako mi na to odgovorite, ja ću vama kazati kojom vlašću ovo činim."},{"v":25,"t":"Krst Ivanov odakle li bijaše? Od Neba ili od ljudi?” A oni umovahu među sobom: “Reknemo li 'Od Neba', odvratit će nam: 'Zašto mu, dakle, ne povjerovaste?'"},{"v":26,"t":"A reknemo li 'Od ljudi', strah nas je mnoštva. Ta svi Ivana smatraju prorokom.”"},{"v":27,"t":"Zato odgovore Isusu: “Ne znamo.” I on njima reče: “Ni ja vama neću kazati kojom vlašću ovo činim.”"},{"v":28,"t":"“A što vam se čini? Čovjek neki imao dva sina. Priđe prvomu i reče: 'Sinko, hajde danas na posao u vinograd!'"},{"v":29,"t":"On odgovori: 'Neću!' No poslije se predomisli i ode."},{"v":30,"t":"Priđe i drugomu pa mu reče isto tako. A on odgovori: 'Evo me, gospodaru!' i ne ode."},{"v":31,"t":"Koji od te dvojice izvrši volju očevu?” Kažu: “Onaj prvi.” Nato će im Isus: “Zaista, kažem vam, carinici i bludnice pretekoše vas u kraljevstvo Božje!"},{"v":32,"t":"Doista, Ivan dođe k vama putom pravednosti i vi mu ne povjerovaste, a carinici mu i bludnice povjerovaše. Vi pak, makar to vidjeste, ni kasnije se ne predomisliste da mu povjerujete.”"},{"v":33,"t":"“Drugu prispodobu čujte! Bijaše neki domaćin koji posadi vinograd, ogradi ga ogradom, iskopa u njemu tijesak i podiže kulu pa ga iznajmi vinogradarima i otputova."},{"v":34,"t":"Kad se približilo vrijeme plodova, posla svoje sluge vinogradarima da uzmu njegov urod."},{"v":35,"t":"A vinogradari pograbe njegove sluge pa jednoga istukoše, drugog ubiše, a trećega kamenovaše."},{"v":36,"t":"I opet posla druge sluge, više njih nego prije, ali oni i s njima postupiše jednako.”"},{"v":37,"t":"“Naposljetku posla k njima sina svoga misleći: 'Poštovat će mog sina.'"},{"v":38,"t":"Ali kad vinogradari ugledaju sina, rekoše među sobom: 'Ovo je baštinik! Hajde da ga ubijemo i imat ćemo baštinu njegovu!'"},{"v":39,"t":"I pograbe ga, izbace iz vinograda i ubiju.”"},{"v":40,"t":"“Kada dakle dođe gospodar vinograda, što će učiniti s tim vinogradarima?”"},{"v":41,"t":"Kažu mu: “Opake će nemilo pogubiti, a vinograd iznajmiti drugim vinogradarima što će mu davati urod u svoje vrijeme.”"},{"v":42,"t":"Kaže im Isus: “Zar nikada niste čitali u Pismima: Kamen što ga odbaciše graditelji postade kamen zaglavni. Gospodnje je to djelo - kakvo čudo u očima našim!"},{"v":43,"t":"Zato će se - kažem vam - oduzeti od vas kraljevstvo Božje i dat će se narodu koji donosi njegove plodove! ("},{"v":44,"t":"I tko padne na taj kamen, smrskat će se, a na koga on padne, satrt će ga.)”"},{"v":45,"t":"Kad su glavari svećenički i farizeji čuli te njegove prispodobe, razumjeli su da govori o njima."},{"v":46,"t":"I tražili su da ga uhvate, ali se pobojaše mnoštva jer ga je smatralo prorokom."}]},"22":{"hr":[{"v":1,"t":"Isus im ponovno prozbori u prispodobama:"},{"v":2,"t":"“Kraljevstvo je nebesko kao kad neki kralj pripravi svadbu sinu svomu."},{"v":3,"t":"Posla sluge da pozovu uzvanike na svadbu. No oni ne htjedoše doći."},{"v":4,"t":"Opet posla druge sluge govoreći: 'Recite uzvanicima: Evo, objed sam ugotovio. Junci su moji i tovljenici poklani i sve pripravljeno. Dođite na svadbu!'”"},{"v":5,"t":"“Ali oni ne mareći odoše - jedan na svoju njivu, drugi za svojom trgovinom."},{"v":6,"t":"Ostali uhvate njegove sluge, zlostave ih i ubiju."},{"v":7,"t":"Nato se kralj razgnjevi, posla svoju vojsku i pogubi one ubojice, a grad im spali.”"},{"v":8,"t":"“Tada kaže slugama: 'Svadba je, evo, pripravljena ali uzvanici ne bijahu dostojni."},{"v":9,"t":"Pođite stoga na raskršća i koga god nađete, pozovite na svadbu!'”"},{"v":10,"t":"“Sluge iziđoše na putove i sabraše sve koje nađoše - i zle i dobre. I svadbena se dvorana napuni gostiju."},{"v":11,"t":"Kad kralj uđe pogledati goste, spazi ondje čovjeka koji ne bijaše odjeven u svadbeno ruho."},{"v":12,"t":"Kaže mu: 'Prijatelju, kako si ovamo ušao bez svadbenoga ruha?' A on zanijemi."},{"v":13,"t":"Tada kralj reče poslužiteljima: 'Svežite mu ruke i noge i bacite ga van u tamu, gdje će biti plač i škrgut zubi.'"},{"v":14,"t":"Doista, mnogo je zvanih, malo izabranih.”"},{"v":15,"t":"Tada farizeji odoše i održaše vijeće kako da Isusa uhvate u riječi."},{"v":16,"t":"Pošalju k njemu svoje učenike s herodovcima da ga upitaju: “Učitelju! Znamo da si istinit te po istini putu Božjem učiš i ne mariš tko je tko jer nisi pristran."},{"v":17,"t":"Reci nam, dakle, što ti se čini: je li dopušteno dati porez caru ili nije?”"},{"v":18,"t":"Znajući njihovu opakost, reče Isus: “Zašto me iskušavate, licemjeri?"},{"v":19,"t":"Pokažite mi porezni novac!” Pružiše mu denar."},{"v":20,"t":"On ih upita: “Čija je ovo slika i natpis?”"},{"v":21,"t":"Odgovore: “Carev.” Kaže im: “Podajte dakle caru carevo, a Bogu Božje.”"},{"v":22,"t":"Čuvši to, zadive se pa ga ostave i odu."},{"v":23,"t":"Toga dana pristupiše k njemu saduceji, koji vele da nema uskrsnuća, i upitaše ga:"},{"v":24,"t":"“Učitelju, Mojsije reče: Umre li tko bez djece, neka se njegov brat oženi njegovom ženom te podigne porod bratu svomu."},{"v":25,"t":"Bijaše tako u nas sedmero braće. Prvi se oženi i umrije bez poroda ostavivši ženu svom bratu."},{"v":26,"t":"Tako i drugi i treći, sve do sedmoga."},{"v":27,"t":"A nakon svih umrije i žena."},{"v":28,"t":"Kojemu će dakle od te sedmorice biti žena o uskrsnuću? Jer sva su je sedmorica imala.”"},{"v":29,"t":"Odgovori im Isus: “U zabludi ste jer ne razumijete Pisama ni sile Božje."},{"v":30,"t":"Ta u uskrsnuću niti se žene niti udavaju, nego su kao anđeli na nebu."},{"v":31,"t":"A što se tiče uskrsnuća mrtvih, zar niste čitali što vam reče Bog:"},{"v":32,"t":"Ja sam Bog Abrahamov, Bog Izakov i Bog Jakovljev? Nije on Bog mrtvih, nego živih!”"},{"v":33,"t":"Čuvši to, mnoštvo osta zaneseno njegovim naukom."},{"v":34,"t":"A kad su farizeji čuli kako ušutka saduceje, okupiše se,"},{"v":35,"t":"a jedan od njih, zakonoznanac, da ga iskuša, upita:"},{"v":36,"t":"“Učitelju, koja ja zapovijed najveća u Zakonu?”"},{"v":37,"t":"A on mu reče: “Ljubi Gospodina Boga svojega svim srcem svojim, i svom dušom svojom, i svim umom svojim."},{"v":38,"t":"To je najveća i prva zapovijed."},{"v":39,"t":"Druga, ovoj slična: Ljubi svoga bližnjega kao sebe samoga."},{"v":40,"t":"O tim dvjema zapovijedima visi sav Zakon i Proroci.”"},{"v":41,"t":"Kad se farizeji skupiše, upita ih Isus:"},{"v":42,"t":"“Što mislite o Kristu? Čiji je on sin?” Kažu mu: “Davidov.”"},{"v":43,"t":"A on će njima: “Kako ga onda David u Duhu naziva Gospodinom, kad veli:"},{"v":44,"t":"Reče Gospod Gospodinu mojemu: 'Sjedi mi zdesna dok ne položim neprijatelje tvoje za podnožje nogama tvojim?'"},{"v":45,"t":"Ako ga dakle David naziva Gospodinom, kako mu je sin?”"},{"v":46,"t":"I nitko mu nije mogao odgovoriti ni riječi, niti se od toga dana tko usudio upitati ga bilo što."}]},"23":{"hr":[{"v":1,"t":"Tada Isus prozbori mnoštvu i svojim učenicima:"},{"v":2,"t":"“Na Mojsijevu stolicu zasjedoše pismoznanci i farizeji."},{"v":3,"t":"Činite dakle i obdržavajte sve što vam kažu, ali se nemojte ravnati po njihovim djelima jer govore, a ne čine."},{"v":4,"t":"Vežu i ljudima na pleća tovare teška bremena, a sami ni da bi ih prstom makli."},{"v":5,"t":"Sva svoja djela čine zato da ih ljudi vide. Doista, proširuju zapise svoje i produljuju rese."},{"v":6,"t":"Vole pročelja na gozbama, prva sjedala u sinagogama,"},{"v":7,"t":"pozdrave na trgovima i da ih ljudi zovu 'Rabbi'."},{"v":8,"t":"Vi pak ne dajte se zvati 'Rabbi', jer jedan je učitelj vaš, a svi ste vi braća."},{"v":9,"t":"Ni ocem ne zovite nikoga na zemlji jer jedan je Otac vaš - onaj na nebesima."},{"v":10,"t":"I ne dajte da vas vođama zovu, jer jedan je vaš vođa - Krist."},{"v":11,"t":"Najveći među vama neka vam bude poslužitelj."},{"v":12,"t":"Tko se god uzvisuje, bit će ponižen, a tko se ponizuje, bit će uzvišen.”"},{"v":13,"t":"“Jao vama, pismoznanci i farizeji! Licemjeri! Zaključavate kraljevstvo nebesko pred ljudima; sami ne ulazite, a ne date ući ni onima koji bi htjeli.”"},{"v":14,"t":"#"},{"v":15,"t":"“Jao vama, pismoznanci i farizeji! Licemjeri! Obilazite morem i kopnom da pridobijete jednog sljedbenika. A kad ga pridobijete, promećete ga u sina paklenoga dvaput goreg od sebe.”"},{"v":16,"t":"“Jao vama! Slijepe vođe! Govorite: 'Zakune li se tko Hramom, nije ništa. Ali ako se zakune hramskim zlatom, veže ga zakletva.'"},{"v":17,"t":"Budale i slijepci! Ta što je veće: zlato ili Hram što posvećuje zlato?"},{"v":18,"t":"Nadalje: 'Zakune li se tko žrtvenikom, nije ništa. Ali ako se zakune darom što je na njemu, veže ga zakletva.'"},{"v":19,"t":"Slijepci! Ta što je veće: dar ili žrtvenik što dar posvećuje?"},{"v":20,"t":"Tko se dakle zakune žrtvenikom, kune se njime i svime što je na njemu."},{"v":21,"t":"I tko se zakune Hramom, kune se njime i Onim koji u njemu prebiva."},{"v":22,"t":"I tko se zakune nebom, kune se prijestoljem Božjim i Onim koji na njemu sjedi.”"},{"v":23,"t":"“Jao vama, pismoznanci i farizeji! Licemjeri! Namirujete desetinu od metvice i kopra i kima, a propuštate najvažnije u Zakonu: pravednost, milosrđe, vjernost. Ovo je trebalo činiti, a ono ne propuštati."},{"v":24,"t":"Slijepe vođe! Cijedite komarca, a gutate devu!”"},{"v":25,"t":"“Jao vama, pismoznanci i farizeji! Licemjeri! Čistite čašu i zdjelu izvana, a iznutra su pune grabeža i pohlepe."},{"v":26,"t":"Farizeju slijepi! Očisti najprije nutrinu čaše da joj i vanjština bude čista.”"},{"v":27,"t":"Jao vama pismoznanci i farizeji! Licemjeri! Nalik ste na obijeljene grobove. Izvana izgledaju lijepi, a iznutra su puni mrtvačkih kostiju i svakojake nečistoće."},{"v":28,"t":"Tako i vi izvana ljudima izgledate pravedni, a iznutra ste puni licemjerja i bezakonja.”"},{"v":29,"t":"“Jao vama, pismoznanci i farizeji! Licemjeri! Gradite grobnice prorocima i kitite spomenike pravednicima"},{"v":30,"t":"te govorite: 'Da smo mi živjeli u dane otaca svojih, ne bismo bili njihovi sudionici u prolijevanju krvi proročke.'"},{"v":31,"t":"Tako sami protiv sebe svjedočite da ste sinovi ubojica proroka."},{"v":32,"t":"Dopunite samo mjeru otaca svojih!”"},{"v":33,"t":"“Zmije! Leglo gujinje! Kako ćete uteći osudi paklenoj?"},{"v":34,"t":"Zato evo ja šaljem vama proroke i mudrace i pismoznance. Jedne ćete od njih ubiti i raspeti, druge bičevati po svojim sinagogama i progoniti od grada do grada"},{"v":35,"t":"da tako na vas dođe sva pravedna krv, prolivena na zemlji od krvi Abela pravednoga pa do krvi Zaharije, sina Barahijina, kojega ubiste između Hrama i žrtvenika."},{"v":36,"t":"Zaista, kažem vam, sve će to doći na ovaj naraštaj!”"},{"v":37,"t":"“Jeruzaleme, Jeruzaleme, koji ubijaš proroke i kamenuješ one što su tebi poslani! Koliko li puta htjedoh okupiti djecu tvoju kao što kvočka okuplja piliće pod krila, i ne htjedoste."},{"v":38,"t":"Evo, napuštena vam kuća."},{"v":39,"t":"Doista, kažem vam, odsada me nećete vidjeti dok ne reknete: Blagoslovljen Onaj koji dolazi u ime Gospodnje!”"}]},"24":{"hr":[{"v":1,"t":"Isus iziđe iz Hrama. Putom mu pristupiše učenici pokazujući mu hramsko zdanje."},{"v":2,"t":"A on im reče: “Ne vidite li sve ovo? Zaista, kažem vam, ne, neće se ovdje ostaviti ni kamen na kamenu nerazvaljen.”"},{"v":3,"t":"Dok je zatim na Maslinskoj gori sjedio, pristupiše k njemu učenici nasamo govoreći: “Reci nam kada će to biti i koji će biti znak tvojega Dolaska i svršetka svijeta?”"},{"v":4,"t":"Isus im odgovori: “Pazite da vas tko ne zavede!"},{"v":5,"t":"Mnogi će doista doći u moje ime i govoriti: 'Ja sam Krist!' I mnoge će zavesti.”"},{"v":6,"t":"“A čut ćete za ratove i za glasove o ratovima. Pazite, ne uznemirujte se. Doista treba da se to dogodi, ali to još nije svršetak."},{"v":7,"t":"Narod će ustati protiv naroda i kraljevstvo protiv kraljevstva; bit će gladi i potresa po raznim mjestima."},{"v":8,"t":"Ali sve je to samo početak trudova.”"},{"v":9,"t":"“Tada će vas predavati na muke i ubijati vas. I svi će vas narodi zamrziti zbog imena moga."},{"v":10,"t":"Mnogi će se tada sablazniti, izdavat će jedni druge i mrziti se među sobom."},{"v":11,"t":"Ustat će mnogi lažni proroci i mnoge zavesti."},{"v":12,"t":"Razmahat će se bezakonje i ohladnjeti ljubav mnogih."},{"v":13,"t":"Ali tko ustraje do svršetka, bit će spašen.”"},{"v":14,"t":"“I propovijedat će se ovo evanđelje Kraljevstva po svem svijetu za svjedočanstvo svim narodima. Tada će doći svršetak.”"},{"v":15,"t":"“Kada dakle vidite da grozota pustoši, po proroštvu Daniela proroka, stoluje na svetome mjestu - tko čita, neka razumije:"},{"v":16,"t":"koji se tada zateknu u Judeji, neka bježe u gore;"},{"v":17,"t":"tko bude na krovu, neka ne silazi uzeti što iz kuće;"},{"v":18,"t":"i tko bude u polju, neka se ne okreće natrag da uzme haljinu!”"},{"v":19,"t":"“A jao trudnicama i dojiljama u one dane!”"},{"v":20,"t":"“I molite da bijeg vaš ne bude zimi ili subotom"},{"v":21,"t":"jer tada će biti velika tjeskoba kakve ne bijaše od početka svijeta sve do sada, a neće je ni biti.”"},{"v":22,"t":"“I kad se ne bi skratili dani oni, nitko se ne bi spasio. No poradi izabranih skratit će se dani oni.”"},{"v":23,"t":"“Ako vam tada tko rekne: 'Gle, evo Krista!' ili: 'Eno ga!' - ne povjerujte!"},{"v":24,"t":"Ustat će, doista, lažni kristi i lažni proroci i iznijeti znamenja velika i čudesa da, bude li moguće, zavedu i izabrane.”"},{"v":25,"t":"“Eto, prorekao sam vam.”"},{"v":26,"t":"“Reknu li vam dakle: 'Evo, u pustinji je!', ne izlazite; 'Evo ga u ložnicama!', ne vjerujte."},{"v":27,"t":"Jer kao što munja izlazi od istoka i bljesne do zapada, tako će biti i s dolaskom Sina Čovječjega.”"},{"v":28,"t":"“Gdje bude strvine, ondje će se skupljati orlovi.”"},{"v":29,"t":"“A odmah nakon nevolje onih dana sunce će pomrčati i mjesec neće više svijetljeti i zvijezde će s neba padati i sile će se nebeske poljuljati.”"},{"v":30,"t":"“I tada će se pojaviti znak Sina Čovječjega na nebu. I tada će proplakati sva plemena zemlje. I ugledat će Sina Čovječjega gdje dolazi na oblacima nebeskim s velikom moći i slavom."},{"v":31,"t":"I razaslat će anđele svoje s trubljom velikom i sabrat će mu izabranike s četiri vjetra, s jednoga kraja neba do drugoga.”"},{"v":32,"t":"“A od smokve se naučite prispodobi! Kad joj grana već omekša i lišće potjera, znate: blizu je ljeto."},{"v":33,"t":"Tako i vi kad sve to ugledate, znajte: blizu je, na vratima!”"},{"v":34,"t":"“Zaista, kažem vam, ne, neće uminuti naraštaj ovaj dok se sve to ne zbude."},{"v":35,"t":"Nebo će i zemlja uminuti, ali riječi moje ne, neće uminuti.”"},{"v":36,"t":"“A o onom danu i času nitko ne zna, pa ni anđeli nebeski, ni Sin, nego samo Otac."},{"v":37,"t":"Kao u dane Noine, tako će biti i Dolazak Sina Čovječjega."},{"v":38,"t":"Kao što su u dane one - prije potopa - jeli i pili, ženili se i udavali do dana kad Noa uđe u korablju"},{"v":39,"t":"i ništa nisu ni slutili dok ne dođe potop i sve odnije - tako će biti i Dolazak Sina Čovječjega."},{"v":40,"t":"Dvojica će tada biti u polju: jedan će se uzeti, drugi ostaviti."},{"v":41,"t":"Dvije će mljeti u mlinu: jedna će se uzeti, druga ostaviti.”"},{"v":42,"t":"“Bdijte dakle jer ne znate u koji dan Gospodin vaš dolazi."},{"v":43,"t":"A ovo znajte: kad bi domaćin znao o kojoj straži kradljivac dolazi, bdio bi i ne bi dopustio potkopati kuće."},{"v":44,"t":"Zato i vi budite pripravni jer u čas kad i ne mislite Sin Čovječji dolazi.”"},{"v":45,"t":"“Tko li je onaj vjerni i razumni sluga što ga gospodar postavi nad svojim ukućanima da im izda hranu u pravo vrijeme?"},{"v":46,"t":"Blago onome sluzi kojega gospodar kada dođe nađe da tako radi!"},{"v":47,"t":"Zaista, kažem vam, postavit će ga nad svim imanjem svojim.”"},{"v":48,"t":"“No rekne li taj zli sluga u srcu: 'Okasnit će gospodar moj'"},{"v":49,"t":"pa stane tući sudrugove, jesti i piti s pijanicama,"},{"v":50,"t":"doći će gospodar toga sluge u dan u koji mu se ne nada i u čas u koji i ne sluti;"},{"v":51,"t":"rasjeći će ga i dodijeliti mu udes među licemjerima. Ondje će biti plač i škrgut zubi.”"}]},"25":{"hr":[{"v":1,"t":"“Tada će kraljevstvo nebesko biti kao kad deset djevica uzeše svoje svjetiljke i iziđoše u susret zaručniku."},{"v":2,"t":"Pet ih bijaše ludih, a pet mudrih."},{"v":3,"t":"Lude uzeše svjetiljke, ali ne uzeše sa sobom ulja."},{"v":4,"t":"Mudre pak zajedno sa svjetiljkama uzeše u posudama ulja.”"},{"v":5,"t":"“Budući da je zaručnik okasnio, sve one zadrijemaše i pozaspaše."},{"v":6,"t":"O ponoći nasta vika: 'Evo zaručnika! Iziđite mu u susret!'"},{"v":7,"t":"Tada ustadoše sve one djevice i urediše svoje svjetiljke."},{"v":8,"t":"Lude tada rekoše mudrima: 'Dajte nam od svoga ulja, gase nam se svjetiljke!'"},{"v":9,"t":"Mudre im odgovore: 'Nipošto! Ne bi doteklo nama i vama. Pođite radije k prodavačima i kupite!'”"},{"v":10,"t":"“Dok one odoše kupiti, dođe zaručnik: koje bijahu pripravne, uđoše s njim na svadbu i zatvore se vrata."},{"v":11,"t":"Poslije dođu i ostale djevice pa stanu dozivati: 'Gospodine! Gospodine! Otvori nam!'"},{"v":12,"t":"A on im odgovori: 'Zaista kažem vam, ne poznam vas!'"},{"v":13,"t":"Bdijte dakle jer ne znate dana ni časa!”"},{"v":14,"t":"“Doista, kao kad ono čovjek, polazeći na put, dozva sluge i dade im svoj imetak."},{"v":15,"t":"Jednomu dade pet talenata, drugomu dva, a trećemu jedan - svakomu po njegovoj sposobnosti."},{"v":16,"t":"I otputova. Onaj koji je primio pet talenata odmah ode, upotrijebi ih i stekne drugih pet."},{"v":17,"t":"Isto tako i onaj sa dva stekne druga dva."},{"v":18,"t":"Onaj naprotiv koji je primio jedan ode, otkopa zemlju i sakri novac gospodarov.”"},{"v":19,"t":"“Nakon dugo vremena dođe gospodar tih slugu i zatraži od njih račun."},{"v":20,"t":"Pristupi mu onaj što je primio pet talenata i donese drugih pet govoreći: 'Gospodaru! Pet si mi talenata predao. Evo, drugih sam pet talenata stekao!'"},{"v":21,"t":"Reče mu gospodar: 'Valjaš, slugo dobri i vjerni! U malome si bio vjeran, nad mnogim ću te postaviti! Uđi u radost gospodara svoga!'”"},{"v":22,"t":"“Pristupi i onaj sa dva talenta te reče: 'Gospodaru! Dva si mi talenta predao. Evo, druga sam dva talenta stekao!'"},{"v":23,"t":"Reče mu gospodar: 'Valjaš, slugo dobri i vjerni! U malome si bio vjeran, nad mnogim ću te postaviti! Uđi u radost gospodara svoga.'”"},{"v":24,"t":"“A pristupi i onaj koji je primio jedan talenat te reče: 'Gospodaru! Znadoh te: čovjek si strog, žanješ gdje nisi sijao i kupiš gdje nisi vijao."},{"v":25,"t":"Pobojah se stoga, odoh i sakrih talenat tvoj u zemlju. Evo ti tvoje!'"},{"v":26,"t":"A gospodar mu reče: 'Slugo zli i lijeni! Znao si da žanjem gdje nisam sijao i kupim gdje nisam vijao!"},{"v":27,"t":"Trebalo je dakle da uložiš moj novac kod novčara i ja bih po povratku izvadio svoje s dobitkom.'”"},{"v":28,"t":"“'Uzmite stoga od njega talenat i podajte onomu koji ih ima deset."},{"v":29,"t":"Doista, onomu koji ima još će se dati, neka ima u izobilju, a od onoga koji nema oduzet će se i ono što ima."},{"v":30,"t":"A beskorisnoga slugu izbacite van u tamu. Ondje će biti plač i škrgut zubi.'”"},{"v":31,"t":"“Kad Sin Čovječji dođe u slavi i svi anđeli njegovi s njime, sjest će na prijestolje slave svoje."},{"v":32,"t":"I sabrat će se pred njim svi narodi, a on će ih jedne od drugih razlučiti kao što pastir razlučuje ovce od jaraca."},{"v":33,"t":"Postavit će ovce sebi zdesna, a jarce slijeva.”"},{"v":34,"t":"“Tada će kralj reći onima sebi zdesna: 'Dođite, blagoslovljeni Oca mojega! Primite u baštinu Kraljevstvo pripravljeno za vas od postanka svijeta!"},{"v":35,"t":"Jer ogladnjeh i dadoste mi jesti; ožednjeh i napojiste me; stranac bijah i primiste me;"},{"v":36,"t":"gol i zaogrnuste me; oboljeh i pohodiste me; u tamnici bijah i dođoste k meni.'”"},{"v":37,"t":"“Tada će mu pravednici odgovoriti: 'Gospodine, kada te to vidjesmo gladna i nahranismo te; ili žedna i napojismo te?"},{"v":38,"t":"Kada te vidjesmo kao stranca i primismo; ili gola i zaogrnusmo te?"},{"v":39,"t":"Kada te vidjesmo bolesna ili u tamnici i dođosmo k tebi?'"},{"v":40,"t":"A kralj će im odgovoriti: 'Zaista, kažem vam, što god učiniste jednomu od ove moje najmanje braće, meni učiniste!'”"},{"v":41,"t":"“Zatim će reći i onima slijeva: 'Odlazite od mene, prokleti, u oganj vječni, pripravljen đavlu i anđelima njegovim!"},{"v":42,"t":"Jer ogladnjeh i ne dadoste mi jesti; ožednjeh i ne dadoste mi piti;"},{"v":43,"t":"stranac bijah i ne primiste me; gol i ne zaogrnuste me; bolestan i u tamnici i ne pohodiste me!'”"},{"v":44,"t":"“Tada će mu i oni odgovoriti: 'Gospodine, a kada te to vidjesmo gladna, ili žedna, ili stranca, ili gola, ili bolesna, ili u tamnici, i ne poslužismo te?'"},{"v":45,"t":"Tada će im on odgovoriti: 'Zaista, kažem vam, što god ne učiniste jednomu od ovih najmanjih, ni meni ne učiniste.'”"},{"v":46,"t":"“I otići će ovi u muku vječnu, a pravednici u život vječni.”"}]},"26":{"hr":[{"v":1,"t":"I kad Isus završi sve te besjede, reče svojim učenicima:"},{"v":2,"t":"“Znate da je za dva dana Pasha, i Sin Čovječji predaje se da se razapne.”"},{"v":3,"t":"Uto se sabraše glavari svećenički i starješine narodne u dvoru velikoga svećenika imenom Kajfe"},{"v":4,"t":"i zaključiše Isusa na prijevaru uhvatiti i ubiti."},{"v":5,"t":"Jer se govorilo: “Nikako ne o Blagdanu da ne nastane pobuna u narodu.”"},{"v":6,"t":"Kad je Isus bio u Betaniji, u kući Šimuna Gubavca,"},{"v":7,"t":"pristupi mu neka žena s alabastrenom posudicom skupocjene pomasti i polije ga po glavi, dok je on bio za stolom."},{"v":8,"t":"Vidjevši to, učenici negodovahu: “Čemu ta rasipnost?"},{"v":9,"t":"Moglo se to skupo prodati i dati siromasima.”"},{"v":10,"t":"Zapazio to Isus pa im reče: “Što dodijavate ženi? Dobro djelo učini prema meni."},{"v":11,"t":"Ta siromaha svagda imate uza se, a mene nemate svagda."},{"v":12,"t":"Izlila je tu pomast na moje tijelo - za ukop mi to učini."},{"v":13,"t":"Zaista, kažem vam, gdje se god bude propovijedalo ovo evanđelje, po svem svijetu, navješćivat će se i ovo što ona učini - njoj na spomen.”"},{"v":14,"t":"Tada jedan od dvanaestorice, zvan Juda Iškariotski, pođe glavarima svećeničkim"},{"v":15,"t":"i reče: “Što ćete mi dati i ja ću vam ga predati.” A oni mu odmjeriše trideset srebrnjaka."},{"v":16,"t":"Otada je tražio priliku da ga preda."},{"v":17,"t":"Prvoga dana Beskvasnih kruhova pristupiše učenici Isusu i upitaše: “Gdje hoćeš da ti pripravimo te blaguješ pashu?”"},{"v":18,"t":"On reče: “Idite u grad tomu i tomu i recite mu: 'Učitelj veli: Vrijeme je moje blizu, kod tebe slavim pashu sa svojim učenicima.'”"},{"v":19,"t":"I učine učenici kako im naredi Isus i priprave pashu."},{"v":20,"t":"Uvečer bijaše Isus za stolom s dvanaestoricom."},{"v":21,"t":"I dok su blagovali, reče: “Zaista, kažem vam, jedan će me od vas izdati.”"},{"v":22,"t":"Silno ožalošćeni, stanu mu jedan za drugim govoriti: “Da nisam ja, Gospodine?”"},{"v":23,"t":"On odgovori: “Onaj koji umoči sa mnom ruku u zdjelu, taj će me izdati."},{"v":24,"t":"Sin Čovječji, istina, odlazi kako je o njemu pisano, ali jao čovjeku onomu koji predaje Sina Čovječjega. Tomu bi čovjeku bolje bilo da se ni rodio nije.”"},{"v":25,"t":"A Juda, izdajnik, prihvati i reče: “Da nisam ja, učitelju?” Reče mu: “Ti kaza.”"},{"v":26,"t":"I dok su blagovali, uze Isus kruh, izreče blagoslov pa razlomi, dade svojim učenicima i reče: “Uzmite i jedite! Ovo je tijelo moje!”"},{"v":27,"t":"I uze čašu, zahvali i dade im govoreći: “Pijte iz nje svi!"},{"v":28,"t":"Ovo je krv moja, krv Saveza koja se za mnoge prolijeva na otpuštenje grijeha."},{"v":29,"t":"A kažem vam: ne, neću od sada piti od ovog roda trsova do onoga dana kad ću ga - novoga - s vama piti u kraljevstvu Oca svojega.”"},{"v":30,"t":"Otpjevavši hvalospjeve, zaputiše se prema Maslinskoj gori."},{"v":31,"t":"Tada im reče Isus: “Svi ćete se vi još ove noći sablazniti o mene. Ta pisano je: Udarit će pastira i stado će se razbjeći."},{"v":32,"t":"Ali kad uskrsnem, ići ću pred vama u Galileju.'"},{"v":33,"t":"Nato će mu Petar: “Ako se i svi sablazne o tebe, ja se nikada neću!”"},{"v":34,"t":"Reče mu Isus: “Zaista, kažem ti, još ove noći, prije negoli se pijetao oglasi, triput ćeš me zatajiti!”"},{"v":35,"t":"Kaže mu Petar: “Bude li trebalo i umrijeti s tobom, ne, neću te zatajiti.” Tako rekoše i svi učenici."},{"v":36,"t":"Tada dođe Isus s njima u predio zvan Getsemani i kaže učenicima: “Sjednite ovdje dok ja odem onamo pomoliti se.”"},{"v":37,"t":"I povede sa sobom Petra i oba sina Zebedejeva. Spopade ga žalost i tjeskoba."},{"v":38,"t":"Tada im reče: “Duša mi je nasmrt žalosna. Ostanite ovdje i bdijte sa mnom!”"},{"v":39,"t":"I ode malo dalje, pade ničice moleći: “Oče moj! Ako je moguće, neka me mimoiđe ova čaša. Ali ne kako ja hoću, nego kako hoćeš ti.”"},{"v":40,"t":"I dođe učenicima i nađe ih pozaspale pa reče Petru: “Tako, zar niste mogli jedan sat probdjeti sa mnom?"},{"v":41,"t":"Bdijte i molite da ne padnete u napast! Duh je, istina, voljan, no tijelo je slabo.”"},{"v":42,"t":"Opet, po drugi put, ode i pomoli se: “Oče moj! Ako nije moguće da me čaša mine da je ne pijem, budi volja tvoja!”"},{"v":43,"t":"I ponovno dođe i nađe ih pozaspale, oči im se sklapale."},{"v":44,"t":"Opet ih ostavi, pođe i pomoli se po treći put ponavljajući iste riječi."},{"v":45,"t":"Tada dođe učenicima i reče im: “Samo spavajte i počivajte! Evo, približio se čas! Sin Čovječji predaje se u ruke grešničke!"},{"v":46,"t":"Ustanite, hajdemo! Evo, približio se moj izdajica.”"},{"v":47,"t":"Dok je on još govorio, gle, dođe Juda, jedan od dvanaestorice, i s njime silna svjetina s mačevima i toljagama poslana od glavara svećeničkih i starješina narodnih."},{"v":48,"t":"A izdajica im dao znak: “Koga poljubim, taj je, njega uhvatite!”"},{"v":49,"t":"I odmah pristupi Isusu i reče: “Zdravo, Učitelju!” I poljubi ga."},{"v":50,"t":"A Isus mu reče: “Prijatelju, zašto ti ovdje!” Tada pristupe, podignu ruke na Isusa i uhvate ga."},{"v":51,"t":"I gle, jedan od onih koji bijahu s Isusom maši se rukom, trgnu mač, udari slugu velikoga svećenika i odsiječe mu uho."},{"v":52,"t":"Kaže mu tada Isus: “Vrati mač na njegovo mjesto jer svi koji se mača laćaju od mača i ginu."},{"v":53,"t":"Ili zar misliš da ja ne mogu zamoliti Oca svojega i eto umah uza me više od dvanaest legija anđela?"},{"v":54,"t":"No kako bi se onda ispunila Pisma da tako mora biti?”"},{"v":55,"t":"U taj čas reče Isus svjetini: “Kao na razbojnika iziđoste s mačevima i toljagama da me uhvatite? Danomice sjeđah u Hramu naučavajući i ne uhvatiste me.”"},{"v":56,"t":"A sve se to dogodilo da se ispune Pisma proročka. Tada ga svi učenici ostave i pobjegnu."},{"v":57,"t":"Nato uhvatiše Isusa i odvedoše ga velikomu svećeniku Kajfi, kod kojega se sabraše pismoznanci i starješine."},{"v":58,"t":"A Petar je išao za njim izdaleka do dvora velikog svećenika; i ušavši unutra, sjedne sa stražarima da vidi svršetak."},{"v":59,"t":"A glavari svećenički i cijelo Vijeće tražili su kakvo lažno svjedočanstvo protiv Isusa da bi ga mogli pogubiti."},{"v":60,"t":"Ali ne nađoše premda pristupiše mnogi lažni svjedoci. Napokon pristupe dvojica"},{"v":61,"t":"i reknu: “Ovaj reče: 'Mogu razvaliti Hram Božji i za tri ga dana sagraditi.'”"},{"v":62,"t":"Usta nato veliki svećenik i reče mu: “Zar ništa ne odgovaraš? Što to ovi protiv tebe svjedoče?”"},{"v":63,"t":"Isus je šutio. Reče mu veliki svećenik: “Zaklinjem te Bogom živim: Kaži nam jesi li ti Krist, Sin Božji?”"},{"v":64,"t":"Reče mu Isus: “Ti kaza! Štoviše, kažem vam: Odsada ćete gledati Sina Čovječjega gdje sjedi zdesna Sile i dolazi na oblacima nebeskim.”"},{"v":65,"t":"Nato veliki svećenik razdrije haljine govoreći: “Pohulio je! Što nam još trebaju svjedoci! Evo, sada ste čuli hulu!"},{"v":66,"t":"Što vam se čini?” Oni odgovoriše: “Smrt zaslužuje!”"},{"v":67,"t":"Tada su mu pljuvali u lice i udarali ga, a drugi ga pljuskali"},{"v":68,"t":"govoreći: “Proreci nam, Kriste, tko te udario?”"},{"v":69,"t":"A Petar je sjedio vani u dvorištu. I pristupi mu jedna sluškinja govoreći: “I ti bijaše s Isusom Galilejcem.”"},{"v":70,"t":"On pred svima zanijeka: “Ne znam što govoriš.”"},{"v":71,"t":"Kad iziđe u predvorje, spazi ga druga i kaže nazočnima: “Ovaj bijaše s Isusom Nazarećaninom.”"},{"v":72,"t":"On opet zanijeka sa zakletvom: “Ne znam toga čovjeka.”"},{"v":73,"t":"Malo zatim nazočni pristupiše Petru i rekoše: “Doista, i ti si od njih! Ta govor te tvoj izdaje!”"},{"v":74,"t":"On se tada stane zaklinjati i preklinjati: “Ne znam toga čovjeka.” I odmah se oglasi pijetao."},{"v":75,"t":"I spomenu se Petar riječi koju mu Isus reče: “Prije nego se pijetao oglasi, triput ćeš me zatajiti.” I iziđe te gorko zaplaka."}]},"27":{"hr":[{"v":1,"t":"A kad objutri, svi su glavari svećenički i starješine narodne održali vijećanje protiv Isusa da ga pogube."},{"v":2,"t":"I svezana ga odveli i predali upravitelju Pilatu."},{"v":3,"t":"Kada Juda, njegov izdajica, vidje da je Isus osuđen, pokaja se i vrati trideset srebrnjaka glavarima svećeničkim i starješinama"},{"v":4,"t":"govoreći: “Sagriješih predavši krv nedužnu!” Odgovoriše: “Što se to nas tiče? To je tvoja stvar!”"},{"v":5,"t":"I bacivši srebrnjake u Hram, ode te se objesi."},{"v":6,"t":"Glavari svećenički uzeše srebrnjake i rekoše:"},{"v":7,"t":"“Nije dopušteno staviti ih u hramsku riznicu jer su krvarina.” Posavjetuju se i kupe za njih lončarovu njivu za ukop stranaca."},{"v":8,"t":"Stoga se ona njiva zove “Krvava njiva” sve do danas."},{"v":9,"t":"Tada se ispuni što je rečeno po proroku Jeremiji: Uzeše trideset srebrnjaka - cijenu Neprocjenjivoga kojega procijeniše sinovi Izraelovi -"},{"v":10,"t":"i dadoše ih za njivu lončarovu kako mi naredi Gospodin."},{"v":11,"t":"Dovedoše dakle Isusa pred upravitelja. Upita ga upravitelj: “Ti li si kralj židovski?” On odgovori: “Ti kažeš.”"},{"v":12,"t":"I dok su ga glavari svećenički i starješine narodne optuživale, ništa nije odgovarao."},{"v":13,"t":"Tada mu reče Pilat: “Ne čuješ li što sve protiv tebe svjedoče?”"},{"v":14,"t":"I ne odgovori mu ni na jednu riječ te se upravitelj silno čudio."},{"v":15,"t":"A o Blagdanu upravitelj je običavao svjetini pustiti jednoga uznika, koga bi već htjeli."},{"v":16,"t":"Tada upravo bijaše u njih poznati uznik zvani Baraba."},{"v":17,"t":"Kad se dakle sabraše, reče im Pilat: “Koga hoćete da vam pustim: Barabu ili Isusa koji se zove Krist?”"},{"v":18,"t":"Znao je doista da ga predadoše iz zavisti."},{"v":19,"t":"Dok je sjedio na sudačkoj stolici, poruči nu njegova žena: “Mani se ti onoga pravednika jer sam danas u snu mnogo pretrpjela zbog njega.”"},{"v":20,"t":"Međutim, glavari svećenički i starješine nagovore svjetinu da zaište Barabu, a Isus da se pogubi."},{"v":21,"t":"Upita ih dakle upravitelj: “Kojega od ove dvojice hoćete da vam pustim?” A oni rekoše: “Barabu!”"},{"v":22,"t":"Kaže im Pilat: “Što dakle da učinim s Isusom koji se zove Krist?” Oni će: “Neka se razapne.”"},{"v":23,"t":"A on upita: “A što je zla učinio?” Vikahu još jače: “Neka se razapne!”"},{"v":24,"t":"Kad Pilat vidje da ništa ne koristi, nego da biva sve veći metež, uzme vodu i opere ruke pred svjetinom govoreći: “Nevin sam od krvi ove! Vi se pazite!”"},{"v":25,"t":"Sav narod nato odvrati: “Krv njegova na nas i na djecu našu!”"},{"v":26,"t":"Tada im pusti Barabu, a Isusa, izbičevana, preda da se razapne."},{"v":27,"t":"Onda vojnici upraviteljevi uvedoše Isusa u dvor upraviteljev i skupiše oko njega cijelu četu."},{"v":28,"t":"Svukoše ga pa zaogrnuše skrletnim plaštem."},{"v":29,"t":"Spletoše zatim vijenac od trnja i staviše mu na glavu, a tako i trsku u desnicu. Prigibajući pred njim koljena, izrugivahu ga: “Zdravo, kralju židovski!”"},{"v":30,"t":"Onda pljujući po njemu, uzimahu trsku i udarahu ga njome po glavi."},{"v":31,"t":"Pošto ga izrugaše, svukoše mu plašt, obukoše mu njegove haljine pa ga odvedoše da ga razapnu."},{"v":32,"t":"Izlazeći nađu nekoga čovjeka Cirenca, imenom Šimuna, i prisile ga da mu ponese križ."},{"v":33,"t":"I dođoše na mjesto zvano Golgota, to jest Lubanjsko mjesto,"},{"v":34,"t":"dadoše mu piti vino sa žuči pomiješano. I kad okusi, ne htjede piti."},{"v":35,"t":"A pošto ga razapeše, razdijeliše među se haljine njegove bacivši kocku."},{"v":36,"t":"I sjedeći ondje, čuvahu ga."},{"v":37,"t":"I staviše mu ponad glave krivicu napisanu: “Ovo je Isus, kralj židovski.”"},{"v":38,"t":"Tada razapeše s njime dva razbojnika, jednoga zdesna, drugoga slijeva."},{"v":39,"t":"A prolaznici su ga pogrđivali mašući glavama:"},{"v":40,"t":"“Ti koji razvaljuješ Hram i za tri ga dana sagradiš, spasi sam sebe! Ako si Sin Božji, siđi s križa!”"},{"v":41,"t":"Slično i glavari svećenički s pismoznancima i starješinama, rugajući se, govorahu:"},{"v":42,"t":"“Druge je spasio, sebe ne može spasiti! Kralj je Izraelov! Neka sada siđe s križa pa ćemo povjerovati u nj!"},{"v":43,"t":"Uzdao se u Boga! Neka ga sad izbavi ako mu omilje! Ta govorio je: 'Sin sam Božji!'”"},{"v":44,"t":"Tako ga vrijeđahu i s njim raspeti razbojnici."},{"v":45,"t":"Od šeste ure nasta tama po svoj zemlji - do ure devete."},{"v":46,"t":"O devetoj uri povika Isus iza glasa: “Eli, Eli, lema sabahtani?” To će reći: “Bože moj, Bože moj, zašto si me ostavio?”"},{"v":47,"t":"A neki od nazočnih, čuvši to, govorahu: “Ovaj zove Iliju.”"},{"v":48,"t":"I odmah pritrča jedan od njih, uze spužvu, natopi je octom, natakne je na trsku i pruži mu piti."},{"v":49,"t":"A ostali rekoše: “Pusti da vidimo hoće li doći Ilija da ga spasi.”"},{"v":50,"t":"A Isus opet povika iz glasa i ispusti duh."},{"v":51,"t":"I gle, zavjesa se hramska razdrije odozgor dodolje, nadvoje; zemlja se potrese, pećine se raspukoše,"},{"v":52,"t":"grobovi otvoriše i tjelesa mnogih svetih preminulih uskrsnuše"},{"v":53,"t":"te iziđoše iz grobova nakon njegova uskrsnuća, uđoše u sveti grad i pokazaše se mnogima."},{"v":54,"t":"A satnik i oni koji su s njime čuvali Isusa vidješe potres i što se zbiva, silno se prestrašiše i rekoše: “Uistinu, Sin Božji bijaše ovaj.”"},{"v":55,"t":"A bijahu ondje i izdaleka promatrahu mnoge žene što su iz Galileje išle za Isusom poslužujući mu;"},{"v":56,"t":"među njima Marija Magdalena i Marija, Jakovljeva i Josipova majka, i majka sinova Zebedejevih."},{"v":57,"t":"Uvečer dođe neki bogat čovjek iz Arimateje, imenom Josip, koji i sam bijaše učenik Isusov."},{"v":58,"t":"On pristupi Pilatu i zaiska tijelo Isusovo. Tada Pilat zapovjedi da mu se dadne."},{"v":59,"t":"Josip uze tijelo, povi ga u čisto platno"},{"v":60,"t":"i položi u svoj novi grob koji bijaše isklesao u stijeni. Dokotrlja velik kamen na grobna vrata i otiđe."},{"v":61,"t":"A bijahu ondje Marija Magdalena i druga Marija: sjedile su nasuprot grobu."},{"v":62,"t":"Sutradan, to jest dan nakon Priprave, sabraše se glavari svećenički i farizeji kod Pilata"},{"v":63,"t":"te mu rekoše: “Gospodaru, sjetismo se da onaj varalica još za života kaza: 'Nakon tri dana uskrsnut ću.'"},{"v":64,"t":"Zapovjedi dakle da se grob osigura sve do trećega dana da ne bi možda došli njegovi učenici, ukrali ga pa rekli narodu: 'Uskrsnuo je od mrtvih!' I bit će posljednja prijevara gora od prve.”"},{"v":65,"t":"Reče im Pilat: “Imate stražu! Idite i osigurajte kako znate!”"},{"v":66,"t":"Nato oni odu i osiguraju grob: zapečate kamen i postave stražu."}]},"28":{"hr":[{"v":1,"t":"Po suboti, u osvit prvoga dana u tjednu, dođe Marija Magdalena i druga Marija pogledati grob."},{"v":2,"t":"I gle, nastade žestok potres jer anđeo Gospodnji siđe s neba, pristupi, otkotrlja kamen i sjede na nj."},{"v":3,"t":"Lice mu bijaše kao munja, a odjeća bijela kao snijeg."},{"v":4,"t":"Od straha pred njim zadrhtaše stražari i obamriješe."},{"v":5,"t":"A anđeo progovori ženama: “Vi se ne bojte! Ta znam: Isusa Raspetoga tražite!"},{"v":6,"t":"Nije ovdje! Uskrsnu kako reče. Hajde, vidite mjesto gdje je ležao"},{"v":7,"t":"pa pođite žurno i javite njegovim učenicima da uskrsnu od mrtvih. I evo, ide pred vama u Galileju. Ondje ćete ga vidjeti. Evo, rekoh vam.”"},{"v":8,"t":"One otiđoše žurno s groba te sa strahom i velikom radošću otrčaše javiti njegovim učenicima."},{"v":9,"t":"Kad eto im Isusa u susret! Reče im: “Zdravo!” One polete k njemu, obujme mu noge i ničice mu se poklone."},{"v":10,"t":"Tada im Isus reče: “Ne bojte se! Idite, javite mojoj braći da pođu u Galileju! Ondje će me vidjeti!”"},{"v":11,"t":"Dok su one odlazile, gle, neki od straže dođoše u grad i javiše glavarima svećeničkim sve što se dogodilo."},{"v":12,"t":"Oni se sabraše sa starješinama na vijećanje, uzeše mnogo novaca i dadoše vojnicima"},{"v":13,"t":"govoreći: “Recite: 'Noću dok smo mi spavali, dođoše njegovi učenici i ukradoše ga.'"},{"v":14,"t":"Ako to dočuje upravitelj, mi ćemo ga uvjeriti i sve učiniti da vi budete bez brige.”"},{"v":15,"t":"Oni uzeše novac i učiniše kako bijahu poučeni. I razglasilo se to među Židovima - sve do danas."},{"v":16,"t":"Jedanaestorica pođoše u Galileju na goru kamo im je naredio Isus."},{"v":17,"t":"Kad ga ugledaše, padoše ničice preda nj. A neki posumnjaše."},{"v":18,"t":"Isus im pristupi i prozbori: “Dana mi je sva vlast na nebu i na zemlji!"},{"v":19,"t":"Pođite dakle i učinite mojim učenicima sve narode krsteći ih u ime Oca i Sina i Duha Svetoga"},{"v":20,"t":"i učeći ih čuvati sve što sam vam zapovjedio!” “I evo, ja sam s vama u sve dane - do svršetka svijeta.”"}]}},"MRK":{"1":{"hr":[{"v":1,"t":"Početak Evanđelja Isusa Krista Sina Božjega."},{"v":2,"t":"Pisano je u Izaiji proroku: Evo šaljem glasnika svoga pred licem tvojim da ti pripravi put."},{"v":3,"t":"Glas viče u pustinji: Pripravite put Gospodinu, poravnite mu staze!"},{"v":4,"t":"Tako se pojavi Ivan: krstio je u pustinji i propovijedao krst obraćenja na otpuštenje grijeha."},{"v":5,"t":"Grnula k njemu sva judejska zemlja i svi Jeruzalemci: primali su od njega krštenje u rijeci Jordanu ispovijedajući svoje grijehe."},{"v":6,"t":"Ivan bijaše odjeven u devinu dlaku, s kožnatim pojasom oko bokova; hranio se skakavcima i divljim medom."},{"v":7,"t":"I propovijedao je: “Nakon mene dolazi jači od mene. Ja nisam dostojan sagnuti se i odriješiti mu remenje na obući."},{"v":8,"t":"Ja vas krstim vodom, a on će vas krstiti Duhom Svetim.”"},{"v":9,"t":"Onih dana dođe Isus iz Nazareta galilejskoga i primi u Jordanu krštenje od Ivana."},{"v":10,"t":"I odmah, čim izađe iz vode, ugleda otvorena nebesa i Duha poput goluba gdje silazi na nj,"},{"v":11,"t":"a glas se zaori s nebesa: Ti si Sin moj, Ljubljeni! U tebi mi sva milina!"},{"v":12,"t":"I odmah ga Duh nagna u pustinju."},{"v":13,"t":"I bijaše u pustinji četrdeset dana, gdje ga je iskušavao Sotona; bijaše sa zvijerima, a anđeli mu služahu."},{"v":14,"t":"A pošto Ivan bijaše predan, otiđe Isus u Galileju. Propovijedao je evanđelje Božje:"},{"v":15,"t":"“Ispunilo se vrijeme, približilo se kraljevstvo Božje! Obratite se i vjerujte evanđelju!”"},{"v":16,"t":"I prolazeći uz Galilejsko more, ugleda Šimuna i Andriju, brata Šimunova, gdje ribare na moru; bijahu ribari."},{"v":17,"t":"I reče im Isus: “Hajdete za mnom i učinit ću vas ribarima ljudi!”"},{"v":18,"t":"Oni odmah ostaviše mreže i pođoše za njim."},{"v":19,"t":"Pošavši malo naprijed, ugleda Jakova Zebedejeva i njegova brata Ivana: u lađi su krpali mreže."},{"v":20,"t":"Odmah pozva i njih. Oni ostave oca Zebedeja u lađi s nadničarima i otiđu za njim."},{"v":21,"t":"I stignu u Kafarnaum. Odmah u subotu uđe on u sinagogu i poče naučavati."},{"v":22,"t":"Bijahu zaneseni njegovim naukom. Ta učio ih je kao onaj koji ima vlast, a ne kao pismoznanci."},{"v":23,"t":"A u njihovoj se sinagogi upravo zatekao čovjek opsjednut nečistim duhom. On povika:"},{"v":24,"t":"“Što ti imaš s nama, Isuse Nazarećanine? Došao si da nas uništiš? Znam tko si: Svetac Božji!”"},{"v":25,"t":"Isus mu zaprijeti: “Umukni i iziđi iz njega!”"},{"v":26,"t":"Nato nečisti duh potrese njime pa povika iz svega glasa i iziđe iz njega."},{"v":27,"t":"Svi se zaprepastiše te se zapitkivahu: “Što li je ovo? Nova li i snažna nauka! Pa i samim nečistim dusima zapovijeda, i pokoravaju mu se.”"},{"v":28,"t":"I pročulo se odmah o njemu posvuda, po svoj okolici galilejskoj."},{"v":29,"t":"I odmah pošto iziđoše iz sinagoge, uđe s Jakovom i Ivanom u kuću Šimunovu i Andrijinu."},{"v":30,"t":"A punica Šimunova ležala u ognjici. I odmah mu kažu za nju."},{"v":31,"t":"On pristupi, prihvati je za ruku i podiže. I pusti je ognjica. I posluživaše im."},{"v":32,"t":"Uvečer, kad sunce zađe, donošahu preda nj sve bolesne i opsjednute."},{"v":33,"t":"I sav je grad nagrnuo k vratima."},{"v":34,"t":"I on ozdravi bolesnike - a bijahu mnogi i razne im bolesti - i zloduhe mnoge izagna. I ne dopusti zlodusima govoriti jer su ga znali."},{"v":35,"t":"Rano ujutro, još za mraka, ustane, iziđe i povuče se na samotno mjesto i ondje se moljaše."},{"v":36,"t":"Potražiše ga Šimun i njegovi drugovi."},{"v":37,"t":"Kad ga nađoše, rekoše mu: “Svi te traže.”"},{"v":38,"t":"Kaže im: “Hajdemo drugamo, u obližnja mjesta, da i ondje propovijedam! Ta zato sam došao.”"},{"v":39,"t":"I prođe svom Galilejom: propovijedao je u njihovim sinagogama i zloduhe izgonio."},{"v":40,"t":"I dođe k njemu neki gubavac, klekne i zamoli: “Ako hoćeš, možeš me očistiti!”"},{"v":41,"t":"Isus ganut pruži ruku, dotače ga se pa će mu: “Hoću, budi čist!”"},{"v":42,"t":"I odmah nesta s njega gube i očisti se."},{"v":43,"t":"Isus se otrese na nj i odmah ga otpravi"},{"v":44,"t":"riječima: “Pazi, nikomu ništa ne kazuj, nego idi, pokaži se svećeniku i prinesi za svoje očišćenje što propisa Mojsije, njima za svjedočanstvo.”"},{"v":45,"t":"Ali čim iziđe, stane on uvelike pripovijedati i razglašavati događaj tako da Isus više nije mogao javno ući u grad, nego se zadržavao vani na samotnim mjestima. I dolažahu k njemu odasvud."}]},"2":{"hr":[{"v":1,"t":"I pošto nakon nekoliko dana opet uđe u Kafarnaum, pročulo se da je u kući."},{"v":2,"t":"I skupiše se mnogi te više nije bilo mjesta ni pred vratima. On im navješćivaše Riječ."},{"v":3,"t":"I dođu noseći k njemu uzetoga. Nosila ga četvorica."},{"v":4,"t":"Budući da ga zbog mnoštva nisu mogli unijeti k njemu, otkriju krov nad mjestom gdje bijaše Isus. Načinivši otvor, spuste postelju na kojoj je uzeti ležao."},{"v":5,"t":"Vidjevši njihovu vjeru, kaže Isus uzetome: “Sinko! Otpuštaju ti se grijesi.”"},{"v":6,"t":"Sjedjeli su ondje neki pismoznanci koji počeše mudrovati u sebi:"},{"v":7,"t":"“Što to ovaj govori? Huli! Ta tko može grijehe otpuštati doli Bog jedini?”"},{"v":8,"t":"Isus duhom odmah proniknu da tako mudruju u sebi, pa će im: “Što to mudrujete u sebi?"},{"v":9,"t":"Ta što je lakše? Reći uzetomu: 'Otpuštaju ti se grijesi' ili reći: 'Ustani, uzmi svoju postelju i hodi?'"},{"v":10,"t":"Ali da znate: vlastan je Sin Čovječji na zemlji otpuštati grijehe!” I reče uzetomu:"},{"v":11,"t":"“Tebi zapovijedam, ustani, uzmi postelju i pođi kući!”"},{"v":12,"t":"I on usta, uze odmah postelju i iziđe na očigled svima. Svi su zaneseni slavili Boga govoreći: “Takvo što nikad još ne vidjesmo!”"},{"v":13,"t":"Isus ponovno iziđe k moru. Sve je ono mnoštvo grnulo k njemu i on ih poučavaše."},{"v":14,"t":"Prolazeći ugleda Levija Alfejeva gdje sjedi u carinarnici. I kaže mu: “Pođi za mnom!” On usta i pođe za njim."},{"v":15,"t":"Kada zatim Isus bijaše za stolom u njegovoj kući, nađoše se za stolom s njime i njegovim učenicima i mnogi carinici i grešnici. Bilo ih je uistinu mnogo. A slijedili su ga"},{"v":16,"t":"i pismoznanci farizejske sljedbe pa vidjevši da jede s grešnicima i carinicima rekoše njegovim učenicima: “Zašto jede s carinicima i grešnicima?”"},{"v":17,"t":"Čuvši to, Isus im reče: “Ne treba zdravima liječnika, nego bolesnima! Ne dođoh zvati pravednike, nego grešnike.”"},{"v":18,"t":"Ivanovi su učenici i farizeji postili. I dođu neki i kažu mu: “Zašto učenici Ivanovi i učenici farizejski poste, a tvoji učenici ne poste?”"},{"v":19,"t":"Nato im Isus reče: “Mogu li svatovi postiti dok je zaručnik s njima? Dokle god imaju zaručnika sa sobom, ne mogu postiti."},{"v":20,"t":"Doći će već dani kad će im se ugrabiti zaručnik i tada će postiti u onaj dan!”"},{"v":21,"t":"“Nitko ne prišiva krpe od sirova sukna na staro odijelo. Inače nova zakrpa vuče sa starog odijela pa nastane još veća rupa.”"},{"v":22,"t":"“I nitko ne ulijeva novo vino u stare mješine. Inače će vino poderati mješine pa propade i vino i mješine. Nego - novo vino u nove mješine!”"},{"v":23,"t":"Jedne je subote prolazio kroz usjeve. Njegovi učenici počeše putem trgati klasje. A farizeji mu rekoše:"},{"v":24,"t":"“Gle! Zašto čine što subotom nije dopušteno?”"},{"v":25,"t":"Isus im odgovori: “Zar nikad niste čitali što učini David kad ogladnje te se nađe u potrebi on i njegovi pratioci?"},{"v":26,"t":"Kako za velikog svećenika Ebjatara uđe u Dom Božji i pojede prinesene kruhove kojih ne smije jesti nitko osim svećenika; a on dade i svojim pratiocima?”"},{"v":27,"t":"I govoraše im: “Subota je stvorena radi čovjeka, a ne čovjek radi subote."},{"v":28,"t":"Tako, Sin Čovječji gospodar je subote!”"}]},"3":{"hr":[{"v":1,"t":"Uđe ponovno u sinagogu. Bio je ondje čovjek usahle ruke."},{"v":2,"t":"A oni vrebahu hoće li ga Isus u subotu izliječiti, da ga optuže."},{"v":3,"t":"On kaže čovjeku usahle ruke: “Stani na sredinu!”"},{"v":4,"t":"A njima će: “Je li subotom dopušteno činiti dobro ili činiti zlo, život spasiti ili pogubiti?” No oni su šutjeli."},{"v":5,"t":"A on, ražalošćen okorjelošću srca njihova, srdito ih ošinu pogledom pa reče tom čovjeku: “Ispruži ruku!” On ispruži - i ruka mu zdrava!"},{"v":6,"t":"Farizeji iziđu i dadnu se odmah s herodovcima na vijećanje protiv njega kako da ga pogube."},{"v":7,"t":"Isus se s učenicima povuče k moru. Za njim je išao silan svijet iz Galileje. I iz Judeje,"},{"v":8,"t":"iz Jeruzalema, iz Idumeje, iz Transjordanije i iz okolice Tira i Sidona - silno je mnoštvo čulo što čini i nagrnulo k njemu."},{"v":9,"t":"Stoga reče učenicima neka mu se zbog mnoštva pripravi lađica da ga ne bi zgnjeli."},{"v":10,"t":"Jer mnoge je ozdravio pa su se svi koji bijahu pogođeni kakvim zlom bacali na nj da bi ga se dotakli."},{"v":11,"t":"A nečisti duhovi, čim bi ga spazili, padali bi preda nj i vikali: “Ti si Sin Božji!”"},{"v":12,"t":"A on im se oštro prijetio da ga ne prokazuju."},{"v":13,"t":"Uziđe na goru i pozove koje sam htjede. I dođoše k njemu."},{"v":14,"t":"I ustanovi dvanaestoricu da budu s njime i da ih šalje propovijedati"},{"v":15,"t":"s vlašću da izgone đavle."},{"v":16,"t":"Ustanovi dakle dvanaestoricu: Šimuna, kojemu nadjenu ime Petar,"},{"v":17,"t":"i Jakova Zebedejeva i Ivana, brata Jakovljeva, kojima nadjenu ime Boanerges, to jest Sinovi groma,"},{"v":18,"t":"i Andriju i Filipa i Bartolomeja i Mateja i Tomu i Jakova Alfejeva i Tadeja i Šimuna Kananajca"},{"v":19,"t":"i Judu Iškariotskoga, koji ga izda."},{"v":20,"t":"I dođe Isus u kuću. Opet se skupi toliko mnoštvo da nisu mogli ni jesti."},{"v":21,"t":"Čuvši to, dođoše njegovi da ga obuzdaju jer se govorilo: “Izvan sebe je!”"},{"v":22,"t":"I pismoznanci što siđoše iz Jeruzalema govorahu: “Beelzebula ima, po poglavici đavolskom izgoni đavle.”"},{"v":23,"t":"A on ih dozva pa im u prispodobama govoraše: “Kako može Sotona Sotonu izgoniti?"},{"v":24,"t":"Ako se kraljevstvo u sebi razdijeli, ono ne može opstati."},{"v":25,"t":"Ili: ako se kuća u sebi razdijeli, ona ne može opstati."},{"v":26,"t":"Ako je dakle Sotona sam na sebe ustao i razdijelio se, ne može opstati, nego mu je kraj."},{"v":27,"t":"Nitko, dakako, ne može u kuću jakoga ući i oplijeniti mu pokućstvo ako prije jakoga ne sveže. Tada će mu kuću oplijeniti!”"},{"v":28,"t":"Doista, kažem vam, sve će se oprostiti sinovima ljudskima, koliki god bili grijesi i hule kojima pohule."},{"v":29,"t":"No pohuli li tko na Duha Svetoga, nema oproštenja dovijeka; krivac je grijeha vječnoga.”"},{"v":30,"t":"Jer govorahu: “Duha nečistoga ima.”"},{"v":31,"t":"I dođu majka njegova i braća njegova. Ostanu vani, a k njemu pošalju neka ga pozovu."},{"v":32,"t":"Oko njega je sjedjelo mnoštvo. I reknu mu: “Eno vani majke tvoje i braće tvoje, traže te!”"},{"v":33,"t":"On im odgovori: “Tko je majka moja i braća moja?”"},{"v":34,"t":"I okruži pogledom po onima što su sjedjeli oko njega u krugu i kaže: “Evo majke moje, evo braće moje!"},{"v":35,"t":"Tko god vrši volju Božju, on mi je brat i sestra i majka.”"}]},"4":{"hr":[{"v":1,"t":"I poče opet poučavati uz more. I zgrnu se k njemu silan svijet te on uđe u lađu i sjede na moru, a sve ono mnoštvo bijaše uz more, na kopnu."},{"v":2,"t":"Poučavao ih je u prispodobama mnogočemu. Govorio im u pouci:"},{"v":3,"t":"“Poslušajte! Gle, iziđe sijač sijati."},{"v":4,"t":"I dok je sijao, poneko zrno pade uz put, dođoše ptice i pozobaše ga."},{"v":5,"t":"Neko opet pade na kamenito tlo gdje nemaše dosta zemlje. Odmah izniknu jer nemaše duboke zemlje."},{"v":6,"t":"Ali kad ogranu sunce, izgorje; i jer nemaše korijenja, osuši se."},{"v":7,"t":"Neko opet pade u trnje i trnje uzraste i uguši ga te ploda ne donese."},{"v":8,"t":"Neko napokon pade u dobru zemlju i dade plod, razraste se i razmnoži, te donese: jedno tridesetostruko, jedno šezdesetostruko, jedno stostruko.”"},{"v":9,"t":"I doda: “Tko ima uši da čuje, neka čuje!”"},{"v":10,"t":"Kad bijaše nasamo, oni oko njega zajedno s dvanaestoricom pitahu ga o prispodobama."},{"v":11,"t":"I govoraše im: “Vama je dano otajstvo kraljevstva Božjega, a onima vani sve biva u prispodobama:"},{"v":12,"t":"da gledaju, gledaju - i ne vide, slušaju, slušaju - i ne razumiju, da se ne obrate pa da im se otpusti.”"},{"v":13,"t":"I kaže im: “Zar ne znate tu prispodobu? Kako ćete onda razumjeti prispodobe uopće?"},{"v":14,"t":"Sijač sije Riječ."},{"v":15,"t":"Oni uz put, gdje je Riječ posijana, jesu oni kojima, netom čuju, odmah dolazi Sotona i odnosi Riječ u njih posijanu."},{"v":16,"t":"Zasijani na tlo kamenito jesu oni koji kad čuju Riječ, odmah je s radošću prime,"},{"v":17,"t":"ali nemaju u sebi korijena, nego su nestalni: kad nastane nevolja ili progonstvo zbog Riječi, odmah se sablazne."},{"v":18,"t":"A drugi su oni u trnje zasijani. To su oni koji poslušaju Riječ,"},{"v":19,"t":"ali nadošle brige vremenite, zavodljivost bogatstva i ostale požude uguše Riječ te ona ostane bez ploda."},{"v":20,"t":"A zasijani na dobru zemlju jesu oni koji čuju i prime Riječ te urode: tridesetostruko, šezdesetostruko, stostruko."},{"v":21,"t":"I govoraše im: “Unosi li se svjetiljka da se pod posudu stavi ili pod postelju? Zar ne da se stavi na svijećnjak?"},{"v":22,"t":"Ta ništa nije zastrto, osim zato da se očituje; i ništa skriveno, osim zato da dođe na vidjelo!"},{"v":23,"t":"Ima li tko uši da čuje, neka čuje.”"},{"v":24,"t":"I govoraše im: “Pazite što slušate. Mjerom kojom mjerite mjerit će vam se. I nadodat će vam se."},{"v":25,"t":"Doista, onomu tko ima dat će se, a onomu tko nema oduzet će se i ono što ima.”"},{"v":26,"t":"I govoraše im: “Kraljevstvo je Božje kao kad čovjek baci sjeme u zemlju."},{"v":27,"t":"Spavao on ili bdio, noću i danju sjeme klija i raste - sam ne zna kako;"},{"v":28,"t":"zemlja sama od sebe donosi plod: najprije stabljiku, onda klas i napokon puno zrnja na klasu."},{"v":29,"t":"A čim plod dopusti, brže se on laća srpa jer eto žetve.”"},{"v":30,"t":"I govoraše: “Kako da prispodobimo kraljevstvo nebesko ili u kojoj da ga prispodobi iznesemo?"},{"v":31,"t":"Kao kad se gorušičino zrno posije u zemlju. Manje od svega sjemenja na zemlji,"},{"v":32,"t":"jednoć posijano, naraste i postane veće od svega povrća pa potjera velike grane te se pod sjenom njegovom gnijezde ptice nebeske.”"},{"v":33,"t":"Mnogim takvim prispodobama navješćivaše im Riječ, kako već mogahu slušati."},{"v":34,"t":"Bez prispodobe im ne govoraše, a nasamo bi svojim učenicima sve razjašnjavao."},{"v":35,"t":"Uvečer istoga dana kaže im: “Prijeđimo prijeko!”"},{"v":36,"t":"Oni otpuste mnoštvo i povezu Isusa kako već bijaše u lađi. A pratile su ga i druge lađe."},{"v":37,"t":"Najednom nasta žestoka oluja, na lađu navale valovi te su je već gotovo napunili."},{"v":38,"t":"A on na krmi spavaše na uzglavku. Probude ga i kažu mu: “Učitelju! Zar ne mariš što ginemo?”"},{"v":39,"t":"On se probudi, zaprijeti vjetru i reče moru: “Utihni! Umukni!” I smiri se vjetar i nasta velika utiha."},{"v":40,"t":"Tada im reče: “Što ste bojažljivi? Kako nemate vjere?”"},{"v":41,"t":"Oni se silno prestrašiše pa se zapitkivahu: “Tko li je ovaj da mu se i vjetar i more pokoravaju?”"}]},"5":{"hr":[{"v":1,"t":"Stigoše na onu stranu mora, u kraj gerazenski."},{"v":2,"t":"Čim iziđe iz lađe, odmah mu iz grobnica pohiti u susret neki čovjek s nečistim duhom."},{"v":3,"t":"Obitavalište je imao u grobnicama. I nitko ga više nije mogao svezati ni lancima"},{"v":4,"t":"jer je već često bio i okovima i lancima svezan, ali je raskinuo okove i iskidao lance i nitko ga nije mogao ukrotiti."},{"v":5,"t":"Po cijele bi noći i dane u grobnicama i po brdima vikao i bio se kamenjem."},{"v":6,"t":"Kad izdaleka opazi Isusa, dotrči i pokloni mu se,"},{"v":7,"t":"a onda u sav glas povika: “Što ti imaš sa mnom, Isuse, Sine Boga Svevišnjega? Zaklinjem te Bogom, ne muči me!”"},{"v":8,"t":"Jer Isus mu bijaše rekao: “Iziđi, duše nečisti, iz ovoga čovjeka!”"},{"v":9,"t":"Isus ga nato upita: “Kako ti je ime?” Kaže mu: “Legija mi je ime! Ima nas mnogo!”"},{"v":10,"t":"I uporno zaklinjaše Isusa da ih ne istjera iz onoga kraja."},{"v":11,"t":"A ondje je pod brdom paslo veliko krdo svinja."},{"v":12,"t":"Zaklinjahu ga dakle: “Pošalji nas u ove svinje da u njih uđemo!”"},{"v":13,"t":"I on im dopusti. Tada iziđoše nečisti duhovi i uđoše u svinje. I krdo od oko dvije tisuće jurnu niz obronak u more i podavi se u moru."},{"v":14,"t":"Svinjari pobjegoše i razglasiše gradom i selima. A ljudi pođoše vidjeti što se dogodilo."},{"v":15,"t":"Dođu Isusu. Ugledaju opsjednutoga: sjedio je obučen i zdrave pameti - on koji ih je imao legiju. I prestraše se."},{"v":16,"t":"A očevici im razlagahu kako je to bilo s opsjednutim i ono o svinjama."},{"v":17,"t":"Tada ga stanu moliti da ode iz njihova kraja."},{"v":18,"t":"Kad je ulazio u lađu, onaj što bijaše opsjednut molio ga da bude uza nj."},{"v":19,"t":"No on mu ne dopusti, nego mu reče: “Pođi kući k svojima pa im javi što ti je učinio Gospodin, kako ti se smilovao.”"},{"v":20,"t":"On ode i poče razglašavati po Dekapolu što mu učini Isus. I svi su se divili."},{"v":21,"t":"Kad se Isus lađom ponovno prebacio prijeko, zgrnu se k njemu silan svijet."},{"v":22,"t":"Stajao je uz more. I dođe, gle, jedan od nadstojnika sinagoge, imenom Jair. Ugledavši ga, padne mu pred noge"},{"v":23,"t":"pa ga usrdno moljaše: “Kćerkica mi je na umoru! Dođi, stavi ruke na nju da ozdravi i ostane u životu!”"},{"v":24,"t":"I pođe s njima. A za njim je išao silan svijet i pritiskao ga."},{"v":25,"t":"A neka je žena dvanaest godina bolovala od krvarenja,"},{"v":26,"t":"mnogo pretrpjela od pustih liječnika, razdala sve svoje i ništa nije koristilo; štoviše, bivalo joj je sve gore."},{"v":27,"t":"Čuvši za Isusa, priđe mu među mnoštvom odostraga i dotaknu se njegove haljine."},{"v":28,"t":"Mislila je: “Dotaknem li se samo njegovih haljina, bit ću spašena.”"},{"v":29,"t":"I odmah prestane njezino krvarenje te osjeti u tijelu da je ozdravila od zla."},{"v":30,"t":"Isus odmah u sebi osjeti da je iz njega izišla sila pa se okrenu usred mnoštva i reče: “Tko se to dotaknu mojih haljina?”"},{"v":31,"t":"A učenici mu rekoše: “Ta vidiš kako te mnoštvo odasvud pritišće i još pitaš: 'Tko me se to dotaknu?'”"},{"v":32,"t":"A on zaokruži pogledom da vidi onu koja to učini."},{"v":33,"t":"Žena, sva u strahu i trepetu, svjesna onoga što joj se dogodilo, pristupi i baci se preda nj pa mu kaza sve po istini."},{"v":34,"t":"On joj reče: “Kćeri, vjera te tvoja spasila! Pođi u miru i budi zdrava od svojega zla!”"},{"v":35,"t":"Dok je Isus još govorio, eto nadstojnikovih s porukom. “Kći ti je umrla. Čemu dalje mučiti učitelja?”"},{"v":36,"t":"Isus je čuo taj razgovor, pa će nadstojniku: “Ne boj se! Samo vjeruj!”"},{"v":37,"t":"I ne dopusti da ga itko drugi prati osim Petra i Jakova i Ivana, brata Jakovljeva."},{"v":38,"t":"I dođu u kuću nadstojnikovu. Ugleda buku i one koji plakahu i naricahu u sav glas."},{"v":39,"t":"Uđe i kaže im: “Što bučite i plačete? Dijete nije umrlo, nego spava.”"},{"v":40,"t":"A oni mu se podsmjehivahu. No on ih sve izbaci, uzme sa sobom djetetova oca i majku i svoje pratioce pa uđe onamo gdje bijaše dijete."},{"v":41,"t":"Primi dijete za ruku govoreći: “Talita, kum!” što znači: “Djevojko! Zapovijedam ti, ustani!”"},{"v":42,"t":"I djevojka odmah usta i poče hodati. Bijaše joj dvanaest godina. I u tren ostadoše zapanjeni, u čudu veliku."},{"v":43,"t":"On im dobro poprijeti neka toga nitko ne dozna; i reče da djevojci dadnu jesti."}]},"6":{"hr":[{"v":1,"t":"I otišavši odande, dođe u svoj zavičaj. A doprate ga učenici."},{"v":2,"t":"I kada dođe subota, poče učiti u sinagogi. I mnogi što su ga slušali preneraženi govorahu: “Odakle to ovome? Kakva li mu je mudrost dana? I kakva se to silna djela događaju po njegovim rukama?"},{"v":3,"t":"Nije li ovo drvodjelja, sin Marijin, i brat Jakovljev, i Josipov, i Judin, i Šimunov? I nisu li mu sestre ovdje među nama?” I sablažnjavahu se o njega."},{"v":4,"t":"A Isus im govoraše: “Nije prorok bez časti doli u svom zavičaju i među rodbinom i u svom domu.”"},{"v":5,"t":"I ne mogaše ondje učiniti ni jedno čudo, osim što ozdravi nekoliko nemoćnika stavivši ruke na njih."},{"v":6,"t":"I čudio se njihovoj nevjeri. Obilazio je selima uokolo i naučavao."},{"v":7,"t":"Dozva dvanaestoricu te ih poče slati dva po dva dajući im vlast nad nečistim dusima."},{"v":8,"t":"I zapovjedi im da na put ne nose ništa osim štapa: ni kruha, ni torbe, ni novaca o pojasu,"},{"v":9,"t":"nego da nose samo sandale i da ne oblače dviju haljina."},{"v":10,"t":"I govoraše im: “Kad uđete gdje u kuću, u njoj ostanite dok ne odete odande."},{"v":11,"t":"Ako vas gdje ne prime te vas ne poslušaju, iziđite odande i otresite prah ispod svojih nogu njima za svjedočanstvo.”"},{"v":12,"t":"Otišavši, propovijedali su obraćenje,"},{"v":13,"t":"izgonili mnoge zloduhe i mnoge su nemoćnike mazali uljem i oni su ozdravljali."},{"v":14,"t":"Dočuo to i kralj Herod jer se razglasilo Isusovo ime te se govorilo: “Ivan Krstitelj uskrsnuo od mrtvih i zato čudesne sile djeluju u njemu.”"},{"v":15,"t":"A drugi govorahu: “Ilija je!” Treći opet: “Prorok, kao jedan od proroka.”"},{"v":16,"t":"Herod pak na to govoraše: “Uskrsnu Ivan kojemu ja odrubih glavu.”"},{"v":17,"t":"Herod doista bijaše dao uhititi Ivana i svezati ga u tamnici zbog Herodijade, žene brata svoga Filipa, kojom se bio oženio."},{"v":18,"t":"Budući da je Ivan govorio Herodu: “Ne smiješ imati žene brata svojega!”,"},{"v":19,"t":"Herodijada ga mrzila i htjela ga ubiti, ali nije mogla"},{"v":20,"t":"jer se Herod bojao Ivana; znao je da je on čovjek pravedan i svet pa ga je štitio. I kad god bi ga slušao, uvelike bi se zbunio, a rado ga je slušao."},{"v":21,"t":"I dođe zgodan dan kad Herod o svom rođendanu priredi gozbu svojim velikašima, časnicima i prvacima galilejskim."},{"v":22,"t":"Uđe kći Herodijadina i zaplesa. Svidje se Herodu i sustolnicima. Kralj reče djevojci: “Zaišti od mene što god hoćeš i dat ću ti!”"},{"v":23,"t":"I zakle joj se: “Što god zaišteš od mene, dat ću ti, pa bilo to i pol mojega kraljevstva.”"},{"v":24,"t":"Ona iziđe pa će svojoj materi: “Što da zaištem?” A ona će: “Glavu Ivana Krstitelja!”"},{"v":25,"t":"I odmah žurno uđe kralju te zaište: “Hoću da mi odmah dadeš na pladnju glavu Ivana Krstitelja!”"},{"v":26,"t":"Ožalosti se kralj, ali zbog zakletve i sustolnika na htjede je odbiti."},{"v":27,"t":"Kralj odmah posla krvnika i naredi da donese glavu Ivanovu. On ode, odrubi mu glavu u tamnici,"},{"v":28,"t":"donese je na pladnju i dade je djevojci, a djevojka materi."},{"v":29,"t":"Kad za to dočuše Ivanovi učenici, dođu, uzmu njegovo tijelo i polože ga u grob."},{"v":30,"t":"Uto se apostoli skupe oko Isusa i izvijeste ga o svemu što su činili i naučavali."},{"v":31,"t":"I reče im: “Hajdete i vi u osamu na samotno mjesto, i otpočinite malo.” Jer mnogo je svijeta dolazilo i odlazilo pa nisu imali kada ni jesti."},{"v":32,"t":"Otploviše dakle lađom na samotno mjesto, u osamu."},{"v":33,"t":"No kad su odlazili, mnogi ih vidješe i prepoznaše te se pješice iz svih gradova strčaše onamo i pretekoše ih."},{"v":34,"t":"Kad iziđe, vidje silan svijet i sažali mu se jer bijahu kao ovce bez pastira pa ih stane poučavati u mnogočemu."},{"v":35,"t":"A u kasni već sat pristupe mu učenici pa mu reknu: “Pust je ovo kraj i već je kasno."},{"v":36,"t":"Otpusti ih da odu po okolnim zaseocima i selima i kupe sebi što za jelo.”"},{"v":37,"t":"No on im odgovori: “Podajte im vi jesti.” Kažu mu: “Da pođemo i kupimo za dvjesta denara kruha pa da im damo jesti?”"},{"v":38,"t":"A on će im: “Koliko kruhova imate? Idite i vidite!” Pošto izvidješe, kažu: “Pet, i dvije ribe.”"},{"v":39,"t":"I zapovjedi im da sve, u skupinama, posjedaju po zelenoj travi."},{"v":40,"t":"I pružiše se po sto i po pedeset na svaku lijehu."},{"v":41,"t":"On uze pet kruhova i dvije ribe, pogleda na nebo, izreče blagoslov pa razlomi kruhove i davaše učenicima da posluže ljude. Tako i dvije ribe razdijeli svima."},{"v":42,"t":"I jeli su svi i nasitili se."},{"v":43,"t":"I od ulomaka nakupiše dvanaest punih košara, a i od riba."},{"v":44,"t":"A jelo je pet tisuća muškaraca."},{"v":45,"t":"On odmah prisili učenike da uđu u lađu i da se prebace prijeko, prema Betsaidi, dok on otpusti mnoštvo."},{"v":46,"t":"I pošto se rasta s ljudima, otiđe u goru da se pomoli."},{"v":47,"t":"Uvečer pak lađa bijaše posred mora, a on sam na kraju."},{"v":48,"t":"Vidjevši kako se muče veslajući, jer im bijaše protivan vjetar, oko četvrte noćne straže dođe k njima hodeći po moru. I htjede ih mimoići."},{"v":49,"t":"A oni, vidjevši kako hodi po moru, pomisliše da je utvara pa kriknuše."},{"v":50,"t":"Jer svi su ga vidjeli i prestrašili se. A on im odmah progovori: “Hrabro samo! Ja sam! Ne bojte se!”"},{"v":51,"t":"I uziđe k njima u lađu, a vjetar utihnu. I veoma se, prekomjerno, snebivahu;"},{"v":52,"t":"još ne shvatiše ono o kruhovima, nego im srce bijaše stvrdnuto."},{"v":53,"t":"Pošto doploviše na kraj, dođu u Genezaret i pristanu."},{"v":54,"t":"Kad iziđu iz lađe, ljudi ga odmah prepoznaju"},{"v":55,"t":"pa oblete sav onaj kraj. I počnu donositi na nosilima bolesnike onamo gdje bi čuli da se on nalazi."},{"v":56,"t":"I kamo bi god ulazio - u sela, u gradove, u zaseoke - po trgovima bi stavljali bolesnike i molili ga da se dotaknu makar skuta njegove haljine. I koji bi ga se god dotakli, ozdravljali bi."}]},"7":{"hr":[{"v":1,"t":"Skupe se oko njega farizeji i neki od pismoznanaca koji dođoše iz Jeruzalema."},{"v":2,"t":"I opaze da neki njegovi učenici jedu kruh nečistih, to jest neopranih ruku."},{"v":3,"t":"A farizeji i svi Židovi ne jedu ako prije temeljito ne operu ruke; drže se predaje starih."},{"v":4,"t":"Niti s trga što jedu ako prije ne operu. Mnogo toga još ima što zbog predaje drže: pranje čaša, vrčeva i lonaca."},{"v":5,"t":"Zato farizeji i pismoznanci upitaju Isusa: “Zašto tvoji učenici ne postupaju po predaji starih, nego nečistih ruku blaguju?”"},{"v":6,"t":"A on im reče: “Dobro prorokova Izaija o vama, licemjeri, kad napisa: Ovaj me narod usnama časti, a srce mu je daleko od mene."},{"v":7,"t":"Uzalud me štuju naučavajući nauke - uredbe ljudske."},{"v":8,"t":"Napustili ste zapovijed Božju, a držite se predaje ljudske.”"},{"v":9,"t":"Još im govoraše: “Lijepo! Dokidate Božju zapovijed da biste sačuvali svoju predaju."},{"v":10,"t":"Mojsije doista reče: Poštuj oca svoga i majku svoju. I: Tko prokune oca ili majku, smrću neka se kazni."},{"v":11,"t":"A vi velite: 'Rekne li tko ocu ili majci: Pomoć koja te od mene ide neka bude 'korban', to jest sveti dar',"},{"v":12,"t":"takvome više ne dopuštate ništa učiniti za oca ili majku."},{"v":13,"t":"Tako dokidate riječ Božju svojom predajom, koju sami sebi predadoste. I još štošta tomu slično činite.”"},{"v":14,"t":"Tada ponovno dozove mnoštvo i stane govoriti: “Poslušajte me svi i razumijte!"},{"v":15,"t":"Ništa što izvana ulazi u čovjeka ne može ga onečistiti, nego što iz čovjeka izlazi - to ga onečišćuje."},{"v":16,"t":"Tko ima uši da čuje, neka čuje!”"},{"v":17,"t":"I kad od mnoštva uđe u kuću, upitaše ga učenici za prispodobu."},{"v":18,"t":"I reče im: “Tako? Ni vi ne razumijete? Ne shvaćate li da čovjeka ne može onečistiti što u nj ulazi"},{"v":19,"t":"jer mu ne ulazi u srce, nego u utrobu te izlazi u zahod?” Tako on očisti sva jela."},{"v":20,"t":"Još dometnu: “Što iz čovjeka izlazi, te onečišćuje čovjeka."},{"v":21,"t":"Ta iznutra, iz srca čovječjega, izlaze zle namisli, bludništva, krađe, ubojstva,"},{"v":22,"t":"preljubi, lakomstva, opakosti, prijevara, razuzdanost, zlo oko, psovka, uznositost, bezumlje."},{"v":23,"t":"Sva ta zla iznutra izlaze i onečišćuju čovjeka.”"},{"v":24,"t":"Odande otiđe u kraj tirski. I uđe u neku kuću. Htio je da nitko ne sazna, ali se nije mogao sakriti,"},{"v":25,"t":"nego odmah doču žena koje kćerkica imaše duha nečistoga. Ona dođe i pade mu pred noge."},{"v":26,"t":"A žena bijaše Grkinja, Sirofeničanka rodom. I moljaše ga da joj iz kćeri istjera zloduha."},{"v":27,"t":"A on joj govoraše: “Pusti da se prije nasite djeca! Ne priliči uzeti kruh djeci i baciti ga psićima.”"},{"v":28,"t":"A ona će mu: “Da, Gospodine! Ali i psići ispod stola jedu od mrvica dječjih.”"},{"v":29,"t":"Reče joj: “Zbog te riječi idi, izišao je iz tvoje kćeri zloduh.”"},{"v":30,"t":"I ode kući te nađe dijete gdje leži na postelji, a zloduh je bio izišao."},{"v":31,"t":"Zatim se ponovno vrati iz krajeva tirskih pa preko Sidona dođe Galilejskom moru, u krajeve dekapolske."},{"v":32,"t":"Donesu mu nekoga gluhog mucavca pa ga zamole da stavi na nj ruku."},{"v":33,"t":"On ga uzme nasamo od mnoštva, utisne svoje prste u njegove uši, zatim pljune i dotakne se njegova jezika."},{"v":34,"t":"Upravi pogled u nebo, uzdahne i kaže mu: “Effata!” - to će reći: “Otvori se!”"},{"v":35,"t":"I odmah mu se otvoriše uši i razdriješi spona jezika te stade govoriti razgovijetno."},{"v":36,"t":"A Isus im zabrani da nikome ne kazuju. No što im je on više branio, oni su to više razglašavali"},{"v":37,"t":"i preko svake mjere zadivljeni govorili: “Dobro je sve učinio! Gluhima daje čuti, nijemima govoriti!”"}]},"8":{"hr":[{"v":1,"t":"Onih se dana opet skupio silan svijet. Budući da nisu imali što jesti, dozva Isus učenike pa im reče:"},{"v":2,"t":"“Žao mi je naroda jer su već tri dana uza me i nemaju što jesti."},{"v":3,"t":"Ako ih otpravim gladne njihovim kućama, klonut će putom. A neki su od njih došli iz daleka.”"},{"v":4,"t":"Učenici mu odgovore: “Otkuda bi ih tko ovdje u pustinji mogao nahraniti kruhom?”"},{"v":5,"t":"On ih zapita: “Koliko kruhova imate?” Oni odgovore: “Sedam.”"},{"v":6,"t":"Nato zapovjedi mnoštvu da posjeda po zemlji. I uze sedam kruhova, zahvali, razlomi i davaše svojim učenicima da posluže. I poslužiše mnoštvu."},{"v":7,"t":"A imali su i malo ribica. Blagoslovi i njih te reče da i to posluže."},{"v":8,"t":"I jeli su i nasitili se. A od preteklih ulomaka odniješe sedam košara."},{"v":9,"t":"Bilo ih je oko četiri tisuće. Tada ih otpusti,"},{"v":10,"t":"a sam sa svojim učenicima odmah uđe u lađu i ode u kraj dalmanutski."},{"v":11,"t":"Tada istupiše farizeji i počeše raspravljati s njime. Iskušavajući ga, zatraže od njega znak s neba."},{"v":12,"t":"On uzdahnu iz sve duše i reče: “Zašto ovaj naraštaj traži znak? Zaista, kažem vam, ovome se naraštaju neće dati znak.”"},{"v":13,"t":"Tada ih ostavi, ponovno uđe u lađu pa otiđe prijeko."},{"v":14,"t":"A zaboraviše ponijeti kruha; imali su samo jedan kruh sa sobom na lađi."},{"v":15,"t":"Nato ih Isus opomenu: “Pazite, čuvajte se kvasca farizejskog i kvasca Herodova!”"},{"v":16,"t":"Oni, zamišljeni, među sobom govorahu: “Kruha nemamo.”"},{"v":17,"t":"Zamijetio to Isus pa im reče: “Zašto ste zamišljeni što kruha nemate? Zar još ne shvaćate i ne razumijete? Zar vam je srce stvrdnuto?"},{"v":18,"t":"Oči imate, a ne vidite; uši imate, a ne čujete? Zar se ne sjećate?"},{"v":19,"t":"Kad sam ono razlomio pet kruhova na pet tisuća, koliko punih košara ulomaka odnijeste?” Kažu mu: “Dvanaest.”"},{"v":20,"t":"“A kada razlomih sedam na četiri tisuće, koliko punih košara ulomaka odnijeste?” Odgovore: “Sedam.”"},{"v":21,"t":"A on će njima: “I još ne razumijete?”"},{"v":22,"t":"Dođu u Betsaidu, dovedu mu slijepca pa ga zamole da ga se dotakne."},{"v":23,"t":"On uhvati slijepca za ruku, izvede ga iz sela, pljunu mu u oči, stavi na nj ruke i zapita ga: “Vidiš li što?”"},{"v":24,"t":"Slijepac upilji pogled i reče: “Opažam ljude; vidim nešto kao drveće ... hodaju.”"},{"v":25,"t":"Tada mu Isus opet stavi ruke na oči i slijepac progleda i ozdravi te je mogao sve jasno na daleko vidjeti."},{"v":26,"t":"Tada ga posla kući i reče mu: “Ne ulazi u selo.”"},{"v":27,"t":"I krenu Isus i njegovi učenici u sela Cezareje Filipove. Putem on upita učenike: “Što govore ljudi, tko sam ja?”"},{"v":28,"t":"Oni mu rekoše: “Da si Ivan Krstitelj, drugi da si Ilija, treći opet da si neki od proroka.”"},{"v":29,"t":"On njih upita: “A vi, što vi kažete, tko sam ja?” Petar prihvati i reče: “Ti si Pomazanik - Krist!”"},{"v":30,"t":"I zaprijeti im da nikomu ne kazuju o njemu."},{"v":31,"t":"I poče ih poučavati kako Sin Čovječji treba da mnogo pretrpi, da ga starješine, glavari svećenički i pismoznanci odbace, da bude ubijen i nakon tri dana da ustane."},{"v":32,"t":"Otvoreno im to govoraše. Petar ga uze u stranu i poče odvraćati."},{"v":33,"t":"A on se okrenu, pogleda svoje učenike pa zaprijeti Petru: “Nosi se od mene, sotono, jer ti nije na pameti što je Božje, nego što je ljudsko!”"},{"v":34,"t":"Tada dozva narod i učenike pa im reče: “Hoće li tko za mnom, neka se odrekne samoga sebe, neka uzme svoj križ i neka ide za mnom."},{"v":35,"t":"Tko hoće život svoj spasiti, izgubit će ga; a tko izgubi život svoj poradi mene i evanđelja, spasit će ga."},{"v":36,"t":"Ta što koristi čovjeku steći sav svijet, a životu svojemu nauditi?"},{"v":37,"t":"Ta što da čovjek dadne u zamjenu za život svoj?"},{"v":38,"t":"Doista, tko se zastidi mene i mojih riječi u ovom preljubničkom i grešničkom naraštaju - njega će se stidjeti i Sin Čovječji kada dođe u slavi Oca svoga zajedno sa svetim anđelima.”"}]},"9":{"hr":[{"v":1,"t":"Još im govoraše: “Zaista, kažem vam, neki od ovdje nazočnih neće okusiti smrti dok ne vide da je kraljevstvo Božje došlo u sili.”"},{"v":2,"t":"Nakon šest dana uze Isus sa sobom Petra, Jakova i Ivana i povede ih na goru visoku, u osamu, same, i preobrazi se pred njima."},{"v":3,"t":"I haljine mu postadoše sjajne, bijele veoma - nijedan ih bjelilac na zemlji ne bi mogao tako izbijeliti."},{"v":4,"t":"I ukaza im se Ilija s Mojsijem te razgovarahu s Isusom."},{"v":5,"t":"A Petar prihvati i reče Isusu: “Učitelju, dobro nam je ovdje biti! Načinimo tri sjenice: tebi jednu, Mojsiju jednu i Iliji jednu.”"},{"v":6,"t":"Doista nije znao što da kaže jer bijahu prestrašeni."},{"v":7,"t":"I pojavi se oblak i zasjeni ih, a iz oblaka se začu glas: “Ovo je Sin moj, Ljubljeni! Slušajte ga!”"},{"v":8,"t":"I odjednom, obazrevši se uokolo, nikoga uza se ne vidješe doli Isusa sama."},{"v":9,"t":"Dok su silazili s gore, naloži im da nikomu ne pripovijedaju što su vidjeli dok Sin Čovječji od mrtvih ne ustane."},{"v":10,"t":"Oni održaše tu riječ, ali se među sobom pitahu što znači to njegovo “od mrtvih ustati”"},{"v":11,"t":"pa ga upitaju: “Zašto pismoznanci govore da prije treba da dođe Ilija?”"},{"v":12,"t":"A on im reče: “Ilija će, doduše, prije doći i sve obnoviti. Pa kako ipak piše o Sinu Čovječjem da će mnogo pretrpjeti i biti prezren?"},{"v":13,"t":"Ali, velim vam: Ilija je već došao i oni učiniše s njim što im se prohtjelo, kao što piše o njemu.”"},{"v":14,"t":"Kada dođoše k učenicima, ugledaše oko njih silan svijet i pismoznance kako raspravljaju s njima."},{"v":15,"t":"Čim ga sve ono mnoštvo ugleda, iznenađeno brže pohrli pozdraviti ga."},{"v":16,"t":"A on ih upita: “Što to raspravljaste s njima?”"},{"v":17,"t":"Odvrati netko iz mnoštva: “Učitelju, dovedoh k tebi svoga sina koji ima nijemoga duha."},{"v":18,"t":"Gdje ga god zgrabi, obara ga, a on pjeni, škripi zubima i koči se. Rekoh tvojim učenicima da ga izagnaju, ali ne mogoše.”"},{"v":19,"t":"On im odvrati: “O rode nevjerni! Dokle mi je biti s vama? Dokle li vas podnositi? Dovedite ga k meni!”"},{"v":20,"t":"I dovedoše ga k njemu. Čim zloduh ugleda Isusa, potrese dječakom i on se, oboren na zemlju, stane valjati i pjeniti."},{"v":21,"t":"Isus upita njegova oca: “Koliko je vremena kako mu se to događa?” On reče: “Od djetinjstva!"},{"v":22,"t":"A često ga znade baciti i u vatru i u vodu da ga upropasti. Nego, ako što možeš, pomozi nam, imaj samilosti s nama!”"},{"v":23,"t":"Nato mu Isus reče: “Što? Ako možeš? Sve je moguće onomu koji vjeruje!”"},{"v":24,"t":"Dječakov otac brže povika: “Vjerujem! Pomozi mojoj nevjeri!”"},{"v":25,"t":"Vidjevši da svijet odasvud grne, Isus zaprijeti nečistomu duhu: “Nijemi i gluhi duše, ja ti zapovijedam, iziđi iz njega i da nisi više u nj ušao!”"},{"v":26,"t":"Zloduh nato zaviče, žestoko strese dječaka te iziđe, a on osta kao mrtav te su mnogi govorili da je umro."},{"v":27,"t":"No Isus ga dohvati za ruku, podiže ga i on ustade."},{"v":28,"t":"Kad Isus uđe u kuću, upitaše ga učenici nasamo: “Kako to da ga mi ne mogosmo izagnati?”"},{"v":29,"t":"Odgovori im: “Ovaj se rod ničim drugim ne može izagnati osim molitvom i postom.”"},{"v":30,"t":"Otišavši odande, prolažahu kroz Galileju. On ne htjede da to itko sazna."},{"v":31,"t":"Jer poučavaše svoje učenike. Govoraše im: “Sin Čovječji predaje se u ruke ljudima. Ubit će ga, ali će on, ubijen, nakon tri dana ustati.”"},{"v":32,"t":"No oni ne razumješe te besjede, a bojahu ga se pitati."},{"v":33,"t":"I dođoše u Kafarnaum. I već u kući upita ih: “Što ste putem raspravljali?”"},{"v":34,"t":"A oni umukoše jer putem među sobom razgovarahu o tome tko je najveći."},{"v":35,"t":"On sjede i dozove dvanaestoricu te im reče: “Ako tko želi biti prvi, neka bude od svih posljednji i svima poslužitelj!”"},{"v":36,"t":"I uzme dijete, postavi ga posred njih, zagrli ga i reče im:"},{"v":37,"t":"“Tko god jedno ovakvo dijete primi u moje ime, mene prima. A tko mene prima, ne prima mene, nego onoga koji mene posla.”"},{"v":38,"t":"Reče mu Ivan: “Učitelju, vidjesmo jednoga kako u tvoje ime izgoni zloduhe. Mi smo mu branili jer ne ide s nama.”"},{"v":39,"t":"A Isus reče: “Ne branite mu! Jer nitko ne može učiniti nešto silno u moje ime pa me ubrzo zatim pogrditi."},{"v":40,"t":"Tko nije protiv nas, za nas je.”"},{"v":41,"t":"“Uistinu, tko vas napoji čašom vode u ime toga što ste Kristovi, zaista, kažem vam, neće mu propasti plaća.”"},{"v":42,"t":"“Onomu naprotiv tko bi sablaznio jednoga od ovih najmanjih što vjeruju, daleko bi bolje bilo da s mlinskim kamenom o vratu bude bačen u more.”"},{"v":43,"t":"“Pa ako te ruka sablažnjava, odsijeci je. Bolje ti je sakatu ući u život, nego s obje ruke otići u pakao, u oganj neugasivi."},{"v":44,"t":"#"},{"v":45,"t":"I ako te noga sablažnjava, odsijeci je. Bolje ti je hromu ući u život, nego s obje noge bit bačen u pakao."},{"v":46,"t":"#"},{"v":47,"t":"I ako te oko sablažnjava, iskopaj ga. Bolje ti je jednooku ući u kraljevstvo Božje, nego s oba oka biti bačen u pakao,"},{"v":48,"t":"gdje crv njihov ne gine niti se oganj gasi."},{"v":49,"t":"Uistinu, ognjem će svaki od njih biti posoljen."},{"v":50,"t":"Dobra je sol. Ali ako sol postane neslana, čime ćete nju začiniti? Imajte sol u sebi, a mir među sobom!”"}]},"10":{"hr":[{"v":1,"t":"Krenuvši odande, dođe u judejski kraj i na onu stranu Jordana. I opet mnoštvo nagrnu k njemu, a on ih po svojem običaju ponovno poučavaše."},{"v":2,"t":"A pristupe farizeji pa, da ga iskušaju, upitaše: “Je li mužu dopušteno otpustiti ženu?”"},{"v":3,"t":"On im odgovori: “Što vam zapovjedi Mojsije?”"},{"v":4,"t":"Oni rekoše: “Mojsije je dopustio napisati otpusno pismo i - otpustiti.”"},{"v":5,"t":"A Isus će im: “Zbog okorjelosti srca vašega napisa vam on tu zapovijed."},{"v":6,"t":"Od početka stvorenja muško i žensko stvori ih."},{"v":7,"t":"Stoga će čovjek ostaviti oca i majku da prione uza svoju ženu;"},{"v":8,"t":"i dvoje njih bit će jedno tijelo. Tako više nisu dvoje, nego jedno tijelo."},{"v":9,"t":"Što dakle Bog združi, čovjek neka ne rastavlja!”"},{"v":10,"t":"U kući su ga učenici ponovno o tome ispitivali."},{"v":11,"t":"I reče im: “Tko otpusti svoju ženu pa se oženi drugom, čini prema prvoj preljub."},{"v":12,"t":"I ako žena napusti svoga muža pa se uda za drugoga, čini preljub.”"},{"v":13,"t":"Donosili mu dječicu da ih se dotakne, a učenici im branili."},{"v":14,"t":"Opazivši to, Isus se ozlovolji i reče im: “Pustite dječicu neka dolaze k meni; ne priječite im jer takvih je kraljevstvo Božje!"},{"v":15,"t":"Zaista, kažem vam, tko ne primi kraljevstva Božjega kao dijete, ne, u nj neće ući.”"},{"v":16,"t":"Nato ih zagrli pa ih blagoslivljaše polažući na njih ruke."},{"v":17,"t":"I dok je izlazio na put, dotrči netko, klekne preda nj pa ga upita: “Učitelju dobri, što mi je činiti da baštinim život vječni?”"},{"v":18,"t":"Isus mu reče: “Što me zoveš dobrim? Nitko nije dobar doli Bog jedini!"},{"v":19,"t":"Zapovijedi znadeš: Ne ubij! Ne čini preljuba! Ne ukradi! Ne svjedoči lažno! Ne otmi! Poštuj oca svoga i majku!”"},{"v":20,"t":"On mu odgovori: “Učitelju, sve sam to čuvao od svoje mladosti.”"},{"v":21,"t":"Isus ga nato pogleda, zavoli ga i rekne mu: “Jedno ti nedostaje! Idi i što imaš, prodaj i podaj siromasima pa ćeš imati blago na nebu. A onda dođi i idi za mnom.”"},{"v":22,"t":"On se na tu riječ smrkne i ode žalostan jer imaše velik imetak."},{"v":23,"t":"Isus zaokruži pogledom pa će svojim učenicima: “Kako li će teško imućnici u kraljevstvo Božje!”"},{"v":24,"t":"Učenici ostadoše zapanjeni tim njegovim riječima. Zato im Isus ponovi: “Djeco, kako je teško u kraljevstvo Božje!"},{"v":25,"t":"Lakše je devi kroz ušice iglene nego bogatašu u kraljevstvo Božje.”"},{"v":26,"t":"Oni se još većma snebivahu te će jedan drugome: “Pa tko se onda može spasiti?”"},{"v":27,"t":"Isus upre u njih pogled i reče: “Ljudima je nemoguće, ali ne Bogu! Ta Bogu je sve moguće!”"},{"v":28,"t":"Petar mu poče govoriti: “Evo, mi sve ostavismo i pođosmo za tobom.”"},{"v":29,"t":"Reče Isus: “Zaista, kažem vam, nema ga tko ostavi kuću, ili braću, ili sestre, ili majku, ili oca, ili djecu, ili polja poradi mene i poradi evanđelja,"},{"v":30,"t":"a da ne bi sada, u ovom vremenu, s progonstvima primio stostruko kuća, i braće, i sestara, i majki, i djece, i polja - i u budućem vijeku život vječni."},{"v":31,"t":"A mnogi prvi bit će posljednji i posljednji prvi.”"},{"v":32,"t":"Putovali su tako uzlazeći u Jeruzalem. Isus je išao pred njima te bijahu zaprepašteni, a oni koji su išli za njima, prestrašeni. Tada Isus opet uze dvanaestoricu i poče im kazivati što će ga zadesiti:"},{"v":33,"t":"“Evo, uzlazimo u Jeruzalem i Sin Čovječji bit će predan glavarima svećeničkim i pismoznancima. Osudit će ga na smrt, predati poganima,"},{"v":34,"t":"izrugati i popljuvati. Izbičevat će ga, ubit će ga, ali on će nakon tri dana ustati.”"},{"v":35,"t":"I pristupe mu Jakov i Ivan, sinovi Zebedejevi, govoreći mu: “Učitelju, htjeli bismo da nam učiniš što te zaištemo.”"},{"v":36,"t":"A on će im: “Što hoćete da vam učinim?”"},{"v":37,"t":"Oni mu rekoše: “Daj nam da ti u slavi tvojoj sjednemo jedan zdesna, a drugi slijeva.”"},{"v":38,"t":"A Isus im reče: “Ne znate što ištete. Možete li piti čašu koju ja pijem, ili krstiti se krstom kojim se ja krstim?”"},{"v":39,"t":"Oni mu rekoše: “Možemo.” A Isus će im: “Čašu koju ja pijem pit ćete i krstom kojim se ja krstim bit ćete kršteni,"},{"v":40,"t":"ali sjesti meni zdesna ili slijeva nisam ja vlastan dati - to je onih kojima je pripravljeno.”"},{"v":41,"t":"Kad su to čula ostala desetorica, počeše se gnjeviti na Jakova i Ivana."},{"v":42,"t":"Zato ih Isus dozva i reče im: “Znate da oni koji se smatraju vladarima gospoduju svojim narodima i velikaši njihovi drže ih pod vlašću."},{"v":43,"t":"Nije tako među vama! Naprotiv, tko hoće da među vama bude najveći, neka vam bude poslužitelj!"},{"v":44,"t":"I tko hoće da među vama bude prvi, neka bude svima sluga."},{"v":45,"t":"Jer ni Sin Čovječji nije došao da bude služen, nego da služi i život svoj dade kao otkupninu za mnoge.”"},{"v":46,"t":"Dođu tako u Jerihon. Kad je Isus s učenicima i sa silnim mnoštvom izlazio iz Jerihona, kraj puta je sjedio slijepi prosjak Bartimej, sin Timejev."},{"v":47,"t":"Kad je čuo da je to Isus Nazarećanin, stane vikati: “Sine Davidov, Isuse, smiluj mi se!”"},{"v":48,"t":"Mnogi ga ušutkivahu, ali on još jače vikaše: “Sine Davidov, smiluj mi se!”"},{"v":49,"t":"Isus se zaustavi i reče: “Pozovite ga!” I pozovu slijepca sokoleći ga: “Ustani! Zove te!”"},{"v":50,"t":"On baci sa sebe ogrtač, skoči i dođe Isusu."},{"v":51,"t":"Isus ga upita: “Što hoćeš da ti učinim?” Slijepac mu reče: “Učitelju moj, da progledam.”"},{"v":52,"t":"Isus će mu: “Idi, vjera te tvoja spasila!” I on odmah progleda i uputi se za njim."}]},"11":{"hr":[{"v":1,"t":"Kad se približe Jeruzalemu, Betfagi i Betaniji, do Maslinske gore, pošalje dva učenika"},{"v":2,"t":"i kaže im: “Hajdete u selo pred vama. Čim u nj uđete, naći ćete privezano magare koje još nitko nije zajahao. Odriješite ga i vodite."},{"v":3,"t":"Ako vam tko reče: 'Što to radite?' recite: 'Gospodinu treba', i odmah će ga ipak ovamo pustiti.”"},{"v":4,"t":"Otiđoše i nađoše magare privezano uz vrata vani na cesti i odriješe ga."},{"v":5,"t":"A neki od nazočnih upitaše: “Što radite? Što driješite magare?”"},{"v":6,"t":"Oni im odvrate kako im reče Isus. I pustiše ih."},{"v":7,"t":"I dovedu magare Isusu, prebace preko njega svoje haljine i on zajaha na nj."},{"v":8,"t":"Mnogi prostriješe svoje haljine po putu, a drugi narezaše zelenih grana po poljima."},{"v":9,"t":"I oni pred njim i oni za njim klicahu: “Hosana! Blagoslovljen Onaj koji dolazi u ime Gospodnje!"},{"v":10,"t":"Blagoslovljeno kraljevstvo oca našega Davida koji dolazi! Hosana u visinama!”"},{"v":11,"t":"I uđe u Jeruzalem, u Hram. I sve uokolo razgleda, pa kako već bijaše kasno, pođe s dvanaestoricom u Betaniju."},{"v":12,"t":"Sutradan su izlazili iz Betanije, a on ogladnje."},{"v":13,"t":"Ugleda izdaleka lisnatu smokvu i priđe ne bi li na njoj što našao. Ali došavši bliže, ne nađe ništa osim lišća jer ne bijaše vrijeme smokvama."},{"v":14,"t":"Tada reče smokvi: “Nitko nikada više ne jeo s tebe!” Čuli su to njegovi učenici."},{"v":15,"t":"Stignu tako u Jeruzalem. On uđe u Hram i stane izgoniti one koji su prodavali i kupovali u Hramu. Mjenjačima isprevrta stolove i prodavačima golubova klupe."},{"v":16,"t":"I ne dopusti da itko išta pronese kroz Hram."},{"v":17,"t":"Učio ih je i govorio: “Nije li pisano: Dom će se moj zvati Dom molitve za sve narode? A vi od njega načinili pećinu razbojničku!”"},{"v":18,"t":"Kada su za to dočuli glavari svećenički i pismoznanci, tražili su kako da ga pogube. Uistinu, bojahu ga se jer je sav narod bio očaran njegovim naukom."},{"v":19,"t":"A kad se uvečerilo, izlazili su iz grada."},{"v":20,"t":"Kad su ujutro prolazili mimo one smokve, opaze da je usahla do korijena."},{"v":21,"t":"Petar se prisjeti pa će Isusu: “Učitelju, pogledaj! Smokva koju si prokleo usahnu.”"},{"v":22,"t":"Isus im odvrati: “Imajte vjeru Božju."},{"v":23,"t":"Zaista, kažem vam, rekne li tko ovoj gori: 'Digni se i baci u more!' i u srcu svome ne posumnja, nego vjeruje da će se dogoditi to što kaže - doista, bit će mu!"},{"v":24,"t":"Stoga vam kažem: Sve što god zamolite i zaištete, vjerujte da ste postigli i bit će vam!"},{"v":25,"t":"No kad ustanete na molitvu, otpustite ako što imate protiv koga da i vama Otac vaš, koji je na nebesima, otpusti vaše prijestupke.”"},{"v":26,"t":"#"},{"v":27,"t":"I dođu opet u Jeruzalem. Dok je obilazio Hramom, dođu k njemu glavari svećenički, pismoznanci i starješine."},{"v":28,"t":"I govorahu mu: “Kojom vlašću to činiš? Ili tko ti dade tu vlast da to činiš?”"},{"v":29,"t":"A Isus im reče: “Jedno ću vas upitati. Odgovorite mi, pa ću vam kazati kojom vlašću ovo činim."},{"v":30,"t":"Krst Ivanov bijaše li od Neba ili od ljudi? Odgovorite mi!”"},{"v":31,"t":"A oni umovahu među sobom: “Reknemo li 'od Neba', odvratit će 'Zašto mu dakle ne povjerovaste?'"},{"v":32,"t":"Nego, da reknemo 'od ljudi!'” - Bojahu se mnoštva. Ta svi Ivana smatrahu doista prorokom."},{"v":33,"t":"I odgovore Isusu: “Ne znamo.” A Isus će im: “Ni ja vama neću kazati kojom vlašću ovo činim.”"}]},"12":{"hr":[{"v":1,"t":"I uze im zboriti u prispodobama: Čovjek vinograd posadi, ogradom ogradi, iskopa tijesak i kulu podiže pa ga iznajmi vinogradarima i otputova."},{"v":2,"t":"I u svoje vrijeme posla vinogradarima slugu da od njih uzme dio uroda vinogradarskoga."},{"v":3,"t":"A oni ga pograbiše, istukoše i otposlaše praznih ruku."},{"v":4,"t":"I opet posla k njima drugog slugu: i njemu razbiše glavu i izružiše ga."},{"v":5,"t":"Trećega također posla: njega ubiše. Tako i mnoge druge: jedne istukoše, druge pobiše.”"},{"v":6,"t":"“Još jednoga imaše, sina ljubljenoga. Njega naposljetku posla k njima misleći: 'Poštovat će sina moga.'"},{"v":7,"t":"Ali ti vinogradari među sobom rekoše: 'Ovo je baštinik! Hajde da ga ubijemo i baština će biti naša.'"},{"v":8,"t":"I pograbe ga, ubiju i izbace iz vinograda.”"},{"v":9,"t":"“Što li će učiniti gospodar vinograda? Doći će i pobiti te vinogradare i dati vinograd drugima."},{"v":10,"t":"Niste li čitali ovo Pismo: Kamen što ga odbaciše graditelji, postade kamen zaglavni."},{"v":11,"t":"Gospodnje je to djelo - kakvo čudo u očima našim!”"},{"v":12,"t":"I tražili su da ga uhvate, ali se pobojaše mnoštva. Razumješe da je protiv njih izrekao prispodobu pa ga ostave i odu."},{"v":13,"t":"I pošalju k njemu neke od farizeja i herodovaca da ga uhvate u riječi."},{"v":14,"t":"Oni dođu i kažu mu: “Učitelju, znamo da si istinit i ne mariš tko je tko jer nisi pristran, nego po istini učiš putu Božjemu. Je li dopušteno dati porez caru ili nije? Da damo ili da ne damo?”"},{"v":15,"t":"A on im reče prozirući njihovo licemjerje: “Što me iskušavate? Donesite mi denar da vidim!”"},{"v":16,"t":"Oni doniješe. I reče im: “Čija je ovo slika i natpis?” A oni će mu: “Carev.”"},{"v":17,"t":"A Isus im reče: “Caru podajte carevo, a Bogu Božje!” I divili su mu se."},{"v":18,"t":"Dođu k njemu saduceji, koji vele da nema uskrsnuća, i upitaju ga:"},{"v":19,"t":"“Učitelju, Mojsije nam napisa: Umre li čiji brat i ostavi ženu, a ne ostavi djeteta, neka njegov brat uzme tu ženu te podigne porod bratu svomu."},{"v":20,"t":"Sedmero braće bijaše. Prvi uze ženu i umrije ne ostavivši poroda."},{"v":21,"t":"I drugi je uze te umrije ne ostavivši poroda. I treći jednako tako."},{"v":22,"t":"I sedmorica ne ostaviše poroda. Najposlije i žena umrije."},{"v":23,"t":"Komu će biti žena o uskrsnuću, kad uskrsnu? Jer sedmorica su je imala za ženu.”"},{"v":24,"t":"Reče im Isus: “Niste li u zabludi zbog toga što ne razumijete Pisama ni sile Božje?"},{"v":25,"t":"Ta kad od mrtvih ustaju, niti se žene niti udavaju, nego su kao anđeli na nebesima."},{"v":26,"t":"A što se tiče mrtvih, da ustaju, niste li čitali u knjizi Mojsijevoj ono o grmu, kako Mojsiju reče Bog: Ja sam Bog Abrahamov i Bog Izakov i Bog Jakovljev?"},{"v":27,"t":"Nije on Bog mrtvih, nego živih. Uvelike se varate.”"},{"v":28,"t":"Tada pristupi jedan od pismoznanaca koji je slušao njihovu raspravu. Vidjevši da im je dobro odgovorio, upita ga: “Koja je zapovijed prva od sviju?”"},{"v":29,"t":"Isus odgovori: “Prva je: Slušaj, Izraele! Gospodin Bog naš Gospodin je jedini."},{"v":30,"t":"Zato ljubi Gospodina Boga svojega iz svega srca svojega, i iz sve duše svoje, i iz svega uma svoga, i iz sve snage svoje!”"},{"v":31,"t":"“Druga je: Ljubi svoga bližnjega kao sebe samoga. Nema druge zapovijedi veće od tih.”"},{"v":32,"t":"Nato će mu pismoznanac: “Dobro, učitelju! Po istini si kazao: On je jedini, nema drugoga osim njega."},{"v":33,"t":"Njega ljubiti iz svega srca, iz svega razuma i iz sve snage i ljubiti bližnjega kao sebe samoga - više je nego sve paljenice i žrtve.”"},{"v":34,"t":"Kad Isus vidje kako je pametno odgovorio, reče mu: “Nisi daleko od kraljevstva Božjega!” I nitko se više nije usuđivao pitati ga."},{"v":35,"t":"A naučavajući u Hramu, uze Isus govoriti: “Kako pismoznanci kažu da je Krist sin Davidov?"},{"v":36,"t":"A sam David reče u Duhu Svetome: Reče Gospod Gospodinu mojemu: 'Sjedni mi zdesna dok ne položim neprijatelje tvoje za podnožje nogama tvojim!'"},{"v":37,"t":"Sam ga David zove Gospodinom. Kako mu je onda sin?” Silan ga je svijet s užitkom slušao."},{"v":38,"t":"A on im u pouci svojoj govoraše: “Čuvajte se pismoznanaca, koji rado idu u dugim haljinama, vole pozdrave na trgovima,"},{"v":39,"t":"prva sjedala u sinagogama i pročelja na gozbama;"},{"v":40,"t":"proždiru kuće udovičke, još pod izlikom dugih molitava. Stići će ih to oštrija osuda!”"},{"v":41,"t":"Potom sjede nasuprot riznici te promatraše kako narod baca sitniš u riznicu. Mnogi bogataši bacahu mnogo."},{"v":42,"t":"Dođe i neka siromašna udovica i baci dva novčića, to jest jedan kvadrant."},{"v":43,"t":"Tada dozove svoje učenike i reče im: “Doista, kažem vam, ova je sirota udovica ubacila više od svih koji ubacuju u riznicu."},{"v":44,"t":"Svi su oni zapravo ubacili od svoga suviška, a ona je od svoje sirotinje ubacila sve što je imala, sav svoj žitak.”"}]},"13":{"hr":[{"v":1,"t":"Kad je izlazio iz Hrama, rekne mu jedan od njegovih učenika: “Učitelju, gledaj! Kakva li kamenja, kakvih li zdanja!”"},{"v":2,"t":"Isus mu odvrati: “Vidiš li ta veličanstvena zdanja? Ne, neće se ostaviti ni kamen na kamenu nerazvaljen.”"},{"v":3,"t":"Dok je zatim na Maslinskoj gori sjedio sučelice Hramu, upitaju ga nasamo Petar, Jakov, Ivan i Andrija:"},{"v":4,"t":"“Reci nam kada će to biti i na koji se znak sve to ima svršiti?”"},{"v":5,"t":"Tada im Isus poče govoriti: “Pazite da vas tko ne zavede."},{"v":6,"t":"Mnogi će doći u moje ime i govoriti: Ja sam! I mnoge će zavesti."},{"v":7,"t":"Kada pak čujete za ratove i za glasove o ratovima, ne uznemirujte se. Treba da se to dogodi, ali to još nije svršetak.”"},{"v":8,"t":"“Narod će ustati protiv naroda, kraljevstvo protiv kraljevstva. Bit će potresa po raznim mjestima, bit će gladi. To je početak trudova.”"},{"v":9,"t":"“Vi pak pazite sami na sebe. Predavat će vas vijećima i tući vas u sinagogama, pred upraviteljima i kraljevima stajat ćete zbog mene, njima za svjedočanstvo."},{"v":10,"t":"A treba da se najprije svim narodima propovijeda evanđelje.”"},{"v":11,"t":"“Kad vas budu vodili na izručenje, ne brinite se unaprijed što ćete govoriti, nego govorite što vam bude dano u onaj čas. Ta niste vi koji govorite, nego Duh Sveti."},{"v":12,"t":"Predavat će na smrt brat brata i otac sina. Djeca će ustajati na roditelje i ubijati ih."},{"v":13,"t":"Svi će vas zamrziti zbog imena moga. Ali tko ustraje do svršetka, bit će spašen.”"},{"v":14,"t":"“I kad vidite da grozota pustoši stoluje gdje joj nije mjesto - tko čita, neka razumije - koji se tada zateknu u Judeji, neka bježe u gore!"},{"v":15,"t":"Tko bude na krovu, neka ne silazi i ne ulazi u kuću da iz nje što uzme."},{"v":16,"t":"I tko bude u polju, neka se ne okreće natrag da uzme ogrtač!”"},{"v":17,"t":"“Jao trudnicama i dojiljama u one dane!"},{"v":18,"t":"A molite da to ne bude zimi"},{"v":19,"t":"jer će onih dana biti tjeskoba kakve ne bi od početka stvorenja, koje stvori Bog, sve do sada, a neće je ni biti."},{"v":20,"t":"I kad Gospodin ne bi skratio dane one, nitko se ne bi spasio. No poradi izabranih, koje on sebi izabra, skratio je on te dane.”"},{"v":21,"t":"Ako vam tada tko rekne: 'Evo Krista ovdje! Eno ondje!' - ne vjerujte."},{"v":22,"t":"Ustat će doista lažni kristi i lažni proroci i tvorit će znamenja i čudesa da, bude li moguće, zavedu izabrane."},{"v":23,"t":"Vi dakle budite na oprezu! Evo, prorekao sam vam sve!”"},{"v":24,"t":"Nego, u one dane, nakon one nevolje, sunce će pomrčati i mjesec neće više svijetljeti"},{"v":25,"t":"a zvijezde će s neba padati i sile će se nebeske poljuljati."},{"v":26,"t":"Tada će ugledati Sina Čovječjega gdje dolazi na oblacima s velikom moći i slavom."},{"v":27,"t":"I razaslat će anđele i sabrati svoje izabranike s četiri vjetra, s kraja zemlje do na kraj neba.”"},{"v":28,"t":"A od smokve se naučite prispodobi! Kad joj grana već omekša i lišće potjera, znate: ljeto je blizu."},{"v":29,"t":"Tako i vi kad vidite da se to zbiva, znajte: blizu je, na vratima!"},{"v":30,"t":"Zaista, kažem vam, ne, neće uminuti naraštaj ovaj dok se sve to ne zbude."},{"v":31,"t":"Nebo će i zemlja uminuti, ali riječi moje ne, neće uminuti.”"},{"v":32,"t":"“A o onom danu i času nitko ne zna, pa ni anđeli na nebu, ni Sin, nego samo Otac.”"},{"v":33,"t":"“Pazite! Bdijte jer ne znate kada je čas."},{"v":34,"t":"Kao kad ono čovjek neki polazeći na put ostavi svoju kuću, upravu povjeri slugama, svakomu svoj posao, a vrataru zapovjedi da bdije."},{"v":35,"t":"Bdijte, dakle, jer ne znate kad će se domaćin vratiti - da li uvečer ili o ponoći, da li za prvih pijetlova ili ujutro -"},{"v":36,"t":"da vas ne bi našao pozaspale ako iznenada dođe.”"},{"v":37,"t":"“Što vama kažem, svima kažem: Bdijte!”"}]},"14":{"hr":[{"v":1,"t":"Za dva dana bijaše Pasha i Beskvasni kruhovi. Glavari svećenički i pismoznanci tražili su kako da ga na prijevaru uhvate i ubiju."},{"v":2,"t":"Jer se govorilo: “Nikako ne na Blagdan da ne nastane pobuna naroda.”"},{"v":3,"t":"I kad je u Betaniji, u kući Šimuna Gubavca, bio za stolom, dođe neka žena s alabastrenom posudicom prave skupocjene nardove pomasti. Razbi posudicu i poli ga po glavi."},{"v":4,"t":"A neki negodovahu te će jedan drugomu: “Čemu to rasipanje pomasti?"},{"v":5,"t":"Mogla se pomast prodati za više od tristo denara i dati siromasima.” I otresahu se na nju."},{"v":6,"t":"A Isus reče: “Pustite je, što joj dodijavate? Dobro djelo učini na meni."},{"v":7,"t":"Ta siromaha svagda imate uza se i kad god hoćete možete im dobro činiti, a mene nemate svagda."},{"v":8,"t":"Učinila je što je mogla: unaprijed mi pomaza tijelo za ukop."},{"v":9,"t":"Zaista, kažem vam, gdje se god bude propovijedalo evanđelje, po svem svijetu, navješćivat će se i ovo što ona učini - njoj na spomen.”"},{"v":10,"t":"A Juda Iškariotski, jedan od dvanaestorice, ode glavarima svećeničkim da im ga preda."},{"v":11,"t":"Kad su oni to čuli, obradovali su se i obećali mu dati novca. I tražio je zgodu da ga preda."},{"v":12,"t":"Prvoga dana Beskvasnih kruhova, kad se žrtvovala pasha, upitaju učenici Isusa: “Gdje hoćeš blagovati pashu, da odemo i pripravimo?”"},{"v":13,"t":"On pošalje dvojicu učenika i rekne im: “Idite u grad i namjerit ćete se na čovjeka koji nosi krčag vode. Pođite za njim"},{"v":14,"t":"pa gdje on uđe, recite domaćinu: 'Učitelj pita: Gdje mi je svratište u kojem bih blagovao pashu sa svojim učenicima?'"},{"v":15,"t":"I on će vam pokazati na katu veliko blagovalište, prostrto i spremljeno. Ondje nam pripravite.”"},{"v":16,"t":"Učenici odu, dođu u grad i nađu kako im on reče te priprave pashu."},{"v":17,"t":"A uvečer dođe on s dvanaestoricom."},{"v":18,"t":"I dok bijahu za stolom te blagovahu, reče Isus: “Zaista, kažem vam, jedan će me od vas izdati - koji sa mnom blaguje.”"},{"v":19,"t":"Ožalošćeni, stanu mu govoriti jedan za drugim: “Da nisam ja?”"},{"v":20,"t":"A on im reče: “Jedan od dvanaestorice koji umače sa mnom u zdjelicu."},{"v":21,"t":"Sin Čovječji, istina, odlazi kako je o njemu pisano, ali jao čovjeku onomu koji ga predaje. Tomu bi čovjeku bolje bilo da se ni rodio nije!”"},{"v":22,"t":"I dok su blagovali, on uze kruh, izreče blagoslov pa razlomi, dade im i reče: “Uzmite, ovo je tijelo moje.”"},{"v":23,"t":"I uze čašu, zahvali i dade im. I svi su iz nje pili."},{"v":24,"t":"A on im reče: “Ovo je krv moja, krv Saveza, koja se za mnoge prolijeva."},{"v":25,"t":"Zaista, kažem vam, ne, neću više piti od ovoga roda trsova do onoga dana kad ću ga - novoga - piti u kraljevstvu Božjem.”"},{"v":26,"t":"Otpjevavši hvalospjeve, zaputiše se prema Maslinskoj gori."},{"v":27,"t":"I reče im Isus: “Svi ćete se sablazniti. Ta pisano je: Udarit ću pastira i ovce će se razbjeći."},{"v":28,"t":"Ali kad uskrsnem, ići ću pred vama u Galileju.”"},{"v":29,"t":"Nato će mu Petar: “Ako se i svi sablazne, ja neću!”"},{"v":30,"t":"A Isus mu reče: “Zaista, kažem ti, baš ti, danas, ove noći, prije nego se pijetao dvaput oglasi, triput ćeš me zatajiti.”"},{"v":31,"t":"Ali on je upornije uvjeravao: “Bude li trebalo i umrijeti s tobom - ne, neću te zatajiti.” A tako su svi govorili."},{"v":32,"t":"I dođu u predio imenom Getsemani. I kaže Isus svojim učenicima: “Sjednite ovdje dok se ne pomolim.”"},{"v":33,"t":"I povede sa sobom Petra, Jakova i Ivana. Spopade ga užas i tjeskoba"},{"v":34,"t":"pa im reče: “Duša mi je nasmrt žalosna! Ostanite ovdje i bdijte!”"},{"v":35,"t":"Ode malo dalje i rušeći se na zemlju molio je da ga, ako je moguće, mimoiđe ovaj čas."},{"v":36,"t":"Govoraše: “Abba! Oče! Tebi je sve moguće! Otkloni čašu ovu od mene! Ali ne što ja hoću, nego što hoćeš ti!”"},{"v":37,"t":"I dođe, nađe ih pozaspale pa reče Petru: “Šimune, spavaš? Jedan sat nisi mogao probdjeti?"},{"v":38,"t":"Bdijte i molite da ne padnete u napast. Duh je, istina, voljan, no tijelo je slabo.”"},{"v":39,"t":"Opet ode i pomoli se istim riječima."},{"v":40,"t":"Ponovno dođe i nađe ih pozaspale. Oči im se sklapale i nisu znali što da mu odgovore."},{"v":41,"t":"Dođe i treći put i reče im: “Samo spavajte i počivajte! Gotovo je! Dođe čas! Evo, predaje se Sin Čovječji u ruke grešničke!"},{"v":42,"t":"Ustanite, hajdemo! Evo, izdajica se moj približio!”"},{"v":43,"t":"Uto, dok je on još govorio, stiže Juda, jedan od dvanaestorice, i s njime svjetina s mačevima i toljagama, poslana od glavara svećeničkih, pismoznanaca i starješina."},{"v":44,"t":"A izdajica im njegov dade znak: “Koga poljubim, taj je! Uhvatite ga i oprezno odvedite!”"},{"v":45,"t":"I kako dođe, odmah pristupi k njemu i reče: “Učitelju!” I poljubi ga."},{"v":46,"t":"Oni podignu na nj ruke i uhvate ga."},{"v":47,"t":"A jedan od nazočnih trgnu mač, udari slugu velikoga svećenika i odsiječe mu uho."},{"v":48,"t":"Isus im prozbori: “Kao na razbojnika iziđoste s mačevima i toljagama da me uhvatite."},{"v":49,"t":"Danomice bijah vam u Hramu, naučavah i ne uhvatiste me. No neka se ispune Pisma!”"},{"v":50,"t":"I svi ga ostave i pobjegnu."},{"v":51,"t":"A jedan je mladić išao za njim, ogrnut samo plahtom. I njega htjedoše uhvatiti,"},{"v":52,"t":"no on ostavi plahtu i gol pobježe."},{"v":53,"t":"Zatim odvedoše Isusa velikom svećeniku. I skupe se svi glavari svećenički, starješine i pismoznanci."},{"v":54,"t":"Petar je izdaleka išao za njim do u dvor velikog svećenika. Tu je sjedio sa stražarima i grijao se uz vatru."},{"v":55,"t":"A glavari svećenički i cijelo Vijeće, da bi mogli pogubiti Isusa, tražili su protiv njega kakvo svjedočanstvo, ali nikako da ga nađu."},{"v":56,"t":"Mnogi su doduše lažno svjedočili protiv njega, ali im se svjedočanstva ne slagahu."},{"v":57,"t":"Ustali su neki i lažno svjedočili protiv njega:"},{"v":58,"t":"“Mi smo ga čuli govoriti: 'Ja ću razvaliti ovaj rukotvoreni Hram i za tri dana sagraditi drugi, nerukotvoreni!'”"},{"v":59,"t":"Ali ni u tom im svjedočanstvo ne bijaše složno."},{"v":60,"t":"Usta nato veliki svećenik na sredinu i upita Isusa: “Zar ništa ne odgovaraš? Što to ovi svjedoče protiv tebe?"},{"v":61,"t":"A on je šutio i ništa mu nije odgovarao. Veliki ga svećenik ponovo upita: “Ti li si Krist, Sin Blagoslovljenoga?”"},{"v":62,"t":"A Isus mu reče: “Ja jesam! I gledat ćete Sina Čovječjega gdje sjedi zdesna Sile i dolazi s oblacima nebeskim.”"},{"v":63,"t":"Nato veliki svećenik razdrije haljine i reče: “Što nam još trebaju svjedoci?"},{"v":64,"t":"Čuli ste hulu. Što vam se čini?” Oni svi presudiše da zaslužuje smrt."},{"v":65,"t":"I neki stanu pljuvati po njemu, zastirati mu lice i udarati ga govoreći: “Proreci!” I sluge ga stadoše pljuskati."},{"v":66,"t":"I dok je Petar bio dolje u dvoru, dođe jedna sluškinja velikoga svećenika;"},{"v":67,"t":"ugledavši Petra gdje se grije, upre u nj pogled i reče: “I ti bijaše s Nazarećaninom, Isusom.”"},{"v":68,"t":"On zanijeka: “Niti znam niti razumijem što govoriš.” I iziđe van u predvorje, a pijetao se oglasi."},{"v":69,"t":"Sluškinja ga ugleda i poče opet govoriti nazočnima: “Ovaj je od njih!”"},{"v":70,"t":"On opet nijekaše. Domalo nazočni opet stanu govoriti Petru: “Doista, i ti si od njih! Ta Galilejac si!”"},{"v":71,"t":"On se tada stane kleti i preklinjati: “Ne znam čovjeka o kom govorite!”"},{"v":72,"t":"I odmah se po drugi put oglasi pijetao. I spomenu se Petar one besjede, kako mu ono Isus reče: “Prije nego se pijetao dvaput oglasi, triput ćeš me zatajiti.” I briznu u plač."}]},"15":{"hr":[{"v":1,"t":"Odmah izjutra glavari svećenički zajedno sa starješinama i pismoznancima - cijelo Vijeće - upriličili su vijećanje pa Isusa svezali, odveli i predali Pilatu."},{"v":2,"t":"I upita ga Pilat: “Ti li si kralj židovski?” On mu odgovori: “Ti kažeš.”"},{"v":3,"t":"I glavari ga svećenički teško optuživahu."},{"v":4,"t":"Pilat ga opet upita: “Ništa ne odgovaraš? Gle, koliko te optužuju.”"},{"v":5,"t":"A Isus ništa više ne odgovori te se Pilat čudio."},{"v":6,"t":"O Blagdanu bi im pustio uznika koga bi zaiskali."},{"v":7,"t":"A zajedno s pobunjenicima koji u pobuni počiniše umorstvo bijaše u okove bačen čovjek zvani Baraba."},{"v":8,"t":"I uziđe svjetina te poče od Pilata iskati ono što im običavaše činiti."},{"v":9,"t":"A on im odgovori: “Hoćete li da vam pustim kralja židovskoga?”"},{"v":10,"t":"Znao je doista da ga glavari svećenički bijahu predali iz zavisti."},{"v":11,"t":"Ali glavari svećenički podjare svjetinu da traži neka im radije pusti Barabu."},{"v":12,"t":"Pilat ih opet upita: “Što dakle da učinim s ovim kojega zovete kraljem židovskim?”"},{"v":13,"t":"A oni opet povikaše: “Raspni ga!”"},{"v":14,"t":"Reče im Pilat: “Ta što je zla učinio?” Povikaše još jače: “Raspni ga!”"},{"v":15,"t":"Hoteći ugoditi svjetini, Pilat im pusti Barabu, a Isusa izbičeva i preda da se razapne."},{"v":16,"t":"Vojnici ga odvedu u unutarnjost dvora, to jest u pretorij, pa sazovu cijelu četu"},{"v":17,"t":"i zaogrnu ga grimizom; spletu trnov vijenac i stave mu na glavu"},{"v":18,"t":"te ga stanu pozdravljati: “Zdravo, kralju židovski!”"},{"v":19,"t":"I udarahu ga trskom po glavi, pljuvahu po njemu i klanjahu mu se prigibajući koljena."},{"v":20,"t":"A pošto ga izrugaše, svukoše mu grimiz i obukoše mu njegove haljine. I izvedu ga da ga razapnu."},{"v":21,"t":"I prisile nekog prolaznika koji je dolazio s polja, Šimuna Cirenca, oca Aleksandrova i Rufova, da mu ponese križ."},{"v":22,"t":"I dovuku ga na mjesto Golgotu, što znači Lubanjsko mjesto."},{"v":23,"t":"I nuđahu mu piti namirisana vina, ali on ne uze."},{"v":24,"t":"Kad ga razapeše, razdijele među se haljine njegove bacivši za njih kocku - što će tko uzeti."},{"v":25,"t":"A bijaše treća ura kad ga razapeše."},{"v":26,"t":"Bijaše napisan i natpis o njegovoj krivici: “Kralj židovski.”"},{"v":27,"t":"A zajedno s njime razapnu i dva razbojnika, jednoga njemu zdesna, drugoga slijeva."},{"v":28,"t":"#"},{"v":29,"t":"Prolaznici su ga pogrđivali mašući glavama: “Ej, ti, koji razvaljuješ Hram i sagradiš ga za tri dana,"},{"v":30,"t":"spasi sam sebe, siđi s križa!”"},{"v":31,"t":"Slično i glavari svećenički s pismoznancima rugajući se govorahu jedni drugima: “Druge je spasio, sebe ne može spasiti!"},{"v":32,"t":"Krist, kralj Izraelov! Neka sad siđe s križa da vidimo i povjerujemo!” Vrijeđahu ga i oni koji bijahu s njim raspeti."},{"v":33,"t":"A o šestoj uri tama nasta po svoj zemlji - sve do ure devete."},{"v":34,"t":"O devetoj uri povika Isus iza glasa: “Eloi, Eloi lama sabahtani?” To znači: “Bože moj, Bože moj, zašto si me ostavio?”"},{"v":35,"t":"Neki od nazočnih čuvši to govorahu: “Gle, Iliju zove.”"},{"v":36,"t":"A jedan otrča, natopi spužvu octom, natakne na trsku i pruži mu piti govoreći: “Pustite da vidimo hoće li doći Ilija da ga skine.”"},{"v":37,"t":"A Isus zavapi jakim glasom i izdahnu."},{"v":38,"t":"I zavjesa se hramska razdrije nadvoje, odozgor dodolje."},{"v":39,"t":"A kad satnik koji stajaše njemu nasuprot vidje da tako izdahnu, reče: “Zaista, ovaj čovjek bijaše Sin Božji!”"},{"v":40,"t":"Izdaleka promatrahu i neke žene: među njima Marija Magdalena i Marija, majka Jakova Mlađega i Josipa, i Saloma -"},{"v":41,"t":"te su ga pratile kad bijaše u Galileji i posluživale mu - i mnoge druge koje uziđoše s njim u Jeruzalem."},{"v":42,"t":"A uvečer, budući da je bila Priprava, to jest predvečerje subote,"},{"v":43,"t":"dođe Josip iz Arimateje, ugledan vijećnik, koji također isčekivaše kraljevstvo Božje: odvaži se, uđe k Pilatu i zaiska tijelo Isusovo."},{"v":44,"t":"Pilat se začudi da je već umro pa dozva satnika i upita ga je li odavna umro."},{"v":45,"t":"Kad sazna od satnika, darova Josipu tijelo."},{"v":46,"t":"Josip kupi platno, skine tijelo i zavije ga u platno te položi u grob, koji bijaše izduben iz stijene. I dokotrlja kamen na grobna vrata."},{"v":47,"t":"A Marija Magdalena i Marija Josipova promatrahu kamo ga polažu."}]},"16":{"hr":[{"v":1,"t":"Kad prođe subota, Marija Magdalena i Marija Jakovljeva i Saloma kupiše miomirisa da odu pomazati Isusa."},{"v":2,"t":"I prvoga dana u tjednu, veoma rano, o izlasku sunčevu, dođu na grob."},{"v":3,"t":"I razgovarahu među sobom: “Tko će nam otkotrljati kamen s vrata grobnih?”"},{"v":4,"t":"Pogledaju, a ono kamen otkotrljan. Bijaše doista veoma velik."},{"v":5,"t":"I ušavši u grob, ugledaju mladića zaogrnuta bijelom haljinom gdje sjedi zdesna. I preplaše se."},{"v":6,"t":"A on će im: “Ne plašite se! Isusa tražite, Nazarećanina, Raspetoga? Uskrsnu! Nije ovdje! Evo mjesta kamo ga položiše."},{"v":7,"t":"Nego idite, recite njegovim učenicima i Petru: Ide pred vama u Galileju! Ondje ćete ga vidjeti, kamo vam reče!”"},{"v":8,"t":"One iziđu i stanu bježati od groba: spopade ih strah i trepet. I nikomu ništa ne rekoše jer se bojahu."},{"v":9,"t":"Uskrsnuvši dakle rano prvog dana u tjednu, ukaza se najprije Mariji Magdaleni iz koje bijaše istjerao sedam zloduha."},{"v":10,"t":"Ona ode i dojavi njegovima, tužnima i zaplakanima."},{"v":11,"t":"Kad su oni čuli da je živ i da ga je ona vidjela, ne povjerovaše."},{"v":12,"t":"Nakon toga ukazao se u drugome obličju dvojici od njih na putu dok su išli u selo."},{"v":13,"t":"I oni odu i dojave drugima. Ni njima ne povjerovaše."},{"v":14,"t":"Napokon se ukaza jedanaestorici dok bijahu za stolom. Prekori njihovu nevjeru i okorjelost srca što ne povjerovaše onima koji ga vidješe uskrsla od mrtvih."},{"v":15,"t":"I reče im: “Pođite po svem svijetu, propovijedajte evanđelje svemu stvorenju."},{"v":16,"t":"Tko uzvjeruje i pokrsti se, spasit će se, a tko ne uzvjeruje, osudit će se."},{"v":17,"t":"A ovi će znakovi pratiti one koji uzvjeruju: u ime će moje izganjati zloduhe, novim će jezicima zboriti,"},{"v":18,"t":"zmije uzimati; i popiju li što smrtonosno, ne, neće im nauditi; na nemoćnike će ruke polagati, i bit će im dobro.”"},{"v":19,"t":"I Gospodin Isus, pošto im to reče, bude uzet na nebo i sjede zdesna Bogu."},{"v":20,"t":"Oni pak odoše i propovijedahu posvuda, a Gospodin surađivaše i utvrđivaše Riječ popratnim znakovima."}]}},"LUK":{"1":{"hr":[{"v":1,"t":"Kad već mnogi poduzeše sastaviti izvješće o događajima koji se ispuniše među nama -"},{"v":2,"t":"kako nam to predadoše oni koji od početka bijahu očevici i sluge Riječi -"},{"v":3,"t":"pošto sam sve, od početka, pomno ispitao, naumih i ja tebi, vrli Teofile, sve po redu napisati"},{"v":4,"t":"da se tako osvjedočiš o pouzdanosti svega u čemu si poučen."},{"v":5,"t":"U dane Heroda, kralja judejskoga, bijaše neki svećenik imenom Zaharija iz razreda Abijina. Žena mu bijaše od kćeri Aronovih, a ime joj Elizabeta."},{"v":6,"t":"Oboje bijahu pravedni pred Bogom: živjeli su besprijekorno po svim zapovijedima i odredbama Gospodnjim."},{"v":7,"t":"No nisu imali djeteta jer Elizabeta bijaše nerotkinja, a oboje već poodmakle dobi."},{"v":8,"t":"Dok je Zaharija jednom po redu svoga razreda obavljao svećeničku službu pred Bogom,"},{"v":9,"t":"ždrijebom ga zapade po bogoslužnom običaju da uđe u Svetište Gospodnje i prinese kad."},{"v":10,"t":"Za vrijeme kađenice sve je ono mnoštvo naroda vani molilo."},{"v":11,"t":"A njemu se ukaza anđeo Gospodnji. Stajao je s desne strane kadionoga žrtvenika."},{"v":12,"t":"Ugledavši ga, Zaharija se prepade i strah ga spopade."},{"v":13,"t":"No anđeo mu reče: “Ne boj se, Zaharija! Uslišana ti je molitva: žena će ti Elizabeta roditi sina. Nadjenut ćeš mu ime Ivan."},{"v":14,"t":"Bit će ti radost i veselje i rođenje će njegovo mnoge obradovati."},{"v":15,"t":"Bit će doista velik pred Gospodinom. Ni vina ni drugoga opojnog pića neće piti. Duha Svetoga bit će pun već od majčine utrobe."},{"v":16,"t":"Mnoge će sinove Izraelove obratiti Gospodinu, Bogu njihovu."},{"v":17,"t":"Ići će pred njim u duhu i sili Ilijinoj da obrati srce otaca k sinovima i nepokorne k razumnosti pravednih te spremi Gospodinu narod pripravan.”"},{"v":18,"t":"Nato Zaharija reče anđelu: “Po čemu ću ja to razaznati. Ta star sam i žena mi poodmakle dobi.”"},{"v":19,"t":"Anđeo mu odgovori: “Ja sam Gabriel koji stojim pred Bogom. Poslan sam da govorim s tobom i da ti donesem ovu radosnu poruku."},{"v":20,"t":"I evo, budući da nisi povjerovao mojim riječima, koje će se ispuniti u svoje vrijeme, zanijemjet ćeš i nećeš moći govoriti do dana dok se to ne zbude.”"},{"v":21,"t":"Narod je iščekivao Zahariju i čudio se što se toliko zadržao u Svetištu."},{"v":22,"t":"Kad je napokon izašao, nije im mogao ništa reći pa zaključiše da je u Svetištu imao viđenje. Nastojao im se doduše izraziti znakovima, ali osta nijem."},{"v":23,"t":"Kad se navršiše dani njegove službe, otiđe kući."},{"v":24,"t":"Nakon tih dana zatrudnje Elizabeta, njegova žena. Krila se pet mjeseci govoreći:"},{"v":25,"t":"“Evo, to mi je učinio Gospodin u dane kad mu se svidje skinuti s mene sramotu među ljudima.”"},{"v":26,"t":"U šestome mjesecu posla Bog anđela Gabriela u galilejski grad imenom Nazaret"},{"v":27,"t":"k djevici zaručenoj s mužem koji se zvao Josip iz doma Davidova; a djevica se zvala Marija."},{"v":28,"t":"Anđeo uđe k njoj i reče: “Zdravo, milosti puna! Gospodin s tobom!”"},{"v":29,"t":"Na tu se riječ ona smete i stade razmišljati kakav bi to bio pozdrav."},{"v":30,"t":"No anđeo joj reče: “Ne boj se, Marijo! Ta našla si milost u Boga."},{"v":31,"t":"Evo, začet ćeš i roditi sina i nadjenut ćeš mu ime Isus."},{"v":32,"t":"On će biti velik i zvat će se Sin Svevišnjega. Njemu će Gospodin Bog dati prijestolje Davida, oca njegova,"},{"v":33,"t":"i kraljevat će nad domom Jakovljevim uvijeke i njegovu kraljevstvu neće biti kraja.”"},{"v":34,"t":"Nato će Marija anđelu: “Kako će to biti kad ja muža ne poznajem?”"},{"v":35,"t":"Anđeo joj odgovori: “Duh Sveti sići će na te i sila će te Svevišnjega osjeniti. Zato će to čedo i biti sveto, Sin Božji."},{"v":36,"t":"A evo tvoje rođakinje Elizabete: i ona u starosti svojoj zače sina. I njoj, nerotkinjom prozvanoj, ovo je već šesti mjesec."},{"v":37,"t":"Ta Bogu ništa nije nemoguće!”"},{"v":38,"t":"Nato Marija reče: “Evo službenice Gospodnje, neka mi bude po tvojoj riječi!” I anđeo otiđe od nje."},{"v":39,"t":"Tih dana usta Marija i pohiti u Gorje, u grad Judin."},{"v":40,"t":"Uđe u Zaharijinu kuću i pozdravi Elizabetu."},{"v":41,"t":"Čim Elizabeta začu Marijin pozdrav, zaigra joj čedo u utrobi. I napuni se Elizabeta Duha Svetoga"},{"v":42,"t":"i povika iz svega glasa: “Blagoslovljena ti među ženama i blagoslovljen plod utrobe tvoje!"},{"v":43,"t":"Ta otkuda meni da mi dođe majka Gospodina mojega?"},{"v":44,"t":"Gledaj samo! Tek što mi do ušiju doprije glas pozdrava tvojega, zaigra mi od radosti čedo u utrobi."},{"v":45,"t":"Blažena ti što povjerova da će se ispuniti što ti je rečeno od Gospodina!”"},{"v":46,"t":"Tada Marija reče: “Veliča duša moja Gospodina,"},{"v":47,"t":"klikće duh moj u Bogu, mome Spasitelju,"},{"v":48,"t":"što pogleda na neznatnost službenice svoje: odsad će me, evo, svi naraštaji zvati blaženom."},{"v":49,"t":"Jer velika mi djela učini Svesilni, sveto je ime njegovo!"},{"v":50,"t":"Od koljena do koljena dobrota je njegova nad onima što se njega boje."},{"v":51,"t":"Iskaza snagu mišice svoje, rasprši oholice umišljene."},{"v":52,"t":"Silne zbaci s prijestolja, a uzvisi neznatne."},{"v":53,"t":"Gladne napuni dobrima, a bogate otpusti prazne."},{"v":54,"t":"Prihvati Izraela, slugu svoga, kako obeća ocima našim:"},{"v":55,"t":"spomenuti se dobrote svoje prema Abrahamu i potomstvu njegovu dovijeka.”"},{"v":56,"t":"Marija osta s Elizabetom oko tri mjeseca, a onda se vrati kući."},{"v":57,"t":"Elizabeti se međutim navršilo vrijeme da rodi. I porodi sina."},{"v":58,"t":"Kad su njezini susjedi i rođaci čuli da joj Gospodin obilno iskaza dobrotu, radovahu se s njome."},{"v":59,"t":"Osmoga se dana okupe da obrežu dječaka. Htjedoše ga prozvati imenom njegova oca - Zaharija,"},{"v":60,"t":"no mati se njegova usprotivi: “Nipošto, nego zvat će se Ivan!”"},{"v":61,"t":"Rekoše joj na to: “Ta nikoga nema od tvoje rodbine koji bi se tako zvao.”"},{"v":62,"t":"Tada znakovima upitaju oca kojim ga imenom želi prozvati."},{"v":63,"t":"On zaiska pločicu i napisa “Ivan mu je ime!” Svi se začude,"},{"v":64,"t":"a njemu se umah otvoriše usta i jezik te progovori blagoslivljajući Boga."},{"v":65,"t":"Strah obuze sve njihove susjede, a po svem su se Gorju judejskom razglašavali svi ti događaji."},{"v":66,"t":"I koji su god čuli, razmišljahu o tome pitajući se: “Što li će biti od ovoga djeteta?” Uistinu, ruka Gospodnja bijaše s njime."},{"v":67,"t":"A Zaharija, otac njegov, napuni se Duha Svetoga i stade prorokovati:"},{"v":68,"t":"“Blagoslovljen Gospodin Bog Izraelov, što pohodi i otkupi narod svoj!"},{"v":69,"t":"Podiže nam snagu spasenja u domu Davida, sluge svojega,"},{"v":70,"t":"kao što obeća na usta svetih proroka svojih odvijeka:"},{"v":71,"t":"spasiti nas od neprijatelja naših i od ruke sviju koji nas mrze;"},{"v":72,"t":"iskazati dobrotu ocima našim i sjetiti se svetog Saveza svojega,"},{"v":73,"t":"zakletve kojom se zakle Abrahamu, ocu našemu: da će nam dati"},{"v":74,"t":"te mu, izbavljeni iz ruku neprijatelja, služimo bez straha"},{"v":75,"t":"u svetosti i pravednosti pred njim u sve dane svoje."},{"v":76,"t":"A ti, dijete, prorok ćeš se Svevišnjega zvati jer ćeš ići pred Gospodinom da mu pripraviš putove,"},{"v":77,"t":"da pružiš spoznaju spasenja narodu njegovu po otpuštenju grijeha njihovih,"},{"v":78,"t":"darom premilosrdnog srca Boga našega po kojem će nas pohoditi Mlado sunce s visine"},{"v":79,"t":"da obasja one što sjede u tmini i sjeni smrtnoj, da upravi noge naše na put mira.”"},{"v":80,"t":"Dječak je međutim rastao i duhom jačao. Boravio je u pustinji sve do dana svoga javnog nastupa pred Izraelom."}]},"2":{"hr":[{"v":1,"t":"U one dane izađe naredba cara Augusta da se provede popis svega svijeta."},{"v":2,"t":"Bijaše to prvi popis izvršen za Kvirinijeva upravljanja Sirijom."},{"v":3,"t":"Svi su išli na popis, svaki u svoj grad."},{"v":4,"t":"Tako i Josip, budući da je bio iz doma i loze Davidove, uziđe iz Galileje, iz grada Nazareta, u Judeju - u grad Davidov, koji se zove Betlehem -"},{"v":5,"t":"da se podvrgne popisu zajedno sa svojom zaručnicom Marijom koja bijaše trudna."},{"v":6,"t":"I dok se bili ondje, navršilo joj se vrijeme da rodi."},{"v":7,"t":"I porodi sina svoga, prvorođenca, povi ga i položi u jasle jer za njih nije bilo mjesta u svratištu."},{"v":8,"t":"A u tom kraju bijahu pastiri: pod vedrim su nebom čuvali noćnu stražu kod svojih stada."},{"v":9,"t":"Anđeo im Gospodnji pristupi i slava ih Gospodnja obasja! Silno se prestrašiše."},{"v":10,"t":"No anđeo im reče: “Ne bojte se! Evo javljam vam blagovijest, veliku radost za sav narod!"},{"v":11,"t":"Danas vam se u gradu Davidovu rodio Spasitelj - Krist, Gospodin."},{"v":12,"t":"I evo vam znaka: naći ćete novorođenče povijeno gdje leži u jaslama.”"},{"v":13,"t":"I odjednom se anđelu pridruži silna nebeska vojska hvaleći Boga i govoreći:"},{"v":14,"t":"“Slava na visinama Bogu, a na zemlji mir ljudima, miljenicima njegovim!”"},{"v":15,"t":"Čim anđeli otiđoše od njih na nebo, pastiri stanu poticati jedni druge: “Hajdemo dakle do Betlehema. Pogledajmo što se to dogodilo, događaj koji nam obznani Gospodin.”"},{"v":16,"t":"I pohite te pronađu Mariju, Josipa i novorođenče gdje leži u jaslama."},{"v":17,"t":"Pošto sve pogledaše, ispripovijediše što im bijaše rečeno o tom djetetu."},{"v":18,"t":"A svi koji su to čuli divili se tome što su im pripovijedali pastiri."},{"v":19,"t":"Marija u sebi pohranjivaše sve te događaje i prebiraše ih u svome srcu."},{"v":20,"t":"Pastiri se zatim vratiše slaveći i hvaleći Boga za sve što su čuli i vidjeli kako im je bilo rečeno."},{"v":21,"t":"Kad se navršilo osam dana da bude obrezan, nadjenuše mu ime Isus, kako ga je bio prozvao anđeo prije njegova začeća."},{"v":22,"t":"Kad se zatim po Mojsijevu Zakonu navršiše dani njihova čišćenja, poniješe ga u Jeruzalem da ga prikažu Gospodinu -"},{"v":23,"t":"kao što piše u Zakonu Gospodnjem: Svako muško prvorođenče neka se posveti Gospodinu! -"},{"v":24,"t":"i da prinesu žrtvu kako je rečeno u Zakonu Gospodnjem: dvije grlice ili dva golubića."},{"v":25,"t":"Živio tada u Jeruzalemu čovjek po imenu Šimun. Taj čovjek, pravedan i bogobojazan, iščekivaše Utjehu Izraelovu i Duh Sveti bijaše na njemu."},{"v":26,"t":"Objavio mu Duh Sveti da neće vidjeti smrti dok ne vidi Pomazanika Gospodnjega."},{"v":27,"t":"Ponukan od Duha, dođe u Hram. I kad roditelji uniješe dijete Isusa da obave što o njemu propisuje Zakon,"},{"v":28,"t":"primi ga on u naručje, blagoslovi Boga i reče:"},{"v":29,"t":"“Sad otpuštaš slugu svojega, Gospodaru, po riječi svojoj, u miru!"},{"v":30,"t":"Ta vidješe oči moje spasenje tvoje,"},{"v":31,"t":"koje si pripravio pred licem svih naroda:"},{"v":32,"t":"svjetlost na prosvjetljenje naroda, slavu puka svoga izraelskoga.”"},{"v":33,"t":"Otac njegov i majka divili se što se to o njemu govori."},{"v":34,"t":"Šimun ih blagoslovi i reče Mariji, majci njegovoj: “Ovaj je evo postavljen na propast i uzdignuće mnogima u Izraelu i za znak osporavan -"},{"v":35,"t":"a i tebi će samoj mač probosti dušu - da se razotkriju namisli mnogih srdaca!”"},{"v":36,"t":"A bijaše neka proročica Ana, kći Penuelova, iz plemena Ašerova, žena veoma odmakla u godinama. Nakon djevojaštva živjela je s mužem sedam godina,"},{"v":37,"t":"a sama kao udovica do osamdeset i četvrte. Nije napuštala Hrama, nego je postovima i molitvama danju i noću služila Bogu."},{"v":38,"t":"Upravo u taj čas nadođe. Hvalila je Boga i svima koji iščekivahu otkupljenje Jeruzalema pripovijedala o djetetu."},{"v":39,"t":"Kad obaviše sve po Zakonu Gospodnjem, vratiše se u Galileju, u svoj grad Nazaret."},{"v":40,"t":"A dijete je raslo, jačalo i napunjalo se mudrosti i milost je Božja bila na njemu."},{"v":41,"t":"Njegovi su roditelji svake godine o blagdanu Pashe išli u Jeruzalem."},{"v":42,"t":"Kad mu bijaše dvanaest godina, uziđoše po običaju blagdanskom."},{"v":43,"t":"Kad su minuli ti dani, vraćahu se oni, a dječak Isus osta u Jeruzalemu, a da nisu znali njegovi roditelji."},{"v":44,"t":"Uvjereni da je među suputnicima, odoše dan hoda, a onda ga stanu tražiti među rodbinom i znancima."},{"v":45,"t":"I kad ga ne nađu, vrate se u Jeruzalem tražeći ga."},{"v":46,"t":"Nakon tri dana nađoše ga u Hramu gdje sjedi posred učitelja, sluša ih i pita."},{"v":47,"t":"Svi koji ga slušahu bijahu zaneseni razumnošću i odgovorima njegovim."},{"v":48,"t":"Kad ga ugledaše, zapanjiše se, a majka mu njegova reče: “Sinko, zašto si nam to učinio? Gle, otac tvoj i ja žalosni smo te tražili.”"},{"v":49,"t":"A on im reče: “Zašto ste me tražili? Niste li znali da mi je biti u onome što je Oca mojega?”"},{"v":50,"t":"Oni ne razumješe riječi koju im reče."},{"v":51,"t":"I siđe s njima, dođe u Nazaret i bijaše im poslušan. A majka je njegova brižno čuvala sve ove uspomene u svom srcu."},{"v":52,"t":"A Isus napredovaše u mudrosti, dobi i milosti kod Boga i ljudi."}]},"3":{"hr":[{"v":1,"t":"Petnaeste godine vladanja cara Tiberija, dok je upravitelj Judeje bio Poncije Pilat, tetrarh Galileje Herod, a njegov brat Filip tetrarh Itureje i zemlje trahonitidske, i Lizanije tetrarh Abilene,"},{"v":2,"t":"za velikog svećenika Ane i Kajfe, dođe riječ Božja Ivanu, sinu Zaharijinu, u pustinji."},{"v":3,"t":"On obiđe svu okolicu jordansku propovijedajući obraćeničko krštenje na otpuštenje grijeha"},{"v":4,"t":"kao što je pisano u Knjizi besjeda Izaije proroka: Glas viče u pustinji: Pripravite put Gospodinu, poravnite mu staze!"},{"v":5,"t":"Svaka dolina neka se ispuni, svaka gora i brežuljak neka se slegne! Što je krivudavo, neka se izravna, a hrapavi putovi neka se izglade!"},{"v":6,"t":"I svako će tijelo vidjeti spasenje Božje."},{"v":7,"t":"Govoraše dakle mnoštvu koje je dolazilo da se krsti: “Leglo gujinje! Tko vas samo upozori da bježite od skore srdžbe?"},{"v":8,"t":"Donosite dakle plodove dostojne obraćenja. I nemojte početi u sebi govoriti: 'Imamo oca Abrahama!' Jer, kažem vam: Bog iz ovog kamenja može podići djecu Abrahamovu."},{"v":9,"t":"Već je sjekira položena na korijen stablima: svako dakle stablo koje ne donosi dobra roda siječe se i u oganj baca.”"},{"v":10,"t":"Pitalo ga mnoštvo: “Što nam je dakle činiti?”"},{"v":11,"t":"On im odgovaraše: “Tko ima dvije haljine, neka podijeli s onim koji nema. U koga ima hrane, neka učini isto tako.”"},{"v":12,"t":"Dođoše krstiti se i carinici pa ga pitahu: “Učitelju, što nam je činiti?”"},{"v":13,"t":"Reče im: “Ne utjerujte više nego što vam je određeno.”"},{"v":14,"t":"Pitahu ga i vojnici: “A nama, što je nama činiti?” I reče im: “Nikome ne činite nasilja, nikoga krivo ne prijavljujte i budite zadovoljni svojom plaćom.”"},{"v":15,"t":"Narod bijaše u iščekivanju i svi se u srcu pitahu o Ivanu nije li on možda Krist."},{"v":16,"t":"Zato im Ivan svima reče: “Ja vas, istina, vodom krstim. Ali dolazi jači od mene. Ja nisam dostojan odriješiti mu remenje na obući. On će vas krstiti Duhom Svetim i ognjem."},{"v":17,"t":"U ruci mu vijača da pročisti gumno svoje i sabere žito u žitnicu svoju, a pljevu će spaliti ognjem neugasivim.”"},{"v":18,"t":"I mnogim je drugim pobudama Ivan narodu navješćivao evanđelje."},{"v":19,"t":"A Heroda je tetrarha Ivan prekorio zbog Herodijade, žene njegova brata i zbog svih njegovih zlodjela."},{"v":20,"t":"Svemu tome nadoda Herod još i ovo: zatvori Ivana u tamnicu."},{"v":21,"t":"Kad se krstio sav narod, krstio se i Isus. I dok se molio, rastvori se nebo,"},{"v":22,"t":"siđe na nj Duh Sveti u tjelesnom obličju, poput goluba, a glas se s neba zaori: “Ti si Sin moj, Ljubljeni! U tebi mi sva milina!”"},{"v":23,"t":"Kad je Isus nastupio, bilo mu je oko trideset godina. Bijaše - kako se smatralo - sin Josipov, Elijev,"},{"v":24,"t":"Matatov, Levijev, Malkijev, Janajev, Josipov."},{"v":25,"t":"Matatijin, Amosov, Naumov, Heslijev, Nagajev,"},{"v":26,"t":"Mahatov, Matatijin, Šimijev, Josehov, Jodin,"},{"v":27,"t":"Johananov, Resin, Zerubabelov, Šealtielov, Nerijev,"},{"v":28,"t":"Malkijev, Adijev, Kosamov, Elmadamov, Erov,"},{"v":29,"t":"Jošuin, Eliezerov, Jorimov, Matatov, Levijev,"},{"v":30,"t":"Šimunov, Judin, Josipov, Jonamov, Elijakimov,"},{"v":31,"t":"Melejin, Menin, Matatin, Natanov, Davidov,"},{"v":32,"t":"Jišajev, Obedov, Boazov, Salin, Nahšonov,"},{"v":33,"t":"Aminadabov, Adminov, Arnijev, Hesronov, Peresov, Judin,"},{"v":34,"t":"Jakovljev, Izakov, Abrahamov, Terahov, Nahorov,"},{"v":35,"t":"Serugov, Reuov, Pelegov, Eberov, Šelahov,"},{"v":36,"t":"Kenanov, Arpakšadov, Šemov, Noin, Lamekov,"},{"v":37,"t":"Metušalahov, Henokov, Jeredov, Mahalalelov, Kenanov,"},{"v":38,"t":"Enošev, Šetov, Adamov, Božji."}]},"4":{"hr":[{"v":1,"t":"Isus se, pun Duha Svetoga, vratio s Jordana i Duh ga četrdeset dana vodio pustinjom,"},{"v":2,"t":"gdje ga je iskušavao đavao. Tih dana nije ništa jeo, te kad oni istekoše, ogladnje."},{"v":3,"t":"A đavao mu reče: “Ako si Sin Božji, reci ovom kamenu da postane kruhom.”"},{"v":4,"t":"Isus mu odgovori: “Pisano je: Ne živi čovjek samo o kruhu.”"},{"v":5,"t":"I povede ga đavao na visoko, pokaza mu odjednom sva kraljevstva zemlje"},{"v":6,"t":"i reče mu: “Tebi ću dati svu ovu vlast i slavu njihovu jer meni je dana i komu hoću, dajem je."},{"v":7,"t":"Ako se dakle pokloniš preda mnom, sve je tvoje.”"},{"v":8,"t":"Isus mu odgovori: “Pisano je: Klanjaj se Gospodinu, Bogu svomu, i njemu jedinomu služi!”"},{"v":9,"t":"Povede ga u Jeruzalem i postavi na vrh Hrama i reče mu: “Ako si Sin Božji, baci se odavde dolje!"},{"v":10,"t":"Ta pisamo je: Anđelima će svojim zapovjediti za tebe da te čuvaju."},{"v":11,"t":"I: Na rukama će te nositi da se gdje nogom ne spotakneš o kamen.”"},{"v":12,"t":"Odgovori mu Isus: “Rečeno je: Ne iskušavaj Gospodina, Boga svojega!”"},{"v":13,"t":"Pošto iscrpi sve kušnje, đavao se udalji od njega do druge prilike."},{"v":14,"t":"A Isus se u snazi Duha vrati u Galileju te glas o njemu puče po svoj okolici."},{"v":15,"t":"I slavljen od sviju, naučavaše po njihovim sinagogama."},{"v":16,"t":"I dođe u Nazaret, gdje bijaše othranjen. I uđe po svom običaju na dan subotni u sinagogu te ustane čitati."},{"v":17,"t":"Pruže mu Knjigu proroka Izaije. On razvije knjigu i nađe mjesto gdje stoji napisano:"},{"v":18,"t":"Duh Gospodnji na meni je jer me pomaza! On me posla blagovjesnikom biti siromasima, proglasiti sužnjima oslobođenje, vid slijepima, na slobodu pustiti potlačene,"},{"v":19,"t":"proglasiti godinu milosti Gospodnje."},{"v":20,"t":"Tada savi knjigu, vrati je poslužitelju i sjede. Oči sviju u sinagogi bijahu uprte u njega."},{"v":21,"t":"On im progovori: “Danas se ispunilo ovo Pismo što vam još odzvanja u ušima.”"},{"v":22,"t":"I svi su mu povlađivali i divili se milini riječi koje su tekle iz njegovih usta. Govorahu: “Nije li ovo sin Josipov?”"},{"v":23,"t":"A on im reče: “Zacijelo ćete mi reći onu prispodobu: Liječniče, izliječi sam sebe! Što smo čuli da se dogodilo u Kafarnaumu, učini i ovdje, u svom zavičaju.”"},{"v":24,"t":"I nastavi: “Zaista, kažem vam, nijedan prorok nije dobro došao u svom zavičaju."},{"v":25,"t":"Uistinu, kažem vam, mnogo bijaše udovica u Izraelu u dane Ilijine kad se na tri godine i šest mjeseci zatvorilo nebo pa zavladala velika glad po svoj zemlji."},{"v":26,"t":"I ni k jednoj od njih nije bio poslan Ilija doli k ženi udovici u Sarfati sidonskoj."},{"v":27,"t":"I mnogo bijaše gubavaca u Izraelu za proroka Elizeja. I nijedan se od njih ne očisti doli Naaman Sirac.”"},{"v":28,"t":"Čuvši to, svi se u sinagogi napune gnjevom,"},{"v":29,"t":"ustanu, izbace ga iz grada i odvedu na rub brijega na kojem je sagrađen njihov grad da ga strmoglave."},{"v":30,"t":"No on prođe između njih i ode."},{"v":31,"t":"I siđe u Kafarnaum, grad galilejski. I poučavaše ih subotom"},{"v":32,"t":"te bijahu zaneseni njegovim naukom jer silna bijaše riječ njegova."},{"v":33,"t":"A zatekao se u sinagogi čovjek s duhom nečistoga đavla. On povika u sav glas:"},{"v":34,"t":"“Hej, što ti imaš s nama, Isuse Nazarećanine? Došao si da nas uništiš! Znam ja tko si ti: Svetac Božji.”"},{"v":35,"t":"Isus mu zaprijeti: “Umukni i iziđi iz njega!” Nato đavao čovjeka obori u sredinu te iziđe iz njega ne naudiv mu ništa."},{"v":36,"t":"I nasta opće zaprepaštenje te se među sobom razgovarahu: “Kakve li riječi! S vlašću i snagom zapovijeda nečistim dusima te izlaze!”"},{"v":37,"t":"I glas se o njemu širio po svim okolnim mjestima."},{"v":38,"t":"Ustavši iz sinagoge, uđe u kuću Šimunovu. A Šimunovu je punicu mučila velika ognjica. I zamole ga za nju."},{"v":39,"t":"On se nadvi nad nju, zaprijeti ognjici i ona je pusti. I odmah ustade i posluživaše im."},{"v":40,"t":"O zalazu sunca svi koji su imali bolesnike od raznih bolesti dovedoše ih k njemu. A on bi na svakoga od njih stavljao ruke i ozdravljao ih."},{"v":41,"t":"A iz mnogih su izlazili i zlodusi vičući: “Ti si Sin Božji!” On im se prijetio i nije im dao govoriti jer su znali da je on Krist."},{"v":42,"t":"Kad osvanu dan, iziđe i pođe na samotno mjesto. I mnoštvo ga tražilo. Dođoše k njemu i zadržavahu ga da ne ode od njih."},{"v":43,"t":"A on im reče: “I drugim gradovima treba da navješćujem evanđelje o kraljevstvu Božjem. Jer za to sam poslan.”"},{"v":44,"t":"I naučavaše po sinagogama judejskim."}]},"5":{"hr":[{"v":1,"t":"Dok se jednom oko njega gurao narod da čuje riječ Božju, stajaše on pokraj Genezaretskog jezera."},{"v":2,"t":"Spazi dvije lađe gdje stoje uz obalu; ribari bili izašli iz njih i ispirali mreže."},{"v":3,"t":"Uđe u jednu od tih lađa; bila je Šimunova pa zamoli Šimuna da malo otisne od kraja. Sjedne te iz lađe poučavaše mnoštvo."},{"v":4,"t":"Kada dovrši pouku, reče Šimunu: “Izvezi na pučinu i bacite mreže za lov.”"},{"v":5,"t":"Odgovori Šimun: “Učitelju, svu smo se noć trudili i ništa ne ulovismo, ali na tvoju riječ bacit ću mreže.”"},{"v":6,"t":"Učiniše tako te uhvatiše veoma mnogo riba; mreže im se gotovo razdirale."},{"v":7,"t":"Mahnuše drugovima na drugoj lađi da im dođu pomoći. Oni dođoše i napuniše obje lađe, umalo im ne potonuše."},{"v":8,"t":"Vidjevši to, Šimun Petar pade do nogu Isusovih govoreći: “Idi od mene! Grešan sam čovjek, Gospodine!”"},{"v":9,"t":"Zbog lovine riba što ih uloviše bijaše se zapanjio on i svi koji bijahu s njime,"},{"v":10,"t":"a tako i Jakov i Ivan, Zebedejevi sinovi, drugovi Šimunovi. Isus reče Šimunu: “Ne boj se! Odsada ćeš loviti ljude!”"},{"v":11,"t":"Oni izvukoše lađe na kopno, ostaviše sve i pođoše za njim."},{"v":12,"t":"I dok bijaše u jednom gradu, gle čovjeka puna gube! Ugledavši Isusa, padne ničice i zamoli ga: “Gospodine, ako hoćeš, možeš me očistiti.”"},{"v":13,"t":"Isus pruži ruku i dotakne ga se govoreći: “Hoću, očisti se!” I odmah nesta gube s njega."},{"v":14,"t":"I zapovjedi mu: “Nikome ni riječi, nego otiđi, pokaži se svećeniku i prinesi za svoje očišćenje kako propisa Mojsije, njima za svjedočanstvo.”"},{"v":15,"t":"Glas se o njemu sve više širio i silan svijet grnuo k njemu da ga sluša i da ozdravi od svojih bolesti."},{"v":16,"t":"A on se sklanjao na samotna mjesta da moli."},{"v":17,"t":"I jednog je dana on naučavao. A sjeđahu ondje farizeji i učitelji Zakona koji bijahu došli iz svih galilejskih i judejskih sela i Jeruzalema. A sila ga je Gospodnja nukala da liječi."},{"v":18,"t":"I gle, ljudi doniješe na nosiljci čovjeka koji bijaše uzet. Tražili su da ga unesu i stave preda nj."},{"v":19,"t":"Budući da zbog mnoštva nisu našli kuda bi ga unijeli, popnu se na krov te ga između crepova s nosiljkom spuste u sredinu pred Isusa."},{"v":20,"t":"Vidjevši njihovu vjeru reče on: “Čovječe, otpušteni su ti grijesi!”"},{"v":21,"t":"Pismoznanci i farizeji počeše mudrovati: “Tko je ovaj što huli? Tko može grijehe otpuštati doli Bog jedini?”"},{"v":22,"t":"Proniknuvši njihovo mudrovanje, upita ih Isus: “Što mudrujete u sebi?"},{"v":23,"t":"Što je lakše? Reći: 'Otpušteni su ti grijesi' ili reći: 'Ustani i hodi?'"},{"v":24,"t":"Ali da znate: Vlastan je Sin Čovječji na zemlji otpuštati grijehe!” I reče uzetomu: “Tebi zapovijedam: ustani, uzmi nosiljku i idi kući!”"},{"v":25,"t":"I on odmah usta pred njima, uze na čemu ležaše i ode kući slaveći Boga."},{"v":26,"t":"A sve obuze zanos te su slavili Boga i puni straha govorili: “Danas vidjesmo nešto neviđeno!”"},{"v":27,"t":"Nakon toga iziđe i ugleda carinika imenom Levija gdje sjedi u carinarnici. I reče mu: “Pođi za mnom!”"},{"v":28,"t":"On sve ostavi, usta i pođe za njim."},{"v":29,"t":"I Levi mu u svojoj kući priredi veliku gozbu. A s njime bijaše za stolom veliko mnoštvo carinika i drugih."},{"v":30,"t":"Farizeji i pismoznanci njihovi negodovahu i govorahu njegovim učenicima: “Zašto s carinicima i grešnicima jedete i pijete?”"},{"v":31,"t":"Isus im odgovori: “Ne treba zdravima liječnika, nego bolesnima."},{"v":32,"t":"Nisam došao zvati pravedne, nego grešnike na obraćenje.”"},{"v":33,"t":"A oni mu rekoše: “Učenici Ivanovi, a tako i farizejski, počesto poste i obavljaju molitve, tvoji pak jedu i piju.”"},{"v":34,"t":"Reče im Isus: “Ne možete svatove prisiliti da poste dok je zaručnik s njima."},{"v":35,"t":"Doći će već dani: kad im se ugrabi zaručnik, tada će postiti, u one dane!”"},{"v":36,"t":"A kazivao im je i prispodobu: “Nitko neće otparati krpe s novog odijela da je stavi na staro odijelo. Inače će i novo rasparati, a starom neće pristajati krpa s novoga.”"},{"v":37,"t":"“I nitko ne ulijeva novo vino u stare mješine. Inače će novo vino proderati mješine pa će se i ono proliti i mješine će propasti."},{"v":38,"t":"Nego, novo vino neka se ulijeva u nove mješine!”"},{"v":39,"t":"“I nitko pijuć staro, ne zaželi novoga. Ta veli se: 'Valja staro!'”"}]},"6":{"hr":[{"v":1,"t":"Jedne je subote prolazio kroz usjeve. Učenici su njegovi trgali klasje, trli ga rukama i jeli."},{"v":2,"t":"A neki farizeji rekoše: “Zašto činite što subotom nije dopušteno?”"},{"v":3,"t":"Odgovori im Isus: “Zar niste čitali što učini David kad ogladnje on i njegovi pratioci?"},{"v":4,"t":"Kako uđe u Dom Božji, uze, pojede i svojim pratiocima dade prinesene kruhove kojih ne smije jesti nitko, nego samo svećenici?”"},{"v":5,"t":"I govoraše im: “Sin Čovječji gospodar je subote!”"},{"v":6,"t":"Druge subote uđe u sinagogu i stane naučavati. Bio je ondje čovjek kome desnica bijaše usahla."},{"v":7,"t":"Pismoznanci i farizeji vrebahu na nj da li subotom liječi kako bi našli u čemu da ga optuže."},{"v":8,"t":"A on je znao njihove namjere pa reče čovjeku s usahlom rukom: “Ustani i stani na sredinu!” On usta i stade."},{"v":9,"t":"A Isus im reče: “Pitam ja vas: je li subotom dopušteno činiti dobro ili činiti zlo? Život spasiti ili upropastiti?”"},{"v":10,"t":"Sve ih ošinu pogledom pa reče čovjeku: “Ispruži ruku!” On učini tako - i ruka mu zdrava."},{"v":11,"t":"A oni se, izbezumljeni, počnu dogovarati što da poduzmu protiv Isusa."},{"v":12,"t":"Onih dana iziđe na goru da se pomoli. I provede noć moleći se Bogu."},{"v":13,"t":"Kad se razdanilo, dozva k sebi učenike te između njih izabra dvanaestoricu, koje prozva apostolima:"},{"v":14,"t":"Šimuna, koga prozva Petrom, i Andriju, brata njegova, i Jakova, i Ivana, i Filipa, i Bartolomeja,"},{"v":15,"t":"i Mateja, i Tomu, i Jakova Alfejeva, i Šimuna zvanoga Revnitelj,"},{"v":16,"t":"i Judu Jakovljeva, i Judu Iškariotskoga, koji posta izdajica."},{"v":17,"t":"Isus siđe s njima i zaustavi se na ravnu. I silno mnoštvo njegovih učenika i silno mnoštvo naroda iz cijele Judeje i Jeruzalema, iz primorja tirskog i sidonskog"},{"v":18,"t":"nagrnuše da ga slušaju i da ozdrave od svojih bolesti. I ozdravljali su oni koje su mučili nečisti dusi."},{"v":19,"t":"Sve je to mnoštvo tražilo da ga se dotakne jer je snaga izlazila iz njega i sve ozdravljala."},{"v":20,"t":"On podigne oči prema učenicima i govoraše: “Blago vama, siromasi: vaše je kraljevstvo Božje!"},{"v":21,"t":"Blago vama koji sada gladujete: vi ćete se nasititi! Blago vama koji sada plačete: vi ćete se smijati!"},{"v":22,"t":"Blago vama kad vas zamrze ljudi i kad vas izopće i pogrde te izbace ime vaše kao zločinačko zbog Sina Čovječjega!"},{"v":23,"t":"Radujte se u dan onaj i poskakujte: evo, plaća vaša velika je na nebu. Ta jednako su činili prorocima oci njihovi!”"},{"v":24,"t":"“Ali jao vama, bogataši: imate svoju utjehu!"},{"v":25,"t":"Jao vama koji ste sada siti: gladovat ćete! Jao vama koji se sada smijete: jadikovat ćete i plakati!"},{"v":26,"t":"Jao vama kad vas svi budu hvalili! Ta tako su činili lažnim prorocima oci njihovi.”"},{"v":27,"t":"“Nego, velim vama koji slušate: Ljubite svoje neprijatelje, dobro činite svojim mrziteljima,"},{"v":28,"t":"blagoslivljajte one koji vas proklinju, molite za one koji vas zlostavljaju.”"},{"v":29,"t":"“Onomu tko te udari po jednom obrazu pruži i drugi, i onomu tko ti otima gornju haljinu ne krati ni donje."},{"v":30,"t":"Svakomu tko od tebe ište daji, a od onoga tko tvoje otima ne potražuj.”"},{"v":31,"t":"“I kako želite da ljudi vama čine, tako činite i vi njima.”"},{"v":32,"t":"“Ako ljubite one koji vas ljube, kakvo li vam uzdarje? Ta i grešnici ljube ljubitelje svoje."},{"v":33,"t":"Jednako tako, ako dobro činite svojim dobročiniteljima, kakvo li vam uzdarje? I grešnici to isto čine."},{"v":34,"t":"Ako pozajmljujete samo onima od kojih se nadate dobiti, kakvo li vam uzdarje? I grešnici grešnicima pozajmljuju da im se jednako vrati.”"},{"v":35,"t":"“Nego, ljubite neprijatelje svoje. Činite dobro i pozajmljujte ne nadajuć se odatle ničemu. I bit će vam plaća velika, i bit ćete sinovi Svevišnjega jer je on dobrostiv i prema nezahvalnicima i prema opakima.”"},{"v":36,"t":"“Budite milosrdni kao što je Otac vaš milosrdan.”"},{"v":37,"t":"“Ne sudite i nećete biti suđeni. Ne osuđujte i nećete biti osuđeni. Praštajte i oprostit će vam se."},{"v":38,"t":"Dajite i dat će vam se: mjera dobra, nabijena, natresena, preobilna dat će se u krilo vaše jer mjerom kojom mjerite vama će se zauzvrat mjeriti.”"},{"v":39,"t":"A kaza im i prispodobu: “Može li slijepac slijepca voditi? Neće li obojica u jamu upasti?"},{"v":40,"t":"Nije učenik nad učiteljem. Pa i tko je posve doučen, bit će samo kao njegov učitelj.”"},{"v":41,"t":"“Što gledaš trun u oku brata svojega, a brvna u oku svome ne opažaš?"},{"v":42,"t":"Kako možeš kazati bratu svomu: 'Brate, de da izvadim trun koji ti je u oku', a sam u svom oku brvna ne vidiš? Licemjere! Izvadi najprije brvno iz oka svoga pa ćeš onda dobro vidjeti izvaditi trun što je u oku bratovu.”"},{"v":43,"t":"“Nema dobra stabla koje bi rađalo nevaljalim plodom niti stabla nevaljala koje bi rađalo dobrim plodom."},{"v":44,"t":"Ta svako se stablo po svom plodu poznaje. S trnja se ne beru smokve niti se s gloga grožđe trga.”"},{"v":45,"t":"“Dobar čovjek iz dobra blaga srca svojega iznosi dobro, a zao iz zla iznosi zlo. Ta iz obilja srca usta mu govore.”"},{"v":46,"t":"“Što me zovete 'Gospodine, Gospodine!', a ne činite što zapovijedam?"},{"v":47,"t":"Tko god dolazi k meni te sluša moje riječi i vrši ih, pokazat ću vam kome je sličan:"},{"v":48,"t":"sličan je čovjeku koji gradi kuću pa iskopa u dubinu i postavi temelj na kamen. A kad bude poplava, nahrupi bujica na tu kuću, ali je ne može uzdrmati jer je dobro sagrađena."},{"v":49,"t":"A koji čuje i ne izvrši, sličan je čovjeku koji sagradi kuću na tlu bez temelja; nahrupi na nju bujica i umah se sruši te bude od te kuće razvalina velika.”"}]},"7":{"hr":[{"v":1,"t":"Pošto dovrši sve te svoje besjede narodu, uđe u Kafarnaum."},{"v":2,"t":"Nekomu satniku bijaše bolestan sluga, samo što ne izdahnu, a bijaše mu veoma drag."},{"v":3,"t":"Kad je satnik čuo za Isusa, posla k njemu starješine židovske moleći ga da dođe i ozdravi mu slugu."},{"v":4,"t":"Kad oni dođoše Isusu, usrdno ga moljahu: “Dostojan je da mu to učiniš"},{"v":5,"t":"jer voli naš narod, i sinagogu nam je sagradio.”"},{"v":6,"t":"Isus se uputi s njima. I kad bijaše već kući nadomak, posla satnik prijatelje s porukom: “Gospodine, ne muči se. Nisam dostojan da uđeš pod krov moj."},{"v":7,"t":"Zato se i ne smatrah dostojnim doći k tebi. Nego - reci riječ da ozdravi sluga moj."},{"v":8,"t":"Ta i ja, premda sam vlasti podređen, imam pod sobom vojnike pa reknem jednomu: 'Idi' - i ode, drugomu: 'Dođi' - i dođe, a sluzi svomu: 'Učini to' - i učini.”"},{"v":9,"t":"Čuvši to, zadivi mu se Isus pa se okrenu mnoštvu koje je išlo za njim i reče: “Kažem vam, ni u Izraelu na nađoh tolike vjere.”"},{"v":10,"t":"Kad se oni koji su bili poslani vratiše kući, nađoše slugu zdrava."},{"v":11,"t":"Nakon toga uputi se Isus u grad zvani Nain. Pratili ga njegovi učenici i silan svijet."},{"v":12,"t":"Kad se približi gradskim vratima, gle, upravo su iznosili mrtvaca, sina jedinca u majke, majke udovice. Pratilo ju mnogo naroda iz grada."},{"v":13,"t":"Kad je Gospodin ugleda, sažali mu se nad njom i reče joj: “Ne plači!”"},{"v":14,"t":"Pristupi zatim, dotače se nosila; nosioci stadoše, a on reče: “Mladiću, kažem ti, ustani!”"},{"v":15,"t":"I mrtvac se podiže i progovori, a on ga dade njegovoj majci."},{"v":16,"t":"Sve obuze strah te slavljahu Boga govoreći: “Prorok velik usta među nama! Pohodi Bog narod svoj!”"},{"v":17,"t":"I proširi se taj glas o njemu po svoj Judeji i po svoj okolici."},{"v":18,"t":"Sve to dojaviše Ivanu njegovi učenici. On dozva dvojicu svojih učenika"},{"v":19,"t":"i posla ih Gospodinu da ga pitaju: “Jesi li ti Onaj koji ima doći ili drugoga da čekamo?”"},{"v":20,"t":"Došavši k njemu, rekoše ti ljudi: “Ivan Krstitelj posla nas k tebi da pitamo: 'Jesi li ti Onaj koji ima doći ili drugoga da čekamo?'”"},{"v":21,"t":"Upravo u taj čas Isus je ozdravio mnoge od bolesti, muka i zlih duhova i mnoge je slijepe podario vidom."},{"v":22,"t":"Tada im odgovori: “Pođite i javite Ivanu što ste vidjeli i čuli: Slijepi progledaju, hromi hode, gubavi se čiste, gluhi čuju, mrtvi ustaju, siromasima se navješćuje evanđelje."},{"v":23,"t":"I blago onom tko se ne sablazni o mene.”"},{"v":24,"t":"Kad Ivanovi glasnici odoše, poče Isus govoriti mnoštvu o Ivanu: “Što ste izašli u pustinju gledati? Trsku koju vjetar ljulja?"},{"v":25,"t":"Ili što ste izašli vidjeti: Čovjeka u mekušaste haljine odjevena? Eno, oni u sjajnoj odjeći i raskošju po kraljevskim su dvorima."},{"v":26,"t":"Ili što ste izašli vidjeti? Proroka? Uistinu, kažem vam, i više nego proroka!"},{"v":27,"t":"On je onaj o kome je pisano: Evo, šaljem glasnika svoga pred licem tvojim da pripravi put pred tobom."},{"v":28,"t":"Kažem vam: među rođenima od žene nitko nije veći od Ivana. A ipak, i najmanji u kraljevstvu Božjem veći je od njega.”"},{"v":29,"t":"Sav narod koji ga je slušao, pa i carinici, uvidješe pravednost Božju: pokrstiše se Ivanovim krstom."},{"v":30,"t":"Naprotiv, farizeji i zakonoznanci ometoše što je Bog s njima naumio jer ne htjedoše da ih Ivan krsti."},{"v":31,"t":"“S kime dakle da prispodobim ljude ovog naraštaja? Komu su nalik?"},{"v":32,"t":"Nalik su djeci što sjede na trgu pa jedni drugima po poslovici dovikuju: 'Zasvirasmo vam i ne zaigraste! Zakukasmo i ne zaplakaste!'"},{"v":33,"t":"Doista, došao je Ivan Krstitelj. Nije kruha jeo ni vina pio, a velite: 'Ðavla ima!'"},{"v":34,"t":"Došao je Sin Čovječji koji jede i pije, a govorite: 'Evo izjelice i vinopije, prijatelja carinika i grešnika!'"},{"v":35,"t":"Ali opravda se Mudrost pred svom djecom svojom.”"},{"v":36,"t":"Neki farizej pozva Isusa da bi blagovao s njime. On uđe u kuću farizejevu i priđe stolu."},{"v":37,"t":"Kad eto neke žene koja bijaše grešnica u gradu. Dozna da je Isus za stolom u farizejevoj kući pa ponese alabastrenu posudicu pomasti"},{"v":38,"t":"i stade odostrag kod njegovih nogu. Sva zaplakana poče mu suzama kvasiti noge: kosom ih glave svoje otirala, cjelivala i mazala pomašću."},{"v":39,"t":"Kad to vidje farizej koji ga pozva, pomisli: “Kad bi ovaj bio Prorok, znao bi tko i kakva je to žena koja ga se dotiče: da je grešnica.”"},{"v":40,"t":"A Isus, da mu odgovori, reče: “Šimune, imam ti nešto reći.” A on će: “Učitelju, reci!” A on:"},{"v":41,"t":"“Neki vjerovnik imao dva dužnika. Jedan mu dugovaše pet stotina denara, drugi pedeset."},{"v":42,"t":"Budući da nisu imali odakle vratiti, otpusti obojici. Koji će ga dakle od njih više ljubiti?”"},{"v":43,"t":"Šimun odgovori: “Predmnijevam, onaj kojemu je više otpustio.” Reče mu Isus: “Pravo si prosudio.”"},{"v":44,"t":"I okrenut ženi reče Šimunu: “Vidiš li ovu ženu? Uđoh ti u kuću, nisi mi vodom noge polio, a ona mi suzama noge oblila i kosom ih svojom otrla."},{"v":45,"t":"Poljupca mi nisi dao, a ona, otkako uđe, ne presta mi noge cjelivati."},{"v":46,"t":"Uljem mi glave nisi pomazao, a ona mi pomašću noge pomaza."},{"v":47,"t":"Stoga, kažem ti, oprošteni su joj grijesi mnogi jer ljubljaše mnogo. Komu se malo oprašta, malo ljubi.”"},{"v":48,"t":"A ženi reče: “Oprošteni su ti grijesi.”"},{"v":49,"t":"Sustolnici počeli nato među sobom govoriti: “Tko je ovaj da i grijehe oprašta?”"},{"v":50,"t":"A on reče ženi: “Vjera te tvoja spasila! Idi u miru!”"}]},"8":{"hr":[{"v":1,"t":"Zatim zareda obilaziti gradom i selom propovijedajući i navješćujući evanđelje o kraljevstvu Božjemu. Bila su s njim dvanaestorica"},{"v":2,"t":"i neke žene koje bijahu izliječene od zlih duhova i bolesti: Marija zvana Magdalena, iz koje bijaše izagnao sedam đavola;"},{"v":3,"t":"zatim Ivana, žena Herodova upravitelja Huze; Suzana i mnoge druge. One su im posluživale od svojih dobara."},{"v":4,"t":"Kad se skupio silan svijet te iz svakoga grada nagrnuše k njemu, prozbori u prispodobi:"},{"v":5,"t":"“Iziđe sijač sijati sjeme. Dok je sijao, jedno pade uz put, bi pogaženo i ptice ga nebeske pozobaše."},{"v":6,"t":"Drugo pade na kamen i, tek što je izniklo, osuši se jer ne imaše vlage."},{"v":7,"t":"Drugo opet pade među trnje i trnje ga preraste i uguši."},{"v":8,"t":"Drugo napokon pade u dobru zemlju, nikne i urodi stostrukim plodom.” Rekavši to, povika: “Tko ima uši da čuje, neka čuje!”"},{"v":9,"t":"Upitaše ga učenici kakva bi to bila prispodoba."},{"v":10,"t":"A on im reče: “Vama je dano znati otajstva kraljevstva Božjega, a ostalima u prispodobama - da gledajući ne vide i slušajući ne razumiju.”"},{"v":11,"t":"“A ovo je prispodoba: Sjeme je Riječ Božja."},{"v":12,"t":"Oni uz put slušatelji su. Zatim dolazi đavao i odnosi Riječ iz srca njihova da ne bi povjerovali i spasili se."},{"v":13,"t":"A na kamenu - to su oni koji kad čuju, s radošću prime Riječ, ali korijena nemaju: ti neko vrijeme vjeruju, a u vrijeme kušnje otpadnu."},{"v":14,"t":"A što pade u trnje - to su oni koji poslušaju, ali poneseni brigama, bogatstvom i nasladama života, uguše se i ne dorode roda."},{"v":15,"t":"Ono pak u dobroj zemlji - to su oni koji u plemenitu i dobru srcu slušaju Riječ, zadrže je i donose rod u ustrajnosti.”"},{"v":16,"t":"“Nitko ne užiže svjetiljke da je pokrije posudom ili stavi pod postelju, nego je stavlja na svijećnjak da oni koji ulaze vide svjetlost."},{"v":17,"t":"Ta ništa nije tajno što se neće očitovati; ništa skriveno što se neće saznati i na vidjelo doći.”"},{"v":18,"t":"“Pazite dakle kako slušate. Doista, onomu tko ima dat će se, a onomu tko nema oduzet će se i ono što misli da ima.”"},{"v":19,"t":"A majka i braća njegova htjedoše k njemu, ali ne mogoše do njega zbog mnoštva."},{"v":20,"t":"Javiše mu: “Majka tvoja i braća tvoja stoje vani i žele te vidjeti.”"},{"v":21,"t":"A on im odgovori: “Majka moja, braća moja - ovi su koji riječ Božju slušaju i vrše.”"},{"v":22,"t":"Jednoga dana uđe u lađu on i učenici njegovi. I reče im: “Prijeđimo na onu stranu jezera.” I otisnuše se."},{"v":23,"t":"Dok su plovili, on zaspa. I spusti se oluja na jezero. Voda stane nadirati te bijahu u pogibli."},{"v":24,"t":"Oni pristupiše i probudiše ga govoreći: “Učitelju, učitelju, propadosmo!” On se probudi, zaprijeti vjetru i valovlju; i oni se smire te nasta utiha."},{"v":25,"t":"A on će im: “Gdje vam je vjera?” A oni se prestrašeni u čudu zapitkivahu: “Tko li je ovaj da i vjetrovima zapovijeda i vodi, i pokoravaju mu se?”"},{"v":26,"t":"Doploviše u gergezenski kraj koji je nasuprot Galileji."},{"v":27,"t":"Čim iziđe na kopno, eto mu iz grada u susret nekog čovjeka koji imaše zloduhe. Već dugo vremena nije se uopće odijevao niti stanovao u kući, nego po grobnicama."},{"v":28,"t":"Kad opazi Isusa, zastenja, pade ničice preda nj i u sav glas povika: “Što ti imaš sa mnom, Isuse, Sine Boga Svevišnjega? Molim te, ne muči me!”"},{"v":29,"t":"Jer bijaše zapovjedio nečistom duhu da iziđe iz toga čovjeka. Da, dugo ga je već vremena držao u vlasti i makar su ga lancima vezali i u verigama čuvali, on bi raskidao spone i zloduh bi ga odagnao u pustinju."},{"v":30,"t":"Isus ga nato upita: “Kako ti je ime?” On reče: “Legija”, jer u nj uđoše mnogi zlodusi."},{"v":31,"t":"I zaklinjahu ga da im ne naredi vratiti se u Bezdan."},{"v":32,"t":"A ondje u gori paslo je poveliko krdo svinja. Zaklinjahu ga dakle da im dopusti ući u njih. I on im dopusti."},{"v":33,"t":"Tada zlodusi iziđoše iz čovjeka i uđoše u svinje. Krdo jurnu niz obronak u jezero i podavi se."},{"v":34,"t":"Vidjevši što se dogodilo, svinjari pobjegoše i razglasiše gradom i selima."},{"v":35,"t":"A ljudi iziđoše vidjeti što se dogodilo. Dođoše Isusu i nađoše čovjeka iz kojega bijahu izašli zlodusi gdje do nogu Isusovih sjedi, obučen i zdrave pameti. I prestraše se."},{"v":36,"t":"A očevici im ispripovijediše kako je opsjednuti ozdravio."},{"v":37,"t":"I zamoli ga sve ono mnoštvo iz okolice gergezenske da ode od njih jer ih strah velik spopade. On uđe u lađu i vrati se."},{"v":38,"t":"A moljaše ga čovjek iz koga iziđoše zlodusi da može ostati s njim, ali ga on otpusti govoreći:"},{"v":39,"t":"“Vrati se kući i pripovijedaj što ti učini Bog.” On ode razglašujući po svem gradu što mu učini Isus."},{"v":40,"t":"Na povratku Isusa dočeka mnoštvo jer su ga svi željno iščekivali."},{"v":41,"t":"I gle, dođe čovjek, ime mu Jair, koji bijaše predstojnik sinagoge. Baci se Isusu pred noge i stane ga moliti da dođe u njegovu kuću."},{"v":42,"t":"Imaše kćer jedinicu, otprilike od dvanaest godina, koja umiraše. Dok je onamo išao, mnoštvo ga guralo odasvud."},{"v":43,"t":"A neka žena koja je već dvanaest godina bolovala od krvarenja, sve svoje imanje potrošila na liječnike i nitko je nije mogao izliječiti,"},{"v":44,"t":"priđe odostrag i dotaknu se skuta njegove haljine i umah joj se zaustavi krvarenje."},{"v":45,"t":"I reče Isus: “Tko me se to dotaknu?” Svi se branili, a Petar će: “Učitelju, mnoštvo te gura i pritišće.”"},{"v":46,"t":"A Isus: “Netko me se dotaknuo. Osjetio sam kako snaga izlazi iz mene.”"},{"v":47,"t":"A žena, vidjevši da se ne može kriti, sva u strahu pristupi i baci se preda nj te pred svim narodom ispripovjedi zašto ga se dotakla i kako je umah ozdravila."},{"v":48,"t":"A on joj reče: “Kćeri, vjera te tvoja spasila. Idi u miru!”"},{"v":49,"t":"Dok je on još govorio, eto jednog od nadstojnikovih s porukom: “Umrla ti kći, ne muči više Učitelja.”"},{"v":50,"t":"Čuo to Isus pa mu reče: “Ne boj se! Samo vjeruj i ona će se spasiti!”"},{"v":51,"t":"Uđe u kuću, ali nikomu ne dopusti da s njim uđe osim Petra, Ivana, Jakova i djetetova oca i majke."},{"v":52,"t":"A svi plakahu i žalovahu za njom. A on im reče: “Ne plačite! Nije umrla, nego spava!”"},{"v":53,"t":"No oni mu se podsmjehivahu znajući da je umrla."},{"v":54,"t":"On je uhvati za ruku i povika: “Dijete, ustani!”"},{"v":55,"t":"I povrati joj se duh i umah ustade, a on naredi da joj dadu jesti."},{"v":56,"t":"Njezini se roditelji začudiše, a on zapovjedi da nikome ne reknu što se dogodilo."}]},"9":{"hr":[{"v":1,"t":"Sazva dvanaestoricu i dade im moć i vlast nad svim zlodusima i da liječe bolesti."},{"v":2,"t":"I posla ih propovijedati kraljevstvo Božje i liječiti bolesnike."},{"v":3,"t":"I reče im: “Ništa ne uzimajte na put: ni štapa, ni torbe, ni kruha, ni srebra! I da niste imali više od dvije haljine!"},{"v":4,"t":"U koju god kuću uđete, ondje ostanite pa odande dalje pođite."},{"v":5,"t":"Gdje vas ne prime, iziđite iz toga grada i stresite prašinu s nogu za svjedočanstvo protiv njih.”"},{"v":6,"t":"Oni krenuše: obilazili su po selima, navješćivali evanđelje i liječili posvuda."},{"v":7,"t":"Dočuo Herod tetrarh sve što se događa te se nađe u nedoumici jer su neki govorili: “Ivan uskrsnu od mrtvih”;"},{"v":8,"t":"drugi: “Pojavio se Ilija”; treći opet: “Ustao je neki od drevnih proroka.”"},{"v":9,"t":"A Herod reče: “Ivanu ja odrubih glavu. Tko je onda ovaj o kom toliko čujem?” I tražio je priliku da ga vidi."},{"v":10,"t":"Apostoli se vrate i ispripovjede što su učinili. Isus ih povede sa sobom i povuče se nasamo u grad zvani Betsaida."},{"v":11,"t":"Saznalo to mnoštvo po pođe za njim. On ih primi te im govoraše o kraljevstvu Božjem i ozdravljaše sve koji su trebali ozdravljenja."},{"v":12,"t":"Dan bijaše na izmaku. Pristupe dakle dvanaestorica pa mu reknu: “Otpusti svijet, neka pođu po okolnim selima i zaseocima da se sklone i nađu jela jer smo ovdje u pustu kraju.”"},{"v":13,"t":"A on im reče: “Podajte im vi jesti!” Oni rekoše: “Nemamo više od pet kruhova i dvije ribe, osim da odemo kupiti hrane za sav ovaj narod.”"},{"v":14,"t":"A bijaše oko pet tisuća muškaraca. Nato će on svojim učenicima: “Posjedajte ih po skupinama, otprilike po pedeset.”"},{"v":15,"t":"I učine tako: sve ih posjedaju."},{"v":16,"t":"A on uze pet kruhova i dvije ribe, pogleda na nebo, blagoslovi ih i razlomi pa davaše učenicima da posluže mnoštvo."},{"v":17,"t":"Jeli su i svi se nasitili. I od preteklih ulomaka nakupilo se dvanaest košara."},{"v":18,"t":"Dok je jednom u osami molio, bijahu s njim samo njegovi učenici. On ih upita: “Što govori svijet, tko sam ja?”"},{"v":19,"t":"Oni odgovoriše: “Da si Ivan Krstitelj, drugi: da si Ilija, treći opet: da neki od drevnih proroka usta.”"},{"v":20,"t":"A on im reče: “A vi, što vi kažete, tko sam ja?” Petar prihvati i reče: “Krist - Pomazanik Božji!”"},{"v":21,"t":"A on im zaprijeti da toga nikomu ne kazuju."},{"v":22,"t":"Reče: “Treba da Sin Čovječji mnogo pretrpi, da ga starješine, glavari svećenički i pismoznanci odbace, da bude ubijen i treći dan da uskrsne.”"},{"v":23,"t":"A govoraše svima: “Hoće li tko za mnom, neka se odrekne samoga sebe, neka danomice uzima križ svoj i neka ide za mnom."},{"v":24,"t":"Tko hoće život svoj spasiti, izgubit će ga; a tko izgubi život svoj poradi mene, taj će ga spasiti."},{"v":25,"t":"Ta što koristi čovjeku ako sav svijet zadobije, a sebe samoga izgubi ili sebi naudi?”"},{"v":26,"t":"“Doista, tko se zastidi mene i mojih riječi, toga će se i Sin Čovječji stidjeti kada dođe u slavi svojoj i Očevoj i svetih anđela.”"},{"v":27,"t":"“A kažem vam uistinu: neki od nazočnih neće okusiti smrti dok ne vide kraljevstva Božjega.”"},{"v":28,"t":"Jedno osam dana nakon tih besjeda povede Isus sa sobom Petra, Ivana i Jakova te uziđe na goru da se pomoli."},{"v":29,"t":"I dok se molio, izgled mu se lica izmijeni, a odjeća sjajem zablista."},{"v":30,"t":"I gle, dva čovjeka razgovarahu s njime. Bijahu to Mojsije i Ilija."},{"v":31,"t":"Ukazali se u slavi i razgovarali s njime o njegovu Izlasku, što se doskora imao ispuniti u Jeruzalemu."},{"v":32,"t":"No Petra i njegove drugove bijaše svladao san. Kad se probudiše, ugledaše njegovu slavu i dva čovjeka koji stajahu uza nj."},{"v":33,"t":"I dok su oni odlazili od njega, reče Petar Isusu: “Učitelju, dobro nam je ovdje biti. Načinimo tri sjenice: jednu tebi, jednu Mojsiju, jednu Iliji.” Nije znao što govori."},{"v":34,"t":"Dok je on to govorio, pojavi se oblak i zasjeni ih. Ušavši u oblak, oni se prestrašiše."},{"v":35,"t":"A glas se začu iz oblaka: “Ovo je Sin moj, Izabranik! Njega slušajte!”"},{"v":36,"t":"I upravo kad se začu glas, osta Isus sam. Oni su šutjeli i nikomu onih dana nisu kazivali što su vidjeli."},{"v":37,"t":"A kad su sutradan sišli s gore, pohiti mu u susret silan svijet."},{"v":38,"t":"I gle, čovjek neki iz mnoštva povika: “Učitelju, molim te pogledaj mi sina: jedinac mi je,"},{"v":39,"t":"a gle, duh ga spopada te on odmah udari u kriku; trza njime i on se pjeni te jedva da od njega odstupi dok ga nije posve satro."},{"v":40,"t":"Molio sam tvoje učenike da ga izagnaju, ali ne mogoše.”"},{"v":41,"t":"Isus odvrati: “O rode nevjerni i opaki, dokle mi je biti s vama i podnositi vas? Dovedi ovamo svoga sina!”"},{"v":42,"t":"I dok je prilazio, obori ga zloduh i potrese. A Isus zaprijeti nečistom duhu te izliječi dječaka i preda ga njegovu ocu."},{"v":43,"t":"Svi se zapanjiše zbog veličanstva Božjega. Dok su se svi divili svemu što je činio, reče on učenicima:"},{"v":44,"t":"“Uzmite k srcu ove riječi: Sin Čovječji doista ima biti predan ljudima u ruke.”"},{"v":45,"t":"Ali oni nerazumješe te besjede, bijaše im skrivena te ne shvatiše, a bojahu se upitati ga o tome."},{"v":46,"t":"U njima se porodi misao tko bi od njih bio najveći."},{"v":47,"t":"Znajući tu misao njihova srca, uzme Isus dijete, postavi ga uza se"},{"v":48,"t":"i reče im: “Tko god primi ovo dijete u moje ime, mene prima. A tko mene prima, prima onoga koji me je poslao. Doista, tko je najmanji među vama svima, taj je velik!”"},{"v":49,"t":"Prihvati Ivan i reče: “Učitelju, vidjesmo jednoga koji u tvoje ime izgoni zloduhe. Mi smo mu branili, jer ne ide za nama.”"},{"v":50,"t":"Reče mu Isus: “Ne branite! Ta tko nije protiv vas, za vas je!”"},{"v":51,"t":"Kad su se navršili dani da bude uznesen, krenu Isus sa svom odlučnošću prema Jeruzalemu."},{"v":52,"t":"I posla glasnike pred sobom. Oni odoše i uđoše u neko samarijansko selo da mu priprave mjesto."},{"v":53,"t":"No ondje ga ne primiše jer je bio na putu u Jeruzalem."},{"v":54,"t":"Kada to vidješe učenici Jakov i Ivan, rekoše: “Gospodine, hoćeš li da kažemo neka oganj siđe s neba i uništi ih?”"},{"v":55,"t":"No on se okrenu i prekori ih."},{"v":56,"t":"I odoše u drugo selo."},{"v":57,"t":"Dok su išli putom, reče mu netko: “Za tobom ću kamo god ti pošao.”"},{"v":58,"t":"Reče mu Isus: “Lisice imaju jazbine, ptice nebeske gnijezda, a Sin Čovječji nema gdje bi glavu naslonio.”"},{"v":59,"t":"Drugomu nekom reče: “Pođi za mnom!” A on će mu: “Dopusti mi da prije odem i pokopam oca.”"},{"v":60,"t":"Reče mu: “Pusti neka mrtvi pokapaju svoje mrtve, a ti idi i navješćuj kraljevstvo Božje.”"},{"v":61,"t":"I neki drugi reče: “Za tobom ću, Gospodine, ali dopusti mi da se prije oprostim sa svojim ukućanima.”"},{"v":62,"t":"Reče mu Isus: “Nitko tko stavi ruku na plug pa se obazire natrag, nije prikladan za kraljevstvo Božje.”"}]},"10":{"hr":[{"v":1,"t":"Nakon toga odredi Gospodin drugih sedamdesetdvojicu učenika i posla ih po dva pred sobom u svaki grad i u svako mjesto kamo je kanio doći."},{"v":2,"t":"Govorio im je: “Žetva je velika, ali radnika malo. Molite dakle gospodara žetve da radnike pošalje u žetvu svoju."},{"v":3,"t":"Idite! Evo, šaljem vas kao janjce među vukove."},{"v":4,"t":"Ne nosite sa sobom ni kese, ni torbe, ni obuće. I nikoga putem ne pozdravljajte."},{"v":5,"t":"U koju god kuću uđete, najprije recite: 'Mir kući ovoj!'"},{"v":6,"t":"Bude li tko ondje prijatelj mira, počinut će na njemu mir vaš. Ako li ne, vratit će se na vas."},{"v":7,"t":"U toj kući ostanite, jedite i pijte što se kod njih nađe. Ta vrijedan je radnik plaće svoje. Ne prelazite iz kuće u kuću.”"},{"v":8,"t":"“Kad u koji grad uđete pa vas prime, jedite što vam se ponudi"},{"v":9,"t":"i liječite bolesnike koji su u njemu. I kazujte im: 'Približilo vam se kraljevstvo Božje!'"},{"v":10,"t":"A kad u neki grad uđete pa vas ne prime, iziđite na njegove ulice i recite:"},{"v":11,"t":"'I prašinu vašega grada, koja nam se nogu uhvatila, stresamo vam sa sebe! Ipak znajte ovo: Približilo se kraljevstvo Božje!'"},{"v":12,"t":"Kažem vam: Sodomcima će u onaj dan biti lakše negoli tomu gradu.”"},{"v":13,"t":"“Jao tebi, Korozaine! Jao tebi, Betsaido! Da su se u Tiru i Sidonu zbila čudesa koja su se dogodila u vama, odavna bi već, sjedeć u kostrijeti i pepelu, činili pokoru."},{"v":14,"t":"Ali Tiru i Sidonu bit će na Sudu lakše negoli vama."},{"v":15,"t":"I ti Kafarnaume! Zar ćeš se do neba uzvisiti? Do u Podzemlje ćeš se strovaliti."},{"v":16,"t":"Tko vas sluša, mene sluša; tko vas prezire, mene prezire. A tko mene prezire, prezire onoga koji mene posla.”"},{"v":17,"t":"Vratiše se zatim sedamdesetdvojica radosni govoreći: “Gospodine, i zlodusi nam se pokoravaju na tvoje ime!”"},{"v":18,"t":"A on im reče: “Promatrah Sotonu kako poput munje s neba pade."},{"v":19,"t":"Evo, dao sam vam vlast da gazite po zmijama i štipavcima i po svoj sili neprijateljevoj i ništa vam neće naškoditi."},{"v":20,"t":"Ali ne radujte se što vam se duhovi pokoravaju, nego radujte se što su vam imena zapisana na nebesima.”"},{"v":21,"t":"U taj isti čas uskliknu Isus u Duhu Svetom: “Slavim te, Oče, Gospodaru neba i zemlje, što si ovo sakrio od mudrih i umnih, a objavio malenima. Da, Oče! Tako se tebi svidjelo."},{"v":22,"t":"Sve mi preda Otac moj i nitko ne zna tko je Sin - doli Otac; niti tko je Otac - doli Sin i onaj kome Sin hoće da objavi.”"},{"v":23,"t":"Tada se okrene učenicima pa im nasamo reče: “Blago očima koje gledaju što vi gledate!"},{"v":24,"t":"Kažem vam: mnogi su proroci i kraljevi htjeli vidjeti što vi gledate, ali nisu vidjeli; i čuti što vi slušate, ali nisu čuli!”"},{"v":25,"t":"I gle, neki zakonoznanac usta i, da ga iskuša, upita: “Učitelju, što mi je činiti da život vječni baštinim?”"},{"v":26,"t":"A on mu reče: “U Zakonu što piše? Kako čitaš?”"},{"v":27,"t":"Odgovori mu onaj: Ljubi Gospodina Boga svojega iz svega srca svoga, i svom dušom svojom, i svom snagom svojom, i svim umom svojim; i svoga bližnjega kao sebe samoga!”"},{"v":28,"t":"Reče mu na to Isus: “Pravo si odgovorio. To čini i živjet ćeš.”"},{"v":29,"t":"Ali hoteći se opravdati, reče on Isusu: “A tko je moj bližnji?”"},{"v":30,"t":"Isus prihvati i reče: “Čovjek neki silazio iz Jeruzalema u Jerihon. Upao među razbojnike koji ga svukoše i izraniše pa odoše ostavivši ga polumrtva."},{"v":31,"t":"Slučajno je onim putem silazio neki svećenik, vidje ga i zaobiđe."},{"v":32,"t":"A tako i levit: prolazeći onuda, vidje ga i zaobiđe."},{"v":33,"t":"Neki Samarijanac putujući dođe do njega, vidje ga, sažali se"},{"v":34,"t":"pa mu pristupi i povije rane zalivši ih uljem i vinom. Zatim ga posadi na svoje živinče, odvede ga u gostinjac i pobrinu se za nj."},{"v":35,"t":"Sutradan izvadi dva denara, dade ih gostioničaru i reče: 'Pobrini se za njega. Ako što više potrošiš, isplatit ću ti kad se budem vraćao.'”"},{"v":36,"t":"“Što ti se čini, koji je od ove trojice bio bližnji onomu koji je upao među razbojnike?”"},{"v":37,"t":"On odgovori: “Onaj koji mu iskaza milosrđe.” Nato mu reče Isus: “Idi pa i ti čini tako!”"},{"v":38,"t":"Dok su oni tako putovali, uđe on u jedno selo. Žena neka, imenom Marta, primi ga u kuću."},{"v":39,"t":"Imala je sestru koja se zvala Marija. Ona sjede do nogu Gospodinovih i slušaše riječ njegovu."},{"v":40,"t":"A Marta bijaše sva zauzeta posluživanjem pa pristupi i reče: “Gospodine, zar ne mariš što me sestra samu ostavila posluživati? Reci joj dakle da mi pomogne.”"},{"v":41,"t":"Odgovori joj Gospodin: “Marta, Marta! Brineš se i uznemiruješ za mnogo,"},{"v":42,"t":"a jedno je potrebno. Marija je uistinu izabrala bolji dio, koji joj se neće oduzeti.”"}]},"11":{"hr":[{"v":1,"t":"Jednom je Isus na nekome mjestu molio. Čim presta, reče mu jedan od učenika: “Gospodine, nauči nas moliti kao što je i Ivan naučio svoje učenike.”"},{"v":2,"t":"On im reče: “Kad molite, govorite: 'Oče! Sveti se ime tvoje! Dođi kraljevstvo tvoje!"},{"v":3,"t":"Kruh naš svagdanji daji nam svaki dan!"},{"v":4,"t":"I otpusti nam grijehe naše: ta i mi otpuštamo svakom dužniku svojem! I ne uvedi nas u napast!'”"},{"v":5,"t":"I reče im: “Tko to od vas ima ovakva prijatelja? Pođe k njemu o ponoći i rekne mu: 'Prijatelju, posudi mi tri kruha."},{"v":6,"t":"Prijatelj mi se s puta svratio te nemam što staviti preda nj!'"},{"v":7,"t":"A onaj mu iznutra odgovori: 'Ne dosađuj mi! Vrata su već zatvorena, a dječica sa mnom u postelji. Ne mogu ustati da ti dadnem...'"},{"v":8,"t":"Kažem vam: ako i ne ustane da mu dadne zato što mu je prijatelj, ustat će i dati mu što god treba zbog njegove bezočnosti.”"},{"v":9,"t":"“I ja vama kažem: Ištite i dat će vam se! Tražite i naći ćete! Kucajte i otvorit će vam se!"},{"v":10,"t":"Doista, tko god ište, prima; i tko traži, nalazi; i onomu tko kuca, otvorit će se.”"},{"v":11,"t":"“A koji je to otac među vama: kad ga sin zaište ribu, zar će mu mjesto ribe zmiju dati?"},{"v":12,"t":"Ili kad zaište jaje, zar će mu dati štipavca?"},{"v":13,"t":"Ako dakle vi, iako zli, znate dobrim darima darivati djecu svoju, koliko li će više Otac s neba obdariti Duhom Svetim one koji ga zaištu!”"},{"v":14,"t":"I istjerivaše đavla koji bijaše nijem. Kad iziđe đavao, progovori njemak. I mnoštvo se divilo."},{"v":15,"t":"A neki od njih rekoše: “Po Beelzebulu, poglavici đavolskom, izgoni đavle!”"},{"v":16,"t":"A drugi su iskušavajući ga, tražili od njega kakav znak s neba."},{"v":17,"t":"Ali on, znajući njihove misli, reče im: “Svako kraljevstvo u sebi razdijeljeno opustjet će i kuća će na kuću pasti."},{"v":18,"t":"Ako je dakle Sotona u sebi razdijeljen, kako će opstati kraljevstvo njegovo? Jer vi kažete da ja po Beelzebulu izgonim đavle."},{"v":19,"t":"Ako dakle ja po Beelzebulu izgonim đavle, po kome ih vaši sinovi izgone? Zato će vam oni biti suci."},{"v":20,"t":"Ali ako ja prstom Božjim izgonim đavle, zbilja je došlo k vama kraljevstvo Božje.”"},{"v":21,"t":"“Dokle god jaki i naoružani čuva svoj stan, u miru je sav njegov posjed."},{"v":22,"t":"Ali ako dođe jači od njega, svlada ga i otme mu sve njegovo oružje u koje se uzdao, a plijen razdijeli.”"},{"v":23,"t":"“Tko nije sa mnom, protiv mene je. I tko sa mnom ne sabire, rasipa.”"},{"v":24,"t":"“Kad nečisti duh iziđe iz čovjeka, luta bezvodnim mjestima tražeći spokoja. Kad ga ne nađe, rekne: 'Vratit ću se u kuću odakle iziđoh.'"},{"v":25,"t":"Došavši, nađe je pometenu i uređenu."},{"v":26,"t":"Tada ode i uzme sa sobom sedam drugih duhova, gorih od sebe, te uđu i nastane se ondje. Na kraju bude onomu čovjeku gore nego na početku.”"},{"v":27,"t":"Dok je on to govorio, povika neka žena iz mnoštva: “Blažena utroba koja te nosila i prsi koje si sisao!”"},{"v":28,"t":"On odgovori: “Još blaženiji oni koji slušaju riječ Božju i čuvaju je!”"},{"v":29,"t":"Kad je nagrnulo mnoštvo, poče im Isus govoriti: “Naraštaj ovaj naraštaj je opak. Znak traži, ali mu se znak neće dati doli znak Jonin."},{"v":30,"t":"Doista, kao što je Jona bio znak Ninivljanima, tako će biti i Sin Čovječji ovomu naraštaju.”"},{"v":31,"t":"“Kraljica će Juga ustati na Sudu s ljudima ovog naraštaja i osuditi ih jer je s krajeva zemlje došla čuti mudrost Salomonovu, a evo ovdje i više od Salomona!"},{"v":32,"t":"Ninivljani će ustati na Sudu s ovim naraštajem i osuditi ga jer se obratiše na propovijed Joninu, a evo ovdje i više od Jone!”"},{"v":33,"t":"“Nitko ne užiže svjetiljku da je stavi u zakutak ili pod posudu, nego na svijećnjak da oni koji ulaze vide svjetlost."},{"v":34,"t":"Oko je svjetiljka tvomu tijelu. Kad ti je oko bistro, sve ti je tijelo svijetlo. A kad je ono nevaljalo, i tijelo ti je tamno."},{"v":35,"t":"Pazi dakle da svjetlost koja je u tebi ne bude tamna."},{"v":36,"t":"Ako ti dakle sve tijelo bude svijetlo, bez djelića tame, bit će posve svijetlo, kao kad te svjetiljka svojim sjajem rasvjetljuje.”"},{"v":37,"t":"Dok je on govorio, pozva ga neki farizej k sebi na objed. On uđe i priđe k stolu."},{"v":38,"t":"Vidjevši to, farizej se začudi što se Isus prije objeda ne opra."},{"v":39,"t":"A Gospodin mu reče: “Da, vi farizeji čistite vanjštinu čaše u zdjele, a nutrina vam je puna grabeža i pakosti."},{"v":40,"t":"Bezumnici! Nije li onaj koji načini vanjštinu načinio i nutrinu."},{"v":41,"t":"Nego, dajte za milostinju ono iznutra i gle - sve vam je čisto.”"},{"v":42,"t":"“Ali jao vama, farizeji! Namirujete desetinu od metvice i rutvice i svake vrste povrća, a ne marite za pravednost i ljubav Božju. Ovo je trebalo činiti, a ono ne zanemariti.”"},{"v":43,"t":"“Jao vama farizeji! Volite prvo sjedalo u sinagogama i pozdrave na trgovima."},{"v":44,"t":"Jao vama! Vi ste kao nezamjetljivi grobovi po kojima ljudi ne znajući hode.”"},{"v":45,"t":"Nato će neki zakonoznanac: “Učitelju, tako govoreći i nas vrijeđaš.”"},{"v":46,"t":"A on reče: “Jao i vama, zakonoznanci! Tovarite na ljude terete nepodnosive, a sami ni da ih se jednim prstom dotaknete.”"},{"v":47,"t":"“Jao vama! Podižete spomenike prorocima, a vaši ih oci ubiše."},{"v":48,"t":"Zato ste svjedoci i sumišljenici djela svojih otaca: oni ih ubiše, a vi spomenike podižete!"},{"v":49,"t":"Zbog toga i kaza Mudrost Božja: 'Poslat ću k njima proroke i apostole. Neke će poubijati i prognati -"},{"v":50,"t":"da se od ovog naraštaja zatraži krv svih proroka prolivena od postanka svijeta,"},{"v":51,"t":"od krvi Abelove do krvi Zaharije, koji je pogubljen između žrtvenika i svetišta.' Da, kažem vam, tražit će se od ovoga naraštaja!”"},{"v":52,"t":"“Jao vama, zakonoznanci! Uzeste ključ znanja: sami ne uđoste, a spriječiste one koji htjedoše ući.”"},{"v":53,"t":"Kad Isus izađe odande, stadoše pismoznanci i farizeji žestoko na nj navaljivati i postavljati mu mnoga pitanja"},{"v":54,"t":"vrebajući na nj, ne bi li štogod ulovili iz njegovih usta."}]},"12":{"hr":[{"v":1,"t":"Kad se uto skupilo mnoštvo, tisuće i tisuće, te su jedni druge gazili, poče Isus govoriti najprije svojim učenicima: “Čuvajte se kvasca farizejskoga, to jest licemjerja."},{"v":2,"t":"Ništa nije skriveno što se neće otkriti ni tajno što se neće saznati."},{"v":3,"t":"Naprotiv, sve što u tami rekoste, na svjetlu će se čuti; i što ste po skrovištima u uho šaptali, propovijedat će se po krovovima.”"},{"v":4,"t":"“A kažem vama, prijateljima svojim: ne bojte se onih koji ubijaju tijelo, a nakon toga nemaju više što učiniti."},{"v":5,"t":"Pokazat ću vam koga vam se bojati: onoga se bojte koji pošto ubije, ima moć baciti u pakao. Da, velim vam, njega se bojte!"},{"v":6,"t":"Ne prodaje li se pet vrapčića za dva novčića? Pa ipak ni jednoga od njih Bog ne zaboravlja."},{"v":7,"t":"A vama su i vlasi na glavi sve izbrojene. Ne bojte se! Vredniji ste nego mnogo vrabaca!”"},{"v":8,"t":"“A kažem vam: tko se god prizna mojim pred ljudima, i Sin Čovječji priznat će se njegovim pred anđelima Božjim."},{"v":9,"t":"A tko mene zaniječe pred ljudima, bit će zanijekan pred anđelima Božjim.”"},{"v":10,"t":"“I tko god rekne riječ na Sina Čovječjega, oprostit će mu se. Ali tko pohuli protiv Duha Svetoga, neće mu se oprostiti.”"},{"v":11,"t":"“Nadalje, kad vas budu dovodili pred sinagoge i poglavarstva i vlasti, ne budite zabrinuti kako ćete se ili čime braniti, što li reći!"},{"v":12,"t":"Ta Duh Sveti poučit će vas u taj čas što valja reći.”"},{"v":13,"t":"Tada mu netko iz mnoštva reče: “Učitelju, reci mome bratu da podijeli sa mnom baštinu.”"},{"v":14,"t":"Nato mu on reče: “Čovječe, tko me postavio sucem ili djeliocem nad vama?”"},{"v":15,"t":"I dometnu im: “Klonite se i čuvajte svake pohlepe: koliko god netko obilovao, život mu nije u onom što posjeduje.”"},{"v":16,"t":"Kaza im i prispodobu: “Nekomu bogatu čovjeku obilno urodi zemlja"},{"v":17,"t":"pa u sebi razmišljaše: 'Što da učinim? Nemam gdje skupiti svoju ljetinu.'"},{"v":18,"t":"I reče: 'Evo što ću učiniti! Srušit ću svoje žitnice i podignuti veće pa ću ondje zgrnuti sve žito i dobra svoja."},{"v":19,"t":"Tada ću reći duši svojoj: dušo, evo imaš u zalihi mnogo dobara za godine mnoge. Počivaj, jedi, pij, uživaj!'"},{"v":20,"t":"Ali Bog mu reče: 'Bezumniče! Već noćas duša će se tvoja zaiskati od tebe! A što si pripravio, čije će biti?'"},{"v":21,"t":"Tako biva s onim koji sebi zgrće blago, a ne bogati se u Bogu.”"},{"v":22,"t":"Zatim reče svojim učenicima: “Zato vam kažem: ne budite zabrinuti za život: što ćete jesti; ni za tijelo: u što ćete se obući."},{"v":23,"t":"Ta život je vredniji od jela i tijelo od odijela."},{"v":24,"t":"Promotrite gavrane! Ne siju niti žanju, nemaju spremišta ni žitnice, pa ipak ih Bog hrani. Koliko li ste vi vredniji od ptica!"},{"v":25,"t":"A tko od vas zabrinutošću može svojemu stasu dodati lakat?"},{"v":26,"t":"Ako dakle ni ono najmanje ne možete, što ste onda za ostalo zabrinuti?"},{"v":27,"t":"Promotrite ljiljane, kako niti predu niti tkaju, a kažem vam: ni Salomon se u svoj svojoj slavi ne zaodjenu kao jedan od njih."},{"v":28,"t":"Pa ako travu koja je danas u polju, a sutra se u peć baca Bog tako odijeva, koliko li će više vas, malovjerni!”"},{"v":29,"t":"“Zato i vi: ne tražite što ćete jesti, što piti. Ne uznemirujte se!"},{"v":30,"t":"Ta sve to traže pogani ovoga svijeta. Otac vaš zna da vam je sve to potrebno."},{"v":31,"t":"Nego, tražite kraljevstvo njegovo, a to će vam se nadodati!”"},{"v":32,"t":"“Ne boj se, stado malo: svidjelo se Ocu vašemu dati vam Kraljevstvo.”"},{"v":33,"t":"“Prodajte što god imate i dajte za milostinju! Načinite sebi kese koje ne stare, blago nepropadljivo na nebesima, kamo se kradljivac ne približava i gdje moljac ne rastače."},{"v":34,"t":"Doista, gdje vam je blago, ondje će vam i srce biti.”"},{"v":35,"t":"“Neka vam bokovi budu opasani i svjetiljke upaljene,"},{"v":36,"t":"a vi slični ljudima što čekaju gospodara kad se vraća sa svadbe da mu odmah otvore čim stigne i pokuca."},{"v":37,"t":"Blago onim slugama koje gospodar, kada dođe, nađe budne! Zaista, kažem vam, pripasat će se, posaditi ih za stol pa će pristupiti i posluživati ih."},{"v":38,"t":"Pa dođe li o drugoj ili o trećoj straži i nađe ih tako, blago njima!”"},{"v":39,"t":"“A ovo znajte: kad bi domaćin znao u koji čas kradljivac dolazi, ne bi dao prokopati kuće."},{"v":40,"t":"I vi budite pripravni jer u čas kad i ne mislite Sin Čovječji dolazi.”"},{"v":41,"t":"Nato će Petar: “Gospodine, govoriš li tu prispodobu samo za nas ili i za sve?”"},{"v":42,"t":"Reče Gospodin: “Tko li je onaj vjerni i razumni upravitelj što će ga gospodar postaviti nad svojom poslugom da im u pravo vrijeme daje obrok?"},{"v":43,"t":"Blago onome sluzi kojega gospodar kada dođe, nađe da tako radi."},{"v":44,"t":"Uistinu, kažem vam, postavit će ga nad svim imanjem svojim.”"},{"v":45,"t":"“No rekne li taj sluga u srcu: 'Okasnit će gospodar moj' pa stane tući sluge i sluškinje, jesti, piti i opijati se,"},{"v":46,"t":"doći će gospodar toga sluge u dan u koji mu se ne nada i u čas u koji i ne sluti; rasjeći će ga i dodijeliti mu udes među nevjernicima.”"},{"v":47,"t":"“I onaj sluga što je znao volju gospodara svoga, a nije bio spreman ili nije učinio po volji njegovoj, dobit će mnogo udaraca."},{"v":48,"t":"A onaj koji nije znao, ali je učinio što zaslužuje udarce, dobit će malo udaraca. Kome je god mnogo dano, od njega će se mnogo iskati. Kome je mnogo povjereno, više će se od njega iskati.”"},{"v":49,"t":"“Oganj dođoh baciti na zemlju pa što hoću ako je već planuo!"},{"v":50,"t":"Ali krstom mi se krstiti i kakve li muke za me dok se to ne izvrši!”"},{"v":51,"t":"“Mislite li da sam došao mir dati na zemlji? Nipošto, kažem vam, nego razdjeljenje."},{"v":52,"t":"Ta bit će odsada petorica u jednoj kući razdijeljena: razdijelit će se trojica protiv dvojice i dvojica protiv trojice -"},{"v":53,"t":"otac protiv sina i sin protiv oca, mati protiv kćeri i kći protiv matere, svekrva protiv snahe i snaha protiv svekrve.”"},{"v":54,"t":"Zatim je govorio mnoštvu: “Kad opazite da se oblak diže na zapadu, odmah kažete: 'Kiša će!' I bude tako."},{"v":55,"t":"Kad zapuše južnjak, kažete: 'Bit će vrućine!' I bude."},{"v":56,"t":"Licemjeri! Lice zemlje i neba umijete rasuditi, kako onda ovo vrijeme ne rasuđujete?”"},{"v":57,"t":"“Zašto sami od sebe ne sudite što je pravo?"},{"v":58,"t":"Kad s protivnikom ideš glavaru, na putu sve uloži da ga se oslobodiš pa te ne odvuče k sucu. Sudac će te predati izvršitelju, a izvršitelj baciti u tamnicu."},{"v":59,"t":"Kažem ti: nećeš izići odande dok ne isplatiš do posljednjega novčića.”"}]},"13":{"hr":[{"v":1,"t":"Upravo u taj čas dođoše neki te mu javiše što se dogodilo s Galilejcima kojih je krv Pilat pomiješao s krvlju njihovih žrtava."},{"v":2,"t":"Isus im odgovori: “Mislite li da ti Galilejci, jer tako postradaše, bijahu grešniji od drugih Galilejaca?"},{"v":3,"t":"Nipošto, kažem vam, nego ako se ne obratite, svi ćete slično propasti!"},{"v":4,"t":"Ili onih osamnaest na koje se srušila kula u Siloamu i ubila ih, zar mislite da su oni bili veći dužnici od svih Jeruzalemaca?"},{"v":5,"t":"Nipošto, kažem vam, nego ako se ne obratite, svi ćete tako propasti.”"},{"v":6,"t":"Nato im pripovjedi ovu prispodobu: “Imao netko smokvu zasađenu u svom vinogradu. Dođe tražeć ploda na njoj i ne nađe"},{"v":7,"t":"pa reče vinogradaru: 'Evo, već tri godine dolazim i tražim ploda na ovoj smokvi i ne nalazim. Posijeci je. Zašto da iscrpljuje zemlju?'"},{"v":8,"t":"A on mu odgovori: 'Gospodaru, ostavi je još ove godine dok je ne okopam i ne pognojim."},{"v":9,"t":"Možda će ubuduće ipak uroditi. Ako li ne, posjeći ćeš je.'”"},{"v":10,"t":"Jedne je subote naučavao u nekoj sinagogi."},{"v":11,"t":"Kad eto žene koja je osamnaest godina imala duha bolesti. Bila je zgrbljena i nikako se nije mogla uspraviti."},{"v":12,"t":"Kad je Isus opazi, dozva je i reče joj: “Ženo, oslobođena si svoje bolesti!”"},{"v":13,"t":"I položi na nju ruke, a ona se umah uspravi i poče slaviti Boga."},{"v":14,"t":"Nadstojnik sinagoge - ozlovoljen što je Isus u subotu izliječio - govoraše mnoštvu: “Šest je dana u koje treba raditi! U te dakle dane dolazite i liječite se, a ne u dan subotni!”"},{"v":15,"t":"Odgovori mu Gospodin: “Licemjeri! Ne driješi li svaki od vas u subotu svoga vola ili magarca od jasala da ga vodi na vodu?"},{"v":16,"t":"Nije li dakle i ovu kćer Abrahamovu, koju Sotona sveza evo osamnaest je već godina, trebalo odriješiti od tih spona u dan subotni?”"},{"v":17,"t":"Na te njegove riječi postidješe se svi protivnici njegovi, a sav se narod radovaše zbog svega čime se on proslavio."},{"v":18,"t":"Govoraše dakle: “Čemu je slično kraljevstvo Božje? Čemu da ga prispodobim?"},{"v":19,"t":"Ono je kao kad čovjek uze gorušičino zrno i baci ga u svoj vrt. Uzraste i razvi se u stablo te mu se ptice nebeske gnijezde po granama.”"},{"v":20,"t":"I opet im reče: “Čemu da prispodobim kraljevstvo Božje?"},{"v":21,"t":"Ono je kao kad žena uze kvasac i zamijesi ga u tri mjere brašna dok sve ne uskisne.”"},{"v":22,"t":"Putujući tako u Jeruzalem, prolazio je i naučavao gradovima i selima."},{"v":23,"t":"Reče mu tada netko: “Gospodine, je li malo onih koji se spasavaju?” A on im reče:"},{"v":24,"t":"“Borite se da uđete na uska vrata jer mnogi će, velim vam, tražiti da uđu, ali neće moći.”"},{"v":25,"t":"“Kada gospodar kuće ustane i zaključa vrata, a vi stojeći vani počnete kucati na vrata: 'Gospodine, otvori nam!', on će vam odgovoriti: 'Ne znam vas odakle ste!'"},{"v":26,"t":"Tada ćete početi govoriti: 'Pa mi smo s tobom jeli i pili, po našim si trgovima naučavao!'"},{"v":27,"t":"A on će vam reći: 'Kažem vam: ne znam odakle ste. Odstupite od mene, svi zlotvori!'”"},{"v":28,"t":"“Ondje će biti plač i škrgut zubi kad ugledate Abrahama i Izaka i Jakova i sve proroke u kraljevstvu Božjem, a sebe vani, izbačene."},{"v":29,"t":"I doći će s istoka i zapada, sa sjevera i juga i sjesti za stol u kraljevstvu Božjem."},{"v":30,"t":"Evo, ima posljednjih koji će biti prvi, ima i prvih koji će biti posljednji.”"},{"v":31,"t":"U taj čas pristupe neki farizeji i reknu mu: “Otiđi, otputuj odavde jer te Herod hoće ubiti.”"},{"v":32,"t":"A on će njima: “Idite i kažite toj lisici: 'Evo, izgonim đavle i liječim danas i sutra, a treći dan dovršujem."},{"v":33,"t":"Ali danas, sutra i prekosutra moram nastaviti put jer ne priliči da prorok pogine izvan Jeruzalema.'”"},{"v":34,"t":"“Jeruzaleme, Jeruzaleme, koji ubijaš proroke i kamenuješ one što su tebi poslani! Koliko li puta htjedoh skupiti djecu tvoju kao kvočka piliće pod krila i ne htjedoste!"},{"v":35,"t":"Evo, napuštena vam kuća. A kažem vam, nećete me vidjeti dok ne dođe čas te reknete: “Blagoslovljen Onaj koji dolazi u ime Gospodnje!”"}]},"14":{"hr":[{"v":1,"t":"Jedne subote dođe on u kuću nekoga prvaka farizejskog na objed. A oni ga vrebahu."},{"v":2,"t":"Kad evo: pred njim neki čovjek koji je imao vodenu bolest."},{"v":3,"t":"Nato Isus upita zakonoznance i farizeje: “Je li dopušteno subotom liječiti ili nije?”"},{"v":4,"t":"A oni mukom ponikoše. On ga dotaknu, izliječi i otpusti."},{"v":5,"t":"A njima reče: “Ako komu od vas sin ili vol padne u bunar, neće li ga brže bolje izvući i u dan subotni?”"},{"v":6,"t":"I ne mogoše mu na to odgovoriti."},{"v":7,"t":"Promatrajući kako uzvanici biraju prva mjesta, kaza im prispodobu:"},{"v":8,"t":"“Kada te tko pozove na svadbu, ne sjedaj na prvo mjesto da ne bi možda bio pozvan koji časniji od tebe,"},{"v":9,"t":"te ne dođe onaj koji je pozvao tebe i njega i ne rekne ti: 'Ustupi mjesto ovome.' Tada ćeš, postiđen, morati zauzeti posljednje mjesto."},{"v":10,"t":"Nego kad budeš pozvan, idi i sjedni na posljednje mjesto pa, kada dođe onaj koji te pozvao, da ti rekne: 'Prijatelju, pomakni se naviše!' Bit će ti to tada na čast pred svim sustolnicima,"},{"v":11,"t":"jer - svaki koji se uzvisuje, bit će ponižen, a koji se ponizuje, bit će uzvišen.”"},{"v":12,"t":"A i onome koji ga pozva, kaza: “Kad priređuješ objed ili večeru, ne pozivaj svojih prijatelja, ni braće, ni rodbine, ni bogatih susjeda, da ne bi možda i oni tebe pozvali i tako ti uzvratili."},{"v":13,"t":"Nego kad priređuješ gozbu, pozovi siromahe, sakate, hrome, slijepe."},{"v":14,"t":"Blago tebi jer oni ti nemaju čime uzvratiti. Uzvratit će ti se doista o uskrsnuću pravednih.”"},{"v":15,"t":"Kad je to čuo jedan od sustolnika, reče mu: “Blago onome koji bude blagovao u kraljevstvu Božjem!”"},{"v":16,"t":"A on mu reče: “Čovjek neki priredi veliku večeru i pozva mnoge."},{"v":17,"t":"I posla slugu u vrijeme večere da rekne uzvanicima: 'Dođite! Već je pripravljeno!'"},{"v":18,"t":"A oni se odreda počeli ispričavati. Prvi mu reče: 'Njivu sam kupio i valja mi poći pogledati je. Molim te, ispričaj me.'"},{"v":19,"t":"Drugi reče: 'Kupio sam pet jarmova volova pa idem okušati ih. Molim te, ispričaj me.'"},{"v":20,"t":"Treći reče: 'Oženio sam se i zato ne mogu doći.'”"},{"v":21,"t":"“Sluga se vrati i javi to domaćinu. Tada domaćin, gnjevan, reče sluzi: 'Iziđi brzo na trgove gradske i ulice pa dovedi ovamo prosjake, sakate, slijepe i hrome.'"},{"v":22,"t":"I sluga reče: 'Gospodaru, učinjeno je što si naredio i još ima mjesta.'"},{"v":23,"t":"Reče gospodar sluzi: 'Iziđi na putove i među ograde i prisili neka uđu da mi se napuni kuća.'"},{"v":24,"t":"A kažem vam: nijedan od onih pozvanih neće okusiti moje večere.”"},{"v":25,"t":"S njim je zajedno putovalo silno mnoštvo. On se okrene i reče im:"},{"v":26,"t":"“Dođe li tko k meni, a ne mrzi svog oca i majku, ženu i djecu, braću i sestre, pa i sam svoj život, ne može biti moj učenik!"},{"v":27,"t":"I tko ne nosi svoga križa i ne ide za mnom, ne može biti moj učenik!”"},{"v":28,"t":"“Tko od vas, nakan graditi kulu, neće prije sjesti i proračunati troškove ima li čime dovršiti:"},{"v":29,"t":"da ga ne bi - pošto već postavi temelj, a ne mogne dovršiti - počeli ismjehivati svi koji to vide:"},{"v":30,"t":"'Ovaj čovjek poče graditi, a ne može dovršiti!'"},{"v":31,"t":"Ili koji kralj kad polazi da se zarati s drugim kraljem, neće prije sjesti i promisliti da li s deset tisuća može presresti onoga koji na nj dolazi s dvadeset tisuća?"},{"v":32,"t":"Ako ne može, dok je onaj još daleko, poslat će poslanstvo da zaište mir.”"},{"v":33,"t":"“Tako dakle nijedan od vas koji se ne odrekne svega što posjeduje, ne može biti moj učenik.”"},{"v":34,"t":"“Dobra je sol. Ali ako i sol obljutavi, čime će se ona začiniti?"},{"v":35,"t":"Nije prikladna ni za zemlju ni za gnojište. Van se baca. Tko ima uši da čuje, neka čuje!”"}]},"15":{"hr":[{"v":1,"t":"Okupljahu se oko njega svi carinici i grešnici da ga slušaju."},{"v":2,"t":"Stoga farizeji i pismoznanci mrmljahu: “Ovaj prima grešnike, i blaguje s njima.”"},{"v":3,"t":"Nato im Isus kaza ovu prispodobu:"},{"v":4,"t":"“Tko to od vas, ako ima sto ovaca pa izgubi jednu od njih, ne ostavi onih devedeset i devet u pustinji te pođe za izgubljenom dok je ne nađe?"},{"v":5,"t":"A kad je nađe, stavi je na ramena sav radostan"},{"v":6,"t":"pa došavši kući, sazove prijatelje i susjede i rekne im: 'Radujte se sa mnom! Nađoh ovcu svoju izgubljenu.'"},{"v":7,"t":"Kažem vam, tako će na nebu biti veća radost zbog jednog obraćena grešnika nego li zbog devedeset i devet pravednika kojima ne treba obraćenja.”"},{"v":8,"t":"“Ili koja to žena, ima li deset drahma pa izgubi jednu drahmu, ne zapali svjetiljku, pomete kuću i brižljivo pretraži dok je ne nađe?"},{"v":9,"t":"A kad je nađe, pozove prijateljice i susjede pa će im: 'Radujte se sa mnom! Nađoh drahmu što je bijah izgubila.'"},{"v":10,"t":"Tako, kažem vam, biva radost pred anđelima Božjim zbog jednog obraćena grešnika.”"},{"v":11,"t":"I nastavi: “Čovjek neki imao dva sina."},{"v":12,"t":"Mlađi reče ocu: 'Oče, daj mi dio dobara koji mi pripada.' I razdijeli im imanje."},{"v":13,"t":"Nakon nekoliko dana mlađi sin pokupi sve, otputova u daleku zemlju i ondje potrati svoja dobra živeći razvratno.”"},{"v":14,"t":"“Kad sve potroši, nasta ljuta glad u onoj zemlji te on poče oskudijevati."},{"v":15,"t":"Ode i pribi se kod jednoga žitelja u onoj zemlji. On ga posla na svoja polja pasti svinje."},{"v":16,"t":"Želio se nasititi rogačima što su ih jele svinje, ali mu ih nitko nije davao.”"},{"v":17,"t":"“Došavši k sebi, reče: 'Koliki najamnici oca moga imaju kruha napretek, a ja ovdje umirem od gladi!"},{"v":18,"t":"Ustat ću, poći svomu ocu i reći mu: 'Oče, sagriješih protiv Neba i pred tobom!"},{"v":19,"t":"Nisam više dostojan zvati se sinom tvojim. Primi me kao jednog od svojih najamnika.'”"},{"v":20,"t":"“Usta i pođe svom ocu. Dok je još bio daleko, njegov ga otac ugleda, ganu se, potrča, pade mu oko vrata i izljubi ga."},{"v":21,"t":"A sin će mu: 'Oče! Sagriješih protiv Neba i pred tobom! Nisam više dostojan zvati se sinom tvojim.'"},{"v":22,"t":"A otac reče slugama: 'Brzo iznesite haljinu najljepšu i obucite ga! Stavite mu prsten na ruku i obuću na noge!"},{"v":23,"t":"Tele ugojeno dovedite i zakoljite, pa da se pogostimo i proveselimo"},{"v":24,"t":"jer sin mi ovaj bijaše mrtav i oživje, izgubljen bijaše i nađe se!' I stadoše se veseliti.”"},{"v":25,"t":"“A stariji mu sin bijaše u polju. Kad se na povratku približio kući, začu svirku i igru"},{"v":26,"t":"pa dozva jednoga slugu da se raspita što je to."},{"v":27,"t":"A ovaj će mu: 'Došao tvoj brat pa otac tvoj zakla tele ugojeno što sina zdrava dočeka.'"},{"v":28,"t":"A on se rasrdi i ne htjede ući. Otac tada iziđe i stane ga nagovarati."},{"v":29,"t":"A on će ocu: 'Evo toliko ti godina služim i nikada ne prestupih tvoju zapovijed, a nikad mi ni jareta nisi dao da se s prijateljima proveselim."},{"v":30,"t":"A kada dođe ovaj sin tvoj koji s bludnicama proždrije tvoje imanje, ti mu zakla ugojeno tele.'"},{"v":31,"t":"Nato će mu otac: 'Sinko, ti si uvijek sa mnom i sve moje - tvoje je."},{"v":32,"t":"No trebalo se veseliti i radovati jer ovaj brat tvoj bijaše mrtav i oživje, izgubljen i nađe se!'”"}]},"16":{"hr":[{"v":1,"t":"Govoraše i svojim učenicima: “Bijaše neki bogat čovjek koji je imao upravitelja."},{"v":2,"t":"Ovaj je bio optužen pred njim kao da mu rasipa imanje. On ga pozva pa mu reče: 'Što to čujem o tebi? Položi račun o svom upravljanju jer više ne možeš biti upravitelj!'"},{"v":3,"t":"Nato upravitelj reče u sebi: 'Što da učinim kad mi gospodar moj oduzima upravu? Kopati? Nemam snage. Prositi? Stidim se."},{"v":4,"t":"Znam što ću da me prime u svoje kuće kad budem maknut s uprave.'”"},{"v":5,"t":"“I pozva dužnike svoga gospodara, jednog po jednog. Upita prvoga: 'Koliko duguješ gospodaru mojemu?' On reče: 'Sto bata ulja.'"},{"v":6,"t":"A on će mu: 'Uzmi svoju zadužnicu, sjedni brzo, napiši pedeset.'"},{"v":7,"t":"Zatim reče drugomu: 'A ti, koliko ti duguješ?' On odgovori: 'Sto kora pšenice.' Kaže mu: 'Uzmi svoju zadužnicu i napiši osamdeset.'”"},{"v":8,"t":"“I pohvali gospodar nepoštenog upravitelja što snalažljivo postupi jer sinovi su ovoga svijeta snalažljiviji prema svojima od sinova svjetlosti.”"},{"v":9,"t":"“I ja vama kažem: napravite sebi prijatelje od nepoštena bogatstva pa kad ga nestane da vas prime u vječne šatore.”"},{"v":10,"t":"“Tko je vjeran u najmanjem, i u najvećem je vjeran; a tko je u najmanjem nepošten, i u najvećem je nepošten."},{"v":11,"t":"Ako dakle ne bijaste vjerni u nepoštenom bogatstvu, tko li će vam istinsko povjeriti?"},{"v":12,"t":"I ako u tuđem ne bijaste vjerni, tko li će vam vaše dati?”"},{"v":13,"t":"“Nijedan sluga ne može služiti dvojici gospodara. Ili će jednoga mrziti, a drugoga ljubiti; ili će uz jednoga prianjati, a drugoga prezirati. Ne možete služiti Bogu i bogatstvu.”"},{"v":14,"t":"Sve su to slušali farizeji, srebroljupci, i rugali mu se."},{"v":15,"t":"On im reče: “Vi se pravite pravedni pred ljudima, ali zna Bog srca vaša. Jer što je ljudima uzvišeno, odvratnost je pred Bogom.”"},{"v":16,"t":"“Zakon i Proroci do Ivana su, a otada se navješćuje kraljevstvo Božje i svatko se u nj silom probija."},{"v":17,"t":"Lakše će nebo i zemlja proći, negoli propasti i jedan potezić Zakona.”"},{"v":18,"t":"“Tko god otpusti svoju ženu pa se oženi drugom, čini preljub. I tko se god oženi otpuštenom, čini preljub.”"},{"v":19,"t":"“Bijaše neki bogataš. Odijevao se u grimiz i tanani lan i danomice se sjajno gostio."},{"v":20,"t":"A neki siromah, imenom Lazar, ležao je sav u čirevima pred njegovim vratima"},{"v":21,"t":"i priželjkivao nasititi se onim što je padalo s bogataševa stola. Čak su i psi dolazili i lizali mu čireve.”"},{"v":22,"t":"“Kad umrije siromah, odnesoše ga anđeli u krilo Abrahamovo. Umrije i bogataš te bude pokopan."},{"v":23,"t":"Tada u teškim mukama u paklu, podiže svoje oči te izdaleka ugleda Abrahama i u krilu mu Lazara"},{"v":24,"t":"pa zavapi: 'Oče Abrahame, smiluj mi se i pošalji Lazara da umoči vršak svoga prsta u vodu i rashladi mi jezik jer se strašno mučim u ovom plamenu.'"},{"v":25,"t":"Reče nato Abraham: 'Sinko! Sjeti se da si za života primio dobra svoja, a tako i Lazar zla. Sada se on ovdje tješi, a ti se mučiš."},{"v":26,"t":"K tome između nas i vas zjapi provalija golema te koji bi i htjeli prijeći odavde k vama, ne mogu, a ni odatle k nama prijelaza nema.'”"},{"v":27,"t":"“Nato će bogataš: 'Molim te onda, oče, pošalji Lazara u kuću oca moga."},{"v":28,"t":"Imam petero braće pa neka im posvjedoči da i oni ne dođu u ovo mjesto muka.'"},{"v":29,"t":"Kaže Abraham: 'Imaju Mojsija i Proroke! Njih neka poslušaju!'"},{"v":30,"t":"A on će: 'O ne, oče Abrahame! Nego dođe li tko od mrtvih k njima, obratit će se.'"},{"v":31,"t":"Reče mu: 'Ako ne slušaju Mojsija i Proroka, neće povjerovati sve da i od mrtvih tko ustane.'”"}]},"17":{"hr":[{"v":1,"t":"I reče svojim učenicima: “Nije moguće da ne dođu sablazni, no jao onome po kom dolaze;"},{"v":2,"t":"je li s mlinskim kamenom o vratu strovaljen u more, korisnije mu je, nego da sablazni jednoga od ovih malenih."},{"v":3,"t":"Čuvajte se!” “Pogriješi li tvoj brat, prekori ga; ako se obrati, oprosti mu."},{"v":4,"t":"Pa ako se sedam puta na dan ogriješi o tebe i sedam se puta obrati tebi govoreći: 'Žao mi je!', oprosti mu.”"},{"v":5,"t":"Apostoli zamole Gospodina: “Umnoži nam vjeru!”"},{"v":6,"t":"Gospodin im odvrati: “Da imate vjere koliko je zrno gorušičino, rekli biste ovom dudu: 'Iščupaj se s korijenom i presadi se u more!' I on bi vas poslušao.”"},{"v":7,"t":"“Tko će to od vas reći sluzi svomu, oraču ili pastiru, koji se vrati s polja: 'Dođi brzo i sjedni za stol?'"},{"v":8,"t":"Neće li mu naprotiv reći: 'Pripravi što ću večerati pa se pripaši i poslužuj mi dok jedem i pijem; potom ćeš ti jesti i piti?'"},{"v":9,"t":"Zar duguje zahvalnost sluzi jer je izvršio što mu je naređeno?"},{"v":10,"t":"Tako i vi: kad izvršite sve što vam je naređeno, recite: 'Sluge smo beskorisne! Učinismo što smo bili dužni učiniti!'”"},{"v":11,"t":"Dok je tako putovao u Jeruzalem, prolazio je između Samarije i Galileje."},{"v":12,"t":"Kad je ulazio u neko selo, eto mu u susret deset gubavaca. Zaustave se podaleko"},{"v":13,"t":"i zavape: “Isuse, Učitelju, smiluj nam se!”"},{"v":14,"t":"Kad ih Isus ugleda, reče im: “Idite, pokažite se svećenicima!” I dok su išli, očistiše se."},{"v":15,"t":"Jedan od njih vidjevši da je ozdravio, vrati se slaveći Boga u sav glas."},{"v":16,"t":"Baci se ničice k Isusovim nogama zahvaljujući mu. A to bijaše neki Samarijanac."},{"v":17,"t":"Nato Isus primijeti: “Zar se ne očistiše desetorica?"},{"v":18,"t":"A gdje su ona devetorica? Ne nađe li se nijedan koji bi se vratio i podao slavu Bogu, osim ovoga tuđinca?”"},{"v":19,"t":"A njemu reče: “Ustani! Idi! Tvoja te vjera spasila!”"},{"v":20,"t":"Upitaju ga farizeji: “Kad će doći kraljevstvo Božje?” Odgovori im: “Kraljevstvo Božje ne dolazi primjetljivo."},{"v":21,"t":"Niti će se moći kazati: 'Evo ga ovdje!' ili: 'Eno ga ondje!' Ta evo - kraljevstvo je Božje među vama!”"},{"v":22,"t":"Zatim reče učenicima: “Doći će dani kad ćete zaželjeti vidjeti i jedan dan Sina Čovječjega, ali ga nećete vidjeti."},{"v":23,"t":"Govorit će vam: 'Eno ga ondje, evo ovdje!' Ne odlazite i ne pomamite se!"},{"v":24,"t":"Jer kao što munja sijevne na jednom kraju obzorja i odbljesne na drugom, tako će biti i sa Sinom Čovječjim u Dan njegov."},{"v":25,"t":"No prije treba da on mnogo pretrpi i da ga ovaj naraštaj odbaci.”"},{"v":26,"t":"“I kao što bijaše u dane Noine, tako će biti i u dane Sina Čovječjega:"},{"v":27,"t":"jeli su, pili, ženili se i udavali do dana kad Noa uđe u korablju. I dođe potop i sve uništi."},{"v":28,"t":"Slično kao što bijaše u dane Lotove: jeli su, pili, kupovali, prodavali, sadili, gradili."},{"v":29,"t":"A onog dana kad Lot iziđe iz Sodome, zapljušti s neba oganj i sumpor i sve uništi."},{"v":30,"t":"Tako će isto biti u dan kad se Sin Čovječji objavi.”"},{"v":31,"t":"“U onaj dan tko bude na krovu, a stvari mu u kući, neka ne siđe da ih uzme."},{"v":32,"t":"I tko bude u polju, neka se ne okreće natrag. Sjetite se žene Lotove!"},{"v":33,"t":"Tko god bude nastojao život svoj sačuvati, izgubit će ga; a tko ga izgubi, živa će ga sačuvati.”"},{"v":34,"t":"“Kažem vam, one će noći biti dvojica u jednoj postelji: jedan će se uzeti, drugi ostaviti."},{"v":35,"t":"Dvije će mljeti zajedno: jedna će se uzeti, druga ostaviti.”"},{"v":36,"t":"#"},{"v":37,"t":"Upitaše ga na to: “Gdje to, Gospodine?” A on im reče: “Gdje bude trupla, ondje će se okupljati i orlovi.”"}]},"18":{"hr":[{"v":1,"t":"Kaza im i prispodobu kako valja svagda moliti i nikada ne sustati:"},{"v":2,"t":"“U nekom gradu bio sudac. Boga se nije bojao, za ljude nije mario."},{"v":3,"t":"U tom gradu bijaše i neka udovica. Dolazila k njemu i molila: 'Obrani me od mog tužitelja!'"},{"v":4,"t":"No on ne htjede zadugo. Napokon reče u sebi: 'Iako se Boga ne bojim nit za ljude marim, ipak,"},{"v":5,"t":"jer mi udovica ova dodijava, obranit ću je da vječno ne dolazi mučiti me.'”"},{"v":6,"t":"Nato reče Gospodin: “Čujte što govori nepravedni sudac!"},{"v":7,"t":"Neće li onda Bog obraniti svoje izabrane koji dan i noć vape k njemu sve ako i odgađa stvar njihovu?"},{"v":8,"t":"Kažem vam, ustat će žurno na njihovu obranu. Ali kad Sin Čovječji dođe, hoće li naći vjere na zemlji?”"},{"v":9,"t":"Nekima pak koji se pouzdavahu u sebe da su pravednici, a druge potcjenjivahu, reče zatim ovu prispodobu:"},{"v":10,"t":"“Dva čovjeka uziđoše u Hram pomoliti se: jedan farizej, drugi carinik."},{"v":11,"t":"Farizej se uspravan ovako u sebi molio: 'Bože, hvala ti što nisam kao ostali ljudi: grabežljivci, nepravednici, preljubnici ili - kao ovaj carinik.'"},{"v":12,"t":"Postim dvaput u tjednu, dajem desetinu od svega što steknem.'"},{"v":13,"t":"A carinik, stojeći izdaleka, ne usudi se ni očiju podignuti k nebu, nego se udaraše u prsa govoreći: 'Bože milostiv budi meni grešniku!'"},{"v":14,"t":"Kažem vam: ovaj siđe opravdan kući svojoj, a ne onaj! Svaki koji se uzvisuje, bit će ponižen; a koji se ponizuje, bit će uzvišen.”"},{"v":15,"t":"A donosili mu i dojenčad da ih se dotakne. Vidjevši to, učenici im branili."},{"v":16,"t":"A Isus ih dozva i reče: “Pustite dječicu neka dolaze k meni i ne priječite im jer takvih je kraljevstvo Božje.”"},{"v":17,"t":"“Zaista, kažem vam, tko ne primi kraljevstva Božjega kao dijete, ne, u nj neće ući.”"},{"v":18,"t":"I upita ga neki uglednik: “Učitelju dobri, što mi je činiti da baštinim život vječni?”"},{"v":19,"t":"Reče mu Isus: “Što me zoveš dobrim? Nitko nije dobar, doli Bog jedini."},{"v":20,"t":"Zapovijedi znaš: Ne čini preljuba! Ne ubij! Ne ukradi! Ne svjedoči lažno! Poštuj oca svoga i majku!”"},{"v":21,"t":"A onaj će: “Sve sam to čuvao od mladosti.”"},{"v":22,"t":"Čuvši to, Isus mu reče: “Još ti jedno preostaje: sve što imaš prodaj i razdaj siromasima pa ćeš imati blago na nebu. A onda dođi i idi za mnom.”"},{"v":23,"t":"Kad je on to čuo, ražalosti se jer bijaše silno bogat."},{"v":24,"t":"Vidjevši ga, reče Isus: “Kako li je teško imućnicima u kraljevstvo Božje!"},{"v":25,"t":"Lakše je devi kroz uši iglene nego bogatašu u kraljevstvo Božje.”"},{"v":26,"t":"Koji su to čuli, rekoše: “Pa tko se onda može spasiti?”"},{"v":27,"t":"A on će: “Što je nemoguće ljudima, moguće je Bogu.”"},{"v":28,"t":"Nato reče Petar: “Evo, mi ostavismo svoje i pođosmo za tobom.”"},{"v":29,"t":"Isus će im: “Zaista, kažem vam, nema ga tko bi ostavio kuću, ili ženu, ili braću, ili roditelje, ili djecu poradi kraljevstva Božjega,"},{"v":30,"t":"a da ne bi primio mnogostruko već u ovom vremenu, i u budućem vijeku život vječni.”"},{"v":31,"t":"I uzevši sa sobom dvanaestoricu, reče im: “Evo uzlazimo u Jeruzalem i na Sinu Čovječjem ispunit će se sve što su napisali proroci:"},{"v":32,"t":"doista, bit će predan poganima, izrugan, zlostavljan i popljuvan;"},{"v":33,"t":"i pošto ga izbičuju, ubit će ga, ali on će treći dan ustati.”"},{"v":34,"t":"No oni ništa od toga ne razumješe. Te im riječi bijahu skrivene i ne shvaćahu što bijaše rečeno."},{"v":35,"t":"A kad se približavao Jerihonu, neki slijepac sjedio kraj puta i prosio."},{"v":36,"t":"Čuvši gdje mnoštvo prolazi, raspitivao se što je to."},{"v":37,"t":"Rekoše mu: “Isus Nazarećanin prolazi.”"},{"v":38,"t":"Tada povika: “Isuse, Sine Davidov, smiluj mi se!”"},{"v":39,"t":"Oni ga sprijeda ušutkivali, ali on je još jače vikao: “Sine Davidov, smiluj mi se!”"},{"v":40,"t":"Isus se zaustavi i zapovjedi da ga dovedu k njemu. Kad se on približi, upita ga:"},{"v":41,"t":"“Što hoćeš da ti učinim?” A on će: “Gospodine, da progledam.”"},{"v":42,"t":"Isus će mu: “Progledaj! Vjera te tvoja spasila.”"},{"v":43,"t":"I umah progleda i uputi se za njim slaveći Boga. I sav narod koji to vidje dade hvalu Bogu."}]},"19":{"hr":[{"v":1,"t":"I uđe u Jerihon. Dok je njime prolazio,"},{"v":2,"t":"eto čovjeka imenom Zakej. Bijaše on nadcarinik, i to bogat."},{"v":3,"t":"Želio je vidjeti tko je to Isus, ali ne mogaše od mnoštva jer je bio niska stasa."},{"v":4,"t":"Potrča naprijed, pope se na smokvu da ga vidi jer je onuda imao proći."},{"v":5,"t":"Kad Isus dođe na to mjesto, pogleda gore i reče mu: “Zakeju, žurno siđi! Danas mi je proboraviti u tvojoj kući.”"},{"v":6,"t":"On žurno siđe i primi ga sav radostan."},{"v":7,"t":"A svi koji to vidješe stadoše mrmljati: “Čovjeku se grešniku svratio!”"},{"v":8,"t":"A Zakej usta i reče Gospodinu: “Evo, Gospodine, polovicu svog imanja dajem siromasima! I ako sam koga u čemu prevario, vraćam četverostruko.”"},{"v":9,"t":"Reče mu na to Isus: “Danas je došlo spasenje ovoj kući jer i on je sin Abrahamov!"},{"v":10,"t":"Ta Sin Čovječji dođe potražiti i spasiti izgubljeno!”"},{"v":11,"t":"Kako su oni to slušali, dometnu on prispodobu - zato što bijaše nadomak Jeruzalemu i oni mislili da će se umah pojaviti kraljevstvo Božje."},{"v":12,"t":"Reče dakle: “Neki je ugledan čovjek imao otputovati u daleku zemlju da primi svoje kraljevstvo pa da se vrati."},{"v":13,"t":"Dozva svojih deset slugu, dade im deset mna i reče: 'Trgujte dok ne dođem.'"},{"v":14,"t":"A njegovi ga građani mrzili te poslaše za njim poslanstvo s porukom: 'Nećemo da se ovaj zakralji nad nama.'”"},{"v":15,"t":"“Kad je on primio kraljevstvo i vratio se, naredi da mu dozovu one sluge kojima je predao novac da sazna što su zaradili.”"},{"v":16,"t":"“Pristupi prvi i reče: 'Gospodaru, tvoja mna donije deset mna.'"},{"v":17,"t":"Reče mu: 'Valjaš, slugo dobri! U najmanjem si bio vjeran, vladaj nad deset gradova!'"},{"v":18,"t":"Dođe i drugi govoreći: 'Mna je tvoja, gospodaru, donijela pet mna.'"},{"v":19,"t":"I tomu reče: 'I ti budi nad pet gradova!'”"},{"v":20,"t":"“Treći, opet dođe govoreći: 'Gospodaru, evo ti tvoje mne. Držao sam je pohranjenu u rupcu."},{"v":21,"t":"Bojao sam te se jer si čovjek strog: uzimaš što nisi pohranio, žanješ što nisi posijao.'”"},{"v":22,"t":"“Kaže mu: 'Iz tvojih te usta sudim, zli slugo! Znao si da sam čovjek strog, da uzimam što nisam pohranio i žanjem što nisam posijao?"},{"v":23,"t":"Zašto onda nisi uložio moj novac u novčarnicu? Ja bih ga po povratku podigao s dobitkom.'"},{"v":24,"t":"Nato reče nazočnima: 'Uzmite od njega mnu i dajte onomu koji ih ima deset.'"},{"v":25,"t":"Rekoše mu: 'Gospodaru, ta već ima deset mna!'"},{"v":26,"t":"Kažem vam: svakomu koji ima još će se dati, a od onoga koji nema oduzet će se i ono što ima."},{"v":27,"t":"A moje neprijatelje - one koji me ne htjedoše za kralja - dovedite ovamo i smaknite ih pred mojim očima!'”"},{"v":28,"t":"Rekavši to, nastavi put uzlazeći u Jeruzalem."},{"v":29,"t":"Kad se približi Betfagi i Betaniji, uz goru koja se zove Maslinska, posla dvojicu učenika"},{"v":30,"t":"govoreći: “Hajdete u selo pred vama. Čim uđete u nj, naći ćete privezano magare koje još nitko nije zajahao. Odriješite ga i dovedite."},{"v":31,"t":"Upita li vas tko: 'Zašto driješite?', ovako recite: 'Gospodinu treba.'”"},{"v":32,"t":"Oni koji bijahu poslani otiđoše i nađoše kako im bijaše rekao."},{"v":33,"t":"I dok su driješili magare, rekoše im gospodari: “Što driješite magare?”"},{"v":34,"t":"Oni odgovore: “Gospodinu treba.”"},{"v":35,"t":"I dovedoše ga Isusu i staviše svoje haljine na magare te posjednuše Isusa."},{"v":36,"t":"I kuda bi on prolazio, prostirali bi po putu svoje haljine."},{"v":37,"t":"A kad se već bio približio obronku Maslinske gore, sve ono mnoštvo učenika, puno radosti, poče iza glasa hvaliti Boga za sva silna djela što ih vidješe:"},{"v":38,"t":"“Blagoslovljen Kralj, Onaj koji dolazi u ime Gospodnje! Na nebu mir! Slava na visinama!”"},{"v":39,"t":"Nato mu neki farizeji iz mnoštva rekoše: “Učitelju, prekori svoje učenike.”"},{"v":40,"t":"On odgovori: “Kažem vam, ako ovi ušute, kamenje će vikati!”"},{"v":41,"t":"Kad se približi i ugleda grad, zaplaka nad njim"},{"v":42,"t":"govoreći: “O kad bi i ti u ovaj dan spoznao što je za tvoj mir!"},{"v":43,"t":"Ali sada je sakriveno tvojim očima. Doći će dani na tebe kad će te neprijatelji tvoji opkoliti opkopom, okružit će te i pritijesniti odasvud."},{"v":44,"t":"Smrskat će o zemlju tebe i djecu tvoju u tebi. I neće ostaviti u tebi ni kamena na kamenu zbog toga što nisi upoznao časa svoga pohođenja.”"},{"v":45,"t":"Ušavši u Hram, stane izgoniti prodavače."},{"v":46,"t":"Kaže im: “Pisano je: Dom moj bit će Dom molitve, a vi od njega načiniste pećinu razbojničku!”"},{"v":47,"t":"I danomice naučavaše u Hramu. A glavari su svećenički i pismoznanci tražili kako da ga pogube, a tako i prvaci narodni,"},{"v":48,"t":"ali nikako naći što da učine jer je sav narod visio o njegovoj riječi."}]},"20":{"hr":[{"v":1,"t":"Jednog dana dok je naučavao narod u Hramu i naviještao evanđelje, ispriječe se glavari svećenički i pismoznanci sa starješinama"},{"v":2,"t":"pa mu dobace: “Reci nam kojom vlašću to činiš ili tko ti dade tu vlast?”"},{"v":3,"t":"On odgovori: “Upitat ću i ja vas. Recite mi:"},{"v":4,"t":"krst Ivanov bijaše li od Neba ili od ljudi?”"},{"v":5,"t":"A oni smišljahu među sobom: “Reknemo li 'od Neba', odvratit će 'Zašto mu ne povjerovaste?'"},{"v":6,"t":"A reknemo li 'od ljudi', sav će nas narod kamenovati. Ta uvjeren je da je Ivan prorok.”"},{"v":7,"t":"I odgovore da ne znaju odakle."},{"v":8,"t":"I Isus reče njima: “Ni ja vama neću kazati kojom vlašću ovo činim.”"},{"v":9,"t":"Zatim uze narodu kazivati ovu prispodobu: “Čovjek posadi vinograd, iznajmi ga vinogradarima i otputova na dulje vrijeme.”"},{"v":10,"t":"“Kada dođe doba, posla slugu vinogradarima da mu dadnu od uroda vinogradskoga. No vinogradari ga istukoše i otposlaše praznih ruku."},{"v":11,"t":"Nato on posla drugoga slugu. Ali oni i toga istukoše, izružiše i otposlaše praznih ruku."},{"v":12,"t":"Posla i trećega. A oni i njega izraniše i izbaciše.”"},{"v":13,"t":"“Nato reče gospodar vinograda: 'Što da učinim? Poslat ću im sina svoga ljubljenoga. Njega će valjda poštovati.'"},{"v":14,"t":"Ali kada ga vinogradari ugledaju, stanu među sobom umovati: 'Ovo je baštinik. Ubijmo ga da baština bude naša.'"},{"v":15,"t":"Izbaciše ga iz vinograda i ubiše.” “Što će dakle učiniti s njima gospodar vinograda?"},{"v":16,"t":"Doći će i pogubiti te vinogradare i dati vinograd drugima.” Koji ga slušahu rekoše: “Bože sačuvaj!”"},{"v":17,"t":"A on ih ošinu pogledom i reče: “A što ono piše: Kamen što ga odbaciše graditelji postade kamen zaglavni?"},{"v":18,"t":"Tko god padne na taj kamen, smrskat će se, a na koga on padne, satrt će ga.”"},{"v":19,"t":"Pismoznanci i glavari svećenički gledahu da istog časa stave ruke na nj, ali se pobojaše naroda. Dobro razumješe da o njima kaza tu prispodobu."},{"v":20,"t":"Vrebajući na nj, poslaše uhode koji su se pravili pravednicima da ga uhvate u riječi pa da ga predaju oblasti i vlasti upraviteljevoj."},{"v":21,"t":"Upitaše ga dakle: “Učitelju, znamo da pravo zboriš i naučavaš te nisi pristran, nego po istini učiš putu Božjem."},{"v":22,"t":"Je li nam dopušteno dati porez caru ili nije?”"},{"v":23,"t":"Proničući njihovu lukavost, reče im:"},{"v":24,"t":"“Pokažite mi denar.” “Čiju ima sliku i natpis?”"},{"v":25,"t":"A oni će: “Carevu.” On im reče: “Stoga dajte caru carevo, a Bogu Božje.”"},{"v":26,"t":"I ne mogoše ga uhvatiti u riječi pred narodom, nego umuknuše zadivljeni njegovim odgovorom."},{"v":27,"t":"Pristupe mu neki od saduceja, koji niječu uskrsnuće. Upitaše ga:"},{"v":28,"t":"“Učitelju! Mojsije nam napisa: Umre li bez djece čiji brat koji imaše ženu, neka njegov brat uzme tu ženu te podigne porod bratu svomu."},{"v":29,"t":"Bijaše tako sedmero braće. Prvi se oženi i umrije bez djece."},{"v":30,"t":"Drugi uze njegovu ženu,"},{"v":31,"t":"onda treći; i tako redom sva sedmorica pomriješe ne ostavivši djece."},{"v":32,"t":"Naposljetku umrije i žena."},{"v":33,"t":"Kojemu će dakle od njih ta žena pripasti o uskrsnuću? Jer sedmorica su je imala za ženu.”"},{"v":34,"t":"Reče im Isus: “Djeca se ovog svijeta žene i udaju."},{"v":35,"t":"No oni koji se nađoše dostojni onog svijeta i uskrsnuća od mrtvih niti se žene niti udaju."},{"v":36,"t":"Zaista, ni umrijeti više ne mogu: anđelima su jednaki i sinovi su Božji jer su sinovi uskrsnuća.”"},{"v":37,"t":"“A da mrtvi ustaju, naznači i Mojsije kad u odlomku o grmu Gospodina zove Bogom Abrahamovim, Bogom Izakovim i Bogom Jakovljevim."},{"v":38,"t":"A nije on Bog mrtvih, nego živih. Ta svi njemu žive!”"},{"v":39,"t":"Neki pismoznanci primijete: “Učitelju! Dobro si rekao!”"},{"v":40,"t":"I nisu se više usuđivali upitati ga bilo što."},{"v":41,"t":"A on im reče: “Kako kažu da je Krist sin Davidov?"},{"v":42,"t":"Ta sam David veli u Knjizi psalama: Reče Gospod Gospodinu mojemu: 'Sjedi mi zdesna"},{"v":43,"t":"dok ne položim neprijatelje tvoje za podnožje nogama tvojim!'"},{"v":44,"t":"David ga dakle naziva Gospodinom. Kako mu je onda sin?”"},{"v":45,"t":"I pred svim narodom reče svojim učenicima:"},{"v":46,"t":"“Čuvajte se pismoznanaca, koji rado hodaju u dugim haljinama, vole pozdrave na trgovima, prva sjedala u sinagogama i pročelja na gozbama,"},{"v":47,"t":"proždiru kuće udovičke, još pod izlikom dugih molitava. Stići će ih to oštrija osuda.”"}]},"21":{"hr":[{"v":1,"t":"Pogleda i vidje kako bogataši bacaju u riznicu svoje darove."},{"v":2,"t":"A ugleda i neku ubogu udovicu kako baca onamo dva novčića."},{"v":3,"t":"I reče: “Uistinu, kažem vam: ova je sirota udovica ubacila više od sviju."},{"v":4,"t":"Svi su oni zapravo među darove ubacili od svog suviška, a ona je od svoje sirotinje ubacila sav žitak što ga imaše.”"},{"v":5,"t":"I dok su neki razgovarali o Hramu, kako ga resi divno kamenje i zavjetni darovi, reče:"},{"v":6,"t":"“Doći će dani u kojima se od ovoga što motrite neće ostaviti ni kamen na kamenu nerazvaljen.”"},{"v":7,"t":"Upitaše ga: “Učitelju, a kada će to biti? I na koji se znak to ima dogoditi?”"},{"v":8,"t":"A on reče: “Pazite, ne dajte se zavesti. Mnogi će doista doći u moje ime i govoriti: 'Ja sam' i: 'Vrijeme se približilo!' Ne idite za njima."},{"v":9,"t":"A kad čujete za ratove i pobune, ne prestrašite se. Doista treba da se to prije dogodi, ali to još nije odmah svršetak.”"},{"v":10,"t":"Tada im kaza: “Narod će ustati protiv naroda i kraljevstvo protiv kraljevstva."},{"v":11,"t":"I bit će velikih potresa i po raznim mjestima gladi i pošasti; bit će strahota i velikih znakova s neba.”"},{"v":12,"t":"“No prije svega toga podignut će na vas ruke i progoniti vas, predavati vas u sinagoge i tamnice. Vući će vas pred kraljeve i upravitelje zbog imena mojega."},{"v":13,"t":"Zadesit će vas to radi svjedočenja.”"},{"v":14,"t":"“Stoga uzmite k srcu: nemojte unaprijed smišljati obranu!"},{"v":15,"t":"Ta ja ću vam dati usta i mudrost kojoj se neće moći suprotstaviti niti oduprijeti nijedan vaš protivnik."},{"v":16,"t":"A predavat će vas čak i vaši roditelji i braća, rođaci i prijatelji. Neke će od vas i ubiti.”"},{"v":17,"t":"“Svi će vas zamrziti zbog imena mojega."},{"v":18,"t":"Ali ni vlas vam s glave neće propasti."},{"v":19,"t":"Svojom ćete se postojanošću spasiti.”"},{"v":20,"t":"“Kad ugledate da vojska opkoljuje Jeruzalem, tada znajte: približilo se njegovo opustošenje."},{"v":21,"t":"Koji se tada zateknu u Judeji, neka bježe u gore; a koji u Gradu, neka ga napuste; koji pak po poljima, neka se u nj ne vraćaju"},{"v":22,"t":"jer to su dani odmazde, da se ispuni sve što je pisano.”"},{"v":23,"t":"“Jao trudnicama i dojiljama u one dane jer bit će jad velik na zemlji i gnjev nad ovim narodom."},{"v":24,"t":"Padat će od oštrice mača, odvodit će ih kao roblje po svim narodima. I Jeruzalem će gaziti pogani sve dok se ne navrše vremena pogana.”"},{"v":25,"t":"“I bit će znaci na suncu, mjesecu i zvijezdama, a na zemlji bezizlazna tjeskoba naroda zbog huke mora i valovlja."},{"v":26,"t":"Izdisat će ljudi od straha i iščekivanja onoga što prijeti svijetu. Doista, sile će se nebeske poljuljati."},{"v":27,"t":"Tada će ugledati Sina Čovječjega gdje dolazi u oblaku s velikom moći i slavom."},{"v":28,"t":"Kad se sve to stane zbivati, uspravite se i podignite glave jer se približuje vaše otkupljenje.”"},{"v":29,"t":"I reče im prispodobu: “Pogledajte smokvu i sva stabla."},{"v":30,"t":"Kad već propupaju, i sami vidite i znate: blizu je već ljeto."},{"v":31,"t":"Tako i vi kad vidite da se to zbiva, znajte: blizu je kraljevstvo Božje."},{"v":32,"t":"Zaista, kažem vam, ne, neće uminuti naraštaj ovaj dok se sve ne zbude."},{"v":33,"t":"Nebo će i zemlja uminuti, ali moje riječi ne, neće uminuti.”"},{"v":34,"t":"“Pazite na se da vam srca ne otežaju u proždrljivosti, pijanstvu i u životnim brigama te vas iznenada ne zatekne onaj Dan"},{"v":35,"t":"jer će kao zamka nadoći na sve žitelje po svoj zemlji.”"},{"v":36,"t":"“Stoga budni budite i u svako doba molite da uzmognete umaći svemu tomu što se ima zbiti i stati pred Sina Čovječjega.”"},{"v":37,"t":"Danju je učio u Hramu, a noću bi izlazio i noćio na gori zvanoj Maslinska."},{"v":38,"t":"A sav bi narod rano hrlio k njemu u Hram da ga sluša."}]},"22":{"hr":[{"v":1,"t":"Bližio se Blagdan beskvasnih kruhova zvan Pasha."},{"v":2,"t":"Glavari svećenički i pismoznanci tražili su kako da Isusa smaknu jer se bojahu naroda."},{"v":3,"t":"A Sotona uđe u Judu zvanog Iškariotski koji bijaše iz broja dvanaestorice."},{"v":4,"t":"On ode i ugovori s glavarima svećeničkim i zapovjednicima kako da im ga preda."},{"v":5,"t":"Oni se povesele i ugovore da će mu dati novca."},{"v":6,"t":"On pristade. Otada je tražio priliku da im ga preda mimo naroda."},{"v":7,"t":"Kada dođe Dan beskvasnih kruhova, u koji je trebalo žrtvovati pashu,"},{"v":8,"t":"posla Isus Petra i Ivana i reče: “Hajdete, pripravite nam da blagujemo pashu.”"},{"v":9,"t":"Rekoše mu: “Gdje hoćeš da pripravimo?”"},{"v":10,"t":"On im reče: “Evo, čim uđete u grad, namjerit ćete se na čovjeka koji nosi krčag vode. Pođite za njim u kuću u koju uniđe"},{"v":11,"t":"i recite domaćinu te kuće: 'Učitelj veli: Gdje je svratište u kojem bih blagovao pashu sa svojim učenicima?'"},{"v":12,"t":"I on će vam pokazati na katu veliko blagovalište prostrto: ondje pripravite.”"},{"v":13,"t":"Oni odu, nađu kako im je rekao i priprave pashu."},{"v":14,"t":"Kada dođe čas, sjede Isus za stol i apostoli s njim."},{"v":15,"t":"I reče im: “Svom sam dušom čeznuo ovu pashu blagovati s vama prije svoje muke."},{"v":16,"t":"Jer kažem vam, neću je više blagovati dok se ona ne završi u kraljevstvu Božjem.”"},{"v":17,"t":"I uze čašu, zahvali i reče: “Uzmite je i razdijelite među sobom."},{"v":18,"t":"Jer kažem vam, ne, neću više piti od roda trsova dok kraljevstvo Božje ne dođe.”"},{"v":19,"t":"I uze kruh, zahvali, razlomi i dade im govoreći: “Ovo je tijelo moje koje se za vas predaje. Ovo činite meni na spomen.”"},{"v":20,"t":"Tako i čašu, pošto večeraše, govoreći: “Ova čaša novi je Savez u mojoj krvi koja se za vas prolijeva.”"},{"v":21,"t":"“A evo, ruka mog izdajice sa mnom je na stolu."},{"v":22,"t":"Sin Čovječji, istina, ide kako je određeno, ali jao čovjeku onomu koji ga predaje.”"},{"v":23,"t":"I oni se počeše ispitivati tko bi od njih mogao takvo što učiniti."},{"v":24,"t":"Uto nasta među njima prepirka tko bi od njih bio najveći."},{"v":25,"t":"A on im reče: “Kraljevi gospoduju svojim narodima i vlastodršci nazivaju sebe dobrotvorima."},{"v":26,"t":"Vi nemojte tako! Naprotiv, najveći među vama neka bude kao najmlađi; i predstojnik kao poslužitelj."},{"v":27,"t":"Ta tko je veći? Koji je za stolom ili koji poslužuje? Zar ne onaj koji je za stolom? A ja sam posred vas kao onaj koji poslužuje.”"},{"v":28,"t":"“Da, vi ste sa mnom ustrajali u mojim kušnjama."},{"v":29,"t":"Ja vam stoga u baštinu predajem kraljevstvo što ga je meni predao moj Otac:"},{"v":30,"t":"da jedete i pijete za mojim stolom u kraljevstvu mojemu i sjedite na prijestoljima sudeći dvanaest plemena Izraelovih.”"},{"v":31,"t":"“Šimune, Šimune, evo Sotona zaiska da vas prorešeta kao pšenicu."},{"v":32,"t":"Ali ja sam molio za tebe da ne malakše tvoja vjera. Pa kad k sebi dođeš, učvrsti svoju braću.”"},{"v":33,"t":"Petar mu reče: “Gospodine, s tobom sam spreman i u tamnicu i u smrt.”"},{"v":34,"t":"A Isus će mu: “Kažem ti, Petre, neće se danas oglasiti pijetao dok triput ne zatajiš da me poznaš.”"},{"v":35,"t":"I reče: “Kad sam vas poslao bez kese i bez torbe i bez sandala, je li vam što nedostajalo?” Oni odgovore: “Ništa.”"},{"v":36,"t":"Nato će im: “No sada tko ima kesu, neka je uzme! Isto tako i torbu! A koji nema, neka proda svoju haljinu i neka kupi sebi mač"},{"v":37,"t":"jer kažem vam, ono što je napisano treba se ispuniti na meni: Među zlikovce bi ubrojen. Uistinu, sve što se odnosi na mene ispunja se.”"},{"v":38,"t":"Oni mu rekoše: “Gospodine, evo ovdje dva mača!” Reče im: “Dosta je!”"},{"v":39,"t":"Tada iziđe te se po običaju zaputi na Maslinsku goru. Za njim pođoše i njegovi učenici."},{"v":40,"t":"Kada dođe onamo, reče im: “Molite da ne padnete u napast!”"},{"v":41,"t":"I otrgnu se od njih koliko bi se kamenom dobacilo, pade na koljena pa se molio:"},{"v":42,"t":"“Oče! Ako hoćeš, otkloni ovu čašu od mene. Ali ne moja volja, nego tvoja neka bude!”"},{"v":43,"t":"A ukaza mu se anđeo s neba koji ga ohrabri. A kad je bio u smrtnoj muci, usrdnije se molio."},{"v":44,"t":"I bijaše znoj njegov kao kaplje krvi koje su padale na zemlju."},{"v":45,"t":"Usta od molitve, dođe učenicima i nađe ih snene od žalosti"},{"v":46,"t":"pa im reče: “Što spavate? Ustanite! Molite da ne padnete u napast!”"},{"v":47,"t":"Dok je on još govorio, eto svjetine, a pred njom jedan od dvanaestorice, zvani Juda. On se približi Isusu da ga poljubi."},{"v":48,"t":"Isus mu reče: “Juda, poljupcem Sina Čovječjeg predaješ?”"},{"v":49,"t":"A oni oko njega, vidjevši što se zbiva, rekoše: “Gospodine, da udarimo mačem?”"},{"v":50,"t":"I jedan od njih udari slugu velikoga svećenika i odsiječe mu desno uho."},{"v":51,"t":"Isus odgovori: “Pustite! Dosta!” Onda se dotače uha i zacijeli ga."},{"v":52,"t":"Nato Isus reče onima koji se digoše na nj, glavarima svećeničkim, zapovjednicima hramskim i starješinama: “Kao na razbojnika iziđoste s mačevima i toljagama!"},{"v":53,"t":"Danomice bijah s vama u Hramu i ne digoste ruke na me. No ovo je vaš čas i vlast Tmina.”"},{"v":54,"t":"Uhvatiše ga dakle, odvedoše i uvedoše u dom velikoga svećenika. Petar je išao za njim izdaleka."},{"v":55,"t":"A posred dvorišta naložiše vatru i posjedaše uokolo. Među njih sjedne Petar."},{"v":56,"t":"Ugleda ga neka sluškinja gdje sjedi kraj vatre, oštro ga pogleda i reče: “I ovaj bijaše s njim!”"},{"v":57,"t":"A on zanijeka: “Ne znam ga, ženo!”"},{"v":58,"t":"Malo zatim opazi ga netko drugi i reče: “I ti si od njih!” A Petar reče: “Čovječe, nisam!”"},{"v":59,"t":"I nakon otprilike jedne ure drugi neki navaljivaše: “Doista, i ovaj bijaše s njim! Ta Galilejac je!”"},{"v":60,"t":"A Petar će: “Čovječe, ne znam što govoriš!” I umah, dok je on još govorio, oglasi se pijetao."},{"v":61,"t":"Gospodin se obazre i upre pogled u Petra, a Petar se spomenu riječi Gospodinove, kako mu ono reče: “Prije nego se danas pijetao oglasi, zatajit ćeš me tri puta.”"},{"v":62,"t":"I iziđe te gorko zaplaka."},{"v":63,"t":"A ljudi koji su Isusa čuvali udarajući ga poigravali se njime"},{"v":64,"t":"i zastirući mu lice, zapitkivali ga: “Proreci tko te udario!”"},{"v":65,"t":"I mnogim se drugim pogrdama nabacivali na nj."},{"v":66,"t":"A kad se razdanilo, sabra se starješinstvo narodno, glavari svećenički i pismoznanci te ga dovedoše pred svoje Vijeće"},{"v":67,"t":"i rekoše: “Ako si ti Krist, reci nam!” A on će im: “Ako vam reknem, nećete vjerovati;"},{"v":68,"t":"ako vas zapitam, nećete odgovoriti."},{"v":69,"t":"No od sada će Sin Čovječji sjedjeti zdesna Sile Božje.”"},{"v":70,"t":"Nato svi rekoše: “Ti si, dakle, Sin Božji!” On im reče: “Vi velite! Ja jesam!”"},{"v":71,"t":"Nato će oni: “Što nam još svjedočanstvo treba? Ta sami smo čuli iz njegovih usta!”"}]},"23":{"hr":[{"v":1,"t":"I ustade sva ona svjetina. Odvedoše ga Pilatu"},{"v":2,"t":"i stadoše ga optuživati: “Ovoga nađosmo kako zavodi naš narod i brani davati caru porez te za sebe tvrdi da je Krist, kralj.”"},{"v":3,"t":"Pilat ga upita: “Ti li si kralj židovski?” On mu odgovori: “Ti kažeš!”"},{"v":4,"t":"Tada Pilat reče glavarima svećeničkim i svjetini: “Nikakve krivnje ne nalazim na ovom čovjeku!”"},{"v":5,"t":"No oni navaljivahu: “Buni narod naučavajući po svoj Judeji, počevši od Galileje pa dovde!”"},{"v":6,"t":"Čuvši to, Pilat propita da li je taj čovjek Galilejac."},{"v":7,"t":"Saznavši da je iz oblasti Herodove, posla ga Herodu, koji i sam bijaše onih dana u Jeruzalemu."},{"v":8,"t":"A kad Herod ugleda Isusa, veoma se obradova jer ga je već odavna želo vidjeti zbog onoga što je o njemu slušao te se nadao od njega vidjeti koje čudo."},{"v":9,"t":"Postavljao mu je mnoga pitanja, ali mu Isus uopće nije odgovarao."},{"v":10,"t":"A stajahu ondje i glavari svećenički i pismoznanci optužujući ga žestoko."},{"v":11,"t":"Herod ga zajedno sa svojom vojskom prezre i ismija: obuče ga u bijelu haljinu i posla natrag Pilatu."},{"v":12,"t":"Onoga se dana Herod i Pilat sprijateljiše, jer prije bijahu neprijatelji."},{"v":13,"t":"A Pilat dade sazvati glavare svećeničke, vijećnike i narod"},{"v":14,"t":"te im reče: “Doveli ste mi ovoga čovjeka kao da buni narod. Ja ga evo ispitah pred vama pa ne nađoh na njemu ni jedne krivice za koju ga optužujete."},{"v":15,"t":"A ni Herod jer ga posla natrag nama. Evo, on nije počinio ništa čime bi zaslužio smrt."},{"v":16,"t":"Kaznit ću ga dakle i pustiti.”"},{"v":17,"t":"#"},{"v":18,"t":"I povikaše svi uglas: “Smakni ovoga, a pusti nam Barabu!”"},{"v":19,"t":"A taj bijaše bačen u tamnicu zbog neke pobune u gradu i ubojstva."},{"v":20,"t":"Pilat im stoga ponovno progovori hoteći osloboditi Isusa."},{"v":21,"t":"Ali oni vikahu: “Raspni, raspni ga!”"},{"v":22,"t":"On im treći put reče: “Ta što je on zla učinio? Ne nađoh na njemu smrtne krivice. Kaznit ću ga dakle i pustiti.”"},{"v":23,"t":"Ali oni navaljivahu iza glasa ištući da se razapne. I vika im bivala sve jača."},{"v":24,"t":"Pilat presudi da im bude što ištu."},{"v":25,"t":"Pusti onoga koji zbog pobune i ubojstva bijaše bačen u tamnicu, koga su iskali, a Isusa preda njima na volju."},{"v":26,"t":"Kad ga odvedoše, uhvatiše nekog Šimuna Cirenca koji je dolazio s polja i stave na nj križ da ga nosi za Isusom."},{"v":27,"t":"Za njim je išlo silno mnoštvo svijeta, napose žena, koje su plakale i naricale za njim."},{"v":28,"t":"Isus se okrenu prema njima pa im reče: “Kćeri Jeruzalemske, ne plačite nada mnom, nego plačite nad sobom i nad djecom svojom."},{"v":29,"t":"Jer evo idu dani kad će se govoriti: 'Blago nerotkinjama, utrobama koje ne rodiše i sisama koje ne dojiše.'"},{"v":30,"t":"Tad će početi govoriti gorama: 'Padnite na nas!' i bregovima: 'Pokrijte nas!'"},{"v":31,"t":"Jer ako se tako postupa sa zelenim stablom, što li će biti sa suhim?”"},{"v":32,"t":"A vodili su i drugu dvojicu, zločince, da ih s njime pogube."},{"v":33,"t":"I kada dođoše na mjesto zvano Lubanja, ondje razapeše njega i te zločince, jednoga zdesna, drugoga slijeva."},{"v":34,"t":"A Isus je govorio: “Oče, oprosti im, ne znaju što čine!” I razdijeliše među se haljine njegove bacivši kocke."},{"v":35,"t":"Stajao je ondje narod i promatrao. A podrugivali se i glavari govoreći: “Druge je spasio, neka spasi sam sebe ako je on Krist Božji, Izabranik!”"},{"v":36,"t":"Izrugivali ga i vojnici, prilazili mu i nudili ga octom"},{"v":37,"t":"govoreći: “Ako si ti kralj židovski, spasi sam sebe!”"},{"v":38,"t":"A bijaše i natpis ponad njega: “Ovo je kralj židovski.”"},{"v":39,"t":"Jedan ga je od obješenih zločinaca pogrđivao: “Nisi li ti Krist? Spasi sebe i nas!”"},{"v":40,"t":"A drugi ovoga prekoravaše: “Zar se ne bojiš Boga ni ti, koji si pod istom osudom?"},{"v":41,"t":"Ali mi po pravdi jer primamo što smo djelima zaslužili, a on - on ništa opako ne učini.”"},{"v":42,"t":"Onda reče: “Isuse, sjeti me se kada dođeš u kraljevstvo svoje.”"},{"v":43,"t":"A on će mu: “Zaista ti kažem: danas ćeš biti sa mnom u raju!”"},{"v":44,"t":"Bijaše već oko šeste ure kad nasta tama po svoj zemlji - sve do ure devete,"},{"v":45,"t":"jer sunce pomrča, a hramska se zavjesa razdrije po sredini."},{"v":46,"t":"I povika Isus iza glasa: “Oče, u ruke tvoje predajem duh svoj!” To rekavši, izdahnu."},{"v":47,"t":"Kad satnik vidje što se zbiva, stane slaviti Boga: “Zbilja, čovjek ovaj bijaše pravednik!”"},{"v":48,"t":"I kad je sav svijet koji se zgrnuo na taj prizor vidio što se zbiva, vraćao se bijući se u prsa."},{"v":49,"t":"Stajahu podalje i gledahu to svi znanci njegovi i žene koje su za njim išle iz Galileje."},{"v":50,"t":"I dođe čovjek imenom Josip, vijećnik, čovjek čestit i pravedan;"},{"v":51,"t":"on ne privoli njihovoj odluci i postupku. Bijaše iz Arimateje, grada judejskoga i iščekivaše kraljevstvo Božje."},{"v":52,"t":"Taj dakle pristupi Pilatu i zaiska tijelo Isusovo."},{"v":53,"t":"Zatim ga skinu, povi u platno i položi u grob isklesan u koji još ne bijaše nitko položen."},{"v":54,"t":"Bijaše dan Priprave; subota je svitala."},{"v":55,"t":"A pratile to žene koje su s Isusom došle iz Galileje: motrile grob i kako je položeno tijelo njegovo."},{"v":56,"t":"Zatim se vrate i priprave miomirise i pomasti. U subotu mirovahu po propisu."}]},"24":{"hr":[{"v":1,"t":"Prvoga dana u tjednu, veoma rano, dođoše one na grob s miomirisima što ih pripraviše."},{"v":2,"t":"Kamen nađoše otkotrljan od groba."},{"v":3,"t":"Uđoše, ali ne nađoše tijela Gospodina Isusa."},{"v":4,"t":"I dok su stajale zbunjene nad tim, gle, dva čovjeka u blistavoj odjeći stadoše do njih."},{"v":5,"t":"Zastrašene obore lica k zemlji, a oni će im: “Što tražite Živoga među mrtvima?"},{"v":6,"t":"Nije ovdje, nego uskrsnu! Sjetite se kako vam je govorio dok je još bio u Galileji:"},{"v":7,"t":"'Treba da Sin Čovječji bude predan u ruke grešnika, i raspet, i treći dan da ustane.'”"},{"v":8,"t":"I sjetiše se one riječi njegovih,"},{"v":9,"t":"vratiše se s groba te javiše sve to jedanaestorici i svima drugima."},{"v":10,"t":"A bile su to: Marija Magdalena, Ivana i Marija Jakovljeva. I ostale zajedno s njima govorahu to apostolima,"},{"v":11,"t":"ali njima se te riječi pričiniše kao tlapnja, te im ne vjerovahu."},{"v":12,"t":"A Petar usta i potrča na grob. Sagnuvši se, opazi samo povoje. I vrati se kući čudeći se tome što se zbilo."},{"v":13,"t":"I gle, dvojica su od njih toga istog dana putovala u selo koje se zove Emaus, udaljeno od Jeruzalema šezdeset stadija."},{"v":14,"t":"Razgovarahu međusobno o svemu što se dogodilo."},{"v":15,"t":"I dok su tako razgovarali i raspravljali, približi im se Isus i pođe s njima."},{"v":16,"t":"Ali prepoznati ga - bijaše uskraćeno njihovim očima."},{"v":17,"t":"On ih upita: “Što to putem pretresate među sobom?” Oni se snuždeni zaustave"},{"v":18,"t":"te mu jedan od njih, imenom Kleofa, odgovori: “Zar si ti jedini stranac u Jeruzalemu te ne znaš što se u njemu dogodilo ovih dana?”"},{"v":19,"t":"A on će: “Što to?” Odgovore mu: “Pa ono s Isusom Nazarećaninom, koji bijaše prorok - silan na djelu i na riječi pred Bogom i svim narodom:"},{"v":20,"t":"kako su ga glavari svećenički i vijećnici naši predali da bude osuđen na smrt te ga razapeli."},{"v":21,"t":"A mi se nadasmo da je on onaj koji ima otkupiti Izraela. Ali osim svega toga ovo je već treći dan što se to dogodilo."},{"v":22,"t":"A zbuniše nas i žene neke od naših: u praskozorje bijahu na grobu,"},{"v":23,"t":"ali nisu našle njegova tijela pa dođoše te rekoše da su im se ukazali anđeli koji su rekli da je on živ."},{"v":24,"t":"Odoše nato i neki naši na grob i nađoše kako žene rekoše, ali njega ne vidješe.”"},{"v":25,"t":"A on će im: “O bezumni i srca spora da vjerujete što god su proroci navijestili!"},{"v":26,"t":"Nije li trebalo da Krist sve to pretrpi te uđe u svoju slavu?”"},{"v":27,"t":"Počevši tada od Mojsija i svih proroka, protumači im što u svim Pismima ima o njemu."},{"v":28,"t":"Uto se približe selu kamo su išli, a on kao da htjede dalje."},{"v":29,"t":"No oni navaljivahu: “Ostani s nama jer zamalo će večer i dan je na izmaku!” I uniđe da ostane s njima."},{"v":30,"t":"Dok bijaše s njima za stolom, uze kruh, izreče blagoslov, razlomi te im davaše."},{"v":31,"t":"Uto im se otvore oči te ga prepoznaše, a on im iščeznu s očiju."},{"v":32,"t":"Tada rekoše jedan drugome: “Nije li gorjelo srce u nama dok nam je putem govorio, dok nam je otkrivao Pisma?”"},{"v":33,"t":"U isti se čas digoše i vratiše u Jeruzalem. Nađoše okupljenu jedanaestoricu i one koji bijahu s njima."},{"v":34,"t":"Oni im rekoše: “Doista uskrsnu Gospodin i ukaza se Šimunu!”"},{"v":35,"t":"Nato oni pripovjede ono s puta i kako ga prepoznaše u lomljenju kruha."},{"v":36,"t":"Dok su oni o tom razgovarali, stane Isus posred njih i reče im: “Mir vama!”"},{"v":37,"t":"Oni, zbunjeni i prestrašeni, pomisliše da vide duha."},{"v":38,"t":"Reče im Isus: “Zašto se prepadoste? Zašto vam sumnje obuzimaju srce?"},{"v":39,"t":"Pogledajte ruke moje i noge! Ta ja sam! Opipajte me i vidite jer duh tijela ni kostiju nema kao što vidite da ja imam.”"},{"v":40,"t":"Rekavši to, pokaza im ruke i noge."},{"v":41,"t":"I dok oni od radosti još nisu vjerovali, nego se čudom čudili, on im reče: “Imate li ovdje što za jelo?”"},{"v":42,"t":"Oni mu pruže komad pečene ribe."},{"v":43,"t":"On uzme i pred njima pojede."},{"v":44,"t":"Nato im reče: “To je ono što sam vam govorio dok sam još bio s vama: treba da se ispuni sve što je u Mojsijevu Zakonu, u Prorocima i Psalmima o meni napisano.”"},{"v":45,"t":"Tada im otvori pamet da razumiju Pisma"},{"v":46,"t":"te im reče: “Ovako je pisano: 'Krist će trpjeti i treći dan ustati od mrtvih,"},{"v":47,"t":"i u njegovo će se ime propovijedati obraćenje i otpuštenje grijeha po svim narodima počevši od Jeruzalema.'"},{"v":48,"t":"Vi ste tomu svjedoci."},{"v":49,"t":"I evo, ja šaljem na vas Obećanje Oca svojega. Ostanite zato u gradu dok se ne obučete u Silu odozgor.”"},{"v":50,"t":"Zatim ih izvede do Betanije, podiže ruke pa ih blagoslovi."},{"v":51,"t":"I dok ih blagoslivljaše, rasta se od njih i uznesen bi na nebo."},{"v":52,"t":"Oni mu se ničice poklone pa se s velikom radosti vrate u Jeruzalem"},{"v":53,"t":"te sve vrijeme u Hramu blagoslivljahu Boga."}]}},"JHN":{"1":{"hr":[{"v":1,"t":"U početku bijaše Riječ i Riječ bijaše u Boga i Riječ bijaše Bog."},{"v":2,"t":"Ona bijaše u početku u Boga."},{"v":3,"t":"Sve postade po njoj i bez nje ne postade ništa. Svemu što postade"},{"v":4,"t":"u njoj bijaše život i život bijaše ljudima svjetlo;"},{"v":5,"t":"i svjetlo u tami svijetli i tama ga ne obuze."},{"v":6,"t":"Bi čovjek poslan od Boga, ime mu Ivan."},{"v":7,"t":"On dođe kao svjedok da posvjedoči za Svjetlo da svi vjeruju po njemu."},{"v":8,"t":"Ne bijaše on Svjetlo, nego - da posvjedoči za Svjetlo."},{"v":9,"t":"Svjetlo istinsko koje prosvjetljuje svakog čovjeka dođe na svijet;"},{"v":10,"t":"bijaše na svijetu i svijet po njemu posta i svijet ga ne upozna."},{"v":11,"t":"K svojima dođe i njegovi ga ne primiše."},{"v":12,"t":"A onima koji ga primiše podade moć da postanu djeca Božja: onima koji vjeruju u njegovo ime,"},{"v":13,"t":"koji su rođeni ne od krvi, ni od volje tjelesne, ni od volje muževlje, nego - od Boga."},{"v":14,"t":"I Riječ tijelom postade i nastani se među nama i vidjesmo slavu njegovu - slavu koju ima kao Jedinorođenac od Oca - pun milosti i istine."},{"v":15,"t":"Ivan svjedoči za njega. Viče: “To je onaj o kojem rekoh: koji za mnom dolazi, preda mnom je jer bijaše prije mene!”"},{"v":16,"t":"Doista, od punine njegove svi mi primismo, i to milost na milost."},{"v":17,"t":"Uistinu, Zakon bijaše dan po Mojsiju, a milost i istina nasta po Isusu Kristu."},{"v":18,"t":"Boga nitko nikada ne vidje: Jedinorođenac - Bog - koji je u krilu Očevu, on ga obznani."},{"v":19,"t":"A evo svjedočanstva Ivanova. Kad su Židovi iz Jeruzalema poslali k njemu svećenike i levite da ga upitaju: “Tko si ti?”,"},{"v":20,"t":"on prizna; ne zanijeka, nego prizna: “Ja nisam Krist.”"},{"v":21,"t":"Upitaše ga nato: “Što dakle? Jesi li Ilija?” Odgovori: “Nisam.” “Jesi li Prorok?” Odgovori: “Ne.”"},{"v":22,"t":"Tada mu rekoše: “Pa tko si da dadnemo odgovor onima koji su nas poslali? Što kažeš sam o sebi?”"},{"v":23,"t":"On odgovori: “Ja sam glas koji viče u pustinji: Poravnite put Gospodnji! - kako reče prorok Izaija.”"},{"v":24,"t":"A neki izaslanici bijahu farizeji."},{"v":25,"t":"Oni prihvatiše riječ i upitaše ga: “Zašto onda krstiš kad nisi Krist, ni Ilija, ni Prorok?”"},{"v":26,"t":"Ivan im odgovori: “Ja krstim vodom. Među vama stoji koga vi ne poznate -"},{"v":27,"t":"onaj koji za mnom dolazi, komu ja nisam dostojan odriješiti remenje na obući.”"},{"v":28,"t":"To se dogodilo u Betaniji s onu stranu Jordana, gdje je Ivan krstio."},{"v":29,"t":"Sutradan Ivan ugleda Isusa gdje dolazi k njemu pa reče: “Evo Jaganjca Božjega koji odnosi grijeh svijeta!”"},{"v":30,"t":"To je onaj o kojem rekoh: Za mnom dolazi čovjek koji je preda mnom jer bijaše prije mene!”"},{"v":31,"t":"“Ja ga nisam poznavao, ali baš zato dođoh i krstim vodom da se on očituje Izraelu.”"},{"v":32,"t":"I posvjedoči Ivan: “Promatrao sam Duha gdje s neba silazi kao golub i ostaje na njemu."},{"v":33,"t":"Njega ja nisam poznavao, ali onaj koji me posla vodom krstiti reče mi: 'Na koga vidiš da Duh silazi i ostaje na njemu, to je onaj koji krsti Duhom Svetim.'"},{"v":34,"t":"I ja sam to vidio i svjedočim: on je Sin Božji.”"},{"v":35,"t":"Sutradan opet stajaše Ivan s dvojicom svojih učenika."},{"v":36,"t":"Ugleda Isusa koji je onuda prolazio i reče: “Evo Jaganjca Božjega!”"},{"v":37,"t":"Te njegove riječi čula ona dva njegova učenika pa pođoše za Isusom."},{"v":38,"t":"Isus se obazre i vidjevši da idu za njim, upita ih: “Što tražite?” Oni mu rekoše: “Rabbi” - što znači: “Učitelju - gdje stanuješ?”"},{"v":39,"t":"Reče im: “Dođite i vidjet ćete.” Pođoše dakle i vidješe gdje stanuje i ostadoše kod njega onaj dan. Bila je otprilike deseta ura."},{"v":40,"t":"Jedan od one dvojice, koji su čuvši Ivana pošli za Isusom, bijaše Andrija, brat Šimuna Petra."},{"v":41,"t":"On najprije nađe svoga brata Šimuna te će mu: “Našli smo Mesiju!” - što znači “Krist - Pomazanik”."},{"v":42,"t":"Dovede ga Isusu, a Isus ga pogleda i reče: “Ti si Šimun, sin Ivanov! Zvat ćeš se Kefa!” - što znači “Petar - Stijena”."},{"v":43,"t":"Sutradan naumi Isus poći u Galileju. Nađe Filipa i reče mu: “Pođi za mnom!”"},{"v":44,"t":"Filip je bio iz Betsaide, iz grada Andrijina i Petrova."},{"v":45,"t":"Filip nađe Natanaela i javi mu: “Našli smo onoga o kome je pisao Mojsije u Zakonu i Proroci: Isusa, sina Josipova, iz Nazareta.”"},{"v":46,"t":"Reče mu Natanael: “Iz Nazareta da može biti što dobro?” Kaže mu Filip: “Dođi i vidi.”"},{"v":47,"t":"Kad Isus ugleda gdje Natanael dolazi k njemu, reče za njega: “Evo istinitog Izraelca u kojem nema prijevare!”"},{"v":48,"t":"Kaže mu Natanael: “Odakle me poznaješ?” Odgovori mu Isus: “Vidjeh te prije negoli te Filip pozva, dok si bio pod smokvom.”"},{"v":49,"t":"Nato će mu Natanael: “Učitelju, ti si Sin Božji! Ti kralj si Izraelov!”"},{"v":50,"t":"Odgovori mu Isus: “Stoga što ti rekoh: 'Vidjeh te pod smokvom', vjeruješ. I više ćeš od toga vidjeti!”"},{"v":51,"t":"I nadoda: “Zaista, zaista, kažem vam: gledat ćete otvoreno nebo i anđele Božje gdje uzlaze i silaze nad Sina Čovječjega.”"}]},"2":{"hr":[{"v":1,"t":"Trećeg dana bijaše svadba u Kani Galilejskoj. Bila ondje Isusova majka."},{"v":2,"t":"Na svadbu bijaše pozvan i Isus i njegovi učenici."},{"v":3,"t":"Kad ponesta vina, Isusu će njegova majka: “Vina nemaju.”"},{"v":4,"t":"Kaže joj Isus: “Ženo, što ja imam s tobom? Još nije došao moj čas!”"},{"v":5,"t":"Nato će njegova mati poslužiteljima: “Što god vam rekne, učinite!”"},{"v":6,"t":"A bijaše ondje Židovima za čišćenje šest kamenih posuda od po dvije do tri mjere."},{"v":7,"t":"Kaže Isus poslužiteljima: “Napunite posude vodom!” I napune ih do vrha."},{"v":8,"t":"Tada im reče: “Zagrabite sada i nosite ravnatelju stola.” Oni odnesu."},{"v":9,"t":"Kad okusi vodu što posta vinom, a nije znao odakle je - znale su sluge koje zagrabiše vodu - ravnatelj stola pozove zaručnika"},{"v":10,"t":"i kaže mu: “Svaki čovjek stavlja na stol najprije dobro vino, a kad se ponapiju, gore. Ti si čuvao dobro vino sve do sada.”"},{"v":11,"t":"Tako, u Kani Galilejskoj, učini Isus prvo znamenje i objavi svoju slavu te povjerovaše u njega njegovi učenici."},{"v":12,"t":"Nakon toga siđe sa svojom majkom, s braćom i sa svojim učenicima u Kafarnaum. Ondje ostadoše nekoliko dana."},{"v":13,"t":"Blizu bijaše židovska Pasha. Stoga Isus uziđe u Jeruzalem."},{"v":14,"t":"U Hramu nađe prodavače volova, ovaca i golubova i mjenjače gdje sjede."},{"v":15,"t":"I načini bič od užeta te ih sve istjera iz Hrama zajedno s ovcama i volovima. Mjenjačima rasu novac i stolove isprevrta,"},{"v":16,"t":"a prodavačima golubova reče: “Nosite to odavde i ne činite od kuće Oca mojega kuću trgovačku.”"},{"v":17,"t":"Prisjetiše se njegovi učenici da je pisano: Izjeda me revnost za Dom tvoj."},{"v":18,"t":"Nato se umiješaju Židovi i upitaju ga: “Koje nam znamenje možeš pokazati da to smiješ činiti?”"},{"v":19,"t":"Odgovori im Isus: “Razvalite ovaj hram i ja ću ga u tri dana podići.”"},{"v":20,"t":"Rekoše mu nato Židovi: “Četrdeset i šest godina gradio se ovaj Hram, a ti da ćeš ga u tri dana podići?”"},{"v":21,"t":"No on je govorio o hramu svoga tijela."},{"v":22,"t":"Pošto uskrsnu od mrtvih, prisjetiše se njegovi učenici da je to htio reći te povjerovaše Pismu i besjedi koju Isus reče."},{"v":23,"t":"Dok je boravio u Jeruzalemu o blagdanu Pashe, mnogi povjerovaše u njegovo ime promatrajući znamenja koja je činio."},{"v":24,"t":"No sam se Isus njima nije povjeravao jer ih je sve dobro poznavao"},{"v":25,"t":"i nije trebalo da mu tko daje svjedočanstvo o čovjeku: ta sam je dobro znao što je u čovjeku."}]},"3":{"hr":[{"v":1,"t":"Bijaše među farizejima čovjek imenom Nikodem, ugledan Židov."},{"v":2,"t":"On dođe Isusu obnoć i reče mu: “Rabbi, znamo da si od Boga došao kao učitelj jer nitko ne može činiti znamenja kakva ti činiš ako Bog nije s njime.”"},{"v":3,"t":"Odgovori mu Isus: “Zaista, zaista, kažem ti: tko se ne rodi nanovo, odozgor, ne može vidjeti kraljevstva Božjega!”"},{"v":4,"t":"Kaže mu Nikodem: “Kako se čovjek može roditi kad je star? Zar može po drugi put ući u utrobu majke svoje i roditi se?”"},{"v":5,"t":"Odgovori Isus: “Zaista, zaista, kažem ti: ako se tko ne rodi iz vode i Duha, ne može ući u kraljevstvo Božje."},{"v":6,"t":"Što je od tijela rođeno, tijelo je; i što je od Duha rođeno, duh je."},{"v":7,"t":"Ne čudi se što ti rekoh: 'Treba da se rodite nanovo, odozgor.'"},{"v":8,"t":"Vjetar puše gdje hoće; čuješ mu šum, a ne znaš odakle dolazi i kamo ide. Tako je sa svakim koji je rođen od Duha.”"},{"v":9,"t":"Upita ga Nikodem: “Kako se to može zbiti?”"},{"v":10,"t":"Odgovori mu Isus: “Ti si učitelj u Izraelu pa to da ne razumiješ?"},{"v":11,"t":"Zaista, zaista, kažem ti: govorimo što znamo, svjedočimo za ono što vidjesmo, ali svjedočanstva našega ne primate."},{"v":12,"t":"Ako vam rekoh zemaljsko pa ne vjerujete, kako ćete vjerovati kad vam budem govorio nebesko?"},{"v":13,"t":"Nitko nije uzašao na nebo doli onaj koji siđe s neba, Sin Čovječji."},{"v":14,"t":"I kao što je Mojsije podigao zmiju u pustinji tako ima biti podignut Sin Čovječji"},{"v":15,"t":"da svaki koji vjeruje u njemu ima život vječni."},{"v":16,"t":"Uistinu, Bog je tako ljubio svijet te je dao svoga Sina Jedinorođenca da nijedan koji u njega vjeruje ne propadne, nego da ima život vječni."},{"v":17,"t":"Ta Bog nije poslao Sina na svijet da sudi svijetu, nego da se svijet spasi po njemu."},{"v":18,"t":"Tko vjeruje u njega, ne osuđuje se; a tko ne vjeruje, već je osuđen što nije vjerovao u ime jedinorođenoga Sina Božjega."},{"v":19,"t":"A ovo je taj sud: Svjetlost je došla na svijet, ali ljudi su više ljubili tamu nego svjetlost jer djela im bijahu zla."},{"v":20,"t":"Uistinu, tko god čini zlo, mrzi svjetlost i ne dolazi k svjetlosti da se ne razotkriju djela njegova;"},{"v":21,"t":"a tko čini istinu, dolazi k svjetlosti nek bude bjelodano da su djela njegova u Bogu učinjena.”"},{"v":22,"t":"Poslije toga ode Isus sa svojim učenicima u Judejsku zemlju. Tu je boravio s njima i krstio."},{"v":23,"t":"A krstio je i Ivan, u Enonu blizu Salima, jer ondje bijaše mnogo vode. Ljudi su dolazili i krstili se."},{"v":24,"t":"Jer Ivan još nije bio bačen u tamnicu."},{"v":25,"t":"Između Ivanovih učenika i nekog Židova nastade tako prepirka o čišćenju."},{"v":26,"t":"Dođoše Ivanu i rekoše mu: “Učitelju, onaj koji s tobom bijaše s onu stranu Jordana i za kojega si ti svjedočio - on eno krsti i svi hrle k njemu.”"},{"v":27,"t":"Ivan odgovori: “Nitko ne može sebi uzeti ništa ako mu nije dano s neba."},{"v":28,"t":"Vi ste mi sami svjedoci da sam rekao: 'Nisam ja Krist, nego poslan sam pred njim.'"},{"v":29,"t":"Tko ima zaručnicu, zaručnik je. A prijatelj zaručnikov, koji stoji uza nj i sluša ga, klikće od radosti na glas zaručnikov. Ta se moja radost upravo ispunila."},{"v":30,"t":"On treba da raste, a ja da se umanjujem."},{"v":31,"t":"Tko odozgor dolazi, on je iznad sviju; tko je sa zemlje, zemaljski je i zemaljski govori. Tko dolazi s neba, on je iznad sviju:"},{"v":32,"t":"što je vidio i čuo - za to svjedoči, a svjedočanstva njegova nitko ne prima."},{"v":33,"t":"Tko primi njegovo svjedočanstvo, potvrđuje da je Bog istinit."},{"v":34,"t":"Uistinu, onaj koga Bog posla Božje riječi govori jer Bog Duha ne daje na mjeru."},{"v":35,"t":"Otac ljubi Sina i sve je predao u ruku njegovu."},{"v":36,"t":"Tko vjeruje u Sina, ima vječni život; a tko neće da vjeruje u Sina, neće vidjeti života; gnjev Božji ostaje na njemu.”"}]},"4":{"hr":[{"v":1,"t":"Kad Gospodin dozna da su farizeji dočuli kako on, Isus, okuplja i krsti više učenika nego Ivan -"},{"v":2,"t":"iako zapravo nije krstio sam Isus, nego njegovi učenici -"},{"v":3,"t":"ode iz Judeje i ponovno se vrati u Galileju."},{"v":4,"t":"Morao je proći kroza Samariju."},{"v":5,"t":"Dođe dakle u samarijski grad koji se zove Sihar, blizu imanja što ga Jakov dade svojemu sinu Josipu."},{"v":6,"t":"Ondje bijaše zdenac Jakovljev. Isus je umoran od puta sjedio na zdencu. Bila je otprilike šesta ura."},{"v":7,"t":"Dođe neka žena Samarijanka zahvatiti vode. Kaže joj Isus: “Daj mi piti!”"},{"v":8,"t":"Njegovi učenici bijahu otišli u grad kupiti hrane."},{"v":9,"t":"Kaže mu na to Samarijanka: “Kako ti, Židov, išteš piti od mene, Samarijanke?” Jer Židovi se ne druže sa Samarijancima."},{"v":10,"t":"Isus joj odgovori: “Kad bi znala dar Božji i tko je onaj koji ti veli: 'Daj mi piti', ti bi u njega zaiskala i on bi ti dao vode žive.”"},{"v":11,"t":"Odvrati mu žena: “Gospodine, ta nemaš ni čime bi zahvatio, a zdenac je dubok. Otkuda ti dakle voda živa?"},{"v":12,"t":"Zar si ti možda veći od oca našeg Jakova koji nam dade ovaj zdenac i sam je iz njega pio, a i sinovi njegovi i stada njegova?”"},{"v":13,"t":"Odgovori joj Isus: “Tko god pije ove vode, opet će ožednjeti."},{"v":14,"t":"A tko bude pio vode koju ću mu ja dati, ne, neće ožednjeti nikada: voda koju ću mu ja dati postat će u njemu izvorom vode koja struji u život vječni.”"},{"v":15,"t":"Kaže mu žena: “Gospodine, daj mi te vode da ne žeđam i da ne moram dolaziti ovamo zahvaćati.”"},{"v":16,"t":"Nato joj on reče: “Idi i zovi svoga muža pa se vrati ovamo.”"},{"v":17,"t":"Odgovori mu žena: “Nemam muža.” Kaže joj Isus: “Dobro si rekla: 'Nemam muža!'"},{"v":18,"t":"Pet si doista muževa imala, a ni ovaj koga sada imaš nije ti muž. To si po istini rekla.”"},{"v":19,"t":"Kaže mu žena: “Gospodine, vidim da si prorok."},{"v":20,"t":"Naši su se očevi klanjali na ovome brdu, a vi kažete da je u Jeruzalemu mjesto gdje se treba klanjati.”"},{"v":21,"t":"A Isus joj reče: “Vjeruj mi, ženo, dolazi čas kad se nećete klanjati Ocu ni na ovoj gori ni u Jeruzalemu."},{"v":22,"t":"Vi se klanjate onome što ne poznate, a mi se klanjamo onome što poznamo jer spasenje dolazi od Židova."},{"v":23,"t":"Ali dolazi čas - sada je! - kad će se istinski klanjatelji klanjati Ocu u duhu i istini jer takve upravo klanjatelje traži Otac."},{"v":24,"t":"Bog je duh i koji se njemu klanjaju, u duhu i istini treba da se klanjaju.”"},{"v":25,"t":"Kaže mu žena: “Znam da ima doći Mesija zvani Krist - Pomazanik. Kad on dođe, objavit će nam sve.”"},{"v":26,"t":"Kaže joj Isus: “Ja sam, ja koji s tobom govorim!”"},{"v":27,"t":"Uto dođu njegovi učenici pa se začude što razgovara sa ženom. Nitko ga ipak ne zapita: “Što tražiš?” ili: “Što razgovaraš s njom?”"},{"v":28,"t":"Žena ostavi svoj krčag pa ode u grad i reče ljudima:"},{"v":29,"t":"“Dođite da vidite čovjeka koji mi je kazao sve što sam počinila. Da to nije Krist?”"},{"v":30,"t":"Oni iziđu iz grada te se upute k njemu."},{"v":31,"t":"Učenici ga dotle nudili: “Učitelju, jedi!”"},{"v":32,"t":"A on im reče: “Hraniti mi se valja jelom koje vi ne poznajete.”"},{"v":33,"t":"Učenici se nato zapitkivahu: “Da mu nije tko donio jesti?”"},{"v":34,"t":"Kaže im Isus: “Jelo je moje vršiti volju onoga koji me posla i dovršiti djelo njegovo."},{"v":35,"t":"Ne govorite li vi: 'Još četiri mjeseca i evo žetve?' Gle, kažem vam, podignite oči svoje i pogledajte polja: već se bjelasaju za žetvu."},{"v":36,"t":"Žetelac već prima plaću, sabire plod za vječni život da se sijač i žetelac zajedno raduju."},{"v":37,"t":"Tu se obistinjuje izreka: 'Jedan sije, drugi žanje.'"},{"v":38,"t":"Ja vas poslah žeti ono oko čega se niste trudili; drugi su se trudili, a vi ste ušli u trud njihov.”"},{"v":39,"t":"Mnogi Samarijanci iz onoga grada povjerovaše u njega zbog riječi žene koja je svjedočila: “Kazao mi je sve što sam počinila.”"},{"v":40,"t":"Kad su dakle Samarijanci došli k njemu, moljahu ga da ostane u njih. I ostade ondje dva dana."},{"v":41,"t":"Tada ih je još mnogo više povjerovalo zbog njegove riječi"},{"v":42,"t":"pa govorahu ženi: “Sada više ne vjerujemo zbog tvoga kazivanja; ta sami smo čuli i znamo: ovo je uistinu Spasitelj svijeta.”"},{"v":43,"t":"Nakon dva dana ode odande u Galileju."},{"v":44,"t":"Sam je Isus doduše izjavio da prorok nema časti u svom zavičaju."},{"v":45,"t":"Kad je dakle stigao u Galileju, Galilejci ga lijepo primiše jer bijahu vidjeli što je sve učinio u Jeruzalemu za blagdana. Jer su i oni bili uzišli na blagdan."},{"v":46,"t":"Dođe dakle ponovno u Kanu Galilejsku, gdje bijaše pretvorio vodu u vino. Ondje bijaše neki kraljevski službenik koji je imao bolesna sina u Kafarnaumu."},{"v":47,"t":"Kad je čuo da je Isus došao iz Judeje u Galileju, ode k njemu pa ga moljaše da siđe i ozdravi mu sina jer već samo što nije umro."},{"v":48,"t":"Nato mu Isus reče: “Ako ne vidite znamenja i čudesa, ne vjerujete!”"},{"v":49,"t":"Kaže mu kraljevski službenik: “Gospodine, siđi dok mi ne umre dijete.”"},{"v":50,"t":"Kaže mu Isus: “Idi, sin tvoj živi!” Povjerova čovjek riječi koju mu reče Isus i ode."},{"v":51,"t":"Dok je on još silazio, pohite mu u susret sluge s viješću da mu sin živi."},{"v":52,"t":"Upita ih dakle za uru kad mu je krenulo nabolje. Rekoše mu: “Jučer oko sedme ure pustila ga ognjica.”"},{"v":53,"t":"Tada razabra otac da je to bilo upravo onog časa kad mu Isus reče: “Sin tvoj živi.” I povjerova on i sav dom njegov."},{"v":54,"t":"Bijaše to drugo znamenje što ga učini Isus po povratku iz Judeje u Galileju."}]},"5":{"hr":[{"v":1,"t":"Nakon toga bijaše židovski blagdan pa Isus uziđe u Jeruzalem."},{"v":2,"t":"U Jeruzalemu se kod Ovčjih vrata nalazi kupalište koje se hebrejski zove Bethzatha, a ima pet trijemova."},{"v":3,"t":"U njima je ležalo mnoštvo bolesnika - slijepih, hromih, uzetih:čekali su da izbije voda.."},{"v":4,"t":"Anđeo bi Gospodnji, naime, silazio od vremena do vremena u ribnjak i pokrenuo vodu: tko bi prvi ušao pošto je voda izbila, ozdravio bi makar bolovao od bilo kakve bolesti."},{"v":5,"t":"Bijaše ondje neki čovjek koji je trpio od svoje bolesti trideset i osam godina."},{"v":6,"t":"Kad ga Isus opazi gdje leži i kada dozna da je već dugo u tome stanju, kaže mu: “Želiš li ozdraviti?”"},{"v":7,"t":"Odgovori mu bolesnik: “Gospodine, nikoga nemam tko bi me uronio u kupalište kad se voda uzbiba. Dok ja stignem, drugi već prije mene siđe.”"},{"v":8,"t":"Kaže mu Isus: “Ustani, uzmi svoju postelju i hodi!”"},{"v":9,"t":"Čovjek odmah ozdravi, uzme svoju postelju i prohoda. Toga dana bijaše subota."},{"v":10,"t":"Židovi su stoga govorili ozdravljenomu: “Subota je! Ne smiješ nositi postelju svoju!”"},{"v":11,"t":"On im odvrati: “Onaj koji me ozdravi reče mi: 'Uzmi svoju postelju i hodi!'”"},{"v":12,"t":"Upitaše ga dakle: “Tko je taj čovjek koji ti je rekao: 'Uzmi i hodi?'”"},{"v":13,"t":"No ozdravljenik nije znao tko je taj jer je Isus nestao u mnoštvu što se ondje nalazilo."},{"v":14,"t":"Nakon toga nađe ga Isus u Hramu i reče mu: “Eto, ozdravio si! Više ne griješi da te što gore ne snađe!”"},{"v":15,"t":"Čovjek ode i javi Židovima da je Isus onaj koji ga je ozdravio."},{"v":16,"t":"Zbog toga su Židovi počeli Isusa napadati što to radi subotom."},{"v":17,"t":"Isus im odgovori: “Otac moj sve do sada radi pa i ja radim.”"},{"v":18,"t":"Zbog toga su Židovi još više gledali da ga ubiju jer je ne samo kršio subotu nego i Boga nazivao Ocem svojim izjednačujući sebe s Bogom."},{"v":19,"t":"Isus nato odvrati: “Zaista, zaista, kažem vam: Sin ne može sam od sebe činiti ništa, doli što vidi da čini Otac; što on čini, to jednako i Sin čini."},{"v":20,"t":"Jer Otac Ljubi Sina i pokazuje mu sve što sam čini. Pokazat će mu i veća djela od ovih te ćete se čudom čuditi."},{"v":21,"t":"Uistinu, kao što Otac uskrisuje mrtve i oživljava tako i Sin oživljava koje hoće."},{"v":22,"t":"Otac doista ne sudi nikomu: sav je sud predao Sinu"},{"v":23,"t":"da svi časte Sina kao što časte Oca. Tko ne časti Sina, ne časti ni Oca koji ga posla.”"},{"v":24,"t":"“Zaista, zaista, kažem vam: tko sluša moju riječ i vjeruje onomu koji me posla, ima život vječni i ne dolazi na sud, nego je prešao iz smrti u život."},{"v":25,"t":"Zaista, zaista, kažem vam: dolazi čas - sada je! - kad će mrtvi čuti glas Sina Božjega i koji čuju, živjet će."},{"v":26,"t":"Doista, kao što Otac ima život u sebi tako je i Sinu dao da ima život u sebi;"},{"v":27,"t":"i ovlasti ga da sudi jer je Sin Čovječji."},{"v":28,"t":"Ne čudite se tome jer dolazi čas kad će svi koji su u grobovima, čuti njegov glas."},{"v":29,"t":"I izići će: koji su dobro činili - na uskrsnuće života, a koji su radili zlo - na uskrsnuće osude."},{"v":30,"t":"Ja sam od sebe ne mogu učiniti ništa: kako čujem, sudim, i sud je moj pravedan jer ne tražim svoje volje, nego volju onoga koji me posla.”"},{"v":31,"t":"“Ako ja svjedočim sam za sebe, svjedočanstvo moje nije istinito."},{"v":32,"t":"Drugi svjedoči za mene i znam: istinito je svjedočanstvo kojim on svjedoči za mene."},{"v":33,"t":"Vi ste poslali k Ivanu i on je posvjedočio za istinu."},{"v":34,"t":"Ja ne primam svjedočanstva od čovjeka, već govorim to da se vi spasite."},{"v":35,"t":"On bijaše svjetiljka što gori i svijetli, a vi se htjedoste samo za čas naslađivati njegovom svjetlosti."},{"v":36,"t":"Ali ja imam svjedočanstvo veće od Ivanova: djela koja mi je dao izvršiti Otac, upravo ta djela koja činim, svjedoče za mene - da me poslao Otac."},{"v":37,"t":"Pa i Otac koji me posla sam je svjedočio za mene. Niti ste glasa njegova ikada čuli niti ste lica njegova ikada vidjeli,"},{"v":38,"t":"a ni riječ njegova ne prebiva u vama jer ne vjerujete onomu kojega on posla."},{"v":39,"t":"Vi istražujete Pisma jer mislite po njima imati život vječni. I ona svjedoče za mene,"},{"v":40,"t":"a vi ipak nećete da dođete k meni da život imate."},{"v":41,"t":"Slave od ljudi ne tražim,"},{"v":42,"t":"ali vas dobro upoznah: ljubavi Božje nemate u sebi."},{"v":43,"t":"Ja sam došao u ime Oca svoga i vi me ne primate. Dođe li tko drugi u svoje ime, njega ćete primiti."},{"v":44,"t":"Ta kako biste vi vjerovali kad tražite slavu jedni od drugih, a slave od Boga jedinoga ne tražite!"},{"v":45,"t":"Ne mislite da ću vas ja tužiti Ocu. Vaš je tužitelj Mojsije u koga se uzdate."},{"v":46,"t":"Uistinu, kad biste vjerovali Mojsiju, i meni biste vjerovali: ta o meni je on pisao."},{"v":47,"t":"Ali ako njegovim pismima ne vjerujete, kako da mojim riječima vjerujete?”"}]},"6":{"hr":[{"v":1,"t":"Nakon toga ode Isus na drugu stranu Galilejskog, Tiberijadskog mora."},{"v":2,"t":"Slijedilo ga silno mnoštvo jer su gledali znamenja što ih je činio na bolesnicima."},{"v":3,"t":"A Isus uziđe na goru i ondje sjeđaše sa svojim učenicima."},{"v":4,"t":"Bijaše blizu Pasha, židovski blagdan."},{"v":5,"t":"Isus podigne oči i ugleda kako silan svijet dolazi k njemu pa upita Filipa: “Gdje da kupimo kruha da ovi blaguju?”"},{"v":6,"t":"To reče kušajući ga; jer znao je što će učiniti."},{"v":7,"t":"Odgovori mu Filip: “Za dvjesta denara kruha ne bi bilo dosta da svaki nešto malo dobije.”"},{"v":8,"t":"Kaže mu jedan od njegovih učenika, Andrija, brat Šimuna Petra:"},{"v":9,"t":"“Ovdje je dječak koji ima pet ječmenih kruhova i dvije ribice! Ali što je to za tolike?”"},{"v":10,"t":"Reče Isus: “Neka ljudi posjedaju!” A bilo je mnogo trave na tome mjestu. Posjedaše dakle muškarci, njih oko pet tisuća."},{"v":11,"t":"Isus uze kruhove, izreče zahvalnicu pa razdijeli onima koji su posjedali. A tako i od ribica - koliko su god htjeli."},{"v":12,"t":"A kad se nasitiše, reče svojim učenicima: “Skupite preostale ulomke da ništa ne propadne!”"},{"v":13,"t":"Skupili su dakle i napunili dvanaest košara ulomaka što od pet ječmenih kruhova pretekoše onima koji su blagovali."},{"v":14,"t":"Kad su ljudi vidjeli znamenje što ga Isus učini, rekoše: “Ovo je uistinu Prorok koji ima doći na svijet!”"},{"v":15,"t":"Kad Isus spozna da kane doći, pograbiti ga i zakraljiti, povuče se ponovno u goru, posve sam."},{"v":16,"t":"Kad nasta večer, siđoše njegovi učenici k moru,"},{"v":17,"t":"uđoše u lađicu i krenuše na onu stranu mora, u Kafarnaum. Već se i smrklo, a Isusa još nikako k njima."},{"v":18,"t":"More se uzburkalo od silnog vjetra što je zapuhao."},{"v":19,"t":"Pošto su dakle isplovili oko dvadeset i pet do trideset stadija, ugledaju Isusa gdje ide po moru i približava se lađici. Prestraše se,"},{"v":20,"t":"a on će njima: “Ja sam! Ne bojte se!”"},{"v":21,"t":"Htjedoše ga uzeti u lađicu, kadli se lađica odmah nađe na obali kamo su se zaputili."},{"v":22,"t":"Sutradan mnoštvo, koje osta s onu stranu mora, zapazi da ondje bijaše samo jedna lađica i da Isus nije bio ušao zajedno sa svojim učenicima u lađicu, nego da oni odoše sami."},{"v":23,"t":"Iz Tiberijade pak stigoše druge lađice blizu onog mjesta gdje jedoše kruh pošto je Gospodin izrekao zahvalnicu."},{"v":24,"t":"Kada dakle mnoštvo vidje da ondje nema Isusa ni njegovih učenika, uđu u lađice i odu u Kafarnaum tražeći Isusa."},{"v":25,"t":"Kad ga nađoše s onu stranu mora, rekoše mu: “Učitelju, kad si ovamo došao?”"},{"v":26,"t":"Isus im odgovori: “Zaista, zaista, kažem vam: tražite me, ali ne stoga što vidjeste znamenja, nego stoga što ste jeli od onih kruhova i nasitili se."},{"v":27,"t":"Radite, ali ne za hranu propadljivu, nego za hranu koja ostaje za život vječni: nju će vam dati Sin Čovječji jer njega Otac - Bog - opečati.”"},{"v":28,"t":"Rekoše mu dakle: “Što nam je činiti da bismo radili djela Božja?”"},{"v":29,"t":"Odgovori im Isus: “Djelo je Božje da vjerujete u onoga kojega je on poslao.”"},{"v":30,"t":"Rekoše mu onda: “Kakvo ti znamenje činiš da vidimo pa da ti vjerujemo? Koje je tvoje djelo?"},{"v":31,"t":"Očevi naši blagovaše manu u pustinji, kao što je pisano: Nahrani ih kruhom nebeskim.”"},{"v":32,"t":"Reče im Isus: “Zaista, zaista, kažem vam: nije vam Mojsije dao kruh s neba, nego Otac moj daje vam kruh s neba, kruh istinski;"},{"v":33,"t":"jer kruh je Božji Onaj koji silazi s neba i daje život svijetu.”"},{"v":34,"t":"Rekoše mu nato: “Gospodine, daj nam uvijek toga kruha.”"},{"v":35,"t":"Reče im Isus: “Ja sam kruh života. Tko dolazi k meni, neće ogladnjeti; tko vjeruje u mene, neće ožednjeti nikada."},{"v":36,"t":"No rekoh vam: vidjeli ste me, a opet ne vjerujete."},{"v":37,"t":"Svi koje mi daje Otac doći će k meni, i onoga tko dođe k meni neću izbaciti;"},{"v":38,"t":"jer siđoh s neba ne da vršim svoju volju, nego volju onoga koji me posla."},{"v":39,"t":"A ovo je volja onoga koji me posla: da nikoga od onih koje mi je dao ne izgubim, nego da ih uskrisim u posljednji dan."},{"v":40,"t":"Da, to je volja Oca mojega da tko god vidi Sina i vjeruje u njega, ima život vječni i ja da ga uskrisim u posljednji dan.”"},{"v":41,"t":"Židovi nato mrmljahu protiv njega što je rekao: “Ja sam kruh koji je sišao s neba.”"},{"v":42,"t":"Govorahu: “Nije li to Isus, sin Josipov? Ne poznajemo li mu oca i majku? Kako sada govori: 'Sišao sam s neba?'”"},{"v":43,"t":"Isus im odvrati: “Ne mrmljajte među sobom!"},{"v":44,"t":"Nitko ne može doći k meni ako ga ne povuče Otac koji me posla; i ja ću ga uskrisiti u posljednji dan."},{"v":45,"t":"Pisano je u Prorocima: Svi će biti učenici Božji. Tko god čuje od Oca i pouči se, dolazi k meni."},{"v":46,"t":"Ne da bi tko vidio Oca, doli onaj koji je kod Boga; on je vidio Oca."},{"v":47,"t":"Zaista, zaista, kažem vam: tko vjeruje, ima život vječni."},{"v":48,"t":"Ja sam kruh života."},{"v":49,"t":"Očevi vaši jedoše u pustinji manu i pomriješe."},{"v":50,"t":"Ovo je kruh koji silazi s neba: da tko od njega jede, ne umre."},{"v":51,"t":"Ja sam kruh živi koji je s neba sišao. Tko bude jeo od ovoga kruha, živjet će uvijeke. Kruh koji ću ja dati tijelo je moje - za život svijeta.”"},{"v":52,"t":"Židovi se nato među sobom prepirahu: “Kako nam ovaj može dati tijelo svoje za jelo?”"},{"v":53,"t":"Reče im stoga Isus: “Zaista, zaista, kažem vam: ako ne jedete tijela Sina Čovječjega i ne pijete krvi njegove, nemate života u sebi!"},{"v":54,"t":"Tko blaguje tijelo moje i pije krv moju, ima život vječni; i ja ću ga uskrisiti u posljednji dan."},{"v":55,"t":"Tijelo je moje jelo istinsko, krv je moja piće istinsko."},{"v":56,"t":"Tko jede moje tijelo i pije moju krv, u meni ostaje i ja u njemu."},{"v":57,"t":"Kao što je mene poslao živi Otac i ja živim po Ocu, tako i onaj koji mene blaguje živjet će po meni."},{"v":58,"t":"Ovo je kruh koji je s neba sišao, ne kao onaj koji jedoše očevi i pomriješe. Tko jede ovaj kruh, živjet će uvijeke.”"},{"v":59,"t":"To reče Isus naučavajući u sinagogi u Kafarnaumu."},{"v":60,"t":"Mnogi od njegovih učenika čuvši to rekoše: “Tvrda je to besjeda! Tko je može slušati?”"},{"v":61,"t":"A Isus znajući sam od sebe da njegovi učenici zbog toga mrmljaju, reče im: “Zar vas to sablažnjava?"},{"v":62,"t":"A što ako vidite Sina Čovječjega kako uzlazi onamo gdje je prije bio?”"},{"v":63,"t":"“Duh je onaj koji oživljuje, tijelo ne koristi ništa. Riječi koje sam vam govorio duh su i život su.”"},{"v":64,"t":"“A ipak, ima ih među vama koji ne vjeruju.” Jer znao je Isus od početka koji su oni što ne vjeruju i tko je onaj koji će ga izdati."},{"v":65,"t":"I doda: “Zato sam vam i rekao da nitko ne može doći k meni ako mu nije dano od Oca.”"},{"v":66,"t":"Otada mnogi učenici odstupiše, više nisu išli s njime."},{"v":67,"t":"Reče stoga Isus dvanaestorici: “Da možda i vi ne kanite otići?”"},{"v":68,"t":"Odgovori mu Šimun Petar: “Gospodine, kome da idemo? Ti imaš riječi života vječnoga!"},{"v":69,"t":"I mi vjerujemo i znamo: ti si Svetac Božji.”"},{"v":70,"t":"Odgovori im Isus: “Nisam li ja vas dvanaestoricu izabrao? A ipak, jedan je od vas đavao.”"},{"v":71,"t":"Govoraše to o Judi, sinu Šimuna Iškariotskoga, jednom od dvanaestorice, jer on ga je imao izdati."}]},"7":{"hr":[{"v":1,"t":"Nakon toga Isus je obilazio po Galileji; nije htio u Judeju jer su Židovi tražili da ga ubiju."},{"v":2,"t":"Bijaše blizu židovski Blagdan sjenica."},{"v":3,"t":"Rekoše mu stoga njegova braća: “Otiđi odavle i pođi u Judeju da i tvoji učenici vide djela što činiš."},{"v":4,"t":"Ta tko želi biti javno poznat, ne čini ništa u tajnosti. Ako već činiš sve to, očituj se svijetu.”"},{"v":5,"t":"Jer ni braća njegova nisu vjerovala u njega."},{"v":6,"t":"Reče im nato Isus: “Moje vrijeme još nije došlo, a za vas je vrijeme svagda pogodno."},{"v":7,"t":"Vas svijet ne može mrziti, ali mene mrzi jer ja svjedočim protiv njega: da su mu djela opaka."},{"v":8,"t":"Vi samo uziđite na blagdan. Ja još ne uzlazim na ovaj blagdan jer moje se vrijeme još nije ispunilo.”"},{"v":9,"t":"To im reče i ostade u Galileji."},{"v":10,"t":"Ali pošto njegova braća uziđoše na blagdan, uziđe i on, ne javno, nego potajno."},{"v":11,"t":"A Židovi su ga tražili o blagdanu pitajući : “Gdje je onaj?”"},{"v":12,"t":"I među mnoštvom o njemu se mnogo šaptalo. Jedni govorahu: “Dobar je!” Drugi pak: “Ne, nego zavodi narod.”"},{"v":13,"t":"Ipak nitko nije otvoreno govorio o njemu zbog straha od Židova."},{"v":14,"t":"Usred blagdana uziđe Isus u Hram i stade naučavati."},{"v":15,"t":"Židovi se u čudu pitahu: “Kako ovaj znade Pisma, a nije učio?”"},{"v":16,"t":"Nato im Isus odvrati: “Moj nauk nije moj, nego onoga koji me posla."},{"v":17,"t":"Ako tko hoće vršiti volju njegovu, prepoznat će da li je taj nauk od Boga ili ja sam od sebe govorim."},{"v":18,"t":"Tko sam od sebe govori, svoju slavu traži, a tko traži slavu onoga koji ga posla, taj je istinit i nema u njemu nepravednosti."},{"v":19,"t":"Nije li vam Mojsije dao Zakon? Pa ipak nitko od vas ne vrši Zakona.” “Zašto tražite da me ubijete?”"},{"v":20,"t":"Odgovori mnoštvo: “Zloduha imaš! Tko traži da te ubije?”"},{"v":21,"t":"Uzvrati im Isus: “Jedno djelo učinih i svi se čudite."},{"v":22,"t":"Mojsije vam dade obrezanje - ne, ono i nije od Mojsija, nego od otaca - i vi u subotu obrezujete čovjeka."},{"v":23,"t":"Ako čovjek može primiti obrezanje u subotu da se ne prekrši Mojsijev zakon, zašto se ljutite na mene što sam svega čovjeka ozdravio u subotu?"},{"v":24,"t":"Ne sudite po vanjštini, nego sudite sudom pravednim!”"},{"v":25,"t":"Rekoše tada neki Jeruzalemci: “Nije li to onaj koga traže da ga ubiju?"},{"v":26,"t":"A evo, posve otvoreno govori i ništa mu ne kažu. Da nisu možda i glavari doista upoznali da je on Krist?"},{"v":27,"t":"Ali za njega znamo odakle je, a kad Krist dođe, nitko neće znati odakle je!”"},{"v":28,"t":"Nato Isus, koji je učio u Hramu, povika: “Da! Poznajete me i znate odakle sam! A ipak ja nisam došao sam od sebe: postoji jedan istiniti koji me posla. Njega vi ne znate."},{"v":29,"t":"Ja ga znadem jer sam od njega i on me poslao.”"},{"v":30,"t":"Židovi su otad vrebali da ga uhvate. Ipak nitko ne stavi na nj ruke jer još nije bio došao njegov čas."},{"v":31,"t":"A mnogi iz mnoštva povjerovaše u nj te govorahu: “Zar će Krist, kada dođe, činiti više znamenja nego što ih ovaj učini?”"},{"v":32,"t":"Dočuli farizeji da se to u mnoštvu o njemu šapće. Stoga glavari svećenički i farizeji poslaše stražare da ga uhvate."},{"v":33,"t":"Tada Isus reče: “Još sam malo vremena s vama i odlazim onomu koji me posla."},{"v":34,"t":"Tražit ćete me i nećete me naći; gdje sam ja, vi ne možete doći.”"},{"v":35,"t":"Rekoše nato Židovi među sobom: “Kamo to ovaj kani da ga mi nećemo naći? Da ne kani poći raseljenima među Grcima i naučavati Grke?"},{"v":36,"t":"Što li znači besjeda koju reče: 'Tražit ćete me i nećete me naći; gdje sam ja, vi ne možete doći'?”"},{"v":37,"t":"U posljednji, veliki dan blagdana Isus stade i povika: “Ako je tko žedan, neka dođe k meni! Neka pije"},{"v":38,"t":"koji vjeruje u mene! Kao što reče Pismo: 'Rijeke će žive vode poteći iz njegove utrobe!'”"},{"v":39,"t":"To reče o Duhu kojega su imali primiti oni što vjeruju u njega. Tada doista ne bijaše još došao Duh jer Isus nije bio proslavljen."},{"v":40,"t":"Kad su neki iz naroda čuli te riječi, govorahu: “Ovo je uistinu Prorok.”"},{"v":41,"t":"Drugi govorahu: “Ovo je Krist.” A bilo ih je i koji su pitali: “Pa zar Krist dolazi iz Galileje?"},{"v":42,"t":"Ne kaže li Pismo da Krist dolazi iz potomstva Davidova, i to iz Betlehema, mjesta gdje bijaše David?”"},{"v":43,"t":"Tako je u narodu nastala podvojenost zbog njega."},{"v":44,"t":"Neki ga čak htjedoše uhvatiti, ali nitko ne stavi na nj ruke."},{"v":45,"t":"Dođoše dakle stražari glavarima svećeničkim i farizejima, a ovi im rekoše: “Zašto ga ne dovedoste?”"},{"v":46,"t":"Stražari odgovore: “Nikada nitko nije ovako govorio.”"},{"v":47,"t":"Nato će im farizeji: “Zar ste se i vi dali zavesti?"},{"v":48,"t":"Je li itko od glavara ili farizeja povjerovao u njega?"},{"v":49,"t":"Ali ta svjetina koja ne pozna Zakona - to je prokleto!”"},{"v":50,"t":"Kaže im Nikodem - onaj koji ono prije dođe k Isusu, a bijaše jedan od njih:"},{"v":51,"t":"“Zar naš Zakon sudi čovjeku ako ga prije ne sasluša i ne dozna što čini?”"},{"v":52,"t":"Odgovoriše mu: “Da nisi i ti iz Galileje? Istraži pa ćeš vidjeti da iz Galileje ne ustaje prorok.”"},{"v":53,"t":"I otiđoše svaki svojoj kući."}]},"8":{"hr":[{"v":1,"t":"A Isus se uputi na Maslinsku goru."},{"v":2,"t":"U zoru eto ga opet u Hramu. Sav je narod hrlio k njemu. On sjede i stade poučavati."},{"v":3,"t":"Uto mu pismoznanci i farizeji dovedu neku ženu zatečenu u preljubu. Postave je u sredinu"},{"v":4,"t":"i kažu mu: “Učitelju! Ova je žena zatečena u samom preljubu."},{"v":5,"t":"U Zakonu nam je Mojsije naredio takve kamenovati. Što ti na to kažeš?”"},{"v":6,"t":"To govorahu samo da ga iskušaju pa da ga mogu optužiti. Isus se sagne pa stane prstom pisati po tlu."},{"v":7,"t":"A kako su oni dalje navaljivali, on se uspravi i reče im: “Tko je od vas bez grijeha, neka prvi na nju baci kamen.”"},{"v":8,"t":"I ponovno se sagnuvši, nastavi pisati po zemlji."},{"v":9,"t":"A kad oni to čuše, stadoše odlaziti jedan za drugim, počevši od starijih. Osta Isus sam - i žena koja stajaše u sredini."},{"v":10,"t":"Isus se uspravi i reče joj: “Ženo, gdje su oni? Zar te nitko ne osudi?”"},{"v":11,"t":"Ona reče: “Nitko, Gospodine.” Reče joj Isus: “Ni ja te ne osuđujem. Idi i odsada više nemoj griješiti.”"},{"v":12,"t":"Isus im zatim ponovno progovori: “Ja sam svjetlost svijeta; tko ide za mnom, neće hoditi u tami, nego će imati svjetlost života.”"},{"v":13,"t":"Farizeji mu nato rekoše: “Ti svjedočiš sam za sebe: svjedočanstvo tvoje nije istinito!”"},{"v":14,"t":"Odgovori im Isus: “Ako ja i svjedočim sam za sebe, svjedočanstvo je moje istinito jer znam odakle dođoh i kamo idem. A vi ne znate ni odakle dolazim ni kamo idem."},{"v":15,"t":"Vi sudite po tijelu; ja ne sudim nikoga;"},{"v":16,"t":"no ako i sudim, sud je moj istinit jer nisam sam, nego - ja i onaj koji me posla, Otac."},{"v":17,"t":"Ta i u vašem zakonu piše da je svjedočanstvo dvojice istinito."},{"v":18,"t":"Ja svjedočim za sebe, a svjedoči za mene i onaj koji me posla, Otac.”"},{"v":19,"t":"Nato ga upitaju: “Gdje je tvoj Otac?” Odgovori Isus: “Niti mene poznajete niti Oca mojega. Kad biste poznavali mene, i Oca biste moga poznavali.”"},{"v":20,"t":"Te riječi rekao je Isus u riznici dok je naučavao u Hramu. I nitko ga ne uhvati jer još ne bijaše došao njegov čas."},{"v":21,"t":"Reče im ponovno Isus: “Ja odlazim, a vi ćete me tražiti i u svojem ćete grijehu umrijeti. Kamo ja odlazim, vi ne možete doći.”"},{"v":22,"t":"Židovi se nato stanu pitati: “Da se možda ne kani ubiti kad govori: 'Kamo ja odlazim, vi ne možete doći'?”"},{"v":23,"t":"A Isus nastavi: “Vi ste odozdol, ja sam odozgor. Vi ste od ovoga svijeta, a ja nisam od ovoga svijeta."},{"v":24,"t":"Stoga vam i rekoh: 'Umrijet ćete u grijesima svojim.' Uistinu, ako ne povjerujete da Ja jesam, umrijet ćete u grijesima svojim.”"},{"v":25,"t":"Nato mu oni rekoše: “A tko si ti?” Odvrati Isus:"},{"v":26,"t":"“Ta što da vam s početka opet zborim? Mnogo toga imam o vama zboriti i suditi; no onaj koji me posla istinit je, i što sam čuo od njega, to ja zborim svijetu.”"},{"v":27,"t":"Ne shvatiše da im govori o Ocu."},{"v":28,"t":"Isus im nato reče: “Kad uzdignete Sina Čovječjega, tada ćete upoznati da Ja jesam i da sam od sebe ne činim ništa, nego da onako zborim kako me naučio Otac."},{"v":29,"t":"Onaj koji me posla sa mnom je i ne ostavi me sama jer ja uvijek činim što je njemu milo.”"},{"v":30,"t":"Na te njegove riječi mnogi povjerovaše u njega."},{"v":31,"t":"Tada Isus progovori Židovima koji mu povjerovaše: “Ako ostanete u mojoj riječi, uistinu, moji ste učenici;"},{"v":32,"t":"upoznat ćete istinu i istina će vas osloboditi.”"},{"v":33,"t":"Odgovore mu: “Potomstvo smo Abrahamovo i nikome nikada nismo robovali. Kako to ti govoriš: 'Postat ćete slobodni?'”"},{"v":34,"t":"Odgovori im Isus: “Zaista, zaista, kažem vam: tko god čini grijeh, rob je grijeha."},{"v":35,"t":"Rob ne ostaje u kući zauvijek, a sin ostaje zauvijek."},{"v":36,"t":"Ako vas dakle Sin oslobodi, zbilja ćete biti slobodni."},{"v":37,"t":"Znam: potomstvo ste Abrahamovo, a ipak tražite da me ubijete jer moja riječ nema mjesta u vama."},{"v":38,"t":"Ja govorim što vidjeh kod Oca, a vi činite što čuste od svog oca.”"},{"v":39,"t":"Odgovoriše mu: “Naš je otac Abraham”. Kaže im Isus: “Da ste djeca Abrahamova, djela biste Abrahamova činili."},{"v":40,"t":"A eto, tražite da ubijete mene, mene koji sam vam govorio istinu što sam je od Boga čuo. Takvo što Abraham nije učinio!"},{"v":41,"t":"Vi činite djela oca svojega.” Rekoše mu: “Mi se nismo rodili iz preljuba, jedan nam je Otac - Bog.”"},{"v":42,"t":"Reče im Isus: “Kad bi Bog bio vaš Otac, ljubili biste mene jer sam ja od Boga izišao i došao; nisam sam od sebe došao, nego on me posla."},{"v":43,"t":"Zašto moje besjede ne razumijete? Zato što niste kadri slušati moju riječ."},{"v":44,"t":"Vama je otac đavao i hoće vam se vršiti prohtjeve oca svoga. On bijaše čovjekoubojica od početka i ne stajaše u istini jer nema istine u njemu: kad govori laž, od svojega govori jer je lažac i otac laži."},{"v":45,"t":"A meni, jer istinu govorim, meni ne vjerujete."},{"v":46,"t":"Tko će mi od vas dokazati grijeh? Ako istinu govorim, zašto mi ne vjerujete?"},{"v":47,"t":"Tko je od Boga, riječi Božje sluša; vi zato ne slušate jer niste od Boga.”"},{"v":48,"t":"Odgovoriše mu Židovi: “Ne kažemo li pravo da si ti Samarijanac i da imaš zloduha?”"},{"v":49,"t":"Odgovori Isus: “Ja nemam zloduha, nego častim svoga Oca, a vi me obeščašćujete."},{"v":50,"t":"No ja ne tražim svoje slave; ima tko traži i sudi."},{"v":51,"t":"Zaista, zaista, kažem vam: ako tko očuva moju riječ, neće vidjeti smrti dovijeka.”"},{"v":52,"t":"Rekoše mu Židovi: “Sada vidimo da imaš zloduha. Abraham umrije, tako i proroci, a ti kažeš: 'Ako tko čuva moju riječ, neće okusiti smrti dovijeka.'"},{"v":53,"t":"Zar si ti veći od oca našega Abrahama, koji je umro? Pa i proroci pomriješe. Kime se to praviš?”"},{"v":54,"t":"Odgovori Isus: “Ako ja sam sebe slavim, slava moja nije ništa. Ima koji me slavi - Otac moj, a vi velite da je on vaš Bog,"},{"v":55,"t":"no ne poznajete ga, a ja ga znam. Ako vam reknem da ga ne znam, bit ću lažac jednak vama. No znam ga i riječ njegovu čuvam."},{"v":56,"t":"Abraham, otac vaš, usklikta što će vidjeti moj Dan. I vidje i obradova se.”"},{"v":57,"t":"Rekoše mu nato Židovi: “Ni pedeset ti još godina nije, a vidio si Abrahama?”"},{"v":58,"t":"Reče im Isus: “Zaista, zaista, kažem vam: prije negoli Abraham posta, Ja jesam!”"},{"v":59,"t":"Nato pograbiše kamenje da bace na nj. No Isus se sakri te iziđe iz Hrama."}]},"9":{"hr":[{"v":1,"t":"Prolazeći ugleda čovjeka slijepa od rođenja."},{"v":2,"t":"Zapitaše ga njegovi učenici: “Učitelju, tko li sagriješi, on ili njegovi roditelji te se slijep rodio?”"},{"v":3,"t":"Odgovori Isus: “Niti sagriješi on niti njegovi roditelji, nego je to zato da se na njemu očituju djela Božja.”"},{"v":4,"t":"“Dok je dan, treba da radimo djela onoga koji me posla. Dolazi noć, kad nitko ne može raditi."},{"v":5,"t":"Dok sam na svijetu, svjetlost sam svijeta.”"},{"v":6,"t":"To rekavši, pljune na zemlju i od pljuvačke načini kal pa mu kalom premaza oči."},{"v":7,"t":"I reče mu: “Idi, operi se u kupalištu Siloamu!” - što znači “Poslanik.” Onaj ode, umije se pa se vrati gledajući."},{"v":8,"t":"Susjedi i oni koji su ga prije viđali kao prosjaka govorili su: “Nije li to onaj koji je sjedio i prosio?”"},{"v":9,"t":"Jedni su govorili: “On je.” Drugi opet: “Nije, nego mu je sličan.” On je sam tvrdio: “Da, ja sam!”"},{"v":10,"t":"Nato ga upitaše: “Kako su ti se otvorile oči?”"},{"v":11,"t":"On odgovori: “Čovjek koji se zove Isus načini kal, premaza mi oči i reče mi: 'Idi u Siloam i operi se.' Odoh dakle, oprah se i progledah.”"},{"v":12,"t":"Rekoše mu: “Gdje je on?” Odgovori: “Ne znam.”"},{"v":13,"t":"Tada odvedoše toga bivšeg slijepca farizejima."},{"v":14,"t":"A toga dana kad Isus načini kal i otvori njegove oči, bijaše subota."},{"v":15,"t":"Farizeji ga počeše iznova ispitivati kako je progledao. On im reče: “Stavio mi kal na oči i ja se oprah - i evo vidim.”"},{"v":16,"t":"Nato neki između farizeja rekoše: “Nije taj čovjek od Boga: ne pazi na subotu.” Drugi su pak govorili: “A kako bi jedan grešnik mogao činiti takva znamenja?” I nastade među njima podvojenost."},{"v":17,"t":"Zatim ponovno upitaju slijepca: “A što ti kažeš o njemu? Otvorio ti je oči!” On odgovori: “Prorok je!”"},{"v":18,"t":"Židovi ipak ne vjerovahu da on bijaše slijep i da je progledao dok ne dozvaše roditelje toga koji je progledao"},{"v":19,"t":"i upitaše ih: “Je li ovo vaš sin za kojega tvrdite da se slijep rodio? Kako sada vidi?”"},{"v":20,"t":"Njegovi roditelji odvrate: “Znamo da je ovo naš sin i da se slijep rodio."},{"v":21,"t":"A kako sada vidi, to mi ne znamo; i tko mu je otvorio oči, ne znamo. Njega pitajte! Punoljetan je: neka sam o sebi govori!”"},{"v":22,"t":"Rekoše tako njegovi roditelji jer su se bojali Židova. Židovi se doista već bijahu dogovorili da se iz sinagoge ima izopćiti svaki koji njega prizna Kristom."},{"v":23,"t":"Zbog toga rekoše njegovi roditelji: “Punoljetan je, njega pitajte!”"},{"v":24,"t":"Pozvaše stoga po drugi put čovjeka koji bijaše slijep i rekoše mu: “Podaj slavu Bogu! Mi znamo da je taj čovjek grešnik!”"},{"v":25,"t":"Nato im on odgovori: “Je li grešnik, ja ne znam. Jedno znam: slijep sam bio, a sada vidim.”"},{"v":26,"t":"Rekoše mu opet: “Što ti učini? Kako ti otvori oči?”"},{"v":27,"t":"Odgovori im: “Već vam rekoh i ne poslušaste me. Što opet hoćete čuti? Da ne kanite i vi postati njegovim učenicima?”"},{"v":28,"t":"Nato ga oni izgrdiše i rekoše: “Ti si njegov učenik, a mi smo učenici Mojsijevi."},{"v":29,"t":"Mi znamo da je Mojsiju govorio Bog, a za ovoga ne znamo ni odakle je.”"},{"v":30,"t":"Odgovori im čovjek: “Pa to i jest čudnovato da vi ne znate odakle je, a meni je otvorio oči."},{"v":31,"t":"Znamo da Bog grešnike ne uslišava; nego je li tko bogobojazan i vrši li njegovu volju, toga uslišava."},{"v":32,"t":"Odvijeka se nije čulo da bi tko otvorio oči slijepcu od rođenja."},{"v":33,"t":"Kad ovaj ne bi bio od Boga, ne bi mogao činiti ništa”."},{"v":34,"t":"Odgovore mu: “Sav si se u grijesima rodio, i ti nas da učiš?” i izbaciše ga."},{"v":35,"t":"Dočuo Isus da su onoga izbacili pa ga nađe i reče mu: “Ti vjeruješ u Sina Čovječjega?”"},{"v":36,"t":"On odgovori: “A tko je taj, Gospodine, da vjerujem u njega?”"},{"v":37,"t":"Reče mu Isus: “Vidio si ga! To je onaj koji govori s tobom!”"},{"v":38,"t":"A on reče: “Vjerujem, Gospodine!” I baci se ničice preda nj."},{"v":39,"t":"Tada Isus reče: “Radi suda dođoh na ovaj svijet: da progledaju koji ne vide, a koji vide, da oslijepe!”"},{"v":40,"t":"Čuli to neki od farizeja koji su bili s njime pa ga upitaju: “Zar smo i mi slijepi?”"},{"v":41,"t":"Isus im odgovori: “Da ste slijepi, ne biste imali grijeha. No vi govorite: 'Vidimo' pa grijeh vaš ostaje.”"}]},"10":{"hr":[{"v":1,"t":"“Zaista, zaista, kažem vam: tko god u ovčinjak ne ulazi na vrata, nego negdje drugdje preskače, kradljivac je i razbojnik."},{"v":2,"t":"A tko na vrata ulazi, pastir je ovaca."},{"v":3,"t":"Tome vratar otvara i ovce slušaju njegov glas. On ovce svoje zove imenom pa ih izvodi."},{"v":4,"t":"A kad sve svoje izvede, pred njima ide i ovce idu za njim jer poznaju njegov glas."},{"v":5,"t":"Za tuđincem, dakako, ne idu, već bježe od njega jer tuđinčeva glasa ne poznaju.”"},{"v":6,"t":"Isus im kaza tu poredbu, ali oni ne razumješe što im htjede time kazati."},{"v":7,"t":"Stoga im Isus ponovno reče: “Zaista, zaista, kažem vam: ja sam vrata ovcama."},{"v":8,"t":"Svi koji dođoše prije mene, kradljivci su i razbojnici; ali ih ovce ne poslušaše."},{"v":9,"t":"Ja sam vrata. Kroza me tko uđe, spasit će se: i ulazit će i izlaziti i pašu nalaziti."},{"v":10,"t":"Kradljivac dolazi samo da ukrade, zakolje i pogubi. Ja dođoh da život imaju, u izobilju da ga imaju.”"},{"v":11,"t":"“Ja sam pastir dobri. Pastir dobri život svoj polaže za ovce."},{"v":12,"t":"Najamnik - koji nije pastir i nije vlasnik ovaca - kad vidi vuka gdje dolazi, ostavlja ovce i bježi, a vuk ih grabi i razgoni:"},{"v":13,"t":"najamnik je i nije mu do ovaca."},{"v":14,"t":"Ja sam pastir dobri i poznajem svoje i mene poznaju moje,"},{"v":15,"t":"kao što mene poznaje Otac i ja poznajem Oca i život svoj polažem za ovce."},{"v":16,"t":"Imam i drugih ovaca, koje nisu iz ovog ovčinjaka. I njih treba da dovedem i glas će moj čuti i bit će jedno stado, jedan pastir."},{"v":17,"t":"Zbog toga me i ljubi Otac što polažem život svoj da ga opet uzmem."},{"v":18,"t":"Nitko mi ga ne oduzima, nego ja ga sam od sebe polažem. Vlast imam položiti ga, vlast imam opet uzeti ga. Tu zapovijed primih od Oca svoga.”"},{"v":19,"t":"Među Židovima ponovno nasta podvojenost zbog tih riječi."},{"v":20,"t":"Mnogi su od njih govorili: “Zloduha ima pa mahnita! Što ga slušate?”"},{"v":21,"t":"Drugi su govorili: “Nisu to riječi opsjednuta. Zar zloduh može slijepima oči otvoriti?”"},{"v":22,"t":"Svetkovao se tada u Jeruzalemu Blagdan posvećenja. Bila je zima."},{"v":23,"t":"Isus je obilazio Hramom po trijemu Salomonovu."},{"v":24,"t":"Okružili ga Židovi i govorili mu: “Dokle ćeš nam dušu držati u neizvjesnosti? Ako si ti Krist, reci nam otvoreno!”"},{"v":25,"t":"Isus im odgovori: “Rekoh vam pa ne vjerujete. Djela što ih ja činim u ime Oca svoga - ona svjedoče za mene."},{"v":26,"t":"Ali vi ne vjerujete jer niste od mojih ovaca."},{"v":27,"t":"Ovce moje slušaju glas moj; ja ih poznajem i one idu za mnom."},{"v":28,"t":"Ja im dajem život vječni te neće propasti nikada i nitko ih neće ugrabiti iz moje ruke."},{"v":29,"t":"Otac moj, koji mi ih dade, veći je od svih i nitko ih ne može ugrabiti iz ruke Očeve."},{"v":30,"t":"Ja i Otac jedno smo.”"},{"v":31,"t":"Židovi ponovno pograbiše kamenje da ga kamenuju."},{"v":32,"t":"Isus im odgovori: “Mnoga vam dobra djela Očeva pokazah. Za koje me od tih djela kamenujete?”"},{"v":33,"t":"Odgovoriše mu Židovi: “Zbog dobra te djela ne kamenujemo, nego zbog hule: što ti - čovjek - sebe Bogom praviš.”"},{"v":34,"t":"Odgovori im Isus: “Nije li pisano u vašem Zakonu: Ja rekoh: bogovi ste!"},{"v":35,"t":"Ako bogovima nazva one kojima je riječ Božja upravljena - a Pismo se ne može dokinuti -"},{"v":36,"t":"kako onda vi onome kog Otac posveti i posla na svijet možete reći: 'Huliš!' - zbog toga što rekoh: 'Sin sam Božji!'"},{"v":37,"t":"Ako ne činim djela Oca svoga, nemojte mi vjerovati."},{"v":38,"t":"Ali ako činim, sve ako meni i ne vjerujete, djelima vjerujte pa uvidite i upoznajte da je Otac u meni i ja u Ocu.”"},{"v":39,"t":"Nato ga ponovno nastojahu uhvatiti, ali im on izmaknu iz ruku."},{"v":40,"t":"I ode ponovno na onu stranu Jordana - na mjesto gdje je prije Ivan krstio. I osta ondje."},{"v":41,"t":"A mnogi dođoše k njemu i rekoše mu: “Ivan doduše ne učini nijednog znamenja, ali se sve obistinilo što je rekao o ovome.”"},{"v":42,"t":"Mnogi ondje povjerovaše u njega."}]},"11":{"hr":[{"v":1,"t":"Bijaše neki bolesnik, Lazar iz Betanije, iz sela Marije i sestre joj Marte."},{"v":2,"t":"Marija bijaše ono pomazala Gospodina pomašću i otrla mu noge svojom kosom. Njezin dakle brat Lazar bijaše bolestan."},{"v":3,"t":"Sestre stoga poručiše Isusu: “Gospodine, evo onaj koga ljubiš, bolestan je.”"},{"v":4,"t":"Čuvši to, Isus reče: “Ta bolest nije na smrt, nego na slavu Božju, da se po njoj proslavi Sin Božji.”"},{"v":5,"t":"A Isus ljubljaše Martu i njezinu sestru i Lazara."},{"v":6,"t":"Ipak, kad je čuo za njegovu bolest, ostade još dva dana u onome mjestu gdje se nalazio."},{"v":7,"t":"Istom nakon toga reče učenicima: “Pođimo opet u Judeju!”"},{"v":8,"t":"Kažu mu učenici: “Učitelju, Židovi su sad tražili da te kamenuju, pa da opet ideš onamo?”"},{"v":9,"t":"Odgovori Isus: “Nema li dan dvanaest sati? Hodi li tko danju, ne spotiče se jer vidi svjetlost ovoga svijeta."},{"v":10,"t":"Hodi li tko noću, spotiče se jer nema svjetlosti u njemu.”"},{"v":11,"t":"To reče, a onda im dometnu: “Lazar, prijatelj naš, spava, no idem probuditi ga.”"},{"v":12,"t":"Rekoše mu nato učenici: “Gospodine, ako spava, ozdravit će.”"},{"v":13,"t":"No Isus to reče o njegovoj smrti, a oni pomisliše da govori o spavanju, o snu."},{"v":14,"t":"Tada im Isus reče posve otvoreno: “Lazar je umro."},{"v":15,"t":"Ja se radujem što ne bijah ondje, i to poradi vas - da uzvjerujete. Nego pođimo k njemu!”"},{"v":16,"t":"Nato Toma zvani Blizanac reče suučenicima: “Hajdemo i mi da umremo s njime!”"},{"v":17,"t":"Kad je dakle Isus stigao, nađe da je onaj već četiri dana u grobu."},{"v":18,"t":"Betanija bijaše blizu Jeruzalema otprilike petnaest stadija."},{"v":19,"t":"A mnogo Židova bijaše došlo tješiti Martu i Mariju zbog brata njihova."},{"v":20,"t":"Kad Marta doču da Isus dolazi, pođe mu u susret dok je Marija ostala u kući."},{"v":21,"t":"Marta reče Isusu: “Gospodine, da si bio ovdje, brat moj ne bi umro."},{"v":22,"t":"Ali i sada znam: što god zaišteš od Boga, dat će ti.”"},{"v":23,"t":"Kaza joj Isus: “Uskrsnut će brat tvoj!”"},{"v":24,"t":"A Marta mu odgovori: “Znam da će uskrsnuti o uskrsnuću, u posljednji dan.”"},{"v":25,"t":"Reče joj Isus: “Ja sam uskrsnuće i život: tko u mene vjeruje, ako i umre, živjet će."},{"v":26,"t":"I tko god živi i vjeruje u mene, neće umrijeti nikada. Vjeruješ li ovo?”"},{"v":27,"t":"Odgovori mu: “Da, Gospodine! Ja vjerujem da si ti Krist, Sin Božji, Onaj koji dolazi na svijet!”"},{"v":28,"t":"Rekavši to ode, zovnu svoju sestru Mariju i reče joj krišom: “Učitelj je ovdje i zove te.”"},{"v":29,"t":"A ona, čim doču, brzo ustane i pođe k njemu."},{"v":30,"t":"Isus još ne bijaše ušao u selo, nego je dotada bio na mjestu gdje ga je Marta susrela."},{"v":31,"t":"Kad Židovi, koji su s Marijom bili u kući i tješili je, vidješe kako je brzo ustala i izišla, pođoše za njom; mišljahu da ide na grob plakati."},{"v":32,"t":"A kad Marija dođe onamo gdje bijaše Isus i kad ga ugleda, baci mu se k nogama govoreći: “Gospodine, da si bio ovjde, brat moj ne bi umro.”"},{"v":33,"t":"Kad Isus vidje kako plače ona i Židovi koji je dopratiše, potresen u duhu i uzbuđen"},{"v":34,"t":"upita: “Kamo ste ga položili?” Odgovoriše mu: “Gospodine, dođi i pogledaj!”"},{"v":35,"t":"I zaplaka Isus."},{"v":36,"t":"Nato su Židovi govorili: “Gle, kako ga je ljubio!”"},{"v":37,"t":"A neki između njih rekoše: “Zar on, koji je slijepcu otvorio oči, nije mogao učiniti da ovaj ne umre?”"},{"v":38,"t":"Isus onda, ponovno potresen, pođe grobu. Bila je to pećina, a na nju navaljen kamen."},{"v":39,"t":"Isus zapovjedi: “Odvalite kamen!” Kaže mu pokojnikova sestra Marta: “Gospodine, već zaudara. Ta četvrti je dan.”"},{"v":40,"t":"Kaže joj Isus: “Nisam li ti rekao: budeš li vjerovala, vidjet ćeš slavu Božju?”"},{"v":41,"t":"Odvališe dakle kamen. A Isus podiže oči i reče: “Oče, hvala ti što si me uslišao."},{"v":42,"t":"Ja sam znao da me svagda uslišavaš; no rekoh to zbog nazočnog mnoštva: da vjeruju da si me ti poslao.”"},{"v":43,"t":"Rekavši to povika iza glasa: “Lazare, izlazi!”"},{"v":44,"t":"I mrtvac iziđe, noge mu i ruke bile povezane povojima, a lice omotano ručnikom. Nato Isus reče: “Odriješite ga i pustite neka ide!”"},{"v":45,"t":"Tada mnogi Židovi koji bijahu došli k Mariji, kad vidješe što Isus učini, povjerovaše u nj."},{"v":46,"t":"A neki od njih odu farizejima i pripovjede im što Isus učini."},{"v":47,"t":"Stoga glavari svećenički i farizeji sazvaše Vijeće. Govorili su: “Što da radimo? Ovaj čovjek čini mnoga znamenja."},{"v":48,"t":"Ako ga pustimo tako, svi će povjerovati u nj pa će doći Rimljani i oduzeti nam ovo mjesto i narod!”"},{"v":49,"t":"A jedan od njih - Kajfa, veliki svećenik one godine - reče im: “Vi ništa ne znate."},{"v":50,"t":"I ne mislite kako je za vas bolje da jedan čovjek umre za narod, nego da sav narod propadne!”"},{"v":51,"t":"To ne reče sam od sebe, nego kao veliki svećenik one godine prorokova da Isus ima umrijeti za narod;"},{"v":52,"t":"ali ne samo za narod nego i zato da raspršene sinove Božje skupi u jedno."},{"v":53,"t":"Toga dana dakle odluče da ga ubiju."},{"v":54,"t":"Zbog toga se Isus više nije javno kretao među Židovima, nego je odatle otišao u kraj blizu pustinje, u grad koji se zove Efrajim. Tu se zadržavao s učenicima."},{"v":55,"t":"Bijaše blizu židovska Pasha i mnogi iz toga kraja uziđoše prije Pashe u Jeruzalem da se očiste."},{"v":56,"t":"Iskahu dakle Isusa te se stojeći u Hramu zapitkivahu: “Što vam se čini? Zar on ne kani doći na Blagdan?”"},{"v":57,"t":"A glavari svećenički i farizeji izdadoše naredbu: ako tko sazna gdje je, neka dojavi da ga uhvate."}]},"12":{"hr":[{"v":1,"t":"Šest dana prije Pashe dođe Isus u Betaniju gdje bijaše Lazar koga je Isus uskrisio od mrtvih."},{"v":2,"t":"Ondje mu prirediše večeru. Marta posluživaše, a Lazar bijaše jedan od njegovih sustolnika."},{"v":3,"t":"Tada Marija uzme libru prave dragocjene nardove pomasti, pomaže Isusu noge i otare ih svojom kosom. I sva se kuća napuni mirisom pomasti."},{"v":4,"t":"Nato reče Juda Iškariotski, jedan od njegovih učenika, onaj koji ga je imao izdati:"},{"v":5,"t":"“Zašto se ta pomast nije prodala za trista denara i razdala siromasima?”"},{"v":6,"t":"To ne reče zbog toga što mu bijaše stalo do siromaha, nego što bijaše kradljivac: kako je imao kesu, kradom je uzimao što se u nju stavljalo."},{"v":7,"t":"Nato Isus odvrati: “Pusti je! Neka to izvrši za dan mog ukopa!"},{"v":8,"t":"Jer siromahe imate uvijek uza se, a mene nemate uvijek.”"},{"v":9,"t":"Silno mnoštvo Židova dozna da je Isus ondje pa se okupi, ne samo zbog Isusa, već i zato da vide Lazara kojega on bijaše uskrisio od mrtvih."},{"v":10,"t":"A glavari svećenički odlučiše i Lazara ubiti"},{"v":11,"t":"jer su zbog njega mnogi Židovi odlazili i vjerovali u Isusa."},{"v":12,"t":"Kad je sutradan silan svijet koji dođe na Blagdan čuo da Isus dolazi u Jeruzalem,"},{"v":13,"t":"uze palmove grančice i iziđe mu u susret. Vikahu: “Hosana! Blagoslovljen Onaj koji dolazi u ime Gospodnje! Kralj Izraelov.”"},{"v":14,"t":"A Isus nađe magarčića i sjede na nj kao što je pisano:"},{"v":15,"t":"Ne boj se, kćeri Sionska! Evo, kralj tvoj dolazi jašuć na mladetu magaričinu!"},{"v":16,"t":"To učenici njegovi isprva ne razumješe. Ali pošto je Isus bio proslavljen, prisjetiše se da je to bilo o njemu napisano i da mu baš to učiniše."},{"v":17,"t":"Mnoštvo koje bijaše s njime kad Lazara pozva iz groba i uskrisi od mrtvih pronosilo je svjedočanstvo o tome."},{"v":18,"t":"Stoga mu je i izišao u susret silan svijet: pročulo se da je on učinio to znamenje."},{"v":19,"t":"Farizeji nato rekoše među sobom: “Vidite da ništa ne postižete. Eno, svijet ode za njim!”"},{"v":20,"t":"A među onima koji su se došli klanjati na Blagdan bijahu i neki Grci."},{"v":21,"t":"Oni pristupe Filipu iz Betsaide galilejske pa ga zamole: “Gospodine, htjeli bismo vidjeti Isusa.”"},{"v":22,"t":"Filip ode i kaže to Andriji pa Andrija i Filip odu i kažu Isusu."},{"v":23,"t":"Isus im odgovori: “Došao je čas da se proslavi Sin Čovječji."},{"v":24,"t":"Zaista, zaista, kažem vam: ako pšenično zrno, pavši na zemlju, ne umre, ostaje samo; ako li umre, donosi obilat rod."},{"v":25,"t":"Tko ljubi svoj život, izgubit će ga. A tko mrzi svoj život na ovome svijetu, sačuvat će ga za život vječni."},{"v":26,"t":"Ako mi tko hoće služiti, neka ide za mnom. I gdje sam ja, ondje će biti i moj služitelj. Ako mi tko hoće služiti, počastit će ga moj Otac.”"},{"v":27,"t":"“Duša mi je sada potresena i što da kažem? Oče, izbavi me iz ovoga časa? No, zato dođoh u ovaj čas!"},{"v":28,"t":"Oče, proslavi ime svoje!” Uto dođe glas s neba: “Proslavio sam i opet ću proslaviti!”"},{"v":29,"t":"Mnoštvo koje je ondje stajalo i slušalo govoraše: “Zagrmjelo je!” Drugi govorahu: “Anđeo mu je zborio.”"},{"v":30,"t":"Isus na to reče: “Ovaj glas nije bio poradi mene, nego poradi vas.”"},{"v":31,"t":"“Sada je sud ovomu svijetu, sada će knez ovoga svijeta biti izbačen."},{"v":32,"t":"A ja kad budem uzdignut sa zemlje, sve ću privući k sebi.”"},{"v":33,"t":"To reče da označi kakvom će smrću umrijeti."},{"v":34,"t":"Nato mu mnoštvo odgovori: “Mi smo iz Zakona čuli da Krist ostaje zauvijek. Kako onda ti govoriš da Sin Čovječji treba da bude uzdignut? Tko je taj Sin Čovječji?”"},{"v":35,"t":"Isus im nato reče: “Još je malo vremena svjetlost među vama. Hodite dok imate svjetlost da vas ne obuzme tama. Tko hodi u tami, ne zna kamo ide."},{"v":36,"t":"Dok imate svjetlost, vjerujte u svjetlost da budete sinovi svjetlosti!” To Isus doreče, a onda ode i sakri se od njih."},{"v":37,"t":"Iako je Isus pred njima učinio tolika znamenja, oni ne povjerovaše u njega,"},{"v":38,"t":"da se ispuni riječ koju kaza prorok Izaija: Gospodine! Tko povjerova našoj poruci? Kome li se otkri ruka Gospodnja?"},{"v":39,"t":"Stoga i ne mogahu vjerovati, jer Izaija dalje kaže:"},{"v":40,"t":"Zaslijepi im oči, stvrdnu srca; da očima ne vide, srcem ne razumiju te se ne obrate pa ih ozdravim."},{"v":41,"t":"Reče to Izaija jer je vidio slavu njegovu te o njemu zborio."},{"v":42,"t":"Ipak, mnogi su i od glavara vjerovali u njega, ali zbog farizeja nisu to priznavali: da ne budu izopćeni iz sinagoge."},{"v":43,"t":"Jer više im je bilo do slave ljudske, nego do slave Božje."},{"v":44,"t":"A Isus povika: “Tko u mene vjeruje, ne vjeruje u mene, nego u onoga koji me posla;"},{"v":45,"t":"i tko vidi mene, vidi onoga koji me posla."},{"v":46,"t":"Ja - Svjetlost - dođoh na svijet da nijedan koji u mene vjeruje u tami ne ostane."},{"v":47,"t":"I sluša li tko moje riječi, a ne čuva ih, ja ga ne sudim. Ja nisam došao suditi svijetu, nego svijet spasiti."},{"v":48,"t":"Tko mene odbacuje i riječi mojih ne prima, ima svoga suca: riječ koju sam zborio - ona će mu suditi u posljednji dan."},{"v":49,"t":"Jer nisam ja zborio sam od sebe, nego onaj koji me posla - Otac - on mi dade zapovijed što da kažem, što da zborim."},{"v":50,"t":"I znam: zapovijed njegova jest život vječni. Što ja dakle zborim, tako zborim kako mi je rekao Otac.”"}]},"13":{"hr":[{"v":1,"t":"Bijaše pred blagdan Pashe. Isus je znao da je došao njegov čas da prijeđe s ovoga svijeta Ocu, budući da je ljubio svoje, one u svijetu, do kraja ih je ljubio."},{"v":2,"t":"I za večerom je đavao već bio ubacio u srce Judi Šimuna Iškariotskoga da ga izda."},{"v":3,"t":"A Isus je znao da mu je Otac sve predao u ruke i da je od Boga izišao te da k Bogu ide pa"},{"v":4,"t":"usta od večere, odloži haljine, uze ubrus i opasa se."},{"v":5,"t":"Nalije zatim vodu u praonik i počne učenicima prati noge i otirati ih ubrusom kojim je bio opasan."},{"v":6,"t":"Dođe tako do Šimuna Petra. A on će mu: “Gospodine! Zar ti da meni pereš noge?”"},{"v":7,"t":"Odgovori mu Isus: “Što ja činim, ti sada ne znaš, ali shvatit ćeš poslije.”"},{"v":8,"t":"Reče mu Petar: “Nećeš mi prati nogu nikada!” Isus mu odvrati: “Ako te ne operem, nećeš imati dijela sa mnom.”"},{"v":9,"t":"Nato će mu Šimun Petar: “Gospodine, onda ne samo noge, nego i ruke i glavu!”"},{"v":10,"t":"Kaže mu Isus: “Tko je okupan, ne treba drugo da opere nego noge - i sav je čist! I vi ste čisti, ali ne svi!”"},{"v":11,"t":"Jer znao je tko će ga izdati. Stoga je i rekao: “Niste svi čisti.”"},{"v":12,"t":"Kad im dakle opra noge, uze svoje haljine, opet sjede i reče im: “Razumijete li što sam vam učinio?"},{"v":13,"t":"Vi me zovete Učiteljem i Gospodinom. Pravo velite jer to i jesam!"},{"v":14,"t":"Ako dakle ja - Gospodin i Učitelj - vama oprah noge, treba da i vi jedni drugima perete noge."},{"v":15,"t":"Primjer sam vam dao da i vi činite kao što ja vama učinih.”"},{"v":16,"t":"Zaista, zaista, kažem vam: nije sluga veći od gospodara niti poslanik od onoga koji ga posla."},{"v":17,"t":"Ako to znate, blago vama budete li tako i činili!”"},{"v":18,"t":"“Ne govorim o svima vama! Ja znam koje izabrah! Ali - neka se ispuni Pismo: Koji blaguje kruh moj, petu na me podiže.”"},{"v":19,"t":"“Već vam sada kažem, prije negoli se dogodi, da kad se dogodi vjerujete da Ja jesam."},{"v":20,"t":"Zaista, zaista, kažem vam: Tko primi onoga kojega ja šaljem, mene prima. A tko mene primi, prima onoga koji je mene poslao.”"},{"v":21,"t":"Rekavši to, potresen u duhu Isus posvjedoči: “Zaista, zaista, kažem vam: jedan će me od vas izdati!”"},{"v":22,"t":"Učenici se zgledahu među sobom u nedoumici o kome to govori."},{"v":23,"t":"A jedan od njegovih učenika - onaj kojega je Isus ljubio - bijaše za stolom Isusu do krila."},{"v":24,"t":"Šimun Petar dade mu znak i reče: “Pitaj tko je taj o kome govori.”"},{"v":25,"t":"Ovaj se privine Isusu uz prsa i upita: “Gospodine, tko je taj?”"},{"v":26,"t":"Isus odgovori: “Onaj je kome ja dadnem umočen zalogaj.”"},{"v":27,"t":"Tada umoči zalogaj, uze ga i dade Judi Šimuna Iškariotskoga. Nakon zalogaja uđe u nj Sotona. Nato mu Isus reče: “Što činiš, učini brzo!”"},{"v":28,"t":"Nijedan od sustolnika nije razumio zašto mu je to rekao."},{"v":29,"t":"Budući da je Juda imao kesu, neki su mislili da mu je Isus rekao: “Kupi što nam treba za blagdan!” - ili neka poda nešto siromasima."},{"v":30,"t":"On dakle uzme zalogaj i odmah iziđe. A bijaše noć."},{"v":31,"t":"Pošto Juda iziđe, reče Isus: “Sada je proslavljen Sin Čovječji i Bog se proslavio u njemu!"},{"v":32,"t":"Ako se Bog proslavio u njemu, i njega će Bog proslaviti u sebi, i uskoro će ga proslaviti!"},{"v":33,"t":"Dječice, još sam malo s vama. Tražit ćete me, ali kao što rekoh Židovima, kažem sada i vama: kamo ja odlazim, vi ne možete doći."},{"v":34,"t":"Zapovijed vam novu dajem: ljubite jedni druge; kao što sam ja ljubio vas tako i vi ljubite jedni druge."},{"v":35,"t":"Po ovom će svi znati da ste moji učenici: ako budete imali ljubavi jedni za druge.”"},{"v":36,"t":"Kaže mu Šimun Petar: “Gospodine, kamo to odlaziš?” Isus mu odgovori: “Kamo ja odlazim, ti zasad ne možeš poći za mnom. No poći ćeš poslije.”"},{"v":37,"t":"Nato će mu Petar: “Gospodine, a zašto sada ne bih mogao poći za tobom? Život ću svoj položiti za tebe!”"},{"v":38,"t":"Odgovori Isus: “Život ćeš svoj položiti za mene? Zaista, zaista, kažem ti: Pijetao neće zapjevati dok me triput ne zatajiš.”"}]},"14":{"hr":[{"v":1,"t":"“Neka se ne uznemiruje srce vaše! Vjerujte u Boga i u mene vjerujte!"},{"v":2,"t":"U domu Oca mojega ima mnogo stanova. Da nema, zar bih vam rekao: 'Idem pripraviti vam mjesto'?"},{"v":3,"t":"Kad odem i pripravim vam mjesto, ponovno ću doći i uzeti vas k sebi da i vi budete gdje sam ja."},{"v":4,"t":"A kamo ja odlazim, znate put.”"},{"v":5,"t":"Reče mu Toma: “Gospodine, ne znamo kamo odlaziš. Kako onda možemo put znati?”"},{"v":6,"t":"Odgovori mu Isus: “Ja sam Put i Istina i Život: nitko ne dolazi Ocu osim po meni."},{"v":7,"t":"Da ste upoznali mene, i Oca biste moga upoznali. Od sada ga i poznajete i vidjeli ste ga.”"},{"v":8,"t":"Kaže mu Filip: “Gospodine, pokaži nam Oca i dosta nam je!”"},{"v":9,"t":"Nato će mu Isus: “Filipe, toliko sam vremena s vama i još me ne poznaš?” “Tko je vidio mene, vidio je i Oca. Kako ti onda kažeš: 'Pokaži nam Oca'?"},{"v":10,"t":"Ne vjeruješ li da sam ja u Ocu i Otac u meni? Riječi koje vam govorim, od sebe ne govorim: Otac koji prebiva u meni čini djela svoja."},{"v":11,"t":"Vjerujte mi: ja sam u Ocu i Otac u meni. Ako ne inače, zbog samih djela vjerujte."},{"v":12,"t":"Zaista, zaista, kažem vam: Tko vjeruje u mene, činit će djela koja ja činim; da veća će od njih činiti jer ja odlazim Ocu."},{"v":13,"t":"I što god zaištete u moje ime, učinit ću, da se proslavi Otac u Sinu."},{"v":14,"t":"Ako me što zaištete u moje ime, učinit ću.”"},{"v":15,"t":"“Ako me ljubite, zapovijedi ćete moje čuvati."},{"v":16,"t":"I ja ću moliti Oca i on će vam dati drugoga Branitelja da bude s vama zauvijek:"},{"v":17,"t":"Duha Istine, kojega svijet ne može primiti jer ga ne vidi i ne poznaje. Vi ga poznajete jer kod vas ostaje i u vama je."},{"v":18,"t":"Neću vas ostaviti kao siročad; doći ću k vama."},{"v":19,"t":"Još malo i svijet me više neće vidjeti, no vi ćete me vidjeti jer ja živim i vi ćete živjeti."},{"v":20,"t":"U onaj ćete dan spoznati da sam ja u Ocu svom i vi u meni i ja u vama."},{"v":21,"t":"Tko ima moje zapovijedi i čuva ih, taj me ljubi; a tko mene ljubi, njega će ljubiti Otac moj, i ja ću ljubiti njega i njemu se očitovati.”"},{"v":22,"t":"Kaže mu Juda, ne Iškariotski: “Gospodine, kako to da ćeš se očitovati nama, a ne svijetu?”"},{"v":23,"t":"Odgovori mu Isus: “Ako me tko ljubi, čuvat će moju riječ pa će i Otac moj ljubiti njega i k njemu ćemo doći i kod njega se nastaniti."},{"v":24,"t":"Tko mene ne ljubi, riječi mojih ne čuva. A riječ koju slušate nije moja, nego Oca koji me posla."},{"v":25,"t":"To sam vam govorio dok sam boravio s vama."},{"v":26,"t":"Branitelj - Duh Sveti, koga će Otac poslati u moje ime, poučavat će vas o svemu i dozivati vam u pamet sve što vam ja rekoh."},{"v":27,"t":"Mir vam ostavljam, mir vam svoj dajem. Dajem vam ga, ali ne kao što svijet daje. Neka se ne uznemiruje vaše srce i neka se ne straši."},{"v":28,"t":"Čuli ste, rekoh vam: 'Odlazim i vraćam se k vama.' Kad biste me ljubili, radovali biste se što idem Ocu jer Otac je veći od mene."},{"v":29,"t":"Kazao sam vam to sada, prije negoli se dogodi, da vjerujete kad se dogodi."},{"v":30,"t":"Neću više s vama mnogo govoriti jer dolazi knez svijeta. Protiv mene ne može on ništa."},{"v":31,"t":"Ali neka svijet upozna da ja ljubim Oca i da tako činim kako mi je zapovjedio Otac. Ustanite, pođimo odavde!”"}]},"15":{"hr":[{"v":1,"t":"“Ja sam istinski trs, a Otac moj - vinogradar."},{"v":2,"t":"Svaku lozu na meni koja ne donosi roda on siječe, a svaku koja rod donosi čisti da više roda donese."},{"v":3,"t":"Vi ste već očišćeni po riječi koju sam vam zborio."},{"v":4,"t":"Ostanite u meni i ja u vama. Kao što loza ne može donijeti roda sama od sebe, ako ne ostane na trsu, tako ni vi ako ne ostanete u meni."},{"v":5,"t":"Ja sam trs, vi loze. Tko ostaje u meni i ja u njemu, taj donosi mnogo roda. Uistinu, bez mene ne možete učiniti ništa."},{"v":6,"t":"Ako tko ne ostane u meni, izbace ga kao lozu i usahne. Takve onda skupe i bace u oganj te gore."},{"v":7,"t":"Ako ostanete u meni i riječi moje ako ostanu u vama, što god hoćete, ištite i bit će vam."},{"v":8,"t":"Ovim se proslavlja Otac moj: da donosite mnogo roda i da budete moji učenici."},{"v":9,"t":"Kao što je Otac ljubio mene tako sam i ja ljubio vas; ostanite u mojoj ljubavi."},{"v":10,"t":"Budete li čuvali moje zapovijedi, ostat ćete u mojoj ljubavi; kao što sam i ja čuvao zapovijedi Oca svoga te ostajem u ljubavi njegovoj."},{"v":11,"t":"To sam vam govorio da moja radost bude u vama i da vaša radost bude potpuna."},{"v":12,"t":"Ovo je moja zapovijed: ljubite jedni druge kao što sam ja vas ljubio!"},{"v":13,"t":"Veće ljubavi nitko nema od ove: da tko život svoj položi za svoje prijatelje."},{"v":14,"t":"Vi ste prijatelji moji ako činite što vam zapovijedam."},{"v":15,"t":"Više vas ne zovem slugama jer sluga ne zna što radi njegov gospodar; vas sam nazvao prijateljima jer vam priopćih sve što sam čuo od Oca svoga."},{"v":16,"t":"Ne izabraste vi mene, nego ja izabrah vas i postavih vas da idete i rod donosite i rod vaš da ostane te vam Otac dadne što ga god zaištete u moje ime."},{"v":17,"t":"Ovo vam zapovijedam: da ljubite jedni druge.”"},{"v":18,"t":"“Ako vas svijet mrzi, znajte da je mene mrzio prije nego vas."},{"v":19,"t":"Kad biste bili od svijeta, svijet bi svoje ljubio; no budući da niste od svijeta, nego sam vas ja izabrao iz svijeta, zbog toga vas svijet mrzi."},{"v":20,"t":"Sjećajte se riječi koju vam rekoh: 'Nije sluga veći od svoga gospodara.' Ako su mene progonili, i vas će progoniti; ako su moju riječ čuvali, da vašu će čuvati."},{"v":21,"t":"A sve će to poduzimati protiv vas poradi imena moga jer ne znaju onoga koji mene posla."},{"v":22,"t":"Da nisam došao i da im nisam govorio, ne bi imali grijeha; no sada nemaju izgovora za svoj grijeh."},{"v":23,"t":"Tko mene mrzi, mrzi i Oca mojega."},{"v":24,"t":"Da nisam učinio među njima djela kojih nitko drugi ne čini, ne bi imali grijeha; a sada vidješe pa ipak zamrziše i mene i Oca mojega."},{"v":25,"t":"No neka se ispuni riječ napisana u njihovu Zakonu: Mrze me nizašto."},{"v":26,"t":"A kada dođe Branitelj koga ću vam poslati od Oca - Duh Istine koji od Oca izlazi - on će svjedočiti za mene."},{"v":27,"t":"I vi ćete svjedočiti jer ste od početka sa mnom."}]},"16":{"hr":[{"v":1,"t":"To sam vam govorio da se ne sablaznite."},{"v":2,"t":"Izopćavat će vas iz sinagoga. Štoviše, dolazi čas kad će svaki koji vas ubije misliti da služi Bogu."},{"v":3,"t":"A to će činiti jer ne upoznaše ni Oca ni mene."},{"v":4,"t":"Govorio sam vam ovo da se, kada dođe vrijeme, sjetite da sam vam rekao.” “S početka vam ne rekoh ovo jer bijah s vama."},{"v":5,"t":"A sada odlazim k onome koji me posla i nitko me od vas ne pita: 'Kamo ideš?'"},{"v":6,"t":"Naprotiv, žalošću se ispunilo vaše srce što vam ovo kazah."},{"v":7,"t":"No kažem vam istinu: bolje je za vas da ja odem: jer ako ne odem, Branitelj neće doći k vama; ako pak odem, poslat ću ga k vama."},{"v":8,"t":"A kad on dođe, pokazat će svijetu što je grijeh, što li pravednost, a što osuda:"},{"v":9,"t":"grijeh je što ne vjeruju u mene;"},{"v":10,"t":"pravednost - što odlazim k Ocu i više me ne vidite;"},{"v":11,"t":"a osuda - što je knez ovoga svijeta osuđen."},{"v":12,"t":"Još vam mnogo imam kazati, ali sada ne možete nositi."},{"v":13,"t":"No kada dođe on - Duh Istine - upućivat će vas u svu istinu; jer neće govoriti sam od sebe, nego će govoriti što čuje i navješćivat će vam ono što dolazi."},{"v":14,"t":"On će mene proslavljati jer će od mojega uzimati i navješćivati vama."},{"v":15,"t":"Sve što ima Otac, moje je. Zbog toga vam rekoh: od mojega uzima i - navješćivat će vama.”"},{"v":16,"t":"“Malo, i više me nećete vidjeti; i opet malo, pa ćete me vidjeti.”"},{"v":17,"t":"Nato se neki od učenika zapitkivahu: “Što je to što nam kaže: 'Malo, i nećete me vidjeti, i opet malo, pa ćete me vidjeti' i 'Odlazim Ocu'?”"},{"v":18,"t":"Govorahu dakle: “Što je to što kaže 'Malo'? Ne znamo što govori.”"},{"v":19,"t":"Isus spozna da su ga htjeli pitati pa im reče: “Pitate se među sobom o tome što kazah: 'Malo, i nećete me vidjeti; i opet malo, pa ćete me vidjeti'?"},{"v":20,"t":"Zaista, zaista, kažem vam: vi ćete plakati i jaukati, a svijet će se veseliti. Vi ćete se žalostiti, ali žalost će se vaša okrenuti u radost."},{"v":21,"t":"Žena kad rađa, žalosna je jer je došao njezin čas; ali kad rodi djetešce, ne spominje se više muke od radosti što se čovjek rodio na svijet."},{"v":22,"t":"Tako dakle i vi: sad ste u žalosti, no ja ću vas opet vidjeti; i srce će vam se radovati i radosti vaše nitko vam oteti neće."},{"v":23,"t":"U onaj me dan nećete ništa više pitati. Zaista, zaista, kažem vam: što god zaištete u Oca, dat će vam u moje ime."},{"v":24,"t":"Dosad niste iskali ništa u moje ime. Ištite i primit ćete da radost vaša bude potpuna!”"},{"v":25,"t":"“To sam vam govorio u poredbama. Dolazi čas kad vam više neću govoriti u poredbama, nego ću vam otvoreno navješćivati Oca."},{"v":26,"t":"U onaj dan iskat ćete u moje ime i ne velim vam da ću ja moliti Oca za vas."},{"v":27,"t":"Ta sam vas Otac ljubi jer vi ste mene ljubili i vjerovali da sam ja od Boga izišao."},{"v":28,"t":"Izišao sam od Oca i došao na svijet. Opet ostavljam svijet i odlazim Ocu.”"},{"v":29,"t":"Kažu mu učenici: “Evo, sad otvoreno zboriš i nikakvon se poredbom ne služiš."},{"v":30,"t":"Sada znamo da sve znaš i ne treba da te tko pita. Stoga vjerujemo da si izišao od Boga.”"},{"v":31,"t":"Odgovori im Isus: “Sada vjerujete?"},{"v":32,"t":"Evo dolazi čas i već je došao: raspršit ćete se svaki na svoju stranu i mene ostaviti sama. No ja nisam sam jer Otac je sa mnom."},{"v":33,"t":"To vam rekoh da u meni mir imate. U svijetu imate muku, ali hrabri budite - ja sam pobijedio svijet!”"}]},"17":{"hr":[{"v":1,"t":"To Isus doreče, a onda podiže oči k nebu i progovori: “Oče, došao je čas: proslavi Sina svoga da Sin proslavi tebe"},{"v":2,"t":"i da vlašću koju si mu dao nad svakim tijelom dade život vječni svima koje si mu dao."},{"v":3,"t":"A ovo je život vječni: da upoznaju tebe, jedinoga istinskog Boga, i koga si poslao - Isusa Krista."},{"v":4,"t":"Ja tebe proslavih na zemlji dovršivši djelo koje si mi dao izvršiti."},{"v":5,"t":"A sada ti, Oče, proslavi mene kod sebe onom slavom koju imadoh kod tebe prije negoli je svijeta bilo."},{"v":6,"t":"Objavio sam ime tvoje ljudima koje si mi dao od svijeta. Tvoji bijahu, a ti ih meni dade i riječ su tvoju sačuvali."},{"v":7,"t":"Sad upoznaše da je od tebe sve što si mi dao"},{"v":8,"t":"jer riječi koje si mi dao njima predadoh i oni ih primiše i uistinu spoznaše da sam od tebe izišao te povjerovaše da si me ti poslao."},{"v":9,"t":"Ja za njih molim; ne molim za svijet, nego za one koje si mi dao jer su tvoji."},{"v":10,"t":"I sve moje tvoje je, i tvoje moje, i ja se proslavih u njima."},{"v":11,"t":"Ja više nisam u svijetu, no oni su u svijetu, a ja idem k tebi. Oče sveti, sačuvaj ih u svom imenu koje si mi dao: da budu jedno kao i mi."},{"v":12,"t":"Dok sam ja bio s njima, ja sam ih čuvao u tvom imenu, njih koje si mi dao; i štitio ih, te nijedan od njih ne propade osim sina propasti, da se Pismo ispuni."},{"v":13,"t":"A sada k tebi idem i ovo govorim u svijetu da imaju puninu moje radosti u sebi."},{"v":14,"t":"Ja sam im predao tvoju riječ, a svijet ih zamrzi jer nisu od svijeta kao što ni ja nisam od svijeta."},{"v":15,"t":"Ne molim te da ih uzmeš sa svijeta, nego da ih očuvaš od Zloga."},{"v":16,"t":"Oni nisu od svijeta kao što ni ja nisam od svijeta."},{"v":17,"t":"Posveti ih u istini: tvoja je riječ istina."},{"v":18,"t":"Kao što ti mene posla u svijet tako i ja poslah njih u svijet."},{"v":19,"t":"I za njih posvećujem samog sebe da i oni budu posvećeni u istini."},{"v":20,"t":"Ne molim samo za ove nego i za one koji će na njihovu riječ vjerovati u mene:"},{"v":21,"t":"da svi budu jedno kao što ti, Oče, u meni i ja u tebi, neka i oni u nama budu da svijet uzvjeruje da si me ti poslao."},{"v":22,"t":"I slavu koju si ti dao meni ja dadoh njima: da budu jedno kao što smo mi jedno -"},{"v":23,"t":"ja u njima i ti u meni, da tako budu savršeno jedno da svijet upozna da si me ti poslao i ljubio njih kao što si mene ljubio."},{"v":24,"t":"Oče, hoću da i oni koje si mi dao budu gdje sam ja, da i oni budu sa mnom: da gledaju moju slavu, slavu koju si mi dao jer si me ljubio prije postanka svijeta."},{"v":25,"t":"Oče pravedni, svijet te nije upoznao, ja te upoznah; a i ovi upoznaše da si me ti poslao."},{"v":26,"t":"I njima sam očitovao tvoje ime, i još ću očitovati, da ljubav kojom si ti mene ljubio bude u njima - i ja u njima.”"}]},"18":{"hr":[{"v":1,"t":"To rekavši, zaputi se Isus sa svojim učenicima na drugu stranu potoka Cedrona. Ondje bijaše vrt u koji uđe Isus i njegovi učenici."},{"v":2,"t":"A poznavaše to mjesto i Juda, njegov izdajica, jer se Isus tu često sastajao sa svojim učenicima."},{"v":3,"t":"Juda onda uze četu i od svećeničkih glavara i farizeja sluge te dođe onamo sa zubljama, svjetiljkama i oružjem."},{"v":4,"t":"Znajući sve što će s njim biti, istupi Isus naprijed te ih upita: “Koga tražite?”"},{"v":5,"t":"Odgovore mu: “Isusa Nazarećanina.” Reče im Isus: “Ja sam!” A stajaše s njima i Juda, njegov izdajica."},{"v":6,"t":"Kad im dakle reče: “Ja sam!” - oni ustuknuše i popadaše na zemlju."},{"v":7,"t":"Ponovno ih tada upita: “Koga tražite?” Oni odgovore: “Isusa Nazarećanina.”"},{"v":8,"t":"Isus odvrati: “Rekoh vam da sam ja. Ako dakle mene tražite, pustite ove da odu” -"},{"v":9,"t":"da se ispuni riječ koju reče: “Ne izgubih ni jednoga od onih koje si mi dao.”"},{"v":10,"t":"A Šimun Petar isuče mač koji je imao uza se pa udari slugu velikoga svećenika i odsiječe mu desno uho. Sluga se zvao Malho."},{"v":11,"t":"Nato Isus reče Petru: “Djeni mač u korice! Čašu koju mi dade Otac zar da ne pijem?”"},{"v":12,"t":"Tada četa, zapovjednik i židovski sluge uhvatiše Isusa te ga svezaše."},{"v":13,"t":"Odvedoše ga najprije Ani jer on bijaše tast Kajfe, velikoga svećenika one godine."},{"v":14,"t":"Kajfa pak ono svjetova Židove: “Bolje da jedan čovjek umre za narod.”"},{"v":15,"t":"Za Isusom su išli Šimun Petar i drugi učenik. Taj učenik bijaše poznat s velikim svećenikom pa s Isusom uđe u dvorište velikoga svećenika."},{"v":16,"t":"Petar osta vani kod vrata. Tada taj drugi učenik, znanac velikoga svećenika, iziđe i reče vratarici te uvede Petra."},{"v":17,"t":"Nato će sluškinja, vratarica, Petru: “Da nisi i ti od učenika toga čovjeka?” On odvrati: “Nisam!”"},{"v":18,"t":"A stajahu ondje sluge i stražari, raspirivahu žeravicu jer bijaše studeno i grijahu se. S njima je stajao i Petar i grijao se."},{"v":19,"t":"Veliki svećenik zapita Isusa o njegovim učenicima i o njegovu nauku."},{"v":20,"t":"Odgovori mu Isus: “Ja sam javno govorio svijetu. Uvijek sam naučavao u sinagogi i u Hramu gdje se skupljaju svi Židovi. Ništa nisam u tajnosti govorio."},{"v":21,"t":"Zašto mene pitaš? Pitaj one koji su slušali što sam im govorio. Oni eto znaju što sam govorio.”"},{"v":22,"t":"Na te njegove riječi jedan od nazočnih slugu pljusne Isusa govoreći: “Tako li odgovaraš velikom svećeniku?”"},{"v":23,"t":"Odgovori mu Isus: “Ako sam krivo rekao, dokaži da je krivo! Ako li pravo, zašto me udaraš?”"},{"v":24,"t":"Ana ga zatim posla svezana Kajfi, velikom svećeniku."},{"v":25,"t":"Šimun Petar stajao je ondje i grijao se. Rekoše mu: “Da nisi i ti od njegovih učenika?” On zanijeka: “Nisam!”"},{"v":26,"t":"Nato će jedan od slugu velikog svećenika, rođak onoga komu je Petar bio odsjekao uho: “Nisam li te ja vidio u vrtu s njime?”"},{"v":27,"t":"I Petar opet zanijeka, a pijetao odmah zapjeva."},{"v":28,"t":"Nato odvedoše Isusa od Kajfe u dvor upraviteljev. Bilo je rano jutro. I oni ne uđoše da se ne okaljaju, već da mognu blagovati pashu."},{"v":29,"t":"Pilat tada iziđe pred njih i upita: “Kakvu tužbu iznosite protiv ovoga čovjeka?”"},{"v":30,"t":"Odgovore mu: “Kad on ne bi bio zločinac, ne bismo ga predali tebi.”"},{"v":31,"t":"Reče im nato Pilat: “Uzmite ga vi i sudite mu po svom zakonu.” Odgovoriše mu Židovi: “Nama nije dopušteno nikoga pogubiti” -"},{"v":32,"t":"da se ispuni riječ Isusova kojom je označio kakvom mu je smrću umrijeti."},{"v":33,"t":"Nato Pilat uđe opet u dvor, pozove Isusa i upita ga: “Ti li si židovski kralj?”"},{"v":34,"t":"Isus odgovori: “Govoriš li ti to sam od sebe ili ti to drugi rekoše o meni?”"},{"v":35,"t":"Pilat odvrati: “Zar sam ja Židov? Tvoj narod i glavari svećenički predadoše te meni. Što si učinio?”"},{"v":36,"t":"Odgovori Isus: “Kraljevstvo moje nije od ovoga svijeta. Kad bi moje kraljevstvo bilo od ovoga svijeta, moje bi se sluge borile da ne budem predan Židovima. Ali kraljevstvo moje nije odavde.”"},{"v":37,"t":"Nato mu reče Pilat: “Ti si dakle kralj?” Isus odgovori: “Ti kažeš: ja sam kralj. Ja sam se zato rodio i došao na svijet da svjedočim za istinu. Tko je god od istine, sluša moj glas.”"},{"v":38,"t":"Reče mu Pilat: “Što je istina?”"},{"v":39,"t":"Rekavši to, opet iziđe pred Židove i reče im: “Ja ne nalazim na njemu nikakve krivice. A u vas je običaj da vam o Pashi nekoga pustim. Hoćete li dakle da vam pustim kralja židovskoga?”"},{"v":40,"t":"Povikaše nato opet: “Ne toga, nego Barabu!” A Baraba bijaše razbojnik."}]},"19":{"hr":[{"v":1,"t":"Tada Pilat uze i izbičeva Isusa."},{"v":2,"t":"A vojnici spletoše vijenac od trnja i staviše mu ga na glavu; i zaogrnuše ga grimiznim plaštem."},{"v":3,"t":"I prilazili su mu i govorili: “Zdravo kralju židovski!” I pljuskali su ga."},{"v":4,"t":"A Pilat ponovno iziđe i reče im: “Evo vam ga izvodim da znate: ne nalazim na njemu nikakve krivice.”"},{"v":5,"t":"Iziđe tada Isus s trnovim vijencem, u grimiznom plaštu. A Pilat im kaže: “Evo čovjeka!”"},{"v":6,"t":"I kad ga ugledaše glavari svećenički i sluge, povikaše: “Raspni, raspni!” Kaže im Pilat: “Uzmite ga vi i raspnite jer ja ne nalazim na njemu krivice.”"},{"v":7,"t":"Odgovoriše mu Židovi: “Mi imamo Zakon i po Zakonu on mora umrijeti jer se pravio Sinom Božjim.”"},{"v":8,"t":"Kad je Pilat čuo te riječi, još se više prestraši"},{"v":9,"t":"pa ponovno uđe u dvor i kaže Isusu: “Odakle si ti?” No Isus mu ne dade odgovora."},{"v":10,"t":"Tada mu Pilat reče: “Zar meni ne odgovaraš? Ne znaš li da imam vlast da te pustim i da imam vlast da te razapnem?”"},{"v":11,"t":"Odgovori mu Isus: “Ne bi imao nada mnom nikakve vlasti da ti nije dano odozgor. Zbog toga ima veći grijeh onaj koji me predao tebi.”"},{"v":12,"t":"Od tada ga je Pilat nastojao pustiti. No Židovi vikahu: “Ako ovoga pustiš, nisi prijatelj caru. Tko se god pravi kraljem, protivi se caru.”"},{"v":13,"t":"Čuvši te riječi, Pilat izvede Isusa i posadi na sudačku stolicu na mjestu koje se zove Litostrotos - Pločnik, hebrejski Gabata -"},{"v":14,"t":"a bijaše upravo priprava za Pashu, oko šeste ure - i kaže Židovima: “Evo kralja vašega!”"},{"v":15,"t":"Oni na to povikaše: “Ukloni! Ukloni! Raspni ga!” Kaže im Pilat: “Zar kralja vašega da razapnem?” Odgovoriše glavari svećenički: “Mi nemamo kralja osim cara!”"},{"v":16,"t":"Tada im ga preda da se razapne. Uzeše dakle Isusa."},{"v":17,"t":"I noseći svoj križ, iziđe on na mjesto zvano Lubanjsko, hebrejski Golgota."},{"v":18,"t":"Ondje ga razapeše, a s njim i drugu dvojicu, s jedne i druge strane, a Isusa u sredini."},{"v":19,"t":"A napisa Pilat i natpis te ga postavi na križ. Bilo je napisano: “Isus Nazarećanin, kralj židovski.”"},{"v":20,"t":"Taj su natpis čitali mnogi Židovi jer mjesto gdje je Isus bio raspet bijaše blizu grada, a bilo je napisano hebrejski, latinski i grčki."},{"v":21,"t":"Nato glavari svećenički rekoše Pilatu: “Nemoj pisati: 'Kralj židovski', nego da je on rekao: 'Kralj sam židovski.'”"},{"v":22,"t":"Pilat odgovori: “Što napisah, napisah!”"},{"v":23,"t":"Vojnici pak, pošto razapeše Isusa, uzeše njegove haljine i razdijeliše ih na četiri dijela - svakom vojniku po dio. A uzeše i donju haljinu, koja bijaše nešivena, otkana u komadu odozgor dodolje."},{"v":24,"t":"Rekoše zato među sobom: “Ne derimo je, nego bacimo za nju kocku pa komu dopane” - da se ispuni Pismo koje veli: Razdijeliše među se haljine moje, za odjeću moju baciše kocku. I vojnici učiniše tako."},{"v":25,"t":"Uz križ su Isusov stajale majka njegova, zatim sestra njegove majke, Marija Kleofina, i Marija Magdalena."},{"v":26,"t":"Kad Isus vidje majku i kraj nje učenika kojega je ljubio, reče majci: “Ženo! Evo ti sina!” Zatim reče učeniku: “Evo ti majke!”"},{"v":27,"t":"I od toga časa uze je učenik k sebi."},{"v":28,"t":"Nakon toga, kako je Isus znao da je sve dovršeno, da bi se ispunilo Pismo, reče: “Žedan sam.”"},{"v":29,"t":"A ondje je stajala posuda puna octa. I natakoše na izopovu trsku spužvu natopljenu octom pa je primakoše njegovim ustima."},{"v":30,"t":"Čim Isus uze ocat, reče: “Dovršeno je!” I prignuvši glavu, preda duh."},{"v":31,"t":"Kako bijaše Priprava, da ne bi tijela ostala na križu subotom, jer velik je dan bio one subote, Židovi zamoliše Pilata da se raspetima prebiju golijeni i da se skinu."},{"v":32,"t":"Dođoše dakle vojnici i prebiše golijeni prvomu i drugomu koji su s Isusom bili raspeti."},{"v":33,"t":"Kada dođoše do Isusa i vidješe da je već umro, ne prebiše mu golijeni,"},{"v":34,"t":"nego mu jedan od vojnika kopljem probode bok i odmah poteče krv i voda."},{"v":35,"t":"Onaj koji je vidio svjedoči i istinito je svjedočanstvo njegovo. On zna da govori istinu da i vi vjerujete"},{"v":36,"t":"jer se to dogodilo da se ispuni Pismo: Nijedna mu se kost neće slomiti."},{"v":37,"t":"I drugo opet Pismo veli: Gledat će onoga koga su proboli."},{"v":38,"t":"Nakon toga Josip iz Arimateje, koji je - kriomice, u strahu od Židova - bio učenik Isusov, zamoli Pilata da smije skinuti tijelo Isusovo. I dopusti mu Pilat. Josip dakle ode i skine Isusovo tijelo."},{"v":39,"t":"A dođe i Nikodem - koji je ono prije bio došao Isusu noću - i donese sa sobom oko sto libara smjese smirne i aloja."},{"v":40,"t":"Uzmu dakle tijelo Isusovo i poviju ga u povoje s miomirisima, kako je u Židova običaj za ukop."},{"v":41,"t":"A na mjestu gdje je Isus bio raspet bijaše vrt i u vrtu nov grob u koji još nitko ne bijaše položen."},{"v":42,"t":"Ondje dakle zbog židovske Priprave, jer grob bijaše blizu, polože Isusa."}]},"20":{"hr":[{"v":1,"t":"Prvog dana u tjednu rano ujutro, još za mraka, dođe Marija Magdalena na grob i opazi da je kamen s groba dignut."},{"v":2,"t":"Otrči stoga i dođe k Šimunu Petru i drugom učeniku, kojega je Isus ljubio, pa im reče: “Uzeše Gospodina iz groba i ne znamo gdje ga staviše.”"},{"v":3,"t":"Uputiše se onda Petar i onaj drugi učenik i dođoše na grob."},{"v":4,"t":"Trčahu obojica zajedno, ali onaj drugi učenik prestignu Petra i stiže prvi na grob."},{"v":5,"t":"Sagne se i opazi povoje gdje leže, ali ne uđe."},{"v":6,"t":"Uto dođe i Šimun Petar koji je išao za njim i uđe u grob. Ugleda povoje gdje leže"},{"v":7,"t":"i ubrus koji bijaše na glavi Isusovoj, ali nije bio uz povoje, nego napose svijen na jednome mjestu."},{"v":8,"t":"Tada uđe i onaj drugi učenik koji prvi stiže na grob i vidje i povjerova."},{"v":9,"t":"Jer oni još ne upoznaše Pisma da Isus treba da ustane od mrtvih."},{"v":10,"t":"Potom se učenici vratiše kući."},{"v":11,"t":"A Marija je stajala vani kod groba i plakala."},{"v":12,"t":"Zaplakana zaviri u grob i ugleda dva anđela u bjelini kako sjede na mjestu gdje je ležalo tijelo Isusovo - jedan kod glave, drugi kod nogu."},{"v":13,"t":"Kažu joj oni: “Ženo, što plačeš?” Odgovori im: “Uzeše Gospodina mojega i ne znam gdje ga staviše.”"},{"v":14,"t":"Rekavši to, obazre se i ugleda Isusa gdje stoji, ali nije znala da je to Isus."},{"v":15,"t":"Kaže joj Isus: “Ženo, što plačeš? Koga tražiš?” Misleći da je to vrtlar, reče mu ona: “Gospodine, ako si ga ti odnio, reci mi gdje si ga stavio i ja ću ga uzeti.”"},{"v":16,"t":"Kaže joj Isus: “Marijo!” Ona se okrene te će mu hebrejski: “Rabbuni!” - što znači: “Učitelju!”"},{"v":17,"t":"Kaže joj Isus: “Ne zadržavaj se sa mnom jer još ne uziđoh Ocu, nego idi mojoj braći i javi im: Uzlazim Ocu svomu i Ocu vašemu, Bogu svomu i Bogu vašemu.”"},{"v":18,"t":"Ode dakle Marija Magdalena i navijesti učenicima: “Vidjela sam Gospodina i on mi je to rekao.”"},{"v":19,"t":"I uvečer toga istog dana, prvog u tjednu, dok su učenici u strahu od Židova bili zatvorili vrata, dođe Isus, stane u sredinu i reče im: “Mir vama!”"},{"v":20,"t":"To rekavši, pokaza im svoje ruke i bok. I obradovaše se učenici vidjevši Gospodina."},{"v":21,"t":"Isus im stoga ponovno reče: “Mir vama! Kao što mene posla Otac i ja šaljem vas.”"},{"v":22,"t":"To rekavši, dahne u njih i kaže im: “Primite Duha Svetoga."},{"v":23,"t":"Kojima otpustite grijehe, otpuštaju im se; kojima zadržite, zadržani su im.”"},{"v":24,"t":"Ali Toma zvani Blizanac, jedan od dvanaestorice, ne bijaše s njima kad dođe Isus."},{"v":25,"t":"Govorili su mu dakle drugi učenici: “Vidjeli smo Gospodina!” On im odvrati: “Ako ne vidim na njegovim rukama biljeg čavala i ne stavim svoj prst u mjesto čavala, ako ne stavim svoju ruku u njegov bok, neću vjerovati.”"},{"v":26,"t":"I nakon osam dana bijahu njegovi učenici opet unutra, a s njima i Toma. Vrata bijahu zatvorena, a Isus dođe, stade u sredinu i reče: “Mir vama!”"},{"v":27,"t":"Zatim će Tomi: “Prinesi prst ovamo i pogledaj mi ruke! Prinesi ruku i stavi je u moj bok i ne budi nevjeran nego vjeran.”"},{"v":28,"t":"Odgovori mu Toma: “Gospodin moj i Bog moj!”"},{"v":29,"t":"Reče mu Isus: “Budući da si me vidio, povjerovao si. Blaženi koji ne vidješe, a vjeruju!”"},{"v":30,"t":"Isus je pred svojim učenicima učinio i mnoga druga znamenja koja nisu zapisana u ovoj knjizi."},{"v":31,"t":"A ova su zapisana da vjerujete: Isus je Krist, Sin Božji, i da vjerujući imate život u imenu njegovu."}]},"21":{"hr":[{"v":1,"t":"Poslije toga očitova se Isus ponovno učenicima na Tiberijadskome moru. Očitova se ovako:"},{"v":2,"t":"Bijahu zajedno Šimun Petar, Toma zvani Blizanac, Natanael iz Kane Galilejske, zatim Zebedejevi i još druga dva njegova učenika."},{"v":3,"t":"Kaže im Šimun Petar: “Idem ribariti.” Rekoše: “Idemo i mi s tobom.” Izađoše i uđoše u lađu, ali te noći ne uloviše ništa."},{"v":4,"t":"Kad je već svanulo, stade Isus na kraju, ali učenici nisu znali da je to Isus."},{"v":5,"t":"Kaže im Isus: “Dječice, imate li što za prismok?” Odgovoriše mu: “Nemamo.”"},{"v":6,"t":"A on im reče: “Bacite mrežu na desnu stranu lađe i naći ćete.” Baciše oni i više je ne mogoše izvući od mnoštva ribe."},{"v":7,"t":"Tada onaj učenik kojega je Isus ljubio kaže Petru: “Gospodin je!” Kad je Šimun Petar čuo da je to Gospodin, pripaše si gornju haljinu, jer bijaše gol, te se baci u more."},{"v":8,"t":"Ostali učenici dođoše s lađicom vukući mrežu s ribom jer ne bijahu daleko od kraja, samo kojih dvjesta lakata."},{"v":9,"t":"Kad iziđu na kraj, ugledaju pripravljenu žeravicu i na njoj pristavljenu ribu i kruh."},{"v":10,"t":"Kaže im Isus: “Donesite riba što ih sada uloviste.”"},{"v":11,"t":"Nato se Šimun Petar popne i izvuče na kraj mrežu punu velikih riba, sto pedeset i tri. I premda ih je bilo toliko, mreža se ne raskinu."},{"v":12,"t":"Kaže im Isus: “Hajde, doručkujte!” I nitko se od učenika ne usudi upitati ga: “Tko si ti?” Znali su da je Gospodin."},{"v":13,"t":"Isus pristupi, uzme kruh i dade im, a tako i ribu."},{"v":14,"t":"To se već treći put očitova Isus učenicima pošto uskrsnu od mrtvih."},{"v":15,"t":"Nakon doručka upita Isus Šimuna Petra: “Šimune Ivanov, ljubiš li me više nego ovi?” Odgovori mu: “Da, Gospodine, ti znaš da te volim.”"},{"v":16,"t":"Kaže mu: “Pasi jaganjce moje!” Upita ga po drugi put: “Šimune Ivanov, ljubiš li me?” Odgovori mu: “Da, Gospodine, ti znaš da te volim!” Kaže mu: “Pasi ovce moje!”"},{"v":17,"t":"Upita ga treći put: “Šimune Ivanov, voliš li me?” Ražalosti se Petar što ga upita treći put: “Voliš li me?” pa mu odgovori: “Gospodine, ti sve znaš! Tebi je poznato da te volim.” Kaže mu Isus: “Pasi ovce moje!”"},{"v":18,"t":"“Zaista, zaista kažem ti: Dok si bio mlađi, sam si se opasivao i hodio kamo si htio; ali kad ostariš, raširit ćeš ruke i drugi će te opasivati i voditi kamo nećeš.”"},{"v":19,"t":"A to mu reče nagovješćujući kakvom će smrću proslaviti Boga. Rekavši to doda: “Idi za mnom!”"},{"v":20,"t":"Petar se okrene i opazi da ga slijedi onaj učenik kojega je Isus ljubio i koji se za večere bijaše privio Isusu uz prsa i upitao ga: “Gospodine, tko će te to izdati?”"},{"v":21,"t":"Vidjevši ga, Petar kaže Isusu: “Gospodine, a što s ovim?”"},{"v":22,"t":"Odgovori mu Isus: “Ako hoću da on ostane dok ne dođem, što je tebi do toga? Ti idi za mnom!”"},{"v":23,"t":"Stoga se pronese među braćom glas da onaj učenik neće umrijeti. No Isus mu nije rekao: “Neće umrijeti”, nego: “Ako hoću da on ostane dok ne dođem, što je tebi do toga?”"},{"v":24,"t":"Taj učenik za ovo svjedoči i ovo napisa. I znamo da je istinito svjedočanstvo njegovo."},{"v":25,"t":"A ima još mnogo toga što učini Isus i kad bi se sve redom popisalo, sav svijet, mislim, ne bi obuhvatio knjiga koje bi se napisale."}]}},"ACT":{"1":{"hr":[{"v":1,"t":"Prvu sam knjigu, Teofile, sastavio o svemu što je Isus činio i učio"},{"v":2,"t":"do dana kad je uznesen pošto je dao upute apostolima koje je izabrao po Duhu Svetome."},{"v":3,"t":"Njima je poslije svoje muke mnogim dokazima pokazao da je živ, četrdeset im se dana ukazivao i govorio o kraljevstvu Božjem."},{"v":4,"t":"I dok je jednom s njima blagovao, zapovjedi im da ne napuštaju Jeruzalema, nego neka čekaju Obećanje Očevo “koje čuste od mene:"},{"v":5,"t":"Ivan je krstio vodom, a vi ćete naskoro nakon ovih dana biti kršteni Duhom Svetim.”"},{"v":6,"t":"Nato ga sabrani upitaše: “Gospodine, hoćeš li u ovo vrijeme Izraelu opet uspostaviti kraljevstvo?”"},{"v":7,"t":"On im odgovori: “Nije vaše znati vremena i zgode koje je Otac podredio svojoj vlasti."},{"v":8,"t":"Nego primit ćete snagu Duha Svetoga koji će sići na vas i bit ćete mi svjedoci u Jeruzalemu, po svoj Judeji i Samariji i sve do kraja zemlje.”"},{"v":9,"t":"Kada to reče, bi uzdignut njima naočigled i oblak ga ote njihovim očima."},{"v":10,"t":"I dok su netremice gledali kako on odlazi na nebo, gle, dva čovjeka stadoše kraj njih u bijeloj odjeći"},{"v":11,"t":"i rekoše im: “Galilejci, što stojite i gledate u nebo? Ovaj Isus koji je od vas uznesen na nebo isto će tako doći kao što ste vidjeli da odlazi na nebo.”"},{"v":12,"t":"Onda se vratiše u Jeruzalem s brda zvanoga Maslinsko, koje je blizu Jeruzalema, udaljeno jedan subotni hod."},{"v":13,"t":"I pošto uđu u grad, uspnu se u gornju sobu gdje su boravili: Petar i Ivan i Jakov i Andrija, Filip i Toma, Bartolomej i Matej, Jakov Alfejev i Šimun Revnitelj i Juda Jakovljev -"},{"v":14,"t":"svi oni bijahu jednodušno postojani u molitvi sa ženama, i Marijom, majkom Isusovom, i braćom njegovom."},{"v":15,"t":"U one dane ustade Petar među braćom - a bijaše sakupljenog naroda oko sto i dvadeset duša - i reče:"},{"v":16,"t":"“Braćo! Trebalo je da se ispuni Pismo što ga na usta Davidova proreče Duh Sveti o Judi koji bijaše vođa onih što uhvatiše Isusa."},{"v":17,"t":"A Juda se ubrajao među nas i imao udio u ovoj službi."},{"v":18,"t":"On, eto, steče predio cijenom nepravednosti pa se stropošta, raspuče po sredini i razli mu se sva utroba."},{"v":19,"t":"I svim je Jeruzalemcima znano da se onaj predio njihovim jezikom zove Akeldama, to jest Predio smrti."},{"v":20,"t":"Pisano je doista u Knjizi psalama: Njegova kuća nek opusti, nek ne bude stanovnika u njoj! Njegovo nadgledništvo nek dobije drugi!"},{"v":21,"t":"Jedan dakle od ovih ljudi što bijahu s nama za sve vrijeme što je među nama živio Gospodin Isus -"},{"v":22,"t":"počevši od krštenja Ivanova pa sve do dana kad bi uzet od nas - treba da bude svjedokom njegova uskrsnuća."},{"v":23,"t":"I postaviše dvojicu: Josipa koji se zvao Barsaba a prozvao se Just, i Matiju."},{"v":24,"t":"Onda se pomoliše: “Ti, Gospodine, poznavaoče svih srdaca, pokaži koga si od ove dvojice izabrao"},{"v":25,"t":"da primi mjesto ove apostolske službe kojoj se iznevjeri Juda da ode na svoje mjesto.”"},{"v":26,"t":"Onda baciše kocke i kocka pade na Matiju; tako bi pribrojen jedanaestorici apostola."}]},"2":{"hr":[{"v":1,"t":"Kad je napokon došao dan Pedesetnice, svi su bili zajedno na istome mjestu."},{"v":2,"t":"I eto iznenada šuma s neba, kao kad se digne silan vjetar. Ispuni svu kuću u kojoj su bili."},{"v":3,"t":"I pokažu im se kao neki ognjeni razdijeljeni jezici te siđe po jedan na svakoga od njih."},{"v":4,"t":"Svi se napuniše Duha Svetoga i počeše govoriti drugim jezicima, kako im već Duh davaše zboriti."},{"v":5,"t":"A u Jeruzalemu su boravili Židovi, ljudi pobožni iz svakog naroda pod nebom."},{"v":6,"t":"Pa kad nasta ona huka, strča se mnoštvo i smetÄe jer ih je svatko čuo govoriti svojim jezikom."},{"v":7,"t":"Svi su bili izvan sebe i divili se govoreći: “Gle! Nisu li svi ovi što govore Galilejci?"},{"v":8,"t":"Pa kako to da ih svatko od nas čuje na svojem materinskom jeziku?"},{"v":9,"t":"Parti, Međani, Elamljani, žitelji Mezopotamije, Judeje i Kapadocije, Ponta i Azije,"},{"v":10,"t":"Frigije i Pamfilije, Egipta i krajeva libijskih oko Cirene, pridošlice Rimljani,"},{"v":11,"t":"Židovi i sljedbenici, Krećani i Arapi - svi ih mi čujemo gdje našim jezicima razglašuju veličanstvena djela Božja.”"},{"v":12,"t":"Svi su izvan sebe zbunjeno jedan drugog pitali: “Što bi to moglo biti?”"},{"v":13,"t":"Drugi su pak, podrugujući se, govorili: “Slatkog su se vina ponapili!”"},{"v":14,"t":"A Petar zajedno s jedanaestoricom ustade, podiže glas i prozbori: “Židovi i svi što boravite u Jeruzalemu, ovo znajte i riječi mi poslušajte:"},{"v":15,"t":"Nisu ovi pijani, kako vi mislite - ta istom je treća ura dana -"},{"v":16,"t":"nego to je ono što je rečeno po proroku Joelu:"},{"v":17,"t":"“U posljednje dane, govori Bog: Izlit ću Duha svoga na svako tijelo i proricat će vaši sinovi i kćeri, vaši će mladići gledati viđenja, a starci vaši sne sanjati."},{"v":18,"t":"Čak ću i na sluge i sluškinje svoje izliti Duha svojeg u dane one i proricat će."},{"v":19,"t":"Pokazat ću čudesa na nebu gore i znamenja na zemlji dolje, krv i oganj i stupove dima."},{"v":20,"t":"Sunce će se prometnut u tminu, a mjesec u krv prije nego svane Dan Gospodnji velik i slavan."},{"v":21,"t":"I tko god prizove ime Gospodnje bit će spašen.”"},{"v":22,"t":"“Izraelci, čujte ove riječi: Isusa Nazarećanina, čovjeka kojega Bog pred vama potvrdi silnim djelima, čudesima i znamenjima koja, kao što znate, po njemu učini među vama -"},{"v":23,"t":"njega, predana po odlučenu naumu i promislu Božjem, po rukama bezakonika razapeste i pogubiste."},{"v":24,"t":"Ali Bog ga uskrisi oslobodivši ga grozote smrti jer ne bijaše moguće da ona njime ovlada."},{"v":25,"t":"David doista za nj kaže: Gospodin mi je svagda pred očima jer mi je zdesna da ne posrnem."},{"v":26,"t":"Stog mi se raduje srce i kliče jezik, pa i tijelo mi spokojno počiva."},{"v":27,"t":"Jer mi nećeš ostaviti dušu u Podzemlju ni dati da pravednik tvoj truleži ugleda."},{"v":28,"t":"Pokazat ćeš mi stazu života, ispuniti me radošću lica svoga."},{"v":29,"t":"Braćo, dopustite da vam otvoreno kažem: praotac je David umro, pokopan je i eno mu među nama groba sve do današnjeg dana."},{"v":30,"t":"Ali kako je bio prorok i znao da mu se zakletvom zakle Bog plod utrobe njegove posaditi na prijestolje njegovo,"},{"v":31,"t":"unaprijed je vidio i navijestio uskrsnuće Kristovo: Nije ostavljen u Podzemlju niti mu tijelo truleži ugleda."},{"v":32,"t":"Toga Isusa uskrisi Bog! Svi smo mi tomu svjedoci."},{"v":33,"t":"Desnicom dakle Božjom uzvišen, primio je od Oca Obećanje, Duha Svetoga, i izlio ga kako i sami gledate i slušate."},{"v":34,"t":"Ta David nije bio uznesen na nebesa, a veli: Reče Gospodin Gospodinu mojemu: 'Sjedi mi zdesna'"},{"v":35,"t":"dok ne položim neprijatelje tvoje za podnožje nogama tvojim!"},{"v":36,"t":"Pouzdano dakle neka znade sav dom Izraelov da je toga Isusa kojega vi razapeste Bog učinio i Gospodinom i Kristom.”"},{"v":37,"t":"Kad su to čuli, duboko potreseni rekoše Petru i drugim apostolima: “Što nam je činiti, braćo?”"},{"v":38,"t":"Petar će im: “Obratite se i svatko od vas neka se krsti u ime Isusa Krista da vam se oproste grijesi i primit ćete dar, Duha Svetoga."},{"v":39,"t":"Ta za vas je ovo obećanje i za djecu vašu i za sve one izdaleka, koje pozove Gospodin Bog naš.”"},{"v":40,"t":"I mnogim je drugim riječima još svjedočio i hrabrio ih: “Spasite se od naraštaja ovog opakog!”"},{"v":41,"t":"I oni prigrliše riječ njegovu i krstiše se te im se u onaj dan pridruži oko tri tisuće duša."},{"v":42,"t":"Bijahu postojani u nauku apostolskom, u zajedništvu, lomljenju kruha i molitvama."},{"v":43,"t":"Strahopoštovanje obuzimaše svaku dušu: apostoli su činili mnoga čudesa i znamenja."},{"v":44,"t":"Svi koji prigrliše vjeru bijahu združeni i sve im bijaše zajedničko."},{"v":45,"t":"Sva bi imanja i dobra prodali porazdijelili svima kako bi tko trebao."},{"v":46,"t":"Svaki bi dan jednodušno i postojano hrlili u Hram, u kućama bi lomili kruh te u radosti i prostodušnosti srca zajednički uzimali hranu"},{"v":47,"t":"hvaleći Boga i uživajući naklonost svega naroda. Gospodin je pak danomice zajednici pridruživao spasenike."}]},"3":{"hr":[{"v":1,"t":"Petar i Ivan uzlazili su u Hram na devetu molitvenu uru."},{"v":2,"t":"Upravo su donosili nekog čovjeka, hroma od majčine utrobe; njega bi svaki dan postavljali kod hramskih vrata, zvanih Divna, da prosi milostinju od onih koji ulaze u Hram."},{"v":3,"t":"On ugleda Petra i Ivana upravo kad zakoračiše u Hram te zamoli milostinju."},{"v":4,"t":"Petar ga zajedno s Ivanom prodorno pogleda i reče: “Pogledaj u nas!”"},{"v":5,"t":"Dok ih je molećivo motrio očekujući od njih nešto dobiti,"},{"v":6,"t":"reče mu Petar: “Srebra i zlata nema u mene, ali što imam - to ti dajem: u ime Isusa Krista Nazarećanina hodaj!”"},{"v":7,"t":"I uhvativši ga za desnu ruku, pridiže ga: umah mu omoćaše noge i gležnjevi"},{"v":8,"t":"pa skoči, uspravi se, stane hodati te uđe s njima u Hram hodajući, poskakujući i hvaleći Boga."},{"v":9,"t":"Sav ga narod vidje kako hoda i hvali Boga."},{"v":10,"t":"Razabraše da je to on - onaj koji je na Divnim vratima Hrama prosio milostinju - i ostadoše zapanjeni i izvan sebe zbog onoga što se s njim dogodilo."},{"v":11,"t":"Kako se pak on držao Petra i Ivana, sav se narod zapanjen strča k njima u trijem zvani Salomonov."},{"v":12,"t":"Kada to vidje Petar, obrati se narodu: “Izraelci, što se ovomu čudite? Ili što nas gledate kao da smo svojom snagom ili pobožnošću postigli da ovaj prohoda?"},{"v":13,"t":"Bog Abrahamov, Izakov i Jakovljev, Bog otaca naših, proslavi slugu svoga, Isusa kojega vi predadoste i kojega se odrekoste pred Pilatom kad već bijaše odlučio pustiti ga."},{"v":14,"t":"Vi se odrekoste Sveca i Pravednika, a izmoliste da vam se daruje ubojica."},{"v":15,"t":"Začetnika života ubiste. Ali Bog ga uskrisi od mrtvih, čemu smo mi svjedoci.”"},{"v":16,"t":"“I po vjeri u njegovo ime, to je ime dalo snagu ovomu kojega gledate i poznate: vjera u Njega vratila je ovomu potpuno zdravlje naočigled vas sviju.”"},{"v":17,"t":"“I sada, braćo, znam da ste ono uradili iz neznanja kao i glavari vaši."},{"v":18,"t":"Ali Bog tako ispuni što unaprijed navijesti po ustima svih proroka: da će njegov Pomazanik trpjeti."},{"v":19,"t":"Pokajte se dakle i obratite da se izbrišu grijesi vaši"},{"v":20,"t":"pa od Gospodina dođu vremena rashlade te on pošalje vama unaprijed namijenjenog Pomazanika, Isusa.”"},{"v":21,"t":"Njega treba da nebo pridrži do vremena uspostave svega što obeća Bog na usta svetih proroka svojih odvijeka.”"},{"v":22,"t":"“Mojsije tako reče: Proroka poput mene od vaše braće podignut će vam Gospodin, Bog vaš. Njega slušajte u svemu što vam god reče."},{"v":23,"t":"I svaka duša koja ne posluša toga proroka, neka se iskorijeni iz naroda.”"},{"v":24,"t":"“I svi Proroci koji su - od Samuela dalje - govorili, također su navijestili ove dane.”"},{"v":25,"t":"“Vi ste sinovi proroka i Saveza koji sklopi Bog s ocima vašim govoreći Abrahamu: Potomstvom će se tvojim blagoslivljati sva plemena zemlje."},{"v":26,"t":"Vama najprije podiže Bog Slugu svoga i posla ga blagoslivljati vas da se svatko obrati od opačina svojih.”"}]},"4":{"hr":[{"v":1,"t":"Dok su oni još govorili narodu, priđu im svećenici, hramski zapovjednik i saduceji,"},{"v":2,"t":"ozlovoljeni što uče narod i navješćuju - u Isusu - uskrsnuće od mrtvih;"},{"v":3,"t":"pograbe ih i bace u tamnicu do sutra jer već bijaše večer."},{"v":4,"t":"Ipak mnogi od onih koji su čuli Riječ, povjerovaše te broj vjernika poraste nekako do pet tisuća."},{"v":5,"t":"Sutradan se sastadoše u Jeruzalemu glavari, starješine i pismoznanci -"},{"v":6,"t":"i veliki svećenik Ana, i Kajfa, i Ivan, i Aleksandar, i svi od roda velikosvećeničkoga."},{"v":7,"t":"Izvedoše apostole preda se pa ih stadoše ispitivati: “Kojom snagom ili po kojem imenu vi to učiniste?”"},{"v":8,"t":"Onda Petar pun Duha Svetoga reče: “Glavari narodni i starješine!"},{"v":9,"t":"Zar mi danas odgovaramo zbog dobra djela učinjena bolesnu čovjeku? Po kome je ovaj spašen?"},{"v":10,"t":"Neka bude znano svima vama i svemu narodu Izraelovu: po imenu Isusa Krista Nazarećanina, kojega ste vi raspeli, a kojega Bog uskrisi od mrtvih! Po njemu ovaj stoji pred vama zdrav!"},{"v":11,"t":"On je onaj kamen koji vi graditelji odbaciste, ali koji postade kamen zaglavni."},{"v":12,"t":"I nema ni u kome drugom spasenja. Nema uistinu pod nebom drugoga imena dana ljudima po kojemu se možemo spasiti.”"},{"v":13,"t":"Kad vidješe neustrašivost Petrovu i Ivanovu, a znajući da su to ljudi nepismeni i neuki, bijahu u čudu; znali su ih, da bijahu s Isusom, ali"},{"v":14,"t":"videći gdje s njima stoji izliječeni čovjek, nisu mogli ništa protusloviti."},{"v":15,"t":"Stoga zapovjediše da izađu iz vijećnice pa stadoše raspravljati:"},{"v":16,"t":"“Što ćemo s tim ljudima? Ta učinili su očit znak, poznat svim Jeruzalemcima, ne možemo ga nijekati;"},{"v":17,"t":"ali da se još više ne razglasi u narod, zaprijetimo im da nikomu živom o tom Imenu više ne govore.”"},{"v":18,"t":"Pozvaše ih i zapovjediše im da podnipošto ne zbore niti naučavaju u ime Isusovo."},{"v":19,"t":"Ali im Petar i Ivan odgovoriše: “Sudite je li pred Bogom pravo slušati radije vas nego Boga."},{"v":20,"t":"Mi doista ne možemo ne govoriti što vidjesmo i čusmo.”"},{"v":21,"t":"Ali oni ne našavši kako da ih kazne, opet im zaprijete pa ih otpuste poradi naroda jer su svi slavili Boga zbog onoga što se dogodilo."},{"v":22,"t":"Jer čovjeku na kom se dogodi čudo ozdravljenja bijaše više od četrdeset godina."},{"v":23,"t":"Otpušteni, odoše svojima i javiše što im rekoše veliki svećenici i starješine."},{"v":24,"t":"Kad su oni to čuli, jednodušno podigoše glas k Bogu i rekoše: “Gospodine, ti si stvorio nebo i zemlju i more i sve što je u njima!"},{"v":25,"t":"Ti si na usta oca našega, sluge svoga Davida, po Duhu Svetom rekao: Zašto se bune narodi, zašto puci ludosti snuju?"},{"v":26,"t":"Ustaju kraljevi zemaljski, Knezovi se rotÄe protiv Gospodina i protiv Pomazanika njegova."},{"v":27,"t":"RotÄe se, uistinu, u ovome gradu na svetog Slugu tvoga Isusa, kog pomaza, rotÄe se Herod i Poncije Pilat zajedno s narodima i pucima izraelskim"},{"v":28,"t":"da učine što tvoja ruka i tvoja volja predodredi da se zbude."},{"v":29,"t":"I evo sada, Gospodine, promotri prijetnje njihove i daj slugama svojim sa svom smjelošću navješćivati riječ tvoju!"},{"v":30,"t":"Pruži ruku svoju da bude ozdravljenja, znamenja i čudesa po imenu svetoga Sluge tvoga Isusa.”"},{"v":31,"t":"I pošto se pomoliše, potrese se mjesto gdje bijahu sabrani, i svi se napuniše Duha Svetoga te stanu navješćivati riječ Božju smjelo."},{"v":32,"t":"U mnoštva onih što prigrliše vjeru bijaše jedno srce i jedna duša. I nijedan od njih nije svojim zvao ništa od onoga što je imao, nego im sve bijaše zajedničko."},{"v":33,"t":"Apostoli pak velikom silom davahu svjedočanstvo o uskrsnuću Gospodina Isusa i svi uživahu veliku naklonost."},{"v":34,"t":"Doista, nitko među njima nije oskudijevao jer koji bi god posjedovali zemljišta ili kuće, prodavali bi ih i utržak donosili"},{"v":35,"t":"i stavljali pred noge apostolima. A dijelilo se svakomu koliko je trebao."},{"v":36,"t":"A Josip, od apostola prozvan Barnaba, što znači Sin utjehe, levit, rodom Cipranin,"},{"v":37,"t":"posjedovaše jednu njivu; proda je pa donese novac i postavi pred noge apostolima."}]},"5":{"hr":[{"v":1,"t":"Neki pak čovjek po imenu Ananija, zajedno sa svojom ženom Safirom proda imanje"},{"v":2,"t":"pa u dogovoru sa ženom odvoji nešto od utrška, a samo jedan dio donese i postavi pred noge apostolima."},{"v":3,"t":"Petar mu reče: “Ananija, zašto ti Sotona ispuni srce te si slagao Duhu Svetomu i odvojio od utrška imanja?"},{"v":4,"t":"Da je ostalo neprodano, ne bi li tvoje ostalo; i jednoć prodano, nije li u tvojoj vlasti? Zašto si se na takvo što odlučio? Nisi slagao ljudima, nego Bogu!”"},{"v":5,"t":"Kako Ananija ču te riječi, sruši se i izdahnu. I silan strah spopade sve koji su to čuli."},{"v":6,"t":"Nato ustanu mladići, poviju ga, iznesu i pokopaju."},{"v":7,"t":"Nakon otprilike tri sata uđe njegova žena ne znajući što se dogodilo."},{"v":8,"t":"Petar joj reče: “Reci mi, jeste li za toliko dali imanje?” Ona odgovori: “Da, za toliko.”"},{"v":9,"t":"A Petar će joj: “Što vam bi da se složiste iskušati Duha Gospodnjega? Eto na vratima nogu onih koji ti pokopaše muža! I tebe će iznijeti!”"},{"v":10,"t":"Ona se umah sruši do njegovih nogu i izdahnu. Oni mladići uđu, nađu je mrtvu, iznesu je i pokopaju uz muža."},{"v":11,"t":"I silan strah spopade cijelu Crkvu i sve koji su to čuli."},{"v":12,"t":"Po rukama se apostolskim događala mnoga znamenja i čudesa u narodu. Svi su se jednodušno okupljali u Trijemu Salomonovu."},{"v":13,"t":"Nitko se drugi nije usuđivao pridružiti im se, ali ih je narod veličao."},{"v":14,"t":"I sve se više povećavalo mnoštvo muževa i žena što vjerovahu Gospodinu"},{"v":15,"t":"tako da su na trgove iznosili bolesnike i postavljali ih na ležaljkama i posteljama ne bi li, kad Petar bude prolazio, bar sjena njegova osjenila kojega od njih."},{"v":16,"t":"A slijegalo bi se i mnoštvo iz gradova oko Jeruzalema: donosili bi bolesnike i opsjednute od nečistih duhova, i svi bi ozdravljali."},{"v":17,"t":"Onda se podiže veliki svećenik i sve njegove pristaše - sljedba saducejska."},{"v":18,"t":"Puni zavisti, pohvataju apostole i strpaju ih u javnu tamnicu."},{"v":19,"t":"Ali anđeo Gospodnji noću otvori vrata tamnice, izvede ih i reče:"},{"v":20,"t":"“Pođite i postojano u Hramu navješćujte narodu sve riječi Života ovoga.”"},{"v":21,"t":"Poslušni, u praskozorje su ušli u Hram te naučavali. Uto stiže veliki svećenik i njegove pristaše, sazovu Vijeće i sve starješinstvo sinova Izraelovih pa pošalju u zatvor da ih dovedu."},{"v":22,"t":"Kad stražari stigoše onamo, ne nađoše ih u tamnici pa se vrate i jave:"},{"v":23,"t":"“Zatvor smo našli sa svom pomnjom zatvoren i čuvare na straži pred vratima, ali kad smo otvorili, nikoga unutra ne nađosmo.”"},{"v":24,"t":"Kad su hramski zapovjednik i veliki svećenici čuli te riječi, u nedoumici su se pitali što bi to moglo biti."},{"v":25,"t":"Nato netko pristigne i dojavi im: “Eno, ljudi koje baciste u tamnicu, u Hramu stoje i uče narod.”"},{"v":26,"t":"Tada zapovjednik sa stražarima ode te ih dovede - ne na silu jer se bojahu da ih narod ne kamenuje."},{"v":27,"t":"Dovedoše ih i privedoše pred Vijeće. Veliki ih svećenik zapita:"},{"v":28,"t":"“Nismo li vam strogo zabranili učiti u to Ime? A vi ste eto napunili Jeruzalem svojim naukom i hoćete na nas navući krv toga čovjeka.”"},{"v":29,"t":"Petar i apostoli odvrate: “Treba se većma pokoravati Bogu negoli ljudima!"},{"v":30,"t":"Bog otaca naših uskrisi Isusa kojega vi smakoste objesivši ga na drvo."},{"v":31,"t":"Njega Bog desnicom svojom uzvisi za Začetnika i Spasitelja da obraćenjem podari Izraela i oproštenjem grijeha."},{"v":32,"t":"I mi smo svjedoci tih događaja i Duh Sveti kojega dade Bog onima što mu se pokoravaju.”"},{"v":33,"t":"Nato se oni razgnjeviše i htjedoše ih ubiti."},{"v":34,"t":"Ali ustade u Vijeću neki farizej imenom Gamaliel, zakonoznanac, kojega je poštovao sav narod. On zapovjedi da ljude načas izvedu"},{"v":35,"t":"pa će vijećnicima: “Izraelci, dobro promislite što ćete s tim ljudima."},{"v":36,"t":"Ta prije nekog vremena podiže se Teuda tvrdeći da je netko, i uza nj prista oko četiri stotine ljudi. Bi smaknut i sve mu se pristaše razbjegoše i netragom ih nesta."},{"v":37,"t":"Nakon toga se u dane popisa podiže Juda Galilejac i odvuče narod za sobom. I on propade i sve mu se pristaše raspršiše."},{"v":38,"t":"I sad evo kanite se, velim vam, tih ljudi i otpustite ih. Jer ako je taj naum ili to djelo od ljudi, propast će;"},{"v":39,"t":"ako li je pak od Boga, nećete ga moći uništiti - da se i s Bogom u ratu ne nađete.” Poslušaju ga"},{"v":40,"t":"pa dozovu apostole, išibaju ih, zapovjede im da ne govore u ime Isusovo pa ih otpuste."},{"v":41,"t":"Oni pak odu ispred Vijeća radosni što bijahu dostojni podnijeti pogrde za Ime."},{"v":42,"t":"I svaki su dan u Hramu i po kućama neprestance učili i navješćivali Krista, Isusa."}]},"6":{"hr":[{"v":1,"t":"U one dane, kako se broj učenika množio, Židovi grčkog jezika stadoše mrmljati protiv domaćih Židova što se u svagdanjem služenju zanemaruju njihove udovice."},{"v":2,"t":"Dvanaestorica nato sazvaše mnoštvo učenika i rekoše: “Nije pravo da mi napustimo riječ Božju da bismo služili kod stolova."},{"v":3,"t":"De pronađite, braćo, između sebe sedam muževa na dobru glasu, punih Duha i mudrosti. Njih ćemo postaviti nad ovom službom,"},{"v":4,"t":"a mi ćemo se posvetiti molitvi i posluživanju Riječi.”"},{"v":5,"t":"Prijedlog se svidje svemu mnoštvu pa izabraše Stjepana, muža puna vjere i Duha Svetoga, zatim Filipa, Prohora, Nikanora, Timona, Parmenu te antiohijskog pridošlicu Nikolu."},{"v":6,"t":"Njih postave pred apostole, a oni pomolivši se, polože na njih ruke."},{"v":7,"t":"I riječ je Božja rasla, uvelike se množio broj učenika u Jeruzalemu i veliko je mnoštvo svećenika prihvaćalo vjeru."},{"v":8,"t":"Stjepan je pun milosti i snage činio velika čudesa i znamenja u narodu."},{"v":9,"t":"Nato se digoše neki iz takozvane sinagoge Slobodnjaka, Cirenaca, Aleksandrinaca te onih iz Cilicije i Azije pa počeše raspravljati sa Stjepanom,"},{"v":10,"t":"ali nisu mogli odoljeti mudrosti i Duhu kojim je govorio."},{"v":11,"t":"Onda podmetnuše neke ljude koji rekoše: “Čuli smo ga govoriti pogrdne riječi protiv Mojsija i Boga.”"},{"v":12,"t":"Podjare i narod, starješine i pismoznance pa priđu, zgrabe ga i odvuku u Vijeće."},{"v":13,"t":"Ondje namjestiše lažne svjedoke koji rekoše: “Ovaj čovjek neprestance govori protiv svetog Mjesta i Zakona."},{"v":14,"t":"Čuli smo ga doista govoriti: 'Isus Nazarećanin razvalit će ovo Mjesto i izmijeniti običaje koje nam predade Mojsije'.”"},{"v":15,"t":"A svi koji su sjedili u Vijeću upriješe pogled u Stjepana te opaziše - lice mu kao u anđela."}]},"7":{"hr":[{"v":1,"t":"Veliki svećenik upita: “Je li to tako?”"},{"v":2,"t":"Stjepan odgovori: “Braćo i oci, čujte! Bog slave ukaza se ocu našemu Abrahamu dok bijaše u Mezopotamiji, prije negoli se nastani u Haranu,"},{"v":3,"t":"i reče mu: Iziđi iz zemlje svoje, iz zavičaja svoga, hajde u zemlju koju ću ti pokazati."},{"v":4,"t":"On nato iziđe iz zemlje kaldejske i nastani se u Haranu. Odande ga nakon smrti oca njegova Bog preseli u ovu zemlju u kojoj vi sada boravite."},{"v":5,"t":"U njoj mu ne dade ni stope baštine, nego obeća dati je u posjed njemu i potomstvu njegovu nakon njega, premda još nije imao djeteta."},{"v":6,"t":"Bog isto tako reče da će potomci njegovi biti pridošlice u zemlji tuđoj, da će ih porobljavati i tlačiti četiri stotine godina."},{"v":7,"t":"Ali narod kojemu budu robovali ja ću suditi, reče Bog. A nakon toga izići će i iskazati mi štovanje na ovome mjestu."},{"v":8,"t":"Dade mu i Savez obrezanja. Tako rodi Izaka i obreza ga osmi dan, Izak Jakova, Jakov dvanaest rodozačetnika.”"},{"v":9,"t":"“Rodozačetnici pak, iz zavisti, Josipa predadoše u Egipat. Ali Bog bijaše s njim"},{"v":10,"t":"te ga izbavljaše iz svih nevolja, podari ga naklonošću i mudrošću pred faraonom, kraljem egipatskim koji ga postavi za upravitelja nad Egiptom i nad cijelim dvorom svojim."},{"v":11,"t":"Onda u cijeloj zemlji egipatskoj i kanaanskoj nasta glad i nevolja velika: oci naši ne mogahu naći hrane."},{"v":12,"t":"Kad Jakov doču da u Egiptu ima žita, posla onamo najprije oce naše."},{"v":13,"t":"Drugi se put Josip očitova braći svojoj pa faraon dozna za podrijetlo Josipovo."},{"v":14,"t":"Josip tada posla po Jakova, oca svoga, i svu rodbinu, sedamdeset i pet duša."},{"v":15,"t":"Jakov tako siđe u Egipat. I umrije on i oci naši."},{"v":16,"t":"Preneseni su u Sihem i položeni u grob koji je Abraham za srebro kupio od sinova Hamorovih u Sihemu.”"},{"v":17,"t":"“Kako se bližilo vrijeme obećanja koje Bog obreče Abrahamu, rastao je u Egiptu narod i množio se"},{"v":18,"t":"dok ondje ne zavlada drugi kralj koji nije poznavao Josipa."},{"v":19,"t":"Lukav prema rodu našemu, tlačio je on oce naše da bi djecu svoju izlagali da ne ostanu na životu."},{"v":20,"t":"U taj se čas rodi Mojsije. Bijaše božanski lijep. Tri je mjeseca hranjen u kući očinskoj,"},{"v":21,"t":"a onda, kad je bio izložen, prigrli ga kći faraonova i othrani sebi za sina."},{"v":22,"t":"Tako Mojsije, odgojen u svoj mudrosti egipatskoj, bijaše silan na riječima i djelima.”"},{"v":23,"t":"“Kad mu bijaše četrdeset godina, ponuka ga srce da pohodi braću svoju, sinove Izraelove."},{"v":24,"t":"I kad vidje kako je jednomu nanesena nepravda, suprotstavi se i osveti zlostavljenoga ubivši Egipćanina."},{"v":25,"t":"Mislio je da će braća njegova shvatiti kako će im Bog po njegovoj ruci pružiti spasenje, ali oni ne shvatiše."},{"v":26,"t":"Sutradan se pojavi pred onima koji su se tukli te ih stade nagovarati da se izmire: 'Ljudi, braća ste! Zašto zlostavljate jedan drugoga?'"},{"v":27,"t":"Ali ga onaj što je zlostavljao svoga bližnjega odbi riječima: Tko te postavi glavarom i sucem nad nama?"},{"v":28,"t":"Kaniš li ubiti i mene kao što si jučer ubio onog Egipćanina?"},{"v":29,"t":"Na te riječi pobježe Mojsije i skloni se u zemlju midjansku, gdje mu se rodiše dva sina.”"},{"v":30,"t":"“Nakon četrdeset godina ukaza mu se Anđeo u pustinji brda Sinaja u rasplamtjeloj vatri jednoga grma."},{"v":31,"t":"Opazivši to, zadivi se Mojsije viđenju. Dok je prilazio da bolje promotri, eto glasa Gospodnjega:"},{"v":32,"t":"Ja sam Bog Otaca tvojih, Bog Abrahamov, Izakov i Jakovljev. Sav preplašen, Mojsije se ne usudi pogledati."},{"v":33,"t":"A Gospodin će mu: Izuj obuću s nogu! Jer mjesto na kojem stojiš, sveto je tlo."},{"v":34,"t":"Vidio sam, vidio nevolju naroda svoga u Egiptu i uzdisaj mu čuo pa siđoh izbaviti ga. I sad hajde! Šaljem te u Egipat!”"},{"v":35,"t":"“Toga Mojsija - kojega su se odrekli rekavši: Tko te postavi glavarom i sucem? - toga im Bog kao glavara i otkupitelja posla po Anđelu koji mu se ukaza u grmu."},{"v":36,"t":"On ih izvede učinivši čudesa i znamenja u zemlji egipatskoj, u Crvenome moru i u pustinji kroz četrdeset godina."},{"v":37,"t":"To je onaj Mojsije koji reče sinovima Izraelovim: Proroka poput mene od vaše braće podići će vam Bog."},{"v":38,"t":"To je onaj koji za skupa u pustinji bijaše između Anđela što mu govoraše na brdu Sinaju i otaca naših; onaj koji je primio riječi životne da ih nama preda."},{"v":39,"t":"Njemu se ne htjedoše pokoriti oci naši, nego ga odbiše i u srcima se svojima vratiše u Egipat"},{"v":40,"t":"rekavši Aronu: 'Napravi nam bogove koji će ići pred nama! Ta ne znamo što se dogodi s tim Mojsijem koji nas izvede iz zemlje egipatske.'"},{"v":41,"t":"Tele načiniše u dane one, prinesoše žrtvu tom kumiru i veseljahu se djelima ruku svojih."},{"v":42,"t":"Bog se pak odvrati i prepusti ih da časte vojsku nebesku, kao što piše u Knjizi proročkoj: Prinosiste li mi žrtve i prinose četrdeset godina u pustinji, dome Izraelov?"},{"v":43,"t":"Poprimiste šator Molohov i zvijezdu boga Refana - likove koje napraviste da biste im se klanjali. Odvest ću vas stoga u progonstvo onkraj Babilona!”"},{"v":44,"t":"“Oci naši imahu u pustinji Šator svjedočanstva kako odredi Onaj koji reče Mojsiju da se on načini po praliku koji je vidio."},{"v":45,"t":"Taj su Šator preuzeli oci naši i pod Jošuom ga unijeli u posjed s kojega Bog pred licem njihovim rastjera narode. Tako bijaše sve do dana Davida,"},{"v":46,"t":"koji je našao milost pred Bogom te molio da nađe boravište Bogu Jakovljevu."},{"v":47,"t":"Istom Salomon izgradi mu Dom."},{"v":48,"t":"Ali Svevišnji u rukotvorinama ne prebiva, kao što veli prorok:"},{"v":49,"t":"Nebesa su moje prijestolje, a zemlja podnožje nogama. Kakav dom da mi sagradite, govori Gospodin, i gdje da bude mjesto mog počinka?"},{"v":50,"t":"Nije li ruka moja načinila sve to?"},{"v":51,"t":"Tvrdovrati i neobrezanih srdaca i ušiju, vi se uvijek opirete Duhu Svetomu: kako oci vaši tako i vi!"},{"v":52,"t":"Kojega od proroka nisu progonili oci vaši? I pobiše one koji su unaprijed navijestili dolazak Pravednika čiji ste vi sada izdajice i ubojice,"},{"v":53,"t":"vi koji po anđeoskim uredbama primiste Zakon, ali ga se niste držali.”"},{"v":54,"t":"Kad su to čuli, uskipješe u srcima i počeše škripati zubima na njega."},{"v":55,"t":"Ali on, pun Duha Svetoga, uprije pogled u nebo i ugleda slavu Božju i Isusa gdje stoji zdesna Bogu"},{"v":56,"t":"pa reče: “Evo vidim nebesa otvorena i Sina Čovječjega gdje stoji zdesna Bogu.”"},{"v":57,"t":"Vičući iza glasa, oni zatisnuše uši i navališe jednodušno na njega."},{"v":58,"t":"Izbaciše ga iz grada pa ga kamenovahu. Svjedoci odložiše haljine do nogu mladića koji se zvao Savao."},{"v":59,"t":"I dok su ga kamenovali, Stjepan je zazivao: “Gospodine Isuse, primi duh moj!”"},{"v":60,"t":"Onda se baci na koljena i povika iza glasa: “Gospodine, ne uzmi im ovo za grijeh!” Kada to reče, usnu."}]},"8":{"hr":[{"v":1,"t":"Savao je pristao da se Stjepan smakne. U onaj dan navali velik progon na Crkvu u Jeruzalemu. Svi se osim apostola raspršiše po krajevima judejskim i samarijskim."},{"v":2,"t":"Bogobojazni su ljudi pokopali Stjepana i održali veliko žalovanje za njim."},{"v":3,"t":"Savao je pak pustošio Crkvu: ulazio je u kuće, odvlačio muževe i žene i predavao ih u tamnicu."},{"v":4,"t":"Oni dakle što su se raspršili obilazili su navješćujući Riječ."},{"v":5,"t":"Filip tako siđe u grad samarijski i stade im propovijedati Krista."},{"v":6,"t":"Mnoštvo je jednodušno prihvaćalo što je Filip govorio slušajući ga i gledajući znamenja koja je činio."},{"v":7,"t":"Doista, iz mnogih su opsjednutih izlazili nečisti duhovi vičući iza glasa, a ozdravljali su i mnogi uzeti i hromi."},{"v":8,"t":"Nasta tako velika radost u onome gradu."},{"v":9,"t":"Čovjek se neki, imenom Šimun, u gradu već duže bavio čarobnjaštvom i opčaravao narod tvrdeći da je neki veliki."},{"v":10,"t":"Priklanjalo mu se sve, malo i veliko, te govorilo: “Ovaj je Snaga Božja, zvana Velika.”"},{"v":11,"t":"A priklanjahu mu se jer ih je duže vremena opčaravao svojim vradžbinama."},{"v":12,"t":"Ali kad povjerovaše Filipu koji navješćivaše evanđelje o kraljevstvu Božjemu i o imenu Isusa Krista, krštavahu se - muževi i žene."},{"v":13,"t":"Povjerova i Šimun te se krsti i osta uz Filipa: bio je zanesen promatrajući znamenja i čudesa koja su se događala."},{"v":14,"t":"Kad su apostoli u Jeruzalemu čuli da je Samarija prigrlila riječ Božju, poslaše k njima Petra i Ivana."},{"v":15,"t":"Oni siđoše i pomoliše se za njih da bi primili Duha Svetoga."},{"v":16,"t":"Jer još ni na koga od njih ne bijaše sišao; bijahu samo kršteni u ime Gospodina Isusa."},{"v":17,"t":"Tada polagahu ruke na njih i oni primahu Duha Svetoga."},{"v":18,"t":"Kad Šimun vidje da se polaganjem ruku apostolskih daje Duh, ponudi apostolima novaca"},{"v":19,"t":"govoreći: “Dajte i meni tu moć da svatko na koga položim ruke primi Duha Svetoga.”"},{"v":20,"t":"Petar mu odvrati: “Novac tvoj zajedno s tobom propao kad si mislio dar Božji novcima steći!"},{"v":21,"t":"Nema tebi ovdje dijela ni udjela jer tvoje srce nije pravo pred Bogom!"},{"v":22,"t":"Obrati se od te opakosti svoje i moli Gospodina ne bi li ti se kako oprostila namisao srca tvoga."},{"v":23,"t":"Ta gledam te: žučju si gorak i nepravdom okovan.”"},{"v":24,"t":"Šimun odgovori: “Molite i vi za me Gospodina da me ne snađe ništa od toga što rekoste!”"},{"v":25,"t":"Oni pak pošto posvjedočiše i dorekoše riječ Gospodnju, vratiše se u Jeruzalem navješćujući evanđelje mnogim selima samarijskim."},{"v":26,"t":"Anđeo se Gospodnji obrati Filipu: “Ustani i pođi na jug putom što iz Jeruzalema silazi u Gazu; on je pust.”"},{"v":27,"t":"On usta i pođe. Odjednom eto nekog Etiopljanina, dvoranina, visokog dostojanstvenika kandake, kraljice etiopske koji bijaše nad svom njezinom riznicom."},{"v":28,"t":"Vraćao se iz Jeruzalema, kamo je bio pošao pokloniti se; sjeđaše na svojim kolima i čitaše proroka Izaiju."},{"v":29,"t":"Duh reče Filipu: “Pođi i pridruži se tim kolima!”"},{"v":30,"t":"Filip pritrča i ču gdje onaj čita Izaiju proroka pa će mu: “Razumiješ li što čitaš?”"},{"v":31,"t":"On odvrati: “Kako bih mogao ako me tko ne uputi?” Onda zamoli Filipa da se uspne i sjedne uza nj."},{"v":32,"t":"A čitao je ovaj odlomak Pisma: Ko ovcu na klanje odvedoše ga, ko janje nijemo pred onim što ga striže on ne otvara svojih usta."},{"v":33,"t":"U poniženju sud mu je uskraćen. Naraštaj njegov tko da opiše? Da, uklonjen je sa zemlje život njegov."},{"v":34,"t":"Dvoranin se obrati Filipu pa će mu: “Molim te, o kome to prorok govori? O sebi ili o kome drugom?"},{"v":35,"t":"Filip prozbori te mu, pošavši od toga Pisma, navijesti evanđelje: Isusa."},{"v":36,"t":"Putujući tako, stigoše do neke vode pa će dvoranin: “Evo vode! Što priječi da se krstim?”"},{"v":37,"t":"#"},{"v":38,"t":"Zapovjedi da kola stanu pa obojica, Filip i dvoranin, siđoše u vodu te ga Filip krsti."},{"v":39,"t":"A kad iziđoše iz vode, Duh Gospodnji ugrabi Filipa te ga dvoranin više ne vidje. On radosno nastavi svojim putom,"},{"v":40,"t":"a Filip se nađe u Azotu. I kako je prolazio, navješćivaše evanđelje svim gradovima dok ne stiže u Cezareju."}]},"9":{"hr":[{"v":1,"t":"Savao pak, sveudilj zadahnut prijetnjom i pokoljem prema učenicima Gospodnjim, pođe k velikomu svećeniku,"},{"v":2,"t":"zaiska od njega pisma za sinagoge u Damasku, da sve koje nađe od ovoga Puta, muževe i žene, okovane dovede u Jeruzalem."},{"v":3,"t":"Kad se putujući približi Damasku, iznenada ga obasja svjetlost s neba."},{"v":4,"t":"Sruši se na zemlju i začu glas što mu govoraše: “Savle, Savle, zašto me progoniš?”"},{"v":5,"t":"On upita: “Tko si, Gospodine?” A on će: “Ja sam Isus kojega ti progoniš!"},{"v":6,"t":"Nego ustani, uđi u grad i reći će ti se što ti je činiti.”"},{"v":7,"t":"Njegovi suputnici ostadoše bez riječi: čuli su doduše glas, ali ne vidješe nikoga."},{"v":8,"t":"Savao usta sa zemlje. Otvorenih očiju nije ništa vidio pa ga povedu za ruku i uvedu u Damask."},{"v":9,"t":"Tri dana nije vidio, nije jeo ni pio."},{"v":10,"t":"U Damasku bijaše neki učenik imenom Ananija. Njemu u viđenju reče Gospodin: “Ananija!” On se odazva: “Evo me, Gospodine!”"},{"v":11,"t":"A Gospodin će mu: “Ustani, pođi u ulicu zvanu Ravna i u kući Judinoj potraži Taržanina imenom Savla. Eno, moli se;"},{"v":12,"t":"i u viđenju vidje čovjeka imenom Ananiju gdje ulazi i polaže na nj ruke da bi progledao.”"},{"v":13,"t":"Ananija odgovori: “Gospodine, od mnogih sam čuo o tom čovjeku kolika je zla tvojim svetima učinio u Jeruzalemu."},{"v":14,"t":"On ima od velikih svećenika i punomoć okovati sve koji prizivlju ime tvoje.”"},{"v":15,"t":"Gospodin mu odvrati: “Pođi jer on mi je oruđe izabrano da ponese ime moje pred narode i kraljeve i sinove Izraelove."},{"v":16,"t":"Ja ću mu uistinu pokazati koliko mu je za ime moje trpjeti.”"},{"v":17,"t":"Ananija ode, uđe u kuću, položi na nj ruke i reče: “Savle, brate! Gospodin, Isus koji ti se ukaza na putu kojim si išao, posla me da progledaš i napuniš se Duha Svetoga.”"},{"v":18,"t":"I odmah mu s očiju spade nešto kao ljuske te on progleda pa usta, krsti se"},{"v":19,"t":"i uzevši hrane, okrijepi se. Nekoliko dana provede s učenicima u Damasku."},{"v":20,"t":"te odmah stade po sinagogama propovijedati Isusa, da je on Sin Božji."},{"v":21,"t":"Koji ga god slušahu, izvan sebe govorahu: “Nije li ovo onaj koji je u Jeruzalemu istrebljivao sve koji Ime ovo prizivlju, pa i ovamo zato došao da ih okovane odvede pred velike svećenike?”"},{"v":22,"t":"Savao pak, sve silniji, zbunjivaše Židove koji prebivahu u Damasku dokazujući: “Ovo je Krist!”"},{"v":23,"t":"Pošto je minulo podosta vremena, odluče Židovi pogubiti ga,"},{"v":24,"t":"ali Savao dozna za njihov naum. Nadzirahu i vrata danju i noću da bi ga pogubili,"},{"v":25,"t":"ali ga učenici noću uzeše i preko zidina oprezno spustiše u košari."},{"v":26,"t":"Kad je Savao došao u Jeruzalem, gledao se pridružiti učenicima, ali ga se svi bojahu: nisu vjerovali da je učenik."},{"v":27,"t":"Tada ga Barnaba uze i povede k apostolima te im pripovjedi kako je Savao na putu vidio Gospodina koji mu je govorio i kako je u Damasku smjelo propovijedao u ime Isusovo."},{"v":28,"t":"Od tada se s njima slobodno kretao po Jeruzalemu i smjelo propovijedao u ime Gospodnje."},{"v":29,"t":"Govorio je i raspravljao sa Židovima grčkog jezika pa i oni snovahu pogubiti ga."},{"v":30,"t":"Saznala to braća pa ga odvedoše u Cezareju i uputiše u Tarz."},{"v":31,"t":"Crkva je po svoj Judeji, Galileji i Samariji uživala mir, izgrađivala se i napredovala u strahu Gospodnjem te rasla utjehom Svetoga Duha."},{"v":32,"t":"Jednom Petar, obilazeći posvuda, siđe i k svetima u Lidi."},{"v":33,"t":"Ondje nađe nekog čovjeka imenom Eneja, koji je osam godina ležao na postelji: bijaše uzet."},{"v":34,"t":"Reče mu Petar: “Eneja, ozdravlja te Isus Krist! Ustani i prostri sam sebi!” On umah usta."},{"v":35,"t":"Vidješe to svi žitelji Lide i Šarona te se obratiše Gospodinu."},{"v":36,"t":"U Jopi pak bijaše učenica imenom Tabita, što prevedeno znači Košuta. Bijaše ona bogata dobrim djelima i milostinjama što ih je dijelila."},{"v":37,"t":"Upravo u one dane obolje i umrije. Pošto je operu, izlože je u gornjoj sobi."},{"v":38,"t":"A kako je Lida blizu Jope, učenici čuše da je Petar ondje i poslaše k njemu dva čovjeka s molbom: “Dođi k nama, ne oklijevaj!”"},{"v":39,"t":"Petar usta i krenu s njima. Čim stiže, odvedoše ga u gornju sobu. Okružiše ga sve udovice te mu plačući pokazivahu haljine i odijela što ih je Košuta izrađivala dok je još bila s njima."},{"v":40,"t":"Petar sve istjera van, kleknu, pomoli se pa se okrenu prema tijelu i reče: “Tabita, ustani!” Ona otvori oči, pogleda Petra i sjede."},{"v":41,"t":"On joj pruži ruku i pridiže je. Onda pozove svete i udovice pa im je pokaza živu."},{"v":42,"t":"Dozna se za to po svoj Jopi te mnogi povjerovaše u Gospodina."},{"v":43,"t":"Petar osta neko vrijeme u Jopi u nekog Šimuna kožara."}]},"10":{"hr":[{"v":1,"t":"U Cezareji bijaše neki čovjek imenom Kornelije, satnik takozvane italske čete,"},{"v":2,"t":"pobožan i bogobojazan sa svim svojim domom. Dijelio je mnoge milostinje narodu i bez prestanka se molio Bogu."},{"v":3,"t":"U viđenju negdje oko devete ure dana ugleda on jasno anđela Božjega gdje dolazi k njemu i veli mu: “Kornelije!”"},{"v":4,"t":"Zagleda se u nj pa mu prestrašen reče: “Što je, Gospodine?” A on njemu: “Molitve su tvoje i milostinje uzišle kao žrtva podsjetnica pred Boga."},{"v":5,"t":"Zato sada pošalji ljude u Jopu i dozovi Šimuna koji se zove Petar."},{"v":6,"t":"On je gost u nekog Šimuna kožara čija je kuća uz more.”"},{"v":7,"t":"Čim ode anđeo koji mu je govorio, pozove on dvojicu slugu i jednoga pobožna, privržena vojnika,"},{"v":8,"t":"sve im ispripovjedi i posla ih u Jopu."},{"v":9,"t":"Sutradan, dok su oni putovali i približavali se gradu, oko šeste ure uziđe Petar na krov moliti."},{"v":10,"t":"Ogladnje i zaželje se jela. Dok mu pripremahu, pade on u zanos."},{"v":11,"t":"Gleda on nebo rastvoreno i posudu neku poput velika platna: uleknuta s četiri okrajka, silazi na zemlju."},{"v":12,"t":"U njoj bijahu svakovrsni četveronošci, gmazovi zemaljski i ptice nebeske."},{"v":13,"t":"I glas će mu neki: “Ustaj, Petre! Kolji i jedi!”"},{"v":14,"t":"Petar odvrati: “Nipošto, Gospodine! Ta nikad još ne okusih ništa okaljano i nečisto”."},{"v":15,"t":"A glas će mu opet, po drugi put: “Što Bog očisti, ti ne zovi okaljanim!”"},{"v":16,"t":"To se ponovi do triput, a onda je posuda ponesena na nebo."},{"v":17,"t":"Dok se Petar dvoumio što bi imalo značiti viđenje koje vidje, eto ljudi koje je poslao Kornelije: pošto se raspitaše za Šimunovu kuću, pojave se na vratima,"},{"v":18,"t":"zovnu te upitaju je li ondje ugošćen neki Šimun, nazvan Petar."},{"v":19,"t":"Dok je Petar sveudilj razmišljao o viđenju, reče mu Duh: “Evo, neka te trojica traže."},{"v":20,"t":"De ustani, siđi i pođi s njima ne skanjujući se jer ja sam ih poslao.”"},{"v":21,"t":"Petar siđe k ljudima i reče: “Evo me! Ja sam onaj kojega tražite! Zbog čega ste došli?”"},{"v":22,"t":"Oni odgovore: “Satnik Kornelije, muž pravedan i bogobojazan, za kojega svjedoči sav narod židovski, primi od svetog anđela naputak da te dozove u dom svoj i čuje od tebe riječi.”"},{"v":23,"t":"Tada ih Petar pozva unutra i ugosti. Sutradan usta i krenu s njima; pratila ga neka braća iz Jope."},{"v":24,"t":"Drugi dan stiže u Cezareju. Kornelije ih je čekao sazvavši rodbinu i prisne prijatelje."},{"v":25,"t":"Kad je Petar ulazio, pohrli mu Kornelije u susret, padne mu k nogama i pokloni se."},{"v":26,"t":"Petar ga pridigne govoreći: “Ustani! I ja sam čovjek.”"},{"v":27,"t":"I razgovarajući s njime, uđe i nađe sabrane mnoge"},{"v":28,"t":"te im reče: “Vi znate kako je Židovu zabranjeno družiti se sa strancem ili k njemu ulaziti, ali meni Bog pokaza da nikoga ne zovem okaljanim ili nečistim."},{"v":29,"t":"Stoga, pozvan, i dođoh bez pogovora. Da čujemo dakle zbog čega me pozvaste!”"},{"v":30,"t":"Kornelije reče: “Prije četiri dana baš u ovo doba, o devetoj uri, molio sam se u kući kad gle: čovjek neki u sjajnoj odjeći stane preda me"},{"v":31,"t":"i reče: 'Kornelije, uslišana ti je molitva i milostinje su tvoje spomenute pred Bogom!"},{"v":32,"t":"Pošalji dakle u Jopu i dozovi Šimuna koji se zove Petar. On je gost u kući Šimuna kožara uz more.'"},{"v":33,"t":"Odmah sam dakle poslao k tebi, a ti si dobro učinio što si došao. Evo nas dakle sviju pred Bogom da čujemo sve što ti zapovjedi Gospodin!”"},{"v":34,"t":"Petar tada prozbori i reče: “Sad uistinu shvaćam da Bog nije pristran,"},{"v":35,"t":"nego - u svakom je narodu njemu mio onaj koji ga se boji i čini pravdu."},{"v":36,"t":"Riječ posla sinovima Izraelovim navješćujući im evanđelje: mir po Isusu Kristu; on je Gospodar sviju."},{"v":37,"t":"Vi znate što se događalo po svoj Judeji, počevši od Galileje, nakon krštenja koje je propovijedao Ivan:"},{"v":38,"t":"kako Isusa iz Nazareta Bog pomaza Duhom Svetim i snagom, njega koji je, jer Bog bijaše s njime, prošao zemljom čineći dobro i ozdravljajući sve kojima bijaše ovladao đavao.”"},{"v":39,"t":"“Mi smo svjedoci svega što on učini u zemlji judejskoj i Jeruzalemu. I njega smakoše, objesivši ga na drvo!"},{"v":40,"t":"Bog ga uskrisi treći dan i dade mu da se očituje -"},{"v":41,"t":"ne svemu narodu, nego svjedocima od Boga predodređenima - nama koji smo s njime zajedno jeli i pili pošto uskrsnu od mrtvih.”"},{"v":42,"t":"“On nam i naloži propovijedati narodu i svjedočiti: Ovo je onaj kojega Bog postavi sucem živih i mrtvih!”"},{"v":43,"t":"“Za nj svjedoče svi proroci: da tko god u nj vjeruje, po imenu njegovu prima oproštenje grijeha.”"},{"v":44,"t":"Dok je Petar još govorio te riječi, siđe Duh Sveti na sve koji su slušali tu besjedu."},{"v":45,"t":"A vjernici iz obrezanja, koji dođoše zajedno s Petrom, začudiše se što se i na pogane izlio dar Duha Svetoga."},{"v":46,"t":"Jer čuli su ih govoriti drugim jezicima i veličati Boga. Tada Petar reče:"},{"v":47,"t":"“Može li tko uskratiti vodu da se ne krste ovi koji su primili Duha Svetoga kao i mi?”"},{"v":48,"t":"I zapovjedi da se krste u ime Isusa Krista. Tada ga zamole da ostane ondje nekoliko dana."}]},"11":{"hr":[{"v":1,"t":"Dočuli apostoli i braća po Judeji da i pogani primiše riječ Božju"},{"v":2,"t":"pa kad Petar uziđe u Jeruzalem, uzeše mu obrezanici prigovarati:"},{"v":3,"t":"“Ušao si, dobacivahu, k ljudima neobrezanima i jeo s njima!”"},{"v":4,"t":"Onda započe Petar te im izloži sve po redu:"},{"v":5,"t":"“Molio sam se, reče, u Jopi kadli u zanosu ugledam viđenje: posudu neku poput velika platna, uleknuta s četiri okrajka, gdje silazi s neba i dolazi do mene."},{"v":6,"t":"Zagledah se, promotrih je i vidjeh četvoronošce zemaljske, zvijeri i gmazove te ptice nebeske."},{"v":7,"t":"Začuh i glas koji mi govoraše: 'Ustaj, Petre! Kolji i jedi!'"},{"v":8,"t":"Ja odvratih: 'Nipošto, Gospodine! Ta nikad mi još ništa okaljano ili nečisto ne uđe u usta.'"},{"v":9,"t":"A glas će s neba po drugi put: 'Što Bog očisti, ti ne zovi nečistim.'"},{"v":10,"t":"To se ponovi do triput, a onda se sve opet povuče na nebo.”"},{"v":11,"t":"“I odmah se, evo, pred kućom u kojoj bijah pojaviše tri čovjeka poslana iz Cezareje k meni."},{"v":12,"t":"A Duh mi reče da pođem s njima ništa ne premišljajući. Sa mnom pođoše i ova šestorica braće te uđosmo u kuću tog čovjeka."},{"v":13,"t":"On nam pripovjedi kako je u svojoj kući vidio anđela koji je stao preda nj i rekao: 'Pošalji u Jopu i dozovi Šimuna nazvanog Petar;"},{"v":14,"t":"on će ti navijestiti riječi po kojima ćeš se spasiti ti i sav dom tvoj.'”"},{"v":15,"t":"“I kad počeh govoriti, siđe na njih Duh Sveti kao ono na nas u početku."},{"v":16,"t":"Sjetih se tada riječi Gospodnje: 'Ivan je, govoraše on, krstio vodom, a vi ćete biti kršteni Duhom Svetim.'"},{"v":17,"t":"Ako im je dakle Bog dao isti dar kao i nama koji povjerovasmo u Gospodina Isusa Krista, tko sam ja da bih se smio oprijeti Bogu?”"},{"v":18,"t":"Kad su to čuli, umiriše se te stadoše slaviti Boga govoreći: “Dakle i poganima Bog dade obraćenje na život!”"},{"v":19,"t":"Oni dakle što ih rasprši nevolja nastala u povodu Stjepana dopriješe do Fenicije, Cipra i Antiohije, nikomu ne propovijedajući Riječi doli samo Židovima."},{"v":20,"t":"Neki su od njih bili Ciprani i Cirenci. Kad stigoše u Antiohiju, propovijedahu i Grcima navješćujući evanđelje: Gospodina, Isusa."},{"v":21,"t":"Ruka Gospodnja bijaše s njima te velik broj ljudi povjerova i obrati se Gospodinu."},{"v":22,"t":"Vijest o tome doprije do Crkve u Jeruzalemu pa poslaše Barnabu u Antiohiju."},{"v":23,"t":"Kad on stiže i vidje milost Božju, obradova se te potaknu sve da u odlučnosti srca ostanu uz Gospodina."},{"v":24,"t":"Ta bijaše to muž čestit, pun Duha Svetoga i vjere. Znatno se mnoštvo prikloni Gospodinu."},{"v":25,"t":"Barnaba se zatim zaputi u Tarz potražiti Savla."},{"v":26,"t":"Kad ga nađe, odvede ga u Antiohiju. Punu su se godinu dana sastajali u toj Crkvi i poučavali poveće mnoštvo te se u Antiohiji učenici najprije prozvaše kršćanima."},{"v":27,"t":"U one dane dođoše u Antiohiju neki proroci iz Jeruzalema."},{"v":28,"t":"Jedan od njih, imenom Agab, usta i po Duhu pretkaza da će uskoro nastati velika glad po svem svijetu. Ona i nasta za Klaudija."},{"v":29,"t":"Stoga će svatko od učenika, odlučiše, koliko smogne poslati da se posluži braći u Judeji."},{"v":30,"t":"To i učiniše te poslaše starješinama po Barnabi i Savlu."}]},"12":{"hr":[{"v":1,"t":"U to vrijeme uze Herod zlostavljati neke od Crkve."},{"v":2,"t":"Mačem pogubi Jakova, brata Ivanova."},{"v":3,"t":"Kad vidje da je to drago Židovima, uhvati i Petra (bijahu upravo Dani beskvasnih kruhova)."},{"v":4,"t":"Uhiti ga, baci u tamnicu i dade da ga čuvaju četiri vojničke četverostraže, nakan izvesti ga nakon Pashe pred narod."},{"v":5,"t":"Petra su dakle čuvali u tamnici, a Crkva se svesrdno moljaše Bogu za njega."},{"v":6,"t":"One noći kad ga je Herod kanio privesti, spavao je Petar između dva vojnika, okovan dvojim verigama, a stražari pred vratima čuvahu stražu."},{"v":7,"t":"Kad eto: pojavi se anđeo Gospodnji te svjetlost obasja ćeliju. Anđeo udari Petra u rebra, probudi ga i reče: “Ustaj brzo!” I spadoše mu verige s ruku."},{"v":8,"t":"Anđeo mu reče: “Opaši se i priveži obuću!” On učini tako. Onda će mu anđeo: “Zaogrni se i hajde za mnom!”"},{"v":9,"t":"Petar izađe, pođe za njim, a nije znao da je zbilja što se događa po anđelu: činilo mu se da gleda viđenje."},{"v":10,"t":"Prošavši prvu stražu, i drugu, dođoše do željeznih vrata koja vode u grad. Ona im se sama otvore te oni izađu, prođu jednu ulicu, a onda anđeo odjednom odstupi od njega."},{"v":11,"t":"Petar pak, došavši k sebi, reče: “Sad uistinu znam da je Gospodin poslao anđela svoga i izbavio me iz Herodove ruke i od svega što je očekivao židovski narod.”"},{"v":12,"t":"Kad je to uočio, zaputi se kući Marije, majke Ivana nazvanog Marko. Ondje se mnogi bijahu sabrali i molili."},{"v":13,"t":"Kad Petar pokuca na dvorišna vrata, dođe prisluhnuti sluškinja imenom Ruža."},{"v":14,"t":"Kad prepozna Petrov glas, od radosti i ne otvori vrata, nego utrča i javi da je Petar pred vratima."},{"v":15,"t":"Oni joj rekoše: “Mahnitaš!” Ali je ona uporno tvrdila da je tako. Nato će oni: “Bit će njegov anđeo!”"},{"v":16,"t":"Petar nastavi kucati. Kad napokon otvoriše i ugledaše ga, ostadoše izvan sebe."},{"v":17,"t":"On im rukom mahnu neka šute pa im pripovjedi kako ga Gospodin izvede iz tamnice te dometnu: “Javite to Jakovu i braći!” Onda izađe i ode u drugo mjesto."},{"v":18,"t":"Kad se razdani, nasta među vojnicima uzbuna nemalena što li se s Petrom dogodilo."},{"v":19,"t":"Herod ga stade tražiti, a kad ga ne nađe, sasluša stražare i naredi da se smaknu. Onda siđe iz Judeje u Cezareju i ondje osta."},{"v":20,"t":"A bio je u žestoku sukobu s Tircima i Sidoncima. Oni zajednički dođoše k njemu i pošto pridobiše kraljevskoga komornika Blasta, zaiskaše mir, jer je njihova zemlja dobivala živež od kraljeve."},{"v":21,"t":"U određeni dan sjede Herod odjeven u kraljevsko ruho na prijestol i stade im govoriti."},{"v":22,"t":"Narod izvikivaše: “Božji glas, a ne ljudski!”"},{"v":23,"t":"Umah ga, zbog toga što ne dade slavu Bogu, udari anđeo Gospodnji te on rascrvotočen izdahnu."},{"v":24,"t":"Riječ je pak Božja rasla i širila se."},{"v":25,"t":"Barnaba i Savao, pošto obaviše služenje u Jeruzalemu, vratiše se uzevši sa sobom Ivana zvanog Marko."}]},"13":{"hr":[{"v":1,"t":"U antiohijskoj je Crkvi bilo proroka i učitelja: Barnaba, Šimun zvani Niger, Lucije Cirenac, Manahen, suothranjenik Heroda četverovlasnika, i Savao."},{"v":2,"t":"Dok su jednom obavljali službu Božju i postili, reče Duh Sveti: “De mi odlučite Barnabu i Savla za djelo na koje sam ih pozvao.”"},{"v":3,"t":"Onda su postili, molili, položili na njih ruke i otpustili ih."},{"v":4,"t":"Poslani od Svetoga Duha siđu u Seleuciju, a odande odjedre na Cipar."},{"v":5,"t":"Kad se nađoše u Salamini, navješćivahu riječ Božju u židovskim sinagogama. Imali su i Ivana za poslužitelja."},{"v":6,"t":"Pošto pak prođoše sav otok do Pafa, nađoše nekog vračara, nazoviproroka, Židova, imenom Barjesu."},{"v":7,"t":"On bijaše uz namjesnika Sergija Pavla, čovjeka razborita. Sergije dozva Barnabu i Savla te zaiska čuti riječ Božju,"},{"v":8,"t":"ali im se usprotivi Elim, Vračar - tako mu se ime prevodi - nastojeći odvratiti namjesnika od vjere."},{"v":9,"t":"Savao pak, zvan i Pavao, pun Duha Svetoga, ošinu ga pogledom"},{"v":10,"t":"i reče: “Pun svake lukavosti i prevrtljivosti, sine đavolski, neprijatelju svake pravednosti, zar nikako da prestaneš iskrivljavati ravne putove Gospodnje?"},{"v":11,"t":"Evo stoga sada ruke Gospodnje na tebi: oslijepljet ćeš i neko vrijeme nećeš gledati sunca!” Odmah pade na nj mrak i tama te on glavinjajući stade tražiti ruke vodilje."},{"v":12,"t":"Videći što se dogodilo, povjerova tada namjesnik, zanesen naukom Gospodnjim."},{"v":13,"t":"Pošto se Pavao i oni oko njega otisnuše od Pafa, stigoše u Pergu pamfilijsku. Ivan ih napusti te se vrati u Jeruzalem."},{"v":14,"t":"Oni pak krenuše iz Perge i stigoše u Antiohiju pizidijsku. U dan subotni ušli su u sinagogu i sjeli."},{"v":15,"t":"Nakon čitanja Zakona i Proroka pošalju nadstojnici sinagoge k njima: “Braćo, rekoše, ima li u vas koja riječ utjehe za narod, govorite!”"},{"v":16,"t":"Nato usta Pavao, dadne rukom znak i reče: “Izraelci i vi koji se Boga bojite, čujte!"},{"v":17,"t":"Bog naroda ovoga, Izraela, izabra oce naše i uzdiže narod za boravka u zemlji egipatskoj te ga ispruženom rukom izvede iz nje."},{"v":18,"t":"Oko četrdeset ga je godina na rukama nosio u pustinji"},{"v":19,"t":"pa pošto zatre sedam naroda u zemlji kanaanskoj, ubaštini ga u zemlji njihovoj"},{"v":20,"t":"za kakve četiri stotine i pedeset godina. Nakon toga dade im suce - do Samuela proroka."},{"v":21,"t":"Onda zaiskaše kralja pa im Bog za četrdeset godina dade Šaula, sina Kiševa, iz plemena Benjaminova."},{"v":22,"t":"Pošto svrgnu njega, podiže im za kralja Davida za kojega posvjedoči: Nađoh Davida, sina Jišajeva, čovjeka po svom srcu, koji će ispuniti sve moje želje."},{"v":23,"t":"Iz njegova potomstva izvede Bog po svom obećanju Izraelu Spasitelja, Isusa."},{"v":24,"t":"Pred njegovim je dolaskom Ivan propovijedao krštenje obraćenja svemu narodu izraelskomu."},{"v":25,"t":"A kad je Ivan dovršavao svoju trku, govorio je: 'Nisam ja onaj za koga me vi držite. Nego za mnom evo dolazi onaj komu ja nisam dostojan odriješiti obuće na nogama.'”"},{"v":26,"t":"“Braćo, sinovi roda Abrahamova, vi i oni koji se među vama Boga boje, nama je upravljena ova Riječ spasenja."},{"v":27,"t":"Doista, žitelji Jeruzalema i glavari njihovi ne upoznaše njega ni riječi proročkih što se čitaju svake subote pa ih, osudivši ga, ispuniše."},{"v":28,"t":"Premda ne nađoše nikakva razloga smrti, zatražiše od Pilata da ga smakne."},{"v":29,"t":"Pošto pak izvršiše sve što je o njemu napisano, skinuše ga s drveta i položiše u grob."},{"v":30,"t":"Ali Bog ga uskrisi od mrtvih."},{"v":31,"t":"On se mnogo dana ukazivao onima koji s njim bijahu uzašli iz Galileje u Jeruzalem. Oni su sada njegovi svjedoci pred narodom.”"},{"v":32,"t":"“I mi vam navješćujemo evanđelje: obećanje dano ocima"},{"v":33,"t":"Bog je ispunio djeci, nama, uskrisivši Isusa, kao što je i pisano u Psalmu drugom: Ti si Sin moj, danas te rodih."},{"v":34,"t":"Da ga pak uskrisi od mrtvih te se on više nikad neće vratiti u trulež, rekao je ovime: Dat ću vama svetinje Davidove, pouzdane."},{"v":35,"t":"Zato i na drugome mjestu kaže: Nećeš dati da Svetac tvoj ugleda truleži."},{"v":36,"t":"David doista, pošto u svom naraštaju posluži volji Božjoj, preminu, pridruži se ocima svojim i vidje trulež,"},{"v":37,"t":"a Onaj koga Bog uskrisi ne vidje truleži."},{"v":38,"t":"/"},{"v":39,"t":"Neka vam dakle braćo, znano bude: po Ovome vam se navješćuje oproštenje grijeha! Po Ovome se tko god vjeruje, opravdava od svega od čega se po Mojsijevu zakonu niste mogli opravdati!"},{"v":40,"t":"Pazite da se ne zbude što je rečeno u Prorocima:"},{"v":41,"t":"Obazrite se, preziratelji, snebijte se i nestanite! Jer djelo činim u dane vaše, djelo u koje ne biste vjerovali da vam ga tko ispriča.”"},{"v":42,"t":"Na izlasku su ih molili da im iduće subote o tome govore."},{"v":43,"t":"A pošto se skup raspustio, mnogi Židovi i bogobojazne pridošlice pođoše za Pavlom i Barnabom koji su ih nagovarali ustrajati u milosti Božjoj."},{"v":44,"t":"Iduće se subote gotovo sav grad zgrnu čuti riječ Gospodnju."},{"v":45,"t":"Kad su Židovi ugledali mnoštvo, puni zavisti psujući suprotstavljali su se onomu što je Pavao govorio."},{"v":46,"t":"Na to im Pavao i Barnaba smjelo rekoše: “Trebalo je da se najprije vama navijesti riječ Božja. Ali kad je odbacujete i sami sebe ne smatrate dostojnima života vječnoga, obraćamo se evo poganima."},{"v":47,"t":"Jer ovako nam je zapovjedio Gospodin: Postavih te za svjetlost poganima, da budeš na spasenje do nakraj zemlje."},{"v":48,"t":"Pogani koji su slušali radovali su se i slavili riječ Gospodnju te povjerovaše oni koji bijahu određeni za život vječni."},{"v":49,"t":"Riječ se pak Gospodnja pronese po svoj onoj pokrajini."},{"v":50,"t":"Ali Židovi potakoše ugledne bogobojazne žene i prvake gradske te zametnuše progon protiv Pavla i Barnabe pa ih izbaciše iz svoga kraja."},{"v":51,"t":"Oni pak stresu prašinu s nogu protiv njih pa odu u Ikonij."},{"v":52,"t":"A učenici su se ispunjali radošću i Duhom Svetim."}]},"14":{"hr":[{"v":1,"t":"U Ikoniju isto tako uđoše u židovsku sinagogu i govorahu tako da povjerova veliko mnoštvo Židova i Grka."},{"v":2,"t":"Ali nepokorni Židovi razdražiše i podjariše pogane protiv braće."},{"v":3,"t":"Oni se ipak zadržaše duže vremena, smjeli u Gospodinu koji je svjedočio za Riječ milosti svoje, davao da se po njihovim rukama događaju znamenja i čudesa."},{"v":4,"t":"Mnoštvo se gradsko podvoji: jedni bijahu za Židove, drugi za apostole."},{"v":5,"t":"Pogani i Židovi sa svojim glavarima navališe da zlostave i kamenuju apostole."},{"v":6,"t":"Kada to opaziše, prebjegoše oni u likaonske gradove Listru i Derbu i okolicu."},{"v":7,"t":"Ondje su navješćivali evanđelje."},{"v":8,"t":"U Listri je sjedio neki čovjek uzetih nogu, hrom od majčine utrobe; nikada nije hodao."},{"v":9,"t":"Čuo je Pavla gdje govori."},{"v":10,"t":"Pavao ga pronikne pogledom, vidje da ima vjeru u spasenje pa mu iza glasa reče: “Uspravi se na noge!” On skoči i prohoda."},{"v":11,"t":"Kad mnoštvo ugleda što učini Pavao, povika likaonski: “Bogovi u ljudskom obličju siđoše k nama!”"},{"v":12,"t":"I nazvaše Barnabu Zeusom, a Pavla Hermesom jer je Pavao vodio riječ."},{"v":13,"t":"A svećenik Zeusa Predgradskoga dovede pred vrata bikove i vijence te u zajednici s narodom htjede žrtvovati."},{"v":14,"t":"Kada su to dočuli apostoli Barnaba i Pavao, razdriješe haljine i uletješe u narod vičući:"},{"v":15,"t":"“Ljudi, što to radite? I mi smo smrtnici, baš kao i vi! Navješćujemo vam da se od tih ispraznosti obratite k Bogu živomu koji stvori nebo i zemlju, more i sve što je u njima."},{"v":16,"t":"On je u prošlim naraštajima pustio da svi pogani pođu svojim putovima."},{"v":17,"t":"Ipak ne ostavi sebe neposvjedočena: dobročinstva iskazuje, s neba vam kišu daje i vremena plodonosna, napunja hranom i radošću srca vaša.”"},{"v":18,"t":"I tako govoreći, jedva sklonuše mnoštvo da im ne žrtvuje."},{"v":19,"t":"Uto iz Antiohije i Ikonija nadođu neki Židovi, pridobiju svjetinu te kamenuju Pavla i odvuku ga izvan grada misleći da je mrtav."},{"v":20,"t":"Kad ga pak okružiše učenici, usta on i uđe u grad. Sutradan ode s Barnabom u Derbu."},{"v":21,"t":"Pošto navijestiše evanđelje tomu gradu i mnoge učiniše učenicima, vratiše se u Listru, u Ikonij i u Antiohiju."},{"v":22,"t":"Učvršćivali su duše učenika bodreći ih da ustraju u vjeri jer da nam je kroz mnoge nevolje ući u kraljevstvo Božje."},{"v":23,"t":"Postavljali su im po crkvama starješine te ih, nakon molitve i posta, povjeravahu Gospodinu u kojega su povjerovali."},{"v":24,"t":"Pošto su prešli Pizidiju, stigoše u Pamfiliju."},{"v":25,"t":"U Pergi navijestiše Riječ pa siđu u Ataliju."},{"v":26,"t":"Odande pak odjedriše u Antiohiju, odakle ono bijahu povjereni milosti Božjoj za djelo koje izvršiše."},{"v":27,"t":"Kada stigoše, sabraše Crkvu i pripovjediše što sve učini Bog po njima: da i poganima otvori vrata vjere."},{"v":28,"t":"I proveli su nemalo vremena s učenicima."}]},"15":{"hr":[{"v":1,"t":"Uto neki siđoše iz Judeje i počeše učiti braću: “Ako se ne obrežete po običaju Mojsijevu, ne možete se spasiti.”"},{"v":2,"t":"Kad između njih te Pavla i Barnabe nasta prepirka i raspra nemalena, odrediše da Pavao i Barnaba i još neki drugi između njih uzađu u Jeruzalem k apostolima i starješinama poradi tog pitanja."},{"v":3,"t":"Oni su dakle, ispraćeni od Crkve, prolazili kroz Feniciju i Samariju pripovijedajući o obraćenju pogana i donoseći svoj braći veliku radost."},{"v":4,"t":"Kada pak stigoše u Jeruzalem, primi ih Crkva, apostoli i starješine. Ispripovjediše što sve Bog učini po njima."},{"v":5,"t":"Onda ustanu neki od onih što iz farizejske sljedbe bijahu prigrlili vjeru pa reknu: “Treba ih obrezati i zapovjediti im da opslužuju Zakon Mojsijev.”"},{"v":6,"t":"Nato se apostoli i starješine sastanu da to razmotre."},{"v":7,"t":"Nakon duge raspre ustade Petar i reče im: “Braćo, vi znate kako me Bog od najprvih dana između vas izabra da iz mojih usta pogani čuju riječ evanđelja i uzvjeruju."},{"v":8,"t":"I Bog, Poznavatelj srdaca, posvjedoči za njih: dade im Duha Svetoga kao i nama."},{"v":9,"t":"Nikakve razlike nije pravio između nas i njih: vjerom očisti njihova srca."},{"v":10,"t":"Što dakle sada iskušavate Boga stavljajući učenicima na vrat jaram kojeg ni oci naši ni mi nismo mogli nositi?"},{"v":11,"t":"Vjerujemo, naprotiv: po milosti smo Gospodina Isusa spašeni, baš kao i oni.”"},{"v":12,"t":"Nato sve mnoštvo umuknu. Slušali su Barnabu i Pavla koji pripovjedahu kolika je znamenja i čudesa Bog po njima učinio među poganima."},{"v":13,"t":"Kad oni ušutješe, progovori Jakov: “Poslušajte me, braćo!"},{"v":14,"t":"Šimun je izložio kako se Bog već na početku pobrinu između pogana uzeti narod imenu svojemu."},{"v":15,"t":"S time su u skladu riječi Proroka. Ovako je doista pisano:"},{"v":16,"t":"Nakon toga vratit ću se i opet podići pali šator Davidov, iz ruševina ga podići, opet ga sazidati"},{"v":17,"t":"da preostali ljudi potraže Gospodina i svi pogani na koje je zazvano ime moje, govori Gospodin, koji to"},{"v":18,"t":"obznanjuje odvijeka."},{"v":19,"t":"Zato smatram da ne valja dodijavati onima koji se s poganstva obraćaju k Bogu,"},{"v":20,"t":"nego im poručiti da se uzdržavaju od mesa okaljana idolima, od bludništva, od udavljenoga i od krvi."},{"v":21,"t":"Ta Mojsije od pradavnih naraštaja ima po gradovima propovjednike koji ga u sinagogama svake subote čitaju.”"},{"v":22,"t":"Tad apostoli i starješine zajedno sa svom Crkvom zaključe izabrati neke muževe između sebe i poslati ih u Antiohiju s Pavlom i Barnabom. Bijahu to Juda zvani Barsaba, i Sila, muževi vodeći među braćom."},{"v":23,"t":"Po njima pošalju ovo pismo: “Apostoli i starješine, braća, braći iz poganstva po Antiohiji, Siriji i Ciliciji - pozdrav!”"},{"v":24,"t":"“Budući da smo čuli kako vas neki od naših, ali bez našega naloga, nekakvim izjavama smetoše i duše vam uznemiriše,"},{"v":25,"t":"zaključismo jednodušno izabrati neke muževe i poslati ih k vama zajedno s našim ljubljenim Barnabom i Pavlom,"},{"v":26,"t":"ljudima koji su svoje živote izložili za ime Gospodina našega Isusa Krista."},{"v":27,"t":"Šaljemo vam dakle Judu i Silu. Oni će vam i usmeno priopćiti to isto."},{"v":28,"t":"Zaključismo Duh Sveti i mi ne nametati vam nikakva tereta osim onoga što je potrebno:"},{"v":29,"t":"uzdržavati se od mesa žrtvovana idolima, od krvi, od udavljenoga i od bludništva. Budete li se toga držali, dobro ćete učiniti. Živjeli!”"},{"v":30,"t":"Oni su se dakle oprostili i sišli u Antiohiju; sabrali su mnoštvo i predali pismo."},{"v":31,"t":"Kad ga pročitaše, svi se obradovaše zbog ohrabrenja."},{"v":32,"t":"Juda i Sila, i sami proroci, mnogim riječima ohrabriše i utvrdiše braću."},{"v":33,"t":"Neko se vrijeme zadrže pa se onda s mirom od braće vrate onima koji ih poslaše."},{"v":34,"t":"#"},{"v":35,"t":"A Pavao i Barnaba ostadoše u Antiohiji naučavajući i navješćujući zajedno s mnogima drugima riječ Gospodnju."},{"v":36,"t":"Nakon nekog vremena reče Pavao Barnabi: “Vratimo se i pohodimo braću po svim gradovima u kojima smo navješćivali riječ Gospodnju, da vidimo kako su!”"},{"v":37,"t":"Barnaba je htio povesti i Ivana zvanog Marko."},{"v":38,"t":"Pavao pak nije smatrao uputnim sa sobom voditi onoga koji se u Pamfiliji odvojio od njih te nije s njima pošao na djelo."},{"v":39,"t":"Spopade ih takva ogorčenost da se raziđoše: Barnaba povede Marka i otplovi na Cipar,"},{"v":40,"t":"a Pavao sebi izabra Silu pa od braće povjeren milosti Gospodnjoj"},{"v":41,"t":"proputova Siriju i Ciliciju, utvrđujući Crkve."}]},"16":{"hr":[{"v":1,"t":"Stiže tako u Derbu i Listru. Ondje, gle, bijaše učenik neki imenom Timotej, sin neke pokrštene Židovke i oca Grka."},{"v":2,"t":"Uživao je dobar glas među braćom u Listri i Ikoniju."},{"v":3,"t":"Pavao htjede da on pođe s njime pa ga uze i obreza zbog Židova koji bijahu u onim mjestima. Jer svi su znali da mu je otac Grk."},{"v":4,"t":"I kako su prolazili gradovima, predavali su im za opsluživanje odredbe koje su apostoli i starješine utvrdili u Jeruzalemu."},{"v":5,"t":"Tako se Crkve učvršćivahu u vjeri i broj im se danomice povećavao."},{"v":6,"t":"Prođoše Frigiju i galacijski kraj jer ih je Duh Sveti spriječio propovijedati riječ u Aziji."},{"v":7,"t":"Kad su došli do Mizije, htjedoše u Bitiniju, ali im ne dopusti Duh Isusov."},{"v":8,"t":"Onda prođoše Miziju i siđoše u Troadu."},{"v":9,"t":"Noću je Pavao imao viđenje: Makedonac neki stajaše i zaklinjaše ga: “Prijeđi u Makedoniju i pomozi nam!”"},{"v":10,"t":"Nakon viđenja nastojasmo odmah otputovati u Makedoniju, uvjereni da nas Bog zove navješćivati im evanđelje."},{"v":11,"t":"Otplovismo iz Troade i zaputismo se ravno u Samotraku pa sutradan u Neapol,"},{"v":12,"t":"a odande u naseobinu Filipe - grad prvog dijela Makedonije. U tom se gradu zadržasmo nekoliko dana."},{"v":13,"t":"U dan subotni iziđosmo izvan gradskih vrata k rijeci, gdje smo mislili da će biti bogomolja. Sjedosmo i stadosmo govoriti okupljenim ženama."},{"v":14,"t":"Slušala je tako i neka bogobojazna žena imenom Lidija, prodavačica grimiza iz grada Tijatire. Gospodin joj otvori srce, te ona prihvati što je Pavao govorio."},{"v":15,"t":"Pošto se pak krsti ona i njezin dom, zamoli: “Ako smatrate da sam vjerna Gospodinu, uđite u moj dom i ostanite u njemu.” I prisili nas."},{"v":16,"t":"Jednom nas na putu u bogomolju sretne neka ropkinja koja je imala duha vračarskoga i gatajući donosila veliku dobit svojim gospodarima."},{"v":17,"t":"Pošla je za Pavlom i za nama te vikala: “Ovi su ljudi sluge Boga Svevišnjega; navješćuju vam put spasenja.”"},{"v":18,"t":"To je činila mnogo dana. Pavlu to napokon dodija pa se okrenu i reče duhu: “Zapovijedam ti u ime Isusa Krista: iziđi iz nje!” I iziđe toga časa."},{"v":19,"t":"Kad njezini gospodari vidješe da im nesta nade u dobit, pograbiše Pavla i Silu te ih odvukoše na trg pred glavare."},{"v":20,"t":"Privedoše ih pretorima i rekoše: “Ovi ljudi uznemiruju naš grad. Židovi su"},{"v":21,"t":"te šire običaje kojih mi Rimljani ne smijemo ni prihvatiti ni držati.”"},{"v":22,"t":"Nato svjetina nahrupi na njih, a pretori trgoše s njih odijelo i zapovjediše da se išibaju."},{"v":23,"t":"Pošto ih izudaraše, bace ih u tamnicu i zapovjede tamničaru da ih pomno čuva."},{"v":24,"t":"Primivši takvu zapovijed, uze ih on i baci u nutarnju tamnicu, a noge im stavi u klade."},{"v":25,"t":"Oko ponoći su Pavao i Sila molili pjevajući hvalu Bogu, a uznici ih slušali."},{"v":26,"t":"Odjednom nasta potres velik te se poljuljaše temelji zatvora, umah se otvoriše sva vrata, i svima spadoše okovi."},{"v":27,"t":"Tamničar se prenu oda sna pa kad ugleda tamnička vrata otvorena, trgnu mač i samo što se ne ubi misleći da su uznici pobjegli."},{"v":28,"t":"Ali Pavao povika iza glasa: “Ne čini sebi nikakva zla! Svi smo ovdje!”"},{"v":29,"t":"Onaj nato zaiska svjetlo, uleti i dršćući baci se pred Pavla i Silu;"},{"v":30,"t":"izvede ih i upita: “Gospodo, što mi je činiti da se spasim?”"},{"v":31,"t":"Oni će mu: “Vjeruj u Gospodina Isusa i spasit ćeš se - ti i dom tvoj!”"},{"v":32,"t":"Onda navijestiše riječ Gospodnju njemu i svima u domu njegovu."},{"v":33,"t":"Te iste noćne ure uze ih, opra im rane pa se odmah krsti - on i svi njegovi."},{"v":34,"t":"Onda ih uvede u dom, prostre stol te se zajedno sa svim domom obradova što je povjerovao Bogu."},{"v":35,"t":"Kad se razdani, poslaše pretori liktore s porukom: “Pusti te ljude!”"},{"v":36,"t":"Tamničar to priopći Pavlu: “Pretori, reče, poručiše da vas pustim. Iziđite dakle sad i pođite u miru!”"},{"v":37,"t":"Nato im Pavao odvrati: “Javno su nas neosuđene išibali, nas rimske građane, i bacili u tamnicu. A sada da nas potajno izbace? Nipošto, nego neka oni sami dođu i izvedu nas!”"},{"v":38,"t":"Liktori to jave pretorima. Oni su se uplašili kada doznaše da su Rimljani."},{"v":39,"t":"Zato dođu da ih nagovore pa ih izvedu i zamole da odu iz grada."},{"v":40,"t":"Izišavši iz tamnice, oni pođu k Lidiji, pogledaju i obodre braću pa odu."}]},"17":{"hr":[{"v":1,"t":"Prošavši kroz Amfipol i Apoloniju, stigoše u Solun, gdje bijaše židovska sinagoga."},{"v":2,"t":"Po običaju uđe Pavao onamo. Tri je subote s njima raspravljao na temelju Pisama."},{"v":3,"t":"Tumačio je i izlagao: “Trebalo je da Krist trpi i uskrsne od mrtvih. Taj Krist jest Isus koga vam ja navješćujem.”"},{"v":4,"t":"Neki se od njih uvjeriše pa se pridružiše Pavlu i Sili; tako i veliko mnoštvo bogobojaznih Grka i nemalo uglednih žena."},{"v":5,"t":"Židove nato spopade zavist pa pridobiše neke opake uličnjake, potakoše ih i pobuniše grad te nahrupiše u kuću Jasonovu tražeći da se Pavao i Sila izvedu pred narod."},{"v":6,"t":"Kako ih ne nađoše, odvukoše Jasona i neke od braće pred gradske glavare vičući: “Evo i ovdje onih koji pobuniše sav svijet."},{"v":7,"t":"Jason ih je ugostio. Svi oni rade protiv carskih odredaba: tvrde da postoji drugi kralj - Isus.”"},{"v":8,"t":"Time uzbuniše svjetinu i glavare koji su to čuli"},{"v":9,"t":"te oni od Jasona i ostalih uzeše jamčevinu pa ih pustiše."},{"v":10,"t":"Braća su pak brže-bolje noću odaslala Pavla i Silu u Bereju. Kad su stigli, odoše u židovsku sinagogu."},{"v":11,"t":"Ovi su Židovi bili plemenitiji od solunskih: primili su Riječ sa svom spremnošću i danomice istraživali Pisma, da li je to tako."},{"v":12,"t":"Mnogi od njih stoga povjerovaše, a tako i nemalo uglednih grčkih žena i muževa."},{"v":13,"t":"Ali kad su solunski Židovi doznali da Pavao i u Bereji navješćuje riječ Božju, odoše te i ondje podjariše i uzbuniše svjetinu."},{"v":14,"t":"Braća tada brže-bolje uputiše Pavla k moru. Sila pak i Timotej ostadoše ondje."},{"v":15,"t":"Pratioci dovedoše Pavla do Atene pa se vratiše noseći Sili i Timoteju zapovijed da što prije dođu k njemu."},{"v":16,"t":"Dok ih je u Ateni iščekivao, ogorči se Pavao u duši promatrajući kako je grad pokumiren."},{"v":17,"t":"Međutim raspravljaše u sinagogi sa Židovima i bogobojaznima, a na trgu svaki dan s onima koji bi se ondje zatekli."},{"v":18,"t":"Dobacivahu mu i neki od epikurejskih i stoičkih filozofa. Jedni su govorili: “Što bi htjela reći ta čavka?” Drugi pak: “Navješćuje, čini se, neke tuđe bogove.” Jer navješćivaše Isusa i uskrsnuće."},{"v":19,"t":"Onda su ga uzeli i odveli na Areopag i upitali: “Bismo li mogli znati kakav to nov nauk naučavaš?"},{"v":20,"t":"Čudnovatim nam nekim tvrdnjama uši puniš. Željeli bismo stoga znati što bi to imalo biti.”"},{"v":21,"t":"Nijedan Atenjanin ni doseljeni stranac ni na što drugo ne trati vrijeme nego na pripovijedanje i slušanje novosti."},{"v":22,"t":"Tada Pavao stade posred Areopaga i reče: “Atenjani! U svemu ste, vidim, nekako veoma bogoljubni."},{"v":23,"t":"Doista, prolazeći i promatrajući vaše svetinje nađoh i žrtvenik s natpisom: Nepoznatom Bogu. Što dakle ne poznajete, a štujete, to vam ja navješćujem.”"},{"v":24,"t":"“Bog koji stvori svijet i sve na njemu, on, neba i zemlje Gospodar, ne prebiva u rukotvorenim hramovima;"},{"v":25,"t":"i ne poslužuju ga ljudske ruke, kao da bi što trebao, on koji svima daje život, dah i - sve."},{"v":26,"t":"Od jednoga sazda cijeli ljudski rod da prebiva po svem licu zemlje; ustanovi određena vremena i međe prebivanja njihova"},{"v":27,"t":"da traže Boga, ne bi li ga kako napipali i našli. Ta nije daleko ni od koga od nas."},{"v":28,"t":"U njemu doista živimo, mičemo se i jesmo, kao što i neki od vaših pjesnika rekoše: “Njegov smo čak i rod!”"},{"v":29,"t":"“Ako smo dakle rod Božji, ne smijemo smatrati da je božanstvo slično zlatu, srebru ili kamenu, liku isklesanu umijećem i maštom ljudskom.”"},{"v":30,"t":"“I ne obazirući se na vremena neznanja, nutka sada Bog ljude da se svi i posvuda obrate"},{"v":31,"t":"jer ustanovi Dan u koji će suditi svijetu po pravdi, po Čovjeku kojega odredi, pred svima ovjerovi uskrisivši ga od mrtvih.”"},{"v":32,"t":"Kad čuše “uskrsnuće od mrtvih”, jedni se stadoše rugati, a drugi rekoše: “Još ćemo te o tom slušati!”"},{"v":33,"t":"Tako se Pavao povuče od njih."},{"v":34,"t":"Neki ipak prionuše uza nj i povjerovaše; među njima i Dionizije Areopagit, neka žena imenom Damara i drugi s njima."}]},"18":{"hr":[{"v":1,"t":"Nakon toga napusti Pavao Atenu i ode u Korint."},{"v":2,"t":"Ondje nađe nekog Židova imenom Akvilu, rodom iz Ponta, koji netom bijaše došao iz Italije sa svojom ženom Priscilom jer je Klaudije naredio da svi Židovi napuste Rim. Pohodio ih je"},{"v":3,"t":"i, kako bijahu istog zanimanja, ostao kod njih i radio. Po zanimanju bijahu šatorari."},{"v":4,"t":"Svake je pak subote raspravljao u sinagogi i uvjeravao Židove i Grke."},{"v":5,"t":"Kad iz Makedonije pristigoše Sila i Timotej, Pavao se potpuno posveti Riječi svjedočeći Židovima da Isus jest Krist."},{"v":6,"t":"Kako se pak oni stadoše protiviti i huliti, otrese on haljine i reče im: “Krv vaša na glave vaše! Ja sam nedužan. Od sada idem k poganima.”"},{"v":7,"t":"I ode odande te prijeđe u kuću nekoga bogobojazna čovjeka, imenom Ticija Justa, čija kuća bijaše tik do sinagoge."},{"v":8,"t":"A nadstojnik sinagoge Krisp povjerova Gospodinu zajedno sa svim svojim domom. I mnogi od Korinćana koji su to slušali povjerovaše i pokrstiše se."},{"v":9,"t":"Jedne noći reče Gospodin Pavlu u viđenju: “Ne boj se, nego govori i ne daj se ušutkati!"},{"v":10,"t":"Ta ja sam s tobom i nitko se neće usuditi da ti naudi. Jer mnogo je naroda mojega u ovome gradu.”"},{"v":11,"t":"Tako se zadrža godinu i šest mjeseci naučavajući među njima riječ Božju."},{"v":12,"t":"Ali dok je Galion bio prokonzul Ahaje, navališe Židovi jednodušno na Pavla, dovukoše ga u sudnicu"},{"v":13,"t":"i rekoše: “Ovaj potiče ljude da protiv zakona štuju Boga.”"},{"v":14,"t":"Pavao samo što nije zaustio kadli Galion reče Židovima: “Da je posrijedi zločin kakav ili nedjelo opako, saslušao bih vas, Židovi, kako je pravo;"},{"v":15,"t":"je li pak raspra o riječi i imenima i o nekom vašem zakonu, proviđajte sami; u tome ja ne želim biti sudac.”"},{"v":16,"t":"I otpremi ih iz sudnice."},{"v":17,"t":"A oni svi pograbiše nadstojnika sinagoge Sostena i stadoše ga šibati pred sudnicom. Galion nije za to ništa mario."},{"v":18,"t":"Pavao osta još podosta vremena, a onda se oprosti s braćom pa pošto se u Kenhreji ošiša jer imaše zavjet, zaplovi prema Siriji, a s njime i Priscila i Akvila."},{"v":19,"t":"Stigoše u Efez. Tu ih ostavi, a on uđe u sinagogu i stade raspravljati sa Židovima."},{"v":20,"t":"Oni ga zamole da ostanu duže vremena, ali on ne pristade,"},{"v":21,"t":"nego se oprosti: “Još ću se, reče, vratiti k vama, bude li Božja volja.” I otplovi iz Efeza."},{"v":22,"t":"Kad stiže u Cezareju, uziđe pozdraviti Crkvu pa onda siđe u Antiohiju."},{"v":23,"t":"Neko se vrijeme zadrža pa onda ode i zareda galacijskim područjem i Frigijom utvrđujući sve učenike."},{"v":24,"t":"Uto neki Židov imenom Apolon, rodom Aleksandrijac, čovjek rječit i upućen u Pisma, stiže u Efez."},{"v":25,"t":"On bijaše upućen u Put Gospodnji pa je vatrene duše govorio i naučavao pomno o Isusu, premda je znao samo za Ivanovo krštenje."},{"v":26,"t":"Poče on tako smjelo govoriti u sinagogi. Čuše ga Priscila i Akvila, uzeše ga k sebi i pomnije mu izložiše Put Božji."},{"v":27,"t":"A kad je nakanio otići u Ahaju, ohrabriše ga braća i napisaše učenicima da ga prime. Kad je stigao onamo, uvelike je koristio vjernicima po milosti"},{"v":28,"t":"jer je snažno pobijao Židove javno pokazujući iz Pisama da Isus jest Krist."}]},"19":{"hr":[{"v":1,"t":"Dok je Apolon bio u Korintu, Pavao, pošto prođe gornje krajeve, dođe u Efez, nađe neke učenike"},{"v":2,"t":"pa ih upita: “Jeste li primili Duha Svetoga kad ste povjerovali?” Oni će mu: “Ta ni čuli nismo da ima Duh Sveti.”"},{"v":3,"t":"Nato će on: “Kako ste onda kršteni?” “Krštenjem Ivanovim”, odvrate oni."},{"v":4,"t":"Nato će Pavao: “Ivan je krstio krštenjem obraćenja govoreći narodu da vjeruje u Onoga koji za njim dolazi, to jest u Isusa.”"},{"v":5,"t":"Čuvši to, krste se u ime Gospodina Isusa,"},{"v":6,"t":"pa kad Pavao položi na njih ruke, dođe Duh Sveti na njih te stanu govoriti drugim jezicima i prorokovati."},{"v":7,"t":"Bijaše u svemu dvanaestak muževa."},{"v":8,"t":"Onda Pavao uđe u sinagogu te je tri mjeseca hrabro raspravljao i uvjeravao o kraljevstvu Božjem."},{"v":9,"t":"Ali kako neki, okorjeli i nepokorni, ocrnjivahu ovaj Put pred mnoštvom, odstupi od njih, odvoji učenike i danomice raspravljaše u školi nekog Tirana."},{"v":10,"t":"Trajalo je to dvije godine, tako da su svi azijski žitelji, Židovi i Grci, čuli riječ Božju."},{"v":11,"t":"Bog je pak činio čudesa nesvakidašnja po rukama Pavlovima"},{"v":12,"t":"tako da bi na bolesnike stavljali rupce ili rublje s Pavlova tijela pa bi s njih nestajalo bolesti i zli duhovi iz njih izlazili."},{"v":13,"t":"Zato i neki Židovi zaklinjaoci-potukači pokušaše zazvati ime Gospodina Isusa nad one koji imahu zle duhove. Govorili su: “Zaklinjem vas Isusom koga Pavao propovijeda.”"},{"v":14,"t":"To činjaše sedam sinova nekog Skeve, židovskoga velikog svećenika."},{"v":15,"t":"Zli im duh odvrati: “Isusa poznajem i Pavla znam, ali tko ste vi?”"},{"v":16,"t":"I čovjek u kome bijaše zli duh, nasrnu na njih i nadjača ih te oni goli i izranjeni pobjegoše iz one kuće."},{"v":17,"t":"Doznaše to svi žitelji efeški, Židovi i Grci, pa ih sve obuze strah te se stade veličati ime Gospodina Isusa."},{"v":18,"t":"Mnogi pak od onih koji su povjerovali dolazili su ispovijedati i očitovati svoja djela."},{"v":19,"t":"I podosta onih koji su se bavili praznovjerjem donosili su knjige i spaljivali ih pred svima. Procijeniše ih te nađoše da vrijede pedeset tisuća srebrnjaka."},{"v":20,"t":"TAko se snagom Gospodnjom Riječ širila i jačala."},{"v":21,"t":"Pošto se to ispuni, naumi Pavao preko Makedonije i Ahaje otići u Jeruzalem te reče: “Pošto budem ondje, trebat će da i Rim vidim.”"},{"v":22,"t":"Onda posla u Makedoniju dvojicu svojih poslužitelja, Timoteja i Erasta, a on provede još neko vrijeme u Aziji."},{"v":23,"t":"Nekako u ono doba nasta nemalena pobuna protiv ovog Puta."},{"v":24,"t":"Neki srebrar, imenom Demetrije, izrađivao je srebrne hramiće Artemidine i namicao obrtnicima nemalu dobit."},{"v":25,"t":"Skupi on njih i sve koji su se bavili takvim poslom te im reče: “Ljudi, vi znate, u ovom je umijeću naše blagostanje."},{"v":26,"t":"A vidite i čujete da je taj Pavao ne samo u Efezu nego gotovo i u svoj Aziji uvjerio i preokrenuo poveliko mnoštvo govoreći da nema bogova rukama izdjeljanih."},{"v":27,"t":"Tako prijeti opasnost ne samo da na zao glas dođe naše zanimanje, nego i to da se ništa neće držati do hrama velike božice Artemide te će nestati veličanstva one koju štuje sva Azija i sav svijet.”"},{"v":28,"t":"Čuvši to, razgnjeve se pa poviču: “Velika je Artemida efeška!”"},{"v":29,"t":"Sav se grad uskomeša; jednodušno nahrupe u kazalište vukući sa sobom Makedonce Gaja i Aristarha, suputnike Pavlove."},{"v":30,"t":"Kad je Pavao htio među narod, ne dopustiše mu učenici."},{"v":31,"t":"Čak i neki azijarsi, njegovi prijatelji, poslaše k njemu i zamoliše da ne dolazi u kazalište."},{"v":32,"t":"Jedni su izvikivali jedno, drugi drugo jer je skup bio uskomešan te mnogi nisu ni znali zašto su se strčali."},{"v":33,"t":"Neki iz svjetine uputiše nekog Aleksandra jer su ga Židovi gurali naprijed. Aleksandar pak mahnu rukom i htjede se obraniti pred narodom."},{"v":34,"t":"Ali kada doznaše da je Židov, udarahu gotovo dva sata svi u jedan glas: “Velika je Artemida efeška!”"},{"v":35,"t":"Onda tajnik umiri svjetinu pa reče: “Efežani! Tko to od ljudi ne zna da je grad Efez čuvar hrama velike Artemide i kipa s neba palog?"},{"v":36,"t":"Budući dakle da je to neporecivo, valja da budete mirni te ništa brzopleto ne činite."},{"v":37,"t":"Doveli ste ove ljude, a nisu ni svetokradice ni hulitelji naše božice."},{"v":38,"t":"Ako pak Demetrije i njegovi obrtnici imaju protiv koga kakvu tužbu, sudovi se sastaju, a tu su i prokonzuli. Neka se tuže!"},{"v":39,"t":"Ištete li pak što drugo, u zakonitu će se skupu riješiti."},{"v":40,"t":"Ta izlažemo se opasnosti da za ovo današnje budemo optuženi s pobune jer nema nikakva razloga kojim bismo mogli opravdati ovu strku.” To rekavši, raspusti skup."}]},"20":{"hr":[{"v":1,"t":"Kad se sleže metež, posla Pavao po učenike, ohrabri ih, pozdravi i otputova u Makedoniju."},{"v":2,"t":"Prešavši one krajeve, hrabreći braću besjedom mnogom, dođe u Grčku"},{"v":3,"t":"i provede ondje tri mjeseca. Upravo kad je htio otploviti u Siriju, postaviše mu Židovi zasjedu pa odluči vratiti se preko Makedonije."},{"v":4,"t":"Pratili su ga: Sopater Pirov, Berejac, Solunjani Aristarh i Sekund, Gaj Derbanin, Timotej i Azijci Tihik i Trofim."},{"v":5,"t":"Oni odoše prije te nas dočekaše u Troadi."},{"v":6,"t":"Mi pak nakon dana Beskvasnih kruhova otplovismo iz Filipa i nakon pet dana dođosmo k njima u Troadu gdje proboravismo sedam dana."},{"v":7,"t":"U prvi dan tjedna, kad se sabrasmo lomiti kruh, Pavao im govoraše i kako je sutradan kanio otputovati, probesjedi sve do ponoći."},{"v":8,"t":"U gornjoj sobi gdje smo se sabrali bijaše dosta svjetiljaka."},{"v":9,"t":"Na prozoru je sjedio neki mladić imenom Eutih. Kako je Pavao dulje govorio, utone on u dubok san. Svladan snom, pade s trećeg kata dolje. Digoše ga mrtva."},{"v":10,"t":"Pavao siđe, nadnese se nad dječaka, obujmi ga i reče: “Ne uznemirujte se! Duša je još u njemu!”"},{"v":11,"t":"Zatim se pope pa pošto razlomi kruh i blagova, dugo je još zborio, sve do zore. Tad otputova."},{"v":12,"t":"Mladića odvedoše živa, neizmjerno utješeni."},{"v":13,"t":"Mi pak pođosmo naprijed lađom: otplovismo u As. Odande smo imali povesti Pavla - tako je odredio kad se spremao poći pješice."},{"v":14,"t":"Kad nam se u Asu pridruži, uzesmo ga i stigosmo u Mitilenu."},{"v":15,"t":"Odande odjedrismo sutradan i stigosmo nadomak Hija, prekosutra krenusmo u Sam, a idućeg dana stigosmo u Milet."},{"v":16,"t":"Jer Pavao je odlučio mimoići Efez da se ne bi zadržao u Aziji: žurio se da, uzmogne li, na dan Pedesetnice bude u Jeruzalemu."},{"v":17,"t":"Ipak iz Mileta posla u Efez po starješine Crkve."},{"v":18,"t":"Kad stigoše, reče im: “Vi znate kako sam se sve vrijeme, od prvog dana kada stupih u Aziju, ponašao među vama:"},{"v":19,"t":"služio sam Gospodinu sa svom poniznošću u suzama i kušnjama koje me zadesiše zbog zasjeda židovskih;"},{"v":20,"t":"ništa korisno nisam propustio navijestiti vam i naučiti vas - javno i po kućama;"},{"v":21,"t":"upozoravao sam Židove i Grke da se obrate k Bogu i da vjeruju u Gospodina našega Isusa.”"},{"v":22,"t":"“A sad, evo, okovan Duhom idem u Jeruzalem. Što će me u njemu zadesiti, ne znam,"},{"v":23,"t":"osim što mi Duh Sveti u svakom gradu jamči da me čekaju okovi i nevolje."},{"v":24,"t":"Ali ni najmanje mi nije do života, samo da dovršim trku svoju i službu koju primih od Gospodina Isusa: svjedočiti za evanđelje milosti Božje.”"},{"v":25,"t":"“I sad, evo, znam: nećete više vidjeti lica moga, svi vi posred kojih prođoh propovijedajući Kraljevstvo."},{"v":26,"t":"Zato vam u ovaj dan današnji jamčim: čist sam od krvi sviju"},{"v":27,"t":"jer nisam propustio navijestiti vam ništa od svega nauma Božjega.”"},{"v":28,"t":"“Pazite na sebe i na sve stado u kojem vas Duh Sveti postavi nadglednicima, da pasete Crkvu Božju koju steče krvlju svojom.”"},{"v":29,"t":"“Ja znam da će nakon mog odlaska među vas uljesti vuci okrutni koji ne štede stada,"},{"v":30,"t":"a između vas će samih ustati ljudi koji će iskrivljavati nauk da bi odvukli učenike za sobom."},{"v":31,"t":"Zato bdijte imajući na pameti da sam tri godine bez prestanka noću i danju suze lijevajući urazumljivao svakoga od vas.”"},{"v":32,"t":"“I sada vas povjeravam Bogu i Riječi milosti njegove koja je kadra izgraditi vas i dati vam baštinu među svima posvećenima.”"},{"v":33,"t":"“Ni za čijim srebrom, zlatom ili ruhom nisam hlepio."},{"v":34,"t":"Sami znate: za potrebe moje i onih koji su sa mnom zasluživale su ove ruke."},{"v":35,"t":"U svemu vam pokazah: tako se trudeći treba se zauzimati za nemoćne i na pameti imati riječi Gospodina Isusa jer on reče: 'Blaženije je davati nego primati.'”"},{"v":36,"t":"Kada to doreče, klekne te se zajedno sa svima njima pomoli."},{"v":37,"t":"Tad svi briznuše u velik plač, obisnuše Pavlu oko vrata i stadoše ga cjelivati,"},{"v":38,"t":"ražalošćeni nadasve riječju koju im reče: da više neće vidjeti lica njegova. Zatim ga ispratiše na lađu."}]},"21":{"hr":[{"v":1,"t":"Pošto se otrgosmo od njih, zaplovismo. Jedreći ravno, stigosmo na Kos, a sutradan na Rod pa odande u Pataru."},{"v":2,"t":"Kad nađosmo lađu za Feniciju, popesmo se i otplovismo."},{"v":3,"t":"Kad bijasmo napomol Cipru, ostavismo ga slijeva jedreći prema Siriji. Pristadosmo u Tiru jer je ondje lađa imala iskrcati tovar."},{"v":4,"t":"Pronađosmo učenike i ostadosmo ondje sedam dana. Oni po Duhu nagovarahu Pavla da ne uzlazi u Jeruzalem."},{"v":5,"t":"Ali kad nam istekoše dani, ipak otputovasmo. Ispratiše nas svi, sa ženama i djecom, do izvan grada. Na žalu klekosmo i pomolismo se."},{"v":6,"t":"Pozdravismo se, popesmo se na lađu, a oni se vratiše kući."},{"v":7,"t":"Tako dovršismo plovidbu. Iz Tira stigosmo u Ptolemaidu. Pozdravili smo braću i ostali jedan dan u njih."},{"v":8,"t":"Sutradan otputovasmo i stigosmo u Cezareju. Uđosmo u kuću Filipa evanđelista, jednog od sedmorice, i ostadosmo kod njega."},{"v":9,"t":"On je imao četiri kćeri djevice koje su prorokovale."},{"v":10,"t":"Kako smo se zadržali mnogo dana, siđe iz Judeje neki prorok imenom Agab,"},{"v":11,"t":"dođe k nama, uze Pavlov pojas, sveza sebi noge i ruke te reče: “Ovo govori Duh Sveti: Čovjeka čiji je ovo pojas ovako će svezati Židovi u Jeruzalemu i predati u ruke pogana.”"},{"v":12,"t":"Kada smo to čuli, stadosmo mi i mještani zaklinjati Pavla da ne uzlazi u Jeruzalem."},{"v":13,"t":"Nato on odvrati: “Što plačete i parate mi srce? Ta spreman sam ne samo biti svezan nego i umrijeti u Jeruzalemu za ime Gospodina Isusa.”"},{"v":14,"t":"A kako se nije dao nagovoriti, ušutjesmo rekavši: “Gospodnja budi volja!”"},{"v":15,"t":"Nakon tih dana spremismo se i uzađosmo u Jeruzalem."},{"v":16,"t":"S nama pođoše i učenici iz Cezareje pa nas odvedoše k nekomu Mnasonu Cipraninu, starom učeniku, da u njega odsjednemo."},{"v":17,"t":"Kad stigosmo u Jeruzalem, primiše nas braća radosno."},{"v":18,"t":"Sutradan ode Pavao zajedno s nama k Jakovu. Nađoše se ondje i sve starješine."},{"v":19,"t":"Pošto ih pozdravi, stade im potanko izlagati što učini Bog među poganima po njegovoj službi."},{"v":20,"t":"Pošto su ga oni poslušali, dadoše slavu Bogu pa mu rekoše: “Vidiš, brate: deseci su tisuća Židova povjerovali i svi su revnitelji Zakona."},{"v":21,"t":"A o tebi im je dojavljeno da sve Židove koji su među poganima upućuješ na otpad od Mojsija učeći ih da ne obrezuju djece i ne žive po običajima."},{"v":22,"t":"Što dakle? Čut će svakako da si došao."},{"v":23,"t":"Učini stoga što ti kažemo. U nas su četiri čovjeka koji imaju zavjet."},{"v":24,"t":"Njih uzmi, s njima se zajedno posveti, plati za njih da se ošišaju pa će svi spoznati da nema ništa od onoga što im je o tebi dojavljeno, nego da si i ti na pravu putu i da opslužuješ Zakon."},{"v":25,"t":"A što se tiče pogana koji povjerovaše - poslali smo što odlučismo: da se klone mesa žrtvovana idolima, krvi, udavljenoga i bludništva.”"},{"v":26,"t":"Nato Pavao uze one ljude, sutradan se s njima zajedno posveti, uđe u Hram, oglasi svršetak dana posvećenja nakon kojih će se za svakoga od njih prinijeti prinos."},{"v":27,"t":"Kad se upravo navršavalo tih sedam dana, neki ga Židovi iz Azije opaze u Hramu, uzbune sav narod pa podignu na nj ruke"},{"v":28,"t":"vičući: “Izraelci, u pomoć! Evo čovjeka koji sve posvuda poučava protiv naroda, Zakona i ovoga mjesta pa je još i Grke uveo u Hram i oskvrnuo ovo sveto mjesto.”"},{"v":29,"t":"Jer prije su s njime u Gradu vidjeli Trofima Efežanina i mislili da je Pavao njega uveo u Hram."},{"v":30,"t":"Sav se grad uskomeša, nasta strka naroda. Pograbe Pavla i odvuku ga izvan Hrama pa odmah pozatvaraju vrata."},{"v":31,"t":"Dok su mu o glavi radili, dođe do tisućnika čete glas da je sav Jeruzalem uzavreo."},{"v":32,"t":"On odmah uze vojnike i satnike pa otrča dolje k njima. Oni pak kako ugledaše tisućnika i vojnike, prestadoše udarati Pavla."},{"v":33,"t":"Onda se tisućnik približi, uhvati ga, zapovjedi da ga okuju dvojim verigama pa stade ispitivati tko je i što je učinio."},{"v":34,"t":"Iz svjetine su jedni izvikivali ovo, drugi ono. Kako zbog graje nije mogao saznati ništa pouzdano, zapovjedi da se odvede u vojarnu."},{"v":35,"t":"Kad se Pavao pojavi na stubama, morali su ga vojnici nositi zbog silovitosti svjetine."},{"v":36,"t":"Jer mnoštvo je naroda išlo za njima i vikalo: “Smakni ga!”"},{"v":37,"t":"Upravo na ulazu u vojarnu reče Pavao tisućniku: “Smijem li nešto reći?” On ga upita: “Zar znaš grčki?"},{"v":38,"t":"Ti dakle nisi onaj Egipćanin koji je prije nekoliko dana pobunio i u pustinju odveo one četiri tisuće bodežara?”"},{"v":39,"t":"Pavao odvrati: “Ja sam Židov iz Tarza cilicijskoga, građanin grada znamenitoga. Molim te, dopusti mi progovoriti narodu.”"},{"v":40,"t":"Kad mu on dopusti, Pavao stojeći na stubama mahnu rukom narodu pa kad nasta velika tišina, prozbori hebrejskim jezikom:"}]},"22":{"hr":[{"v":1,"t":"“Braćo i oci, poslušajte što ću vam sad u svoju obranu reći.”"},{"v":2,"t":"Kad čuše da im govori hebrejskim jezikom, još većma utihnuše. On nastavi:"},{"v":3,"t":"“Ja sam Židov, rođen u Tarzu cilicijskom, ali odrastao u ovom gradu, do nogu Gamalielovih odgojen točno po otačkom Zakonu; bijah revnitelj Božji kao što ste svi vi još danas."},{"v":4,"t":"Ovaj sam Put na smrt progonio, u okove bacao i predavao u tamnice muževe i žene,"},{"v":5,"t":"kako mi to može posvjedočiti i veliki svećenik i sve starješinstvo. Od njih sam i pisma dobio za braću u Damasku pa se zaputio da i one ondje okovane dovedem u Jeruzalem da se kazne.”"},{"v":6,"t":"“Dok sam tako putovao i približavao se Damasku, s neba me oko podneva iznenada obasja svjetlost velika."},{"v":7,"t":"Sruših se na tlo i začuh glas što mi govoraše: 'Savle, Savle, zašto me progoniš?'"},{"v":8,"t":"Ja odgovorih: 'Tko si, Gospodine?' Reče mi: 'Ja sam Isus Nazarećanin koga ti progoniš.'"},{"v":9,"t":"Oni koji bijahu sa mnom svjetlost doduše primijetiše, ali ne čuše glasa Onoga koji mi govoraše."},{"v":10,"t":"Rekoh nato: 'Što mi je činiti, Gospodine?' Gospodin će mi: 'Ustani, pođi u Damask i ondje će ti se reći što ti je određeno učiniti.'"},{"v":11,"t":"Kako od sjaja one svjetlosti obnevidjeh, pratioci me povedoše za ruku te stigoh u Damask.”"},{"v":12,"t":"“Neki Ananija, čovjek po Zakonu pobožan i na dobru glasu u Židova ondje nastanjenih -"},{"v":13,"t":"dođe k meni, pristupi mi i reče: 'Savle, brate, progledaj!' I ja se u taj čas zagledah u nj."},{"v":14,"t":"A on će: 'Bog otaca naših predodredi te da upoznaš volju njegovu, da vidiš Pravednika i čuješ glas iz usta njegovih"},{"v":15,"t":"jer bit ćeš mu pred svim ljudima svjedokom onoga što si vidio i čuo."},{"v":16,"t":"I što sad oklijevaš? Ustani, krsti se i operi grijehe svoje, prizivljući Ime njegovo!'”"},{"v":17,"t":"“Pošto se vratih u Jeruzalem, dok sam se jednom molio u Hramu, padoh u zanos"},{"v":18,"t":"i vidjeh Gospodina gdje mi govori: 'Pohiti, žurno izađi iz Jeruzalema jer neće primiti tvoga svjedočanstva o meni.'"},{"v":19,"t":"Ja rekoh: 'Gospodine, oni znaju da sam ja u tamnice bacao i bičevao po sinagogama one koji vjeruju u te."},{"v":20,"t":"I dok se prolijevala krv Stjepana, svjedoka tvoga, i ja sam ondje stajao i odobravao te čuvao haljine onih koji ga ubijahu.'"},{"v":21,"t":"Nato mi reče: 'Pođi jer ću te poslati daleko k poganima!'"},{"v":22,"t":"Slušali su ga sve do te riječi, a tada podigoše glas: “Ukloni takva sa zemlje! Nije pravo da živi!”"},{"v":23,"t":"Kako oni stadoše bučiti, odbacivati haljine i vitlati prašinu u zrak,"},{"v":24,"t":"zapovjedi tisućnik da Pavla uvedu u vojarnu pa odredi da ga bičevima ispitaju kako bi doznao zašto tako viču protiv njega."},{"v":25,"t":"Kad ga remenjem rastegoše, reče on nazočnom satniku: “Rimskoga građanina, i još neosuđena, smijete bičevati?”"},{"v":26,"t":"Kad je to čuo satnik, priđe tisućniku i dojavi mu: “Što si to nakanio? Ovaj je čovjek Rimljanin!”"},{"v":27,"t":"Tisućnik tada priđe Pavlu pa mu reče: “Reci mi, jesi li Rimljanin!” On odvrati: “Da.”"},{"v":28,"t":"Tisućnik dometnu: “Ja stekoh to građanstvo za skupe novce.” Pavao nato reče: “Ja sam se pak s njim i rodio.”"},{"v":29,"t":"Brže stoga odstupe od njega oni koji su ga imali ispitivati. I tisućnik se preplaši kad sazna da je Pavao Rimljanin, a on ga bijaše okovao."},{"v":30,"t":"Sutradan pak kad je htio točno saznati za što ga Židovi optužuju, odriješi ga pa zapovjedi da se sastanu veliki svećenici i sve Vijeće te privede Pavla i postavi ga pred njih."}]},"23":{"hr":[{"v":1,"t":"Pavao uprije pogled u Vijeće i reče: “Braćo, ja sam posve mirne savjesti živio pred Bogom sve do dana današnjega.”"},{"v":2,"t":"Nato veliki svećenik Ananija naredi onima što stajahu uza nj da ga udare po ustima."},{"v":3,"t":"Onda mu Pavao reče: “Udarit će Bog tebe, zide obijeljeni! Ti li sjediš da me po Zakonu sudiš, a protuzakonito zapovijedaš da me biju?”"},{"v":4,"t":"Oni što su ondje stajali rekoše nato: “Zar velikog svećenika Božjega da pogrđuješ?”"},{"v":5,"t":"Pavao odvrati: “Nisam znao, braćo, da je veliki svećenik. Ta pisano je: Glavara naroda svoga ne proklinji.”"},{"v":6,"t":"Pavao je znao da su oni dijelom saduceji, a dijelom farizeji pa povika u Vijeću: “Braćo, ja sam farizej, sin farizeja. Sudi mi se zbog nade, uskrsnuća mrtvih.”"},{"v":7,"t":"Tek što je on to rekao, nasta razmirica između farizeja i saduceja i mnoštvo se razdijeli."},{"v":8,"t":"Jer saduceji vele da nema uskrsnuća, ni anđela, ni duha, a farizeji sve to priznaju."},{"v":9,"t":"Nasta velika graja te ustadoše neki pismoznanci farizejske stranke i zaoštre boj govoreći: “Ništa zlo ne nalazimo na tom čovjeku! A što ako mu je duh govorio, ili anđeo?”"},{"v":10,"t":"Kad razmirica posta još većom, poboja se tisućnik da Pavla ne rastrgaju pa zapovjedi da vojska siđe, otme ga ispred njih i povede u vojarnu."},{"v":11,"t":"Iduće noći pristupi mu Gospodin i reče: “Hrabro samo! Jer kao što si za me svjedočio u Jeruzalemu tako treba da i u Rimu posvjedočiš!”"},{"v":12,"t":"Kad osvanu dan, skovaše Židovi urotu i zakleše se da neće ni jesti ni piti dok ne ubiju Pavla."},{"v":13,"t":"Bilo je više od četrdeset onih koji su skovali tu zavjeru."},{"v":14,"t":"Oni odu k velikim svećenicima i starješinama pa reknu: “Zakletvom se zaklesmo ništa ne okusiti dok ne ubijemo Pavla."},{"v":15,"t":"Stoga vi sada zajedno s Vijećem predočite tisućniku neka vam ga dovede kao da kanite točnije razaznati njegov slučaj. A mi smo spremni pogubiti ga prije negoli se i približi.”"},{"v":16,"t":"Ali sin Pavlove sestre doču za zavjeru, približi se i uđe u vojarnu dojaviti Pavlu."},{"v":17,"t":"Pavao pak pozove jednog satnika i reče mu: “Ovog mladića odvedi k tisućniku: ima mu nešto dojaviti.”"},{"v":18,"t":"On ga uze, odvede k tisućniku i reče mu: “Uznik me Pavao pozva i zaiska da ovog mladića privedem k tebi; ima ti nešto reći.”"},{"v":19,"t":"Tisućnik ga prihvati za ruku, povede nasamo pa ga upita: “Što mi imaš dojaviti?”"},{"v":20,"t":"“Židovi su se, reče on, dogovorili da te zamole da im sutra Pavla dovedeš u Vijeće kao da se kane točnije raspitati o njemu."},{"v":21,"t":"Ne vjeruj im! U zasjedi ga čeka više od četrdeset onih koji se zakleše da neće jesti ni piti dok ga ne smaknu. Već su spremni, samo čekaju tvoju privolu.”"},{"v":22,"t":"Tisućnik onda otpusti mladića i zapovjedi mu: “Nikomu ne kazuj da si mi to dojavio.”"},{"v":23,"t":"Zatim dozva dva satnika i reče im: “Pripravite dvjesta vojnika, sedamdeset konjanika i dvjesta strijelaca da nakon treće noćne ure pođu u Cezareju."},{"v":24,"t":"Neka se pripravi živina na koju će se posaditi Pavao te živ i zdrav dovesti k upravitelju Feliksu.”"},{"v":25,"t":"Napisa i pismo ovoga sadržaja:"},{"v":26,"t":"“Klaudije Lizija vrlom upravitelju Feliksu - pozdrav!"},{"v":27,"t":"Ovoga čovjeka Židovi uhvatiše i tek što ga ne smakoše kadli s vojskom pritrčah i istrgoh im ga kada doznah da je Rimljanin."},{"v":28,"t":"Htjedoh saznati za što ga okrivljuju pa ga dovedoh u njihovo Vijeće."},{"v":29,"t":"Utvrdih da ga okrivljuju za nešto prijeporno u njihovu zakonu i da nema nikakve krivnje kojom bi zaslužio smrt ili okove."},{"v":30,"t":"Kad mi pak dojaviše da su protiv njega skovali zavjeru, poslah ga k tebi, a tužitelje uputih neka se tebi obrate protiv njega.”"},{"v":31,"t":"Vojnici dakle, po primljenoj naredbi uzeše Pavla i odvedoše ga noću u Antipatridu."},{"v":32,"t":"Sutradan ostave konjanike da s njime pođu dalje, a oni se vratiše u vojarnu."},{"v":33,"t":"Kad konjanici stigoše u Cezareju, uručiše upravitelju pismo i privedoše mu Pavla."},{"v":34,"t":"Pošto upravitelj pročita pismo, zapita iz koje je pokrajine. Kad sazna da je iz Cilicije:"},{"v":35,"t":"“Saslušat ću te, reče, kad pristignu i tužitelji tvoji.” Onda zapovjedi čuvati ga u dvoru Herodovu."}]},"24":{"hr":[{"v":1,"t":"Nakon pet dana siđe veliki svećenik Ananija s nekim starješinama i odvjetnikom, nekim Tertulom te izniješe upravitelju tužbu protiv Pavla."},{"v":2,"t":"Pošto dozvaše Pavla, poče ga Tertul optuživati: “Veliki mir što ga po tebi, vrli Felikse, uživamo i boljitak što tvojom providnošću narodu ovomu nastaje,"},{"v":3,"t":"u svemu i posvuda primamo sa svom zahvalnošću."},{"v":4,"t":"Ali, da ti dulje ne dodijavam, molim te da nas u svojoj blagonaklonosti ukratko poslušaš."},{"v":5,"t":"Utvrdismo da je ovaj čovjek kuga, da pokreće bune među svim Židovima po svijetu, da je kolovođa nazaretske sljedbe,"},{"v":6,"t":"da je čak i Hram pokušao oskvrnuti pa ga uhitismo."},{"v":7,"t":"#"},{"v":8,"t":"Od njega, ako ga o svemu tomu ispitaš, možeš saznati za što ga mi optužujemo.”"},{"v":9,"t":"Podržaše ga i Židovi tvrdeći da je tako."},{"v":10,"t":"Nato Pavao odvrati pošto mu upravitelj kimnu da govori: “Kako znam da si već mnogo godina sudac narodu ovomu, mirne se duše branim."},{"v":11,"t":"Ta možeš se osvjedočiti da nema više od dvanaest dana otkad uzađoh u Jeruzalem da se poklonim."},{"v":12,"t":"A nisu me našli ni u Hramu da s kim raspravljam ili bunu podižem, ni u sinagogama, ni po gradu."},{"v":13,"t":"I ne mogu ti dokazati ono za što me sada optužuju.”"},{"v":14,"t":"“Jamčim ti, naprotiv, ovo: Putom koji nazivaju sljedbom služim otačkom Bogu vjerujući u sve što je u Zakonu i u Prorocima napisano,"},{"v":15,"t":"uzdajući se u Boga da će uskrsnuti pravednici i nepravednici, što oni i sami očekuju."},{"v":16,"t":"Zato se i ja trudim uvijek imati savjest besprijekornu pred Bogom i pred ljudima.”"},{"v":17,"t":"“Nakon više godina dođoh da donesem milostinju za svoj narod i prinose;"},{"v":18,"t":"dok sam ih prinosio, nađoše me posvećena u Hramu, a ne sa svjetinom ni u metežu."},{"v":19,"t":"Ali neki Židovi iz Azije - da, trebalo bi da se oni pojave pred tobom i optuže me ako što imaju protiv mene."},{"v":20,"t":"Ili neka ovi sami kažu: koji su zločin na meni našli kad sam stajao pred Vijećem,"},{"v":21,"t":"osim možda one jedne riječi koju doviknuh među njima stojeći: Zbog uskrsnuća mrtvih sudi mi se danas pred vama!”"},{"v":22,"t":"Nato Feliks, koji je točno znao sve o ovom Putu, odgodi njihovu parnicu rekavši: “Kada dođe tisućnik Lizija, riješit ću vaš spor.”"},{"v":23,"t":"Satniku pak naredi da se Pavao čuva, ali da uživa olakšice i da se nikomu od njegovih ne brani posluživati ga."},{"v":24,"t":"Nakon nekoliko dana stigne i Feliks sa svojom ženom Druzilom koja bijaše Židovka; posla po Pavla i posluša ga o vjeri u Isusa Krista."},{"v":25,"t":"Kad Pavao stade raspravljati o pravednosti, uzdržljivosti i budućem Sudu, Feliks uplašen reče: “Zasad idi, a kad nađem vremena, pozvat ću te.”"},{"v":26,"t":"Ujedno se nadao da će mu Pavao dati novaca. Zato ga je češće pozivao i s njim razgovarao."},{"v":27,"t":"Nakon dvije godine dobi Feliks za nasljednika Porcija Festa. Hoteći ugoditi Židovima, ostavi Feliks Pavla u okovima."}]},"25":{"hr":[{"v":1,"t":"Fest dakle tri dana nakon dolaska u provinciju uziđe iz Cezareje u Jeruzalem."},{"v":2,"t":"Veliki mu svećenici i prvaci židovski izniješe tužbu protiv Pavla te ga zaklinjahu"},{"v":3,"t":"ištući milost protiv Pavla: da ga pošalje u Jeruzalem. Jer spremali su zasjedu da ga putom smaknu."},{"v":4,"t":"Ali Fest odvrati kako Pavao treba da ostane zatvoren u Cezareji, a i on da će uskoro onamo."},{"v":5,"t":"“Ovlašteni dakle među vama, reče, neka sa mnom siđu pa ako na tom čovjeku ima krivnje, neka ga tuže.”"},{"v":6,"t":"Pošto se u njih zadrži najviše osam ili deset dana, siđe u Cezareju. Sutradan sjede na sudačku stolicu i zapovjedi da se dovede Pavao."},{"v":7,"t":"Kad se on pojavi, okružiše ga Židovi koji su sišli iz Jeruzalema i izniješe protiv njega mnoge i teške optužbe kojih ne mogahu dokazati."},{"v":8,"t":"Pavao se branio: “Ničim se nisam ogriješio ni o židovski Zakon, ni o Hram, ni o cara.”"},{"v":9,"t":"Nato Fest hoteći ugoditi Židovima, odvrati Pavlu: “Hoćeš li u Jeruzalem da ti se ondje za to sudi preda mnom?”"},{"v":10,"t":"A Pavao će: “Stojim pred sudom carevim, gdje treba da mi se sudi. Židovima ništa ne skrivih, kao što i ti veoma dobro znaš."},{"v":11,"t":"Ako sam pak doista što skrivio i učinio štogod što zavređuje smrt, ne izmičem smrti; ako li pak ne stoji ono za što me ovi tuže, nitko me ne može njima izručiti. Na cara se prizivljem!”"},{"v":12,"t":"Tada se Fest posavjetova s vijećem pa odgovori: “Na cara si se prizvao, pred cara ćeš ići!”"},{"v":13,"t":"Nekoliko dana poslije dođu kralj Agripa i Berenika u Cezareju da pozdrave Festa."},{"v":14,"t":"Kako se ondje zadržaše nekoliko dana, izloži Fest kralju to o Pavlu: “Ima neki čovjek, reče, što ga je Feliks ostavio uznikom."},{"v":15,"t":"Kad bijah u Jeruzalemu, izniješe veliki svećenici i starješine protiv njega tužbu i zatražiše osudu."},{"v":16,"t":"Odgovorih im da u Rimljana nije običaj izručivati kojega čovjeka prije negoli se, optužen, suoči s tužiteljima i dobije prigodu da se brani od optužbe."},{"v":17,"t":"Pošto zajedno dođosmo ovamo, bez ikakva odgađanja sjedoh ja sutradan na sudačku stolicu i zapovjedih dovesti toga čovjeka."},{"v":18,"t":"Tužitelji ga okružiše, ali ne izniješe tužbe ni za jedno od zlodjela koja sam ja naslućivao,"},{"v":19,"t":"nego su protiv njega imali nešto prijeporno o svojoj vjeri i o nekom Isusu koji je umro, a Pavao tvrdi da je živ."},{"v":20,"t":"Ne snalazeći se u takvoj raspravi, upitah bi li htio u Jeruzalem da mu se ondje za to sudi."},{"v":21,"t":"Budući da se Pavao prizivom podložio presudi njegova Veličanstva, zapovjedih da ga čuvaju dok ga ne pošaljem caru.”"},{"v":22,"t":"Na to će Agripa Festu: “Htio bih i ja čuti toga čovjeka.” “Sutra ćeš ga, reče, čuti.”"},{"v":23,"t":"Sutradan dakle dođu Agripa i Berenika s velikim sjajem te uđu u dvoranu zajedno s tisućnicima i najuglednijim gradskim muževima. Kad na zapovijed Festovu dovedu Pavla,"},{"v":24,"t":"reče Fest: “Agripa, kralju, i vi svi ovdje s nama nazočni, gledajte ovoga čovjeka! Zbog njega me sav narod židovski salijetao i u Jeruzalemu i ovdje vičući da on ne smije više živjeti."},{"v":25,"t":"Ali ja nađoh da nije učinio ništa čime bi zaslužio smrt pa kad se on sam prizvao na njegovo Veličanstvo, odlučih poslati mu ga."},{"v":26,"t":"Ja nemam ništa pouzdano o njemu napisati Gospodaru. Zato ga izvedoh pred vas, ponajpače preda te, kralju Agripa, da bih nakon ove istrage imao što napisati."},{"v":27,"t":"Čini mi se doista besmislenim poslati uznika, a ne naznačiti optužbu protiv njega.”"}]},"26":{"hr":[{"v":1,"t":"Nato Agripa reče Pavlu: “Dopušta ti se o sebi govoriti.” Pavao ispruži ruku i stade se braniti:"},{"v":2,"t":"“Smatram se sretnim što se u svemu za što me Židovi optužuju mogu, evo, danas braniti pred tobom, kralju Agripa,"},{"v":3,"t":"jer ti najbolje poznaješ židovske običaje i zadjevice. Zato me, molim, velikodušno poslušaj.”"},{"v":4,"t":"“Dakle, život moj od najranije mladosti proveden u narodu mojem, u Jeruzalemu, znaju svi Židovi."},{"v":5,"t":"Poznaju me odavna te mogu, ako samo hoće, svjedočiti da sam po najstrožoj sljedbi naše vjere živio kao farizej."},{"v":6,"t":"I sada stojim pred sudom zbog nade u obećanje koje Bog dade ocima našim"},{"v":7,"t":"i kojemu se dovinuti nada dvanaest plemena naših, svesrdno noću i danju služeći Bogu. Za tu me nadu, kralju, tuže Židovi."},{"v":8,"t":"Zašto nevjerojatnim smatrate da Bog mrtve uskrisuje?”"},{"v":9,"t":"“Pa i ja sam nekoć smatrao da mi se svim silama boriti protiv imena Isusa Nazarećanina."},{"v":10,"t":"To sam i činio u Jeruzalemu: mnoge sam svete, pošto od velikih svećenika dobih punomoć, u tamnice zatvorio, dao svoj glas kad su ih ubijali"},{"v":11,"t":"i po svim ih sinagogama često mučenjem prisiljavao psovati i, prekomjerno bijesan na njih, progonio sam ih čak i u tuđim gradovima.”"},{"v":12,"t":"“Radi toga pođoh u Damask s punomoći i ovlaštenjem velikih svećenika"},{"v":13,"t":"kadli u pol bijela dana na putu vidjeh, kralju, kako s neba svjetlost od sunca sjajnija obasja mene i moje suputnike."},{"v":14,"t":"Pošto popadasmo na zemlju, začuh glas što mi govoraše hebrejskim jezikom: 'Savle, Savle, zašto me progoniš? Teško ti se protiv ostana praćakati.'"},{"v":15,"t":"Ja odvratih: 'Tko si, Gospodine?' Gospodin će mi: 'Ja sam Isus koga ti progoniš!"},{"v":16,"t":"Nego ustani, na noge se jer zato ti se ukazah da te postavim za poslužitelja i svjedoka onoga što si vidio i što ću ti pokazati."},{"v":17,"t":"Izbavit ću te od naroda i od pogana kojima te šaljem"},{"v":18,"t":"da im otvoriš oči pa se obrate od tame k svjetlosti, od vlasti Sotonine k Bogu te po vjeri u mene prime oproštenje grijeha i baštinu među posvećenima.'”"},{"v":19,"t":"“Otada, kralju Agripa, ne bijah neposlušan nebeskom viđenju."},{"v":20,"t":"Nego najprije onima u Damasku pa onda i u Jeruzalemu, svoj zemlji židovskoj i poganima navješćivah da se pokaju i obrate k Bogu i čine djela dostojna obraćenja."},{"v":21,"t":"Zbog toga me Židovi uhvatiše u Hramu i pokušaše ubiti."},{"v":22,"t":"Ali s pomoću Božjom sve do dana današnjega svjedočim, evo, malu i veliku, ne govoreći ništa osim onoga što Proroci govorahu i Mojsije da se ima zbiti:"},{"v":23,"t":"da će Krist trpjeti i da će on, prvouskrsli od mrtvih, svjetlost navješćivati narodu i poganima.”"},{"v":24,"t":"Dok se on tako branio, Fest će mu u sav glas: “Mahnitaš, Pavle! Veliko ti znanje mozgom zavrnulo.”"},{"v":25,"t":"“Ne mahnitam, vrli Feste, odvrati Pavao, nego riječi istine i razbora kazujem."},{"v":26,"t":"Ta znade za to kralj komu s pouzdanjem govorim. Ništa mu od toga, uvjeren sam, nije nepoznato; jer nije se to dogodilo u kakvu zakutku."},{"v":27,"t":"Vjeruješ li, kralju Agripa, Prorocima? Znam da vjeruješ!”"},{"v":28,"t":"Agripa će Pavlu: “Zamalo pa me uvjeri te kršćaninom postah!”"},{"v":29,"t":"Pavao pak: “Dao Bog te i za malo i za mnogo, ne samo ti nego i svi koji me danas slušaju postali ovakvima kakav sam ja, osim ovih okova!”"},{"v":30,"t":"Nato usta kralj, upravitelj, Berenika i oni koji su s njima zasjedali."},{"v":31,"t":"Udaljujući se govorili su među sobom: “Ovaj čovjek ne čini ništa čime bi zaslužio smrt ili okove.”"},{"v":32,"t":"Agripa pak reče Festu: “Ovaj bi čovjek mogao biti pušten da se nije prizvao na cara.”"}]},"27":{"hr":[{"v":1,"t":"Kad je odlučeno da odjedrimo u Italiju, predadoše i Pavla i neke druge uznike satniku carske čete, imenom Juliju."},{"v":2,"t":"Popesmo se na neku adramitsku lađu koja je imala ploviti u azijska mjesta pa otplovismo. S nama je bio Aristarh Makedonac, Solunjanin."},{"v":3,"t":"Sutradan doplovismo u Sidon. Julije, koji je s Pavlom čovječno postupao, dopusti mu poći k prijateljima da se pobrinu za nj."},{"v":4,"t":"Odande smo otplovili, jedrili uz Cipar - jer su nam vjetrovi bili protivni -"},{"v":5,"t":"pa preplovili more duž Cilicije i Pamfilije i stigli u Miru licijsku."},{"v":6,"t":"Ondje satnik nađe neku aleksandrijsku lađu za Italiju i ukrca nas na nju."},{"v":7,"t":"Više smo dana plovili sporo i jedva doprli do Knida. Kako nam vjetar ne dade pristati, doplovismo pod Kretu kod Salmone"},{"v":8,"t":"pa jedva jedvice ploveći uza nju, stigosmo na neko mjesto zvano Dobra pristaništa, blizu kojega je grad Laseja."},{"v":9,"t":"Kad je nakon duljeg vremena plovidba već postala pogibeljna jer je Post već bio izminuo, opominjaše Pavao:"},{"v":10,"t":"“Ljudi, govorio im je, vidim da će plovidba biti nezgodna i na veliku štetu ne samo za tovar i lađu nego i za naše živote.”"},{"v":11,"t":"Ali je satnik više vjerovao kormilaru i brodovlasniku negoli Pavlovim riječima."},{"v":12,"t":"A kako luka nije bila prikladna za zimovanje, većina je predlagala da odande otplove ne bi li kako doprli do kretske luke Feniksa, što gleda prema jugozapadu i sjeverozapadu, pa ondje prezimili."},{"v":13,"t":"Uto duhne blagi južnjak i oni, misleći da bi mogli ostvariti naum, digoše sidro i zaploviše tik uz Kretu."},{"v":14,"t":"Ali nedugo zatim razbjesni se žestok vjetar zvan sjeveroistočnjak."},{"v":15,"t":"Zahvati lađu te mu nije mogla odoljeti pa se prepustismo da nas nosi."},{"v":16,"t":"Prolazeći ispod nekog otočića zvanog Kauda, jedva uspjesmo dohvatiti čamac."},{"v":17,"t":"Podigoše ga pa upotrijebiše snast da potpašu lađu. Bojeći se pak da se ne nasuču u Sirti, spustiše prvenjaču. Tako ih je nosilo."},{"v":18,"t":"Budući da nas je oluja silovito udarala, sutradan se riješiše tovara,"},{"v":19,"t":"a treći dan svojim rukama izbaciše brodsku opremu."},{"v":20,"t":"Kako se pak više dana nije pomaljalo ni sunce ni zvijezde, a oluja bjesnjela nemalena, bila je već propala svaka nada da ćemo se spasiti."},{"v":21,"t":"Ni jelo se već dugo nije. Onda usta Pavao posred njih i reče: “Trebalo je, ljudi, poslušati me, ne se otiskivati od Krete i izbjeći ovu nepogodu i štetu."},{"v":22,"t":"Sada vas pak opominjem: razvedrite se jer ni živa duša između vas neće stradati, nego samo lađa."},{"v":23,"t":"Noćas mi se ukaza anđeo Boga čiji sam i komu služim"},{"v":24,"t":"te reče: 'Ne boj se, Pavle! Pred cara ti je stati i evo Bog ti daruje sve koji plove s tobom.'"},{"v":25,"t":"Zato razvedrite se, ljudi! Vjerujem Bogu: bit će kako mi je rečeno."},{"v":26,"t":"Ali treba da se nasučemo na neki otok.”"},{"v":27,"t":"Bijaše već četrnaesta noć što smo bili tamo-amo gonjani po Jadranu kad oko ponoći naslutiše mornari da im se primiče neka zemlja."},{"v":28,"t":"Bacivši olovnicu, nađoše dvadeset hvati dubine; malo poslije baciše je opet i nađoše ih petnaest."},{"v":29,"t":"Kako se bojahu da ne naletimo na grebene, baciše s krme četiri sidra iščekujući da se razdani."},{"v":30,"t":"Kad su mornari bili naumili uteći iz lađe i počeli spuštati čamac u more pod izlikom da s pramca kane spustiti sidra,"},{"v":31,"t":"reče Pavao satniku i vojnicima: “Ako ovi ne ostanu na lađi, vi se spasiti ne možete!”"},{"v":32,"t":"Nato vojnici presjekoše užad čamca i pustiše da padne."},{"v":33,"t":"Do pred svanuće nutkao je Pavao sve da uzmu hrane: “Četrnaesti je danas dan, reče, što bez jela čekate, ništa ne okusivši."},{"v":34,"t":"Stoga vas molim: založite nešto jer to je za vaš spas. Ta nikome od vas ni vlas s glave neće propasti.”"},{"v":35,"t":"Rekavši to, uze kruh, pred svima zahvali Bogu, razlomi i stade jesti."},{"v":36,"t":"Svi se razvedre te i oni uzmu hrane."},{"v":37,"t":"A svih nas je u lađi bilo dvjesta sedamdeset i šest duša."},{"v":38,"t":"Jednom nasićeni, stanu rasterećivati lađu bacajući žito u more."},{"v":39,"t":"Kad osvanu, mornari ne prepoznaše zemlje; razabraše neki zaljev ravne obale pa odluče, bude li moguće, u nj zavesti lađu."},{"v":40,"t":"Odriješe sidra i ostave ih u moru. Istodobno popuste i spone kormila, razapnu prvenjaču prema vjetru pa udare k obali."},{"v":41,"t":"Ali naletješe na plićak i nasukaše brod: pramac, nasađen, osta nepomičan, a krmu razdiraše žestina valova."},{"v":42,"t":"Tada vojnici naumiše poubijati sužnje da ne bi koji isplivao i pobjegao,"},{"v":43,"t":"ali im satnik, hoteći spasiti Pavla, omete naum: zapovjedi da oni koji znaju plivati najprvi poskaču i izađu na kraj,"},{"v":44,"t":"a ostali će, tko na daskama, tko na olupinama lađe. Tako svi živi i zdravi prispješe na kopno."}]},"28":{"hr":[{"v":1,"t":"Jednom spašeni, doznasmo da se otok zove Malta."},{"v":2,"t":"Urođenici nam iskazivahu nesvakidašnje čovjekoljublje. Zapališe krijes i okupiše nas oko njega jer je počela kiša i bilo zima."},{"v":3,"t":"Pavao nakupi naramak granja i baci na krijes kadli zbog vrućine izađe zmija i pripije mu se za ruku."},{"v":4,"t":"Kad su urođenici vidjeli gdje mu životinja visi o ruci, govorili su među sobom: “Ovaj je čovjek zacijelo ubojica: umakao je moru i Pravda mu ne da živjeti.”"},{"v":5,"t":"Ali on otrese životinju u vatru i ne bi mu ništa;"},{"v":6,"t":"a oni očekivahu da će oteći i umah se srušiti mrtav. Pošto su dugo čekali i vidjeli da mu se ništa neobično nije dogodilo, promijeniše mišljenje te stadoše govoriti da je bog."},{"v":7,"t":"U okolici onoga mjesta bilo je imanje prvaka otoka, imenom Publija. On nas je primio i tri dana uljudno gostio."},{"v":8,"t":"A Publijeva je oca uhvatila ognjica i srdobolja pa je ležao. Pavao uđe k njemu, pomoli se, stavi na nj ruke i izliječi ga."},{"v":9,"t":"Nakon toga su dolazili i drugi koji na otoku bijahu bolesni te ozdravljali."},{"v":10,"t":"Oni nas mnogim počastima počastiše i na odlasku nam priskrbiše što je potrebno."},{"v":11,"t":"Nakon tri mjeseca otplovismo aleksandrijskom lađom koja je prezimila na otoku i imala za znak Dioskure."},{"v":12,"t":"Doplovismo u Sirakuzu i ostadosmo ondje tri dana."},{"v":13,"t":"Odande ploveći uz obalu, stigosmo u Regij. Sutradan okrenu južnjak te za dva dana stigosmo u Puteole."},{"v":14,"t":"Ondje nađosmo braću koja nas zamoliše da ostanemo u njih sedam dana. Tako stigosmo u Rim."},{"v":15,"t":"Kada su tamošnja braća čula za nas, iziđoše nam u susret do Apijeva trga i Triju gostionica. Kad ih Pavao ugleda, zahvali Bogu i ohrabri se."},{"v":16,"t":"A kad uđosmo u Rim, Pavlu su dopustili stanovati zasebno, zajedno s vojnikom koji ga je čuvao."},{"v":17,"t":"Nakon tri dana sazva on židovske prvake. Kad se sabraše, reče im: “Ja, braćo, ne učinih ništa protiv naroda ni običaja otačkih, a ipak me okovana u Jeruzalemu predadoše u ruke Rimljana."},{"v":18,"t":"Oni me nakon istrage htjedoše pustiti jer nije na meni bilo ništa čime bih bio zaslužio smrt."},{"v":19,"t":"Kako se Židovi tome opriješe, bio sam prisiljen prizvati se na cara; ne dakle stoga što bih imao bilo za što tužiti svoj narod."},{"v":20,"t":"S toga dakle razloga zamolih vidjeti vas i obratiti vam se jer zbog nade Izraelove nosim ove verige.”"},{"v":21,"t":"Oni mu odvrate: “Mi o tebi nismo primili nikakva pisma iz Judeje niti nam je tko od pristigle braće o tebi što zlo javio ili rekao."},{"v":22,"t":"Nego htjeli bismo od tebe čuti što misliš jer o toj sljedbi znamo samo da joj se posvuda proturječi.”"},{"v":23,"t":"Nato urekoše dan pa dođoše mnogi k njemu u stan. Izlagao im je i svjedočio o kraljevstvu Božjemu te ih od jutra do večeri iz Mojsijeva Zakona i Proroka uvjeravao o Isusu."},{"v":24,"t":"I jedne uvjeriše njegove riječi, a drugi nisu vjerovali."},{"v":25,"t":"Nesložni tako među sobom, stadoše se razilaziti kadli im Pavao reče još jednu riječ: “Lijepo Duh Sveti po Izaiji proroku reče ocima vašim:"},{"v":26,"t":"Idi k tomu narodu i reci mu: Slušat ćete, slušati - i nećete razumjeti; gledat ćete, gledati - i nećete vidjeti!"},{"v":27,"t":"Jer usalilo se srce naroda ovoga: uši začepiše, oči zatvoriše da očima ne vide, ušima ne čuju, srcem ne razumiju te se ne obrate pa ih izliječim."},{"v":28,"t":"Neka vam je dakle svima znano: poganima je poslano ovo spasenje Božje; oni će poslušati!”"},{"v":29,"t":"#"},{"v":30,"t":"Pavao osta pune dvije godine u svom unajmljenom stanu gdje je primao sve koji su dolazili k njemu,"},{"v":31,"t":"propovijedao kraljevstvo Božje i naučavao o Gospodinu Isusu Kristu sa svom slobodom, nesmetano."}]}},"ROM":{"1":{"hr":[{"v":1,"t":"Pavao, sluga Krista Isusa, pozvan za apostola, odlučen za evanđelje Božje -"},{"v":2,"t":"koje Bog unaprijed obećavaše po svojim prorocima u Pismima svetim"},{"v":3,"t":"o Sinu svome, potomku Davidovu po tijelu,"},{"v":4,"t":"postavljenu Sinom Božjim, u snazi, po Duhu posvetitelju uskrsnućem od mrtvih, o Isusu Kristu, Gospodinu našemu,"},{"v":5,"t":"po komu primismo milost i apostolstvo da na slavu imena njegova k poslušnosti vjere privodimo sve pogane"},{"v":6,"t":"među kojima ste i vi pozvanici Isusa Krista:"},{"v":7,"t":"svima u Rimu, miljenicima Božjim, pozvanicima, svetima. Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista."},{"v":8,"t":"Ponajprije zahvaljujem Bogu mojemu po Isusu Kristu za sve vas: što se vaša vjera navješćuje po svem svijetu."},{"v":9,"t":"Doista, svjedok mi je Bog - komu duhom svojim služim u evanđelju Sina njegova - da vas se"},{"v":10,"t":"u svojim molitvama neprekidno spominjem i uvijek molim ne bi li mi se već jednom s voljom Božjom nekako posrećilo doći k vama."},{"v":11,"t":"Jer čeznem vidjeti vas da vam predam nešto dara duhovnoga te se ojačate, zapravo -"},{"v":12,"t":"da se zajedno s vama ohrabrim zajedničkom vjerom, vašom i mojom."},{"v":13,"t":"A ne bih htio, braćo, da ne znate: često sam bio nakanio doći k vama - i sve dosad bio spriječen - da i među vama uberem koji plod kao i među drugim narodima."},{"v":14,"t":"Dužnik sam Grcima i barbarima, mudracima i neznalicama."},{"v":15,"t":"Odatle moja nakana da i vama u Rimu navijestim evanđelje."},{"v":16,"t":"Ne stidim se, uistinu, evanđelja: ono je snaga Božja na spasenje svakomu tko vjeruje - Židovu najprije, pa Grku."},{"v":17,"t":"Jer pravednost se Božja od vjere k vjeri u njemu otkriva kao što je pisano: Pravednik će od vjere živjeti."},{"v":18,"t":"Otkriva se doista s neba gnjev Božji na svaku bezbožnost i nepravednost ljudi koji istinu sputavaju nepravednošću."},{"v":19,"t":"Jer što se o Bogu može spoznati, očito im je: Bog im očitova."},{"v":20,"t":"Uistinu, ono nevidljivo njegovo, vječna njegova moć i božanstvo, onamo od stvaranja svijeta, umom se po djelima razabire tako da nemaju isprike."},{"v":21,"t":"Jer premda upoznaše Boga, ne iskazaše mu kao Bogu ni slavu ni zahvalnost, nego ishlapiše u mozganjima svojim te se pomrači bezumno srce njihovo."},{"v":22,"t":"Gradeći se mudrima, poludješe i"},{"v":23,"t":"zamijeniše slavu neraspadljivog Boga likom, obličjem raspadljiva čovjeka, i ptica, i četveronožaca, i gmazova."},{"v":24,"t":"Zato ih je Bog po pohotama srdaca njihovih predao nečistoći te sami obeščašćuju svoja tijela,"},{"v":25,"t":"oni što su Istinu - Boga zamijenili lažju, častili i štovali stvorenje umjesto Stvoritelja, koji je blagoslovljen u vjekove. Amen."},{"v":26,"t":"Stoga ih je Bog predao sramotnim strastima: njihove žene zamijeniše naravno općenje protunaravnim,"},{"v":27,"t":"a tako su i muškarci napustili naravno općenje sa ženom i raspalili se pohotom jedni za drugima te muškarci s muškarcima sramotno čine i sami na sebi primaju zasluženu plaću svoga zastranjenja."},{"v":28,"t":"I kako nisu smatrali vrijednim držati se spoznaje Boga, predade ih Bog nevaljanu umu te čine što ne dolikuje,"},{"v":29,"t":"puni svake nepravde, pakosti, lakomosti, zloće; puni zavisti, ubojstva, svađe, prijevare, zlonamjernosti; došaptavači,"},{"v":30,"t":"klevetnici, mrzitelji Boga, drznici, oholice, preuzetnici, izmišljači zala, roditeljima neposlušni,"},{"v":31,"t":"nerazumni, nevjerni, bešćutni, nemilosrdni."},{"v":32,"t":"Znaju za odredbu Božju - da smrt zaslužuju koji takvo što čine - a oni ne samo da to čine nego i povlađuju onima koji čine."}]},"2":{"hr":[{"v":1,"t":"Zato nemaš isprike, čovječe koji sudiš, tko god ti bio. Jer time što drugoga sudiš, sebe osuđuješ: ta to isto činiš ti što sudiš."},{"v":2,"t":"Znamo pak: Bog po istini sudi one koji takvo što čine."},{"v":3,"t":"Misliš li da ćeš izbjeći sudu Božjemu, ti čovječe što sudiš one koji takvo što čine, a sam to isto činiš?"},{"v":4,"t":"Ili prezireš bogatstvo dobrote, strpljivosti i velikodušnosti njegove ne shvaćajući da te dobrota Božja k obraćenju privodi?"},{"v":5,"t":"Tvrdokornošću svojom i srcem koje neće obraćenja zgrćeš na se gnjev za Dan gnjeva i objavljenja pravedna suda Boga"},{"v":6,"t":"koji će uzvratiti svakom po djelima:"},{"v":7,"t":"onima koji postojanošću u dobrim djelima ištu slavu, čast i neraspadljivost - život vječni;"},{"v":8,"t":"buntovnicima pak i nepokornima istini, a pokornima nepravdi - gnjev i srdžba!"},{"v":9,"t":"Nevolja i tjeskoba na svaku dušu čovječju koja čini zlo, na Židova najprije, pa na Grka;"},{"v":10,"t":"a slava, čast i mir svakomu koji čini dobro, Židovu najprije, pa Grku!"},{"v":11,"t":"Ta u Boga nema pristranosti."},{"v":12,"t":"Uistinu koji bez Zakona sagriješiše, bez Zakona će i propasti; i koji pod Zakonom sagriješiše, po Zakonu će biti suđeni."},{"v":13,"t":"Ne, pred Bogom nisu pravedni slušatelji Zakona, nego - izvršitelji će Zakona biti opravdani."},{"v":14,"t":"Ta kad se god pogani, koji nemaju Zakona, po naravi drže Zakona, i nemajući Zakona, oni su sami sebi Zakon:"},{"v":15,"t":"pokazuju da je ono što Zakon nalaže upisano u srcima njihovim. O tom svjedoči i njihova savjest, a i prosuđivanja kojima se među sobom optužuju ili brane."},{"v":16,"t":"To će se očitovati na Dan u koji će, po mojem evanđelju, Bog po Isusu Kristu suditi ono što je skriveno u ljudima."},{"v":17,"t":"Ako pak ti koji se Židovom nazivaš, koji mirno počivaš na Zakonu i dičiš se Bogom,"},{"v":18,"t":"koji poznaješ Volju i iz Zakona poučen razlučuješ što je bolje"},{"v":19,"t":"te si uvjeren da si vođa slijepih, svjetlo onih u tami,"},{"v":20,"t":"odgojitelj nerazumnih, učitelj nejačadi jer u Zakonu imaš oličenje znanja i istine;"},{"v":21,"t":"ti, dakle, koji drugoga učiš, sam sebe ne učiš! Ti koji propovijedaš da se ne krade, kradeš!"},{"v":22,"t":"Ti koji zabranjuješ preljub, preljub počinjaš! Ti komu su odvratni kumiri, pljačkaš hramove!"},{"v":23,"t":"Ti koji se Zakonom dičiš, kršenjem toga Zakona Boga obeščašćuješ!"},{"v":24,"t":"Doista, kako je pisano, ime se Božje zbog vas huli među narodima."},{"v":25,"t":"Da, obrezanje koristi ako vršiš Zakon; ako pak kršiš Zakon, obrezanje tvoje postalo je neobrezanje."},{"v":26,"t":"Ako dakle neobrezani opslužuje propise Zakona, neće li se njegovo neobrezanje smatrati obrezanjem?"},{"v":27,"t":"I onaj koji je podrijetlom neobrezanik, a ispunja Zakon, sudit će tebi koji si, uza sve slovo i obrezanje, prijestupnik Zakona."},{"v":28,"t":"Ta nije Židov tko je Židov naizvana i nije obrezanje ono izvana,"},{"v":29,"t":"na tijelu, nego pravi je Židov u nutrini i pravo je obrezanje u srcu, po duhu, ne po slovu. Pohvala mu nije od ljudi, nego od Boga."}]},"3":{"hr":[{"v":1,"t":"Koja je dakle prednost Židova? Ili kakva korist od obrezanja?"},{"v":2,"t":"Velika u svakom pogledu. Ponajprije: povjerena su im obećanja Božja."},{"v":3,"t":"Da, a što ako su se neki iznevjerili? Neće li njihova nevjernost obeskrijepiti vjernost Božju?"},{"v":4,"t":"Nipošto! Nego neka Bog bude istinit, a svaki čovjek lažac, kao što je pisano: Da pravedan budeš po obećanjima svojim i pobijediš kada te sudili budu."},{"v":5,"t":"Ako pak naša nepravednost ističe Božju pravednost, što ćemo na to reći? Nije li onda - po ljudsku govorim - nepravedan Bog koji daje maha gnjevu?"},{"v":6,"t":"Nipošto! Ta kako će inače Bog suditi svijet?"},{"v":7,"t":"Ako je, doista, istina Božja po mojoj lažljivosti obilno zasjala njemu na slavu, zašto da ja još budem suđen kao grešnik?"},{"v":8,"t":"I zar da ne “činimo zlo da dođe dobro”, kako nas kleveću i kako neki kažu da govorimo? Sud ih pravedni čeka!"},{"v":9,"t":"Što dakle? Imamo li prednost? Ne baš! Jer upravo optužismo sve, i Židove i Grke, da su pod grijehom,"},{"v":10,"t":"kao što je pisano: Nema pravedna ni jednoga,"},{"v":11,"t":"nema razumna, nema ga tko bi Boga tražio."},{"v":12,"t":"Svi skrenuše, svi se zajedno pokvariše, nitko da čini dobro - nijednoga nema."},{"v":13,"t":"Grob otvoren grlo je njihovo, jezikom lažno laskaju, pod usnama im je otrov ljutičin,"},{"v":14,"t":"usta im puna kletve i grkosti;"},{"v":15,"t":"noge im hitre da krv proliju,"},{"v":16,"t":"razvaline i nevolja na njinim su putima,"},{"v":17,"t":"put mira oni ne poznaju,"},{"v":18,"t":"straha Božjega nemaju pred očima."},{"v":19,"t":"A znamo: što god Zakon veli, govori onima pod Zakonom, da svaka usta umuknu i sav svijet bude krivac pred Bogom."},{"v":20,"t":"Zato se po djelima Zakona nitko neće opravdati pred njim. Uistinu, po Zakonu - samo spoznaja grijeha!"},{"v":21,"t":"Sada se pak izvan Zakona očitovala pravednost Božja, posvjedočena Zakonom i Prorocima,"},{"v":22,"t":"pravednost Božja po vjeri Isusa Krista, prema svima koji vjeruju. Ne, nema razlike!"},{"v":23,"t":"Svi su zaista sagriješili i potrebna im je slava Božja;"},{"v":24,"t":"opravdani su besplatno, njegovom milošću po otkupljenju u Kristu Isusu."},{"v":25,"t":"Njega je Bog izložio da krvlju svojom bude Pomirilište po vjeri. Htio je tako očitovati svoju pravednost kojom je u svojoj božanskoj strpljivosti propuštao dotadašnje grijehe;"},{"v":26,"t":"htio je očitovati svoju pravednost u sadašnje vrijeme - da bude pravedan i da opravdava onoga koji je od vjere Isusove."},{"v":27,"t":"Gdje je dakle hvastanje? Isključeno je. Po kojem zakonu? Po zakonu djela? Ne, nego po zakonu vjere."},{"v":28,"t":"Smatramo zaista da se čovjek opravdava vjerom bez djela Zakona."},{"v":29,"t":"Ili je Bog samo Bog Židova? Nije li i pogana? Da, i pogana."},{"v":30,"t":"Jer jedan je Bog: on će opravdati obrezane zbog vjere i neobrezane po vjeri."},{"v":31,"t":"Obeskrepljujemo li dakle Zakon po vjeri? Nipošto! Naprotiv, Zakon utvrđujemo."}]},"4":{"hr":[{"v":1,"t":"Što ćemo dakle reći? Što je Abraham, otac naš, našao po tijelu?"},{"v":2,"t":"Doista, ako je Abraham po djelima opravdan, ima se čime dičiti - ali ne pred Bogom."},{"v":3,"t":"Ta što veli Pismo? Povjerova Abraham Bogu i uračuna mu se u pravednost."},{"v":4,"t":"Onomu tko radi ne računa se plaća kao milost, nego kao dug."},{"v":5,"t":"Onomu tko ne radi, a vjeruje u Onoga koji opravdava bezbožnika, vjera se uračunava u pravednost,"},{"v":6,"t":"kao što i David blaženim proglašuje čovjeka kojemu Bog uračunava pravednost bez djela:"},{"v":7,"t":"Blaženi oni kojima je zločin otpušten, kojima je grijeh pokriven!"},{"v":8,"t":"Blago čovjeku komu Gospodin ne ubraja krivnju."},{"v":9,"t":"Ide li dakle ovo blaženstvo samo obrezane ili i neobrezane? Ta velimo: Vjera se Abrahamu uračuna u pravednost."},{"v":10,"t":"A kako mu se uračuna? Već obrezanu ili još neobrezanu? Ne obrezanu, nego neobrezanu!"},{"v":11,"t":"I znak obrezanja primi kao pečat pravednosti koju je po vjeri zadobio još neobrezan, da bude ocem svih vjernika: neobrezanih - te im se uračuna pravednost -"},{"v":12,"t":"i ocem obrezanih, ne onih koji su samo obrezani, nego onih koji uz to idu stopama vjere još neobrezana oca našeg Abrahama."},{"v":13,"t":"Doista, obećanje da će biti baštinik svijeta nije Abrahamu ili njegovu potomstvu dano na temelju nekog zakona, nego na temelju pravednosti vjere."},{"v":14,"t":"Jer ako su baštinici oni iz Zakona, prazna je vjera, jalovo obećanje."},{"v":15,"t":"Ta Zakon rađa gnjev; gdje pak nema Zakona, nema ni prekršaja."},{"v":16,"t":"Zato - zbog vjere da bude po milosti to obećanje zajamčeno svemu potomstvu, ne potomstvu samo po Zakonu, nego i po vjeri Abrahama, koji je otac svih nas -"},{"v":17,"t":"kao što je pisano: Ocem mnoštva naroda ja te postavljam - pred Onim komu povjerova, pred Bogom koji oživljuje mrtve i zove da bude ono što nije."},{"v":18,"t":"U nadi protiv svake nade povjerova Abraham da postane ocem naroda mnogih po onom što je rečeno: Toliko će biti tvoje potomstvo."},{"v":19,"t":"Nepokolebljivom vjerom promotri on tijelo svoje već obamrlo - bilo mu je blizu sto godina - i obamrlost krila Sarina."},{"v":20,"t":"Ali pred Božjim obećanjem nije nevjeran dvoumio, nego se vjerom ojačao davši slavu Bogu,"},{"v":21,"t":"posve uvjeren da on može učiniti što je obećao."},{"v":22,"t":"Zato mu se i uračuna u pravednost."},{"v":23,"t":"Ali nije samo za nj napisano: Uračuna mu se,"},{"v":24,"t":"nego i za nas kojima se ima uračunati, nama što vjerujemo u Onoga koji od mrtvih uskrisi Isusa, Gospodina našega,"},{"v":25,"t":"koji je predan za opačine naše i uskrišen radi našeg opravdanja."}]},"5":{"hr":[{"v":1,"t":"Opravdani dakle vjerom, u miru smo s Bogom po Gospodinu našem Isusu Kristu."},{"v":2,"t":"Po njemu imamo u vjeri i pristup u ovu milost u kojoj stojimo i dičimo se nadom slave Božje."},{"v":3,"t":"I ne samo to! Mi se dičimo i u nevoljama jer znamo: nevolja rađa postojanošću,"},{"v":4,"t":"postojanost prokušanošću, prokušanost nadom."},{"v":5,"t":"Nada pak ne postiđuje. Ta ljubav je Božja razlivena u srcima našim po Duhu Svetom koji nam je dan!"},{"v":6,"t":"Doista, dok mi još bijasmo nemoćni, Krist je, već u to vrijeme, za nas bezbožnike umro."},{"v":7,"t":"Zbilja, jedva bi tko za pravedna umro; možda bi se za dobra tko i odvažio umrijeti."},{"v":8,"t":"A Bog pokaza ljubav svoju prema nama ovako: dok još bijasmo grešnici, Krist za nas umrije."},{"v":9,"t":"Koliko li ćemo se više sada, pošto smo opravdani krvlju njegovom, spasiti po njemu od srdžbe?"},{"v":10,"t":"Doista, ako se s Bogom pomirismo po smrti Sina njegova dok još bijasmo neprijatelji, mnogo ćemo se više, pomireni, spasiti životom njegovim."},{"v":11,"t":"I ne samo to! Dičimo se u Bogu po Gospodinu našemu Isusu Kristu po kojem zadobismo pomirenje."},{"v":12,"t":"Zbog toga, kao što po jednom Čovjeku uđe u svijet grijeh i po grijehu smrt, i time što svi sagriješiše, na sve ljude prijeđe smrt..."},{"v":13,"t":"Doista, do Zakona bilo je grijeha u svijetu, ali se grijeh ne ubraja kad nema zakona."},{"v":14,"t":"Da, ali smrt je od Adama do Mojsija doista kraljevala i nad onima koji ne sagriješiše prekršajem sličnim kao Adam, koji je pralik Onoga koji ima doći."},{"v":15,"t":"Ali s darom nije kao s grijehom. Jer ako su grijehom jednoga mnogi umrli, mnogo se obilatije na sve razlila milost Božja, milost darovana u jednom čovjeku, Isusu Kristu."},{"v":16,"t":"I dar - to nije kao kad je ono jedan sagriješio: jer presuda nakon jednoga grijeha posta osudom, a dar nakon mnogih grijeha - opravdanjem."},{"v":17,"t":"Uistinu, ako grijehom jednoga smrt zakraljeva - po jednome, mnogo će više oni koji primaju izobilje milosti i dara pravednosti kraljevati u životu - po Jednome, Isusu Kristu."},{"v":18,"t":"Dakle, grijeh jednoga - svim ljudima na osudu, tako i pravednost Jednoga - svim ljudima na opravdanje, na život!"},{"v":19,"t":"Doista, kao što su neposluhom jednoga čovjeka mnogi postali grešnici tako će i posluhom Jednoga mnogi postati pravednici."},{"v":20,"t":"A zakon nadođe da se umnoži grijeh. Ali gdje se umnožio grijeh, nadmoćno izobilova milost:"},{"v":21,"t":"kao što grijeh zakraljeva smrću, da tako i milost kraljuje pravednošću za život vječni po Isusu Kristu Gospodinu našemu."}]},"6":{"hr":[{"v":1,"t":"Što ćemo dakle reći? Da ostanemo u grijehu da milost izobiluje?"},{"v":2,"t":"Nipošto! Jednom umrli grijehu, kako da još živimo u njemu?"},{"v":3,"t":"Ili zar ne znate: koji smo god kršteni u Krista Isusa, u smrt smo njegovu kršteni."},{"v":4,"t":"Krštenjem smo dakle zajedno s njime ukopani u smrt da kao što Krist slavom Očevom bi uskrišen od mrtvih, i mi tako hodimo u novosti života."},{"v":5,"t":"Ako smo doista s njime srasli po sličnosti smrti njegovoj, očito ćemo srasti i po sličnosti njegovu uskrsnuću."},{"v":6,"t":"Ovo znamo: naš je stari čovjek zajedno s njim raspet da onemoća ovo grešno tijelo te više ne robujemo grijehu."},{"v":7,"t":"Ta tko umre, opravdan je od grijeha."},{"v":8,"t":"Pa ako umrijesmo s Kristom, vjerujemo da ćemo i živjeti zajedno s njime."},{"v":9,"t":"Znamo doista: Krist uskrišen od mrtvih, više ne umire, smrt njime više ne gospoduje."},{"v":10,"t":"Što umrije, umrije grijehu jednom zauvijek; a što živi, živi Bogu."},{"v":11,"t":"Tako i vi: smatrajte sebe mrtvima grijehu, a živima Bogu u Kristu Isusu!"},{"v":12,"t":"Neka dakle ne kraljuje grijeh u vašem smrtnom tijelu da slušate njegove požude;"},{"v":13,"t":"i ne predajite grijehu udova svojih za oružje nepravde, nego sebe, od mrtvih oživjele, predajte Bogu i udove svoje dajte Bogu za oružje pravednosti."},{"v":14,"t":"Valjda grijeh neće vama gospodovati! Ta niste pod Zakonom nego pod milošću!"},{"v":15,"t":"Što dakle? Da griješimo jer nismo pod Zakonom nego pod milošću? Nipošto!"},{"v":16,"t":"Ne znate li: ako se komu predate za robove, na poslušnost, robovi ste onoga koga slušate: bilo grijeha - na smrt, bilo poslušnosti - na pravednost."},{"v":17,"t":"Bijaste robovi grijeha, ali ste, hvala Bogu, od srca poslušali ono pravilo nauka kojemu ste povjereni;"},{"v":18,"t":"da, oslobođeni grijeha, postadoste sluge pravednosti."},{"v":19,"t":"Po ljudsku govorim zbog vaše ljudske slabosti: kao što nekoć predadoste udove svoje za robove nečistoći i bezakonju - do bezakonja, tako sada predajte udove svoje za robove pravednosti - do posvećenja."},{"v":20,"t":"Uistinu, kad bijaste robovi grijeha, “slobodni” bijaste od pravednosti."},{"v":21,"t":"Pa kakav ste plod onda imali? Onoga se sada stidite jer svršetak je tomu - smrt."},{"v":22,"t":"Sada pak pošto ste oslobođeni grijeha i postali sluge Božje, imate plod svoj za posvećenje, a svršetak - život vječni."},{"v":23,"t":"Jer plaća je grijeha smrt, a dar Božji jest život vječni u Kristu Isusu, Gospodinu našem."}]},"7":{"hr":[{"v":1,"t":"Ili zar ne znate, braćo - poznavaocima zakona govorim - da zakon gospodari čovjekom samo za vrijeme njegova života."},{"v":2,"t":"Doista, udana je žena vezana zakonom dok joj muž živi; umre li joj muž, riješena je zakona o mužu."},{"v":3,"t":"Dakle: dok joj muž živi, zvat će se, očito, preljubnicom pođe li za drugoga. Ako li joj pak muž umre, slobodna je od zakona te nije preljubnica pođe li za drugoga."},{"v":4,"t":"Tako, braćo moja, i vi po tijelu Kristovu umrijeste Zakonu da pripadnete drugomu, Onomu koji je od mrtvih uskrišen, te plodove donosimo Bogu."},{"v":5,"t":"Doista, dok bijasmo u tijelu, grešne su strasti, Zakonom izazvane, djelovale u našim udovima te smrti donosile plodove;"},{"v":6,"t":"sada pak umrijevši onomu što nas je sputavalo, riješeni smo Zakona te služimo u novosti Duha, a ne u stareži slova."},{"v":7,"t":"Što ćemo dakle reći? Je li Zakon grijeh? Nipošto! Nego: grijeha ne spoznah doli po Zakonu jer za požudu ne bih znao da Zakon nije govorio: Ne poželi!"},{"v":8,"t":"A grijeh je, uhvativši priliku, po zapovijedi u meni prouzročio svakovrsnu požudu. Ta bez zakona grijeh je mrtav."},{"v":9,"t":"Da, ja sam nekoć živio bez zakona. Ali kad je došla zapovijed, grijeh oživje."},{"v":10,"t":"Ja pak umrijeh i ustanovi se: zapovijed dana za život bi mi na smrt."},{"v":11,"t":"Doista grijeh, uhvativši priliku, zapovijeđu me zavede, njome me i ubi."},{"v":12,"t":"Tako: Zakon je svet, i zapovijed je sveta, i pravedna, i dobra."},{"v":13,"t":"Pa zar se to dobro meni u smrt prometnu? Nipošto! Nego: grijeh, da se grijehom očituje, po tom dobru uzrokuje mi smrt - da grijeh po zapovijedi postane najvećim grešnikom."},{"v":14,"t":"Zakon je, znamo, duhovan; ja sam pak tjelesan, prodan pod grijeh."},{"v":15,"t":"Zbilja ne razumijem što radim: ta ne činim ono što bih htio, nego što mrzim - to činim."},{"v":16,"t":"Ako li pak činim što ne bih htio, slažem se sa Zakonom, priznajem da je dobar."},{"v":17,"t":"Onda to ne činim više ja, nego grijeh koji prebiva u meni."},{"v":18,"t":"Doista znam da dobro ne prebiva u meni, to jest u mojem tijelu. Uistinu: htjeti mi ide, ali ne i činiti dobro."},{"v":19,"t":"Ta ne činim dobro koje bih htio, nego zlo koje ne bih htio - to činim."},{"v":20,"t":"Ako li pak činim ono što ne bih htio, nipošto to ne radim ja, nego grijeh koji prebiva u meni."},{"v":21,"t":"Nalazim dakle ovaj zakon: kad bih htio činiti dobro, nameće mi se zlo."},{"v":22,"t":"Po nutarnjem čovjeku s užitkom se slažem sa Zakonom Božjim,"},{"v":23,"t":"ali opažam u svojim udovima drugi zakon koji vojuje protiv zakona uma moga i zarobljuje me zakonom grijeha koji je u mojim udovima."},{"v":24,"t":"Jadan li sam ja čovjek! Tko će me istrgnuti iz ovoga tijela smrtonosnoga?"},{"v":25,"t":"Hvala Bogu po Isusu Kristu Gospodinu našem! Ja, dakle, umom ja služim zakonu Božjemu, a tijelom zakonu grijeha."}]},"8":{"hr":[{"v":1,"t":"Nikakve dakle sada osude onima koji su u Kristu Isusu!"},{"v":2,"t":"Ta zakon Duha života u Kristu Isusu oslobodi me zakona grijeha i smrti."},{"v":3,"t":"Uistinu, što je bilo nemoguće Zakonu, jer je zbog tijela onemoćao, Bog je učinio: poslavši Sina svoga u obličju grešnoga tijela i s obzirom na grijeh, osudi grijeh u tijelu"},{"v":4,"t":"da se pravednost Zakona ispuni u nama koji ne živimo po tijelu nego po Duhu."},{"v":5,"t":"Da, oni koji žive po tijelu, teže za onim što je tjelesno; a koji po Duhu, za onim što je Duhovo:"},{"v":6,"t":"težnja je tijela smrt, a težnja Duha život i mir."},{"v":7,"t":"Jer težnja je tijela protivna Bogu: zakonu se Božjemu ne podvrgava, a i ne može."},{"v":8,"t":"Oni pak koji su u tijelu, ne mogu se Bogu svidjeti."},{"v":9,"t":"A vi niste u tijelu, nego u Duhu, ako Duh Božji prebiva u vama. A nema li tko Duha Kristova, taj nije njegov."},{"v":10,"t":"I ako je Krist u vama, tijelo je doduše mrtvo zbog grijeha, ali Duh je život zbog pravednosti."},{"v":11,"t":"Ako li Duh Onoga koji uskrisi Isusa od mrtvih prebiva u vama, Onaj koji uskrisi Krista od mrtvih oživit će i smrtna tijela vaša po Duhu svome koji prebiva u vama."},{"v":12,"t":"Dakle, braćo, dužnici smo, ali ne tijelu da po tijelu živimo!"},{"v":13,"t":"Jer ako po tijelu živite, umrijeti vam je, ako li pak Duhom usmrćujete tjelesna djela, živjet ćete."},{"v":14,"t":"Svi koje vodi Duh Božji sinovi su Božji."},{"v":15,"t":"Ta ne primiste duh robovanja da se opet bojite, nego primiste Duha posinstva u kojem kličemo: “Abba! Oče!”"},{"v":16,"t":"Sam Duh susvjedok je s našim duhom da smo djeca Božja;"},{"v":17,"t":"ako pak djeca, onda i baštinici, baštinici Božji, a subaštinici Kristovi, kada doista s njime zajedno trpimo, da se zajedno s njime i proslavimo."},{"v":18,"t":"Smatram, uistinu: sve patnje sadašnjega vremena nisu ništa prema budućoj slavi koja se ima očitovati u nama."},{"v":19,"t":"Doista, stvorenje sa svom žudnjom iščekuje ovo objavljenje sinova Božjih:"},{"v":20,"t":"stvorenje je uistinu podvrgnuto ispraznosti - ne po svojoj volji, nego zbog onoga koji ga podvrgnu - ali u nadi."},{"v":21,"t":"Jer i stvorenje će se osloboditi robovanja pokvarljivosti da sudjeluje u slobodi i slavi djece Božje."},{"v":22,"t":"Jer znamo: sve stvorenje zajedno uzdiše i muči se u porođajnim bolima sve do sada."},{"v":23,"t":"Ali ne samo ono! I mi koji imamo prvine Duha, i mi u sebi uzdišemo iščekujući posinstvo, otkupljenje svoga tijela."},{"v":24,"t":"Ta u nadi smo spašeni! Nada pak koja se vidi nije nada. Jer što tko gleda, kako da se tomu i nada?"},{"v":25,"t":"Nadamo li se pak onomu čega ne gledamo, postojano to iščekujemo."},{"v":26,"t":"Tako i Duh potpomaže našu nemoć. Doista ne znamo što da molimo kako valja, ali se sam Duh za nas zauzima neizrecivim uzdasima."},{"v":27,"t":"A Onaj koji proniče srca zna koja je želja Duha - da se on po Božju zauzima za svete."},{"v":28,"t":"Znamo pak da Bog u svemu na dobro surađuje s onima koji ga ljube, s onima koji su odlukom njegovom pozvani."},{"v":29,"t":"Jer koje predvidje, te i predodredi da budu suobličeni slici Sina njegova te da on bude prvorođenac među mnogom braćom."},{"v":30,"t":"Koje pak predodredi, te i pozva; koje pozva, te i opravda; koje opravda, te i proslavi."},{"v":31,"t":"Što ćemo dakle na to reći? Ako je Bog za nas, tko će protiv nas?"},{"v":32,"t":"Ta on ni svojega Sina nije poštedio, nego ga je za sve nas predao! Kako nam onda s njime neće sve darovati?"},{"v":33,"t":"Tko će optužiti izabranike Božje? Bog opravdava!"},{"v":34,"t":"Tko će osuditi? Krist Isus umrije, štoviše i uskrsnu, on je i zdesna Bogu - on se baš zauzima za nas!"},{"v":35,"t":"Tko će nas rastaviti od ljubavi Kristove? Nevolja? Tjeskoba? Progonstvo? Glad? Golotinja? Pogibao? Mač?"},{"v":36,"t":"Kao što je pisano: Poradi tebe ubijaju nas dan za danom i mi smo im ko ovce za klanje."},{"v":37,"t":"U svemu tome nadmoćno pobjeđujemo po onome koji nas uzljubi."},{"v":38,"t":"Uvjeren sam doista: ni smrt ni život, ni anđeli ni vlasti, ni sadašnjost ni budućnost, ni sile,"},{"v":39,"t":"ni dubina ni visina, ni ikoji drugi stvor neće nas moći rastaviti od ljubavi Božje u Kristu Isusu Gospodinu našem."}]},"9":{"hr":[{"v":1,"t":"Istinu govorim u Kristu, ne lažem; susvjedok mi je savjest moja u Duhu Svetom:"},{"v":2,"t":"silna mi je tuga i neprekidna bol u srcu."},{"v":3,"t":"Da, htio bih ja sam proklet biti, odvojen od Krista, za braću svoju, sunarodnjake svoje po tijelu."},{"v":4,"t":"Oni su Izraelci, njihovo je posinstvo, i Slava, i Savezi, i zakonodavstvo, i bogoštovlje, i obećanja;"},{"v":5,"t":"njihovi su i oci, od njih je, po tijelu, i Krist, koji je iznad svega, Bog blagoslovljen u vjekove. Amen."},{"v":6,"t":"Ali ne kao da se izjalovila riječ Božja. Jer nisu Izrael svi koji potječu od Izraela;"},{"v":7,"t":"i nisu svi djeca Abrahamova zato što su njegovo potomstvo, nego po Izaku će ti se nazivati potomstvo;"},{"v":8,"t":"to jest: djeca tijela nisu i djeca Božja, nego - djeca obećanja računaju se u potomstvo."},{"v":9,"t":"Evo doista riječi obećanja: U ovo ću doba doći i Sara će imati sina."},{"v":10,"t":"Ali ne samo to! I Rebeka je s jednim, s Izakom, ocem našim, zanijela."},{"v":11,"t":"Pa kad još blizanci ne bijahu rođeni niti učiniše što dobro ili zlo - da bi trajnom ostala odluka Božja o izabranju:"},{"v":12,"t":"ne po djelima, nego po onome tko poziva - rečeno joj je: Stariji će služiti mlađemu,"},{"v":13,"t":"kako je pisano: Jakova sam zavolio, a Ezav mi omrznu."},{"v":14,"t":"Što ćemo dakle reći? Možda da u Boga ima nepravde? Nipošto!"},{"v":15,"t":"Ta Mojsiju veli: Smilovat ću se komu hoću da se smilujem; sažalit ću se nad kim hoću da se sažalim."},{"v":16,"t":"Nije dakle do onoga koji hoće ni do onoga koji trči, nego do Boga koji se smiluje."},{"v":17,"t":"Jer Pismo veli faraonu: Zato te upravo podigoh da na tebi pokažem svoju moć i da se razglasi ime moje po svoj zemlji."},{"v":18,"t":"Tako dakle: smiluje se komu hoće, a otvrdnjuje koga hoće."},{"v":19,"t":"Da, reći ćeš mi: Što se onda još tuži? Ta tko se to volji njegovoj odupro?"},{"v":20,"t":"Čovječe, tko si ti zapravo da se pravdaš s Bogom? Zar da djelo rekne tvorcu: “Što si me ovakvim načinio?”"},{"v":21,"t":"Ili zar lončar nema vlasti nad glinom da od istoga tijesta načini posudu sad časnu, sad nečasnu."},{"v":22,"t":"A što ako je Bog, hoteći očitovati gnjev i obznaniti svoju moć u silnoj strpljivosti podnosio posude gnjeva, dozrele za propast,"},{"v":23,"t":"da obznani bogatstvo slave svoje na posudama milosrđa, koje unaprijed pripravi za slavu,"},{"v":24,"t":"na nama koje pozva ne samo između Židova nego i između pogana?"},{"v":25,"t":"Tako i u Hošeji veli: Ne-narod moj prozvat ću narodom mojim i Neljubljenu ljubljenom."},{"v":26,"t":"Na mjestu gdje im je rečeno: Vi niste moj narod prozvat će se sinovi Boga živoga."},{"v":27,"t":"Izaija pak proglasuje o Izraelu: Zaista, sinova će Izraelovih brojem biti kao pijeska morskog - Ostatak će se spasiti;"},{"v":28,"t":"jer riječ će ispuniti i uskoro izvršiti Gospodin na zemlji."},{"v":29,"t":"Tako je Izaija i prorekao: Da nam Gospodin nad Vojskama ne ostavi sjeme, ko Sodoma bismo bili i Gomori nalik."},{"v":30,"t":"Što ćemo dakle reći? Da pogani koji nisu tražili pravednosti stekoše pravednost, pravednost po vjeri."},{"v":31,"t":"Izrael pak koji je tražio neki zakon pravednosti, nije do zakona dopro."},{"v":32,"t":"Zašto? Jer nije tražio po vjeri, nego kao po djelima. Spotakoše se o kamen spoticanja,"},{"v":33,"t":"kao što je pisano: Evo postavljam na Sionu kamen spoticanja i stijenu posrtanja. Ali tko u nj vjeruje, neće se postidjeti."}]},"10":{"hr":[{"v":1,"t":"Braćo! Želja je srca moga i molitva Bogu za njih: da se spase."},{"v":2,"t":"Svjedočim doista za njih: imaju revnosti Božje, ali ne u pravom razumijevanju."},{"v":3,"t":"Ne priznajući, doista, Božje pravednosti i tražeći uspostaviti svoju, pravednosti se Božjoj ne podložiše."},{"v":4,"t":"Jer dovršetak je Zakona Krist - na opravdanje svakomu tko vjeruje."},{"v":5,"t":"Da, Mojsije piše o onoj pravednosti iz Zakona: Tko je vrši, naći će život u njoj."},{"v":6,"t":"A pravednost iz vjere ovako veli: Nemoj reći u srcu svom: Tko će se popeti na nebo - to jest Krista svesti?"},{"v":7,"t":"Ili: Tko će sići u bezdan - to jest izvesti Krista od mrtvih?"},{"v":8,"t":"Nego što veli? Blizu ti je Riječ, u ustima tvojim i u srcu tvome - to jest Riječ vjere koju propovijedamo."},{"v":9,"t":"Jer ako ustima ispovijedaš da je Isus Gospodin, i srcem vjeruješ da ga je Bog uskrisio od mrtvih, bit ćeš spašen."},{"v":10,"t":"Doista, srcem vjerovati opravdava, a ustima ispovijedati spasava."},{"v":11,"t":"Jer veli Pismo: Tko god u nj vjeruje, neće se postidjeti."},{"v":12,"t":"Nema uistinu razlike između Židova i Grka jer jedan je Gospodin sviju, bogat prema svima koji ga prizivlju."},{"v":13,"t":"Jer: Tko god prizove ime Gospodnje, bit će spašen."},{"v":14,"t":"Ali kako da prizovu onoga u koga ne povjerovaše? A kako da povjeruju u onoga koga nisu čuli? Kako pak da čuju bez propovjednika?"},{"v":15,"t":"A kako propovijedati bez poslanja? Tako je pisano: Kako li su ljupke noge onih koji donose blagovijest dobra."},{"v":16,"t":"Ali nisu svi poslušali blagovijesti - evanđelja! Zaista, Izaija veli: Gospodine, tko povjerova našoj poruci?"},{"v":17,"t":"Dakle: vjera po poruci, a poruka riječju Kristovom."},{"v":18,"t":"Nego pitam: Zar nisu čuli? Dapače! Po svoj zemlji razliježe se jeka, riječi njihove sve do nakraj svijeta."},{"v":19,"t":"Onda pitam: Zar Izrael nije shvatio? Najprije Mojsije veli: Ja ću vas na ljubomor izazvati pukom ništavnim, razdražit ću vas glupim nekim narodom."},{"v":20,"t":"Izaija pak hrabro veli: Nađoše me koji me ne tražahu, objavih se onima koji me ne pitahu."},{"v":21,"t":"A Izraelu veli: Cio dan pružah ruku narodu nepokornom i buntovnom."}]},"11":{"hr":[{"v":1,"t":"Pitam dakle: Zar je Bog odbacio narod svoj? Nipošto? Ta i ja sam Izraelac, iz potomstva Abrahamova, plemena Benjaminova."},{"v":2,"t":"Nije Bog odbacio naroda svojega koga predvidje. Ili zar ne znate što veli Pismo, ono o Iliji - kako se tuži Bogu na Izraela:"},{"v":3,"t":"Gospode, proroke tvoje pobiše, žrtvenike tvoje porušiše; ja ostadoh sam i još mi o glavi rade."},{"v":4,"t":"Pa što mu veli Božji glas? Ostavih sebi sedam tisuća ljudi koji ne prignuše koljena pred Baalom."},{"v":5,"t":"Tako dakle i u sadašnje vrijeme postoji Ostatak po milosnom izboru."},{"v":6,"t":"Ako pak po milosti, nije po djelima; inače milost nije više milost!"},{"v":7,"t":"Što dakle? Što Izrael ište, to nije postigao, ali izabrani postigoše. Ostali pak otvrdnuše,"},{"v":8,"t":"kao što je pisano: Dade im Bog duh obamrlosti, oči da ne vide, uši da ne čuju sve do dana današnjega."},{"v":9,"t":"I David veli: Nek im stol pred njima bude zamkom, i mrežom, i stupicom, i plaćom."},{"v":10,"t":"Nek im potamne oči da ne vide i leđa im zauvijek pogni!"},{"v":11,"t":"Pitam dakle: jesu li posrnuli da propadnu? Nipošto! Naprotiv: po njihovu posrtaju spasenje poganima da se tako oni, Židovi, izazovu na ljubomor."},{"v":12,"t":"Pa ako je njihov posrtaj bogatstvo za svijet, i njihovo smanjenje bogatstvo za pogane, koliko li će više to biti njihov puni broj?"},{"v":13,"t":"Vama pak, poganima, velim: ja kao apostol pogana službu svoju proslavljam"},{"v":14,"t":"ne bih li na ljubomor izazvao njih, tijelo svoje, i spasio neke od njih."},{"v":15,"t":"Jer ako je njihovo odbačenje izmirenje svijeta, što li će biti njihovo prihvaćanje ako ne oživljenje od mrtvih?"},{"v":16,"t":"Ako li su prvine svete, sveto je i tijesto; ako li je korijen svet, svete su i grane."},{"v":17,"t":"Pa ako su neke grane odlomljene, a ti, divlja maslina, pricijepljen umjesto njih, postao suzajedničar korijena, sočnosti masline,"},{"v":18,"t":"ne uznosi se nad grane. Ako li se hoćeš uznositi - ne nosiš ti korijena, nego korijen tebe."},{"v":19,"t":"Reći ćeš na to: grane su odlomljene da se ja pricijepim."},{"v":20,"t":"Dobro! Oni su zbog nevjere odlomljeni, a ti po vjeri stojiš. Ne uznosi se, nego strahuj!"},{"v":21,"t":"Jer ako Bog ne poštedje prirodnih grana, ni tebe neće poštedjeti."},{"v":22,"t":"Promotri dakle dobrotu i strogost Božju: strogost na palima, a dobrotu Božju na sebi ako ostaneš u toj dobroti, inače ćeš i ti biti odsječen."},{"v":23,"t":"A i oni, ako ne ostanu u nevjeri, bit će pricijepljeni; ta moćan je Bog da ih opet pricijepi."},{"v":24,"t":"Doista, ako si ti, po naravi divlja maslina, odsječen pa mimo narav pricijepljen na pitomu maslinu, koliko li će lakše oni po naravi biti pricijepljeni na vlastitu maslinu!"},{"v":25,"t":"Jer ne bih htio, braćo, da budete sami po sebi pametni, a da ne znate ovo otajstvo: djelomično je otvrdnuće zadesilo Izraela dok punina pogana ne uđe."},{"v":26,"t":"I tako će se cio Izrael spasiti, kako je pisano: Doći će sa Siona Otkupitelj, odvratit će bezbožnost od Jakova."},{"v":27,"t":"I to će biti moj Savez s njima, kad uklonim grijehe njihove."},{"v":28,"t":"U pogledu evanđelja oni su, istina, protivnici poradi vas, ali u pogledu izabranja oni su ljubimci poradi otaca."},{"v":29,"t":"Ta neopozivi su dari i poziv Božji!"},{"v":30,"t":"Doista, kao što vi nekoć bijaste neposlušni Bogu, a sada po njihovoj neposlušnosti zadobiste milosrđe"},{"v":31,"t":"tako i oni sada po milosrđu vama iskazanu postadoše neposlušni da i oni sada zadobiju milosrđe."},{"v":32,"t":"Jer Bog je sve zatvorio u neposlušnost da se svima smiluje."},{"v":33,"t":"O dubino bogatstva, i mudrosti, i spoznanja Božjega! Kako li su nedokučivi sudovi i neistraživi putovi njegovi!"},{"v":34,"t":"Doista, tko spozna misao Gospodnju, tko li mu bi savjetnikom?"},{"v":35,"t":"Ili: tko ga darom preteče da bi mu se uzvratiti moralo?"},{"v":36,"t":"Jer sve je od njega i po njemu i za njega! Njemu slava u vjekove! Amen."}]},"12":{"hr":[{"v":1,"t":"Zaklinjem vas, braćo, milosrđem Božjim: prikažite svoja tijela za žrtvu živu, svetu, Bogu milu - kao svoje duhovno bogoslužje."},{"v":2,"t":"Ne suobličujte se ovomu svijetu, nego se preobrazujte obnavljanjem svoje pameti da mognete razabirati što je volja Božja, što li je dobro, Bogu milo, savršeno."},{"v":3,"t":"Da, po milosti koja mi je dana svakomu između vas velim: ne precjenjujte se više no što se treba cijeniti, nego cijenite se razumno, kako je već komu Bog odmjerio mjeru vjere."},{"v":4,"t":"Jer kao što u jednom tijelu imamo mnogo udova, a nemaju svi isto djelovanje,"},{"v":5,"t":"tako smo i mi, mnogi, jedno tijelo u Kristu, a pojedinci udovi jedan drugomu."},{"v":6,"t":"Dare pak imamo različite po milosti koja nam je dana: je li to prorokovanje - neka je primjereno vjeri;"},{"v":7,"t":"je li služenje - neka je u služenju; je li poučavanje - u poučavanju;"},{"v":8,"t":"je li hrabrenje - u hrabrenju; tko dijeli, neka je darežljiv; tko je predstojnik - revan; tko iskazuje milosrđe - radostan!"},{"v":9,"t":"Ljubav nehinjena! Zazirite oda zla, prianjajte uz dobro!"},{"v":10,"t":"Srdačno se ljubite pravim bratoljubljem! Pretječite jedni druge poštovanjem!"},{"v":11,"t":"U revnosti budite hitri, u duhu gorljivi, Gospodinu služite!"},{"v":12,"t":"U nadi budite radosni, u nevolji strpljivi, u molitvi postojani!"},{"v":13,"t":"Pritječite u pomoć svetima u nuždi, gajite gostoljubivost!"},{"v":14,"t":"Blagoslivljajte svoje progonitelje, blagoslivljajte, a ne proklinjite!"},{"v":15,"t":"Radujte se s radosnima, plačite sa zaplakanima!"},{"v":16,"t":"Budite istomišljenici među sobom! Neka vas ne zanosi što je visoko, nego privlači što je ponizno. Ne umišljajte si da ste mudri!"},{"v":17,"t":"Nikome zlo za zlo ne vraćajte; zauzimajte se za dobro pred svim ljudima!"},{"v":18,"t":"Ako je moguće, koliko je do vas, u miru budite sa svim ljudima!"},{"v":19,"t":"Ne osvećujte se, ljubljeni, nego dajte mjesta Božjem gnjevu. Ta pisano je: Moja je odmazda, ja ću je vratiti, veli Gospodin."},{"v":20,"t":"Naprotiv: Ako je gladan neprijatelj tvoj, nahrani ga, i ako je žedan, napoj ga! Činiš li tako, ugljevlje mu ražareno zgrćeš na glavu."},{"v":21,"t":"Ne daj se pobijediti zlom, nego dobrim svladavaj zlo."}]},"13":{"hr":[{"v":1,"t":"Svaka duša neka se podlaže vlastima nad sobom. Jer nema vlasti doli od Boga: koje postoje, od Boga su postavljene."},{"v":2,"t":"Stoga tko se suprotstavlja vlasti, Božjoj se odredbi protivi; koji se pak protive, sami će na se navući osudu."},{"v":3,"t":"Vladari doista nisu strah i trepet zbog dobra, nego zbog zla djela. Hoćeš li se ne bojati vlasti? Dobro čini pa ćeš imati pohvalu od nje!"},{"v":4,"t":"Ta Božji je ona poslužitelj - tebi na dobro. Ako li zlo činiš, strahuj! Ne nosi uzalud mača! Božji je ona poslužitelj: gnjev njegov iskaljuje na onome koji zlo čini."},{"v":5,"t":"Treba se stoga podlagati, ne samo zbog gnjeva nego i zbog savjesti."},{"v":6,"t":"Zato i poreze plaćate: ta službenici su Božji oni koji se time bave."},{"v":7,"t":"Dajte svakomu što mu pripada: komu porez - porez, komu carina - carina, komu poštovanje - poštovanje, komu čast - čast."},{"v":8,"t":"Nikomu ništa ne dugujte, osim da jedni druge ljubite. Jer tko drugoga ljubi, ispunio je Zakon."},{"v":9,"t":"Uistinu: Ne čini preljuba! Ne ubij! Ne ukradi! Ne poželi! i ima li koja druga zapovijed, sažeta je u ovoj riječi: Ljubi svoga bližnjega kao sebe samoga."},{"v":10,"t":"Ljubav bližnjemu zla ne čini. Punina dakle Zakona jest ljubav."},{"v":11,"t":"To tim više što shvaćate ovaj čas: vrijeme je već da se oda sna prenemo jer nam je sada spasenje bliže nego kad povjerovasmo."},{"v":12,"t":"Noć poodmače, dan se približi! Odložimo dakle djela tame i zaodjenimo se oružjem svjetlosti."},{"v":13,"t":"Kao po danu pristojno hodimo, ne u pijankama i pijančevanjima, ne u priležništvima i razvratnostima, ne u svađi i ljubomoru,"},{"v":14,"t":"nego zaodjenite se Gospodinom Isusom Kristom i, u brizi za tijelo, ne pogodujte požudama."}]},"14":{"hr":[{"v":1,"t":"Slaboga u vjeri prigrlite, ali ne da se prepirete o mišljenjima."},{"v":2,"t":"Netko vjeruje da smije sve jesti, slabi opet jede samo povrće."},{"v":3,"t":"Tko jede, neka ne prezire onoga tko ne jede; tko pak ne jede, neka ne sudi onoga tko jede. Ta Bog ga je prigrlio."},{"v":4,"t":"Tko si ti da sudiš tuđega slugu? Svojemu Gospodaru i stoji i pada! A stajat će jer moćan je Gospodin da ga podrži."},{"v":5,"t":"Netko razlikuje dan od dana, nekomu je opet svaki dan jednak. Samo nek je svatko posve uvjeren u svoje mišljenje."},{"v":6,"t":"Tko na dan misli, poradi Gospodina misli; i tko jede, poradi Gospodina jede: zahvaljuje Bogu. I tko ne jede, poradi Gospodina ne jede i - zahvaljuje Bogu."},{"v":7,"t":"Jer nitko od nas sebi ne živi, nitko sebi ne umire."},{"v":8,"t":"Doista, ako živimo, Gospodinu živimo, i ako umiremo, Gospodinu umiremo. Živimo li dakle ili umiremo - Gospodinovi smo."},{"v":9,"t":"Ta Krist zato umrije i oživje da gospodar bude i mrtvima i živima."},{"v":10,"t":"A ti, što sudiš brata svoga? Ili ti, što prezireš brata svoga? Ta svi ćemo stati pred sudište Božje."},{"v":11,"t":"Jer pisano je: Života mi moga, govori Gospodin, prignut će se preda mnom svako koljeno i svaki će jezik priznati Boga."},{"v":12,"t":"Svaki će dakle od nas za sebe Bogu dati račun."},{"v":13,"t":"Dakle, ne sudimo više jedan drugoga, nego radije sudite o tome da ne valja postavljati bratu stupice ili spoticala."},{"v":14,"t":"Znam i uvjeren sam u Gospodinu: ništa samo od sebe nije nečisto. Samo je onomu nečisto tko to smatra nečistim."},{"v":15,"t":"Doista, ako je poradi hrane tvoj brat ražalošćen, već nisi na putu ljubavi. Ne upropašćuj tom svojom hranom onoga za koga je Krist umro!"},{"v":16,"t":"Nemojte da se pogrđuje vaše dobro!"},{"v":17,"t":"Ta kraljevstvo Božje nije jelo ili piće, nego pravednost, mir i radost u Duhu Svetome."},{"v":18,"t":"Da, tko tako Kristu služi, mio je Bogu i cijene ga ljudi."},{"v":19,"t":"Nastojmo stoga promicati mir i uzajamno izgrađivanje!"},{"v":20,"t":"Ne razaraj djela Božjega poradi hrane! Sve je, istina, čisto, ali je zlo za onoga tko na sablazan jede."},{"v":21,"t":"Dobro je ne jesti mesa i ne piti vina i ne uzimati ništa o što se tvoj brat spotiče."},{"v":22,"t":"Ti imaš uvjerenje. Za sebe ga imaj pred Bogom. Blago onomu tko samoga sebe ne osuđuje u onom na što se odlučuje!"},{"v":23,"t":"Jede li tko dvoumeći, osudio se jer ne radi iz uvjerenja. A sve što nije iz uvjerenja, grijeh je."}]},"15":{"hr":[{"v":1,"t":"Mi jaki treba da nosimo slabosti slabih, a ne da sebi ugađamo."},{"v":2,"t":"Svaki od nas neka ugađa bližnjemu na dobro, na izgrađivanje."},{"v":3,"t":"Ta ni Krist nije sebi ugađao, nego kao što je pisano: Poruge onih koji se rugaju tebi padoše na me."},{"v":4,"t":"Uistinu, što je nekoć napisano, nama je za pouku napisano da po postojanosti i utjesi Pisama imamo nadu."},{"v":5,"t":"A Bog postojanosti i utjehe dao vam da međusobno budete složni po Kristu Isusu"},{"v":6,"t":"te jednodušno, iz jednoga grla, slavite Boga i Oca Gospodina našega Isusa Krista."},{"v":7,"t":"Prigrljujte jedni druge kao što je Krist prigrlio vas na slavu Božju."},{"v":8,"t":"Krist je, velim, postao poslužitelj obrezanika za istinu Božju da ispuni obećanja dana ocima,"},{"v":9,"t":"a pogani da za milosrđe proslave Boga, kao što je pisano: Zato ću te slaviti među pucima i psalam pjevati tvome imenu."},{"v":10,"t":"I još veli: Kličite, puci, s njegovim narodom."},{"v":11,"t":"I još: Hvalite, svi puci, Gospodina, slavili ga svi narodi!"},{"v":12,"t":"Izaija opet veli: Pojavit će se Jišajev izdanak, dignut da vlada narodima, u njemu je nada narodima."},{"v":13,"t":"A Bog nade napunio vas svakom radošću i mirom u vjeri da izobilujete u nadi snagom Duha Svetoga."},{"v":14,"t":"Ja sam, braćo moja, uvjeren: vi ste i sami puni čestitosti, ispunjeni svakim znanjem, sposobni jedni druge urazumljivati."},{"v":15,"t":"Ipak vam djelomično smionije napisah da vas na poznato nekako podsjetim poradi milosti koja mi je dana od Boga -"},{"v":16,"t":"da budem bogoslužnik Krista Isusa među poganima, svećenik evanđelja Božjega te prinos pogana postane ugodan, posvećen Duhom Svetim."},{"v":17,"t":"Imam se dakle čime dičiti u Kristu Isusu s obzirom na ono što je Božje."},{"v":18,"t":"/"},{"v":19,"t":"Jer ne bih se usudio govoriti o nečemu što Krist riječju i djelom, snagom znamenja i čudesa, snagom Duha nije po meni učinio da k poslušnosti privede pogane. Tako sam od Jeruzalema pa uokolo sve do Ilirika pronio evanđelje Kristovo,"},{"v":20,"t":"i to tako da sam se trsio navješćivati evanđelje ne gdje se već spominjao Krist - da ne bih gradio na temeljima drugih -"},{"v":21,"t":"nego, kako je pisano: Vidjet će ga oni kojima nije naviješten, shvatiti oni koji za nj nisu čuli."},{"v":22,"t":"Time sam ponajčešće i bio spriječen doći k vama."},{"v":23,"t":"Sad mi pak više nema mjesta u ovim krajevima, a živa mi je želja, ima već mnogo godina, doći k vama"},{"v":24,"t":"kad pođem u Španjolsku. Nadam se doista da ću vas na proputovanju posjetiti i da ćete me onamo otpraviti pošto mi se najprije bar donekle ispuni želja biti s vama."},{"v":25,"t":"Ali sad idem u Jeruzalem da poslužim svetima."},{"v":26,"t":"Makedonija i Ahaja odlučiše očitovati neko zajedništvo prema siromašnim svetima u Jeruzalemu."},{"v":27,"t":"Da, odlučiše, a i dužnici su im. Jer ako su pogani postali sudionicima njihovih duhovnih dobara, dužni su im u tjelesnima poslužiti."},{"v":28,"t":"Pošto dakle to obavim - ovaj im plod zapečaćen uručim - uputit ću se u Španjolsku i usput k vama."},{"v":29,"t":"A kada dođem k vama, doći ću, znam, s puninom blagoslova Kristova."},{"v":30,"t":"Ali zaklinjem vas, braćo, Gospodinom Isusom Kristom i ljubavlju Duha: suborci mi budite u molitvama Bogu upravljenima za me,"},{"v":31,"t":"da umaknem onim nevjernima u Judeji i da moja pomoć Jeruzalemu bude po volji svetima"},{"v":32,"t":"te s Božjom voljom radosno dođem k vama i s vama zajedno odahnem."},{"v":33,"t":"Bog mira sa svima vama! Amen."}]},"16":{"hr":[{"v":1,"t":"Preporučujem vam Febu, sestru našu, poslužiteljicu Crkve u Kenhreji:"},{"v":2,"t":"primite je u Gospodinu kako dolikuje svetima i priskočite joj u pomoć u svemu što od vas ustreba jer je i ona bila zaštitnicom mnogima i meni samomu."},{"v":3,"t":"Pozdravite Prisku i Akvilu, suradnike moje u Kristu Isusu."},{"v":4,"t":"Oni su za moj život podmetnuli svoj vrat; zahvaljujem im ne samo ja nego i sve Crkve pogana."},{"v":5,"t":"Pozdravite i Crkvu u njihovoj kući. Pozdravite ljubljenog mi Epeneta koji je prvina Azije za Krista."},{"v":6,"t":"Pozdravite Mariju koja se mnogo trudila za vas."},{"v":7,"t":"Pozdravite Andronika i Juniju, rođake i suuznike moje; oni su ugledni među apostolima i prije mene bili su u Kristu."},{"v":8,"t":"Pozdravite Amplijata, ljubljenoga moga u Gospodinu."},{"v":9,"t":"Pozdravite Urbana, suradnika moga u Kristu, i ljubljenog mi Staha."},{"v":10,"t":"Pozdravite Apela, prokušanoga u Kristu. Pozdravite Aristobulove."},{"v":11,"t":"Pozdravite Herodiona, rođaka moga. Pozdravite Narcisove koji su u Gospodinu."},{"v":12,"t":"Pozdravite Trifenu i Trifozu koje se trude u Gospodinu. Pozdravite ljubljenu Persidu koja se mnogo trudila u Gospodinu."},{"v":13,"t":"Pozdravite Rufa, izabranika u Gospodinu, i majku njegovu i moju."},{"v":14,"t":"Pozdravite Asinkrita, Flegonta, Herma, Patrobu, Hermu i braću koja su s njima."},{"v":15,"t":"Pozdravite Filologa i Juliju, Nereja i njegovu sestru, i Olimpu, i sve svete koji su s njima."},{"v":16,"t":"Pozdravite jedni druge cjelovom svetim. Pozdravljaju vas sve Crkve Kristove."},{"v":17,"t":"Zaklinjem vas, braćo, čuvajte se onih koji siju razdore i sablazni mimo nauk u kojem ste poučeni, i klonite ih se."},{"v":18,"t":"Jer takvi ne služe Gospodinu našemu Kristu, nego svom trbuhu te lijepim i laskavim riječima zavode srca nedužnih."},{"v":19,"t":"Doista, vaša je poslušnost doprla do sviju. Zbog vas se dakle radujem i htio bih da budete mudri za dobro, a bezazleni za zlo."},{"v":20,"t":"Bog mira satrt će ubrzo Sotonu pod vašim nogama. Milost Gospodina Isusa s vama!"},{"v":21,"t":"Pozdravlja vas Timotej, suradnik moj, i Lucije, Jason i Sosipater, rođaci moji."},{"v":22,"t":"Pozdravljam vas u Gospodinu ja, Tercije, koji napisah ovu poslanicu."},{"v":23,"t":"Pozdravlja vas Gaj, gostoprimac moj i cijele Crkve. Pozdravlja vas Erast, gradski blagajnik, i brat Kvart."},{"v":24,"t":"#"},{"v":25,"t":"Onomu koji vas može učvrstiti - po mojem evanđelju i propovijedanju Isusa Krista, po objavljenju Otajstva prešućenog drevnim vremenima,"},{"v":26,"t":"a sada očitovanog i po proročkim pismima odredbom vječnoga Boga svim narodima obznanjenog za poslušnost, vjeru -"},{"v":27,"t":"jedinomu Mudromu, Bogu, po Isusu Kristu: Njemu slava u vijeke! Amen."}]}},"1CO":{"1":{"hr":[{"v":1,"t":"Pavao, po Božjoj volji pozvan za apostola Krista Isusa, i brat Sosten"},{"v":2,"t":"Crkvi Božjoj u Korintu - posvećenima u Kristu Isusu, pozvanicima, svetima, sa svima što na bilo kojemu mjestu prizivlju ime Isusa Krista, Gospodina našega, njihova i našega."},{"v":3,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista!"},{"v":4,"t":"Zahvaljujem Bogu svojemu svagda za vas zbog milosti Božje koja vam je dana u Kristu Isusu:"},{"v":5,"t":"u njemu se obogatiste u svemu - u svakoj riječi i svakom spoznanju."},{"v":6,"t":"Kako li se svjedočanstvo o Kristu utvrdilo u vama"},{"v":7,"t":"te ne oskudijevate ni na jednom daru čekajući Objavljenje Gospodina našega Isusa Krista!"},{"v":8,"t":"On će vas učiniti i postojanima do kraja, besprigovornima u Dan Gospodina našega Isusa Krista."},{"v":9,"t":"Vjeran je Bog koji vas pozva u zajedništvo Sina svojega Isusa Krista, Gospodina našega."},{"v":10,"t":"Zaklinjem vas, braćo, imenom Gospodina našega Isusa Krista: svi budite iste misli; neka ne bude među vama razdora, nego budite savršeno istog osjećanja i istog mišljenja."},{"v":11,"t":"Jer Klojini mi, braćo moja, o vama rekoše da među vama ima svađa."},{"v":12,"t":"Mislim to što svaki od vas govori: “Ja sam Pavlov”, “A ja Apolonov”, “A ja Kefin”, “A ja Kristov”."},{"v":13,"t":"Zar je Krist razdijeljen? Zar je Pavao raspet za vas? Ili ste u Pavlovo ime kršteni?"},{"v":14,"t":"Hvala Bogu što ne krstih nikoga od vas, osim Krispa i Gaja;"},{"v":15,"t":"da ne bi tko rekao da ste u moje ime kršteni."},{"v":16,"t":"A da, krstih i Stefanin dom. Inače ne znam krstih li koga drugoga."},{"v":17,"t":"Jer ne posla me Krist krstiti, nego navješćivati evanđelje, i to ne mudrošću besjede, da se ne obeskrijepi križ Kristov."},{"v":18,"t":"Uistinu, besjeda o križu ludost je onima koji propadaju, a nama spašenicima sila je Božja."},{"v":19,"t":"Ta pisano je: Upropastit ću mudrost mudrih, i odbacit ću umnost umnih."},{"v":20,"t":"Gdje je mudrac? Gdje je književnik? Gdje je istraživač ovoga svijeta? Zar ne izludi Bog mudrost svijeta?"},{"v":21,"t":"Doista, kad svijet u mudrosti Božjoj Boga ne upozna mudrošću, svidjelo se Bogu ludošću propovijedanja spasiti vjernike."},{"v":22,"t":"Jer i Židovi znake ištu i Grci mudrost traže,"},{"v":23,"t":"a mi propovijedamo Krista raspetoga: Židovima sablazan, poganima ludost,"},{"v":24,"t":"pozvanima pak - i Židovima i Grcima - Krista, Božju snagu i Božju mudrost."},{"v":25,"t":"Jer ludo Božje mudrije je od ljudi i slabo Božje jače je od ljudi."},{"v":26,"t":"Ta gledajte, braćo, sebe, pozvane: nema mnogo mudrih po tijelu, nema mnogo snažnih, nema mnogo plemenitih."},{"v":27,"t":"Nego lude svijeta izabra Bog da posrami mudre, i slabe svijeta izabra Bog da posrami jake;"},{"v":28,"t":"i neplemenite svijeta i prezrene izabra Bog, i ono što nije, da uništi ono što jest,"},{"v":29,"t":"da se nijedan smrtnik ne bi hvalio pred Bogom."},{"v":30,"t":"Od njega je da vi jeste u Kristu Isusu, koji nama posta mudrost od Boga, i pravednost, i posvećenje, i otkupljenje,"},{"v":31,"t":"da bude kako je pisano: Tko se hvali, u Gospodu neka se hvali."}]},"2":{"hr":[{"v":1,"t":"I ja kada dođoh k vama, braćo, ne dođoh s uzvišenom besjedom ili mudrošću navješćivati vam svjedočanstvo Božje"},{"v":2,"t":"jer ne htjedoh među vama znati što drugo osim Isusa Krista, i to raspetoga."},{"v":3,"t":"I ja priđoh k vama slab, u strahu i u veliku drhtanju."},{"v":4,"t":"I besjeda moja i propovijedanje moje ne bijaše u uvjerljivim riječima mudrosti, nego u pokazivanju Duha i snage"},{"v":5,"t":"da se vjera vaša ne temelji na mudrosti ljudskoj nego na snazi Božjoj."},{"v":6,"t":"Mudrost doduše navješćujemo među zrelima, ali ne mudrost ovoga svijeta, ni knezova ovoga svijeta koji propadaju,"},{"v":7,"t":"nego navješćujemo Mudrost Božju, u Otajstvu, sakrivenu; onu koju predodredi Bog prije vjekova za slavu našu,"},{"v":8,"t":"a koje nijedan od knezova ovoga svijeta nije upoznao. Jer da su je upoznali, ne bi Gospodina slave razapeli."},{"v":9,"t":"Nego, kako je pisano: Što oko ne vidje, i uho ne ču, i u srce čovječje ne uđe, to pripravi Bog onima koji ga ljube."},{"v":10,"t":"A nama to Bog objavi po Duhu jer Duh sve proniče, i dubine Božje."},{"v":11,"t":"Jer tko od ljudi zna što je u čovjeku osim duha čovječjega u njemu? Tako i što je u Bogu, nitko ne zna osim Duha Božjega."},{"v":12,"t":"A mi, mi ne primismo duha svijeta, nego Duha koji je od Boga da znamo čime nas je obdario Bog."},{"v":13,"t":"To i navješćujemo, ne naučenim riječima čovječje mudrosti, nego naukom Duha izlažući duhovno duhovnima."},{"v":14,"t":"Naravan čovjek ne prima što je od Duha Božjega; njemu je to ludost i ne može spoznati jer po Duhu valja prosuđivati."},{"v":15,"t":"Duhovan pak prosuđuje sve, a njega nitko ne prosuđuje."},{"v":16,"t":"Jer tko spozna misao Gospodnju, tko da ga pouči? A mi imamo misao Kristovu."}]},"3":{"hr":[{"v":1,"t":"I ja, braćo, nisam mogao govoriti vama kao duhovnima, nego kao tjelesnima, kao nejačadi u Kristu."},{"v":2,"t":"Mlijekom vas napojih, ne jelom: još ne mogoste, a ni sada još ne možete"},{"v":3,"t":"jer još ste tjelesni. Doista, dok je među vama zavist i prepiranje, zar niste tjelesni, zar po ljudsku ne postupate?"},{"v":4,"t":"Jer kad jedan govori: “Ja sam Pavlov”, a drugi: “Ja Apolonov”, niste li odveć ljudi?"},{"v":5,"t":"Ta što je Apolon? Što je Pavao? Poslužitelji po kojima povjerovaste - kako već komu Gospodin dade."},{"v":6,"t":"Ja zasadih, Apolon zali, ali Bog dade rasti."},{"v":7,"t":"Tako niti je što onaj tko sadi ni onaj tko zalijeva, nego Bog koji daje rasti."},{"v":8,"t":"Tko sadi i tko zalijeva, jedno su; a svaki će po svome trudu primiti plaću."},{"v":9,"t":"Jer Božji smo suradnici: Božja ste njiva, Božja građevina."},{"v":10,"t":"Po milosti Božjoj koja mi je dana ja kao mudri graditelj postavih temelj, a drugi naziđuje; ali svaki neka pazi kako naziđuje."},{"v":11,"t":"Jer nitko ne može postaviti drugoga temelja osim onoga koji je postavljen, a taj je Isus Krist."},{"v":12,"t":"Naziđuje li tko na ovom temelju zlatom, srebrom, dragim kamenjem, drvom, sijenom, slamom -"},{"v":13,"t":"svačije će djelo izići na svjetlo. Onaj će Dan pokazati jer će se u ognju očitovati. I kakvo je čije djelo, oganj će iskušati."},{"v":14,"t":"Ostane li djelo, primit će plaću onaj tko ga je nazidao."},{"v":15,"t":"Izgori li čije djelo, taj će štetovati; ipak, on će se sam spasiti, ali kao kroz oganj."},{"v":16,"t":"Ne znate li? Hram ste Božji i Duh Božji prebiva u vama."},{"v":17,"t":"Ako tko upropašćuje hram Božji, upropastit će njega Bog. Jer hram je Božji svet, a to ste vi."},{"v":18,"t":"Nitko neka se ne vara. Ako tko misli da je mudar među vama na ovome svijetu, neka bude lud da bude mudar."},{"v":19,"t":"Jer mudrost ovoga svijeta ludost je pred Bogom. Ta pisano je: On hvata mudre u njihovu lukavstvu."},{"v":20,"t":"I opet: Gospodin poznaje namisli mudrih, one su isprazne."},{"v":21,"t":"Zato neka se nitko ne hvasta ljudima jer sve je vaše."},{"v":22,"t":"Bio Pavao, ili Apolon, ili Kefa, bio svijet, ili život, ili smrt, ili sadašnje, ili buduće: sve je vaše,"},{"v":23,"t":"vi Kristovi, a Krist Božji."}]},"4":{"hr":[{"v":1,"t":"Tako, neka nas svatko smatra službenicima Kristovim i upraviteljima otajstava Božjih."},{"v":2,"t":"A od upravitelja iziskuje se napokon da budu vjerni."},{"v":3,"t":"Meni pak nije nimalo do toga da me sudite vi ili bilo koji ljudski sud; a ni ja sam sebe ne sudim."},{"v":4,"t":"Doista, ničega sebi nisam svjestan, no time nisam opravdan: moj je sudac Gospodin."},{"v":5,"t":"Zato ne sudite ništa prije vremena dok ne dođe Gospodin koji će iznijeti na vidjelo što je sakriveno u tami i razotkriti nakane srdaca. I tada će svatko primiti pohvalu od Boga."},{"v":6,"t":"Time, braćo, smjerah na sebe i Apolona radi vas: da na nama naučite onu “Ne preko onoga što je pisano” te se ne nadimate jednim protiv drugoga."},{"v":7,"t":"Ta tko tebi daje prednost? Što imaš da nisi primio? Ako si primio, što se hvastaš kao da nisi primio?"},{"v":8,"t":"Već ste siti, već se obogatiste, bez nas se zakraljiste! Kamo sreće da se zakraljiste da i mi s vama zajedno kraljujemo!"},{"v":9,"t":"Jer Bog je, čini mi se, nas apostole prikazao posljednje, kao na smrt osuđene, jer postali smo prizor svijetu, i anđelima, i ljudima -"},{"v":10,"t":"mi ludi poradi Krista, vi mudri u Kristu; mi slabi, vi jaki; vi čašćeni, mi prezreni;"},{"v":11,"t":"sve do ovoga časa i gladujemo, i žeđamo, i goli smo, i pljuskaju nas, i beskućnici smo,"},{"v":12,"t":"i patimo se radeći svojim rukama. Proklinjani blagoslivljamo, proganjani ustrajavamo,"},{"v":13,"t":"pogrđivani tješimo. Kao smeće svijeta postasmo, svačiji izmet sve do sada."},{"v":14,"t":"Ne pišem ovoga da vas postidim, nego da vas kao ljubljenu svoju djecu urazumim."},{"v":15,"t":"Jer da imate u Kristu i deset tisuća učitelja, ipak ne biste imali više otaca. Ta u Kristu Isusu po evanđelju ja vas rodih!"},{"v":16,"t":"Zaklinjem vas, dakle: nasljedovatelji moji budite."},{"v":17,"t":"Zato upravo poslah k vama Timoteja, koji mi je dijete ljubljeno i vjerno u Gospodinu, da vas podsjeti na naputke moje, u Kristu, kako posvuda u svakoj crkvi učim."},{"v":18,"t":"Neki se uzniješe kao da ja neću doći k vama."},{"v":19,"t":"Ipak, eto me ubrzo k vama, ako Gospodin htjedne, i rasudit ću ne riječi onih nadutih, nego krepost."},{"v":20,"t":"Ta nije u riječi kraljevstvo Božje, nego u kreposti."},{"v":21,"t":"Što želite? Da k vama dođem sa šibom ili s ljubavlju i duhom blagosti?"}]},"5":{"hr":[{"v":1,"t":"Općenito se čuje o bludnosti među vama, i to takvoj bludnosti kakve nema ni među poganima: da netko ima očevu ženu."},{"v":2,"t":"I vi mi se uznijeli, mjesto da žalujete pa da se iskorijeni iz vaše sredine onaj koji takvo djelo počini."},{"v":3,"t":"A ja, i nenazočan tijelom, ali nazočan duhom, već sam presudio kao nazočan onoga koji je takvo što počinio."},{"v":4,"t":"Pošto se u ime Gospodina našega Isusa Krista okupite vi i moj duh, snagom Gospodina našega Isusa,"},{"v":5,"t":"neka se takav preda Sotoni na propast tijela da bi se spasio duh u Dan Gospodina Isusa."},{"v":6,"t":"Ne valja vam hvastanje! Zar ne znate da malo kvasca sve tijesto ukvasa?"},{"v":7,"t":"Očistite stari kvasac da budete novo tijesto, kao što i jeste beskvasni jer već je žrtvovana Pasha naša, Krist."},{"v":8,"t":"Zato svetkujmo, ne sa starim kvascem ni s kvascem zloće i pakosti, nego s beskvasnim kruhovima čistoće i istine."},{"v":9,"t":"Napisah vam u poslanici da se ne miješate s bludnicima -"},{"v":10,"t":"ne općenito s bludnicima ovoga svijeta, ili lakomcima, ili razbojnicima, ili idolopoklonicima jer biste inače morali iz svijeta izići."},{"v":11,"t":"Napisah vam zapravo da se ne miješate s nazovibratom koji bi bio bludnik, ili lakomac, ili idolopoklonik, ili pogrđivač, ili pijanica, ili razbojnik. S takvim ni za stol!"},{"v":12,"t":"Što spada na me suditi one vani? Ne sudite li vi one koji su unutra?"},{"v":13,"t":"A one vani sudit će Bog. Iskorijenite opakoga iz svoje sredine."}]},"6":{"hr":[{"v":1,"t":"Tko bi se od vas u sporu s drugim usudio parničiti se pred nepravednima, a ne pred svetima?"},{"v":2,"t":"Ili zar ne znate da će sveti suditi svijet? Pa ako ćete vi suditi svijet, zar niste vrijedni suditi sitnice?"},{"v":3,"t":"Ne znate li da ćemo suditi anđele, kamo li ne ono svagdanje?"},{"v":4,"t":"A vi, kad imate sporove o svagdanjem, sucima postavljate one do kojih Crkva ništa ne drži!"},{"v":5,"t":"Vama na sramotu govorim. Tako? Zar nema među vama ni jednoga mudra koji bi mogao rasuditi među braćom?"},{"v":6,"t":"Nego brat se s bratom parniči, i to pred nevjernicima?"},{"v":7,"t":"Zapravo, već vam je to nedostatak što se parničite među sobom. Zašto radije ne trpite nepravdu? Zašto se radije ne pustite oplijeniti?"},{"v":8,"t":"Nego vi činite nepravdu i plijenite, i to braću."},{"v":9,"t":"Ili zar ne znate da nepravednici neće baštiniti kraljevstva Božjega? Ne varajte se! Ni bludnici, ni idolopoklonici, ni preljubnici, ni mekoputnici, ni muškoložnici,"},{"v":10,"t":"ni kradljivci, ni lakomci, ni pijanice, ni psovači, ni razbojnici neće baštiniti kraljevstva Božjega."},{"v":11,"t":"To evo, bijahu neki od vas, ali oprali ste se, ali posvetili ste se, ali opravdali ste se u imenu Gospodina našega Isusa Krista i u Duhu Boga našega."},{"v":12,"t":"“Sve mi je dopušteno!” Ali - sve ne koristi. “Sve mi je dopušteno!” Ali - neću da mnome išta vlada."},{"v":13,"t":"“Jela trbuhu, a trbuh jelima; Bog će i jedno i drugo uništiti.” Ali ne tijelo bludnosti, nego Gospodinu, i Gospodin tijelu!"},{"v":14,"t":"Ta Bog koji je Gospodina uskrisio i nas će uskrisiti snagom njegovom."},{"v":15,"t":"Ne znate li da su tijela vaša udovi Kristovi? Hoću li dakle uzeti udove Kristove i učiniti ih udovima bludničinim? Nipošto!"},{"v":16,"t":"Ili zar ne znate: tko uz bludnicu prione, jedno je tijelo? Jer veli se: Bit će njih dvoje jedno tijelo."},{"v":17,"t":"A tko prione uz Gospodina, jedan je duh."},{"v":18,"t":"Bježite od bludnosti! Svaki grijeh koji učini čovjek, izvan tijela je, a bludnik griješi protiv svojega tijela."},{"v":19,"t":"Ili zar ne znate? Tijelo vaše hram je Duha Svetoga koji je u vama, koga imate od Boga, te niste svoji."},{"v":20,"t":"Jer kupljeni ste otkupninom. Proslavite dakle Boga u tijelu svojem!"}]},"7":{"hr":[{"v":1,"t":"Sada o onome što ste mi pisali. Dobro je čovjeku ne dotaći ženu."},{"v":2,"t":"Ipak, zbog bludnosti, neka svaki ima svoju ženu i svaka neka ima svoga muža."},{"v":3,"t":"Muž neka vrši dužnost prema ženi, a tako i žena prema mužu."},{"v":4,"t":"Žena nije gospodar svoga tijela, nego muž, a tako ni muž nije gospodar svoga tijela, nego žena."},{"v":5,"t":"Ne uskraćujte se jedno drugome, osim po dogovoru, povremeno, da se posvetite molitvi pa se opet združite da vas Sotona ne bi napastovao zbog vaše neizdržljivosti."},{"v":6,"t":"Ali to velim kao dopuštenje, ne kao zapovijed."},{"v":7,"t":"A htio bih da svi ljudi budu kao i ja; ali svatko ima svoj dar od Boga, ovaj ovako, onaj onako."},{"v":8,"t":"Neoženjenima pak i udovicama velim: dobro im je ako ostanu kao i ja."},{"v":9,"t":"Ako li se ne mogu uzdržati, neka se žene, udaju. Jer bolje je ženiti se negoli izgarati."},{"v":10,"t":"A oženjenima zapovijedam, ne ja, nego Gospodin: žena neka se od muža ne rastavlja -"},{"v":11,"t":"ako se ipak rastavi, neka ostane neudana ili neka se s mužem pomiri - i muž neka ne otpušta žene."},{"v":12,"t":"Ostalima pak velim - ja, ne Gospodin: ima li koji brat ženu nevjernicu i ona privoli stanovati s njime, neka je ne otpušta."},{"v":13,"t":"I žena koja ima muža nevjernika te on privoli stanovati s njome, neka ne otpušta muža."},{"v":14,"t":"Ta muž nevjernik posvećen je ženom i žena nevjernica posvećena je bratom. Inače bi djeca vaša bila nečista, a ovako - sveta su."},{"v":15,"t":"Ako li se nevjernik hoće rastaviti, neka se rastavi; brat ili sestra u takvim prilikama nisu vezani: ta na mir nas je pozvao Bog."},{"v":16,"t":"Jer što znaš, ženo, hoćeš li spasiti muža? Ili što znaš, mužu, hoćeš li spasiti ženu?"},{"v":17,"t":"U drugome svatko neka živi kako mu je Gospodin dodijelio, kako ga je Bog pozvao. Tako određujem po svim crkvama."},{"v":18,"t":"Je li tko pozvan kao obrezan, neka ne prepravlja obrezanja. Ako je pozvan kao neobrezan, neka se ne obrezuje."},{"v":19,"t":"Obrezanje nije ništa i neobrezanje nije ništa, nego - držanje Božjih zapovijedi."},{"v":20,"t":"Svatko neka ostane u onom zvanju u koje je pozvan."},{"v":21,"t":"Jesi li pozvan kao rob? Ne brini! Nego, ako i možeš postati slobodan, radije se okoristi."},{"v":22,"t":"Jer tko je u Gospodinu pozvan kao rob, slobodnjak je Gospodnji. Tako i tko je pozvan kao slobodnjak, rob je Kristov."},{"v":23,"t":"Otkupninom ste kupljeni: ne budite robovi ljudima."},{"v":24,"t":"Svatko u čemu je pozvan, braćo, u tome neka i ostane pred Bogom."},{"v":25,"t":"O djevicama nemam zapovijedi, nego dajem savjet kao čovjek po milosrđu Gospodnjem vrijedan povjerenja."},{"v":26,"t":"Smatram dakle: dobro je to zbog sadašnje nevolje, dobro je čovjeku tako biti."},{"v":27,"t":"Jesi li vezan za ženu? Ne traži rastave. Jesi li slobodan od žene? Ne traži žene."},{"v":28,"t":"Ali ako se i oženiš, nisi sagriješio; i djevica ako se uda, nije sagriješila. Ali takvi će imati tjelesnu nevolju, a ja bih vas rado poštedio."},{"v":29,"t":"Ovo hoću reći, braćo: Vrijeme je kratko. Odsele i koji imaju žene, neka budu kao da ih nemaju;"},{"v":30,"t":"i koji plaču, kao da ne plaču; i koji se vesele, kao da se ne vesele; i koji kupuju, kao da ne posjeduju;"},{"v":31,"t":"i koji uživaju ovaj svijet, kao da ga ne uživaju, jer - prolazi obličje ovoga svijeta."},{"v":32,"t":"A rado bih da budete bezbrižni. Neoženjen se brine za Gospodnje, kako da ugodi Gospodinu."},{"v":33,"t":"A oženjen se brine za svjetovno, kako da ugodi ženi,"},{"v":34,"t":"pa je razdijeljen. I žena neudana i djevica brine se za Gospodnje, da bude sveta i tijelom i duhom; a udana se brine za svjetovno, kako da ugodi mužu."},{"v":35,"t":"Ovo pak govorim vama na korist, ne da vam postavim zamku, nego da primjerno i nesmetano budete privrženi Gospodinu."},{"v":36,"t":"Misli li tko da je nepriličan prema svojoj djevici kad je preživotan i s njome mora biti, neka čini što je nakanio, ne griješi: neka se uzmu."},{"v":37,"t":"Tko je pak nepokolebljivo stalan u srcu te nema potrebe, a u vlasti mu je volja pa to odluči u svom srcu - čuvati svoju djevicu - dobro čini."},{"v":38,"t":"Tako, tko se oženi svojom djevicom, dobro čini, a tko se ne oženi, bolje čini."},{"v":39,"t":"Žena je vezana dokle živi muž njezin. Umre li muž, slobodna je: neka se uda za koga hoće, samo u Gospodinu."},{"v":40,"t":"Bit će ipak blaženija ostane li onako, po mojem savjetu. A mislim da i ja imam Duha Božjega."}]},"8":{"hr":[{"v":1,"t":"U pogledu mesa žrtvovana idolima, znamo, svi posjedujemo znanje. Ali znanje nadima, a ljubav izgrađuje."},{"v":2,"t":"Ako tko misli da što zna, još ne zna kako treba znati."},{"v":3,"t":"A ljubi li tko Boga, Bog ga poznaje."},{"v":4,"t":"Dakle, u pogledu blagovanja mesa žrtvovana idolima, znamo: nema idola na svijetu i nema Boga do Jednoga."},{"v":5,"t":"Jer sve kad bi i bilo nazovibogova ili na nebu ili na zemlji - kao što ima mnogo “bogova” i mnogo “gospodara”! -"},{"v":6,"t":"nama je jedan Bog, Otac, od koga je sve, a mi za njega; i jedan Gospodin, Isus Krist, po kome je sve, i mi po njemu."},{"v":7,"t":"Ali nemaju svi toga znanja. Neki, navikli na idole, još jedu meso kao idolima žrtvovano i njihova se savjest kalja jer je nejaka."},{"v":8,"t":"A k Bogu nas ne privodi jelo. Niti što gubimo ako ne jedemo; niti što dobivamo ako jedemo."},{"v":9,"t":"A pazite da ne bi možda ta vaša sloboda bila spoticaj nejakima."},{"v":10,"t":"Jer vidi li tko tebe koji imaš znanje za stolom u hramu idolskomu, neće li se njegova savjest, jer je nejaka, “izgraditi” da jede žrtvovano idolima?"},{"v":11,"t":"I s tvoga znanja propada nejaki, brat za kojega je Krist umro."},{"v":12,"t":"Tako griješeći protiv braće i ranjavajući njihovu nejaku savjest, protiv Krista griješite."},{"v":13,"t":"Zato ako jelo sablažnjava brata moga, ne, neću jesti mesa dovijeka da brata svoga ne sablaznim."}]},"9":{"hr":[{"v":1,"t":"Nisam li ja slobodan? Nisam li apostol? Nisam li vidio Isusa, Gospodina našega? Niste li vi djelo moje u Gospodinu?"},{"v":2,"t":"Ako drugima nisam apostol, vama svakako jesam. Ta vi ste pečat mojega apostolstva u Gospodinu."},{"v":3,"t":"Moj odgovor mojim tužiteljima jest ovo:"},{"v":4,"t":"Zar nemamo prava jesti i piti?"},{"v":5,"t":"Zar nemamo prava ženu vjernicu voditi sa sobom kao i drugi apostoli i braća Gospodnja i Kefa?"},{"v":6,"t":"Ili samo ja i Barnaba nemamo prava ne raditi?"},{"v":7,"t":"Tko ikada vojuje o svojem trošku? Tko sadi vinograd pa roda njegova ne jede? Ili tko pase stado pa od mlijeka stada ne jede?"},{"v":8,"t":"Zar to govorim po ljudsku? Ne kaže li to i Zakon?"},{"v":9,"t":"Jer u Mojsijevu zakonu piše: Ne zavezuj usta volu koji vrši! Zar je Bogu do volova?"},{"v":10,"t":"Ne govori li on baš radi nas? Doista, radi nas je napisano, jer tko ore, u nadi treba da ore; i tko vrši, u nadi da će dobiti dio."},{"v":11,"t":"Ako smo mi vama sijali dobra duhovna, veliko li je nešto ako vam požanjemo tjelesna?"},{"v":12,"t":"Ako drugi sudjeluju u vašim dobrima, zašto ne bismo mi mogli još većma. Ali nismo se poslužili tim pravom, nego sve teglimo da ne bismo postavili kakvu zapreku evanđelju Kristovu?"},{"v":13,"t":"Ne znate li: koji obavljaju svetinje, od svetišta se hrane; i koji žrtveniku služe, sa žrtvenikom dijele?"},{"v":14,"t":"Tako je i Gospodin onima koji evanđelje navješćuju odredio od evanđelja živjeti."},{"v":15,"t":"No ja se ničim od toga nisam poslužio. A i ne napisah toga da bi se tako postupilo prema meni. Radije umrijeti, nego... Te mi slave nitko neće oduzeti!"},{"v":16,"t":"Jer što navješćujem evanđelje, nije mi na hvalu, ta dužnost mi je. Doista, jao meni ako evanđelja ne navješćujem."},{"v":17,"t":"Jer ako to činim iz vlastite pobude, ide me plaća; ako li ne iz vlastite pobude - služba je to koja mi je povjerena."},{"v":18,"t":"Koja mi je dakle plaća? Da propovijedajući pružam evanđelje besplatno ne služeći se svojim pravom u evanđelju."},{"v":19,"t":"Jer premda slobodan od sviju, sam sebe svima učinih slugom da ih što više steknem."},{"v":20,"t":"Bijah Židovima Židov da Židove steknem; onima pod Zakonom, kao da sam pod Zakonom - premda ja nisam pod Zakonom - da one pod Zakonom steknem;"},{"v":21,"t":"onima bez Zakona, kao da sam bez zakona - premda nisam bez Božjega zakona, nego u Kristovu zakonu - da steknem one bez Zakona;"},{"v":22,"t":"bijah nejakima nejak da nejake steknem. Svima bijah sve da pošto-poto neke spasim."},{"v":23,"t":"A sve činim poradi evanđelja da bih i ja bio suzajedničar u njemu."},{"v":24,"t":"Ne znate li: trkači u trkalištu svi doduše trče, ali jedan prima nagradu? Tako trčite da dobijete."},{"v":25,"t":"Svaki natjecatelj sve moguće izdržava; oni da dobiju raspadljiv vijenac, mi neraspadljiv."},{"v":26,"t":"Ja dakle tako trčim - ne kao besciljno, tako udaram šakom - ne kao da mlatim vjetar,"},{"v":27,"t":"nego krotim svoje tijelo i zarobljavam da sam ne budem isključen pošto sam drugima propovijedao."}]},"10":{"hr":[{"v":1,"t":"Jer ne bih, braćo, htio da budete u neznanju: oci naši svi bijahu pod oblakom, i svi prijeđoše kroz more,"},{"v":2,"t":"i svi su se na Mojsija krstili u oblaku i u moru,"},{"v":3,"t":"i svi su isto duhovno jelo jeli,"},{"v":4,"t":"i svi su isto duhovno piće pili. A pili su iz duhovne stijene koja ih je pratila; stijena bijaše Krist."},{"v":5,"t":"Ali većina njih nije bila po volji Bogu: ta poubijani su po pustinji."},{"v":6,"t":"To bijahu pralikovi naši: da ne žudimo za zlima kao što su žudjeli oni."},{"v":7,"t":"I ne budite idolopoklonici kao neki od njih, kako je pisano: Posjeda narod da jede i pije pa ustadoše da igraju."},{"v":8,"t":"I ne podajimo se bludu kao što se neki od njih bludu podaše i padoše u jednom danu dvadeset i tri tisuće."},{"v":9,"t":"I ne iskušavajmo Gospodina kao što su ga neki od njih iskušavali te od zmija izginuli."},{"v":10,"t":"I ne mrmljajte kao što neki od njih mrmljahu te izgiboše od Zatornika."},{"v":11,"t":"Sve se to, kao pralik, događalo njima, a napisano je za upozorenje nama, koje su zapala posljednja vremena."},{"v":12,"t":"Tko dakle misli da stoji, neka pazi da ne padne."},{"v":13,"t":"Nije vas zahvatila druga kušnja osim ljudske. Ta vjeran je Bog: neće pustiti da budete kušani preko svojih sila, nego će s kušnjom dati i ishod da možete izdržati."},{"v":14,"t":"Zato, ljubljeni moji, bježite od idolopoklonstva."},{"v":15,"t":"Kao razumnima velim: sudite sami što govorim."},{"v":16,"t":"Čaša blagoslovna koju blagoslivljamo nije li zajedništvo krvi Kristove? Kruh koji lomimo nije li zajedništvo tijela Kristova?"},{"v":17,"t":"Budući da je jedan kruh, jedno smo tijelo mi mnogi; ta svi smo dionici jednoga kruha."},{"v":18,"t":"Gledajte Izraela po tijelu! Koji blaguju žrtve nisu li zajedničari žrtvenika?"},{"v":19,"t":"Što dakle hoću reći? Idolska žrtva da je nešto? Ili idol da je nešto?"},{"v":20,"t":"Naprotiv, da pogani vrazima žrtvuju, ne Bogu. A neću da budete zajedničari vražji."},{"v":21,"t":"Ne možete piti čašu Gospodnju i čašu vražju. Ne možete biti sudionici stola Gospodnjega i stola vražjega."},{"v":22,"t":"Ili da izazivamo ljubomor Gospodnji? Zar smo jači od njega?"},{"v":23,"t":"“Sve je slobodno!” Ali - sve ne koristi. “Sve je dopušteno!” Ali - sve ne saziđuje."},{"v":24,"t":"Nitko neka ne traži svoje, nego dobro drugoga."},{"v":25,"t":"Sve što se prodaje na tržnici, jedite ništa ne ispitujući poradi savjesti."},{"v":26,"t":"Ta Gospodnja je zemlja i sve na njoj!"},{"v":27,"t":"Pozove li vas koji nevjernik i želite se odazvati, jedite što vam se ponudi ništa ne ispitujući poradi savjesti."},{"v":28,"t":"Ako vam tko reče: “To je žrtvovano”, ne jedite poradi onoga koji vas je upozorio, i savjesti."},{"v":29,"t":"Savjesti mislim, ne svoje, nego onoga drugoga. Ta zašto da moju slobodu druga savjest sudi?"},{"v":30,"t":"Ako sa zahvalom sudjelujem, zašto da me grde zbog onoga za što zahvaljujem?"},{"v":31,"t":"Dakle, ili jeli, ili pili, ili drugo što činili, sve na slavu Božju činite."},{"v":32,"t":"Ne budite na sablazan ni Židovima, ni Grcima, ni Crkvi Božjoj,"},{"v":33,"t":"kao što i ja svima u svemu ugađam ne tražeći svoju korist, nego što koristi mnogima na spasenje."}]},"11":{"hr":[{"v":1,"t":"Nasljedovatelji moji budite, kao što sam i ja Kristov."},{"v":2,"t":"Hvalim vas što me se u svemu sjećate i držite se predaja kako vam predadoh."},{"v":3,"t":"Ali htio bih da znate: svakomu je mužu glava Krist, glava ženi muž, a glava Kristu Bog."},{"v":4,"t":"Svaki muž koji se moli ili prorokuje pokrivene glave sramoti glavu svoju."},{"v":5,"t":"Svaka pak žena koja se moli ili prorokuje gologlava sramoti glavu svoju. Ta to je isto kao da je obrijana."},{"v":6,"t":"Jer ako se žena ne pokriva, neka se šiša; ako li je pak ružno ženi šišati se ili brijati, neka se pokrije."},{"v":7,"t":"A muž ne mora pokrivati glave, ta slika je i slava Božja; a žena je slava muževa."},{"v":8,"t":"Jer nije muž od žene, nego žena od muža."},{"v":9,"t":"I nije stvoren muž radi žene, nego žena radi muža."},{"v":10,"t":"Zato žena treba da ima “vlast” na glavi poradi anđela."},{"v":11,"t":"Ipak, u Gospodinu - ni žena bez muža, ni muž bez žene!"},{"v":12,"t":"Jer kao što je žena od muža, tako je i muž po ženi; a sve je od Boga."},{"v":13,"t":"Sami sudite dolikuje li da se žena gologlava Bogu moli?"},{"v":14,"t":"Ne uči li nas i sama narav da je mužu sramota ako goji kosu?"},{"v":15,"t":"A ženi je dika ako je goji jer kosa joj je dana mjesto prijevjesa."},{"v":16,"t":"Ako je kome do prepirke, takva običaja mi nemamo, a ni Crkve Božje."},{"v":17,"t":"Kad već dajem ta upozorenja, ne mogu pohvaliti što se ne sastajete na bolje, nego na gore."},{"v":18,"t":"Ponajprije čujem, djelomično i vjerujem: kad se okupite na Sastanak, da su među vama razdori."},{"v":19,"t":"Treba doista da i podjela bude među vama da se očituju prokušani među vama."},{"v":20,"t":"Kad se dakle tako zajedno sastajete, to nije blagovanje Gospodnje večere:"},{"v":21,"t":"ta svatko se pri blagovanju prihvati svoje večere te jedan gladuje, a drugi se opija."},{"v":22,"t":"Zar nemate kuća da jedete i pijete? Ili Crkvu Božju prezirete i postiđujete one koji nemaju? Što da vam kažem? Da vas pohvalim? U tom vas ne hvalim."},{"v":23,"t":"Doista, ja od Gospodina primih što vama predadoh: Gospodin Isus one noći kad bijaše predan uze kruh,"},{"v":24,"t":"zahvalivši razlomi i reče: “Ovo je tijelo moje - za vas. Ovo činite meni na spomen.”"},{"v":25,"t":"Tako i čašu po večeri govoreći: “Ova čaša novi je Savez u mojoj krvi. Ovo činite kad god pijete, meni na spomen.”"},{"v":26,"t":"Doista, kad god jedete ovaj kruh i pijete čašu, smrt Gospodnju navješćujete dok on ne dođe."},{"v":27,"t":"Stoga, tko god jede kruh ili pije čašu Gospodnju nedostojno, bit će krivac tijela i krvi Gospodnje."},{"v":28,"t":"Neka se dakle svatko ispita pa tada od kruha jede i iz čaše pije."},{"v":29,"t":"Jer tko jede i pije, sud sebi jede i pije ako ne razlikuje Tijela."},{"v":30,"t":"Zato su među vama mnogi nejaki i nemoćni, i spavaju mnogi."},{"v":31,"t":"Jer kad bismo sami sebe sudili, ne bismo bili suđeni."},{"v":32,"t":"A kad nas sudi Gospodin, odgaja nas da ne budemo sa svijetom osuđeni."},{"v":33,"t":"Zato, braćo moja, kad se sastajete na blagovanje, pričekajte jedni druge."},{"v":34,"t":"Je li tko gladan, kod kuće neka jede da se ne sastajete na osudu. Drugo ću urediti kada dođem."}]},"12":{"hr":[{"v":1,"t":"O darima Duha ne bih, braćo, htio da budete u neznanju."},{"v":2,"t":"Znate kako ste se dok bijaste pogani, zavedeni, zanosili nijemim idolima."},{"v":3,"t":"Zato vam obznanjujem: nitko tko u Duhu Božjem govori ne kaže: “Prokletstvo Isusu”. I nitko ne može reći: “Gospodin Isus” osim u Duhu Svetom."},{"v":4,"t":"Različiti su dari, a isti Duh;"},{"v":5,"t":"i različite službe, a isti Gospodin;"},{"v":6,"t":"i različita djelovanja, a isti Bog koji čini sve u svima."},{"v":7,"t":"A svakomu se daje očitovanje Duha na korist."},{"v":8,"t":"Doista, jednomu se po Duhu daje riječ mudrosti, drugomu riječ spoznanja po tom istom Duhu;"},{"v":9,"t":"drugomu vjera u tom istom Duhu, drugomu dari liječenja u tom jednom Duhu;"},{"v":10,"t":"drugomu čudotvorstva, drugomu prorokovanje, drugomu razlučivanje duhova, drugomu različiti jezici, drugomu tumačenje jezika."},{"v":11,"t":"A sve to djeluje jedan te isti Duh dijeleći svakomu napose kako hoće."},{"v":12,"t":"Doista, kao što je tijelo jedno te ima mnogo udova, a svi udovi tijela iako mnogi, jedno su tijelo - tako i Krist."},{"v":13,"t":"Ta u jednom Duhu svi smo u jedno tijelo kršteni, bilo Židovi, bilo Grci, bilo robovi, bilo slobodni. I svi smo jednim Duhom napojeni."},{"v":14,"t":"Ta ni tijelo nije jedan ud, nego mnogi."},{"v":15,"t":"Rekne li noga: “Nisam ruka, nisam od tijela”, zar zbog toga nije od tijela?"},{"v":16,"t":"I rekne li uho: “Nisam oko, nisam od tijela”, zar zbog toga nije od tijela?"},{"v":17,"t":"Kad bi sve tijelo bilo oko, gdje bi bio sluh? Kad bi sve bilo sluh, gdje bi bio njuh?"},{"v":18,"t":"A ovako, Bog je rasporedio udove, svaki od njih u tijelu, kako je htio."},{"v":19,"t":"Kad bi svi bili jedan ud, gdje bio bilo tijelo?"},{"v":20,"t":"A ovako, mnogi udovi - jedno tijelo!"},{"v":21,"t":"Ne može oko reći ruci: “Ne trebam te”, ili pak glava nogama: “Ne trebam vas.”"},{"v":22,"t":"Naprotiv, mnogo su potrebniji udovi tijela koji izgledaju slabiji."},{"v":23,"t":"A udove koje smatramo nečasnijima, okružujemo većom čašću. I s nepristojnima se pristojnije postupa,"},{"v":24,"t":"a pristojni toga ne trebaju. Nego, Bog je tako sastavio tijelo da je posljednjem udu dao izobilniju čast"},{"v":25,"t":"da ne bude razdora u tijelu, nego da se udovi jednako brinu jedni za druge."},{"v":26,"t":"I ako trpi jedan ud, trpe zajedno svi udovi; ako li se slavi jedan ud, raduju se zajedno svi udovi."},{"v":27,"t":"A vi ste tijelo Kristovo i, pojedinačno, udovi."},{"v":28,"t":"I neke postavi Bog u Crkvi: prvo za apostole, drugo za proroke, treće za učitelje; onda čudesa, onda dari liječenja; zbrinjavanja, upravljanja, razni jezici."},{"v":29,"t":"Zar su svi apostoli? Zar svi proroci? Zar svi učitelji? Zar svi čudotvorci?"},{"v":30,"t":"Zar svi imaju dare liječenja? Zar svi govore jezike? Zar svi tumače?"},{"v":31,"t":"Čeznite za višim darima! A evo vam puta najizvrsnijega!"}]},"13":{"hr":[{"v":1,"t":"Kad bih sve jezike ljudske govorio i anđeoske, a ljubavi ne bih imao, bio bih mjed što ječi ili cimbal što zveči."},{"v":2,"t":"Kad bih imao dar prorokovanja i znao sva otajstva i sve spoznanje; i kad bih imao svu vjeru da bih i gore premještao, a ljubavi ne bih imao - ništa sam!"},{"v":3,"t":"I kad bih razdao sav svoj imutak i kad bih predao tijelo svoje da se sažeže, a ljubavi ne bih imao - ništa mi ne bi koristilo."},{"v":4,"t":"Ljubav je velikodušna, dobrostiva je ljubav, ne zavidi, ljubav se ne hvasta, ne nadima se;"},{"v":5,"t":"nije nepristojna, ne traži svoje, nije razdražljiva, ne pamti zlo;"},{"v":6,"t":"ne raduje se nepravdi, a raduje se istini;"},{"v":7,"t":"sve pokriva, sve vjeruje, svemu se nada, sve podnosi."},{"v":8,"t":"Ljubav nikad ne prestaje. Prorokovanja? Uminut će. Jezici? Umuknut će. Spoznanje? Uminut će."},{"v":9,"t":"Jer djelomično je naše spoznanje, i djelomično prorokovanje."},{"v":10,"t":"A kada dođe ono savršeno, uminut će ovo djelomično."},{"v":11,"t":"Kad bijah nejače, govorah kao nejače, mišljah kao nejače, rasuđivah kao nejače. A kad postadoh zreo čovjek, odbacih ono nejačko."},{"v":12,"t":"Doista, sada gledamo kroza zrcalo, u zagonetki, a tada - licem u lice! Sada spoznajem djelomično, a tada ću spoznati savršeno, kao što sam i spoznat!"},{"v":13,"t":"A sada: ostaju vjera, ufanje i ljubav - to troje - ali najveća je među njima ljubav."}]},"14":{"hr":[{"v":1,"t":"Težite za ljubavlju, čeznite za darima Duha, a najvećma da prorokujete."},{"v":2,"t":"Jer tko govori drugim jezikom, ne govori ljudima nego Bogu: nitko ga ne razumije jer Duhom govori stvari tajanstvene."},{"v":3,"t":"Tko pak prorokuje, ljudima govori: izgrađuje, hrabri, tješi."},{"v":4,"t":"Tko govori drugim jezikom, sam sebe izgrađuje, a tko prorokuje, Crkvu izgrađuje."},{"v":5,"t":"A htio bih da vi svi govorite drugim jezicima, ali većma da prorokujete. Jer veći je tko prorokuje, negoli tko govori drugim jezicima, osim ako protumači Crkvi radi izgrađivanja."},{"v":6,"t":"A sada, braćo, kad bih došao k vama govoreći drugim jezicima, što bi vam koristilo kad vam ne bih priopćio bilo otkrivenje, bilo spoznanje, bilo proroštvo, bilo nauk?"},{"v":7,"t":"Ako neživa glazbala, svirala ili citra, ne daju razgovijetna glasa, kako će se razabrati što se to izvodi na svirali ili citri?"},{"v":8,"t":"Ili ako trublja daje nejasan glas, tko će se spremiti na boj?"},{"v":9,"t":"Tako i vi, ako jezikom ne budete jasno zborili, kako će se razabrati što se govori? Govorit ćete u vjetar."},{"v":10,"t":"Toliko, recimo, ima na svijetu vrsta glasova i - nijedan bez značenja."},{"v":11,"t":"Ako dakle ne znam značenja glasa, bit ću sugovorniku tuđinac, a sugovornik tuđinac meni."},{"v":12,"t":"Tako i vi, budući da čeznete za darima Duha, nastojte njima obilovati radi izgrađivanja Crkve."},{"v":13,"t":"Stoga tko govori drugim jezikom, neka se moli da može protumačiti."},{"v":14,"t":"Jer ako se drugim jezikom molim, moj se duh moli, ali um je moj neplodan."},{"v":15,"t":"Što dakle? Molit ću se duhom, molit ću se i umom; pjevat ću hvalospjeve duhom, ali pjevat ću ih i umom."},{"v":16,"t":"Jer ako Boga blagoslivljaš duhom, kako će neupućen reći “Amen” na tvoju zahvalnicu? Ne zna što govoriš."},{"v":17,"t":"Ti doduše lijepo zahvaljuješ, ali se drugi ne izgrađuje."},{"v":18,"t":"Hvala Bogu, ja govorim drugim jezicima većma nego svi vi."},{"v":19,"t":"Ali draže mi je u Crkvi reći pet riječi po svojoj pameti, da i druge poučim, negoli deset tisuća riječi drugim jezikom."},{"v":20,"t":"Braćo, ne budite djeca pameću, nego nejačad pakošću, a zreli pameću!"},{"v":21,"t":"U Zakonu je pisano: Drugim jezicima i drugim usnama govorit ću ovomu narodu pa me ni tako neće poslušati, govori Gospodin."},{"v":22,"t":"Tako drugi jezici nisu znak vjernicima, nego nevjernicima; a prorokovanje vjernicima, ne nevjernicima."},{"v":23,"t":"Ako se dakle skupi sva Crkva zajedno i svi govore drugim jezicima, a uđu neupućeni ili nevjernici, neće li reći da mahnitate?"},{"v":24,"t":"Ako pak svi prorokuju, a uđe koji nevjernik ili neupućen, sve ga prekorava, sve ga osuđuje."},{"v":25,"t":"Tajne se njegova srca očituju te će pasti ničice i pokloniti se Bogu priznajući: Zaista, Bog je u vama."},{"v":26,"t":"Što dakle braćo? Kad se skupite te poneki ima hvalospjev, poneki ima nauk, ima otkrivenje, ima jezik, ima tumačenje - sve neka bude radi izgrađivanja."},{"v":27,"t":"Ako tko govori drugim jezikom - dvojica, najviše trojica, i to jedan za drugim - jedan neka tumači;"},{"v":28,"t":"ako pak ne bi bilo tumača, neka šuti u Crkvi, neka govori sam sebi i Bogu."},{"v":29,"t":"Od proroka pak neka govore dvojica ili trojica, drugi neka rasuđuju."},{"v":30,"t":"Ali ako drugomu uza nj bude što objavljeno, prvi neka šuti."},{"v":31,"t":"A možete jedan po jedan svi prorokovati da svi budu poučeni i svi ohrabreni."},{"v":32,"t":"Proročki su duhovi prorocima podložni"},{"v":33,"t":"jer Bog nije Bog nesklada, nego Bog mira. Kao u svim Crkvama svetih, žene na Sastancima neka šute."},{"v":34,"t":"Nije im dopušteno govoriti, nego neka budu podložne, kako i Zakon govori."},{"v":35,"t":"Žele li što saznati, neka kod kuće pitaju svoje muževe jer ružno je da žena govori na Sastanku."},{"v":36,"t":"Ili zar je riječ Božja od vas proizašla, zar je samo k vama došla?"},{"v":37,"t":"Smatra li tko da je prorok ili duhom obdaren, neka zna: što vam pišem, Gospodnja je zapovijed."},{"v":38,"t":"Tko to ne prizna, ne priznaje se."},{"v":39,"t":"Zato, braćo moja, težite prorokovati i ne priječite da se govori drugim jezicima!"},{"v":40,"t":"A sve neka bude dostojno i uredno."}]},"15":{"hr":[{"v":1,"t":"Dozivljem vam, braćo, u pamet evanđelje koje vam navijestih, koje primiste, u kome stojite,"},{"v":2,"t":"po kojem se spasavate, ako držite što sam vam navijestio; osim ako uzalud povjerovaste."},{"v":3,"t":"Doista, predadoh vam ponajprije što i primih: Krist umrije za grijehe naše po Pismima;"},{"v":4,"t":"bi pokopan i uskrišen treći dan po Pismima;"},{"v":5,"t":"ukaza se Kefi, zatim dvanaestorici."},{"v":6,"t":"Potom se ukaza braći, kojih bijaše više od pet stotina zajedno; većina ih još i sada živi, a neki usnuše."},{"v":7,"t":"Zatim se ukaza Jakovu, onda svim apostolima."},{"v":8,"t":"Najposlije, kao nedonoščetu, ukaza se i meni."},{"v":9,"t":"Da, ja sam najmanji među apostolima i nisam dostojan zvati se apostolom jer sam progonio Crkvu Božju."},{"v":10,"t":"Ali milošću Božjom jesam što jesam i njegova milost prema meni ne bijaše zaludna; štoviše, trudio sam se više nego svi oni - ali ne ja, nego milost Božja sa mnom."},{"v":11,"t":"Ili dakle ja ili oni: tako propovijedamo, tako vjerujete."},{"v":12,"t":"No ako se propovijeda da je Krist od mrtvih uskrsnuo, kako neki među vama govore da nema uskrsnuća mrtvih?"},{"v":13,"t":"Ako nema uskrsnuća mrtvih, ni Krist nije uskrsnuo."},{"v":14,"t":"Ako pak Krist nije uskrsnuo, uzalud je doista propovijedanje naše, uzalud i vjera vaša."},{"v":15,"t":"Zatekli bismo se i kao lažni svjedoci Božji što posvjedočismo protiv Boga: da je uskrisio Krista, kojega nije uskrisio, ako doista mrtvi ne uskršavaju."},{"v":16,"t":"Jer ako mrtvi ne uskršavaju, ni Krist nije uskrsnuo."},{"v":17,"t":"A ako Krist nije uskrsnuo, uzaludna je vjera vaša, još ste u grijesima."},{"v":18,"t":"Onda i oni koji usnuše u Kristu, propadoše."},{"v":19,"t":"Ako se samo u ovom životu u Krista ufamo, najbjedniji smo od svih ljudi."},{"v":20,"t":"Ali sada: Krist uskrsnu od mrtvih, prvina usnulih!"},{"v":21,"t":"Doista po čovjeku smrt, po Čovjeku i uskrsnuće od mrtvih!"},{"v":22,"t":"Jer kao što u Adamu svi umiru, tako će i u Kristu svi biti oživljeni."},{"v":23,"t":"Ali svatko u svom redu: prvina Krist, a zatim koji su Kristovi, o njegovu Dolasku;"},{"v":24,"t":"potom - svršetak, kad preda kraljevstvo Bogu i Ocu, pošto obeskrijepi svako Vrhovništvo, svaku Vlast i Silu."},{"v":25,"t":"Doista, on treba da kraljuje dok ne podloži sve neprijatelje pod noge svoje."},{"v":26,"t":"Kao posljednji neprijatelj bit će obeskrijepljena Smrt"},{"v":27,"t":"jer sve podloži nogama njegovim. A kad veli: Sve je podloženo, jasno - sve osim Onoga koji mu je sve podložio."},{"v":28,"t":"I kad mu sve bude podloženo, tada će se i on sam, Sin, podložiti Onomu koji je njemu sve podložio da Bog bude sve u svemu."},{"v":29,"t":"Što onda čine oni koji se krste za mrtve? Ako mrtvi uopće ne uskršavaju, što se krste za njih?"},{"v":30,"t":"Što se onda i mi svaki čas izlažemo pogiblima?"},{"v":31,"t":"Dan za danom umirem, tako mi slave vaše, braćo, koju imam u Kristu Isusu, Gospodinu našem!"},{"v":32,"t":"Ako sam se po ljudsku borio sa zvijerima u Efezu, kakva mi korist? Ako mrtvi ne uskršavaju, jedimo i pijmo jer sutra nam je umrijeti."},{"v":33,"t":"Ne varajte se: “Zli razgovori kvare dobre običaje.”"},{"v":34,"t":"Otrijeznite se kako valja i ne griješite jer neki, na sramotu vam kažem, ne znaju za Boga."},{"v":35,"t":"Ali reći će netko: Kako uskršavaju mrtvi? I s kakvim li će tijelom doći?"},{"v":36,"t":"Bezumniče! Što siješ, ne oživljuje ako ne umre."},{"v":37,"t":"I što siješ, ne siješ tijelo buduće, već golo zrno, pšenice - recimo - ili čega drugoga."},{"v":38,"t":"A Bog mu daje tijelo kakvo hoće, i to svakom sjemenu svoje tijelo."},{"v":39,"t":"Nije svako tijelo isto tijelo; drugo je tijelo čovječje, drugo tijelo stoke, drugo tijelo ptičje, a drugo riblje."},{"v":40,"t":"Ima tjelesa nebeskih i tjelesa zemaljskih, ali drugi je sjaj nebeskih, a drugi zemaljskih."},{"v":41,"t":"Drugi je sjaj sunca, drugi sjaj mjeseca i drugi sjaj zvijezda; jer zvijezda se od zvijezde razlikuje u sjaju."},{"v":42,"t":"Tako i uskrsnuće mrtvih: sije se u raspadljivosti, uskršava u neraspadljivosti;"},{"v":43,"t":"sije se u sramoti, uskršava u slavi; sije se u slabosti, uskršava u snazi;"},{"v":44,"t":"sije se tijelo naravno, uskršava tijelo duhovno. Ako ima tijelo naravno, ima i duhovno."},{"v":45,"t":"Tako je i pisano: Prvi čovjek, Adam, postade živa duša, posljednji Adam - duh životvorni."},{"v":46,"t":"Ali ne bi najprije duhovno, nego naravno pa onda duhovno."},{"v":47,"t":"Prvi je čovjek od zemlje, zemljan; drugi čovjek - s neba."},{"v":48,"t":"Kakav je zemljani takvi su i zemljani, a kakav je nebeski takvi su i nebeski."},{"v":49,"t":"I kao što smo nosili sliku zemljanoga, nosit ćemo i sliku nebeskoga."},{"v":50,"t":"A ovo, braćo, tvrdim: tijelo i krv ne mogu baštiniti kraljevstva Božjega i raspadljivost ne baštini neraspadljivosti."},{"v":51,"t":"Evo otajstvo vam kazujem: svi doduše nećemo usnuti, ali svi ćemo se izmijeniti."},{"v":52,"t":"Odjednom, u tren oka, na posljednju trublju - jer zatrubit će - i mrtvi će uskrsnuti neraspadljivi i mi ćemo se izmijeniti."},{"v":53,"t":"Jer ovo raspadljivo treba da se obuče u neraspadljivost i ovo smrtno da se obuče u besmrtnost."},{"v":54,"t":"A kad se ovo raspadljivo obuče u neraspadljivost i ovo smrtno obuče u besmrtnost, tada će se obistiniti riječ napisana: Pobjeda iskapi smrt."},{"v":55,"t":"Gdje je, smrti, pobjeda tvoja? Gdje je, smrti, žalac tvoj?"},{"v":56,"t":"Žalac je smrti grijeh, snaga je grijeha Zakon."},{"v":57,"t":"A hvala Bogu koji nam daje pobjedu po Gospodinu našem Isusu Kristu!"},{"v":58,"t":"Tako, braćo moja ljubljena, budite postojani, nepokolebljivi, i obilujte svagda u djelu Gospodnjem znajući da trud vaš nije neplodan u Gospodinu."}]},"16":{"hr":[{"v":1,"t":"U pogledu sabiranja za svete, i vi činite kako odredih crkvama galacijskim."},{"v":2,"t":"Svakoga prvog dana u tjednu neka svaki od vas kod sebe na stranu stavlja i skuplja što uzmogne da se ne sabire istom kada dođem."},{"v":3,"t":"A kada dođem, poslat ću s preporučnicom one koje odaberete da odnesu vašu ljubav u Jeruzalem."},{"v":4,"t":"Bude li vrijedno da i ja pođem, poći će sa mnom."},{"v":5,"t":"A k vama ću doći kad prođem Makedoniju; Makedonijom ću samo proći,"},{"v":6,"t":"a kod vas ću se možda zadržati ili čak zimovati da me otpratite kamo god pođem."},{"v":7,"t":"Ne bih vas doista htio tek na prolazu vidjeti jer se nadam neko vrijeme proboraviti kod vas, dopusti li Gospodin."},{"v":8,"t":"U Efezu ću ostati do Pedesetnice"},{"v":9,"t":"jer vrata mi se otvoriše velika i uspješna, a protivnika mnogo."},{"v":10,"t":"Ako dođe Timotej, gledajte da bude kod vas bez bojazni jer radi djelo Gospodnje kao i ja."},{"v":11,"t":"Neka ga dakle nitko ne prezre. A ispratite ga u miru da dođe k meni jer ga s braćom iščekujem."},{"v":12,"t":"A što se tiče brata Apolona: mnogo sam ga nagovarao da ode k vama s braćom. I nikako mu ne bijaše s voljom da sada dođe, no doći će kad mu bude zgodno."},{"v":13,"t":"Bdijte postojani u vjeri, muževni budite, čvrsti."},{"v":14,"t":"Sve vaše neka bude u ljubavi!"},{"v":15,"t":"Zaklinjem vas, braćo - znate dom Stefanin, da je prvina Ahaje i da se posvetiše posluživanju svetih -"},{"v":16,"t":"da se i vi pokoravate takvima i svakomu tko surađuje i trudi se."},{"v":17,"t":"Radujem se s dolaska Stefanina i Fortunatova i Ahajikova jer oni nadoknadiše vašu nenazočnost:"},{"v":18,"t":"umiriše duh moj i vaš. Cijenite dakle takve."},{"v":19,"t":"Pozdravljaju vas crkve azijske. Pozdravljaju vas mnogo u Gospodinu Akvila i Priska zajedno s Crkvom u njihovu domu."},{"v":20,"t":"Pozdravljaju vas sva braća. Pozdravite jedni druge cjelovom svetim."},{"v":21,"t":"Pozdrav mojom rukom, Pavlovom."},{"v":22,"t":"Ako tko ne ljubi Gospodina, neka bude proklet. Marana tha!"},{"v":23,"t":"Milost Gospodina Isusa s vama!"},{"v":24,"t":"Ljubav moja sa svima vama u Kristu Isusu!"}]}},"2CO":{"1":{"hr":[{"v":1,"t":"Pavao, po volji Božjoj apostol Krista Isusa, i brat Timotej: Crkvi Božjoj u Korintu sa svima svetima u svoj Ahaji."},{"v":2,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista!"},{"v":3,"t":"Blagoslovljen Bog i Otac Gospodina našega Isusa Krista, Otac milosrđa i Bog svake utjehe!"},{"v":4,"t":"On nas tješi u svakoj našoj nevolji da bismo i mi sve koji su u nevolji mogli tješiti onom utjehom kojom nas same tješi Bog."},{"v":5,"t":"Jer kao što su obilate patnje Kristove u nama, tako je po Kristu obilata i utjeha naša."},{"v":6,"t":"Bili mi nevoljama pritisnuti za vašu je to utjehu i spasenje; bili utješeni, za vašu je utjehu - djelotvornu: da strpljivo podnesete iste patnje koje i mi podnosimo."},{"v":7,"t":"I tako je stamena nada naša o vama jer znamo: kao što ste zajedničari patnja tako ste i utjehe."},{"v":8,"t":"Ne bismo doista htjeli, braćo, da ne znate za nevolju koja nas je snašla u Aziji. Bijasmo prekomjerno, preko snage, opterećeni te smo već strepili i za život."},{"v":9,"t":"Ali u sebi prihvatismo i smrtnu osudu da se ne bismo uzdali u same sebe, nego u Boga koji uskrisuje mrtve."},{"v":10,"t":"On nas je od takve smrti izbavio i izbavit će nas; u njega se uzdamo, on će nas i dalje izbavljati."},{"v":11,"t":"A i vi ćete nam pomagati molitvom da bi mnogi za nas zahvaljivali Bogu na milosti koja nam je darovana posredovanjem mnogih."},{"v":12,"t":"A ovo je naša slava: svjedočansto naše savjesti da smo u svijetu živjeli - osobito prema vama - u svetosti i iskrenosti Božjoj, ne u mudrosti tjelesnoj, nego u Božjoj milosti."},{"v":13,"t":"Ta i ne pišemo vam drugo doli ovo što čitate i razumijete; a nadam se da ćete i do kraja razumjeti,"},{"v":14,"t":"kao što nas djelomično i razumjeste: da smo mi vaša slava kao i vi naša u Dan Gospodina našega Isusa."},{"v":15,"t":"U tom uvjerenju namjeravao sam najprije doći k vama"},{"v":16,"t":"i preko vas prijeći u Makedoniju pa se opet, da biste imali i drugu milost, iz Makedonije vratiti k vama da me vi otpratite u Judeju."},{"v":17,"t":"Pa jesam li možda bio lakomislen kad sam to namjeravao? Ili što namjeravam, po tijelu namjeravam te je u mene istodobno “Da, da!” i “Ne, ne!”?"},{"v":18,"t":"Bog je svjedok: naša riječ vama nije “Da!” i “Ne!”"},{"v":19,"t":"jer Sin Božji, Isus Krist, koga mi - ja i Silvan i Timotej - vama navijestismo nije bio “Da!” i “Ne!” nego u njemu bijaše “Da!”."},{"v":20,"t":"Doista, sva obećanja Božja u njemu su “Da!”. I stoga po njemu i naš “Amen!” Bogu na slavu!"},{"v":21,"t":"A Bog je onaj koji nas zajedno s vama utvrđuje za Krista; on nas i pomaza,"},{"v":22,"t":"on nas i zapečati i u srca naša dade zalog - Duha."},{"v":23,"t":"A ja prizivljem Boga za svjedoka: duše mi, da vas poštedim, nisam više dolazio u Korint."},{"v":24,"t":"Ta mi nismo gospodari vaše vjere, nego suradnici vaše radosti. Ta u vjeri ste postojani."}]},"2":{"hr":[{"v":1,"t":"Odlučih dakle u sebi da neću k vama opet sa žalošću."},{"v":2,"t":"Jer ako ja vas ražalostim, a tko će mene obradovati ako ne onaj koga ja žalostim?"},{"v":3,"t":"Zato vam to i napisah da me, kada dođem, ne ražaloste oni koji bi mi imali biti na radost. Uzdam se doista u sve vas, da je moja radost - radost svih vas."},{"v":4,"t":"Pisah vam uistinu uz mnoge suze, iz velike nevolje i tjeskobe srca, ne da se ražalostite, nego da upoznate moju preveliku ljubav prema vama."},{"v":5,"t":"Ako me tko ražalostio, nije ražalostio mene, nego u neku ruku - da ne pretjeram - sve vas."},{"v":6,"t":"Dosta je takvu ona kazna od većine"},{"v":7,"t":"pa ga vi radije pomilujte i utješite da ga pretjerana žalost ne shrva."},{"v":8,"t":"Zato vas molim, iskažite mu ljubav."},{"v":9,"t":"Ta zato vam i pisah da vidim jeste li prokušani, jeste li u svemu poslušni."},{"v":10,"t":"Komu dakle vi što oprostite, tomu i ja; jer i ja, ako kome što oprostih, oprostih poradi vas - pred Kristom,"},{"v":11,"t":"da nas ne nadmudri Sotona. Ta znamo njegove namjere!"},{"v":12,"t":"Kada dođoh u Troadu poradi evanđelja Kristova, premda mi se otvoriše vrata u Gospodinu,"},{"v":13,"t":"ne bijaše mi duši spokoja što ne nađoh Tita, brata svoga; oprostih se stoga s njima i pođoh u Makedoniju."},{"v":14,"t":"Ali hvala Bogu koji nas u Kristu uvijek proslavlja te širi po nama na svakome mjestu miris svoga spoznanja."},{"v":15,"t":"Da, Kristov smo miomiris Bogu i među onima koji se spasavaju i među onima koji propadaju:"},{"v":16,"t":"ovima miris iz smrti za smrt, onima miris iz života za život. A tko je za to podoban?"},{"v":17,"t":"Uistinu, mi nismo kao mnogi koji trguju riječju Božjom, nego iskreno - kao od Boga pred Bogom - u Kristu govorimo."}]},"3":{"hr":[{"v":1,"t":"Počinjemo li opet sami sebe preporučivati? Ili trebamo li, kao neki, preporučna pisma na vas ili od vas?"},{"v":2,"t":"Vi ste pismo naše, upisano u srcima vašim; znaju ga i čitaju svi ljudi."},{"v":3,"t":"Vi ste, očito, pismo Kristovo kojemu mi poslužismo, napisano ne crnilom, nego Duhom Boga živoga; ne na pločama kamenim, nego na pločama od mesa, u srcima."},{"v":4,"t":"Takvo pouzdanje imamo po Kristu u Boga."},{"v":5,"t":"Ne kao da smo sami sobom, kao od sebe, sposobni što pomisliti, nego naša je sposobnost od Boga."},{"v":6,"t":"On nas osposobi za poslužitelje novoga Saveza, ne slova, nego Duha; jer slovo ubija, a Duh oživljuje."},{"v":7,"t":"Pa ako je smrtonosna služba, slovima uklesana u kamenju, bila tako slavna da sinovi Izraelovi nisu mogli pogledati u lice Mojsijevo zbog prolazne slave lica njegova,"},{"v":8,"t":"koliko li će slavnija biti služba Duha."},{"v":9,"t":"Jer ako je služba osude bila slavna, mnogo je slavnija služba pravednosti."},{"v":10,"t":"I zbilja, nije ni bilo proslavljeno ono što je u toj mjeri proslavljeno, ako se usporedi s uzvišenijom slavom."},{"v":11,"t":"Jer ako je ono prolazno bilo slavno, mnogo je slavnije ovo što ostaje."},{"v":12,"t":"Imajući dakle takvo pouzdanje, nastupamo sa svom otvorenošću,"},{"v":13,"t":"a ne kao Mojsije koji je stavljao prijevjes na lice da sinovi Izraelovi ne vide svršetak prolaznoga."},{"v":14,"t":"Ali otvrdnu im pamet. Doista, do dana današnjega zastire taj prijevjes čitanje Staroga zavjeta: nije im otkriveno da je u Kristu prestao."},{"v":15,"t":"Naprotiv, kad god se čita Mojsije, do danas prijevjes zastire srce njihovo."},{"v":16,"t":"Ali kad se Izrael obrati Gospodinu, skinut će se prijevjes."},{"v":17,"t":"Gospodin je Duh, a gdje je Duh Gospodnji, ondje je sloboda."},{"v":18,"t":"A svi mi, koji otkrivenim licem odrazujemo slavu Gospodnju, po Duhu se Gospodnjem preobražavamo u istu sliku - iz slave u slavu."}]},"4":{"hr":[{"v":1,"t":"Zato, budući da po milosrđu imamo ovu službu, ne malakšemo."},{"v":2,"t":"Ali odrekosmo se sramotnoga prikrivanja: ne nastupamo lukavo niti izopačujemo riječ Božju, nego se objavljivanjem istine preporučujemo svakoj savjesti ljudskoj pred Bogom."},{"v":3,"t":"Ako je i zastrto evanđelje naše, u onima je zastrto koji propadaju:"},{"v":4,"t":"u onima kojima bog ovoga svijeta oslijepi pameti nevjerničke da ne zasvijetli svjetlost evanđelja slave Krista koji je slika Božja."},{"v":5,"t":"Jer ne propovijedamo same sebe, nego Krista Isusa Gospodinom, a sebe slugama vašim poradi Isusa."},{"v":6,"t":"Ta Bog koji reče: Neka iz tame svjetlost zasine!, on zasvijetli u srcima našim da nam spoznanje slave Božje zasvijetli na licu Kristovu."},{"v":7,"t":"To pak blago imamo u glinenim posudama da izvanredna ona snaga bude očito Božja, a ne od nas."},{"v":8,"t":"U svemu pritisnuti, ali ne pritiješnjeni; dvoumeći, ali ne zdvajajući;"},{"v":9,"t":"progonjeni, ali ne napušteni; obarani, ali ne oboreni -"},{"v":10,"t":"uvijek umiranje Isusovo u tijelu pronosimo da se i život Isusov u tijelu našem očituje."},{"v":11,"t":"Doista, mi se živi uvijek na smrt predajemo poradi Isusa da se i život Isusov očituje u našem smrtnom tijelu."},{"v":12,"t":"Tako smrt djeluje u nama, život u vama."},{"v":13,"t":"A budući da imamo isti duh vjere kao što je pisano: Uzvjerovah, zato besjedim, i mi vjerujemo pa zato i besjedimo."},{"v":14,"t":"Ta znamo: onaj koji je uskrisio Gospodina Isusa i nas će s Isusom uskrisiti i zajedno s vama uza se postaviti."},{"v":15,"t":"A sve je to za vas: da milost - umnožena - zahvaljivanjem mnogih izobiluje Bogu na slavu."},{"v":16,"t":"Zato ne malakšemo. Naprotiv, ako se naš izvanji čovjek i raspada, nutarnji se iz dana u dan obnavlja."},{"v":17,"t":"Ta ova malenkost naše časovite nevolje donosi nam obilato, sve obilatije, breme vječne slave"},{"v":18,"t":"jer nama nije do vidljivog nego do nevidljivog: ta vidljivo je privremeno, a nevidljivo - vječno."}]},"5":{"hr":[{"v":1,"t":"Znamo doista: ako se razruši naš zemaljski dom, šator, imamo zdanje od Boga, dom nerukotvoren, vječan na nebesima."},{"v":2,"t":"U ovome doista stenjemo i čeznemo da se povrh njega zaodjenemo svojim nebeskim obitavalištem;"},{"v":3,"t":"dakako, ako se nađemo obučeni, ne goli."},{"v":4,"t":"Da, i mi koji smo u ovom šatoru, stenjemo opterećeni jer nećemo da budemo svučeni, nego da se još obučemo da život iskapi što je smrtno."},{"v":5,"t":"A zato nas je sazdao Bog - on koji nam dade zalog Duha."},{"v":6,"t":"Uvijek smo stoga puni pouzdanja makar i znamo: naseljeni u tijelu, iseljeni smo od Gospodina."},{"v":7,"t":"Ta u vjeri hodimo, ne u gledanju."},{"v":8,"t":"Da, puni smo pouzdanja i najradije bismo se iselili iz tijela i naselili kod Gospodina."},{"v":9,"t":"Zato se i trsimo da mu omilimo, bilo naseljeni, bilo iseljeni."},{"v":10,"t":"Jer svima nam se pojaviti pred sudištem Kristovim da svaki dobije što je kroz tijelo zaradio, bilo dobro, bilo zlo."},{"v":11,"t":"Prožeti dakle strahom Gospodnjim uvjeravamo ljude; razotkriveni smo Bogu, a nadam se - i vašim savjestima."},{"v":12,"t":"Ne preporučujemo vam opet sami sebe, nego vam dajemo prigodu ponositi se nama, da imate odgovor za one koji se diče licem, a ne srcem."},{"v":13,"t":"Doista, ako bijasmo “izvan sebe” - Bogu bijasmo; ako li “pri sebi” - vama bijasmo."},{"v":14,"t":"Jer ljubav nas Kristova obuzima kad promatramo ovo: jedan za sve umrije, svi dakle umriješe;"},{"v":15,"t":"i za sve umrije da oni koji žive ne žive više sebi, nego onomu koji za njih umrije i uskrsnu."},{"v":16,"t":"Stoga mi od sada nikoga ne poznajemo po tijelu; ako smo i poznavali po tijelu Krista, sada ga tako više ne poznajemo."},{"v":17,"t":"Dakle, je li tko u Kristu, nov je stvor. Staro uminu, novo, gle, nasta!"},{"v":18,"t":"A sve je od Boga koji nas sa sobom pomiri po Kristu i povjeri nam službu pomirenja."},{"v":19,"t":"Jer Bog je u Kristu svijet sa sobom pomirio ne ubrajajući im opačina njihovih i polažući u nas riječ pomirenja."},{"v":20,"t":"Kristovi smo dakle poslanici; Bog vas po nama nagovara. Umjesto Krista zaklinjemo: dajte, pomirite se s Bogom!"},{"v":21,"t":"Njega koji ne okusi grijeha Bog za nas grijehom učini da mi budemo pravednost Božja u njemu."}]},"6":{"hr":[{"v":1,"t":"Kao suradnici opominjemo vas da ne primite uzalud milosti Božje."},{"v":2,"t":"Jer on veli: U vrijeme milosti usliših te i u dan spasa pomogoh ti. Evo sad je vrijeme milosno, evo sad je vrijeme spasa."},{"v":3,"t":"Ni u čemu ne dajemo nikakve sablazni da se ne kudi ova služba,"},{"v":4,"t":"nego se u svemu iskazujemo kao poslužitelji Božji: velikom postojanošću u nevoljama, u potrebama, u tjeskobama,"},{"v":5,"t":"pod udarcima, u tamnicama, u bunama, u naporima, u bdjenjima, u postovima,"},{"v":6,"t":"u čistoći, u spoznanju, u velikodušnosti, u dobroti, u Duhu Svetomu, u ljubavi nehinjenoj,"},{"v":7,"t":"u riječi istinitoj, u snazi Božjoj; oružjem pravde zdesna i slijeva;"},{"v":8,"t":"slavom i sramotom; zlim i dobrim glasom; kao zavodnici, a istiniti;"},{"v":9,"t":"kao nepoznati, a poznati; kao umirući, a evo živimo; kao kažnjeni, a ne ubijeni;"},{"v":10,"t":"kao žalosni, a uvijek radosni; kao siromašni, a mnoge obogaćujemo; kao oni koji ništa nemaju, a sve posjeduju."},{"v":11,"t":"Usta su naša otvorena vama, Korinćani, srce naše rašireno."},{"v":12,"t":"Nije vam tijesno u nama, ali je tijesno u vašim grudima."},{"v":13,"t":"Za uzdarje - kao djeci govorim - raširite se i vi."},{"v":14,"t":"Ne ujarmljujte se s nevjernicima. Ta što ima pravednost s bezakonjem? Ili kakvo zajedništvo svjetlo s tamom?"},{"v":15,"t":"Kakvu slogu Krist s Belijarom? Ili kakav dio vjernik s nevjernikom?"},{"v":16,"t":"Kakav sporazum hram Božji s idolima? Jer mi smo hram Boga živoga, kao što reče Bog: Prebivat ću u njima i hoditi među njima; i bit ću Bog njihov, a oni narod moj."},{"v":17,"t":"Zato iziđite iz njihove sredine i odvojite se, govori Gospodin, i ništa nečisto ne dotičite i ja ću vas primiti."},{"v":18,"t":"I bit ću vam otac i vi ćete mi biti sinovi i kćeri, veli Gospodin Svemogući."}]},"7":{"hr":[{"v":1,"t":"Dakle, budući da imamo ta obećanja, očistimo se, ljubljeni, od svake ljage tijela i duha te dovršimo posvećenje u strahu Božjemu."},{"v":2,"t":"Shvatite nas! Nikomu nismo nanijeli nepravde, nikoga nismo upropastili, nikoga zakinuli."},{"v":3,"t":"Ne govorim da osudim. Ta rekoh već: u srcima ste našim te umiremo i živimo zajedno."},{"v":4,"t":"Veliko je moje pouzdanje u vas, uvelike se vama ponosim. Pun sam utjehe, obilujem radošću uza svu nevolju našu."},{"v":5,"t":"Doista, i kada dođosmo u Makedoniju, nikakva spokoja nije imalo tijelo naše, nego nevolje odasvud: izvana borbe, iznutra strepnje."},{"v":6,"t":"Ali Bog, tješitelj poniznih, utješi nas dolaskom Titovim."},{"v":7,"t":"Ne samo dolaskom njegovim, nego i utjehom kojom se utješi zbog vas: obavijesti nas o vašoj čežnji, vašem jadikovanju, vašoj žarkoj ljubavi prema meni tako da se još većma obradovah."},{"v":8,"t":"Doista, ako sam vas i ožalostio onom poslanicom, nije mi žao; ako mi i bijaše žao - vidim uistinu da vas je ta poslanica makar i načas ožalostila -"},{"v":9,"t":"sad se radujem, ne što ste se ožalostili, nego što ste se ožalostili na obraćenje. Jer ožalostili ste se po Božju te zbog nas ni u čemu niste štetovali."},{"v":10,"t":"Jer žalost po Božju rađa neopozivo spasonosnim obraćenjem, a žalost svjetovna rađa smrću."},{"v":11,"t":"Gle, doista baš to što ste se po Božju ožalostili, kolikom gorljivošću urodi među vama, pa opravdavanjem, pa ogorčenjem, pa strahom, pa čežnjom, pa revnošću, pa kažnjavanjem. Svime ste time pokazali da ste u onome nedužni."},{"v":12,"t":"Ako sam vam dakle pisao, nisam to zbog uvreditelja ni zbog uvrijeđenoga, nego zbog toga da vam se očituje vaša gorljivost za nas pred Bogom."},{"v":13,"t":"To nas je utješilo. A povrh te naše utjehe još se mnogo više obradovasmo zbog radosti Titove jer svi vi okrijepiste duh njegov."},{"v":14,"t":"Doista, ako sam mu se što vama pohvalio, ne postidjeh se, nego kao što smo po istini vama govorili, tako je istina bila i pohvala naša pred Titom."},{"v":15,"t":"I njegovo je srce prema vama još nježnije kad se sjeti poslušnosti svih vas, kako ga sa strahom i trepetom primiste."},{"v":16,"t":"Radujem se što se u svemu mogu pouzdati u vas."}]},"8":{"hr":[{"v":1,"t":"Priopćujemo vam, braćo, milost Božju koja je dana crkvama makedonskim:"},{"v":2,"t":"unatoč mnogim kušnjama i nevoljama izobilna njihova radost i skrajnje siromaštvo preli se u bogatstvo darežljivosti."},{"v":3,"t":"Svjedočim uistinu: oni su nas dragovoljno - po svojim mogućnostima i preko mogućnosti -"},{"v":4,"t":"veoma usrdno molili za milost zajedništva u ovom posluživanju svetih."},{"v":5,"t":"I to ne samo kako se nadasmo, nego same sebe predadoše najprvo Gospodinu, a onda nama, po volji Božjoj."},{"v":6,"t":"Zato zamolismo Tita da kao što je započeo, tako i dovrši među vama i to djelo darežljivosti."},{"v":7,"t":"Stoga kao što se u svemu odlikujete - u vjeri, i riječi, i spoznanju, i svakoj gorljivosti, i u ljubavi svojoj prema nama - odlikujte se i u ovoj darežljivosti."},{"v":8,"t":"Ne zapovijedam, nego gorljivošću drugih prokušavam istinitost vaše ljubavi."},{"v":9,"t":"Ta poznate darežljivost Gospodina našega Isusa Krista! Premda bogat, radi vas posta siromašan, da se vi njegovim siromaštvom obogatite."},{"v":10,"t":"Time dajem samo savjet: to doista dolikuje vama koji već prošle godine prvi to započeste, ne samo činom nego i odlukom."},{"v":11,"t":"Sada dovršite to djelo da kao što spremno odlučiste, tako prema mogućnostima i dovršite."},{"v":12,"t":"Jer ima li spremnosti, mila je po onom što ima, a ne po onom čega nema."},{"v":13,"t":"Ne dakako: drugima olakšica, vama oskudica, nego - jednakost!"},{"v":14,"t":"U sadašnjem trenutku vaš suvišak za njihovu oskudicu da jednom njihov suvišak bude za vašu oskudicu - te bude jednakost,"},{"v":15,"t":"kao što je pisano: Nije ništa preteklo onome koji bijaše nakupio mnogo, a niti je nedostajalo onome koji bijaše nakupio manje."},{"v":16,"t":"A hvala Bogu koji je stavio jednaku gorljivost za vas u srce Titovo."},{"v":17,"t":"On je prihvatio i molbu, ali budući da je veoma revan, otiđe k vama i dragovoljno."},{"v":18,"t":"S njime pak šaljemo brata kojega s evanđelja slave sve crkve."},{"v":19,"t":"Štoviše, crkve ga izabraše za našeg suputnika u ovom djelu darežljivosti kojemu služimo - na slavu samoga Gospodina i na našu želju"},{"v":20,"t":"kako bismo izbjegli da nas tko ne prekori zbog ovog obilja kojim raspolažemo."},{"v":21,"t":"Doista, revno nastojimo oko dobra ne samo pred Gospodinom nego i pred ljudima."},{"v":22,"t":"Šaljemo s njima i našega brata koji je, kako smo u mnogome često iskusili, gorljiv, a sada je još mnogo gorljiviji zbog velikoga pouzdanja u vas."},{"v":23,"t":"A Tito? Moj je drug i suradnik za vas. A braća naša? Poslanici su crkava, slava Kristova."},{"v":24,"t":"Pružite im dakle pred crkvama dokaz svoje ljubavi i toga da se s pravom vama ponosimo."}]},"9":{"hr":[{"v":1,"t":"A o posluživanju svetih suvišno je da vam pišem."},{"v":2,"t":"Ta poznajem vašu spremnost s koje se vama ponosim pred Makedoncima: “Ahaja je spremna od prošle godine.” I vaša gorljivost potaknu mnoge."},{"v":3,"t":"Ipak šaljem braću da se u tome pogledu ne opovrgne što se vama ponosimo; da budete spremni kao što sam tvrdio te se -"},{"v":4,"t":"ako sa mnom dođu Makedonci i nađu vas nespremne - ne osramotimo s preuzetnosti mi, da ne kažemo vi."},{"v":5,"t":"Smatrao sam dakle potrebnim zamoliti braću da unaprijed pođu k vama i da pripreme vaš još prije obećani dar te bude pripravan - kao dar darežljivosti, a ne škrtosti."},{"v":6,"t":"Ta eno: tko sije oskudno, oskudno će i žeti; a tko sije obilato, obilato će i žeti."},{"v":7,"t":"Svatko neka dade kako je srcem odlučio; ne sa žalošću ili na silu jer Bog ljubi vesela darivatelja."},{"v":8,"t":"A Bog vas može obilato obdariti svakovrsnim darom da u svemu svagda imate svega dovoljno za se i izobilno za svako dobro djelo -"},{"v":9,"t":"kao što je pisano: Rasipno dijeli, daje sirotinji, pravednost njegova ostaje dovijeka."},{"v":10,"t":"A onaj koji pribavlja sjeme sijaču i kruh za jelo, pribavit će i umnožiti sjeme vaše i povećati plodove pravednosti vaše."},{"v":11,"t":"Tako ćete se u svemu obogatiti za svakovrsnu darežljivost koja se, našim posredovanjem, izvija u zahvalnicu Bogu."},{"v":12,"t":"Jer ovo bogoslužno posluživanje ne samo da podmiruje oskudicu svetih nego se i obilno prelijeva u mnoge zahvalnice Bogu."},{"v":13,"t":"Osvjedočeni ovim posluživanjem, slave Boga zbog vašega pokornog ispovijedanja evanđelja Kristova i zbog velikodušnog zajedništva prema njima i prema svima."},{"v":14,"t":"A moleći se za vas, čeznu za vama zbog preobilne milosti Božje na vama."},{"v":15,"t":"Hvala Bogu na njegovu neizrecivom daru!"}]},"10":{"hr":[{"v":1,"t":"Ja, Pavao, osobno vas zaklinjem blagošću i obazrivošću Kristovom - ja koji sam licem u lice među vama “skroman”, a nenazočan prema vama “odvažan” -"},{"v":2,"t":"molim da, jednom nazočan, ne moram biti odvažan smionošću kojom se kanim osmjeliti protiv nekih što smatraju da mi po tijelu živimo."},{"v":3,"t":"Jer iako živimo u tijelu, ne vojujemo po tijelu."},{"v":4,"t":"Ta oružje našega vojevanja nije tjelesno, nego božanski snažno za rušenje utvrda. Obaramo mudrovanja"},{"v":5,"t":"i svaku oholost koja se podiže protiv spoznanja Boga i zarobljujemo svaki um na pokornost Kristu;"},{"v":6,"t":"i spremni smo kazniti svaku nepokornost čim bude savršena vaša pokornost."},{"v":7,"t":"Gledajte što je očito! Ako je tko uvjeren da je “Kristov”, neka sam ponovno promisli ovo: kako je on Kristov, tako smo i mi."},{"v":8,"t":"Kad bih se doista i malo više pohvalio našom vlašću - koju nam Gospodin dade za vaše izgrađivanje, a ne rušenje - ne bih se morao stidjeti."},{"v":9,"t":"Samo da se ne bi činilo kao da vas zastrašujem poslanicama!"},{"v":10,"t":"Jer “poslanice su, kaže, stroge i snažne, ali tjelesna nazočnost nemoćna i riječ bezvrijedna”."},{"v":11,"t":"Takav neka promisli ovo: kakvi smo nenazočni riječju u poslanicama, takvi smo i nazočni djelom."},{"v":12,"t":"Ne usuđujemo se, doista, izjednačiti ili usporediti s nekima koji sami sebe preporučuju, ali nisu razumni jer sami sebe sobom mjere i sami sebe sa sobom uspoređuju."},{"v":13,"t":"Mi se pak nećemo hvaliti u bezmjerje, nego po mjeri, mjerilu što nam ga odmjeri Bog kao mjeru: doprijeti sve do vas."},{"v":14,"t":"Jer mi ne posežemo preko svoga, kao da još nismo stigli do vas. Ta prvi doista doprijesmo do vas s evanđeljem Kristovim."},{"v":15,"t":"Ne hvalimo se u bezmjerje, tuđim naporima. A nadamo se da ćemo s uzrastom vaše vjere među vama i mi - po našem mjerilu - prerasti u izobilje:"},{"v":16,"t":"i preko vaših granica navijestiti evanđelje, a ne hvastati se onim što je već učinjeno na tuđem području."},{"v":17,"t":"Tko se hvali, u Gospodinu neka se hvali."},{"v":18,"t":"Ta nije prokušan tko sam sebe preporučuje, nego koga preporučuje Gospodin."}]},"11":{"hr":[{"v":1,"t":"O kad biste podnijeli nešto malo bezumlja mojega! Da, podnesite me!"},{"v":2,"t":"Ljubomoran sam doista na vas Božjim ljubomorom: ta zaručih vas s jednim mužem, kao čistu djevicu privedoh vas Kristu."},{"v":3,"t":"Ali se bojim da se - kao što zmija zavede Evu svojom lukavštinom - misli vaše ne pokvare i odmetnu od iskrenosti prema Kristu."},{"v":4,"t":"Uistinu, ako tko dođe i propovijeda drugog Isusa, kojega mi nismo propovijedali - ili ako drugoga Duha primate, kojega niste primili; ili drugo evanđelje, koje niste prigrlili - takva lijepo podnosÄite."},{"v":5,"t":"Smatram, eto, da ni u čemu nisam manji od “nadapostola”."},{"v":6,"t":"Jer ako sam i nevješt u govoru, nisam u znanju; naprotiv, u svemu vam ga i pred svima očitovasmo."},{"v":7,"t":"Ili sam grijeh počinio što sam vam - ponizujući sebe da se vi uzvisite - besplatno navješćivao Božje evanđelje?"},{"v":8,"t":"Druge sam crkve plijenio, od njih primao potporu da bih mogao vama služiti. I dok bijah u vas, premda u oskudici, nikomu nisam bio na teret."},{"v":9,"t":"U oskudici su mi pomogla braća koja dođoše iz Makedonije. U svemu sam se čuvao da vam ne budem težak, a i čuvat ću se."},{"v":10,"t":"Istine mi Kristove u meni, ove mi hvale nitko neće oduzeti u ahajskim krajevima."},{"v":11,"t":"Zašto? Jer vas ne ljubim? Bog znade!"},{"v":12,"t":"A što činim, i dalje ću činiti da izbijem izliku onima koji izliku traže ne bi li se s nama izjednačili u onom čime se hvastaju."},{"v":13,"t":"Jer takvi su ljudi lažni apostoli, himbeni radnici, prerušuju se u apostole Kristove."},{"v":14,"t":"I nikakvo čudo! Ta sam se Sotona prerušuje u anđela svjetla."},{"v":15,"t":"Ništa osobito dakle ako se i službenici njegovi prerušuju u službenike pravednosti. Svršetak će im biti po djelima njihovim."},{"v":16,"t":"Opet velim: da me tko ne bi smatrao bezumnim! Uostalom, primite me makar i kao bezumna da se i ja nešto malo pohvalim."},{"v":17,"t":"Što govorim, ne govorim po Gospodnju, nego kao u bezumlju, u ovoj hvalisavoj smionosti."},{"v":18,"t":"Budući da se mnogi hvale po ljudsku, i ja ću se hvaliti."},{"v":19,"t":"Ta rado podnosÄite bezumne, vi umni!"},{"v":20,"t":"Da, podnosÄite ako vas tko zarobljava, ako vas tko proždire, ako tko otima, ako se tko uznosi, ako vas tko po obrazu bije."},{"v":21,"t":"Na sramotu govorim: bili smo, biva, slabi! Ipak, čime se god tko osmjeljuje - u bezumlju govorim - osmjeljujem se i ja!"},{"v":22,"t":"Hebreji su? I ja sam! Izraelci su? I ja sam! Potomstvo su Abrahamovo? I ja sam!"},{"v":23,"t":"Poslužitelji su Kristovi? Kao mahnit govorim: ja još više! U naporima - preobilno; u tamnicama - preobilno; u batinama - prekomjerno; u smrtnim pogiblima - često."},{"v":24,"t":"Od Židova primio sam pet puta po četrdeset manje jednu."},{"v":25,"t":"Triput sam bio šiban, jednom kamenovan, triput doživio brodolom, jednu noć i dan proveo sam u bezdanu."},{"v":26,"t":"Česta putovanja, pogibli od rijeka, pogibli od razbojnika, pogibli od sunarodnjaka, pogibli od pogana, pogibli u gradu, pogibli u pustinji, pogibli na moru, pogibli od lažne braće;"},{"v":27,"t":"u trudu i naporu, često u nespavanju, u gladu i žeđi, često u postovima, u studeni i golotinji!"},{"v":28,"t":"Osim toga, uz drugo, salijetanje svakodnevno, briga za sve crkve."},{"v":29,"t":"Tko je slab, a ja da ne budem slab? Tko se sablažnjuje, a ja da ne izgaram?"},{"v":30,"t":"Treba li se hvaliti, svojom ću se slabošću hvaliti."},{"v":31,"t":"Bog i Otac Gospodina Isusa, blagoslovljen u vijeke, zna da ne lažem."},{"v":32,"t":"U Damasku namjesnik kralja Arete čuvaše grad damaščanski hoteći me uhvatiti."},{"v":33,"t":"Ali kroz prozor spustiše me u košari preko zida te umakoh njegovim rukama."}]},"12":{"hr":[{"v":1,"t":"Hvaliti se treba? Ne koristi doduše ali - dolazim na viđenje i objave Gospodnje."},{"v":2,"t":"Znam čovjeka u Kristu: prije četrnaest godina - da li u tijelu, ne znam; da li izvan tijela, ne znam, Bog zna - taj je bio ponesen do trećeg neba."},{"v":3,"t":"I znam da je taj čovjek - da li u tijelu, da li izvan tijela, ne znam, Bog zna -"},{"v":4,"t":"bio ponesen u raj i čuo neizrecive riječi, kojih čovjek ne smije govoriti."},{"v":5,"t":"Time ću se hvaliti, a samim se sobom neću hvaliti osim slabostima svojim."},{"v":6,"t":"Uistinu, kad bih se i htio hvaliti, ne bih bio bezuman; istinu bih govorio. Ali se uzdržavam da ne bi tko mislio o meni više nego što vidi na meni ili što čuje od mene."},{"v":7,"t":"I da se zbog uzvišenosti objava ne bih uzoholio, dan mi je trn u tijelu, anđeo Sotonin, da me udara da se ne uzoholim."},{"v":8,"t":"Za to sam triput molio Gospodina, da odstupi od mene. A on mi reče:"},{"v":9,"t":"“Dosta ti je moja milost jer snaga se u slabosti usavršuje.” Najradije ću se dakle još više hvaliti svojim slabostima da se nastani u meni snaga Kristova."},{"v":10,"t":"Zato uživam u slabostima, uvredama, poteškoćama, progonstvima, tjeskobama poradi Krista. Jer kad sam slab, onda sam jak."},{"v":11,"t":"Postao sam bezuman! Vi me natjeraste. Ta trebalo je da me vi preporučite jer ni u čemu nisam manji od “nadapostola”, premda nisam ništa."},{"v":12,"t":"Znamenja apostolstva moga ostvarena su među vama u posvemašnjoj postojanosti: znakovima i čudesima i silnim djelima."},{"v":13,"t":"Ta u čemu ste to manji od drugih crkava, osim što vam ja nisam bio na teret? Oprostite mi ovu “nepravdu”."},{"v":14,"t":"Evo, spremam se treći put doći k vama i neću vam biti na teret jer ne ištem vaše, nego vas. Djeca doista nisu dužna stjecati roditeljima, nego roditelji djeci."},{"v":15,"t":"A ja ću najradije trošiti i istrošiti se za duše vaše. Ako vas više ljubim, zar da budem manje ljubljen?"},{"v":16,"t":"Ali neka! Ja vas nisam opterećivao, nego, “lukav” kako jesam, “na prijevaru vas uhvatih”."},{"v":17,"t":"Da vas možda nisam zakinuo po kome od onih koje poslah k vama?"},{"v":18,"t":"Zamolio sam Tita i poslao s njime brata. Da vas možda Tit nije u čemu zakinuo? Zar nismo hodili u istom duhu? I istim stopama?"},{"v":19,"t":"Odavna smatrate da se pred vama branimo. Pred Bogom u Kristu govorimo: sve je to, ljubljeni, za vaše izgrađivanje."},{"v":20,"t":"Bojim se doista da vas kada dođem, možda neću naći kakve bih htio i da ćete vi mene naći kakva ne biste htjeli: da ne bi možda bilo svađa, zavisti, žestina, spletkarenja, klevetanja, došaptavanja, nadimanja, buna;"},{"v":21,"t":"da me opet kada dođem, ne bi ponizio Bog moj kod vas kako ne bih morao oplakivati mnoge koji su prije sagriješili, a nisu se pokajali za nečistoću i bludnost i razvratnost koju počiniše."}]},"13":{"hr":[{"v":1,"t":"Evo treći put idem k vama. Svaka presuda neka počiva na iskazu dvojice ili trojice svjedoka."},{"v":2,"t":"Onima koji su prije sagriješili i svima drugima rekoh već i opet - kao onda drugi put nazočan, tako i sada nenazočan - unaprijed velim: ako opet dođem, neću štedjeti."},{"v":3,"t":"Jer vi tražite dokaz da u meni govori Krist koji prema vama nije nemoćan, nego je snažan među vama."},{"v":4,"t":"I raspet bi, istina, po slabosti, ali živi po snazi Božjoj. I mi smo, istina, slabi u njemu, ali ćemo po snazi Božjoj živjeti s njime za vas."},{"v":5,"t":"Same sebe ispitujte, jeste li u vjeri! Same sebe provjeravajte! Zar ne spoznajete sami sebe: da je Isus Krist u vama? Inače niste pravi."},{"v":6,"t":"A spoznat ćete, nadam se, da smo mi pravi."},{"v":7,"t":"Molimo se Bogu da ne činite nikakva zla; ne da se mi pokažemo pravi, nego da vi dobro činite, pa izašli mi i kao nepravi."},{"v":8,"t":"Ta ništa ne možemo protiv istine, nego samo za istinu."},{"v":9,"t":"Da, radujemo se kad smo mi slabi, a vi jaki. Za to se i molimo, za vaše usavršavanje."},{"v":10,"t":"To vam nenazočan pišem zato da nazočan ne bih morao oštro nastupiti vlašću koju mi Gospodin dade za izgrađivanje, a ne za rušenje."},{"v":11,"t":"Uostalom, braćo, radujte se, usavršujte se, tješite se, složni budite, mir njegujte i Bog ljubavi i mira bit će s vama."},{"v":12,"t":"Pozdravite jedni druge svetim cjelovom. Pozdravljaju vas svi sveti."},{"v":13,"t":"Milost Gospodina Isusa Krista, ljubav Boga i zajedništvo Duha Svetoga sa svima vama!"}]}},"GAL":{"1":{"hr":[{"v":1,"t":"Pavao, apostol - ne od ljudi ni po kojem čovjeku, nego po Isusu Kristu i Bogu Ocu koji ga uskrisi od mrtvih -"},{"v":2,"t":"i sva braća koja su sa mnom: Crkvama u Galaciji."},{"v":3,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista,"},{"v":4,"t":"koji sam sebe dade za grijehe naše da nas istrgne iz sadašnjega svijeta opakoga kao što je volja Boga i Oca našega,"},{"v":5,"t":"komu slava u vijeke vjekova! Amen."},{"v":6,"t":"Čudim se da od Onoga koji vas pozva na milost Kristovu tako brzo prelazite na neko drugo evanđelje,"},{"v":7,"t":"koje uostalom i ne postoji. Postoje samo neki koji vas zbunjuju i hoće prevratiti evanđelje Kristovo."},{"v":8,"t":"Ali kad bismo vam mi, ili kad bi vam anđeo s neba navješćivao neko evanđelje mimo onoga koje vam mi navijestismo, neka je proklet!"},{"v":9,"t":"Što smo već rekli, to sad i ponavljam: navješćuje li vam tko neko evanđelje mimo onoga koje primiste, neka je proklet."},{"v":10,"t":"Doista, nastojim li ovo pridobiti ljude ili Boga? Ili idem li za tim da ljudima ugodim? Kad bih sveudilj nastojao ljudima ugađati, ne bih bio Kristov sluga."},{"v":11,"t":"Obznanjujem vam, braćo: evanđelje koje sam navješćivao nije od ljudi,"},{"v":12,"t":"niti ga ja od kojeg čovjeka primih ili naučih, nego objavom Isusa Krista."},{"v":13,"t":"Ta čuli ste za moje negdašnje ponašanje u židovstvu: preko svake sam mjere progonio i pustošio Crkvu Božju"},{"v":14,"t":"te sam u židovstvu, prerevno odan otačkim predajama, nadmašio mnoge vršnjake u svojem narodu."},{"v":15,"t":"Ali kad se Onomu koji me odvoji već od majčine utrobe i pozva milošću svojom, svidjelo"},{"v":16,"t":"otkriti mi Sina svoga da ga navješćujem među poganima, odmah, ne posavjetovah se s tijelom i krvlju"},{"v":17,"t":"i ne uziđoh u Jeruzalem k onima koji bijahu apostoli prije mene, nego odoh u Arabiju pa se opet vratih u Damask."},{"v":18,"t":"Onda nakon tri godine uziđoh u Jeruzalem potražiti Kefu i ostadoh kod njega petnaest dana."},{"v":19,"t":"Od apostola ne vidjeh nikoga drugog osim Jakova, brata Gospodinova."},{"v":20,"t":"Što vam pišem, Bog mi je svjedok, ne lažem."},{"v":21,"t":"Zatim dođoh u krajeve sirijske i cilicijske."},{"v":22,"t":"Osobno pak bijah nepoznat Kristovim crkvama u Judeji."},{"v":23,"t":"One su samo čule: “Negdašnji naš progonitelj sada navješćuje vjeru koju je nekoć pustošio”"},{"v":24,"t":"i slavile su Boga zbog mene."}]},"2":{"hr":[{"v":1,"t":"Zatim nakon četrnaest godina opet uziđoh u Jeruzalem s Barnabom, a povedoh sa sobom i Tita."},{"v":2,"t":"Uziđoh po objavi i izložih im - napose uglednijima - evanđelje koje propovijedam među poganima da ne bih možda, ili da nisam, trčao uzalud."},{"v":3,"t":"Čak ni Tit, pratilac moj, premda Grk, nije bio prisiljen obrezati se,"},{"v":4,"t":"i to radi uljeza, lažne braće, koja se ušuljaše da vrebaju slobodu koju imamo u Kristu Isusu, ne bi li nas učinili robovima."},{"v":5,"t":"Ne, ni načas im nismo popustili, nismo se podložili: da istina evanđelja ostane kod vas!"},{"v":6,"t":"A oni koji štogod znače - bili oni što bili, nije mi do toga, Bog ne gleda tko je tko - ti uglednici, uistinu, ništa nisu pridometnuli."},{"v":7,"t":"Nego naprotiv, vidjevši da mi je povjereno evanđelje za neobrezane, kao Petru za obrezane -"},{"v":8,"t":"jer Onaj koji je bio na djelu po Petrovu apostolstvu među obrezanima, bio je na djelu i po meni među poganima -"},{"v":9,"t":"i spoznavši milost koja mi je dana, Jakov, Kefa i Ivan, smatrani stupovima, pružiše meni i Barnabi desnice zajedništva: mi ćemo među pogane, a oni među obrezane!"},{"v":10,"t":"Samo neka se sjećamo siromaha, što sam revno i činio."},{"v":11,"t":"A kad Kefa stiže u Antiohiju, u lice mu se usprotivih jer je zavrijedio osudu:"},{"v":12,"t":"doista, prije nego stigoše neki od Jakova, blagovao je zajedno s poganima; a kad oni dođoše, počeo se povlačiti i odvajati bojeći se onih iz obrezanja."},{"v":13,"t":"Za njim se povedoše i ostali Židovi te je i Barnaba zaveden tom prijetvornošću."},{"v":14,"t":"Ali kad vidjeh da ne hode ravno, po istini evanđelja, rekoh Kefi pred svima: “Ako ti, Židov, poganski živiš, a ne židovski, kako možeš siliti pogane da se požidove?”"},{"v":15,"t":"Mi smo podrijetlom Židovi, a ne “grešnici iz poganstva”."},{"v":16,"t":"Ali znamo: čovjek se ne opravdava po djelima Zakona, nego vjerom u Isusa Krista. Zato i mi u Krista Isusa povjerovasmo da se opravdamo po vjeri u Krista, a ne po djelima Zakona jer se po djelima Zakona nitko neće opravdati."},{"v":17,"t":"Ako se pak po tome što zaiskasmo opravdati se u Kristu očitovalo da smo i mi grešnici, nije li onda Krist u službi grijeha? Nipošto!"},{"v":18,"t":"Doista, ako ponovno gradim što sam bio srušio, pokazujem da sam prijestupnik."},{"v":19,"t":"Ta po Zakonu ja Zakonu umrijeh da Bogu živim. S Kristom sam razapet."},{"v":20,"t":"Živim, ali ne više ja, nego živi u meni Krist. A što sada živim u tijelu, u vjeri živim u Sina Božjega koji me ljubio i predao samoga sebe za mene."},{"v":21,"t":"Ne dokidam milosti Božje! Doista, ako je opravdanje po Zakonu, onda je Krist uzalud umro."}]},"3":{"hr":[{"v":1,"t":"O bezumni Galaćani, tko li vas opčara? A pred očima vam je Isus Krist bio ocrtan kao Raspeti."},{"v":2,"t":"Ovo bih samo htio doznati od vas: jeste li primili Duha po djelima Zakona ili po vjeri u Poruku?"},{"v":3,"t":"Tako li ste bezumni? Započeli ste u Duhu pa da sada u tijelu dovršite?"},{"v":4,"t":"Zar ste toliko toga uzalud doživjeli? A kad bi doista bilo uzalud!"},{"v":5,"t":"Onaj dakle koji vam daje Duha i čini među vama silna djela, čini li to zbog djela Zakona ili zbog vjere u Poruku?"},{"v":6,"t":"Tako Abraham povjerova Bogu i uračuna mu se u pravednost."},{"v":7,"t":"Shvatite dakle: oni od vjere, to su sinovi Abrahamovi."},{"v":8,"t":"A Pismo, predvidjevši da Bog po vjeri opravdava pogane, unaprijed navijesti Abrahamu: U tebi će blagoslovljeni biti svi narodi."},{"v":9,"t":"Tako: oni od vjere blagoslivlju se s vjernikom Abrahamom."},{"v":10,"t":"Doista, koji su god od djela Zakona, pod prokletstvom su. Ta pisano je: Proklet tko se god ne drži i tko ne vrši svega što je napisano u Knjizi Zakona."},{"v":11,"t":"A da se pred Bogom nitko ne opravdava Zakonom, očito je jer: Pravednik će od vjere živjeti."},{"v":12,"t":"Zakon pak nije od vjere, nego veli: Tko ga vrši, u njemu će naći život."},{"v":13,"t":"Krist nas otkupi od prokletstva Zakona, postavši za nas prokletstvom - jer pisano je: Proklet je tko god visi na drvetu -"},{"v":14,"t":"da u Kristu Isusu na pogane dođe blagoslov Abrahamov: da Obećanje, Duha, primimo po vjeri."},{"v":15,"t":"Braćo, po ljudsku govorim: već i ljudski valjan savez nitko ne poništava niti mu što dodaje."},{"v":16,"t":"A ova su obećanja dana Abrahamu i potomstvu njegovu. Ne veli se: “i potomcima” kao o mnogima, nego kao o jednomu: I potomstvu tvojem, to jest Kristu."},{"v":17,"t":"Ovo hoću kazati: Saveza koji je Bog valjano sklopio ne obeskrepljuje Zakon, koji je nastao četiri stotine i trideset godina poslije, i ne dokida obećanja."},{"v":18,"t":"Doista, ako se baština zadobiva po Zakonu, ne zadobiva se po obećanju. A Abrahama je Bog po obećanju obdario."},{"v":19,"t":"Čemu onda Zakon? Dometnut je poradi prekršaja dok ne dođe potomstvo komu je namijenjeno obećanje; sastavljen je po anđelima preko posrednika."},{"v":20,"t":"Posrednika pak nema gdje je samo jedan. A Bog je jedan."},{"v":21,"t":"Zar je dakle Zakon protiv obećanja Božjih? Nipošto! Jer da je dan Zakon koji bi mogao oživljavati, pravednost bi doista proizlazila iz Zakona."},{"v":22,"t":"Ali je Pismo sve zatvorilo pod grijeh da se, po vjeri u Isusa Krista, obećano dade onima koji vjeruju."},{"v":23,"t":"Prije dolaska vjere, pod Zakonom zatvoreni, bili smo čuvani za vjeru koja se imala objaviti."},{"v":24,"t":"Tako nam je Zakon bio nadzirateljem sve do Krista da se po vjeri opravdamo."},{"v":25,"t":"A otkako je nadošla vjera, nismo više pod nadzirateljem."},{"v":26,"t":"Uistinu, svi ste sinovi Božji, po vjeri u Kristu Isusu."},{"v":27,"t":"Doista, koji ste god u Krista kršteni, Kristom se zaodjenuste."},{"v":28,"t":"Nema više: Židov - Grk! Nema više: rob - slobodnjak! Nema više: muško - žensko! Svi ste vi Jedan u Kristu Isusu!"},{"v":29,"t":"Ako li ste Kristovi, onda ste Abrahamovo potomstvo, baštinici po obećanju."}]},"4":{"hr":[{"v":1,"t":"Hoću reći: sve dok je baštinik maloljetan, ništa se ne razlikuje od roba premda je gospodar svega:"},{"v":2,"t":"pod skrbnicima je i upraviteljima sve do dana koji je odredio otac."},{"v":3,"t":"Tako i mi: dok bijasmo maloljetni, robovasmo počelima svijeta."},{"v":4,"t":"A kada dođe punina vremena, odasla Bog Sina svoga: od žene bi rođen, Zakonu podložan"},{"v":5,"t":"da podložnike Zakona otkupi te primimo posinstvo."},{"v":6,"t":"A budući da ste sinovi, odasla Bog u srca vaša Duha Sina svoga koji kliče: “Abba! Oče!”"},{"v":7,"t":"Tako više nisi rob nego sin; ako pak sin, onda i baštinik po Bogu."},{"v":8,"t":"Onda dok još niste poznavali Boga, služili ste bogovima koji po naravi to nisu."},{"v":9,"t":"Ali sada kad ste spoznali Boga - zapravo, kad je Bog spoznao vas - kako se sad opet vraćate k nemoćnim i bijednim počelima i opet im, ponovno, hoćete robovati?"},{"v":10,"t":"Dane pomno opslužujete, i mjesece, i vremena, i godine!"},{"v":11,"t":"Sve se bojim za vas! Da se možda nisam uzalud trudio oko vas!"},{"v":12,"t":"Postanite, braćo, molim vas, kao ja jer i ja postadoh kao vi. Ničim me niste povrijedili."},{"v":13,"t":"Znate: prvi sam vam put za bolesti navješćivao evanđelje."},{"v":14,"t":"Svoju kušnju, moje tijelo, niste ni prezreli ni odbacili, nego ste me primili kao anđela Božjega, kao Krista Isusa."},{"v":15,"t":"Gdje je sada ono vaše blaženstvo? Svjedočim vam doista: kad bi bilo moguće, oči biste svoje bili iskopali i dali mi ih."},{"v":16,"t":"Tako? Postadoh li vam neprijateljem propovijedajući vam istinu?"},{"v":17,"t":"Oni revnuju za vas, ne časno, nego - odvojiti vas hoće da onda vi za njih revnujete."},{"v":18,"t":"Dobro je da se za vas revnuje u dobru uvijek, a ne samo kad sam nazočan kod vas,"},{"v":19,"t":"dječice moja, koju ponovno u trudovima rađam dok se Krist ne oblikuje u vama."},{"v":20,"t":"Htio bih sada biti kod vas, pa i jezik promijeniti, jer ne znam što bih s vama."},{"v":21,"t":"Recite mi vi, koji želite biti pod Zakonom, zar ne čujete Zakona?"},{"v":22,"t":"Ta pisano je da je Abraham imao dva sina, jednoga od ropkinje i jednoga od slobodne."},{"v":23,"t":"Ali onaj od ropkinje rođen je po tijelu, a onaj od slobodne snagom obećanja."},{"v":24,"t":"To je slika. Doista, te žene dva su Saveza: jedan s brda Sinaja, koji rađa za ropstvo - to je Hagara."},{"v":25,"t":"Jer Hagara znači brdo Sinaj u Arabiji i odgovara sadašnjem Jeruzalemu jer robuje zajedno sa svojom djecom."},{"v":26,"t":"Onaj pak Jeruzalem gore slobodan je; on je majka naša."},{"v":27,"t":"Pisano je doista: Kliči, nerotkinjo, koja ne rađaš, podvikuj od radosti, ti što ne znaš za trudove! Jer osamljena više djece ima negoli udana."},{"v":28,"t":"Vi ste, braćo, kao Izak, djeca obećanja."},{"v":29,"t":"I kao što je onda onaj po tijelu rođeni progonio onoga po duhu rođenoga, tako je i sada."},{"v":30,"t":"Nego, što veli Pismo? Otjeraj sluškinju i sina njezina jer sin sluškinje ne smije biti baštinik sa sinom slobodne."},{"v":31,"t":"Zato, braćo, nismo djeca ropkinje nego slobodne."}]},"5":{"hr":[{"v":1,"t":"Za slobodu nas Krist oslobodi! Držite se dakle i ne dajte se ponovno u jaram ropstva!"},{"v":2,"t":"Evo ja, Pavao, velim vam: ako se obrežete, Krist vam ništa neće koristiti."},{"v":3,"t":"I ponovno jamčim svakom čovjeku koji se obreže: dužan je opsluživati sav Zakon."},{"v":4,"t":"Prekinuli ste s Kristom vi koji se u Zakonu mislite opravdati; iz milosti ste ispali."},{"v":5,"t":"Jer mi po Duhu iz vjere očekujemo pravednost, nadu svoju."},{"v":6,"t":"Uistinu, u Kristu Isusu ništa ne vrijedi ni obrezanje ni neobrezanje, nego - vjera ljubavlju djelotvorna."},{"v":7,"t":"Dobro ste trčali; tko li vas je samo spriječio da se više ne pokoravate istini?"},{"v":8,"t":"Ta pobuda nije od Onoga koji vas zove!"},{"v":9,"t":"Malo kvasca cijelo tijesto ukvasa."},{"v":10,"t":"Ja se uzdam u vas u Gospodinu: vi nećete drukčije misliti. A tko vas zbunjuje, snosit će osudu, tko god bio."},{"v":11,"t":"A ja, braćo, ako sveudilj propovijedam obrezanje, zašto me sveudilj progone? Onda je obeskrijepljena sablazan križa!"},{"v":12,"t":"Uškopili se oni koji vas podbunjuju!"},{"v":13,"t":"Doista vi ste, braćo, na slobodu pozvani! Samo neka ta sloboda ne bude izlikom tijelu, nego - ljubavlju služite jedni drugima."},{"v":14,"t":"Ta sav je Zakon ispunjen u jednoj jedinoj riječi, u ovoj: Ljubi bližnjega svoga kao sebe samoga!"},{"v":15,"t":"Ako li pak jedni druge grizete i glođete, pazite da jedni druge ne proždrete."},{"v":16,"t":"Hoću reći: po Duhu živite pa nećete ugađati požudi tijela!"},{"v":17,"t":"Jer tijelo žudi protiv Duha, a Duh protiv tijela. Doista, to se jedno drugomu protivi da ne činite što hoćete."},{"v":18,"t":"Ali ako vas Duh vodi, niste pod Zakonom."},{"v":19,"t":"A očita su djela tijela. To su: bludnost, nečistoća, razvratnost,"},{"v":20,"t":"idolopoklonstvo, vračanje, neprijateljstva, svađa, ljubomor, srdžbe, spletkarenja, razdori, strančarenja,"},{"v":21,"t":"zavisti, pijančevanja, pijanke i tome slično. Unaprijed vam kažem, kao što vam već rekoh: koji takvo što čine, kraljevstva Božjega neće baštiniti."},{"v":22,"t":"Plod je pak Duha: ljubav, radost, mir, velikodušnost, uslužnost, dobrota, vjernost,"},{"v":23,"t":"blagost, uzdržljivost. Protiv tih nema zakona."},{"v":24,"t":"Koji su Kristovi, razapeše tijelo sa strastima i požudama."},{"v":25,"t":"Ako živimo po Duhu, po Duhu se i ravnajmo!"},{"v":26,"t":"Ne hlepimo za taštom slavom! Ne izazivajmo jedni druge, ne zaviđajmo jedni drugima!"}]},"6":{"hr":[{"v":1,"t":"Braćo, ako se tko i zatekne u kakvu prijestupu, vi, duhovni, takva ispravljajte u duhu blagosti. A pazi na samoga sebe da i ti ne podlegneš napasti."},{"v":2,"t":"Nosite jedni bremena drugih i tako ćete ispuniti zakon Kristov!"},{"v":3,"t":"Jer misli li tko da jest štogod, a nije ništa, sam sebe vara."},{"v":4,"t":"Svatko neka ispita sam svoje djelo pa će onda u samom sebi imati čime se dičiti, a ne u usporedbi s drugim."},{"v":5,"t":"Ta svatko će nositi svoj teret."},{"v":6,"t":"Koji se uči Riječi, neka sva dobra dijeli sa svojim učiteljem."},{"v":7,"t":"Ne varajte se: Bog se ne da izrugivati! Što tko sije, to će i žeti!"},{"v":8,"t":"Doista, tko sije u tijelo svoje, iz tijela će žeti raspadljivost, a tko sije u duh, iz duha će žeti život vječni."},{"v":9,"t":"Neka nam ne dozlogrdi činiti dobro: ako ne sustanemo, u svoje ćemo vrijeme žeti!"},{"v":10,"t":"Dakle, dok imamo vremena, činimo dobro svima, ponajpače domaćima u vjeri."},{"v":11,"t":"Gledajte kolikim vam slovima pišem svojom rukom."},{"v":12,"t":"Svi koji se hoće praviti važni tijelom, sile vas na obrezanje, samo da zbog križa Kristova ne bi trpjeli progonstvo."},{"v":13,"t":"Ta ni sami obrezani ne opslužuju Zakona, ali hoće da se vi obrežete da bi se mogli ponositi vašim tijelom."},{"v":14,"t":"A ja, Bože sačuvaj da bih se ičim ponosio osim križem Gospodina našega Isusa Krista po kojem je meni svijet raspet i ja svijetu."},{"v":15,"t":"Uistinu, niti je što obrezanje niti neobrezanje, nego - novo stvorenje."},{"v":16,"t":"A na sve koji se ovoga pravila budu držali, i na sveg Izraela Božjega - mir i milosrđe!"},{"v":17,"t":"Ubuduće neka mi nitko ne dodijava jer ja na svom tijelu nosim biljege Isusove!"},{"v":18,"t":"Milost Gospodina našega Isusa Krista s duhom vašim, braćo! Amen"}]}},"EPH":{"1":{"hr":[{"v":1,"t":"Pavao, po volji Božjoj apostol Krista Isusa: svetima koji su u Efezu i vjernima u Isusu Kristu."},{"v":2,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista!"},{"v":3,"t":"Blagoslovljen Bog i Otac Gospodina našega Isusa Krista, on koji nas blagoslovi svakim blagoslovom duhovnim u nebesima, u Kristu."},{"v":4,"t":"Tako: u njemu nas sebi izabra prije postanka svijeta da budemo sveti i bez mane pred njim;"},{"v":5,"t":"u ljubavi nas predodredi za posinstvo, za sebe, po Isusu Kristu, dobrohotnošću svoje volje,"},{"v":6,"t":"na hvalu Slave svoje milosti. Njome nas zamilova u Ljubljenome"},{"v":7,"t":"u kome, njegovom krvlju, imamo otkupljenje, otpuštenje prijestupa po bogatstvu njegove milosti."},{"v":8,"t":"Nju preobilno u nas uli zajedno sa svom mudrošću i razumijevanjem"},{"v":9,"t":"obznanivši nam otajstvo svoje volje po dobrohotnom naumu svojem što ga prije u njemu zasnova"},{"v":10,"t":"da se provede punina vremena: uglaviti u Kristu sve - na nebesima i na zemlji."},{"v":11,"t":"U njemu, u kome i nama - predodređenima po naumu Onoga koji sve izvodi po odluci svoje volje - u dio pade"},{"v":12,"t":"da budemo na hvalu Slave njegove - mi koji smo se već prije nadali u Kristu."},{"v":13,"t":"U njemu ste i vi, pošto ste čuli Riječ istine - evanđelje spasenja svoga - u njemu ste, prigrlivši vjeru, opečaćeni Duhom obećanim, Svetim,"},{"v":14,"t":"koji je zalog naše baštine: otkupljenja, posvojenja - na hvalu Slave njegove."},{"v":15,"t":"Zato i ja, otkad sam čuo za vašu vjeru u Gospodinu Isusu i za ljubav prema svima svetima,"},{"v":16,"t":"ne prestajem zahvaljivati za vas i sjećati vas se u svojim molitvama:"},{"v":17,"t":"Bog Gospodina našega Isusa Krista, Otac Slave, dao vam Duha mudrosti i objave kojom ćete ga spoznati;"},{"v":18,"t":"prosvijetlio vam oči srca da upoznate koje li nade u pozivu njegovu, koje li bogate slave u baštini njegovoj među svetima"},{"v":19,"t":"i koje li prekomjerne veličine u moći njegovoj prema nama koji vjerujemo: ona je primjerena djelotvornosti sile i snage njegove"},{"v":20,"t":"koju na djelu pokaza u Kristu, kad ga uskrisi od mrtvih i posjede sebi zdesna na nebesima"},{"v":21,"t":"iznad svakog Vrhovništva i Vlasti i Moći i Gospodstva i svakog imena imenovana ne samo na ovom svijetu nego i u budućemu."},{"v":22,"t":"Sve mu podloži pod noge, a njega postavi - nad svime - Glavom Crkvi,"},{"v":23,"t":"koja je Tijelo njegovo, punina Onoga koji sve u svima ispunja."}]},"2":{"hr":[{"v":1,"t":"I vi bijaste mrtvi zbog prijestupa i grijeha"},{"v":2,"t":"u kojima ste nekoć živjeli po Eonu ovoga svijeta, po Knezu vlasti zraka, po tomu duhu koji sada djeluje u sinovima neposlušnima."},{"v":3,"t":"Među njima smo i mi nekoć živjeli u požudama tijela svoga, udovoljavajući prohtjevima tijela i ćudi, te po naravi bijasmo djeca gnjeva kao i drugi."},{"v":4,"t":"Ali Bog, bogat milosrđem, zbog velike ljubavi kojom nas uzljubi,"},{"v":5,"t":"nas koji bijasmo mrtvi zbog prijestupa, oživi zajedno s Kristom - milošću ste spašeni! -"},{"v":6,"t":"te nas zajedno s njim uskrisi i posadi na nebesima u Kristu Isusu:"},{"v":7,"t":"da u dobrohotnosti prema nama u Kristu Isusu pokaže budućim vjekovima preobilno bogatstvo milosti svoje."},{"v":8,"t":"Ta milošću ste spašeni po vjeri! I to ne po sebi! Božji je to dar!"},{"v":9,"t":"Ne po djelima, da se ne bi tko hvastao."},{"v":10,"t":"Njegovo smo djelo, stvoreni u Kristu Isusu za dobra djela, koja Bog unaprijed pripravi da u njima živimo."},{"v":11,"t":"Spominjite se stoga da nekoć bijaste neznabošci u tijelu - neobrezanicima su vas zvali oni koji se zovu obrezani, rukom, na tijelu -"},{"v":12,"t":"i da u ono vrijeme bijaste izvan Krista, udaljeni od građanstva izraelskoga, tuđi Savezima obećanja, bez nade bijaste i neznabošci na svijetu."},{"v":13,"t":"Sada pak, u Kristu Isusu, vi koji nekoć bijaste daleko, dođoste blizu - po Krvi Kristovoj."},{"v":14,"t":"Doista, on je mir naš, on koji od dvoga učini jedno: pregradu razdvojnicu, neprijateljstvo razori u svome tijelu."},{"v":15,"t":"Zakon zapovijedi s propisima obeskrijepi da u sebi, uspostavljajući mir, od dvojice sazda jednoga novog čovjeka"},{"v":16,"t":"te obojicu u jednome Tijelu izmiri s Bogom po križu, ubivši u sebi neprijateljstvo."},{"v":17,"t":"I dođe te navijesti mir vama daleko i mir onima blizu,"},{"v":18,"t":"jer po njemu jedni i drugi u jednome Duhu imamo pristup Ocu."},{"v":19,"t":"Tako dakle više niste tuđinci ni pridošlice, nego sugrađani ste svetih i ukućani Božji"},{"v":20,"t":"nazidani na temelju apostola i proroka, a zaglavni je kamen sam Krist Isus."},{"v":21,"t":"U njemu je sva građevina povezana i raste u hram svet u Gospodinu."},{"v":22,"t":"U njemu ste i vi ugrađeni u prebivalište Božje u Duhu."}]},"3":{"hr":[{"v":1,"t":"Radi toga ja, Pavao, sužanj Krista Isusa za vas pogane..."},{"v":2,"t":"Zacijelo ste čuli za rasporedbu milosti Božje koja mi je dana za vas:"},{"v":3,"t":"objavom mi je obznanjeno otajstvo, kako netom ukratko opisah."},{"v":4,"t":"Čitajući to, možete dokučiti kako ja shvaćam Kristovo otajstvo,"},{"v":5,"t":"koje nije bilo obznanjeno sinovima ljudskim drugih naraštaja. Ono je sada u Duhu objavljeno svetim njegovim apostolima i prorocima:"},{"v":6,"t":"da su pogani subaštinici i “sutijelo” i sudionici obećanja u Kristu Isusu - po evanđelju,"},{"v":7,"t":"kojega postadoh poslužiteljem darom milosti Božje koja mi je dana djelotvornošću snage njegove."},{"v":8,"t":"Meni, najmanjemu od svih svetih, dana je ova milost: poganima biti blagovjesnikom neistraživog bogatstva Kristova"},{"v":9,"t":"i osvijetliti rasporedbu otajstva, pred vjekovima skrivena u Bogu, koji sve stvori,"},{"v":10,"t":"da sada - po Crkvi - Vrhovništvima i Vlastima na nebesima bude obznanjena mnogolika mudrost Božja"},{"v":11,"t":"zasnovana - po naumu o vjekovima - u Kristu Isusu Gospodinu našemu."},{"v":12,"t":"U njemu, s pouzdanjem po vjeri u njega, imamo slobodan pristup."},{"v":13,"t":"Zato ne klonite, molim, s nevolja mojih za vas! One su slava vaša!"},{"v":14,"t":"Zato prigibam koljena pred Ocem,"},{"v":15,"t":"od koga ime svakom očinstvu na nebu i na zemlji:"},{"v":16,"t":"neka vam dadne po bogatstvu Slave svoje ojačati se po Duhu njegovu u snazi za unutarnjeg čovjeka"},{"v":17,"t":"da po vjeri Krist prebiva u srcima vašim te u ljubavi ukorijenjeni i utemeljeni"},{"v":18,"t":"mognete shvatiti sa svima svetima što je Dužina i Širina i Visina i Dubina"},{"v":19,"t":"te spoznati nadspoznatljivu ljubav Kristovu da se ispunite do sve Punine Božje."},{"v":20,"t":"Onomu pak koji snagom u nama djelatnom može učiniti mnogo izobilnije nego li mi moliti ili zamisliti -"},{"v":21,"t":"Njemu slava u Crkvi i u Kristu Isusu za sva pokoljenja vijeka vjekovječnoga! Amen."}]},"4":{"hr":[{"v":1,"t":"Zaklinjem vas dakle ja, sužanj u Gospodinu: sa svom poniznošću i blagošću, sa strpljivošću živite dostojno poziva kojim ste pozvani!"},{"v":2,"t":"Podnosite jedni druge u ljubavi;"},{"v":3,"t":"trudite se sačuvati jedinstvo Duha svezom mira!"},{"v":4,"t":"Jedno tijelo i jedan Duh - kao što ste i pozvani na jednu nadu svog poziva!"},{"v":5,"t":"Jedan Gospodin! Jedna vjera! Jedan krst!"},{"v":6,"t":"Jedan Bog i Otac sviju, nad svima i po svima i u svima!"},{"v":7,"t":"A svakomu je od nas dana milost po mjeri dara Kristova."},{"v":8,"t":"Zato veli: Na visinu uzađe vodeći sužnje, dade dare ljudima."},{"v":9,"t":"Ono “uzađe” - što drugo znači doli to da i siđe u donje krajeve, na zemlju?"},{"v":10,"t":"Koji siđe, isti je onaj koji i uzađe ponad svih nebesa da sve ispuni."},{"v":11,"t":"On i “dade” jedne za apostole, druge za proroke, jedne opet za evanđeliste, a druge za pastire i učitelje"},{"v":12,"t":"da opremi svete za djelo služenja, za izgrađivanje Tijela Kristova"},{"v":13,"t":"dok svi ne prispijemo do jedinstva vjere i spoznaje Sina Božjega, do čovjeka savršena, do mjere uzrasta punine Kristove:"},{"v":14,"t":"da više ne budemo nejačad kojom se valovi poigravaju i koje goni svaki vjetar nauka u ovom kockanju ljudskom, u lukavosti što put krči zabludi."},{"v":15,"t":"Nego, istinujući u ljubavi da poradimo te sve uzraste u Njega, koji je Glava, Krist,"},{"v":16,"t":"od kojega sve Tijelo, usklađeno i povezano svakovrsnim zglobom zbrinjavanja po djelotvornosti primjerenoj svakomu pojedinom dijelu, promiče svoj rast na saziđivanje u ljubavi."},{"v":17,"t":"Ovo govorim i zaklinjem u Gospodinu: ne živite više kao što pogani žive - u ispraznosti pameti njihove:"},{"v":18,"t":"zamračena uma, udaljeni od života Božjega, sve zbog neznanja koje je u njima, zbog okorjelosti srca njihova."},{"v":19,"t":"Sami su sebe otupili i podali se razvratnosti da bi u pohlepi počinjali svaku nečistoću."},{"v":20,"t":"Vi pak ne naučiste tako Krista,"},{"v":21,"t":"ako ste ga doista čuli i u njemu bili poučeni kako je istina u Isusu:"},{"v":22,"t":"da vam je odložiti prijašnje ponašanje, starog čovjeka, koga varave požude vode u propast,"},{"v":23,"t":"a obnavljati se duhom svoje pameti"},{"v":24,"t":"i obući novog čovjeka, po Bogu stvorena u pravednosti i svetosti istine."},{"v":25,"t":"Zato odložite laž i govorite istinu jedan drugomu jer udovi smo jedni drugima."},{"v":26,"t":"Srdite se, ali ne griješite! Sunce nek ne zađe nad vašom srdžbom"},{"v":27,"t":"i ne dajite mjesta đavlu."},{"v":28,"t":"Tko je krao, neka više ne krade, nego neka se radije trudi svojim rukama priskrbljivati da ima što podijeliti s potrebnim."},{"v":29,"t":"Nikakva nevaljala riječ neka ne izlazi iz vaših usta, nego samo dobra, da prema potrebi saziđuje i milost iskaže slušateljima."},{"v":30,"t":"I ne žalostite Duha Svetoga, Božjega, kojim ste opečaćeni za Dan otkupljenja!"},{"v":31,"t":"Daleko od vas svaka gorčina, i srdžba, i gnjev, i vika, i hula sa svom opakošću!"},{"v":32,"t":"Naprotiv! Budite jedni drugima dobrostivi, milosrdni; praštajte jedni drugima kao što i Bog u Kristu nama oprosti."}]},"5":{"hr":[{"v":1,"t":"Budite dakle nasljedovatelji Božji kao djeca ljubljena"},{"v":2,"t":"i hodite u ljubavi kao što je i Krist ljubio vas i sebe predao za nas kao prinos i žrtvu Bogu na ugodan miris."},{"v":3,"t":"A bludnost i svaka nečistoća ili pohlepa neka se i ne spominje među vama, kako dolikuje svetima!"},{"v":4,"t":"Ni prostota, ni ludorija, ni dvosmislica, što se ne priliči, nego radije zahvaljivanje!"},{"v":5,"t":"Jer dobro znajte ovo: nijedan bludnik, ili bestidnik, ili pohlepnik - taj idolopoklonik - nema baštine u kraljevstvu Kristovu i Božjemu."},{"v":6,"t":"Nitko neka vas ispraznim riječima ne zavarava: zbog toga dolazi gnjev Božji na sinove neposlušne."},{"v":7,"t":"Nemajte dakle ništa s njima!"},{"v":8,"t":"Da, nekoć bijaste tama, a sada ste svjetlost u Gospodinu: kao djeca svjetlosti hodite -"},{"v":9,"t":"plod je svjetlosti svaka dobrota, pravednost i istina -"},{"v":10,"t":"i odlučite se za ono što je milo Gospodinu."},{"v":11,"t":"A nemajte udjela u jalovim djelima tame, nego ih dapače raskrinkavajte,"},{"v":12,"t":"jer što potajno čine, sramota je i govoriti."},{"v":13,"t":"A sve što se raskrinka, pod svjetlošću postaje sjajno; što je pak sjajno, svjetlost je."},{"v":14,"t":"Zato veli: “Probudi se, ti što spavaš, ustani od mrtvih i zasvijetljet će ti Krist.”"},{"v":15,"t":"Razmotrite dakle pomno kako živite! Ne kao ludi, nego kao mudri!"},{"v":16,"t":"Iskupljujte vrijeme jer dani su zli!"},{"v":17,"t":"Zato ne budite nerazumni, nego shvatite što je volja Gospodnja!"},{"v":18,"t":"I ne opijajte se vinom u kojem je razuzdanost, nego - punite se Duhom!"},{"v":19,"t":"Razgovarajte među sobom psalmima, hvalospjevima i duhovnim pjesmama! Pjevajte i slavite Gospodina u svom srcu!"},{"v":20,"t":"Svagda i za sve zahvaljujte Bogu i Ocu u imenu Gospodina našega Isusa Krista!"},{"v":21,"t":"Podložni budite jedni drugima u strahu Kristovu!"},{"v":22,"t":"Žene svojim muževima kao Gospodinu!"},{"v":23,"t":"Jer muž je glava žene kao i Krist Glava Crkve - On, Spasitelj Tijela."},{"v":24,"t":"Pa kao što se Crkva podlaže Kristu, tako i žene muževima u svemu!"},{"v":25,"t":"Muževi, ljubite svoje žene kao što je Krist ljubio Crkvu te sebe predao za nju"},{"v":26,"t":"da je posveti, očistivši je kupelji vode uz riječ"},{"v":27,"t":"te sebi predvede Crkvu slavnu, bez ljage i nabora ili čega takva, nego da bude sveta i bez mane."},{"v":28,"t":"Tako treba da i muževi ljube svoje žene kao svoja tijela. Tko ljubi svoju ženu, sebe ljubi."},{"v":29,"t":"Ta nitko nikada ne mrzi svoga tijela, nego ga hrani i njeguje kao i Krist Crkvu."},{"v":30,"t":"Doista, mi smo udovi njegova Tijela!"},{"v":31,"t":"Stoga će čovjek ostaviti oca i majku da prione uza svoju ženu; dvoje njih bit će jedno tijelo."},{"v":32,"t":"Otajstvo je to veliko! Ja smjeram na Krista i na Crkvu."},{"v":33,"t":"Dakle, neka svaki od vas ljubi svoju ženu kao samog sebe, a žena neka poštuje svog muža."}]},"6":{"hr":[{"v":1,"t":"Djeco, slušajte svoje roditelje u Gospodinu jer to je pravedno."},{"v":2,"t":"Poštuj oca svoga i majku - to je prva zapovijed s obećanjem:"},{"v":3,"t":"da ti dobro bude i da dugo živiš na zemlji."},{"v":4,"t":"A vi, očevi, ne srdite djece svoje, nego ih odgajajte stegom i urazumljivanjem Gospodnjim!"},{"v":5,"t":"Robovi, slušajte svoje zemaljske gospodare kao Krista - sa strahom i trepetom, u jednostavnosti srca."},{"v":6,"t":"Ne naoko, kao oni koji se ulaguju ljudima, nego kao sluge Kristove koje zdušno vrše volju Božju;"},{"v":7,"t":"dragovoljno služe - kao Gospodinu, a ne ljudima,"},{"v":8,"t":"znajući da će svatko, bio on rob ili slobodnjak, učini li što dobro, za to dobiti plaću od Gospodina."},{"v":9,"t":"I vi, gospodari, isto se tako vladajte prema njima: kanite se prijetnje, znajući da je i njihov i vaš Gospodar na nebesima i da u njega nema pristranosti."},{"v":10,"t":"Ubuduće jačajte se u Gospodinu i u silnoj snazi njegovoj."},{"v":11,"t":"Obucite svu opremu Božju da se mognete oduprijeti lukavstvima đavlovim."},{"v":12,"t":"Jer nije nam se boriti protiv krvi i mesa, nego protiv Vrhovništava, protiv Vlasti, protiv upravljača ovoga mračnoga svijeta, protiv zlih duhova po nebesima."},{"v":13,"t":"Zbog toga posegnite za svom opremom Božjom da uzmognete odoljeti u dan zli i održati se kada sve nadvladate."},{"v":14,"t":"Držite se dakle! Opašite bedra istinom, obucite oklop pravednosti,"},{"v":15,"t":"potpašite noge spremnošću za evanđelje mira!"},{"v":16,"t":"U svemu imajte uza se štit vjere: njime ćete moći ugasiti ognjene strijele Zloga."},{"v":17,"t":"Uzmite i kacigu spasenja i mač Duha, to jest Riječ Božju."},{"v":18,"t":"Svakovrsnom se molitvom i prošnjom u svakoj prigodi u Duhu molite. Poradi toga i bdijte sa svom ustrajnošću i molitvom za sve svete,"},{"v":19,"t":"i za me, da mi se otvore usta i dade riječ hrabro obznaniti otajstvo evanđelja"},{"v":20,"t":"kojeg sam poslanik u okovima, da se ohrabrim o njemu kako treba govoriti."},{"v":21,"t":"A da i vi znate što je sa mnom, kako mi je, o svemu će vas obavijestiti Tihik, ljubljeni brat i vjerni poslužitelj u Gospodinu."},{"v":22,"t":"Njega šaljem k vama baš zato da znate kako smo i da ohrabri srca vaša."},{"v":23,"t":"Mir braći i ljubav, s vjerom, od Boga Oca i Gospodina Isusa Krista!"},{"v":24,"t":"Milost sa svima koji ljube Gospodina našega Isusa Krista - u neraspadljivosti."}]}},"PHP":{"1":{"hr":[{"v":1,"t":"Pavao i Timotej, sluge Krista Isusa, svima svetima u Kristu Isusu koji su u Filipima, s nadglednicima i poslužiteljima."},{"v":2,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista!"},{"v":3,"t":"Zahvaljujem Bogu svomu kad vas se god sjetim."},{"v":4,"t":"Uvijek se u svakoj svojoj molitvi za vas s radošću molim"},{"v":5,"t":"zbog vašeg udjela u evanđelju od onoga prvog dana sve do sada -"},{"v":6,"t":"uvjeren u ovo: Onaj koji otpoče u vama dobro djelo, dovršit će ga do Dana Krista Isusa."},{"v":7,"t":"I pravo je da tako osjećam o svima vama! Ta ja vas nosim u srcu jer u okovima mojim i u obrani i utvrđivanju evanđelja svi ste vi suzajedničari moje milosti."},{"v":8,"t":"Bog mi je doista svjedok koliko žudim za svima vama srcem Isusa Krista!"},{"v":9,"t":"I molim za ovo: da ljubav vaša sve više i više raste u spoznanju i potpunu pronicanju"},{"v":10,"t":"te mognete prosuditi što je najbolje da budete čisti i besprijekorni za Dan Kristov,"},{"v":11,"t":"puni ploda pravednosti po Isusu Kristu - na slavu i hvalu Božju."},{"v":12,"t":"A hoću da znate, braćo: ovaj se moj udes pače okrenuo u napredovanje evanđelja"},{"v":13,"t":"tako da se moji okovi u Kristu razglasiše u svem pretoriju i među svima drugima,"},{"v":14,"t":"a većina braće u Gospodinu, ohrabrena mojim okovima, još se više usuđuje neustrašivo zboriti Riječ."},{"v":15,"t":"Neki, istina, propovijedaju Krista iz zavisti i nadmetanja, a neki iz dobre volje:"},{"v":16,"t":"ovi iz ljubavi jer znaju da sam ovdje za obranu evanđelja;"},{"v":17,"t":"oni pak Krista navješćuju iz suparništva, neiskreno - misleći da će tako otežati nevolju mojih okova."},{"v":18,"t":"Pa što onda? Samo se na svaki način, bilo himbeno, bilo istinito, Krist navješćuje. I tome se radujem, a i radovat ću se."},{"v":19,"t":"Jer znadem: po vašoj molitvi i pomoći Duha Isusa Krista to će mi biti na spasenje,"},{"v":20,"t":"kako željno i očekujem i nadam se da se ni zbog čega neću smesti, nego da će se mojom posvemašnjom odvažnošću - kako uvijek tako i sada - Krist uzveličati u mome tijelu, bilo životom, bilo smrću."},{"v":21,"t":"Ta meni je živjeti Krist, a umrijeti dobitak!"},{"v":22,"t":"A ako mi živjeti u tijelu omogućuje plodno djelovanje, što da odaberem? Ne znam!"},{"v":23,"t":"Pritiješnjen sam od ovoga dvoga: želja mi je otići i s Kristom biti jer to je mnogo, mnogo bolje;"},{"v":24,"t":"ali ostati u tijelu potrebnije je poradi vas."},{"v":25,"t":"U to uvjeren, znam da ću ostati i biti uz vas sve, za vaš napredak i na radost vjere,"},{"v":26,"t":"da ponos vaš mnome poraste u Kristu Isusu kad opet dođem k vama."},{"v":27,"t":"Samo se ponašajte dostojno evanđelja Kristova, pa - došao ja i vidio vas ili nenazočan slušao što je s vama - da mogu utvrditi kako ste postojani u jednome duhu i jednodušno se zajednički borite za evanđeosku vjeru"},{"v":28,"t":"ne plašeći se ni u čemu protivnika. To je njima najava njihove propasti, a vašega spasenja, i to od Boga."},{"v":29,"t":"Jer vama je dana milost: “za Krista”, ne samo u njega vjerovati nego za njega i trpjeti,"},{"v":30,"t":"isti boj bijući koji na meni vidjeste i sada o meni čujete."}]},"2":{"hr":[{"v":1,"t":"Ima li dakle u Kristu kakve utjehe, ima li kakva ljubazna bodrenja, ima li kakva zajedništva Duha, ima li kakva srca i samilosti,"},{"v":2,"t":"ispunite me radošću: složni budite, istu ljubav njegujte, jednodušni, jedne misli budite;"},{"v":3,"t":"nikakvo suparništvo ni umišljenost, nego - u poniznosti jedni druge smatrajte višima od sebe;"},{"v":4,"t":"ne starajte se samo svaki za svoje, nego i za ono što se tiče drugih!"},{"v":5,"t":"Neka u vama bude isto mišljenje kao i u Kristu Isusu:"},{"v":6,"t":"On, trajni lik Božji, nije se kao plijena držao svoje jednakosti s Bogom,"},{"v":7,"t":"nego sam sebe “oplijeni” uzevši lik sluge, postavši ljudima sličan; obličjem čovjeku nalik,"},{"v":8,"t":"ponizi sam sebe, poslušan do smrti, smrti na križu."},{"v":9,"t":"Zato Bog njega preuzvisi i darova mu ime, ime nad svakim imenom,"},{"v":10,"t":"da se na ime Isusovo prigne svako koljeno nebesnika, zemnika i podzemnika."},{"v":11,"t":"I svaki će jezik priznati: “Isus Krist jest Gospodin!” - na slavu Boga Oca."},{"v":12,"t":"Tako, ljubljeni moji, poslušni kako uvijek bijaste, ne samo kao ono za moje nazočnosti nego mnogo više sada, za moje nenazočnosti, sa strahom i trepetom radite oko svoga spasenja!"},{"v":13,"t":"Da, Bog u svojoj dobrohotnosti izvodi u vama i htjeti i djelovati."},{"v":14,"t":"Sve činite bez mrmljanja i oklijevanja"},{"v":15,"t":"da budete besprijekorni i čisti, djeca Božja neporočna posred poroda izopačena i lukava u kojem svijetlite kao svjetlila u svijetu"},{"v":16,"t":"držeći riječ Života meni na ponos za Dan Kristov, što nisam zaludu trčao niti se zaludu trudio."},{"v":17,"t":"Naprotiv, ako se ja i izlijevam za žrtvu i bogoslužje, za vjeru vašu, radostan sam i radujem se sa svima vama."},{"v":18,"t":"A tako i vi budite radosni i radujte se sa mnom."},{"v":19,"t":"Nadam se u Gospodinu Isusu da ću vam uskoro poslati Timoteja da mi odlane kad saznam što je s vama."},{"v":20,"t":"Nikoga doista nemam tako srodne duše tko bi se kao on svojski za vas pobrinuo"},{"v":21,"t":"jer svi traže svoje, a ne ono što je Isusa Krista."},{"v":22,"t":"A prokušanost vam je njegova poznata: kao dijete s ocem služio je sa mnom evanđelju."},{"v":23,"t":"Njega se dakle nadam poslati tek što razvidim što je sa mnom."},{"v":24,"t":"A uvjeren sam u Gospodinu da ću i sam uskoro doći."},{"v":25,"t":"Smatrao sam potrebnim poslati k vama Epafrodita, brata, suradnika i suborca moga kojega ste poslali da mi poslužuje u potrebi."},{"v":26,"t":"Jer je čeznuo za svima vama i bio zabrinut što ste saznali da je obolio."},{"v":27,"t":"I doista je gotovo na smrt bio obolio, ali Bog mu se smilovao, ne samo njemu nego i meni, da me ne zadesi žalost na žalost."},{"v":28,"t":"Brže ga dakle poslah da se, pošto ga vidite, opet obradujete, i ja da budem manje žalostan."},{"v":29,"t":"Primite ga dakle u Gospodinu sa svom radosti i poštujte takve"},{"v":30,"t":"jer se za djelo Kristovo smrti sasvim približio, životnoj se pogibli izložio da nadopuni ono u čemu me vi ne mogoste poslužiti."}]},"3":{"hr":[{"v":1,"t":"Uostalom, braćo moja, radujte se u Gospodinu! Pisati vam jedno te isto meni nije dosadno, a za vas je sigurnije."},{"v":2,"t":"Čuvajte se tih pasa, čuvajte se tih opakih radnika, čuvajte se te osakaćenosti!"},{"v":3,"t":"Jer mi smo obrezanje, mi koji u Duhu Božjemu obavljamo bogoslužje i dičimo se Kristom Isusom, a ne pouzdajemo se u tijelo,"},{"v":4,"t":"iako bih se ja mogao pouzdati i u tijelo. Smatra li tko drugi da se može uzdati u tijelo, ja još više:"},{"v":5,"t":"obrezan osmog dana, od roda sam Izraelova, plemena Benjaminova, Hebrej od Hebreja; po Zakonu farizej,"},{"v":6,"t":"po revnosti progonitelj Crkve, po pravednosti zakonskoj besprijekoran."},{"v":7,"t":"Ali što mi god bijaše dobitak, to poradi Krista smatram gubitkom."},{"v":8,"t":"Štoviše, čak sve gubitkom smatram zbog onoga najizvrsnijeg, zbog spoznanja Isusa Krista, Gospodina mojega, radi kojega sve izgubih i otpadom smatram: da Krista steknem"},{"v":9,"t":"i u njemu se nađem - ne svojom pravednošću, onom od Zakona, nego pravednošću po vjeri u Krista, onom od Boga, na vjeri utemeljenoj -"},{"v":10,"t":"da upoznam njega i snagu uskrsnuća njegova i zajedništvo u patnjama njegovim,"},{"v":11,"t":"ne bih li kako, suobličen smrti njegovoj, prispio k uskrsnuću od mrtvih."},{"v":12,"t":"Ne kao da sam već postigao ili dopro do savršenstva, nego - hitim ne bih li kako dohvatio jer sam i zahvaćen od Krista."},{"v":13,"t":"Braćo, ja nipošto ne smatram da sam već dohvatio. Jedno samo: što je za mnom, zaboravljam, za onim što je preda mnom, prežem,"},{"v":14,"t":"k cilju hitim, k nagradi višnjeg poziva Božjeg u Kristu Isusu."},{"v":15,"t":"Koji smo god zreli, ovako mislimo! I ako što drukčije mislite, Bog će vam ovako objaviti."},{"v":16,"t":"Samo, držimo se onoga do čega smo stigli!"},{"v":17,"t":"Braćo! Nasljedovatelji moji budite i promatrajte one koji žive po uzoru koji imate u nama."},{"v":18,"t":"Jer često sam vam govorio, a sada i plačući govorim: mnogi žive kao neprijatelji križa Kristova."},{"v":19,"t":"Svršetak im je propast, bog im je trbuh, slava u sramoti - jer misle na zemaljsko."},{"v":20,"t":"Naša je pak domovina na nebesima, odakle iščekujemo Spasitelja, Gospodina našega Isusa Krista:"},{"v":21,"t":"snagom kojom ima moć sve sebi podložiti on će preobraziti ovo naše bijedno tijelo i suobličiti ga tijelu svomu slavnomu."}]},"4":{"hr":[{"v":1,"t":"Stoga, braćo moja ljubljena i željkovana, radosti moja i vijenče moj, tako - čvrsto stojte u Gospodinu."},{"v":2,"t":"Evodiju zaklinjem, i Sintihu zaklinjem da budu složne u Gospodinu."},{"v":3,"t":"Da, molim i tebe, čestiti druže, pomaži im jer su se one u evanđelju borile zajedno sa mnom, i s Klementom i ostalim mojim suradnicima, kojih su imena u knjizi Života."},{"v":4,"t":"Radujte se u Gospodinu uvijek! Ponavljam: radujte se!"},{"v":5,"t":"Blagost vaša neka je znana svim ljudima! Gospodin je blizu!"},{"v":6,"t":"Ne budite zabrinuti ni za što, nego u svemu - molitvom i prošnjom, sa zahvaljivanjem - očitujte svoje molbe Bogu."},{"v":7,"t":"I mir Božji koji je iznad svakog razuma čuvat će srca vaša i vaše misli u Kristu Isusu."},{"v":8,"t":"Uostalom, braćo, što je god istinito, što god časno, što god pravedno, što god čisto, što god ljubazno, što god hvalevrijedno; je li što krepost, je li što pohvala - to nek vam je na srcu!"},{"v":9,"t":"Što ste naučili, i primili, i čuli, i vidjeli na meni - to činite i Bog mira bit će s vama!"},{"v":10,"t":"Uvelike se obradovah u Gospodinu što ste napokon procvali te mislite na me; mislili ste i prije, ali niste imali prigode."},{"v":11,"t":"Govorim to ne zbog oskudice, ta naučen sam u svakoj prigodi biti zadovoljan."},{"v":12,"t":"Znam i oskudijevati, znam i obilovati! Na sve sam i na svašta navikao: i sit biti i gladovati, i obilovati i oskudijevati."},{"v":13,"t":"Sve mogu u Onome koji me jača!"},{"v":14,"t":"Ipak, lijepo je od vas što sa mnom podijeliste moju nevolju."},{"v":15,"t":"A i vi, Filipljani, znate: u početku evanđelja, kad otputovah iz Makedonije, nijedna mi se Crkva nije pridružila u pogledu izdataka i primitaka, doli vi jedini."},{"v":16,"t":"Čak ste mi i u Solun i jednom, i dvaput, za potrebe poslali."},{"v":17,"t":"Ne, ne tražim dara; tražim samo plod izobilan u vašu korist."},{"v":18,"t":"Imam svega i u izobilju; namiren sam otkad po Epafroditu primih ono od vas, miris ugodan, žrtvu milu, ugodnu Bogu."},{"v":19,"t":"A Bog moj ispunit će svaku vašu potrebu po bogatstvu svome, veličanstveno, u Kristu Isusu."},{"v":20,"t":"Bogu pak, Ocu našemu, slava u vijeke vjekova! Amen."},{"v":21,"t":"Pozdravite svakoga svetog u Kristu Isusu. Pozdravljaju vas braća koja su sa mnom."},{"v":22,"t":"Pozdravljaju vas svi sveti, ponajpače oni iz careva dvora."},{"v":23,"t":"Milost Gospodina Isusa Krista s duhom vašim!"}]}},"COL":{"1":{"hr":[{"v":1,"t":"Pavao, po volji Božjoj apostol Krista Isusa, i brat Timotej:"},{"v":2,"t":"Kološanima, svetoj i vjernoj braći u Kristu. Milost vam i mir od Boga, Oca našega!"},{"v":3,"t":"Zahvaljujemo Bogu, Ocu Gospodina našega Isusa Krista, svagda za vas moleći."},{"v":4,"t":"Jer čuli smo za vašu vjeru u Kristu Isusu i za ljubav koju gajite prema svima svetima"},{"v":5,"t":"poradi nade koja vam je pohranjena u nebesima. Za nju ste već čuli u Riječi istine -"},{"v":6,"t":"evanđelju koje je do vas doprlo te plodove nosi i raste, kao što po svem svijetu, tako i među vama od dana kad ste čuli i spoznali milost Božju po istini,"},{"v":7,"t":"kako ste naučili od ljubljenog Epafre, sluge zajedno s nama; on je umjesto nas, vjeran poslužitelj Kristov,"},{"v":8,"t":"on nas je i obavijestio o vašoj ljubavi u Duhu."},{"v":9,"t":"Zato i mi, od dana kada to čusmo, neprestano za vas molimo i ištemo da se ispunite spoznajom volje Njegove u svoj mudrosti i shvaćanju duhovnome:"},{"v":10,"t":"da živite dostojno Gospodina i posve mu ugodite, plodni svakim dobrim djelom i rastući u spoznaji Božjoj;"},{"v":11,"t":"osnaženi svakom snagom, po sili Slave njegove, za svaku postojanost i strpljivost;"},{"v":12,"t":"s radošću zahvaljujući Ocu koji vas osposobi za dioništvo u baštini svetih u svjetlosti."},{"v":13,"t":"On nas izbavi iz vlasti tame i prenese u kraljevstvo Sina, ljubavi svoje,"},{"v":14,"t":"u kome imamo otkupljenje, otpuštenje grijeha."},{"v":15,"t":"On je slika Boga nevidljivoga, Prvorođenac svakog stvorenja."},{"v":16,"t":"Ta u njemu je sve stvoreno na nebesima i na zemlji, vidljivo i nevidljivo, bilo Prijestolja, bilo Gospodstva, bilo Vrhovništva, bilo Vlasti - sve je po njemu i za njega stvoreno:"},{"v":17,"t":"on je prije svega i sve stoji u njemu."},{"v":18,"t":"On je Glava Tijela, Crkve; on je Početak, Prvorođenac od mrtvih, da u svemu bude Prvak."},{"v":19,"t":"Jer svidjelo se Bogu u njemu nastaniti svu Puninu"},{"v":20,"t":"i po njemu - uspostavivši mir krvlju križa njegova - izmiriti sa sobom sve, bilo na zemlji, bilo na nebesima."},{"v":21,"t":"I vas, nekoć po zlim djelima udaljene i neprijateljski raspoložene,"},{"v":22,"t":"sada u ljudskom tijelu Kristovu, po smrti, sa sobom izmiri da vas k sebi privede svete, bez mane i besprigovorne."},{"v":23,"t":"Samo ako ostanete u vjeri utemeljeni, stalni i nepoljuljani u nadi evanđelja koje čuste, koje se propovijeda svakom stvorenju pod nebom, a ja mu, Pavao, postadoh poslužiteljem."},{"v":24,"t":"Radujem se sada dok trpim za vas i u svom tijelu dopunjam što nedostaje mukama Kristovim za Tijelo njegovo, za Crkvu."},{"v":25,"t":"Njoj ja postadoh poslužiteljem po rasporedbi Božjoj koja mi je dana za vas da potpuno pronesem Riječ Božju -"},{"v":26,"t":"otajstvo pred vjekovima i pred naraštajima skriveno, a sada očitovano svetima njegovim."},{"v":27,"t":"Njima Bog htjede obznaniti kako li je slavom bogato to otajstvo među poganima: to jest Krist u vama, nada slave!"},{"v":28,"t":"Njega mi navješćujemo, opominjući svakoga čovjeka, poučavajući svakoga čovjeka u svoj mudrosti da bismo svakoga čovjeka doveli do savršenstva u Kristu."},{"v":29,"t":"Za to se i trudim i borim njegovom djelotvornošću koja u meni snažno djeluje."}]},"2":{"hr":[{"v":1,"t":"Htio bih uistinu da znate koliko mi se boriti za vas, za one u Laodiceji i za sve koji me nisu vidjeli licem u lice:"},{"v":2,"t":"da se ohrabre srca njihova, povezana u ljubavi, te se vinu do svega bogatstva, punine shvaćanja, do spoznanja otajstva Božjega - Krista,"},{"v":3,"t":"u kojem su sva bogatstva mudrosti i spoznaje skrivena."},{"v":4,"t":"To govorim zato da vas tko ne prevari zavodljivim riječima."},{"v":5,"t":"Jer ako sam tijelom nenazočan, duhom sam ipak s vama: s radošću promatram vaš red i čvrstoću vaše vjere u Krista."},{"v":6,"t":"Kao što primiste Krista Isusa, Gospodina, tako u njemu živite:"},{"v":7,"t":"ukorijenjeni i nazidani na njemu i učvršćeni vjerom kako ste poučeni, obilujte zahvaljivanjem."},{"v":8,"t":"Pazite da vas tko ne odvuče mudrovanjem i ispraznim zavaravanjem što se oslanja na predaju ljudsku, na “počela svijeta”, a ne na Krista."},{"v":9,"t":"Jer u njemu tjelesno prebiva sva punina božanstva; te ste i vi"},{"v":10,"t":"ispunjeni u njemu, koji je glava svakoga Vrhovništva i Vlasti."},{"v":11,"t":"U njemu ste i obrezani obrezanjem nerukotvorenim - svukoste tijelo puteno - obrezanjem Kristovim:"},{"v":12,"t":"s njime suukopani u krštenju, u njemu ste i suuskrsli po vjeri u snagu Boga koji ga uskrisi od mrtvih."},{"v":13,"t":"On i vas, koji bijaste mrtvi zbog prijestupa i neobrezanosti svoga tijela, i vas on oživi zajedno s njime. Milostivo nam je oprostio sve prijestupe,"},{"v":14,"t":"izbrisao zadužnicu koja propisima bijaše protiv nas, protivila nam se. Nju on ukloni pribivši je na križ."},{"v":15,"t":"Skinu Vrhovništva i Vlasti, javno to pokaza: u pobjedničkoj ih povorci s njime vodi."},{"v":16,"t":"Neka vas dakle nitko ne sudi po jelu ili po piću, po blagdanima, mlađacima ili subotama."},{"v":17,"t":"To je tek sjena onoga što dolazi, a zbiljnost jest - tijelo Kristovo."},{"v":18,"t":"Nitko neka vas ne podcjenjuje zato što on sam uživa u “poniznosti i štovanju anđela”, zadubljuje se u svoja viđenja, bezrazložno se nadima tjelesnom pameću svojom,"},{"v":19,"t":"a ne drži se Glave, Njega od kojeg sve Tijelo, zglobovima i svezama zbrinuto i povezano, raste rastom Božjim."},{"v":20,"t":"Ako ste s Kristom umrli za počela svijeta, zašto se, kao da još u ovom svijetu živite, dajete pod propise:"},{"v":21,"t":"“Ne diraj, ne kušaj, ne dotiči”?"},{"v":22,"t":"Sve će to uporabom propasti. Uredbe i nauci ljudski!"},{"v":23,"t":"Po samozvanu bogoštovlju, poniznosti i trapljenju tijela sve to doduše slovi kao mudrost, ali nema nikakve vrijednosti, samo zasićuje tijelo."}]},"3":{"hr":[{"v":1,"t":"Ako ste suuskrsli s Kristom, tražite što je gore, gdje Krist sjedi zdesna Bogu!"},{"v":2,"t":"Za onim gore težite, ne za zemaljskim!"},{"v":3,"t":"Ta umrijeste i život je vaš skriven s Kristom u Bogu!"},{"v":4,"t":"Kad se pojavi Krist, život vaš, tada ćete se i vi s njime pojaviti u slavi."},{"v":5,"t":"Umrtvite dakle udove svoje zemaljske: bludnost, nečistoću, strasti, zlu požudu i pohlepu - to idolopoklonstvo!"},{"v":6,"t":"Zbog toga dolazi gnjev Božji na sinove neposlušne."},{"v":7,"t":"Tim ste putom i vi nekoć hodili, kad ste u tome živjeli."},{"v":8,"t":"Ali sada i vi odložite sve! Gnjev, srdžba, opakost, hula, prostota van iz vaših usta!"},{"v":9,"t":"Ne varajte jedni druge! Jer svukoste staroga čovjeka s njegovim djelima"},{"v":10,"t":"i obukoste novoga, koji se obnavlja za spoznanje po slici svoga Stvoritelja!"},{"v":11,"t":"Tu više nema: Grk - Židov, obrezanje - neobrezanje, barbar - skit, rob - slobodnjak, nego sve i u svima - Krist."},{"v":12,"t":"Zaodjenite se dakle - kao izabranici Božji, sveti i ljubljeni - u milosrdno srce, dobrostivost, poniznost, blagost, strpljivost"},{"v":13,"t":"te podnosite jedni druge praštajući ako tko ima protiv koga kakvu pritužbu! Kao što je Gospodin vama oprostio, tako i vi!"},{"v":14,"t":"A povrh svega - ljubav! To je sveza savršenstva."},{"v":15,"t":"I mir Kristov neka upravlja srcima vašim - mir na koji ste pozvani u jednom tijelu! I zahvalni budite!"},{"v":16,"t":"Riječ Kristova neka u svem bogatstvu prebiva u vama! U svakoj se mudrosti poučavajte i urazumljujte! Psalmima, hvalospjevima, pjesmama duhovnim od srca pjevajte hvalu Bogu!"},{"v":17,"t":"I sve što god riječju ili djelom činite, sve činite u imenu Gospodina Isusa, zahvaljujući Bogu Ocu po njemu!"},{"v":18,"t":"Žene, pokoravajte se svojim muževima kao što dolikuje u Gospodinu!"},{"v":19,"t":"Muževi, ljubite svoje žene i ne budite osorni prema njima."},{"v":20,"t":"Djeco, slušajte roditelje u svemu, ta to je milo u Gospodinu!"},{"v":21,"t":"Očevi, ne ogorčujte svoje djece da ne klonu duhom."},{"v":22,"t":"Robovi, slušajte u svemu svoje zemaljske gospodare! Ne naoko, kao oni koji se ulaguju ljudima, nego u jednostavnosti srca, bojeći se Gospodina."},{"v":23,"t":"Što god radite, zdušno činite, kao Gospodinu, a ne ljudima,"},{"v":24,"t":"znajući da ćete od Gospodina primiti nagradu, baštinu. Gospodinu Kristu služite."},{"v":25,"t":"Doista, nepravedniku će se uzvratiti što je nepravedno učinio. Ne, nema pristranosti!"}]},"4":{"hr":[{"v":1,"t":"Gospodari, pružajte svojim robovima što je pravo i pravično, znajući da i vi imate Gospodina na nebu!"},{"v":2,"t":"U molitvi ustrajte, bdijte u njoj u zahvaljivanju!"},{"v":3,"t":"Molite ujedno i za nas: da nam Bog otvori vrata riječi te propovijedamo otajstvo Kristovo, za koje sam i okovan;"},{"v":4,"t":"da ga očitujem propovijedajući kako treba."},{"v":5,"t":"Mudro se ponašajte prema onima vani: iskupljujte vrijeme!"},{"v":6,"t":"Riječ neka vam je uvijek ljubazna, solju začinjena: znajte svakomu odgovoriti kako treba."},{"v":7,"t":"Što je sa mnom - o svemu će vas obavijestiti Tihik, ljubljeni brat, vjerni poslužitelj i sa mnom sluga u Gospodinu."},{"v":8,"t":"Njega šaljem k vama baš zato da znate kako smo i da ohrabri srca vaša."},{"v":9,"t":"Šaljem ga s Onezimom, vjernim i ljubljenim bratom, koji je vaš zemljak: oni će vam priopćiti kako je ovdje."},{"v":10,"t":"Pozdravlja vas Aristarh, suuznik moj. I Marko, nećak Barnabin, o kome primiste naredbe: dođe li k vama, lijepo ga primite."},{"v":11,"t":"Pozdravlja vas i Isus, zvani Just. Od onih koji su iz obrezanja samo su mi ovi suradnici na kraljevstvu Božjemu, oni mi bijahu utjehom."},{"v":12,"t":"Pozdravlja vas Epafra, vaš zemljak, sluga Krista Isusa; on se uvijek bori za vas u molitvama: da se održite, savršeni i ispunjeni, u posvemašnjoj volji Božjoj."},{"v":13,"t":"Svjedočim doista za nj: mnogo se trudi za vas i za one u Laodiceji i one u Hierapolu."},{"v":14,"t":"Pozdravlja vas Luka, ljubljeni liječnik, i Dema."},{"v":15,"t":"Pozdravite braću u Laodiceji, i Nimfu i Crkvu u njezinoj kući."},{"v":16,"t":"A kad se ova poslanica pročita kod vas, pobrinite se da se pročita i u Laodicejskoj crkvi, i vi da pročitate onu iz Laodiceje."},{"v":17,"t":"I recite Arhipu: “Pazi na službu koju si primio u Gospodinu: ispuni je!”"},{"v":18,"t":"Pozdrav mojom rukom, Pavlovom! Spominjite se mojih okova! Milost s vama!"}]}},"1TH":{"1":{"hr":[{"v":1,"t":"Pavao, Silvan i Timotej Crkvi Solunjana u Bogu Ocu i Gospodinu Isusu Kristu. Milost vam i mir!"},{"v":2,"t":"Zahvaljujemo uvijek Bogu za sve vas i bez prestanka vas se sjećamo u svojim molitvama"},{"v":3,"t":"spominjući se vaše djelotvorne vjere, zauzete ljubavi i postojane nade u Gospodinu našem Isusu Kristu, pred Bogom i Ocem našim."},{"v":4,"t":"Svjesni smo, braćo od Boga ljubljena, vašeg izabranja"},{"v":5,"t":"jer evanđelje naše nije k vama došlo samo u riječi nego i u snazi, u Duhu Svetome i mnogostrukoj punini. Takvi smo, kao što znate, poradi vas među vama bili."},{"v":6,"t":"I vi postadoste nasljedovatelji naši i Gospodinovi: sve u nevolji mnogoj prigrliste Riječ s radošću Duha Svetoga"},{"v":7,"t":"tako da postadoste uzorom svim vjernicima u Makedoniji i Ahaji."},{"v":8,"t":"Od vas je doista ne samo riječ Gospodnja odjeknula po Makedoniji i Ahaji, nego se i vaša vjera u Boga posvuda tako proširila te nije potrebno da o tome govorimo."},{"v":9,"t":"Oni sami o nama pripovijedaju: kako dođosmo k vama, kako se od idola obratiste k Bogu da biste služili Bogu živomu i istinskomu"},{"v":10,"t":"i iščekivali s nebesa Sina njegova koga uskrisi od mrtvih, Isusa koji nas izbavlja od gnjeva što dolazi."}]},"2":{"hr":[{"v":1,"t":"Sami doista znate, braćo: naš dolazak k vama nije bio uzaludan."},{"v":2,"t":"Naprotiv, i pošto smo, kako znate, u Filipima trpjeli i bili pogrđeni, odvažismo se u Bogu našemu iznijeti vam, uz tešku borbu, evanđelje Božje."},{"v":3,"t":"Uistinu, naše poticanje ne proistječe iz zablude, ni nečistoće, ni prijevare,"},{"v":4,"t":"nego kako je Bog prosudio povjeriti nam evanđelje, tako ga i navješćujemo - ne kao da želimo ugoditi ljudima, nego Bogu koji prosuđuje srca naša."},{"v":5,"t":"Nikada se zaista kako znate, ne poslužismo ni laskavom riječju ni - Bog nam je svjedok - prikrivenom pohlepom."},{"v":6,"t":"Niti smo od ljudi iskali slavu - ni od vas, ni od drugih -"},{"v":7,"t":"premda smo se mogli nametnuti kao Kristovi apostoli. Ali bili smo među vama nježni kao majka što hrani i njeguje svoju djecu."},{"v":8,"t":"Tako, puni ljubavi prema vama, htjedosmo vam predati ne samo evanđelje Božje nego i naše duše jer ste nam omiljeli."},{"v":9,"t":"Sjećate se doista, braćo, našega truda i napora. Propovijedali smo vam evanđelje Božje i radili noću i danju da ne bismo opteretili koga od vas."},{"v":10,"t":"Svjedoci ste vi i Bog kako smo se sveto, pravedno i besprijekorno vladali prema vama, vjernicima."},{"v":11,"t":"Kao što znate, svakoga smo od vas kao otac svoju djecu,"},{"v":12,"t":"poticali, sokolili i zaklinjali da živite dostojno Boga koji vas pozva u svoje kraljevstvo i slavu."},{"v":13,"t":"Zato, eto, i mi bez prestanka zahvaljujemo Bogu što ste, kad od nas primiste riječ poruke Božje, primili ne riječ ljudsku, nego kakva uistinu jest, riječ Božju koja i djeluje u vama, vjernicima."},{"v":14,"t":"Doista, vi ste, braćo, postali nasljedovatelji crkava Božjih koje su u Judeji u Kristu Isusu: i vi isto trpite od svojih suplemenika što i oni od Židova,"},{"v":15,"t":"koji su i Gospodina Isusa i proroke ubili, i nas progonili, te Bogu ne ugađaju i svim se ljudima protive"},{"v":16,"t":"kad nam priječe propovijedati poganima da se spase, da bi tako u svako vrijeme navršili mjeru zlodjela svojih. Ali sručio se na njih konačni gnjev."},{"v":17,"t":"A mi, braćo, pošto smo za kratko vrijeme ostali bez vas - licem, ne srcem - brže se bolje, u silnoj čežnji, požurismo ugledati vaše lice."},{"v":18,"t":"Zaista, htjedosmo k vama - ja, Pavao, i jednom i dvaput - ali nas je spriječio Sotona."},{"v":19,"t":"Ta tko li će biti naša nada, radost ili vijenac dični - zar možda ne i vi? - pred Gospodinom našim Isusom o njegovu Dolasku?"},{"v":20,"t":"Vi ste doista slava naša i radost!"}]},"3":{"hr":[{"v":1,"t":"Zato kad više ne mogosmo izdržati, pristadosmo ostati u Ateni sami"},{"v":2,"t":"te poslasmo Timoteja, brata našega i suradnika Božjega u Kristovu evanđelju, da vas učvrsti i ohrabri u vjeri"},{"v":3,"t":"da se nitko ne pokoleba u tim nevoljama. Ta i sami znate da smo za to određeni:"},{"v":4,"t":"doista, kad smo bili kod vas, pretkazivali smo kako nas imaju zadesiti nevolje, što se, kako znate, i dogodilo."},{"v":5,"t":"Zbog toga i ja, ne mogavši više izdržati, poslah da saznam o vašoj vjeri, da vas možda Zavodnik nije zaveo te je naš trud postao uzaludan."},{"v":6,"t":"A sada kad se Timotej od vas k nama vratio i donio nam radosnu vijest o vašoj vjeri i ljubavi, i da nas se sveudilj ugodno sjećate i čeznete vidjeti nas, kao i mi vas -"},{"v":7,"t":"zbog toga smo, braćo, nad vama, vašom vjerom, bili utješeni uza svu svoju tjeskobu i nevolju."},{"v":8,"t":"Da, sada živimo kada ste vi postojani u Gospodinu!"},{"v":9,"t":"I kojom bismo zahvalom mogli Bogu uzvratiti za vas, za svu radost kojom se zbog vas radujemo pred Bogom svojim,"},{"v":10,"t":"dok noću i danju najusrdnije molimo da vidimo vaše lice i nadoknadimo manjkavosti vaše vjere?"},{"v":11,"t":"A sam Bog i Otac naš i Gospodin naš Isus upravio naš put prema vama!"},{"v":12,"t":"Vama pak Gospodin dao te jedni prema drugima i prema svima rasli i obilovali ljubavlju kakva je i naša prema vama."},{"v":13,"t":"Učvrstio vam srca da budu besprijekorno sveta pred Bogom i Ocem našim o Dolasku Gospodina našega Isusa i svih svetih njegovih s njime."}]},"4":{"hr":[{"v":1,"t":"Uostalom, braćo, molimo vas i zaklinjemo u Gospodinu Isusu: primili ste od nas kako treba da živite da biste ugodili Bogu. Vi tako i živite pa sve više napredujete!"},{"v":2,"t":"Ta znate koje smo vam zapovijedi dali u Gospodinu Isusu."},{"v":3,"t":"Doista, ovo je volja Božja: vaše posvećenje - da se uzdržavate od bludnosti,"},{"v":4,"t":"da svatko od vas zna svoje tijelo posjedovati u svetosti i poštovanju,"},{"v":5,"t":"a ne u pohotnoj strasti kao pogani koji ne poznaju Boga,"},{"v":6,"t":"pa time ne prikraćivati i varati svoga brata. Jer Gospodin je osvetnik za sve to, kao što vam već rekosmo i posvjedočismo."},{"v":7,"t":"Bog nas, doista, nije pozvao na nečistoću, nego na svetost."},{"v":8,"t":"Prema tome, tko to odbacuje, ne odbacuje čovjeka nego Boga koji svoga Duha Svetoga udahnjuje u vas."},{"v":9,"t":"A o bratoljublju vam nije potrebno pisati. Ta i sami ste od Boga naučili ljubiti jedni druge,"},{"v":10,"t":"a to doista i činite prema svoj braći u cijeloj Makedoniji. Samo vas, braćo, potičemo da u tom još više uznapredujete"},{"v":11,"t":"pa da se trsite mirno živjeti, svoje činiti i raditi svojim rukama, kako smo vam zapovijedili,"},{"v":12,"t":"te tako časno živite prema onima vani i nikoga ne trebate."},{"v":13,"t":"Nećemo da budete u neznanju, braćo, o onima koji su usnuli, da ne tugujete kao drugi koji nemaju nade."},{"v":14,"t":"Doista, ako vjerujemo da je Isus umro i uskrsnuo, onda će Bog i one koji usnuše u Isusu, privesti zajedno s njime."},{"v":15,"t":"Ovo vam uistinu velimo po riječi Gospodnjoj: mi živi, preostali za Dolazak Gospodnji, nećemo preteći onih koji su usnuli."},{"v":16,"t":"Jer sam će Gospodin - na zapovijed, na glas arkanđelov, na zov trublje Božje - sići s neba. I najprije će uskrsnuti mrtvi u Kristu,"},{"v":17,"t":"a zatim ćemo mi živi, preostali, zajedno s njima biti poneseni na oblacima u susret Gospodinu, u zrak. I tako ćemo uvijek biti s Gospodinom."},{"v":18,"t":"Tješite se dakle uzajamno ovim riječima!"}]},"5":{"hr":[{"v":1,"t":"A o vremenima i trenucima nije, braćo, potrebno pisati vam."},{"v":2,"t":"Ta i sami dobro znate da Dan Gospodnji dolazi baš kao kradljivac u noći."},{"v":3,"t":"Dok još budu govorili: “Mir i sigurnost”, zadesit će ih iznenadna propast kao trudovi trudnicu i neće umaći."},{"v":4,"t":"Ali vi, braćo, niste u tami, da bi vas Dan mogao zaskočiti kao kradljivac:"},{"v":5,"t":"ta svi ste vi sinovi svjetlosti i sinovi dana. Nismo doista od noći ni od tame."},{"v":6,"t":"Onda i ne spavajmo kao ostali, nego bdijmo i trijezni budimo."},{"v":7,"t":"Jer koji spavaju, noću spavaju; i koji se opijaju, noću se opijaju."},{"v":8,"t":"A mi koji smo od dana, budimo trijezni, obucimo oklop vjere i ljubavi i stavimo kacigu, nadu spasenja!"},{"v":9,"t":"Ta Bog nas nije odredio za gnjev, nego da imamo spasenje po Gospodinu našem Isusu Kristu,"},{"v":10,"t":"koji je za nas umro da - bdjeli ili spavali - zajedno s njime živimo."},{"v":11,"t":"Zato, tješite se uzajamno i izgrađujte jedan drugoga, kako i činite."},{"v":12,"t":"Molimo vas, braćo: priznajte one koji se trude među vama, koji su vam predstojnici u Gospodinu i opominju vas;"},{"v":13,"t":"s ljubavlju ih nadasve cijenite poradi njihova djela! Gajite mir među sobom!"},{"v":14,"t":"Potičemo vas, braćo: opominjite neuredne, sokolite malodušne, podržavajte slabe, budite velikodušni prema svima!"},{"v":15,"t":"Pazite da tko komu zlo zlom ne uzvrati, nego uvijek promičite dobro jedni prema drugima i prema svima."},{"v":16,"t":"Uvijek se radujte!"},{"v":17,"t":"Bez prestanka se molite!"},{"v":18,"t":"U svemu zahvaljujte! Jer to je za vas volja Božja u Kristu Isusu."},{"v":19,"t":"Duha ne trnite,"},{"v":20,"t":"proroštava ne prezirite!"},{"v":21,"t":"Sve provjeravajte: dobro zadržite,"},{"v":22,"t":"svake se sjene zla klonite!"},{"v":23,"t":"A sam Bog mira neka vas posvema posveti i cijelo vaše biće - duh vaš i duša i tijelo - neka se besprijekornim, savršenim sačuva za Dolazak Gospodina našega Isusa Krista."},{"v":24,"t":"Vjeran je Onaj tko vas poziva: on će to i učiniti."},{"v":25,"t":"Braćo, molite i za nas!"},{"v":26,"t":"Pozdravite svu braću cjelovom svetim."},{"v":27,"t":"Zaklinjem vas u Gospodinu: neka se ova poslanica pročita svoj braći."},{"v":28,"t":"Milost Gospodina našega Isusa Krista s vama!"}]}},"2TH":{"1":{"hr":[{"v":1,"t":"Pavao, Silvan i Timotej Crkvi Solunjana u Bogu Ocu našemu i Gospodinu Isusu Kristu."},{"v":2,"t":"Milost vam i mir od Boga Oca i Gospodina Isusa Krista!"},{"v":3,"t":"Zahvaljivati moramo Bogu uvijek za vas, braćo, kao što dolikuje jer izvanredno raste vaša vjera i množi se ljubav svakoga od vas prema drugima,"},{"v":4,"t":"tako da se mi sami po crkvama Božjim vama ponosimo zbog vaše postojanosti i vjere u svim progonstvima i nevoljama koje podnosite."},{"v":5,"t":"One su najava pravednog Suda Božjega: da ćete se naći dostojni kraljevstva Božjega za koje i trpite."},{"v":6,"t":"Jer pravo je da Bog vašim mučiteljima mukom,"},{"v":7,"t":"a vama, mučenima, zajedno s nama spokojem uzvrati kad se Gospodin Isus objavi s nama, zajedno s anđelima svoje moći,"},{"v":8,"t":"u ognju žarkome i osveti se onima koji ne poznaju Boga i ne pokoravaju se evanđelju Gospodina našega Isusa."},{"v":9,"t":"Oni će biti kažnjeni vječnom propašću, daleko od lica Gospodnjega i od slave njegova veličanstva,"},{"v":10,"t":"kada - u onaj Dan - dođe da se proslavi u svojim svetima i da se prodiči u svima koji povjerovaše. Jer povjerovalo se svjedočanstvu našemu među vama."},{"v":11,"t":"Zato i molimo uvijek za vas da vas Bog učini dostojnima poziva i snažno dovede do punine svako vaše nastojanje oko dobra i djelo vaše vjere"},{"v":12,"t":"te da se proslavi ime Gospodina našega Isusa u vama i vi u njemu - po milosti Boga našega i Gospodina Isusa Krista."}]},"2":{"hr":[{"v":1,"t":"A što se tiče Dolaska Gospodina našega Isusa Krista i našeg okupljanja oko njega, molimo vas, braćo:"},{"v":2,"t":"ne dajte se brzo pokolebati u svom shvaćanju niti uznemiriti ni nekim duhom, ni nekom riječju, ni nekim tobože našim pismom, kao da će sad-na Dan Gospodnji."},{"v":3,"t":"Neka vas nitko ne zavede ni na koji način. Jer ako prije ne dođe onaj otpad i ne otkrije se Čovjek bezakonja, Sin propasti,"},{"v":4,"t":"Protivnik, onaj koji uzdiže sebe protiv svega što se zove Bog ili svetinja, dotle da i u Božji hram zasjedne gradeći se Bogom..."},{"v":5,"t":"Ne sjećate li se, to sam vam govorio dok sam još bio među vama?"},{"v":6,"t":"I sada znate što ga zadržava da bi se pojavio tek u svoje vrijeme."},{"v":7,"t":"Doista, otajstvo bezakonja već je na djelu, samo ima tko da ga sada zadržava dok ne bude uklonjen."},{"v":8,"t":"Tada će se otkriti Bezakonik. Njega će Gospodin Isus pogubiti dahom usta i uništiti pojavkom Dolaska svoga -"},{"v":9,"t":"njega koji djelovanjem Sotoninim dolazi sa svom silom, lažnim znamenjima i čudesima"},{"v":10,"t":"i sa svim nepravednim zavaravanjem onih koji propadaju poradi toga što ne prihvatiše ljubavi prema istini da bi se spasili."},{"v":11,"t":"I zato im Bog šalje djelovanje zavodničko da povjeruju laži"},{"v":12,"t":"te budu osuđeni svi koji nisu povjerovali istini, nego su se odlučili za nepravednost."},{"v":13,"t":"Mi pak moramo uvijek zahvaljivati Bogu za vas, braćo od Gospodina ljubljena, što vas je od početka odabrao za spasenje, posvećenjem u Duhu i vjerom u istinu."},{"v":14,"t":"Da, na to vas pozva po našem evanđelju - na posjedovanje slave Gospodina našega Isusa Krista."},{"v":15,"t":"Stoga braćo, čvrsto stojte i držite se predaja u kojima ste poučeni bilo našom riječju, bilo pismom."},{"v":16,"t":"A sam Gospodin naš Isus Krist i Bog, Otac naš, koji nas uzljubi i koji nam po milosti dade trajno ohrabrenje i dobru nadu,"},{"v":17,"t":"neka ohrabri vaša srca i neka ih učvrsti u svakom dobru djelu i riječi!"}]},"3":{"hr":[{"v":1,"t":"Uostalom, molite, braćo, za nas da riječ Gospodnja trči i proslavlja se kao i u vas"},{"v":2,"t":"i da se oslobodimo nezgodnih i opakih ljudi. Jer nemaju svi vjere!"},{"v":3,"t":"Ali, vjeran je Gospodin koji će nas učvrstiti i sačuvati od Zloga."},{"v":4,"t":"A uzdamo se, u Gospodinu, u vas: da vršite i da ćete vršiti ono što vam zapovijedamo."},{"v":5,"t":"A Gospodin neka upravi srca vaša k ljubavi Božjoj i postojanosti Kristovoj."},{"v":6,"t":"Zapovijedamo vam, braćo, u ime Gospodina Isusa Krista da se klonite svakoga brata što živi neuredno i ne po predaji koju primiste od nas."},{"v":7,"t":"Ta sami znate kako nas treba nasljedovati. Jer dok bijasmo među vama, nismo živjeli neuredno:"},{"v":8,"t":"ničiji kruh nismo badava jeli, nego smo u trudu i naporu noću i danju radili da ne bismo opteretili koga od vas."},{"v":9,"t":"Ne što ne bismo imali prava, nego da vam sebe damo za uzor koji ćete nasljedovati."},{"v":10,"t":"Doista, dok bijasmo u vas, ovo vam zapovijedasmo: Tko neće da radi, neka i ne jede!"},{"v":11,"t":"A čujemo da neki od vas žive neuredno: ništa ne rade, nego dangube."},{"v":12,"t":"Takvima zapovijedamo i zaklinjemo ih u Gospodinu Isusu Kristu: neka s mirom rade i svoj kruh jedu."},{"v":13,"t":"Vama pak, braćo, neka ne dodija činiti dobro."},{"v":14,"t":"Ako li se tko ne pokorava našoj riječi u ovoj poslanici, zabilježite ga, ne drugujte s njime, da se postidi,"},{"v":15,"t":"ali ga ne smatrajte neprijateljem, nego ga urazumljujte kao brata."},{"v":16,"t":"A sam Gospodin mira dao vam mir zauvijek i na svaki način! Gospodin sa svima vama!"},{"v":17,"t":"Pozdrav mojom rukom, Pavlovom. Ovo je znak u svakoj poslanici: ovako pišem."},{"v":18,"t":"Milost Gospodina našega Isusa Krista sa svima vama!"}]}},"1TI":{"1":{"hr":[{"v":1,"t":"Pavao, apostol Krista Isusa po nalogu Boga, Spasitelja našega, i Krista Isusa, nade naše,"},{"v":2,"t":"Timoteju, pravomu sinu u vjeri: milost, milosrđe i mir od Boga Oca i Krista Isusa, Gospodina našega!"},{"v":3,"t":"Kao što sam te zamolio kad sam odlazio u Makedoniju, ostani u Efezu da zapovijediš nekima neka ne naučavaju drugih nauka"},{"v":4,"t":"i neka se ne zanose beskrajnim bajkama i rodoslovljima, koja više pogoduju rasprama negoli rasporedbi Božjoj po vjeri."},{"v":5,"t":"Svrha je te zapovijedi ljubav iz čista srca, dobre savjesti i vjere neprijetvorne."},{"v":6,"t":"To su neki promašili i zastranili u praznorječje;"},{"v":7,"t":"htjeli bi biti učitelji Zakona, a ne razumiju ni što govore ni što tvrde."},{"v":8,"t":"A mi znamo da je Zakon dobar ako se tko njime služi zakonito,"},{"v":9,"t":"svjestan toga da je Zakon tu ne za pravednika nego za bezakonike i nepokornike, nepobožnike i grešnike, bezbožnike i svetogrdnike, ocoubojice i materoubojice, koljače,"},{"v":10,"t":"bludnike, muškoložnike, trgovce ljudima, varalice, krivokletnike, i ima li još što protivno zdravom nauku -"},{"v":11,"t":"po evanđelju Slave blaženoga Boga koje je meni povjereno."},{"v":12,"t":"Zahvalan sam Onome koji mi dade snagu - Kristu Isusu, Gospodinu našemu - jer me smatrao vrijednim povjerenja, kad u službu postavi mene"},{"v":13,"t":"koji prije bijah hulitelj, progonitelj i nasilnik. Ali pomilovan sam jer sam to u neznanju učinio, još u nevjeri."},{"v":14,"t":"I milost Gospodina našega preobilovala je zajedno s vjerom i ljubavlju, u Kristu Isusu."},{"v":15,"t":"Vjerodostojna je riječ i vrijedna da se posve prihvati: Isus Krist dođe na svijet spasiti grešnike, od kojih sam prvi ja."},{"v":16,"t":"A pomilovan sam zato da na meni prvome Isus Krist pokaže svu strpljivost i pruži primjer svima koji će povjerovati u njega za život vječni."},{"v":17,"t":"A Kralju vjekova, besmrtnome, nevidljivome, jedinome Bogu čast i slava u vijeke vjekova. Amen."},{"v":18,"t":"Taj ti zadatak predajem, sine Timoteju, u skladu s proroštvima nekoć nad tobom izrečenima: na njih oslonjen, bij boj plemeniti"},{"v":19,"t":"imajući vjeru i dobru savjest, koju su neki odbacili i doživjeli brodolom vjere."},{"v":20,"t":"Među njima je Himenej i Aleksandar, koje sam predao Sotoni da nauče ne huliti."}]},"2":{"hr":[{"v":1,"t":"Dakle, preporučujem prije svega da se obavljaju prošnje, molitve, molbenice i zahvalnice za sve ljude,"},{"v":2,"t":"za kraljeve i sve koji su na vlasti, da provodimo miran i spokojan život u svoj bogoljubnosti i ozbiljnosti."},{"v":3,"t":"To je dobro i ugodno pred Spasiteljem našim Bogom,"},{"v":4,"t":"koji hoće da se svi ljudi spase i dođu do spoznanja istine."},{"v":5,"t":"Jer jedan je Bog, jedan je i posrednik između Boga i ljudi, čovjek - Krist Isus,"},{"v":6,"t":"koji sebe samoga dade kao otkup za sve. To je u svoje vrijeme dano svjedočanstvo,"},{"v":7,"t":"za koje sam ja postavljen propovjednikom i apostolom - istinu govorim, ne lažem - učiteljem naroda u vjeri i istini."},{"v":8,"t":"Hoću dakle da muškarci mole na svakome mjestu, podižući čiste ruke bez srdžbe i raspre;"},{"v":9,"t":"isto tako žene - u doličnu držanju: neka se rese stidljivošću i razborom, ne pletenicama i zlatom ili biserjem ili skupocjenim odijelom,"},{"v":10,"t":"nego - dobrim djelima, kako dolikuje ženama koje ispovijedaju bogoljubnost."},{"v":11,"t":"Žena neka u miru prima pouku sa svom podložnošću."},{"v":12,"t":"Poučavati pak ženi ne dopuštam, ni vladati nad mužem, nego - neka bude na miru."},{"v":13,"t":"Jer prvi je oblikovan Adam, onda Eva;"},{"v":14,"t":"i Adam nije zaveden, a žena je, zavedena, učinila prekršaj."},{"v":15,"t":"A spasit će se rađanjem djece ako ustraje u vjeri, ljubavi i posvećivanju, s razborom."}]},"3":{"hr":[{"v":1,"t":"Vjerodostojna je riječ: teži li tko za nadgledništvom, časnu službu želi."},{"v":2,"t":"Treba stoga da nadglednik bude besprijekoran, jedne žene muž, trijezan, razuman, sređen, gostoljubiv, sposoban poučavati,"},{"v":3,"t":"ne vinu sklon, ne nasilan nego popustljiv, ne ratoboran, ne srebroljubac;"},{"v":4,"t":"da svojom kućom dobro upravlja i sinove drži u pokornosti sa svom ozbiljnošću -"},{"v":5,"t":"a ne zna li netko svojom kućom upravljati, kako će se brinuti za Crkvu Božju? -"},{"v":6,"t":"ne novoobraćenik da se ne bi uzoholio i pao pod osudu đavlovu."},{"v":7,"t":"A treba da ima i lijepo svjedočanstvo od onih vani, da ne bi u rug upao i zamku đavlovu."},{"v":8,"t":"Ðakoni isto tako treba da budu ozbiljni, ne dvolični, ne odani mnogom vinu ni prljavu dobitku -"},{"v":9,"t":"imajući otajstvo vjere u čistoj savjesti."},{"v":10,"t":"I neka se najprije iskušavaju, pa onda, budu li besprigovorni, neka obavljaju službu."},{"v":11,"t":"Žene isto tako neka budu ozbiljne, ne klevetnice nego trijezne, vjerne u svemu."},{"v":12,"t":"đakoni neka budu jedne žene muževi, neka dobro upravljaju djecom i svojim kućama."},{"v":13,"t":"Jer oni koji dobro obavljaju službu, stječu častan položaj i veliku smjelost u vjeri, vjeri u Isusu Kristu."},{"v":14,"t":"Ovo ti pišem u nadi da ću ubrzo doći k tebi,"},{"v":15,"t":"a okasnim li, da znaš kako se treba vladati u kući Božjoj, koja je Crkva Boga živoga, stup i uporište istine."},{"v":16,"t":"Da, po sveopćem uvjerenju, veliko je Otajstvo pobožnosti: On, očitovan u tijelu, opravdan u Duhu, viđen od anđela, propovijedan među narodima, vjerovan u svijetu, uznesen u slavu."}]},"4":{"hr":[{"v":1,"t":"Duh izričito govori da će u posljednja vremena neki otpasti od vjere i prikloniti se prijevarnim duhovima i zloduhovskim naucima."},{"v":2,"t":"A sve to pod utjecajem himbe lažljivaca otupjele savjesti"},{"v":3,"t":"koji zabranjuju ženiti se i nameću uzdržavati se od jela što ih je Bog stvorio da ih sa zahvalnošću uzimaju oni koji vjeruju i znaju istinu."},{"v":4,"t":"Doista, svako je Božje stvorenje dobro i ne valja odbaciti ništa što se uzima sa zahvalnošću"},{"v":5,"t":"jer se posvećuje riječju Božjom i molitvom."},{"v":6,"t":"To izlaži braći i bit ćeš dobar poslužitelj Krista Isusa, hranjen riječima vjere i dobroga nauka za kojim postojano ideš."},{"v":7,"t":"Svjetovne pak i bablje priče odbijaj! Vježbaj se u pobožnosti!"},{"v":8,"t":"Uistinu, tjelesno vježbanje malo čemu koristi, a pobožnost je svemu korisna jer joj je obećan život - sadašnji i budući."},{"v":9,"t":"Vjerodostojna je to riječ i vrijedna da se posve prihvati."},{"v":10,"t":"Ta za to se trudimo i borimo jer se pouzdajemo u Boga živoga koji je Spasitelj svih ljudi, ponajpače vjernika."},{"v":11,"t":"Zapovijedaj to i naučavaj!"},{"v":12,"t":"Nitko neka ne prezire tvoje mladosti, nego budi uzor vjernicima u riječi, u vladanju, u ljubavi, u vjeri, u čistoći."},{"v":13,"t":"Dok ne dođem, posveti se čitanju, poticanju, poučavanju."},{"v":14,"t":"Ne zanemari milosnog dara koji je u tebi, koji ti je dan po proroštvu zajedno s polaganjem ruku starješinstva."},{"v":15,"t":"Oko toga nastoj, sav u tom budi da tvoj napredak bude svima očit."},{"v":16,"t":"Pripazi na samog sebe i na poučavanje! Ustraj u tome! Jer to vršeći, spasit ćeš i sebe i one koji te slušaju."}]},"5":{"hr":[{"v":1,"t":"Na starca se ne otresaj, nego ga nagovaraj kao oca, mladiće kao braću,"},{"v":2,"t":"starice kao majke, djevojke kao sestre - u svoj čistoći."},{"v":3,"t":"Udovice poštuj - one koje su zaista udovice."},{"v":4,"t":"Ako li ipak koja udovica ima djecu ili unuke, neka najprije oni znaju očitovati svoju pobožnost prema vlastitom domu i uzdarjem uzvraćati roditeljima jer to je ugodno Bogu."},{"v":5,"t":"A ona koja je zaista udovica, posve sama, pouzdaje se u Boga, odana prošnjama i molitvama noć i dan;"},{"v":6,"t":"ona, naprotiv, koja provodi lagodan život, živa je već umrla."},{"v":7,"t":"I to naglašuj da budu besprijekorne."},{"v":8,"t":"Ako li se tkogod za svoje, navlastito za ukućane, ne stara, zanijekao je vjeru i gori je od nevjernika."},{"v":9,"t":"U popis neka se unosi udovica ne mlađa od šezdeset godina, jednog muža žena,"},{"v":10,"t":"koja ima svjedočanstvo dobrih djela: da je djecu odgojila, da je bila gostoljubiva, da je svetima noge prala, da je nevoljnima pomagala, da se svakom dobru djelu posvećivala."},{"v":11,"t":"Mlađe pak udovice odbijaj jer kad ih požuda odvrati od Krista, hoće se udati,"},{"v":12,"t":"pa zasluže osudu što su pogazile prvotnu vjernost."},{"v":13,"t":"A uz to se, obilazeći po kućama, nauče biti besposlene, i ne samo besposlene, nego i brbljave i nametljive, govoreći što ne bi smjele."},{"v":14,"t":"Hoću dakle da se mlađe udaju, djecu rađaju, da budu kućevne te ne daju protivniku nikakva povoda za pogrđivanje."},{"v":15,"t":"Jer već su neke zastranile za Sotonom."},{"v":16,"t":"Ako koja vjernica ima udovica, neka im pomaže, a neka se ne opterećuje Crkva, da uzmogne pomoći onima koje su zaista udovice."},{"v":17,"t":"Starješine koji su dobri predstojnici dostojni su dvostruke časti, ponajpače oni koji se trude oko Riječi i poučavanja."},{"v":18,"t":"Pismo doista veli: Volu koji vrši ne zavezuj usta! I: Vrijedan je radnik plaće svoje."},{"v":19,"t":"Protiv starješine ne primaj tužbe, osim na osnovi dvaju ili triju svjedoka."},{"v":20,"t":"One koji griješe, pred svima ukori da i drugi imaju straha!"},{"v":21,"t":"Zaklinjem te pred Bogom i Kristom Isusom i izabranim anđelima da se toga držiš bez predrasude i ništa ne činiš po naklonosti."},{"v":22,"t":"Ruku prebrzo ni na koga ne polaži i ne budi dionikom tuđih grijeha! Sebe čistim čuvaj!"},{"v":23,"t":"Ne pij više samo vode, nego uzimaj malo vina poradi želuca i čestih svojih slabosti."},{"v":24,"t":"Grijesi nekih ljudi očiti su i prije suda, nekih pak samo nakon njega."},{"v":25,"t":"Tako su i dobra djela očita, a bila i drukčija, ne mogu se sakriti."}]},"6":{"hr":[{"v":1,"t":"Koji su pod jarmom, robovi, neka svoje gospodare smatraju svake časti dostojnima da se ne bi pogrđivalo ime Božje i nauk."},{"v":2,"t":"A oni kojima su gospodari vjernici, neka ih ne cijene manje zato što su braća, nego neka im još više služe jer ti koji primaju njihovo dobročinstvo vjernici su i ljubljena braća. To naučavaj i preporučuj!"},{"v":3,"t":"A tko drukčije naučava i ne prianja uza zdrave riječi, riječi Gospodina našega Isusa Krista, i nauk u skladu s pobožnošću,"},{"v":4,"t":"nadut je, puka neznalica, samo boluje od raspra i rječoborstava, od kojih nastaje zavist, svađa, pogrde, zla sumnjičenja,"},{"v":5,"t":"razračunavanja ljudi pokvarene pameti i lišenih istine, što pobožnost smatraju dobitkom."},{"v":6,"t":"Pa i jest dobitak velik pobožnost, zadovoljna onim što ima!"},{"v":7,"t":"Ta ništa nismo donijeli na svijet te iz njega ništa ni iznijeti ne možemo!"},{"v":8,"t":"Imamo li dakle hranu i odjeću, zadovoljimo se time."},{"v":9,"t":"Jer oni koji se hoće bogatiti, upadaju u napast, zamku i mnoge nerazumne i štetne požude što ljude strovaljuju u zator i propast."},{"v":10,"t":"Zaista, korijen svih zala jest srebroljublje; njemu odani, mnogi odlutaše od vjere i sami sebe isprobadaše mukama mnogima."},{"v":11,"t":"A ti se, Božji čovječe, toga kloni! Teži za pravednošću, pobožnošću, vjerom, ljubavlju, postojanošću, krotkošću!"},{"v":12,"t":"Bij dobar boj vjere, osvoji vječni život na koji si pozvan i radi kojega si dao ono lijepo svjedočanstvo pred mnogim svjedocima!"},{"v":13,"t":"Zapovijedam pred Bogom koji svemu život daje i pred Kristom Isusom koji pred Poncijem Pilatom posvjedoči lijepo svjedočanstvo:"},{"v":14,"t":"čuvaj Zapovijed, neokaljano i besprijekorno, do Pojavka Gospodina našega Isusa Krista."},{"v":15,"t":"Njega će u svoje vrijeme pokazati On, Blaženi i jedini Vladar, Kralj kraljeva i Gospodar gospodara,"},{"v":16,"t":"koji jedini ima besmrtnost, prebiva u svjetlu nedostupnu, koga nitko od ljudi ne vidje niti ga vidjeti može. Njemu čast i vlast vjekovječna! Amen."},{"v":17,"t":"Onima koji su u sadašnjem svijetu bogati zapovijedaj neka ne budu bahati i neka se ne uzdaju u nesigurno bogatstvo, nego u Boga koji nam sve bogato daje na uživanje;"},{"v":18,"t":"neka dobro čine, neka se bogate dobrim djelima, neka budu darežljivi, zajedničari -"},{"v":19,"t":"prikupljajući sebi lijepu glavnicu za budućnost da osvoje onaj pravi život."},{"v":20,"t":"Timoteju, poklad čuvaj kloneći se svjetovnoga praznoglasja i proturječja nekog nazovispoznanja,"},{"v":21,"t":"koje su neki ispovijedali pa od vjere zastranili. Milost s vama"}]}},"2TI":{"1":{"hr":[{"v":1,"t":"Pavao, apostol Krista Isusa voljom Božjom, po obećanju života, života u Kristu Isusu,"},{"v":2,"t":"Timoteju, ljubljenom sinu: milost, milosrđe i mir od Boga Oca i Krista Isusa, Gospodina našega."},{"v":3,"t":"Zahvalan sam Bogu, kojemu onamo od predaka čiste savjesti služim, dok te se neprestano spominjem u svojim molitvama noć i dan."},{"v":4,"t":"Sjetim se tvojih suza i zaželim vidjeti te da se napunim radosti"},{"v":5,"t":"imajući na pameti neprijetvornu vjeru koja je u tebi - onu vjeru koja je najprije prebivala u tvojoj baki Loidi i tvojoj majci Euniki, a uvjeren sam, i u tebi."},{"v":6,"t":"Poradi toga podsjećam te: raspiruj milosni dar Božji koji je u tebi po polaganju mojih ruku."},{"v":7,"t":"Jer nije nam Bog dao duha bojažljivosti, nego snage, ljubavi i razbora."},{"v":8,"t":"Ne stidi se stoga svjedočanstva za Gospodina našega, ni mene, sužnja njegova. Nego zlopati se zajedno sa mnom za evanđelje, po snazi Boga"},{"v":9,"t":"koji nas je spasio i pozvao pozivom svetim - ne po našim djelima, nego po svojem naumu i milosti koja nam je dana u Kristu Isusu prije vremena vjekovječnih,"},{"v":10,"t":"a očitovana je sada pojavkom Spasitelja našega Krista Isusa, koji obeskrijepi smrt i učini da zasja život i neraspadljivost - po evanđelju"},{"v":11,"t":"za koje sam ja postavljen propovjednikom, apostolom i učiteljem."},{"v":12,"t":"Poradi toga i ovo trpim, ali se ne stidim jer znam komu sam povjerovao i uvjeren sam da je on moćan poklad moj sačuvati za onaj Dan."},{"v":13,"t":"Uzorom neka ti budu zdrave riječi koje si od mene čuo u vjeri i ljubavi u Kristu Isusu."},{"v":14,"t":"Lijepi poklad čuvaj po Duhu Svetom koji prebiva u nama."},{"v":15,"t":"Napustiše me, to znaš, svi u Aziji, među njima i Figel i Hermogen."},{"v":16,"t":"Neka Gospodin milosrđem podari Oneziforov dom jer me često osvježivao i nije se stidio mojih okova,"},{"v":17,"t":"nego kad je bio u Rimu, brižljivo me potražio i našao."},{"v":18,"t":"Dao mu Gospodin naći milosrđe u Gospodina u onaj Dan! A koliko je usluga u Efezu iskazao, to ti najbolje znaš."}]},"2":{"hr":[{"v":1,"t":"Ti se dakle, dijete moje, jačaj milošću u Kristu Isusu"},{"v":2,"t":"i što si od mene po mnogim svjedocima čuo, to predaj vjernim ljudima koji će biti podobni i druge poučiti."},{"v":3,"t":"S njima se zlopati kao dobar vojnik Krista Isusa."},{"v":4,"t":"Tko vojuje, ne zapleće se u svagdanje poslove kako bi se vojskovođi svidio."},{"v":5,"t":"I natječe li se tko, ne ovjenčava se ako se zakonito ne natječe."},{"v":6,"t":"Ratar koji se trudi treba da prvi primi od uroda."},{"v":7,"t":"Shvati što govorim! Ta dat će ti Gospodin razum u svemu."},{"v":8,"t":"Spominji se Isusa Krista, uskrsla od mrtvih, od potomstva Davidova - po mojem evanđelju."},{"v":9,"t":"Za nj se ja zlopatim sve do okova, kao zločinac. Ali riječ Božja nije okovana!"},{"v":10,"t":"Stoga sve podnosim radi izabranih, da i oni postignu spasenje, spasenje u Kristu Isusu, zajedno s vječnom slavom."},{"v":11,"t":"Vjerodostojna je riječ: Ako s njime umrijesmo, s njime ćemo i živjeti."},{"v":12,"t":"Ako ustrajemo, s njime ćemo i kraljevati. Ako ga zaniječemo, i on će zanijekati nas."},{"v":13,"t":"Ako ne budemo vjerni, on vjeran ostaje. Ta ne može sebe zanijekati!"},{"v":14,"t":"Na to podsjećaj zaklinjući pred Bogom neka ne bude rječoborstva: ničemu ne koristi, a na propast je onima koji slušaju."},{"v":15,"t":"Uznastoj da kao prokušan staneš pred Boga kao radnik koji se nema čega stidjeti, koji ispravno reže riječ istine."},{"v":16,"t":"Svjetovnih se pak praznorječja kloni: sve će više provaljivati prema bezbožnosti"},{"v":17,"t":"i riječ će njihova kao rak-rana izgrizati. Od njih su Himenej i Filet,"},{"v":18,"t":"koji zastraniše od istine tvrdeći da je uskrsnuće već bilo te nekima prevraćaju vjeru."},{"v":19,"t":"Ipak čvrsti temelj Božji stoji - pod ovim je pečatom: Poznaje Gospodin one koji su njegovi i neka se kloni zloće tko god imenuje ime Gospodnje."},{"v":20,"t":"Pa u velikoj kući ima posuda ne samo zlatnih i srebrnih, nego i drvenih i glinenih; i jedne su časne, druge pak nečasne."},{"v":21,"t":"Očisti li se dakle tko od toga, bit će posuda časna, posvećena, korisna Gospodaru, za svako dobro djelo prikladna."},{"v":22,"t":"A mladenačkih se strastvenosti kloni! Teži za pravednošću, vjerom, ljubavlju, mirom sa svima koji iz čista srca prizivlju Gospodina."},{"v":23,"t":"Lude pak i neobuzdane raspre odbijaj znajući da rađaju svađama."},{"v":24,"t":"A sluga Gospodnji treba da se ne svađa, nego da bude nježan prema svima, sposoban poučavati, zlo podnositi,"},{"v":25,"t":"da s blagošću preodgaja protivnike, ne bi li ih Bog podario obraćenjem te spoznaju istinu"},{"v":26,"t":"i ponovno budu trijezni izvan zamke đavla koji ih drži robljem svoje volje."}]},"3":{"hr":[{"v":1,"t":"A ovo znaj: u posljednjim danima nastat će teška vremena."},{"v":2,"t":"Ljudi će doista biti sebeljupci, srebroljupci, preuzetnici, oholice, hulitelji, roditeljima neposlušni, nezahvalnici, bezbožnici,"},{"v":3,"t":"bešćutnici, nepomirljivci, klevetnici, neobuzdanici, goropadnici, neljubitelji dobra,"},{"v":4,"t":"izdajice, brzopletnici, naduti, ljubitelji užitka više nego ljubitelji Boga."},{"v":5,"t":"Imaju obličje pobožnosti, ali snage su se njezine odrekli. I njih se kloni!"},{"v":6,"t":"Od njih su doista oni što se uvlače u kuće i zarobljuju ženice, natovarene grijesima, vodane najrazličitijim strastima:"},{"v":7,"t":"one uvijek uče, a nikako ne mogu doći do spoznaje istine."},{"v":8,"t":"Kao što se Janes i Jambres suprotstaviše Mojsiju, tako se i ovi, ljudi pokvarena uma, u vjeri neprokušani, suprotstavljaju istini."},{"v":9,"t":"Ali neće više napredovati jer bezumlje će ovih postati očito, kako se to i onima dogodilo."},{"v":10,"t":"A ti si pošao za nmom u poučavanju, u ponašanju, u naumu, u vjeri, u strpljivosti, u ljubavi, u postojanosti;"},{"v":11,"t":"u progonstvima, u patnjama koje su me zadesile u Antiohiji, u Ikoniju, u Listri. Kakva li sam progonstva podnio! I iz svih me izbavio Gospodin!"},{"v":12,"t":"A i svi koji hoće živjeti pobožno u Kristu Isusu, bit će progonjeni."},{"v":13,"t":"Zli pak ljudi i vračari napredovat će sve više u zlu - kao zavodnici i zavedeni."},{"v":14,"t":"Ti, naprotiv, ostani u onome u čemu si poučen i čemu si vjeru dao, svjestan od koga si sve poučen"},{"v":15,"t":"i da od malena poznaješ Sveta pisma koja su vrsna učiniti te mudrim tebi na spasenje po vjeri, vjeri u Kristu Isusu."},{"v":16,"t":"Sve Pismo, bogoduho, korisno je za poučavanje, uvjeravanje, popravljanje, odgajanje u pravednosti,"},{"v":17,"t":"da čovjek Božji bude vrstan, za svako dobro djelo podoban."}]},"4":{"hr":[{"v":1,"t":"Zaklinjem te pred Bogom i Kristom Isusom, koji će suditi žive i mrtve, zaklinjem te pojavkom njegovim i kraljevstvom njegovim:"},{"v":2,"t":"propovijedaj Riječ, uporan budi - bilo to zgodno ili nezgodno - uvjeravaj, prijeti, zapovijedaj sa svom strpljivošću i poukom."},{"v":3,"t":"Jer doći će vrijeme kad ljudi neće podnositi zdrava nauka nego će sebi po vlastitim požudama nagomilavati učitelje kako im godi ušima;"},{"v":4,"t":"od istine će uho odvraćati, a bajkama se priklanjati."},{"v":5,"t":"Ti, naprotiv, budi trijezan u svemu, zlopati se, djelo izvrši blagovjesničko, služenje svoje posve ispuni!"},{"v":6,"t":"Jer ja se već prinosim za žrtvu ljevanicu, prispjelo je vrijeme moga odlaska."},{"v":7,"t":"Dobar sam boj bio, trku završio, vjeru sačuvao."},{"v":8,"t":"Stoga, pripravljen mi je vijenac pravednosti kojim će mi u onaj Dan uzvratiti Gospodin, pravedan sudac; ne samo meni, nego i svima koji s ljubavlju čekaju njegov pojavak."},{"v":9,"t":"Nastoj što prije doći k meni!"},{"v":10,"t":"Jer Dema me, zaljubljen u sadašnji svijet, napustio i otišao u Solun; Krescencije u Galaciju, Tit u Dalmaciju."},{"v":11,"t":"Luka je jedini sa mnom. Marka uzmi i dovedi sa sobom jer mi je koristan za služenje."},{"v":12,"t":"Tihika sam poslao u Efez."},{"v":13,"t":"Kabanicu koju ostavih u Troadi kod Karpa, kada dođeš, donesi. I knjige, osobito pergamene."},{"v":14,"t":"Aleksandar kovač nanio mi je mnogo zla. Uzvratio mu Gospodin po njegovim djelima!"},{"v":15,"t":"Njega se i ti čuvaj jer se veoma usprotivio našim riječima."},{"v":16,"t":"Za prve moje obrane nitko ne bijaše uza me, svi me napustiše. Ne uračunalo im se!"},{"v":17,"t":"Ali Gospodin je stajao uza me, on me krijepio da se po meni potpuno razglasi Poruka te je čuju svi narodi; i izbavljen sam iz usta lavljih."},{"v":18,"t":"Izbavit će me Gospodin od svakoga zla djela i spasiti za svoje nebesko kraljevstvo. Njemu slava u vijeke vjekova! Amen!"},{"v":19,"t":"Pozdravi Prisku i Akvilu i Oneziforov dom!"},{"v":20,"t":"Erast osta u Korintu, a Trofima ostavih u Miletu bolesna."},{"v":21,"t":"Nastoj doći prije zime. Pozdravlja te Eubul, Pudencije, Lino, Klaudija i sva braća."},{"v":22,"t":"Gospodin s duhom tvojim. Milost s vama!"}]}},"TIT":{"1":{"hr":[{"v":1,"t":"Pavao, sluga Božji i apostol Isusa Krista poradi vjere izabranika Božjih i spoznanja istine usmjerene k pobožnosti"},{"v":2,"t":"u nadi života vječnoga što ga, prije vremena vjekovječnih, obeća Bog, On koji ne laže,"},{"v":3,"t":"a u svoje doba očitova riječ svoju u propovijedanju koje je meni povjereno po odredbi Spasitelja našega, Boga:"},{"v":4,"t":"Titu, pravomu sinu po zajedničkoj vjeri, milost i mir od Boga i Krista Isusa, Spasitelja našega!"},{"v":5,"t":"Poradi toga ostavih te na Kreti da urediš preostalo te po gradovima postaviš starješine kako sam ti ja odredio:"},{"v":6,"t":"je li tko besprigovoran, jedne žene muž, jesu li mu djeca vjernici i ne pod optužbom raskalašenosti ili nepokorna..."},{"v":7,"t":"Jer nadstojnik kao Božji upravitelj treba da bude besprigovoran: ne samoživ, ne jedljiv, ne vinu sklon, ni nasilju, ni prljavu dobitku,"},{"v":8,"t":"nego gostoljubiv, ljubitelj dobra, razuman, pravedan, svet, uzdržljiv,"},{"v":9,"t":"priljubljen uz vjerodostojnu riječ nauka da može i hrabriti u zdravom nauku i uvjeravati protivnike."},{"v":10,"t":"Jer mnogi su nepokorni, praznorječni i zavodnici, ponajpače oni iz obrezanja."},{"v":11,"t":"Njima treba začepiti usta jer cijele domove prevraćaju naučavajući što ne bi smjeli, i to poradi prljava dobitka."},{"v":12,"t":"Reče netko od njih, njihov vlastiti prorok: “Krećani uvijek lašci, opake zvijeri, trbusi dangubni.”"},{"v":13,"t":"Svjedočanstvo je to istinito. Zato ih karaj oštro da budu zdravi u vjeri,"},{"v":14,"t":"da ne prianjaju uza židovske bajke i propise ljudi koji se odvraćaju od istine."},{"v":15,"t":"Sve je čisto čistima; okaljanima pak i nevjernima ništa čisto, nego su im okaljani i razum i savjest."},{"v":16,"t":"Ispovijedaju da Boga poznaju, ali djelima ga niječu - odvratni, neposlušni i za koje god dobro djelo nepodesni."}]},"2":{"hr":[{"v":1,"t":"Ti, naprotiv, govori što se priliči zdravu nauku:"},{"v":2,"t":"starci da budu trijezni, ozbiljni, razumni, zdrave vjere, ljubavi, postojanosti;"},{"v":3,"t":"starice isto tako - vladanja kakvo dolikuje svetima: ne klevetnice, ne ropkinje mnogog vina, nego učiteljice dobra"},{"v":4,"t":"da urazumljuju mlađe neka ljube svoje muževe, djecu,"},{"v":5,"t":"neka budu razumne, čiste, kućevne, dobre, podložne svojim muževima da se riječ Božja ne bi pogrđivala."},{"v":6,"t":"Mladiće isto tako potiči da budu razumni."},{"v":7,"t":"U svemu se pokaži uzorom dobrih djela: u poučavanju - nepokvarljivost, ozbiljnost,"},{"v":8,"t":"riječ zdrava, besprigovorna da se onaj nasuprot postidi nemajući o nama reći ništa zlo."},{"v":9,"t":"Robovi neka se svojim gospodarima u svemu podlažu, ugađaju im, ne proturječe,"},{"v":10,"t":"ne pronevjeruju, nego neka im iskazuju svaku dobru vjernost da u svemu budu ures nauku Spasitelja našega, Boga."},{"v":11,"t":"Pojavila se doista milost Božja, spasiteljica svih ljudi;"},{"v":12,"t":"odgojila nas da se odreknemo bezbožnosti i svjetovnih požuda te razumno, pravedno i pobožno živimo u sadašnjem svijetu,"},{"v":13,"t":"iščekujući blaženu nadu i pojavak slave velikoga Boga i Spasitelja našega Isusa Krista."},{"v":14,"t":"On sebe dade za nas da nas otkupi od svakoga bezakonja i očisti sebi Narod izabrani koji revnuje oko dobrih djela."},{"v":15,"t":"To govori, zapovijedaj, karaj sa svom vlašću. Nitko neka te ne prezire."}]},"3":{"hr":[{"v":1,"t":"Podsjećaj ih da se podlažu poglavarstvima, vlastima, da slušaju, da budu spremni na svako dobro djelo,"},{"v":2,"t":"nikoga da ne pogrđuju, da budu neratoborni, popustljivi, da očituju svaku blagost prema svim ljudima."},{"v":3,"t":"Jer i mi nekoć bijasmo nerazumni, nepokorni, lutalice, robovi raznih požuda i naslada, živjeli smo u zlu i zavisti, odvratni bili, mrzili jedni druge."},{"v":4,"t":"Ali kad se pojavila dobrostivost i čovjekoljublje Spasitelja našega, Boga,"},{"v":5,"t":"on nas spasi ne po djelima što ih u pravednosti mi učinismo, nego po svojem milosrđu: kupelji novoga rođenja i obnavljanja po Duhu Svetom"},{"v":6,"t":"koga bogato izli na nas po Isusu Kristu, Spasitelju našemu,"},{"v":7,"t":"da opravdani njegovom milošću budemo, po nadi, baštinici života vječnoga."},{"v":8,"t":"Vjerodostojna je ovo riječ i hoću da to uporno tvrdiš te da oni koji su povjerovali Bogu uznastoje prednjačiti dobrim djelima. To je dobro i korisno ljudima."},{"v":9,"t":"A ludih se raspra, i rodoslovlja, i svađa, i sukoba zakonskih kloni: beskorisni su i isprazni."},{"v":10,"t":"S krivovjercem nakon prvoga i drugog upozorenja prekini"},{"v":11,"t":"znajući da je izopačen i da griješi: on sam sebe osuđuje."},{"v":12,"t":"Kad pošaljem k tebi Artemu ili Tihika, požuri se k meni u Nikopol jer sam odlučio ondje prezimiti."},{"v":13,"t":"Zenu, pravnika, i Apolona brižljivo opremi da im ništa ne ponestane."},{"v":14,"t":"A i naši neka se uče prednjačiti dobrim djelima u životnim potrebama da ne budu neplodni."},{"v":15,"t":"Pozdravljaju te svi koji su sa mnom. Pozdravi one koji nas ljube u vjeri. Milost sa svima vama!"}]}},"PHM":{"1":{"hr":[{"v":1,"t":"Pavao, sužanj Isusa Krista, i brat Timotej: ljubljenom Filemonu, suradniku našemu,"},{"v":2,"t":"i sestri Apiji, i Arhipu, suborcu našem, i Crkvi u tvojoj kući."},{"v":3,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista!"},{"v":4,"t":"Zahvaljujem svagda Bogu svojemu spominjući te se u svojim molitvama"},{"v":5,"t":"jer čujem za tvoju ljubav i vjeru koju imaš prema Gospodinu Isusu Kristu i prema svima svetima."},{"v":6,"t":"Nek zajedništvo tvoje vjere bude djelotvorno u spoznanju svakoga mogućeg dobra među vama poradi Krista!"},{"v":7,"t":"Uvelike si me doista obradovao i utješio svojom ljubavlju jer si, brate, okrijepio srca svetih."},{"v":8,"t":"Stoga, premda imam punu slobodu u Kristu da ti zapovjedim što ti je činiti,"},{"v":9,"t":"poradi ljubavi radije molim, kakav već jesam, Pavao, starac, a sada i sužanj Krista Isusa."},{"v":10,"t":"Molim te za svoje dijete koje rodih u okovima, za Onezima,"},{"v":11,"t":"negda tebi nekorisna, a sada i tebi i meni veoma korisna."},{"v":12,"t":"Šaljem ti ga - njega, srce svoje."},{"v":13,"t":"Htjedoh ga zadržati kod sebe da mi mjesto tebe posluži u okovima evanđelja."},{"v":14,"t":"Ali ne htjedoh preko tvoje volje da ne bi tvoja dobrota bila od nevolje, nego od dobre volje."},{"v":15,"t":"Možda baš zato bi za čas odijeljen da ga dobiješ zauvijek -"},{"v":16,"t":"ne kao roba, nego više od roba, kao brata ljubljenoga, osobito meni, a koliko više tebi, i po tijelu i po Gospodinu."},{"v":17,"t":"Smatraš li me dakle drugom, primi ga kao mene."},{"v":18,"t":"Ako ti je u čemu skrivio ili ti je što dužan, to meni upiši."},{"v":19,"t":"Ja, Pavao, potpisujem svojom rukom: ja ću platiti. Da ti ne reknem da mi i samoga sebe duguješ!"},{"v":20,"t":"Hajde, brate, da se tobom okoristim u Gospodinu: okrijepi srce moje u Kristu!"},{"v":21,"t":"Uzdajući se u tvoju poslušnost, napisah ti uvjeren da ćeš još više učiniti, nego te molim."},{"v":22,"t":"K tome, pripravi mi obitavalište jer se nadam da ću vam po vašim molitvama biti darovan."},{"v":23,"t":"Pozdravlja te Epafra, moj suuznik u Kristu Isusu,"},{"v":24,"t":"Marko, Aristarh, Dema i Luka, moji suradnici."},{"v":25,"t":"Milost Gospodina našega Isusa Krista s duhom vašim!"}]}},"HEB":{"1":{"hr":[{"v":1,"t":"Više puta i na više načina Bog nekoć govoraše ocima po prorocima;"},{"v":2,"t":"konačno, u ove dane, progovori nama u Sinu. Njega postavi baštinikom svega; Njega po kome sazda svjetove."},{"v":3,"t":"On, koji je odsjaj Slave i otisak Bića njegova te sve nosi snagom riječi svoje, pošto očisti grijehe, sjede zdesna Veličanstvu u visinama;"},{"v":4,"t":"postade toliko moćniji od anđela koliko je uzvišenije nego oni baštinio ime."},{"v":5,"t":"Ta kome od anđela ikad reče: Ti si sin moj, danas te rodih; ili pak: Ja ću njemu biti otac, a on će meni biti sin."},{"v":6,"t":"A opet, kad uvodi Prvorođenca u svijet, govori: Nek pred njim nice padnu svi anđeli Božji."},{"v":7,"t":"Za anđele veli: Anđele čini vjetrovima, sluge svoje plamenom ognjenim,"},{"v":8,"t":"ali za Sina: Prijestolje je tvoje, Bože, u vijeke vjekova, i pravedno žezlo - žezlo je tvog kraljevstva."},{"v":9,"t":"Ti ljubiš pravednost, a mrziš bezakonje, stoga Bog, Bog tvoj, tebe pomaza uljem radosti kao nikog od tvojih drugova."},{"v":10,"t":"I: Ti u početku, Gospodine, utemelji zemlju i nebo je djelo ruku tvojih."},{"v":11,"t":"Propast će, ti ćeš ostati, sve će ostarjeti kao odjeća."},{"v":12,"t":"Mijenjaš ih poput haljine, kao odjeću, i nestaju. A ti si uvijek isti - godinama tvojim nema kraja."},{"v":13,"t":"Za koga pak od anđela ikad reče: Sjedi mi zdesna dok ne položim neprijatelje tvoje za podnožje nogama tvojim!"},{"v":14,"t":"Svi ti zar nisu služnički duhovi što se šalju služiti za one koji imaju baštiniti spasenje?"}]},"2":{"hr":[{"v":1,"t":"Zato treba da mi svesrdnije prianjamo uz ono što čusmo da ne bismo promašili."},{"v":2,"t":"Jer ako je riječ po anđelima izrečena bila čvrsta te je svaki prijestup i neposluh primio pravednu plaću,"},{"v":3,"t":"kako li ćemo mi umaći ako zanemarimo toliko spasenje? Spasenje koje je počeo propovijedati Gospodin, koje su nam potvrdili slušatelji,"},{"v":4,"t":"a suposvjedočio Bog znamenjima i čudesima, najrazličitijim silnim djelima i darivanjima Duha Svetoga po svojoj volji."},{"v":5,"t":"Nije doista anđelima podložio budući svijet o kojem govorimo."},{"v":6,"t":"Netko negdje posvjedoči: Što je čovjek da ga se spominješ, sin čovječji te ga pohađaš."},{"v":7,"t":"Ti ga tek za malo učini manjim od anđela, slavom i časti njega ovjenča,"},{"v":8,"t":"njemu pod noge sve podloži. Kad mu, doista, sve podloži, ništa ne ostavi što mu ne bi bilo podloženo. Sad još ne vidimo da mu je sve podloženo,"},{"v":9,"t":"ali Njega, za malo manjeg od anđela, Isusa, vidimo zbog pretrpljene smrti slavom i časti ovjenčana da milošću Božjom bude svakome na korist što je on smrt okusio."},{"v":10,"t":"Dolikovalo je doista da Onaj radi kojega je sve i po kojemu je sve - kako bi mnoge sinove priveo k slavi - po patnjama do savršenstva dovede Početnika njihova spasenja."},{"v":11,"t":"Ta i Posvetitelj i posvećeni - svi su od jednoga! Zato se on i ne stidi zvati ih braćom,"},{"v":12,"t":"kad veli: Braći ću svojoj naviještat ime tvoje, hvalit ću te usred zbora."},{"v":13,"t":"I još: Ja ću se u njega uzdati, i još: Evo, ja i djeca koju mi Bog dade."},{"v":14,"t":"Pa budući da djeca imaju zajedničku krv i meso, i sam on tako postade u tome sudionikom da smrću obeskrijepi onoga koji imaše moć smrti, to jest đavla,"},{"v":15,"t":"pa oslobodi one koji - od straha pred smrću - kroza sav život bijahu podložni ropstvu."},{"v":16,"t":"Ta ne zauzima se dašto za anđele, nego se zauzima za potomstvo Abrahamovo."},{"v":17,"t":"Stoga je trebalo da u svemu postane braći sličan, da milosrdan bude i ovjerovljen Veliki svećenik u odnosu prema Bogu kako bi okajavao grijehe naroda."},{"v":18,"t":"Doista, u čemu je iskušan trpio, može iskušavanima pomoći."}]},"3":{"hr":[{"v":1,"t":"Stoga, braćo sveta, sudionici nebeskoga poziva, promotrite Apostola i Velikoga svećenika naše vjere - Isusa:"},{"v":2,"t":"on je ovjerovljen kod Onoga koji ga postavi kao ono i Mojsije u svoj kući njegovoj."},{"v":3,"t":"Dostojan je doista toliko veće slave od Mojsija koliko veću čast od kuće ima onaj tko ju je sagradio."},{"v":4,"t":"Jer svaku kuću tkogod gradi, a sve je sagradio Bog."},{"v":5,"t":"Da, i Mojsije bijaše ovjerovljen u svoj kući njegovoj kao služnik da posvjedoči za ono što je imalo biti rečeno,"},{"v":6,"t":"ali Krist - kao Sin, nad kućom njegovom. Njegova smo kuća mi ako sačuvamo smjelost i ponos nade."},{"v":7,"t":"Zato, kao što veli Duh Sveti: Danas ako glas mu čujete,"},{"v":8,"t":"ne budite srca tvrda kao u Pobuni, kao u dan iskušenja u pustinji"},{"v":9,"t":"gdje me kušnjom iskušavahu očevi vaši premda gledahu djela moja"},{"v":10,"t":"četrdeset godina. Zato mi dodija naraštaj onaj pa rekoh: Uvijek su nestalna srca i ne proniču moje putove."},{"v":11,"t":"Tako se zakleh u svom gnjevu: Nikad neće ući u moj počinak!"},{"v":12,"t":"Pazite, braćo, da ne bi u koga od vas srce bilo opako, nevjerno, odmetnulo se od Boga živoga."},{"v":13,"t":"Pače hrabrite jedni druge dan za danom dok još odjekuje ono Danas da ne otvrdne tko od vas zaveden grijehom."},{"v":14,"t":"Doista, sudionici smo Kristovi postali ako, dakako, ono prvo imanje stalnim sačuvamo"},{"v":15,"t":"kad je rečeno: Danas ako glas mu čujete, ne budite srca tvrda kao u Pobuni!"},{"v":16,"t":"Jer, koji su to čuli pa se pobunili? Zar ne svi koji su pod Mojsijem izašli iz Egipta?"},{"v":17,"t":"Koji li mu dodijavahu četrdeset godina? Zar ne oni koji sagriješiše, kojih mrtva tijela popadaše u pustinji?"},{"v":18,"t":"Kojima se zakle da neće ući u njegov počinak, ako li ne nepokornima?"},{"v":19,"t":"I vidimo da ne mogoše ući zbog nevjere."}]},"4":{"hr":[{"v":1,"t":"Bojmo se dakle da se, dok ostaje obećanje o ulasku u njegov Počinak, za koga od vas ne bi utvrdilo kako je zakasnio."},{"v":2,"t":"Jer nama je naviještena blagovijest kao i njima, ali njima Riječ poruke nije uskoristila jer se vjerom nisu pridružili onima koji su poslušali."},{"v":3,"t":"U Počinak doista ulazimo mi koji povjerovasmo, prema onom što je rekao: Tako se zakleh u svom gnjevu: Nikad neće ući u moj počinak, premda su djela od postanka svijeta dovršena."},{"v":4,"t":"Rekao je doista negdje o sedmom danu ovako: I počinu Bog sedmoga dana od svih djela svojih."},{"v":5,"t":"A ovdje opet: Nikad neće ući u moj počinak."},{"v":6,"t":"Preostaje dakle da neki imaju u nj ući, a oni koji su prvi primili blagovijest ne uđoše zbog nepokornosti."},{"v":7,"t":"Zato Bog ponovno određuje jedan dan, Danas, u Davidu nakon toliko vremena govoreći, kako je već rečeno: Danas ako glas mu čujete, ne budite srca tvrda."},{"v":8,"t":"Zbilja, da je Jošua njih u Počinak uveo, ne bi Bog nakon toga govorio o drugome danu."},{"v":9,"t":"Dakle: preostaje neki subotni počinak narodu Božjemu!"},{"v":10,"t":"Zaista, tko uđe u njegov počinak, počinuo je od djela svojih kao ono i Bog od svojih."},{"v":11,"t":"Pohitimo dakle ući u taj Počinak da nitko ne padne po uzoru na takvu nepokornost."},{"v":12,"t":"Živa je, uistinu, Riječ Božja i djelotvorna; oštrija je od svakoga dvosjekla mača; prodire dotle da dijeli dušu i duh, zglobove i moždinu te prosuđuje nakane i misli srca."},{"v":13,"t":"Nema stvorenja njoj skrivena. Sve je, naprotiv, golo i razgoljeno očima Onoga komu nam je dati račun."},{"v":14,"t":"Imajući dakle velikoga Velikog svećenika koji prodrije kroz nebesa - Isusa, Sina Božjega - čvrsto se držimo vjere."},{"v":15,"t":"Ta nemamo takva Velikog svećenika koji ne bi mogao biti supatnik u našim slabostima, nego poput nas iskušavana svime, osim grijehom."},{"v":16,"t":"Pristupajmo dakle smjelo Prijestolju milosti da primimo milosrđe i milost nađemo za pomoć u pravi čas!"}]},"5":{"hr":[{"v":1,"t":"Svaki veliki svećenik, zaista, od ljudi uzet, za ljude se postavlja u odnosu prema Bogu da prinosi darove i žrtve za grijehe."},{"v":2,"t":"On može primjereno suosjećati s onima koji su u neznanju i zabludi jer je i sam zaogrnut slabošću."},{"v":3,"t":"Zato mora i za narod i za sebe prinositi okajnice."},{"v":4,"t":"I nitko sam sebi ne prisvaja tu čast, nego je prima od Boga, pozvan kao Aron."},{"v":5,"t":"Tako i Krist ne proslavi sam sebe postavši svećenik, nego ga proslavi Onaj koji mu reče: Ti si sin moj, danas te rodih,"},{"v":6,"t":"po onome što pak drugdje veli: Zauvijek ti si svećenik po redu Melkisedekovu."},{"v":7,"t":"On je u dane svoga zemaljskog života sa silnim vapajem i suzama prikazivao molitve i prošnje Onomu koji ga je mogao spasiti od smrti. I bi uslišan zbog svoje predanosti:"},{"v":8,"t":"premda je Sin, iz onoga što prepati, naviknu slušati"},{"v":9,"t":"i, postigavši savršenstvo, posta svima koji ga slušaju začetnik vječnoga spasenja -"},{"v":10,"t":"proglašen od Boga Velikim svećenikom po redu Melkisedekovu."},{"v":11,"t":"O tome nas čeka besjeda velika, ali teško ju je riječima izložiti jer ste tvrdih ušiju."},{"v":12,"t":"Pa trebalo bi doista da nakon toliko vremena već budete učitelji, a ono treba da tkogod vas ponovno poučava početnička počela kazivanja Božjih. Takvi ste: mlijeka vam treba, a ne tvrde hrane."},{"v":13,"t":"Doista, tko je god još pri mlijeku, ne zna ništa o nauku pravednosti jer - nejače je."},{"v":14,"t":"A za zrele je tvrda hrana, za one koji imaju iskustvom izvježbana čula za rasuđivanje dobra i zla."}]},"6":{"hr":[{"v":1,"t":"Stoga mimoiđimo početnički nauk o Kristu i uzdignimo se k savršenome ne postavljajući iznovice temelja: obraćenje od mrtvih djela i vjera u Boga,"},{"v":2,"t":"naučavanje o krštenjima i polaganje ruku, uskrsnuće mrtvih i vječni sud."},{"v":3,"t":"To ćemo pak učiniti, dakako, ako Bog da."},{"v":4,"t":"Zaista, onima koji su jednom prosvijetljeni, i okusili dar nebeski, i postali dionici Duha Svetoga,"},{"v":5,"t":"i okusili Lijepu riječ Božju i snage budućega svijeta,"},{"v":6,"t":"pa otpali, nemoguće je opet se obnoviti na obraćenje kad oni sami ponovno razapinju Sina Božjega i ruglu ga izvrgavaju."},{"v":7,"t":"Jer zemlja koja se napije kiše što na nju često pada i rađa raslinjem korisnim onima za koje se i obrađuje, prima blagoslov od Boga;"},{"v":8,"t":"ona pak koja donosi trnje i drač, odbačena je, blizu prokletstvu a svršetak joj je: “U oganj!”"},{"v":9,"t":"A uvjereni smo, ljubljeni, sve ako tako i govorimo, da je s vama dobro i da ste na putu spasenja."},{"v":10,"t":"Ta Bog nije nepravedan da bi zaboravio vaše djelo i ljubav što je iskazaste njegovu imenu posluživši i poslužujući svetima."},{"v":11,"t":"Želimo ipak da svatko od vas sve do svršetka pokazuje tu istu gorljivost za ispunjenje nade"},{"v":12,"t":"te ne omlitavite, nego budete nasljedovatelji onih koji po vjeri i strpljivosti baštine obećano."},{"v":13,"t":"Doista, kad je Bog Abrahamu davao obećanje, jer se nije imao kime većim zakleti, zakle se samim sobom:"},{"v":14,"t":"Uistinu, blagosloviti, blagoslovit ću te i umnožiti, umnožit ću te."},{"v":15,"t":"I tako Abraham, strpljiv, postiže obećano."},{"v":16,"t":"Ljudi se doista kunu onim tko je veći i zakletva im je, kao potkrepa, kraj svake raspre."},{"v":17,"t":"Tako i Bog: htio je baštinicima obećanja obilatije pokazati nepromjenljivost svoje odluke pa zato zajamči zakletvom"},{"v":18,"t":"da bismo po dva nepromjenljiva čina - u kojima je nemoguće da bi Bog prevario - mi pribjeglice imali snažno ohrabrenje da se držimo ponuđene nade."},{"v":19,"t":"Ona nam je kao pouzdano i čvrsto sidro duše što ulazi u unutrašnjost iza zavjese,"},{"v":20,"t":"kamo je kao preteča za nas ušao Isus postavši zauvijek Veliki svećenik po redu Melkisedekovu."}]},"7":{"hr":[{"v":1,"t":"Doista, taj Melkisedek, kralj šalemski, svećenik Boga Svevišnjega što je izašao u susret Abrahamu koji se vraćao s poraza kraljeva i blagoslovio ga,"},{"v":2,"t":"i komu Abraham odijeli desetinu od svega; on koji u prijevodu znači najprije “kralj pravednosti”, a zatim i kralj šalemski, to jest “kralj mira”;"},{"v":3,"t":"on, bez oca, bez majke, bez rodoslovlja; on, kojemu dani nemaju početka ni život kraja - sličan Sinu Božjemu, ostaje svećenik zasvagda."},{"v":4,"t":"Pa promotrite koliki li je taj komu Abraham, rodozačetnik, dade desetinu od najboljega."},{"v":5,"t":"Istina, i oni sinovi Levijevi, koji primaju svećeništvo imaju zakonsku zapovijed da ubiru desetinu od naroda, to jest od svoje braće premda su i ona izašla iz boka Abrahamova."},{"v":6,"t":"Ali on, koji nije iz njihova rodoslovlja, ubra desetinu od Abrahama i blagoslovi njega, nosioca obećanja!"},{"v":7,"t":"A posve je neprijeporno: veći blagoslivlja manjega."},{"v":8,"t":"K tome, ovdje desetinu primaju smrtni ljudi, a ondje onaj, za kojega se svjedoči da živi."},{"v":9,"t":"I u Abrahamu se, tako reći, ubire desetina i od Levija koji inače desetinu prima"},{"v":10,"t":"jer još bijaše u boku očevu kad mu u susret iziđe Melkisedek."},{"v":11,"t":"Da se dakle savršenstvo postiglo po levitskom svećeništvu - jer na temelju njega narod je dobio Zakon - koja bi onda bila potreba da se po redu Melkisedekovu postavi drugi svećenik i da se ne imenuje po redu Aronovu?"},{"v":12,"t":"Doista kad se mijenja svećeništvo, nužno se mijenja i Zakon."},{"v":13,"t":"Jer onaj o kojemu se to veli pripadao je drugom plemenu, od kojega se nitko nije posvetio žrtveniku."},{"v":14,"t":"Poznato je da je Gospodin naš potekao od Jude, plemena za koje Mojsije ništa ne reče s obzirom na svećenike."},{"v":15,"t":"To je još očitije ako se drugi svećenik postavlja po sličnosti s Melkisedekom:"},{"v":16,"t":"postao je svećenikom ne po Zakonu tjelesne uredbe, nego snagom neuništiva života."},{"v":17,"t":"Ta svjedoči se: Zauvijek ti si svećenik po redu Melkisedekovu."},{"v":18,"t":"Dokida se dakle prijašnja uredba zbog njezine nemoći i beskorisnosti -"},{"v":19,"t":"jer Zakon nije ništa priveo k savršenstvu - a uvodi se bolja nada, po kojoj se približujemo Bogu."},{"v":20,"t":"I to se nije zbilo bez zakletve. Jer oni su bez zakletve postali svećenicima,"},{"v":21,"t":"a on sa zakletvom Onoga koji mu reče: Zakleo se Gospodin i neće se pokajati: “Zauvijek ti si svećenik”."},{"v":22,"t":"Utoliko je Isus i postao jamac boljega Saveza."},{"v":23,"t":"K tomu, mnogo je bilo svećenika jer ih je smrt priječila trajno ostati."},{"v":24,"t":"A on, jer ostaje dovijeka, ima neprolazno svećeništvo."},{"v":25,"t":"Zato i može do kraja spasavati one koji po njemu pristupaju k Bogu - uvijek živ da se za njih zauzima."},{"v":26,"t":"Takav nam Veliki svećenik i bijaše potreban - svet, nedužan, neokaljan, odijeljen od grešnika i uzvišeniji od nebesa -"},{"v":27,"t":"koji ne treba da kao oni veliki svećenici danomice prinosi žrtve najprije za svoje grijehe, a onda za grijehe naroda. To on učini jednom prinijevši samoga sebe."},{"v":28,"t":"Zakon doista postavi za velike svećenike ljude podložne slabosti, a riječ zakletve - nakon Zakona - Sina zauvijek usavršena."}]},"8":{"hr":[{"v":1,"t":"A glavno u ovom izlaganju jest: takva imamo Velikog svećenika koji sjede zdesna prijestolja Veličanstva na nebesima"},{"v":2,"t":"kao bogoslužnik Svetinje i Šatora istinskoga što ga podiže Gospodin, a ne čovjek."},{"v":3,"t":"Doista, svaki se veliki svećenik postavlja da prinosi darove i žrtve. Odatle je potrebno da i on ima što bi prinio."},{"v":4,"t":"Svakako, da je na zemlji, ne bi bio svećenik jer postoje oni koji po Zakonu prinose darove."},{"v":5,"t":"Oni služe slici i sjeni onoga nebeskoga, kako je upućen Mojsije kad se spremao praviti šator: Pazi, veli doista, načini sve po praliku koji ti je pokazan na brdu."},{"v":6,"t":"Ovako mu pak dopalo uzvišenije bogosluženje koliko je Posrednik boljega Saveza, koji je uzakonjen na boljim obećanjima."},{"v":7,"t":"Da je, zbilja, onaj prvi bio besprijekoran, ne bi se drugome tražilo mjesto."},{"v":8,"t":"Doista, kudeći ih veli: Evo dolaze dani - govori Gospodin - kad ću s domom Izraelovim i s domom Judinim dovršiti novi Savez."},{"v":9,"t":"Ne Savez kakav učinih s ocima njihovim u dan kad ih uzeh za ruku da ih izvedem iz zemlje egipatske jer oni ne ustrajaše u mom Savezu pa i ja zanemarih njih - govori Gospodin."},{"v":10,"t":"Nego, ovo je Savez kojim ću se svezati s domom Izraelovim nakon ovih dana - govori Gospodin: Zakone ću svoje staviti u dušu njihovu i upisati ih u njihova srca. I bit ću Bog njihov, a oni narod moj."},{"v":11,"t":"I neće više nitko učiti sugrađanina i nitko brata svoga govoreći: “Spoznaj Gospodina”, ta svi će me poznavati, malo i veliko,"},{"v":12,"t":"jer ću se smilovati bezakonjima njihovim i grijeha se njihovih neću više spominjati."},{"v":13,"t":"Kad veli novi, ostari onaj prvi. Što pak stÓari i dotrajava, blizu je nestanku."}]},"9":{"hr":[{"v":1,"t":"I onaj prvi je, svakako, imao bogoštovne uredbe i Svetinju, ali ovosvjetsku."},{"v":2,"t":"Šator je uistinu bio uređen: prvi, u kojem bijaše svijećnjak, stol i prinos kruhova, a zove se Svetinja;"},{"v":3,"t":"iza druge pak zavjese bio je Šator zvan Svetinja nad svetinjama -"},{"v":4,"t":"u njoj zlatni kadionik i Kovčeg saveza, sav optočen zlatom, a u njemu zlatna posuda s manom i štap Aronov, koji je ono procvao, i ploče Saveza;"},{"v":5,"t":"povrh njega pak kerubi Slave što osjenjuju Pomirilište. O tom ne treba sada potanko govoriti."},{"v":6,"t":"Pošto je to tako uređeno, u prvi Šator stalno ulaze svećenici obavljati bogoslužje,"},{"v":7,"t":"a u drugi jednom godišnje samo veliki svećenik, i to ne bez krvi koju prinosi za sebe i za nepažnje naroda."},{"v":8,"t":"Time Duh Sveti očituje da još nije otkriven put u Svetinju dok još postoji prvi Šator."},{"v":9,"t":"To je slika za sadašnje vrijeme: prinose se darovi i žrtve koje ne mogu u savjesti usavršiti bogoslužnika -"},{"v":10,"t":"sve same na ićima i pićima i raznim pranjima utemeljene tjelesne uredbe, nametnute do časa ispravka."},{"v":11,"t":"Krist se pak pojavi kao Veliki svećenik budućih dobara pa po većem i savršenijem Šatoru - nerukotvorenu, koji nije od ovoga stvorenja -"},{"v":12,"t":"i ne po krvi jaraca i junaca, nego po svojoj uđe jednom zauvijek u Svetinju i nađe vječno otkupljenje."},{"v":13,"t":"Doista, ako već poškropljena krv jaraca i bikova i pepeo juničin posvećuje onečišćene, daje tjelesnu čistoću,"},{"v":14,"t":"koliko će više krv Krista - koji po Duhu vječnom samoga sebe bez mane prinese Bogu - očistiti savjest našu od mrtvih djela, na službu Bogu živomu!"},{"v":15,"t":"A radi ovoga je Posrednik novoga Saveza: da po smrti za otkupljenje prekršaja iz starog Saveza pozvani zadobiju obećanu vječnu baštinu."},{"v":16,"t":"Jer gdje je posrijedi savez-oporuka, potrebno je dokazati smrt oporučitelja."},{"v":17,"t":"Oporuka je doista valjana tek nakon smrti: nikad ne vrijedi dok oporučitelj živi."},{"v":18,"t":"Stoga ni onaj prvi Savez nije bez krvi ustanovljen."},{"v":19,"t":"Pošto je svemu narodu priopćio svaku zapovijed zakonsku, uze Mojsije krv junaca i jaraca s vodom i grimiznom vunom i izopom te samu Knjigu i sav narod poškropi"},{"v":20,"t":"govoreći: Ovo je krv Saveza koji vam odredi Bog;"},{"v":21,"t":"a onda krvlju slično poškropi i Šator i sve bogoslužno posuđe."},{"v":22,"t":"I gotovo se sve po zakonu čisti krvlju i bez prolijevanja krvi nema oproštenja."},{"v":23,"t":"Ako se dakle time čiste slike onoga što je na nebu, potrebno je da se samo to nebesko čisti žrtvama od tih uspješnijima."},{"v":24,"t":"Krist doista ne uđe u rukotvorenu Svetinju, protulik one istinske, nego u samo nebo: da se sada pojavi pred licem Božjim za nas."},{"v":25,"t":"Ne da mnogo puta prinosi samoga sebe kao što veliki svećenik svake godine ulazi u Svetinju s tuđom krvlju;"},{"v":26,"t":"inače bi bilo trebalo da trpi mnogo puta od postanka svijeta. No sada se pojavio, jednom na svršetku vjekova, da grijeh dokine žrtvom svojom."},{"v":27,"t":"I kao što je ljudima jednom umrijeti, a potom na sud,"},{"v":28,"t":"tako i Krist: jednom se prinese da grijehe mnogih ponese, a drugi će se put - bez obzira na grijeh - ukazati onima koji ga iščekuju sebi na spasenje."}]},"10":{"hr":[{"v":1,"t":"Budući da Zakon ima tek sjenu budućih dobara, a ne sam lik zbiljnosti, on uistinu žrtvama koje se - iz godine u godinu iste - neprestano prinose ne može nikada usavršiti one što pristupaju."},{"v":2,"t":"Ta ne bi li se prestale prinositi kad bogoslužnici, jednom očišćeni, ne bi više imali nikakve svijesti grijeha?"},{"v":3,"t":"Ali po njima se iz godine u godinu podsjeća na grijehe."},{"v":4,"t":"Jer krv bikova i jaraca nikako ne može odnijeti grijeha."},{"v":5,"t":"Zato On ulazeći u svijet veli: Žrtva i prinos ne mile ti se, nego si mi tijelo pripravio;"},{"v":6,"t":"paljenice i okajnice ne sviđaju ti se."},{"v":7,"t":"Tada rekoh: “Evo dolazim!” U svitku knjige piše za mene: “Vršiti, Bože, volju tvoju!”"},{"v":8,"t":"Pošto gore reče: Žrtve i prinosi, paljenice i okajnice - koje se po Zakonu prinose - ne mile ti se i ne sviđaju,"},{"v":9,"t":"veli zatim: Evo dolazim vršiti volju tvoju! Dokida prvo da uspostavi drugo."},{"v":10,"t":"U toj smo volji posvećeni prinosom tijela Isusa Krista jednom zauvijek."},{"v":11,"t":"I svaki je svećenik dan za danom u bogoslužju te učestalo prinosi iste žrtve, koje nikako ne mogu odnijeti grijeha."},{"v":12,"t":"A ovaj, pošto je prinio jednu jedincatu žrtvu za grijehe, zauvijek sjede zdesna Bogu"},{"v":13,"t":"čekajući otad dok se neprijatelji ne podlože za podnožje nogama njegovim."},{"v":14,"t":"Jednim uistinu prinosom zasvagda usavrši posvećene."},{"v":15,"t":"A to nam svjedoči i Duh Sveti. Pošto je doista rekao:"},{"v":16,"t":"“Ovo je Savez kojim ću se svezati s njima nakon ovih dana”, Gospodin govori: “Zakone ću svoje staviti u njihova srca i upisati ih u dušu njihovu."},{"v":17,"t":"I grijeha se njihovih i bezakonja njihovih neću više spominjati.”"},{"v":18,"t":"A gdje su grijesi oprošteni, nema više prinosa za njih."},{"v":19,"t":"Imamo dakle, braćo, slobodan ulaz u Svetinju po krvi Isusovoj -"},{"v":20,"t":"put nov i živ što nam ga On otvori kroz zavjesu, to jest svoje tijelo;"},{"v":21,"t":"imamo i Velikog svećenika nad kućom Božjom."},{"v":22,"t":"Pristupajmo stoga s istinitim srcem u punini vjere, srdaca škropljenjem očišćenih od zle savjesti i tijela oprana čistom vodom."},{"v":23,"t":"Čuvajmo nepokolebljivu vjeru nade jer je vjeran Onaj koji dade obećanje."},{"v":24,"t":"I pazimo jedni na druge da se potičemo na ljubav i dobra djela"},{"v":25,"t":"te ne propuštamo svojih sastanaka, kako je u nekih običaj, nego se hrabrimo, to više što više vidite da se bliži Dan."},{"v":26,"t":"Jer ako svojevoljno griješimo pošto primismo spoznanje istine, nema više žrtve za grijehe,"},{"v":27,"t":"nego strašno isčekivanje suda i bijesa ognja što će proždrijeti protivnike."},{"v":28,"t":"Je li tko prekršio Zakon Mojsijev, bez milosrđa biva pogubljen na osnovi dvojice ili trojice svjedoka."},{"v":29,"t":"Zamislite koliko li će goru kaznu zavrijediti tko Sina Božjega pogazi, i nečistom smatra krv Saveza kojom je posvećen, i Duha milosti pogrdi?"},{"v":30,"t":"Ta poznajemo Onoga koji je rekao: Moja je odmazda, ja ću je vratiti; i još: Sudit će Gospodin svome puku."},{"v":31,"t":"Strašno je upasti u ruke Boga živoga."},{"v":32,"t":"A spomenite se onih prvih dana kada ste, tek prosvijetljeni, izdržali veliku patničku borbu:"},{"v":33,"t":"ovamo javno izvrgnuti porugama i nevoljama, onamo postavši zajedničari onih s kojima se tako postupalo."},{"v":34,"t":"I doista, sa sužnjevima ste suosjećali i s radošću prihvatili otimanje dobara znajući da imate bolji, trajan posjed."},{"v":35,"t":"Ne gubite dakle pouzdanja! Pripada mu velika plaća!"},{"v":36,"t":"Postojanosti vam uistinu treba da biste vršeći volju Božju zadobili obećano."},{"v":37,"t":"Jer još malo, sasvim malo, i Onaj koji dolazi doći će i neće zakasniti"},{"v":38,"t":"A pravednik će moj od vjere živjeti, ako li pak otpadne, ne mili se on duši mojoj."},{"v":39,"t":"A mi nismo od onih koji otpadaju, sebi na propast, nego od onih koji vjeruju na spas duše."}]},"11":{"hr":[{"v":1,"t":"A vjera je već neko imanje onoga čemu se nadamo, uvjerenost u zbiljnosti kojih ne vidimo."},{"v":2,"t":"Zbog nje stari primiše svjedočanstvo."},{"v":3,"t":"Vjerom spoznajemo da su svjetovi uređeni riječju Božjom tako te ovo vidljivo ne posta od nečega pojavnoga."},{"v":4,"t":"Vjerom Abel prinese Bogu bolju žrtvu nego Kain. Po njoj primi svjedočanstvo da je pravedan - Bog nad njegovim darovima posvjedoči - po njoj i mrtav još govori."},{"v":5,"t":"Vjerom Henok bi prenesen da ne vidi smrti te iščeznu jer ga je prenio Bog. Doista, prije prijenosa primio je svjedočanstvo da omilje Bogu."},{"v":6,"t":"A bez vjere nemoguće je omiljeti Bogu jer tko mu pristupa, vjerovati mora da postoji i da je platac onima koji ga traže."},{"v":7,"t":"Vjerom Noa, upućen u ono što još ne bijaše vidljivo, predano sagradi korablju na spasenje svoga doma. Time osudi svijet i postade baštinikom vjerničke pravednosti."},{"v":8,"t":"Vjerom pozvan, Abraham posluša i zaputi se u kraj koji je imao primiti u baštinu, zaputi se ne znajući kamo ide."},{"v":9,"t":"Vjerom se kao pridošlica naseli u obećanoj zemlji kao u tuđini, prebivajući pod šatorima s Izakom i Jakovom, subaštinicima istog obećanja,"},{"v":10,"t":"jer iščekivaše onaj utemeljeni Grad kojemu je graditelj i tvorac Bog."},{"v":11,"t":"Vjerom i Sara unatoč svojoj dobi zadobi moć da začne jer vjernim smatraše Onoga koji joj dade obećanje."},{"v":12,"t":"Zato od jednoga, i to obamrla, nasta mnoštvo poput zvijezda na nebu i pijeska nebrojena na obali morskoj."},{"v":13,"t":"U vjeri svi su oni umrli, a da nisu zadobili obećanja, već su ih samo izdaleka vidjeli i pozdravili priznavši da su stranci i pridošlice na zemlji."},{"v":14,"t":"Doista, koji tako govore, jasno očituju da domovinu traže."},{"v":15,"t":"Dakako, da su mislili na onu iz koje su izišli, imali bi još prilike vratiti se u nju."},{"v":16,"t":"Ali sada oni čeznu za boljom, to jest nebeskom. Stoga se Bog ne stidi zvati se Bogom njihovim: ta pripravio im je Grad."},{"v":17,"t":"Vjerom Abraham, kušan, prikaza Izaka. Jedinca prikazivaše on koji je primio obećanje,"},{"v":18,"t":"kome bi rečeno: Po Izaku će ti se nazivati potomstvo! -"},{"v":19,"t":"uvjeren da Bog može i od mrtvih uskrisiti. Zato ga u predslici i ponovno zadobi."},{"v":20,"t":"Vjerom baš u pogledu budućnosti Izak blagoslovi Jakova i Ezava."},{"v":21,"t":"Vjerom Jakov, umirući, blagoslovi oba sina Josipova i duboko se prignu oslonjen na vrh svojega štapa."},{"v":22,"t":"Vjerom Josip na umoru napomenu ono o izlasku sinova Izraelovih i dade zapovijed o svojim kostima."},{"v":23,"t":"Vjerom su Mojsija netom rođena tri mjeseca krili njegovi roditelji jer vidješe da je djetešce lijepo i nisu se bojali kraljeve naredbe."},{"v":24,"t":"Vjerom Mojsije, već odrastao, odbi zvati se sinom kćeri faraonove."},{"v":25,"t":"Radije izabra biti zlostavljan zajedno s Božjim narodom, nego se časovito okoristiti grijehom."},{"v":26,"t":"Većim je bogatstvom od blaga egipatskih smatrao muku Kristovu jer je gledao na plaću."},{"v":27,"t":"Vjerom napusti Egipat, ne bojeći se bijesa kraljeva, postojan kao da Nevidljivoga vidi."},{"v":28,"t":"Vjerom je obavio pashu i škropljenje krvlju da Zatornik ne dotakne prvenaca Izraelovih."},{"v":29,"t":"Vjerom prođoše Crvenim morem kao po suhu, što i Egipćani pokušaše, ali se potopiše."},{"v":30,"t":"Vjerom zidine jerihonske padoše nakon sedmodnevnoga ophoda."},{"v":31,"t":"Vjerom Rahaba, bludnica, ne propade zajedno s nepokornicima jer s mirom primi uhode."},{"v":32,"t":"I što još da kažem? Ta ponestat će mi vremena, počnem li raspredati o Gideonu, Baraku, Samsonu, Jiftahu, Davidu, pa Samuelu i prorocima,"},{"v":33,"t":"koji su po vjeri osvojili kraljevstva, odjelotvorili pravednost, zadobili obećano, začepili ralje lavovima,"},{"v":34,"t":"pogasili žestinu ognja, umakli oštrici mača, oporavili se od slabosti, ojačali u boju, odbili navale tuđinaca."},{"v":35,"t":"Žene su po uskrsnuću ponovno zadobile svoje pokojne. Drugi pak, stavljeni na muke, ne prihvatiše oslobođenja da bi ih zapalo bolje uskrsnuće."},{"v":36,"t":"Drugi su opet iskusili izrugivanja i bičeve, pa i okove i tamnicu."},{"v":37,"t":"Kamenovani su, piljeni, poubijani oštricom mača, potucali se u runima, u kozjim kožusima, u oskudici, potlačeni, zlostavljani -"},{"v":38,"t":"svijet ih ne bijaše dostojan - vrludali po pustinjama, gorama, pećinama i pukotinama zemaljskim."},{"v":39,"t":"I svi oni po vjeri, istina, primiše svjedočanstvo, ali ne zadobiše obećano"},{"v":40,"t":"jer Bog je za nas predvidio nešto bolje da oni bez nas ne dođu do savršenstva."}]},"12":{"hr":[{"v":1,"t":"Zato i mi, okruženi tolikim oblakom svjedoka, odložimo svaki teret i grijeh koji nas sapinje te postojano trčimo u borbu koja je pred nama!"},{"v":2,"t":"Uprimo pogled u Početnika i Dovršitelja vjere, Isusa, koji umjesto radosti što je stajala pred njim podnese križ, prezrevši sramotu te sjedi zdesna prijestolja Božjega."},{"v":3,"t":"Doista pomno promotrite njega, koji podnese toliko protivljenje grešnika protiv sebe, da - premoreni - ne klonete duhom."},{"v":4,"t":"Ta još se do krvi ne oduprijeste u borbi protiv grijeha."},{"v":5,"t":"Pa zar ste zaboravili opomenu koja vam je kao sinovima upravljena: Sine moj, ne omalovažavaj stege Gospodnje i ne kloni kad te on ukori."},{"v":6,"t":"Jer koga Gospodin ljubi, onoga i stegom odgaja, šiba sina koga voli."},{"v":7,"t":"Poradi vašega odgajanja trpite. Bog s vama postupa kao sa sinovima: a ima li koji sin kojega otac stegom ne odgaja?"},{"v":8,"t":"Pa ako niste pod stegom, na kojoj su svi imali udjela, onda ste kopilad, a ne djeca."},{"v":9,"t":"Zatim, tjelesne smo oce imali odgojiteljima i poštovali ih. Pa nećemo li se kudikamo više podlagati Ocu duhova te živjeti?"},{"v":10,"t":"Oni su nas doista nešto malo dana stegom odgajali kako se njima činilo, a On - nama na korist, da postanemo sudionici njegove svetosti."},{"v":11,"t":"Isprva se doduše čini da nijedno odgajanje nije radost, nego žalost, ali onima koji su njime uvježbani poslije donosi mironosni plod pravednosti."},{"v":12,"t":"Zato uspravite ruke klonule i koljena klecava,"},{"v":13,"t":"poravnite staze za noge svoje da se hromo ne iščaši, nego, štoviše, da ozdravi."},{"v":14,"t":"Nastojte oko mira sa svima! I oko posvećenja bez kojega nitko neće vidjeti Gospodina!"},{"v":15,"t":"Pripazite da se tko ne sustegne od milosti Božje, da kakav gorki korijen ne proklija pa ne unese zabunu i ne zarazi mnoge,"},{"v":16,"t":"da tko ne postane bludnik ili svetogrdnik kao Ezav, koji za jedan jedini obrok proda svoje prvorodstvo."},{"v":17,"t":"Ta znate da je i poslije, kad je htio baštiniti blagoslov, odbačen jer nije našao mogućnosti promjene premda ju je sa suzama tražio."},{"v":18,"t":"Jer niste pristupili opipljivoj gori i usplamtjelu ognju, ni mraku, tami i vihoru,"},{"v":19,"t":"ni ječanju trublje i tutnjavi riječi. - Koji su je slušali, zamoliše da im se više ne govori"},{"v":20,"t":"jer nisu podnosili naredbe: Ako se ma i živinče dotakne brda, neka se kamenuje!"},{"v":21,"t":"I prizor bijaše tako strašan da Mojsije reče: “Strah me je i dršćem!” -"},{"v":22,"t":"Nego, vi ste pristupili gori Sionu i gradu Boga živoga, Jeruzalemu nebeskom, nebrojenim tisućama anđela, svečanom skupu,"},{"v":23,"t":"Crkvi prvorođenaca zapisanih na nebu, Bogu, sucu sviju, dusima savršenih pravednika"},{"v":24,"t":"i Posredniku novog Saveza - Isusu - i krvi škropljeničkoj što snažnije govori od Abelove."},{"v":25,"t":"Pazite da ne odbijete Onoga koji vam govori! Jer ako ne umakoše oni što su odbili onoga koji je na zemlji davao upute, kudikamo ćemo manje mi ako se okrenemo od Onoga koji ih daje s nebesa."},{"v":26,"t":"Njegov glas tada zemlju uzdrma, sada pak obećava: Još jednom ja ću potresti ne samo zemlju nego i nebo."},{"v":27,"t":"Ono “još jednom” pokazuje da će, kao stvoreno, uminuti ono uzdrmano da ostane ono neuzdrmljivo."},{"v":28,"t":"Zato jer smo primili kraljevstvo neuzdrmljivo, iskazujmo zahvalnost iz koje služimo Bogu kako je njemu milo, s predanjem i strahopoštovanjem."},{"v":29,"t":"Jer Bog je naš oganj što proždire."}]},"13":{"hr":[{"v":1,"t":"Bratoljublje neka je trajno!"},{"v":2,"t":"Gostoljublja ne zaboravljajte: njime neki, i ne znajući, ugostiše anđele!"},{"v":3,"t":"Sjećajte se uznika kao suuznici; zlostavljanih - ta i sami ste u tijelu!"},{"v":4,"t":"Ženidba neka bude u časti u sviju i postelja neokaljana! Jer bludnicima će i preljubnicima suditi Bog."},{"v":5,"t":"U življenju ne budite srebroljupci, zadovoljni onim što imate! Ta on je rekao: Ne, neću te zapustiti i neću te ostaviti."},{"v":6,"t":"Zato možemo pouzdano reći: Gospodin mi je pomoćnik, ja ne strahujem: što mi tko može?"},{"v":7,"t":"Spominjite se svojih glavara koji su vam nevješćivali riječ Božju: promatrajući kraj njihova života, nasljedujte njihovu vjeru."},{"v":8,"t":"Isus Krist jučer i danas isti je - i uvijeke."},{"v":9,"t":"Ne dajte se zanijeti različitim tuđim naucima! Jer bolje je srce utvrđivati milošću nego jelima, koja nisu koristila onima što su ih obdržavali."},{"v":10,"t":"Imamo žrtvenik s kojega nemaju pravo jesti služitelji Šatora."},{"v":11,"t":"Jer tijela životinja, kojih krv veliki svećenik unosi za grijeh u Svetinju, spaljuju se izvan tabora."},{"v":12,"t":"Zato i Isus, da bi vlastitom krvlju posvetio narod, trpio je izvan vrata."},{"v":13,"t":"Stoga iziđimo k njemu izvan tabora noseći njegovu muku"},{"v":14,"t":"jer nemamo ovdje trajna grada, nego onaj budući tražimo."},{"v":15,"t":"Po njemu dakle neprestano prinosimo Bogu žrtvu hvalbenu, to jest plod usana što ispovijedaju ime njegovo."},{"v":16,"t":"Dobrotvornosti i zajedništva ne zaboravljajte jer takve su žrtve mile Bogu!"},{"v":17,"t":"Poslušni budite svojim glavarima i podložni jer oni bdiju nad vašim dušama kao oni koji će polagati račun; neka to čine s radošću, a ne uzdišući jer vam to ne bi bilo korisno."},{"v":18,"t":"Molite za nas! Uvjereni smo doista da imamo dobru savjest i u svemu se želimo dobro ponašati."},{"v":19,"t":"Usrdnije vas pak molim: učinite to kako bih vam se što brže vratio."},{"v":20,"t":"A Bog mira, koji po krvi vječnoga Saveza od mrtvih izvede velikoga Pastira ovaca, Gospodina našega Isusa,"},{"v":21,"t":"osposobio vas za svako dobro djelo da vršite volju njegovu, činio u nama što je njemu milo, po Isusu Kristu, komu slava u vijeke vjekova. Amen."},{"v":22,"t":"Molim vas, braćo, podnesite ovu riječ ohrabrenja: ta samo vam ukratko napisah!"},{"v":23,"t":"Znajte: naš je brat Timotej oslobođen. Ako uskoro stigne, s njime ću vas pohoditi."},{"v":24,"t":"Pozdravite sve svoje glavare i sve svete! Pozdravljaju vas ovi iz Italije."},{"v":25,"t":"Milost sa svima vama!"}]}},"JAS":{"1":{"hr":[{"v":1,"t":"Jakov, sluga Boga i Gospodina Isusa Krista: dvanaestorma plemena Raseljeništva pozdrav."},{"v":2,"t":"Pravom radošću smatrajte, braćo moja, kad upadnete u razne kušnje"},{"v":3,"t":"znajući da prokušanost vaše vjere rađa postojanošću."},{"v":4,"t":"Ali neka postojanost bude na djelu savršena da budete savršeni i potpuni, bez ikakva nedostataka."},{"v":5,"t":"Nedostaje li komu od vas mudrosti, neka ište od Boga, koji svima daje rado i bez negodovanja, i dat će mu se."},{"v":6,"t":"Ali neka ište s vjerom, bez ikakva kolebanja. Jer kolebljivac je sličan morskom valovlju, uzburkanu i gonjenu."},{"v":7,"t":"Neka takav ne misli da će primiti što od Gospodina -"},{"v":8,"t":"čovjek duše dvoumne, nepostojan na svim putovima svojim."},{"v":9,"t":"Neka se brat niska soja ponosi svojim uzvišenjem,"},{"v":10,"t":"a bogataš svojim poniženjem. Ta proći će kao cvijet trave:"},{"v":11,"t":"sunce ogranu žarko te usahnu trava i cvijet njezin uvenu; dražest mu lica propade. Tako će i bogataš na stazama svojim usahnuti."},{"v":12,"t":"Blago čovjeku koji trpi kušnju: prokušan, primit će vijenac života koji je Gospodin obećao onima što ga ljube."},{"v":13,"t":"Neka nitko u napasti ne rekne: “Bog me napastuje.” Ta Bog ne može biti napastovan na zlo, i ne napastuje nikoga."},{"v":14,"t":"Nego svakoga napastuje njegova požuda koja ga privlači i mami."},{"v":15,"t":"Požuda zatim, zatrudnjevši, rađa grijehom, a grijeh izvršen rađa smrću."},{"v":16,"t":"Ne varajte se, braćo moja ljubljena!"},{"v":17,"t":"Svaki dobar dar, svaki savršen poklon odozgor je, silazi od Oca svjetlila u kome nema promjene ni sjene od mijene."},{"v":18,"t":"Po svom naumu on nas porodi riječju Istine da budemo prvina neka njegovih stvorova."},{"v":19,"t":"Znajte, braćo moja ljubljena! Svatko neka bude brz da sluša, spor da govori, spor na srdžbu."},{"v":20,"t":"Jer srdžba čovjekova ne čini pravde Božje."},{"v":21,"t":"Zato odložite svaku prljavštinu i preostalu zloću i sa svom krotkošću primite usađenu riječ koja ima moć spasiti duše vaše."},{"v":22,"t":"Budite vršitelji riječi, a ne samo slušatelji, zavaravajući sami sebe."},{"v":23,"t":"Jer ako je tko slušatelj riječi, a ne i izvršitelj, sličan je čovjeku koji motri svoje rođeno lice u zrcalu:"},{"v":24,"t":"promotri se, ode i odmah zaboravi kakav bijaše."},{"v":25,"t":"A koji se oglÄedÄa u savršenom zakonu slobode i uza nj prione, ne kao zaboravan slušatelj nego djelotvoran izvršitelj, blažen će biti u svem djelovanju svome."},{"v":26,"t":"Smatra li se tko bogoljubnim, a ne obuzdava svoga jezika, nego zavarava srce svoje, isprazna je njegova bogoljubnost."},{"v":27,"t":"Bogoljubnost čista i neokaljana jest: zauzimati se za sirote i udovice u njihovoj nevolji, čuvati se neokaljanim od ovoga svijeta."}]},"2":{"hr":[{"v":1,"t":"Braćo moja, vjeru Gospodina našega Isusa Krista slavnoga ne miješajte s pristranošću!"},{"v":2,"t":"Dođe li na vaš sastanak čovjek sa zlatnim prstenjem, u sjajnoj odjeći, a dođe i siromah u bijednoj odjeći"},{"v":3,"t":"i vi se zagledate u onoga što nosi sjajnu odjeću te reknete: “Ti lijepo ovdje sjedni!”, a siromahu reknete: “Ti stani - ili sjedni - ondje, podno podnožja moga!”,"},{"v":4,"t":"niste li u sebi pristrano sudili te postali suci što naopako sude?"},{"v":5,"t":"Čujte, braćo moja ljubljena: nije li Bog one koji su svijetu siromašni izabrao da budu bogataši u vjeri i baštinici Kraljevstva što ga je obećao onima koji ga ljube?"},{"v":6,"t":"A vi prezreste siromaha! Ne tlače li vas upravo bogataši? Ne vuku li vas baš oni na sudove?"},{"v":7,"t":"Ne psuju li oni lijepo Ime na vas zazvano?"},{"v":8,"t":"Ako doista izvršujete kraljevski zakon po Pismu: Ljubi bližnjega svoga kao sebe samoga, dobro činite;"},{"v":9,"t":"ako li ste pristrani, grijeh činite i Zakon vas osuđuje kao prijestupnike."},{"v":10,"t":"Ta tko sav Zakon uščuva, a u jednome samo posrne, postao je krivac svega."},{"v":11,"t":"Jer tko reče: Ne čini preljuba, reče i: Ne ubij. Ako dakle i ne činiš preljuba, a ubiješ, postao si prijestupnik Zakona."},{"v":12,"t":"Tako govorite i tako činite kao oni koji imaju biti suđeni po zakonu slobode."},{"v":13,"t":"Jer nemilosrdan je sud onomu tko ne čini milosrđa; a milosrđe likuje nad sudom."},{"v":14,"t":"Što koristi, braćo moja, ako tko rekne da ima vjeru, a djela nema? Može li ga vjera spasiti?"},{"v":15,"t":"Ako su koji brat ili sestra goli i bez hrane svagdanje"},{"v":16,"t":"pa im tkogod od vas rekne: “Hajdete u miru, grijte se i sitite”, a ne dadnete im što je potrebno za tijelo, koja korist?"},{"v":17,"t":"Tako i vjera: ako nema djela, mrtva je u sebi."},{"v":18,"t":"Inače, mogao bi tko reći: “Ti imaš vjeru, a ja imam djela. Pokaži mi svoju vjeru bez djela, a ja ću tebi djelima pokazati svoju vjeru."},{"v":19,"t":"Ti vjeruješ da je jedan Bog? Dobro činiš! I đavli vjeruju, i dršću.”"},{"v":20,"t":"Hoćeš li spoznati, šuplja glavo, da je vjera bez djela jalova?"},{"v":21,"t":"Zar se Abraham, otac naš, ne opravda djelima, kad na žrtvenik prinese Izaka, sina svoga?"},{"v":22,"t":"Vidiš: vjera je surađivala s djelima njegovim i djelima se vjera usavršila"},{"v":23,"t":"te se ispunilo Pismo koje veli: Povjerova Abraham Bogu i uračuna mu se u pravednost pa prijatelj Božji posta."},{"v":24,"t":"Gledajte: čovjek se opravdava djelima, a ne samom vjerom."},{"v":25,"t":"Ne opravda li se slično, djelima, i Rahaba bludnica kad primi glasnike i drugim ih putom izvede?"},{"v":26,"t":"Jer kao što je tijelo bez duha mrtvo, tako je i vjera bez djela mrtva."}]},"3":{"hr":[{"v":1,"t":"Neka vas, braćo moja, ne bude mnogo učitelja! Ta znate: bit ćemo strože suđeni."},{"v":2,"t":"Doista, svi mnogo griješimo. Ako tko u govoru ne griješi, savršen je čovjek, vrstan zauzdati i cijelo tijelo."},{"v":3,"t":"Ubacimo li uzde u usta konjima da ih sebi upokorimo, upravljamo i cijelim tijelom njihovim."},{"v":4,"t":"Evo i lađa: tolike su i silni ih vjetrovi gone, a neznatno ih kormilo upravlja kamo kormilarova volja hoće."},{"v":5,"t":"Tako i jezik: malen je ud, a velikim se može ponositi. Evo: kolicna vatra koliku šumu zapali!"},{"v":6,"t":"I jezik je vatra, svijet nepravda jezik je među našim udovima, kalja cijelo tijelo te, zapaljen od pakla, zapaljuje kotač života."},{"v":7,"t":"Doista, sav rod zvijeri i ptica, gmazova i morskih životinja dade se ukrotiti, i rod ih je ljudski ukrotio,"},{"v":8,"t":"a jezik - zlo nemirno, pun otrova smrtonosnog - nitko od ljudi ne može ukrotiti."},{"v":9,"t":"Njime blagoslivljamo Gospodina i Oca, njime i proklinjemo ljude na sliku Božju stvorene:"},{"v":10,"t":"iz istih usta izlazi blagoslov i prokletstvo. Ne smije se, braćo moja, tako događati!"},{"v":11,"t":"Zar vrelo na isti otvor šiklja slatko i gorko?"},{"v":12,"t":"Može li, braćo moja, smokva roditi maslinama ili trs smokvama? Ni slan izvor ne može dati slatke vode."},{"v":13,"t":"Je li tko mudar i razborit među vama? Neka dobrim življenjem pokaže svoja djela u mudroj blagosti."},{"v":14,"t":"Ako u srcu imate gorku zavist i svadljivost, ne uznosite se i ne lažite protiv istine!"},{"v":15,"t":"Nije to mudrost koja odozgor silazi, nego zemaljska, ljudska, đavolska."},{"v":16,"t":"Ta gdje je zavist i svadljivost, ondje je nered i svako zlo djelo."},{"v":17,"t":"A mudrost odozgor ponajprije čista je, zatim mirotvorna, milostiva, poučljiva, puna milosrđa i dobrih plodova, postojana, nehinjena."},{"v":18,"t":"Plod se pak pravednosti u miru sije onima koji tvore mir."}]},"4":{"hr":[{"v":1,"t":"Odakle ratovi, odakle borbe među vama? Zar ne odavde: od pohota što vojuju u udovima vašim?"},{"v":2,"t":"Žudite, a nemate; ubijate i hlepite, a ne možete postići; borite se i ratujete. Nemate jer ne ištete."},{"v":3,"t":"Ištete, a ne primate jer rđavo ištete: da u pohotama svojim potratite."},{"v":4,"t":"Preljubnici! Ne znate li da je prijateljstvo sa svijetom neprijateljstvo prema Bogu? Tko god dakle hoće da bude prijatelj svijeta, promeće se u neprijatelja Božjega."},{"v":5,"t":"Ili mislite da Pismo uzalud veli: Ljubomorno čezne za duhom što ga nastani u nama?"},{"v":6,"t":"A daje on i veću milost. Zato govori: Bog se oholima protivi, a poniznima daje milost."},{"v":7,"t":"Podložite se dakle Bogu! Oduprite se đavlu i pobjeći će od vas!"},{"v":8,"t":"Približite se Bogu i on će se približiti vama! Očistite ruke, grešnici! Očistite srca, dvoličnjaci!"},{"v":9,"t":"Zakukajte, protužite, proplačite! Smijeh vaš nek se u plač obrati i radost u žalost!"},{"v":10,"t":"Ponizite se pred Gospodinom i on će vas uzvisiti!"},{"v":11,"t":"Ne ogovarajte, braćo, jedni druge! Tko ogovara ili sudi brata svoga, ogovara i sudi Zakon. A sudiš li Zakon, nisi vršitelj nego sudac Zakona."},{"v":12,"t":"Jedan je Zakonodavac i Sudac: Onaj koji može spasiti i pogubiti. A tko si ti da sudiš bližnjega?"},{"v":13,"t":"De sada, vi što govorite: “Danas ili sutra otići ćemo u taj i taj grad, provesti ondje godinu, trgovati i zaraditi”,"},{"v":14,"t":"a ne znate što će sutra biti. Ta što je vaš život? Dašak ste što se načas pojavi i zatim nestane!"},{"v":15,"t":"Umjesto da govorite: “Htjedne li Gospodin, živjet ćemo i učiniti ovo ili ono”,"},{"v":16,"t":"vi se razmećete svojim hvastanjima! Svako je takvo hvastanje opako."},{"v":17,"t":"Znati dakle dobro činiti, a ne činiti - grijeh je."}]},"5":{"hr":[{"v":1,"t":"De sada, bogataši, proplačite i zakukajte zbog nevolja koje će vas zadesiti!"},{"v":2,"t":"Bogatstvo vam istrunu, haljine vaše postadoše hrana moljcima,"},{"v":3,"t":"zlato vam i srebro zarđa i rđa će njihova biti svjedočanstvo protiv vas te će kao vatra izjesti tijela vaša! Zgrnuste blago u posljednje dane!"},{"v":4,"t":"Evo: plaća kosaca vaših njiva - koju im uskratiste - viče i vapaji žetelaca dopriješe do ušiju Gospoda nad Vojskama."},{"v":5,"t":"Raskošno ste na zemlji i razvratno živjeli, utoviste srca svoja za dan klanja!"},{"v":6,"t":"Osudiste i ubiste pravednika: on vam se ne suprotstavlja!"},{"v":7,"t":"Strpite se dakle, braćo, do Dolaska Gospodnjega! Evo: ratar iščekuje dragocjeni urod zemlje, strpljiv je s njime dok ne dobije kišu ranu i kasnu."},{"v":8,"t":"Strpite se i vi, očvrsnite srca jer se Dolazak Gospodnji približio!"},{"v":9,"t":"Ne tužite se jedni na druge da ne budete osuđeni! Evo: sudac stoji pred vratima!"},{"v":10,"t":"Za uzor strpljivosti i podnošenja zala uzmite, braćo, proroke koji su govorili u ime Gospodnje."},{"v":11,"t":"Eto: blaženima nazivamo one koji ustrajaše. Za postojanost Jobovu čuste i nakanu Gospodnju vidjeste jer milostiv je Gospodin i milosrdan!"},{"v":12,"t":"Prije svega, braćo moja, ne zaklinjite se ni nebom ni zemljom, ni ikojom drugom zakletvom. Vaše “da” neka bude “da”, i “ne” - “ne”, da ne padnete pod sud."},{"v":13,"t":"Pati li tko među vama? Neka moli! Je li tko radostan? Neka pjeva hvalospjeve!"},{"v":14,"t":"Boluje li tko među vama? Neka dozove starješine Crkve! Oni neka mole nad njim mažući ga uljem u ime Gospodnje"},{"v":15,"t":"pa će molitva vjere spasiti nemoćnika; Gospodin će ga podići, i ako je sagriješio, oprostit će mu se."},{"v":16,"t":"Ispovijedajte dakle jedni drugima grijehe i molite jedni za druge da ozdravite! Mnogo može žarka molitva pravednikova."},{"v":17,"t":"Ilija bijaše čovjek baš kao i mi; usrdno se pomoli da ne bude kiše i kiše nije bilo na zemlji tri godine i šest mjeseci."},{"v":18,"t":"Zatim se ponovno pomoli te nebo dade kišu i zemlja iznese urod svoj."},{"v":19,"t":"Braćo moja, odluta li tko od vas od istine pa ga tkogod vrati,"},{"v":20,"t":"znajte: tko vrati grešnika s lutalačkog puta njegova, spasit će dušu njegovu od smrti i pokriti mnoštvo grijeha."}]}},"1PE":{"1":{"hr":[{"v":1,"t":"Petar, apostol Isusa Krista: putnicima Raseljeništva u Pontu, Galaciji, Kapadociji, Aziji i Bitiniji,"},{"v":2,"t":"po predznanju Boga Oca, posvećenjem Duha izabranima da budu poslušni te poškropljeni krvlju Isusa Krista. Punina vam milosti i mira!"},{"v":3,"t":"Blagoslovljen Bog i Otac Gospodina našega Isusa Krista koji nas po velikom milosrđu svojemu uskrsnućem Isusa Krista od mrtvih nanovo rodi za životnu nadu,"},{"v":4,"t":"za baštinu neraspadljivu, neokaljanu i neuvelu, pohranjenu na nebesima za vas,"},{"v":5,"t":"vas koje snaga Božja po vjeri čuva za spasenje, spremno da se objavi u posljednje vrijeme."},{"v":6,"t":"Zbog toga se radujte, makar se sada možda trebalo malo i žalostiti zbog različitih kušnja:"},{"v":7,"t":"da prokušanost vaše vjere - dragocjenija od propadljivog zlata, koje se ipak u vatri kuša - stekne hvalu, slavu i čast o Objavljenju Isusa Krista."},{"v":8,"t":"Njega vi ljubite iako ga ne vidjeste; u njega, iako ga još ne gledate, vjerujete te klikćete od radosti neizrecive i proslavljene"},{"v":9,"t":"što postigoste svrhu svoje vjere: spasenje duša."},{"v":10,"t":"To su spasenje istraživali i pronicali proroci koji prorokovahu o milosti vama namijenjenoj."},{"v":11,"t":"Pronicali su na koje ili kakvo je vrijeme smjerao Duh Kristov u njima koji je unaprijed svjedočio o Kristovim patnjama te slavama što su nakon njih imale doći:"},{"v":12,"t":"bi im objavljeno da ne sebi nego vama poslužuju ono što vam sada u Duhu Svetom s neba poslanom navijestiše vaši blagovjesnici, a nada što se i anđeli žude nadviti."},{"v":13,"t":"Zato opašite bokove pameti svoje, trijezni budite i savršeno se pouzdajte u milost koju vam donosi Objavljenje Isusa Krista."},{"v":14,"t":"Kao poslušna djeca ne supriličujte se prijašnjim požudama iz doba neznanja."},{"v":15,"t":"Naprotiv, kao što je svet Onaj koji vas pozva, i vi budite sveti u svemu življenju."},{"v":16,"t":"Ta pisano je: Budite sveti jer sam ja svet."},{"v":17,"t":"Ako dakle Ocem nazivate njega koji nepristrano svakoga po djelu sudi, vrijeme svoga proputovanja proživite u bogobojaznosti."},{"v":18,"t":"Ta znate da od svog ispraznog načina života, što vam ga oci namriješe, niste otkupljeni nečim raspadljivim, srebrom ili zlatom,"},{"v":19,"t":"nego dragocjenom krvlju Krista, Jaganjca nevina i bez mane."},{"v":20,"t":"On bijaše doduše predviđen prije postanka svijeta, ali se očitova na kraju vremena radi vas"},{"v":21,"t":"koji po njemu vjerujete u Boga koji ga uskrisi od mrtvih te mu dade slavu da vjera vaša i nada bude u Bogu."},{"v":22,"t":"Pošto ste posluhom istini očistili duše svoje za nehinjeno bratoljublje, od srca žarko ljubite jedni druge."},{"v":23,"t":"Ta nanovo ste rođeni, ne iz sjemena raspadljiva nego neraspadljiva: riječju Boga koji živi i ostaje."},{"v":24,"t":"Doista, svako je tijelo kao trava, sva mu slava ko cvijet poljski: sahne trava, vene cvijet,"},{"v":25,"t":"ali Riječ Gospodnja ostaje dovijeka. Ta pak riječ jest evanđelje koje vam je naviješteno."}]},"2":{"hr":[{"v":1,"t":"Odložite dakle svaku zloću i svaku prijevaru, himbe i zavisti i sva klevetanja."},{"v":2,"t":"Kao novorođenčad žudite za duhovnim, nepatvorenim mlijekom da po njemu uzrastete za spasenje,"},{"v":3,"t":"ako ste doista okusili kako je dobar Gospodin."},{"v":4,"t":"Pristupite k njemu, Kamenu živomu što ga, istina, ljudi odbaciše, ali je u očima Božjim izabran, dragocjen,"},{"v":5,"t":"pa se kao živo kamenje ugrađujte u duhovni Dom za sveto svećenstvo da prinosite žrtve duhovne, ugodne Bogu po Isusu Kristu."},{"v":6,"t":"Stoga stoji u Pismu: Evo postavljam na Sionu kamen odabrani, dragocjeni kamen ugaoni: Tko u nj vjeruje, ne, neće se postidjeti."},{"v":7,"t":"Vama dakle koji vjerujete - čast! A onima koji ne vjeruju - kamen koji odbaciše graditelji postade kamen zaglavni"},{"v":8,"t":"i kamen spoticanja, stijena posrtanja; oni se o nj spotiču, neposlušni Riječi, za što su i određeni."},{"v":9,"t":"A vi ste rod izabrani, kraljevsko svećenstvo, sveti puk, narod stečeni da naviještate silna djela Onoga koji vas iz tame pozva k divnom svjetlu svojemu;"},{"v":10,"t":"vi, nekoć Ne-narod, a sada Narod Božji; vi Ne-mili, a sada Mili."},{"v":11,"t":"Ljubljeni! Zaklinjem vas da se kao pridošlice i putnici klonite putenih požuda koje vojuju protiv duše;"},{"v":12,"t":"življenje vaše među poganima neka bude uzorno da upravo onim za što vas sada potvaraju kao zločince, pošto promotre vaša dobra djela, proslave Boga u dan pohoda."},{"v":13,"t":"Pokoravajte se svakoj ljudskoj ustanovi radi Gospodina: bilo kralju kao vrhovniku,"},{"v":14,"t":"bilo upraviteljima jer ih on šalje da kazne zločince, a pohvale one koji dobro čine."},{"v":15,"t":"Doista, ovo je Božja volja: da čineći dobro ušutkate neznanje bezumnika."},{"v":16,"t":"Kao slobodni ljudi - ali ne kao oni kojima je sloboda tek pokrivalom zloće, već kao Božje sluge -"},{"v":17,"t":"sve poštujte, bratstvo ljubite, Boga se bojte, kralja častite!"},{"v":18,"t":"Sluge, budite sa svim poštovanjem pokorni gospodarima, ne samo dobrima i blagima nego i naopakima."},{"v":19,"t":"To je uistinu milost ako tko radi savjesti, radi Boga podnosi nevolje trpeći nepravedno."},{"v":20,"t":"Kakve li slave doista ako za grijehe udarani strpljivo podnosite? No ako dobro čineći trpite pa strpljivo podnosite, to je Bogu milo."},{"v":21,"t":"Ta na to ste pozvani jer i Krist je trpio za vas i ostavio vam primjer da idete stopama njegovim."},{"v":22,"t":"On koji grijeha ne učini nit mu usta prijevaru izustiše;"},{"v":23,"t":"on koji na uvredu nije uvredom uzvraćao i mučen nije prijetio, prepuštajući to Sucu pravednom;"},{"v":24,"t":"on koji u tijelu svom grijehe naše ponese na drvo da umrijevši grijesima pravednosti živimo; on čijom se modricom izliječiste."},{"v":25,"t":"Doista, poput ovaca lutaste, ali se sada obratiste k pastiru i čuvaru duša svojih."}]},"3":{"hr":[{"v":1,"t":"Tako i vi, žene, pokoravajte se svojim muževima: ako su neki od njih možda neposlušni Riječi, da i bez riječi budu pridobiveni življenjem vas žena,"},{"v":2,"t":"pošto promotre vaše bogoljubno i čisto življenje."},{"v":3,"t":"Vaš nakit neka ne bude izvanjski - pletenje kose, kićenje zlatom ili oblačenje haljina."},{"v":4,"t":"Nego: čovjek skrovita srca, neprolazne ljepote, blaga i smirena duha. To je pred Bogom dragocjeno."},{"v":5,"t":"Tako su se doista i nekoć svete žene, zaufane u Boga, resile: pokoravale su se muževima."},{"v":6,"t":"Sara se tako pokori Abrahamu te ga nazva gospodarom. Njezina ste djeca ako činite dobro ne bojeći se nikakva zastrašivanja."},{"v":7,"t":"Tako i vi, muževi, obazrivo živite sa svojim ženama, kao sa slabijim spolom, te im iskazujte čast kao subaštinicima milosti Života da ne spriječite svojih molitava."},{"v":8,"t":"Napokon, budite svi jednodušni, puni suosjećanja i bratske ljubavi, milosrdni, ponizni!"},{"v":9,"t":"Ne vraćajte zlo za zlo ni uvredu za uvredu! Naprotiv, blagoslivljajte jer ste na to i pozvani da baštinite blagoslov!"},{"v":10,"t":"Doista, tko želi ljubiti život i naužit se dana sretnih, nek suspregne jezik oda zla i usne od riječi prijevarnih;"},{"v":11,"t":"zla nek se kloni, a čini dobro, mir neka traži i za njim ide:"},{"v":12,"t":"jer oči Gospodnje gledaju pravedne, uši mu slušaju vapaje njihove, a lice se Gospodnje okreće protiv zločinaca."},{"v":13,"t":"Pa tko da vam naudi ako revnujete za dobro?"},{"v":14,"t":"Nego, morali i trpjeti zbog svoje pravednosti, blago vama! No ne bojte se njihova zastrašivanja i ne plašite se!"},{"v":15,"t":"Naprotiv, Gospodin - Krist neka vam bude svet, u srcima vašim, te budite uvijek spremni na odgovor svakomu koji od vas zatraži obrazloženje nade koja je u vama,"},{"v":16,"t":"ali blago i s poštovanjem, dobre savjesti da oni koji ozloglašuju vaš dobar život u Kristu, upravo onim budu postiđeni za što vas potvaraju."},{"v":17,"t":"Ta uspješnije je trpjeti, ako je to Božja volja, čineći dobro, nego čineći zlo."},{"v":18,"t":"Doista, i Krist jednom za grijehe umrije, pravedan za nepravedne, da vas privede k Bogu - ubijen doduše u tijelu, ali oživljen u duhu."},{"v":19,"t":"U njemu otiđe i propovijedati duhovima u tamnici"},{"v":20,"t":"koji bijahu nekoć nepokorni, kad ih ono Božja strpljivost iščekivaše, u vrijeme Noino, dok se gradila korablja u kojoj nekolicina, to jest osam duša, bi spašena vodom."},{"v":21,"t":"Njezin protulik, krštenje - ne odlaganje tjelesne nečistoće, nego molitva za dobru savjest upravljena Bogu - i vas sada spasava po uskrsnuću Isusa Krista"},{"v":22,"t":"koji, uzašavši na nebo, jest zdesna Bogu, pošto mu bijahu pokoreni anđeli, vlasti i sile."}]},"4":{"hr":[{"v":1,"t":"Dakle, budući da je Krist trpio u tijelu, i vi se oboružajte istim mišljenjem - jer tko trpi u tijelu okanio se grijeha -"},{"v":2,"t":"da vrijeme što vam u tijelu još preostaje proživite ne više po ljudskim požudama nego po Božjoj volji."},{"v":3,"t":"Dosta je uistinu što ste u prošlom vremenu vršili volju pogana, hodeći u razvratnostima, požudama, pijančevanjima, pijankama, opijanjima i bezakoničkim idolopoklonstvima."},{"v":4,"t":"Stoga se čude što se ne slijevate u tu istu rijeku raskalašenosti te proklinju."},{"v":5,"t":"Polagat će oni račun Onomu tko je već spreman suditi žive i mrtve."},{"v":6,"t":"Zato je i mrtvima naviješteno evanđelje da osuđeni doduše po ljudsku, u tijelu, žive po Božju - u duhu."},{"v":7,"t":"Približio se svršetak svega! Osvijestite se i otrijeznite za molitvu!"},{"v":8,"t":"Prije svega imajte žarku ljubav jedni prema drugima jer ljubav pokriva mnoštvo grijeha!"},{"v":9,"t":"Gostoljubivo primajte jedni druge bez mrmljanja!"},{"v":10,"t":"Jedni druge poslužujte - svatko po primljenom daru - kao dobri upravitelji različitih Božjih milosti!"},{"v":11,"t":"Govori li tko? Neka govori kao riječi Božje! Poslužuje li tko? Neka poslužuje kao snagom koju daje Bog da se u svemu slavi Bog po Isusu Kristu, komu slava i vlast u vijeke vijekova! Amen."},{"v":12,"t":"Ljubljeni! Ne čudite se požaru što bukti među vama da vas iskuša, kao da vam se događa štogod neobično!"},{"v":13,"t":"Naprotiv, radujte se kao zajedničari Kristovih patnja da i o Objavljenju njegove slave mognete radosno klicati."},{"v":14,"t":"Pogrđuju li vas zbog imena Kristova, blago vama, jer Duh Slave, Duh Božji u vama počiva."},{"v":15,"t":"Tek neka nitko od vas ne trpi kao ubojica, ili kradljivac, ili zločinac, ili makar i kao nametljivac;"},{"v":16,"t":"ako li kao kršćanin, neka se ne stidi, nego slavi Boga zbog tog imena."},{"v":17,"t":"Ta vrijeme je da započne Sud - od doma Božjega. No ako već od vas započinje, kakav je onda svršetak onih što nisu poslušni Božjem evanđelju?"},{"v":18,"t":"I ako se pravednik jedva spasava, opak i grešnik gdje da se pojavi?"},{"v":19,"t":"Stoga oni koji po volji Božjoj trpe, neka dobrim djelima povjere duše svoje vjernom Stvoritelju."}]},"5":{"hr":[{"v":1,"t":"Starješine dakle među vama opominjem, ja sustarješina i svjedok Kristovih patnja, a zato i zajedničar slave koja se ima očitovati:"},{"v":2,"t":"pasite povjereno vam stado Božje, nadgledajte ga - ne prisilno, nego dragovoljno, po Božju; ne radi prljava dobitka, nego oduševljeno;"},{"v":3,"t":"i ne kao gospodari Baštine nego kao uzori stada."},{"v":4,"t":"Pa kad se pojavi Natpastir, primit ćete neuveli vijenac slave."},{"v":5,"t":"Tako i vi, mladići, podložite se starješinama; svi se jedni prema drugima pripašite poniznošću jer Bog se oholima protivi, a poniznima daruje milost."},{"v":6,"t":"Ponizite se dakle pod snažnom rukom Božjom da vas uzvisi u pravo vrijeme."},{"v":7,"t":"Svu svoju brigu povjerite njemu jer on se brine za vas."},{"v":8,"t":"Otrijeznite se! Bdijte! Protivnik vaš, đavao, kao ričući lav obilazi tražeći koga da proždre."},{"v":9,"t":"Oprite mu se stameni u vjeri znajući da takve iste patnje podnose vaša braća po svijetu."},{"v":10,"t":"A Bog svake milosti, koji vas pozva na vječnu slavu u Kristu, on će vas, pošto malo potrpite, usavršiti, učvrstiti, ojačati, utvrditi."},{"v":11,"t":"Njemu vlast u vijeke vjekova! Amen."},{"v":12,"t":"Pišem vam ukratko, po Silvanu, koga smatram bratom vjernim, da vas ohrabrim i posvjedočim kako je ovo istinska milost Božja. Nje se držite!"},{"v":13,"t":"Pozdravlja vas suizabranica u Babilonu i Marko, sin moj."},{"v":14,"t":"Pozdravite jedni druge cjelovom ljubavi! Mir svima vama koji ste u Kristu!"}]}},"2PE":{"1":{"hr":[{"v":1,"t":"Šimun Petar, sluga i apostol Isusa Krista, onima koje pravednošću Boga našega i Spasitelja Isusa Krista zapade ista dragocjena vjera kao i nas."},{"v":2,"t":"Punina vam milosti i mira po spoznaji Boga i Isusa, Gospodina našega!"},{"v":3,"t":"Doista, po spoznaji njega, koji nas pozva slavom svojom i krepošću, božanska nas je snaga njegova obdarila svime za život i pobožnost."},{"v":4,"t":"Time smo obdareni dragocjenim, najvećim obećanjima da po njima postanete zajedničari božanske naravi umakavši pokvarenosti koja je u svijetu zbog požude."},{"v":5,"t":"Zbog toga svim marom prionite: vjerom osigurajte krepost, krepošću spoznaje,"},{"v":6,"t":"spoznanjem uzdržljivost, uzdržljivošću postojanost, postojanošću pobožnost,"},{"v":7,"t":"pobožnošću bratoljublje, bratoljubljem ljubav."},{"v":8,"t":"Jer ako to imate i u tom napredujete, nećete biti besposleni i neplodni za spoznanje Isusa Krista."},{"v":9,"t":"A tko toga nema, slijep je, kratkovidan; zaboravio je da je očišćen od svojih prijašnjih grijeha."},{"v":10,"t":"Zato, braćo, to revnije uznastojte učvrstiti svoj poziv i izabranje: to čineći - ne, nećete posrnuti nikada!"},{"v":11,"t":"Tako će vam se bogato osigurati ulazak u vječno kraljevstvo Gospodina našega i Spasitelja Isusa Krista."},{"v":12,"t":"Zato ću vas uvijek na to podsjećati premda to znate i utvrđeni ste u primljenoj istini."},{"v":13,"t":"Pravo je, mislim, da vas dok sam u ovom šatoru, budim opomenom,"},{"v":14,"t":"svjestan da ću brzo napustiti svoj šator, kako mi i Gospodin naš Isus Krist očitova."},{"v":15,"t":"A pobrinut ću se da se i nakon mojeg izlaska uvijek toga sjećate."},{"v":16,"t":"Ta nismo vam navijestili snagu i Dolazak Gospodina našega Isusa Krista slijedeći izmudrene priče, nego kao očevici njegova veličanstva."},{"v":17,"t":"Od Oca je doista primio čast i slavu kad mu ono od uzvišene Slave doprije ovaj glas: Ovo je Sin moj, Ljubljeni moj, u njemu mi sva milina!"},{"v":18,"t":"Taj glas, koji s neba dopiraše, čusmo mi koji bijasmo s njime na Svetoj gori."},{"v":19,"t":"Tako nam je potvrđena proročka riječ te dobro činite što uza nju prianjate kao uza svjetiljku što svijetli na mrklu mjestu - dok Dan ne osvane i Danica se ne pomoli u srcima vašim."},{"v":20,"t":"Ponajprije znajte ovo: nijedno se proroštvo Pisma ne može tumačiti samovoljno"},{"v":21,"t":"jer nikada proroštvo ne bi ljudskom voljom doneseno, nego su Duhom Svetim poneseni ljudi od Boga govorili."}]},"2":{"hr":[{"v":1,"t":"Bilo je u narodu i lažnih proroka, kao što će i među vama biti lažnih učitelja, onih koji će prokrijumčariti pogubna krivovjerja, zanijekati Gospodina koji ih otkupi, i navući na se brzu propast."},{"v":2,"t":"I mnogi će se povesti za njihovim razvratnostima. Zbog njih će se kuditi put istine."},{"v":3,"t":"U svojoj će vas lakomosti kupovati izmišljotinama. Njihova osuda već odavna nije dokona i propast im ne drijema."},{"v":4,"t":"Doista, ako Bog anđela koji sagriješiše nije poštedio nego ih je sunovratio u Tartar i predao mračnom bezdanu da budu čuvani za sud;"},{"v":5,"t":"ako staroga svijeta ne poštedje, nego sačuva - osmoga - Nou, glasnika pravednosti, sručivši potop na svijet bezbožni;"},{"v":6,"t":"ako gradove Sodomu i Gomoru u pepeo pretvori, osudi i za primjer budućim bezbožnicima postavi;"},{"v":7,"t":"ako pravednog Lota, premorena razvratnim življenjem onih razularenika, oslobodi -"},{"v":8,"t":"pravedniku se doista dan za danom duša razdirala dok je gledao i slušao bezakonička djela onih među kojima je boravio -"},{"v":9,"t":"umije Gospod i pobožnike iz napasti izbaviti, a nepravednike za kaznu na Dan sudnji sačuvati,"},{"v":10,"t":"ponajpače one koji u prljavoj požudi idu za puti i preziru Veličanstvo. Preuzetnici, drznici i ne trepnu pogrđujući Slave,"},{"v":11,"t":"dok anđeli, iako jakošću i snagom od njih veći, ne izriču protiv njih pred Gospodinom pogrdna suda."},{"v":12,"t":"Oni pak kao nerazumne životinje, po naravi rođene za lov i istrebljenje, pogrđuju što ne poznaju. Istim će istrebljenjem i oni biti istrebljeni;"},{"v":13,"t":"zadesit će ih nepravda, plaća nepravednosti. Užitkom smatraju razvratnost u pol bijela dana. Ljage i sramote! Naslađuju se prijevarama svojim dok se s vama goste."},{"v":14,"t":"Oči su im pune preljubnice, nikako da se nasite grijeha; mame duše nepostojane, srce im je uvježbano u lakomstvu, prokleti sinovi!"},{"v":15,"t":"Zabludiše, napustivši ravan put, te pođoše putom Bosorova sina Bileama, koji prigrli plaću nepravednosti,"},{"v":16,"t":"ali primi i ukor za svoje nedjelo: nijemo živinče ljudskim glasom prozbori i spriječi prorokovo bezumlje."},{"v":17,"t":"Oni su izvori bezvodni, oblaci vjetrom gonjeni; za njih se čuva mrkla tmina."},{"v":18,"t":"Naklapajući naduvene ispraznosti, požudama putenim, razvratnostima mame one što netom odbjegoše od onih koji žive u zabludi."},{"v":19,"t":"Obećavaju im slobodu, a sami su robovi pokvarenosti. Jer svatko robuje onomu tko ga svlada."},{"v":20,"t":"Doista, pošto su po spoznaji Gospodina našega i Spasitelja Isusa Krista odbjegli od prljavština svijeta, ako se opet u njih upleću i daju se svladati, ovo im je potonje gore od onoga prvoga."},{"v":21,"t":"Bilo bi im doista bolje da nisu spoznali puta pravednosti, negoli, pošto ga spoznaše, okrenuti leđa svetoj zapovijedi koja im je predana."},{"v":22,"t":"Dogodilo im se što veli istinita izreka: “Pas se vraća svojoj bljuvotini i okupana svinja valjanju u blatu.”"}]},"3":{"hr":[{"v":1,"t":"Ljubljeni, pišem evo već drugu poslanicu. U objema opomenom budim vaš zdrav razbor"},{"v":2,"t":"da se sjetite riječi što ih prorekoše sveti proroci i zapovijedi apostola vaših, zapovijedi Gospodinove i Spasiteljeve."},{"v":3,"t":"Znajte ponajprije ovo: u posljednje će se dane pojaviti podrugljivi izrugivači; povoditi će se za svojim požudama"},{"v":4,"t":"i pitati: “Što je s obećanjem njegova Dolaska? Jer i otkad Oci pomriješe, sve ostaje kao što bijaše od početka stvorenja.”"},{"v":5,"t":"Ta oni naumice zaboravljaju da nebesa bijahu odavna i da zemlja na Božju riječ posta iz vode i po vodi."},{"v":6,"t":"Na isti način ondašnji svijet propade vodom potopljen."},{"v":7,"t":"A sadašnja nebesa i zemlja istom su riječju pohranjena za oganj i čuvaju se za Dan suda i propasti bezbožnih ljudi."},{"v":8,"t":"Jedno, ljubljeni, ne smetnite s uma: jedan je dan kod Gospodina kao tisuću godina, a tisuću godina kao jedan dan."},{"v":9,"t":"Ne kasni Gospodin ispuniti obećanje, kako ga neki sporim smatraju, nego je strpljiv prema vama jer neće da tko propadne, nego hoće da svi prispiju k obraćenju."},{"v":10,"t":"Kao tat će doći Dan Gospodnji u koji će nebesa trijeskom uminuti, počela se, užarena, raspasti, a zemlja i djela na njoj razotkriti."},{"v":11,"t":"Kad se sve tako ima raspasti, kako li treba da se svi vi ističete u svetu življenju i pobožnosti"},{"v":12,"t":"iščekujući i pospješujući dolazak Dana Božjega u koji će se nebesa, zapaljena, raspasti i počela, užarena, rastaliti."},{"v":13,"t":"Ta po obećanju njegovu iščekujemo nova nebesa i zemlju novu, gdje pravednost prebiva."},{"v":14,"t":"Zato, ljubljeni, dok to iščekujete, uznastojte da mu budete neokaljani i besprijekorni, u miru."},{"v":15,"t":"A strpljivost Gospodina našega spasenjem smatrajte, kako vam i ljubljeni brat naš Pavao napisa po mudrosti koja mu je dana."},{"v":16,"t":"Tako u svim poslanicama gdje o tome govori. U njima ima ponešto nerazumljivo, što neupućeni i nepostojani iskrivljuju, kao i ostala Pisma - sebi na propast."},{"v":17,"t":"Vi dakle, ljubljeni pošto ste upozoreni, čuvajte se da ne biste, zavedeni bludnjom razularenika, otpali od svoje postojanosti."},{"v":18,"t":"A rastite u milosti i spoznanju Gospodina našega i Spasitelja Isusa Krista! Njemu slava i sada i do u dan vječnosti! Amen!"}]}},"1JN":{"1":{"hr":[{"v":1,"t":"Što bijaše od početka, što smo čuli, što smo vidjeli očima svojim, što razmotrismo i ruke naše opipaše o Riječi, Životu -"},{"v":2,"t":"da, Život se očitova, i vidjeli smo i svjedočimo, i navješćujemo vam Život vječni, koji bijaše kod Oca i očitova se nama -"},{"v":3,"t":"što smo vidjeli i čuli, navješćujemo i vama da i vi imate zajedništvo s nama. A naše je zajedništvo s Ocem i sa Sinom njegovim Isusom Kristom."},{"v":4,"t":"I to vam pišemo da radost naša bude potpuna."},{"v":5,"t":"A ovo je navještaj koji smo čuli od njega i navješćujemo vama: Bog je svjetlost i tame u njemu nema nikakve!"},{"v":6,"t":"Reknemo li da imamo zajedništvo s njim, a u tami hodimo, lažemo i ne činimo istine."},{"v":7,"t":"Ako u svjetlosti hodimo, kao što je on u svjetlosti, imamo zajedništvo jedni s drugima i krv Isusa, Sina njegova, čisti nas od svakoga grijeha."},{"v":8,"t":"Reknemo li da grijeha nemamo, sami sebe varamo i istine nema u nama."},{"v":9,"t":"Ako priznamo grijehe svoje, vjeran je on i pravedan: otpustit će nam grijehe i očistiti nas od svake nepravde."},{"v":10,"t":"Reknemo li da nismo zgriješili, pravimo ga lašcem i riječi njegove nema u nama."}]},"2":{"hr":[{"v":1,"t":"Dječice moja, ovo vam pišem da ne griješite. Ako tko i sagriješi, zagovornika imamo kod Oca - Isusa Krista, Pravednika."},{"v":2,"t":"On je pomirnica za grijeha naše, i ne samo naše, nego i svega svijeta."},{"v":3,"t":"I po ovom znamo da ga poznajemo: ako zapovijedi njegove čuvamo."},{"v":4,"t":"Tko veli: “Poznajem ga”, a zapovijedi njegovih ne čuva, lažac je, u njemu nema istine."},{"v":5,"t":"A tko čuva riječ njegovu, u njemu je zaista savršena ljubav Božja. Po tom znamo da smo u njemu."},{"v":6,"t":"Tko veli da u njemu ostaje, valja mu ići putom kojim je on hodio."},{"v":7,"t":"Ljubljeni, pišem vam ne novu zapovijed, nego staru zapovijed, koju ste imali od početka. Ta stara zapovijed jest riječ koju ste čuli."},{"v":8,"t":"A opet, novu vam zapovijed pišem - obistinjuje se u njemu i vama - jer tama prolazi, svjetlost istinita već svijetli."},{"v":9,"t":"Tko veli da je u svjetlosti, a mrzi brata svojega, u tami je sve do sada."},{"v":10,"t":"Tko ljubi brata svojega, u svjetlosti ostaje i sablazni u njemu nema."},{"v":11,"t":"A tko mrzi brata svojega, u tami je, u tami hodi i ne zna kamo ide jer mu tama zaslijepi oči."},{"v":12,"t":"Pišem vama, dječice, jer su vam grijesi oprošteni po njegovu imenu."},{"v":13,"t":"Pišem vama, oci, jer upoznaste onoga koji je od početka. Pišem vama, mladići, jer ste pobijedili Zloga."},{"v":14,"t":"Napisah vama, djeco, jer upoznaste Oca. Napisah vama, oci, jer upoznaste onoga koji je od početka. Napisah vama, mladići, jer ste jaki i riječ Božja u vama ostaje i pobijedili ste Zloga."},{"v":15,"t":"Ne ljubite svijeta ni što je u svijetu. Ako tko ljubi svijet, nema u njemu ljubavi Očeve."},{"v":16,"t":"Jer što je god svjetovno - požuda tijela, i požuda očiju, i oholost života - nije od Oca, nego od svijeta."},{"v":17,"t":"Svijet prolazi i požuda njegova, a tko čini volju Božju, ostaje dovijeka."},{"v":18,"t":"Djeco, posljednji je čas! I, kako ste čuli, dolazi Antikrist. I sad su se već mnogi antikristi pojavili. Odatle znamo da je posljednji čas."},{"v":19,"t":"Od nas iziđoše, ali ne bijahu od nas. Jer kad bi bili od nas, ostali bi s nama; ali neka se očituje da nisu od nas."},{"v":20,"t":"A vi imate Pomazanje od Svetoga, i znanje svi imate."},{"v":21,"t":"Ne pisah vam zato što ne biste znali istine, nego jer je znate i jer znate da nikakva laž nije od istine."},{"v":22,"t":"Tko je lažac, ako ne onaj koji tvrdi da Isus nije Krist? Antikrist je onaj"},{"v":23,"t":"tko niječe Oca i Sina. Svaki koji niječe Sina, nema ni Oca, a tko priznaje Sina, ima i Oca."},{"v":24,"t":"A vi - što čuste od početka, u vama nek ostane. Ako u vama ostane što čuste od početka, i vi ćete ostati u Sinu i Ocu."},{"v":25,"t":"A ovo je obećanje koje nam on obeća: život vječni."},{"v":26,"t":"Ovo vam napisah o onima koji vas zavode."},{"v":27,"t":"A vi - Pomazanje koje primiste od njega u vama ostaje i ne treba da vas itko poučava. Nego njegovo vas Pomazanje uči o svemu, a istinito je i nije laž, pa kao što vas je ono naučilo, ostanite u Njemu."},{"v":28,"t":"I sada, dječice, ostanite u njemu da budemo puni pouzdanja kad se pojavi te se ne postidimo pred njim o njegovu dolasku."},{"v":29,"t":"Ako znate da je on Pravednik, znate i da je svaki koji čini pravdu od njega rođen."}]},"3":{"hr":[{"v":1,"t":"Gledajte koliku nam je ljubav darovao Otac: djeca se Božja zovemo, i jesmo. A svijet nas ne poznaje zato što ne poznaje njega."},{"v":2,"t":"Ljubljeni, sad smo djeca Božja i još se ne očitova što ćemo biti. Znamo: kad se očituje, bit ćemo njemu slični, jer vidjet ćemo ga kao što jest."},{"v":3,"t":"I tko god ima tu nadu u njemu, čisti se kao što je on čist."},{"v":4,"t":"Tko god čini grijeh, čini i bezakonje; ta grijeh je bezakonje."},{"v":5,"t":"I znate: on se pojavi da odnese grijehe i grijeha nema u njemu."},{"v":6,"t":"Tko god u njemu ostaje, ne griješi. Tko god griješi, nije ga vidio nit upoznao."},{"v":7,"t":"Dječice, nitko neka vas ne zavede! Tko čini pravdu, pravedan je kao što je On pravedan."},{"v":8,"t":"Tko čini grijeh, od đavla je jer đavao griješi od početka. Zato se pojavi Sin Božji: da razori djela đavolska."},{"v":9,"t":"Tko god je rođen od Boga, ne čini grijeha jer njegovo sjeme ostaje u njemu; ne može griješiti jer je rođen od Boga."},{"v":10,"t":"Po ovom se raspoznaju djeca Božja i djeca đavolska: tko god ne čini pravde i tko ne ljubi brata, nije od Boga."},{"v":11,"t":"Jer ovo je navještaj koji čuste od početka: da ljubimo jedni druge."},{"v":12,"t":"Ne kao Kajin, koji bijaše od Zloga i ubi brata svog. A zašto ga ubi? Jer mu djela bijahu zla, a bratova pravedna."},{"v":13,"t":"Ne čudite se, braćo ako vas svijet mrzi."},{"v":14,"t":"Mi znamo da smo iz smrti prešli u život jer ljubimo braću; tko ne ljubi, ostaje u smrti."},{"v":15,"t":"Tko god mrzi brata svoga, ubojica je. A znate da nijedan ubojica nema u sebi trajnoga, vječnoga života."},{"v":16,"t":"Po ovom smo upoznali Ljubav: on je za nas položio život svoj. I mi smo dužni živote položiti za braću."},{"v":17,"t":"Tko ima dobra ovoga svijeta i vidi brata svoga u potrebi pa zatvori pred njim srce - kako ljubav Božja ostaje u njemu?"},{"v":18,"t":"Dječice, ne ljubimo riječju i jezikom, već djelom i istinom."},{"v":19,"t":"Po tom ćemo znati da smo od istine. I umirit ćemo pred njim srce svoje"},{"v":20,"t":"ako nas ono bilo u čem osuđuje. Jer Bog je veći od našega srca i znade sve."},{"v":21,"t":"Ljubljeni, ako nas srce ne osuđuje, možemo zaufano k Bogu."},{"v":22,"t":"I što god ištemo, primamo od njega jer zapovijedi njegove čuvamo i činimo što je njemu drago."},{"v":23,"t":"I ovo je zapovijed njegova: da vjerujemo u ime Sina njegova Isusa Krista i da ljubimo jedni druge kao što nam je dao zapovijed."},{"v":24,"t":"I tko čuva zapovijedi njegove, u njemu ostaje, i On u njemu. I po ovom znamo da on ostaje u nama: po Duhu kojeg nam je dao."}]},"4":{"hr":[{"v":1,"t":"Ljubljeni, ne vjerujte svakom duhu, nego provjeravajte duhove jesu li od Boga, jer su mnogi lažni proroci izišli u svijet."},{"v":2,"t":"Po ovom prepoznajete Duha Božjega: svaki duh koji ispovijeda da je Isus Krist došao u tijelu, od Boga je."},{"v":3,"t":"A nijedan duh koji ne ispovijeda takva Isusa, nije od Boga: on je Antikristov, a za nj ste čuli da dolazi i sad je već na svijetu."},{"v":4,"t":"Vi ste, dječice, od Boga i pobijedili ste ih jer je moćniji Onaj koji je u vama nego onaj koji je u svijetu."},{"v":5,"t":"Oni su od svijeta, zato iz svijeta govore i svijet ih sluša."},{"v":6,"t":"Mi smo od Boga. Tko poznaje Boga, nas sluša, a tko nije od Boga, ne sluša nas. Po tom prepoznajemo Duha istine i duha zablude."},{"v":7,"t":"Ljubljeni, ljubimo jedni druge jer ljubav je od Boga; i svaki koji ljubi, od Boga je rođen i poznaje Boga."},{"v":8,"t":"Tko ne ljubi, ne upozna Boga jer Bog je ljubav."},{"v":9,"t":"U ovom se očitova ljubav Božja u nama: Bog Sina svoga jedinorođenoga posla u svijet da živimo po njemu."},{"v":10,"t":"U ovom je ljubav: ne da smo mi ljubili Boga, nego - on je ljubio nas i poslao Sina svoga kao pomirnicu za grijehe naše."},{"v":11,"t":"Ljubljeni, ako je Bog tako ljubio nas, i mi smo dužni ljubiti jedni druge."},{"v":12,"t":"Boga nitko nikada ne vidje. Ako ljubimo jedni druge, Bog ostaje u nama, i ljubav je njegova u nama savršena."},{"v":13,"t":"Po ovom znamo da ostajemo u njemu i on u nama: od Duha nam je svoga dao."},{"v":14,"t":"I mi smo vidjeli i svjedočimo da je Otac poslao Sina kao Spasitelja svijeta."},{"v":15,"t":"Tko ispovijeda da je Isus Sin Božji, Bog ostaje u njemu, i on u Bogu."},{"v":16,"t":"I mi smo upoznali ljubav koju Bog ima prema nama i povjerovali joj. Bog je ljubav i tko ostaje u ljubavi, u Bogu ostaje, i Bog u njemu."},{"v":17,"t":"U ovom je savršenstvo naše uzajamne ljubavi: imamo pouzdanje na Sudnji dan jer kakav je on, takvi smo i mi u ovom svijetu."},{"v":18,"t":"Straha u ljubavi nema, nego savršena ljubav izgoni strah; jer strah je muka i tko se boji, nije savršen u ljubavi."},{"v":19,"t":"Mi ljubimo jer on nas prije uzljubi."},{"v":20,"t":"Rekne li tko: “Ljubim Boga”, a mrzi brata svog, lažac je. Jer tko ne ljubi svoga brata kojega vidi, Boga kojega ne vidi ne može ljubiti."},{"v":21,"t":"I ovu zapovijed imamo od njega: Tko ljubi Boga, da ljubi i brata svoga."}]},"5":{"hr":[{"v":1,"t":"Tko god vjeruje: “Isus je Krist”, od Boga je rođen. I tko god ljubi roditelja, ljubi i rođenoga."},{"v":2,"t":"Po ovom znamo da ljubimo djecu Božju: kad Boga ljubimo i zapovijedi njegove vršimo."},{"v":3,"t":"Jer ljubav je Božja ovo: zapovijedi njegove čuvati. A zapovijedi njegove nisu teške."},{"v":4,"t":"Jer sve što je od Boga rođeno, pobjeđuje svijet. I ovo je pobjeda što pobijedi svijet: vjera naša."},{"v":5,"t":"Ta tko to pobjeđuje svijet ako ne onaj tko vjeruje da je Isus Sin Božji?"},{"v":6,"t":"On, Isus Krist, dođe kroz vodu i krv. Ne samo u vodi nego - u vodi i krvi. I Duh je koji svjedoči jer Duh je istina."},{"v":7,"t":"Jer troje je što svjedoči:"},{"v":8,"t":"Duh, voda i krv; i to je troje jedno."},{"v":9,"t":"Ako primamo svjedočanstvo ljudi, svjedočanstvo je Božje veće. Jer ovo je svjedočanstvo Božje, kojim je svjedočio za Sina svoga:"},{"v":10,"t":"Tko vjeruje u Sina Božjega, ima to svjedočanstvo Božje u sebi. Tko ne vjeruje Bogu, učinio ga je lašcem jer nije vjerovao u svjedočanstvo kojim je svjedočio Bog za Sina svoga."},{"v":11,"t":"I ovo je svjedočanstvo: Bog nam je dao život vječni; i taj je život u Sinu njegovu."},{"v":12,"t":"Tko ima Sina, ima život; tko nema Sina Božjega, nema života."},{"v":13,"t":"To napisah vama koji vjerujete u ime Sina Božjega da znate da imate život vječni."},{"v":14,"t":"I ovo je pouzdanje koje imamo u njega: ako što ištemo po volji njegovoj, uslišava nas."},{"v":15,"t":"I znamo li da nas uslišava u svemu što ištemo, znamo da već imamo što smo od njega iskali."},{"v":16,"t":"Vidi li tko brata svojega gdje čini grijeh koji nije na smrt, neka ište i dat će mu život - onima koji čine grijeh što nije na smrt. Ima grijeh što je na smrt; za nj ne velim da moli."},{"v":17,"t":"Svaka je nepravda grijeh. A postoji grijeh koji nije na smrt."},{"v":18,"t":"Znamo: tko god je rođen od Boga, ne griješi; nego Rođeni od Boga čuva ga i Zli ga se ne dotiče."},{"v":19,"t":"Znamo: od Boga smo, a sav je svijet pod Zlim."},{"v":20,"t":"Znamo: Sin je Božji došao i dao nam razum da poznamo Istinitoga. I mi smo u Istinitom, u Sinu njegovu, Isusu Kristu. On je Bog istiniti i Život vječni."},{"v":21,"t":"Dječice, klonite se idola!"}]}},"2JN":{"1":{"hr":[{"v":1,"t":"Starješina izabranoj Gospođi i djeci njezinoj koju ja ljubim u Istini - a ne samo ja nego i svi koji upoznaše Istinu -"},{"v":2,"t":"radi Istine koja ostaje u nama i bit će s nama dovijeka."},{"v":3,"t":"Bila s nama milost, milosrđe i mir od Boga Oca i od Sina Očeva Isusa Krista u istini i ljubavi!"},{"v":4,"t":"Obradovah se veoma što sam među tvojom djecom našao takve koji hode u istini, kao što primismo zapovijed od Oca."},{"v":5,"t":"I sada te molim, Gospođo, ne kao da ti novu zapovijed pišem, nego onu koju smo imali od početka: da ljubimo jedni druge."},{"v":6,"t":"A ovo je ta ljubav: da živimo po zapovijedima njegovim. To je zapovijed, kao što čuste od početka, da u njoj živite."},{"v":7,"t":"Jer iziđoše na svijet mnogi zavodnici koji ne ispovijedaju Isusa Krista koji dolazi u tijelu. To je zavodnik i Antikrist."},{"v":8,"t":"Čuvajte se da ne izgubite što ste stekli, nego da primite potpunu plaću."},{"v":9,"t":"Tko god pretjera i ne ostane u nauku Kristovu, nema Boga. Tko ostaje u nauku, ima i Oca i Sina."},{"v":10,"t":"Ako tko dolazi k vama i ne donosi tog nauka, ne primajte ga u kuću i ne pozdravljajte ga."},{"v":11,"t":"Jer tko ga pozdravlja, sudjeluje u njegovim zlim djelima."},{"v":12,"t":"Mnogo bih vam imao pisati, ali ne htjedoh na papiru i crnilom, nego se nadam da ću doći k vama i iz usta u usta govoriti da radost vaša bude potpuna."},{"v":13,"t":"Pozdravljaju te djeca tvoje izabrane sestre."}]}},"3JN":{"1":{"hr":[{"v":1,"t":"Starješina ljubljenom Gaju koga ljubim u Istini."},{"v":2,"t":"Ljubljeni! Želim ti u svemu dobro i da budeš zdrav, kao što je dobro tvojoj duši."},{"v":3,"t":"Veoma se obradovah kada dođoše braća i posvjedočiše za tvoju istinu: kako ti živiš po Istini."},{"v":4,"t":"Čuti da moja djeca po Istini žive! - nema mi veće radosti od toga."},{"v":5,"t":"Ljubljeni, pravi si vjernik u svemu što činiš za braću, i to za došljake."},{"v":6,"t":"Oni posvjedočiše tvoju ljubav pred Crkvom i dobro ćeš učiniti ako ih ispratiš Boga dostojno."},{"v":7,"t":"Jer poradi Imena iziđoše i ne primaju ništa od pogana."},{"v":8,"t":"Mi smo dakle dužni takve primati da budemo suradnici Istine."},{"v":9,"t":"Pisao sam nešto Crkvi: ali Diotref, koji hoće da bude prvi među njima, ne prima nas."},{"v":10,"t":"Zato ako dođem, spočitnut ću mu djela koja čini naklapajući zlobne riječi o nama. Ni to mu nije dosta, nego ne prima braće, a onima koji bi to htjeli, brani i izgoni ih iz Crkve."},{"v":11,"t":"Ljubljeni! Ne nasljeduj zlo, nego dobro. Tko dobro čini, od Boga je; tko zlo čini, nije vidio Boga."},{"v":12,"t":"Za Demetrija svjedoče svi, i sama Istina, a i mi svjedočimo. A znaš da je naše svjedočanstvo istinito."},{"v":13,"t":"Mnogo bih ti imao pisati, ali neću da ti pišem crnilom i perom."},{"v":14,"t":"Nadam se da ću te uskoro vidjeti pa ćemo iz usta u usta govoriti."},{"v":15,"t":"Mir tebi! Pozdravljaju te prijatelji. Pozdravi prijatelje poimence."}]}},"JUD":{"1":{"hr":[{"v":1,"t":"Juda, sluga Isusa Krista, brat Jakovljev: ljubljenima u Bogu, Ocu, čuvanima za Isusa Krista - pozvanima."},{"v":2,"t":"Obilovali milošću, mirom i ljubavlju!"},{"v":3,"t":"Ljubljeni! Dok sam u svojoj brižljivosti kanio pisati vam o našem zajedničkom spasenju, osjetio sam potrebu da vas pismom potaknem da vojujete za vjeru koja je jednom zauvijek predana svetima."},{"v":4,"t":"Jer ušuljali se neki, odavna već zapisani za ovaj sud, bezbožnici koji milost Boga našega promeću u razuzdanost i niječu jedinoga gospodara i Gospodina našega Isusa Krista."},{"v":5,"t":"Želim vas podsjetiti, premda jednom zauvijek sve znate, kako je Gospodin izbavio narod iz Egipta, a zatim uništio nevjerne."},{"v":6,"t":"I anđele, koji nisu čuvali svojeg dostojanstva nego su ostavili svoje prebivalište, sačuvao je za sud velikoga Dana, okovane u mraku vječnim okovima;"},{"v":7,"t":"kao Sodoma i Gomora i okolni gradovi, koji su se poput njih podali bludu i otišli za drugom pÓuti, stoje za primjer, ispaštajući kaznu u vječnom ognju."},{"v":8,"t":"Uza sve to i ovi sanjari jednako skvrne tijelo, zabacuju Veličanstvo, pogrđuju Slave."},{"v":9,"t":"Kad se Mihael arkanđeo s đavlom prepirao za tijelo Mojsijevo, nije se usudio izreći pogrdan sud protiv njega, nego reče: “Spriječio te Gospodin!”"},{"v":10,"t":"A ovi pogrđuju ono što ne poznaju; a što po naravi kao nerazumne životinje poznaju, u tom trunu."},{"v":11,"t":"Jao njima! Putom Kajinovim pođoše, i zabludi se Bileamovoj za plaću podaše, i propadoše od pobune Korahove."},{"v":12,"t":"Oni su ljage na vašim agapama, bezobzirno se s vama gosteći i napasajući se; oblaci bezvodni što ih vjetrovi raznose, stabla besplodna u kasnoj jeseni, dvaput usahla, iskorijenjena,"},{"v":13,"t":"bijesno morsko valovlje što ispjenjuje svoje sramote, zvijezde lutalice kojima je spremljena crna tmina dovijeka."},{"v":14,"t":"O njima prorokova sedmi od Adama, Henok: “Gle, dođe Gospodin sa Desttisućama svojim"},{"v":15,"t":"suditi svima i pokarati sve bezbožnike za sva njihova bezbožna djela kojima bezbožno sagriješiše i za sve drzovite riječi koje grešni bezbožnici izrekoše protiv njega.”"},{"v":16,"t":"To su rogoborni nezadovoljnici koji hode putom svojih požuda, usta im zbore naduto, ulaguju se u lice radi dobitka."},{"v":17,"t":"A vi, ljubljeni, sjetite se riječi što ih prorekoše apostoli Gospodina našega Isusa Krista."},{"v":18,"t":"Oni vam govorahu: “U posljednje će vrijeme biti podrugljivaca koji će se povoditi za bezbožnim požudama svojim.”"},{"v":19,"t":"To su sijači razdora, sjetilnici koji nemaju Duha."},{"v":20,"t":"A vi, ljubljeni, naziđujte se na presvetoj vjeri svojoj moleći se u Duhu Svetom,"},{"v":21,"t":"uščuvajte se u ljubavi Božjoj, iščekujući milosrđe Gospodina našega Isusa Krista za vječni život."},{"v":22,"t":"I jedne, svadljivce, karajte,"},{"v":23,"t":"druge spasavajte otimajući ih ognju, trećima se pak smilujte sa strahom, mrzeći i haljinu puti okaljanu."},{"v":24,"t":"Onomu koji vas može očuvati od pada i besprijekorne postaviti pred svoju Slavu u klicanju -"},{"v":25,"t":"jedinomu Bogu, Spasitelju našemu, po Isusu Kristu, Gospodinu našemu: slava, veličanstvo, vlast i moć i prije svakoga vijeka, i sada, i u sve vijeke. Amen."}]}},"REV":{"1":{"hr":[{"v":1,"t":"Otkrivenje Isusa Krista: njemu ga dade Bog da on pokaže slugama svojim ono što se ima dogoditi ubrzo. I on to označi poslavši svog anđela sluzi svomu Ivanu"},{"v":2,"t":"koji posvjedoči za riječ Božju i za svjedočanstvo Isusa Krista - za sve što vidje."},{"v":3,"t":"Blago onomu koji čita i onima što slušaju riječi ovog proroštva te čuvaju što je u njem napisano. Jer vrijeme je blizu!"},{"v":4,"t":"Ivan sedmerim crkvama u Aziji. Milost vam i mir od Onoga koji jest i koji bijaše i koji dolazi i od sedam duhova što su pred Prijestoljem njegovim"},{"v":5,"t":"i od Isusa Krista, Svjedoka vjernoga, Prvorođenca od mrtvih, Vladara nad kraljevima zemaljskim. Njemu koji nas ljubi, koji nas krvlju svojom otkupi od naših grijeha"},{"v":6,"t":"te nas učini kraljevstvom, svećenicima Bogu i Ocu svojemu: Njemu slava i vlast u vijeke vjekova! Amen!"},{"v":7,"t":"Gle, dolazi s oblacima i gledat će ga svako oko, svi koji su ga proboli, i naricat će nad njim sva plemena zemaljska. Da! Amen."},{"v":8,"t":"Ja sam Alfa i Omega, govori Gospodin Bog - Onaj koji jest i koji bijaše i koji dolazi, Svevladar."},{"v":9,"t":"Ja, Ivan, brat vaš i suzajedničar u nevolji, kraljevstvu i postojanosti, u Isusu: bijah na otoku zvanu Patmos radi riječi Božje i svjedočanstva Isusova."},{"v":10,"t":"Zanijeh se u duhu u dan Gospodnji i začuh iza sebe jak glas, kao glas trublje."},{"v":11,"t":"Govoraše: “Što vidiš, napiši u knjigu i pošalji sedmerim crkvama: U Efez, Smirnu, Pergam, Tijatiru, Sard, Filadelfiju, Laodiceju.”"},{"v":12,"t":"Okrenuh se da vidim glas koji govoraše sa mnom. I okrenuvši se, vidjeh sedam zlatnih svijećnjaka,"},{"v":13,"t":"a posred svijećnjaka netko kao Sin Čovječji, odjeven u dugu haljinu, oko prsiju opasan zlatnim pojasom;"},{"v":14,"t":"glava mu i vlasi bijele poput bijele vune, poput snijega, a oči mu kao plamen ognjeni;"},{"v":15,"t":"noge mu nalik mjedi uglađenoj, kao u peći užarenoj, a glas mu kao šum voda mnogih;"},{"v":16,"t":"u desnici mu sedam zvijezda, iz usta mu izlazi mač dvosječan, oštar, a lice mu kao kad sunce sjaji u svoj svojoj snazi."},{"v":17,"t":"Kad ga vidjeh, padoh mu k nogama kao mrtav. A on stavi na me desnicu govoreći: “Ne boj se! Ja sam Prvi i Posljednji,"},{"v":18,"t":"i Živi! Mrtav bijah, a evo živim u vijeke vjekova te imam ključe Smrti, i Podzemlja."},{"v":19,"t":"Napiši dakle što si vidio: ono što jest i što se ima dogoditi poslije."},{"v":20,"t":"Glede tajne onih sedam zvijezda koje vidje u mojoj desnici i sedam zlatnih svijećnjaka: sedam zvijezda anđeli su sedam crkava, sedam svijećnjaka sedam je crkava.”"}]},"2":{"hr":[{"v":1,"t":"Anđelu Crkve u Efezu napiši: “Ovo govori Onaj koji drži sedam zvijezda u desnici, Onaj koji stupa posred sedam zlatnih svijećnjaka:"},{"v":2,"t":"Znam tvoja djela, tvoj trud i postojanost tvoju i da ne možeš podnijeti opakih. Iskušao si one koji se prave apostolima, a nisu, i otkrio si da su lažljivci."},{"v":3,"t":"Postojan si, podnio si za ime moje i nisi smalaksao."},{"v":4,"t":"Ali imam protiv tebe: prvu si ljubav svoju ostavio."},{"v":5,"t":"Spomeni se dakle odakle si pao, obrati se i čini prva djela. Inače dolazim k tebi i - uklonit ću tvoj svijećnjak s mjesta njegova ako se ne obratiš."},{"v":6,"t":"Ali ovo imaš: mrziš nikolaitska djela koja i ja mrzim.”"},{"v":7,"t":"“Tko ima uho, nek posluša što Duh govori crkvama! Pobjedniku ću dati jesti od stabla života koje je u raju Božjem.”"},{"v":8,"t":"I anđelu Crkve u Smirni napiši: “Ovo govori Prvi i Posljednji, Onaj koji bijaše mrtav i oživje:"},{"v":9,"t":"Znam tvoju nevolju i siromaštvo - ali ti si bogat! - i pogrde od onih koji se nazivaju Židovima, a nisu, nego su sinagoga Sotonina."},{"v":10,"t":"Ne boj se onoga što ti je trpjeti! Evo, Sotona, će neke od vas baciti u tamnicu da budete iskušani. Bit ćete u nevolji deset dana. Budi vjeran do smrti i dat ću ti vijenac života.”"},{"v":11,"t":"“Tko ima uho, nek posluša što Duh govori crkvama! Pobjedniku neće nauditi druga smrt.”"},{"v":12,"t":"I anđelu Crkve u Pergamu napiši: “Ovo govori Onaj u koga je mač dvosjek, oštar:"},{"v":13,"t":"Znam gdje prebivaš - ondje gdje je Sotonino prijestolje - a čvrsto se držiš moga imena te nisi zanijekao moje vjere ni u one dane kad je Antipa, moj svjedok, vjerni moj, ubijen kod vas - gdje Sotona prebiva."},{"v":14,"t":"Ali imam nešto malo protiv tebe: imaš ondje nekih što drže nauk Bileama što pouči Balaka da stupicu stavi sinovima Izraelovim te blaguju od mesa žrtvovana idolima i bludu se podadu."},{"v":15,"t":"Tako i ti imaš takvih koji drže nauk nikolaitski."},{"v":16,"t":"Obrati se dakle! Inače dolazim ubrzo k tebi da ratujem s njima mačem usta svojih.”"},{"v":17,"t":"“Tko ima uho, nek posluša što Duh govori crkvama! Pobjedniku ću dati mane sakrivene i bijel ću mu kamen dati, a na kamenu napisano ime novo koje nitko ne zna doli onaj koji ga prima.”"},{"v":18,"t":"I anđelu Crkve u Tijatiri napiši: “Ovo govori Sin Božji, Onaj u koga su oči kao plamen ognjeni, a noge mu nalik na mjed uglađenu:"},{"v":19,"t":"Znam tvoja djela: tvoju ljubav, i vjeru, i služenje, i postojanost - i tvoja posljednja djela obilatija od prvašnjih."},{"v":20,"t":"Ali imam protiv tebe: puštaš ženu Jezabelu, koja se pravi proročicom, da uči i zavodi moje sluge te se bludu podaju i blaguju od mesa žrtvovana idolima."},{"v":21,"t":"Dadoh joj vremena za obraćenje, ali ona neće da se obrati od bludnosti svoje."},{"v":22,"t":"Evo, bacam je na postelju, a bludne drugare njene u veliku nevolju ako se ne odvrate od njezinih djela;"},{"v":23,"t":"i djecu ću joj smrću pobiti. I znat će sve crkve: Ja sam Onaj koji istražuje bubrege i srca - i dat ću vam svakomu po djelima."},{"v":24,"t":"Vama pak velim - vama drugim u Tijatiri koji ne drže ovog nauka te ne upoznaše takozvanih dubina sotonskih: Ne stavljam na vas drugoga bremena"},{"v":25,"t":"nego - što imate, čvrsto držite dok ne dođem.”"},{"v":26,"t":"“Pobjedniku, onomu što do kraja bude vršio moja djela, dat ću vlast nad narodima"},{"v":27,"t":"i vladat će njima palicom gvozdenom, kao posuđe glineno satirati ih -"},{"v":28,"t":"kao što i ja to primih od Oca svoga. I dat ću mu zvijezdu Danicu."},{"v":29,"t":"Tko ima uho, nek posluša što Duh govori crkvama!”"}]},"3":{"hr":[{"v":1,"t":"I anđelu Crkve u Sardu napiši: “Ovo govori Onaj koji ima sedam duhova Božjih i sedam zvijezda: Znam tvoja djela: imaš ime da živiš, a mrtav si."},{"v":2,"t":"Budan budi i utvrdi ostatak koji tek što ne umre. Doista, ne nađoh da su ti djela pred Bogom mojim savršena."},{"v":3,"t":"Spomeni se dakle: kako si primio Riječ i poslušao, tako je i čuvaj - i obrati se. Ne budeš li dakle budan, doći ću kao tat, a nećeš znati u koji ću čas doći na te."},{"v":4,"t":"Ali imaš u Sardu nekolicinu imena što ne okaljaše svojih haljina; oni će hoditi sa mnom u bjelini jer su dostojni.”"},{"v":5,"t":"“Tako će pobjednik biti odjeven u bijele haljine i neću izbrisati imena njegova iz knjige života i priznat ću ime njegovo pred Ocem svojim i anđelima njegovim.”"},{"v":6,"t":"“Tko ima uho, nek posluša što Duh govori crkvama!”"},{"v":7,"t":"I anđelu Crkve u Filadelfiji napiši: “Ovo govori Sveti, Istiniti, Onaj koji ima ključ Davidov i kad otvori, nitko neće zatvoriti; kad zatvori, nitko neće otvoriti:"},{"v":8,"t":"Znam tvoja djela. Evo, otvorio sam pred tobom vrata kojih nitko zatvoriti ne može. Doista, malena je tvoja snaga, a očuvao si moju riječ i nisi zatajio mog imena."},{"v":9,"t":"Evo, dovest ću neke iz sinagoge Sotonine - koji sebe zovu Židovi, a nisu, nego lažu - evo, prisilit ću ih da dođu da ti se do nogu poklone te upoznaju da te ja ljubim."},{"v":10,"t":"Budući da si očuvao moju riječ o postojanosti, i ja ću očuvati tebe od časa kušnje koji ima doći na sav svijet da se iskušaju svi pozemljari."},{"v":11,"t":"Dolazim ubrzo. Čvrsto drži što imaš da ti nitko ne ugrabi vijenca.”"},{"v":12,"t":"“Pobjednika ću postaviti stupom u hramu Boga moga i odande on više neće izići i napisat ću na njemu ime Boga svoga i ime grada Boga svoga, novog Jeruzalema koji siđe s neba od Boga mojega, i ime moje novo.”"},{"v":13,"t":"“Tko ima uho, nek posluša što Duh govori crkvama!”"},{"v":14,"t":"I anđelu Crkve u Laodiceji napiši: “Ovo govori Amen, Svjedok vjerni i istiniti, Početak Božjeg stvorenja:"},{"v":15,"t":"Znam tvoja djela: nisi ni studen ni vruć. O da si studen ili vruć!"},{"v":16,"t":"Ali jer si mlak, ni vruć ni studen, povratit ću te iz usta."},{"v":17,"t":"Govoriš: 'Bogat sam, obogatih se, ništa mi ne treba!' A ne znaš da si nevolja i bijeda, i ubog, i slijep, i gol."},{"v":18,"t":"Savjetujem ti: kupi od mene zlata u vatri žežena da se obogatiš i bijele haljine da se odjeneš da se ne vidi tvoja sramotna golotinja; i pomasti da oči pomažeš i vidiš."},{"v":19,"t":"Ja korim i odgajam one koje ljubim. Revan budi i obrati se!"},{"v":20,"t":"Evo, na vratima stojim i kucam; posluša li tko glas moj i otvori mi vrata, unići ću k njemu i večerati s njim i on sa mnom.”"},{"v":21,"t":"“Pobjednika ću posjesti sa sobom na prijestolje svoje, kao što i ja, pobijedivši, sjedoh s Ocem svojim na prijestolje njegovo.”"},{"v":22,"t":"“Tko ima uho, nek posluša što Duh govori crkvama!”"}]},"4":{"hr":[{"v":1,"t":"Nakon toga vidjeh: gle, vrata otvorena na nebu! A onaj prijašnji glas, što ga ono začuh kao glas trublje što govoraše sa mnom, reče: “Uziđi ovamo i pokazat ću ti što se ima dogoditi nakon ovoga!”"},{"v":2,"t":"I odmah se u duhu zanijeh kad gle: prijestolje stajaše na nebu i na prijestolje Netko sjede."},{"v":3,"t":"Taj što sjede bijaše nalik na jaspis i sard. A uokolo prijestolja duga slična smaragdu."},{"v":4,"t":"Uokolo prijestolja dvadeset i četiri prijestolja, a na prijestolja sjedoše dvadeset i četiri starješine, obučene u bijele haljine, sa zlatnim vijencima na glavi."},{"v":5,"t":"Od prijestolja izlaze munje, i glasovi, i gromovi; pred prijestoljem gori sedam ognjenih zubalja, to jest sedam duhova Božjih,"},{"v":6,"t":"a pred prijestoljem kao neko stakleno more, nalik na prozirac. U sredini prijestolja, oko prijestolja, četiri bića, sprijeda i straga puna očiju:"},{"v":7,"t":"prvo biće slično lavu, drugo biće slično juncu, treće biće s licem kao čovječjim, četvrto biće slično letećem orlu."},{"v":8,"t":"Ta su četiri bića - u svakoga po šest krila - sve naokolo i iznutra puna očiju. Bez predaha dan i noć govore: “Svet! Svet! Svet Gospodin, Bog Svevladar, Onaj koji bijaše i koji jest i koji dolazi!”"},{"v":9,"t":"I kad god bića dadu slavu i čast pohvalnicu Onomu koji sjedi na prijestolju, Živomu u vijeke vjekova,"},{"v":10,"t":"dvadeset i četiri starješine padnu ničice pred Onim koji sjedi na prijestolju i poklone se njemu - Živomu u vijeke vjekova. I stavljaju svoje vijence pred prijestolje govoreći:"},{"v":11,"t":"“Dostojan si, Gospodine, Bože naš, primiti slavu i čast i moć! Jer ti si sve stvorio, i tvojom voljom sve postade i bi stvoreno!”"}]},"5":{"hr":[{"v":1,"t":"I vidjeh: na desnici Onoga koji sjedi na prijestolju - knjiga, iznutra i izvana ispisana, zapečaćena sa sedam pečata!"},{"v":2,"t":"I vidjeh snažna anđela gdje iza glasa proglašuje: “Tko je dostojan otvoriti knjigu i otpečatiti pečate njezine?”"},{"v":3,"t":"I nitko - ni na nebu, ni na zemlji, ni pod zemljom - nije mogao otvoriti knjige i pogledati u nju."},{"v":4,"t":"Briznem u plač jer se nitko ne nađe dostojan otvoriti knjigu i pogledati u nju."},{"v":5,"t":"A jedan od starješina reče: “Ne plači! Evo, pobijedi Lav iz plemena Judina, Korijen Davidov, on će otvoriti knjigu i sedam pečata njezinih."},{"v":6,"t":"I vidjeh: posred prijestolja i četiriju bića i posred starješina stoji, kao zaklan, Jaganjac sa sedam rogova i sedam očiju, to jest sedam duhova Božjih, po svoj zemlji poslanih."},{"v":7,"t":"On pristupi te iz desnice Onoga koji sjedi na prijestolju uzme knjigu."},{"v":8,"t":"A kad on uze knjigu, četiri bića i dvadeset i četiri starješine padoše ničice pred Jaganjca. U svakoga bijahu citre i zlatne posudice pune kada, to jest molitava svetačkih."},{"v":9,"t":"Pjevaju oni pjesmu novu: “Dostojan si uzeti knjigu i otvoriti pečate njezine jer si bio zaklan i otkupio, krvlju svojom, za Boga ljude iz svakoga plemena i jezika, puka i naroda;"},{"v":10,"t":"učinio si ih Bogu našemu kraljevstvom i svećenicima i kraljevat će na zemlji.”"},{"v":11,"t":"I vidjeh, i začuh glas anđela mnogih uokolo prijestolja, i bića i starješina. Bijaše ih na mirijade mirijada i tisuće tisuća."},{"v":12,"t":"Klicahu iza glasa: “Dostojan je zaklani Jaganjac primiti moć, i bogatstvo, i mudrost, i snagu, i čast, i slavu, i blagoslov!”"},{"v":13,"t":"I začujem: sve stvorenje, i na nebu, i na zemlji, i pod zemljom, i u moru - sve na njima i u njima govori: “Onomu koji sjedi na prijestolju i Jaganjcu blagoslov i čast, i slava i vlast u vijeke vjekova!”"},{"v":14,"t":"I četiri bića ponavljahu: “Amen!” A starješine padnu ničice i poklone se."}]},"6":{"hr":[{"v":1,"t":"I vidjeh: kad Jaganjac otvori prvi od sedam pečata, začujem gdje prvo od četiri bića govori glasom kao gromovnim: “Dođi!”"},{"v":2,"t":"Pogledam, a ono konj bijelac i u njegova konjanika luk. I dan mu je vijenac te kao pobjednik pođe da pobijedi."},{"v":3,"t":"Kad Jaganjac otvori drugi pečat, začujem drugo biće gdje govori: “Dođi!”"},{"v":4,"t":"I iziđe drugi konj, riđan. I njegovu je konjaniku dano dignuti mir sa zemlje da se ljudi među sobom pokolju. I dan mu je mač velik."},{"v":5,"t":"Kad Jaganjac otvori treći pečat, začujem treće biće gdje govori: “Dođi!” Pogledam, a ono konj vranac i njegovu konjaniku u ruci tezulja."},{"v":6,"t":"Tada začujem kao neki glas isred četiriju bića gdje govori: “Mjera pšenice za denar! Tri mjere ječma za denar! A ulju i vinu ne udi!”"},{"v":7,"t":"Kad Jaganjac otvori četvrti pečat, začujem glas četvrtoga bića gdje govori: “Dođi!”"},{"v":8,"t":"Pogledam, a ono konj sivac; konjaniku njegovu ime je “Smrt” i prati ga Podzemlje. Dana im je vlast nad četvrtinom zemlje: ubijati mačem i glađu i smrću i zvijerima zemaljskim."},{"v":9,"t":"Kad Jaganjac otvori peti pečat, vidjeh pod žrtvenikom duše zaklanih zbog riječi Božje i zbog svjedočanstva što ga imahu."},{"v":10,"t":"Vikahu iza glasa: “Ta dokle, Gospodaru sveti i istiniti! Zar nećeš suditi i osvetiti krv našu na pozemljarima?”"},{"v":11,"t":"I svakome je od njih dana bijela haljina i rečeno im je neka se strpe još malo vremena dok se ne ispuni broj njihovih sudrugova u službi i braće njihove koja imaju biti pobijena kao i oni."},{"v":12,"t":"I vidjeh: kad Jaganjac otvori šesti pečat, potres velik nasta. I sunce pocrnje kao dlakava kostrijet, sav mjesec posta kao krv."},{"v":13,"t":"I zvijezde padoše s neba na zemlju kao što smokva smokvice stresa kad je potrese žestok vjetar."},{"v":14,"t":"Nebo iščeznu kao savijena knjiga, a sve se planine i otoci pokrenuše s mjesta."},{"v":15,"t":"Kraljevi zemaljski, i velikaši, i vojvode, i bogataši, i mogućnici, rob i slobodnjak - svi se sakriše u spilje i pećine gorske"},{"v":16,"t":"govoreći gorama i pećinama: “Padnite na nas i sakrijte nas od lica Onoga koji sjedi na prijestolju i od srdžbe Jaganjčeve."},{"v":17,"t":"Jer dođe Dan onaj veliki srdžbe njihove i tko će opstati!”"}]},"7":{"hr":[{"v":1,"t":"Nakon toga vidjeh: četiri anđela stoje na četiri kraja zemlje zadržavajući četiri vjetra zemaljska da nikakav vjetar ne puše ni zemljom ni morem nit ikojim drvećem."},{"v":2,"t":"I vidjeh drugoga jednog anđela gdje uzlazi od istoka sunčeva s pečatom Boga živoga. On povika iza glasa onoj četvorici anđela kojima bi dano nauditi zemlji i moru:"},{"v":3,"t":"“Ne udite ni zemlji ni moru ni drveću dok ne opečatimo sluge Boga našega na čelima!”"},{"v":4,"t":"I začujem broj opečaćenih - sto četrdeset i četiri tisuće opečaćenih iz svih plemena sinova Izraelovih:"},{"v":5,"t":"iz plemena Judina dvanaest tisuća opečaćenih, iz plemena Rubenova dvanaest tisuća, iz plemena Gadova dvanaest tisuća,"},{"v":6,"t":"iz plemena Ašerova dvanaest tisuća, iz plemena Naftalijeva dvanest tisuća, iz plemena Manašeova dvanaest tisuća,"},{"v":7,"t":"iz plemena Šimunova dvanaest tisuća, iz plemena Levijeva dvanaest tisuća, iz plemena Jisakarova dvanaest tisuća,"},{"v":8,"t":"iz plemena Zebulunova dvanaest tisuća, iz plemena Josipova dvanaest tisuća, iz plemena Benjaminova dvanaest tisuća opečaćenih."},{"v":9,"t":"Nakon toga vidjeh: eno velikoga mnoštva, što ga nitko ne mogaše izbrojiti, iz svakoga naroda, i plemena, i puka, i jezika! Stoje pred prijestoljem i pred Jaganjcem odjeveni u bijele haljine; palme im u rukama."},{"v":10,"t":"Viču iz glasa: “Spasenje Bogu našemu koji sjedi na prijestolju i Jaganjcu!”"},{"v":11,"t":"I svi anđeli, što stajahu uokolo prijestolja i starješina i četiriju bića, padoše pred prijestoljem ničice, na svoja lica,"},{"v":12,"t":"i pokloniše se Bogu govoreći: “Amen! Blagoslov i slava, i mudrost, i zahvalnica, i čast, i moć i snaga Bogu našemu u vijeke vjekova. Amen.”"},{"v":13,"t":"I jedan me od starješina upita: “Ovi odjeveni u bijele haljine, tko su i odakle dođoše?”"},{"v":14,"t":"Odgovorih mu: “Gospodine moj, ti to znaš.” A on će mi: “Oni dođoše iz nevolje velike i oprali su haljine svoje i ubijelili ih u krvi Jaganjčevoj."},{"v":15,"t":"Zato su pred prijestoljem Božjim i služe mu dan i noć u hramu njegovu, i Onaj koji sjedi na prijestolju razapet će Šator svoj nad njima."},{"v":16,"t":"Neće više gladovati ni žeđati, neće ih više paliti sunce nit ikakva žega"},{"v":17,"t":"jer - Jaganjac koji je posred prijestolja bit će pastir njihov i vodit će ih na izvore voda života. I otrt će Bog svaku suzu s očiju njihovih.”"}]},"8":{"hr":[{"v":1,"t":"Kad Jaganjac otvori sedmi pečat, nasta muk na nebu oko pola sata."},{"v":2,"t":"I vidjeh: sedmorici anđela što stoje pred Bogom dano je sedam trubalja."},{"v":3,"t":"I drugi jedan anđeo pristupi i sa zlatnom kadionicom stane na žrtvenik. I dano mu je mnogo kada da ga s molitvama svih svetih prinese na zlatni žrtvenik pred prijestoljem."},{"v":4,"t":"I vinu se dim kadni s molitvama svetih iz ruke anđelove pred lice Božje."},{"v":5,"t":"Anđeo uze kadionicu, napuni je vatrom sa žrtvenika i prosu na zemlju. I udariše gromovi, i glasovi, i munje, i potres."},{"v":6,"t":"A sedam anđela sa sedam trubalja pripremiše se da zatrube."},{"v":7,"t":"Prvi zatrubi. I nastadoše tuča i oganj, pomiješani s krvlju, i budu bačeni na zemlju. I trećina zemlje izgorje, i trećina stabala izgorje, i sva zelena trava izgorje."},{"v":8,"t":"Drugi anđeo zatrubi. I nešto kao gora velika, ognjem zapaljena, bačeno bi u more. I trećina se mora pretvori u krv"},{"v":9,"t":"te izginu trećina stvorenja što u moru žive i trećina lađa propade."},{"v":10,"t":"Treći anđeo zatrubi. I pade s neba zvijezda velika - gorjela je kao zublja - pade na trećinu rijeka i na izvore voda."},{"v":11,"t":"Zvijezdi je ime Pelin. I trećina se voda pretvori u pelin te mnoštvo ljudi poginu od zagorčenih voda."},{"v":12,"t":"Četvrti anđeo zatrubi. I bi udarena trećina sunca i trećina mjeseca i trećina zvijezda te pomrčaše za trećinu. I dan izgubi trećinu svoga sjaja, a tako i noć."},{"v":13,"t":"I vidjeh i začuh orla: letio posred neba i vikao iza glasa: “Jao! Jao! Jao pozemljarima od novih glasova trubalja preostale trojice anđela koji će sad-na zatrubiti!”"}]},"9":{"hr":[{"v":1,"t":"Peti anđeo zatrubi. I vidjeh: zvijezda je s neba na zemlju pala i dani su joj ključi zjala Bezdanova."},{"v":2,"t":"Ona otvori zjalo Bezdanovo i vinu se iz zjala dim kao dim iz peći goleme te pomrča sunce i zrak od dima iz zjala."},{"v":3,"t":"Iz dima pak iziđoše na zemlju skakavci i dana im je moć kakvu imaju štipavci zemaljski."},{"v":4,"t":"I zapovjeđeno im je da ne ude travi zemaljskoj nit ikojem zelenilu nit ikojem stablu, nego samo ljudima koji nemaju pečata Božjega na čelu."},{"v":5,"t":"I dano im je ne da ih ubijaju, nego samo da ih muče pet mjeseci, a muka njihova da bude kao muka od uboda štipavaca."},{"v":6,"t":"U one će dane ljudi iskati smrt, ali je neće naći; poželjet će umrijeti, ali smrt će bježati od njih."},{"v":7,"t":"Skakavci bijahu izgledom nalik na konje za boj spremne. Na glavama im kao neki zlatni vijenci, lica im kao u ljudi,"},{"v":8,"t":"kose kao u žena, a zubi kao u lavova."},{"v":9,"t":"Imahu oklope kao od željeza, a šum krila njihovih kao štropot bojnih kola s mnogo konja što u boj jure."},{"v":10,"t":"Repovi im kao u štipavaca, sa žalcima, a u repovima im moć da ude ljudima pet mjeseci."},{"v":11,"t":"Nad njima je kralj, anđeo Bezdana, hebrejski mu ime Abadon, grčki Apolion - Upropastitelj."},{"v":12,"t":"Prvi Jao prođe. Evo, za njim dolaze još dva druga Jao."},{"v":13,"t":"Šesti anđeo zatrubi. I začujem neki glas iz rogova zlatnoga žrtvenika pred Bogom."},{"v":14,"t":"Govoraše šestom anđelu koji je držao trublju: “Odriješi ona četiri anđela svezana na Rijeci velikoj, Eufratu.”"},{"v":15,"t":"I odriješena bijahu četiri anđela, spremna za taj čas i dan i mjesec i godinu, da pobiju trećinu ljudi."},{"v":16,"t":"A broj četa konjaničkih, kako sam čuo, bijaše dvije mirijade mirijada."},{"v":17,"t":"Ovako u viđenju vidjeh konje i njihove jahače: imahu oklope ognjene, plavetne i sumporne boje; glave im kao u lavova, iz usta im sukljao oganj, dim i sumpor."},{"v":18,"t":"Od ovih triju zala poginu trećina ljudi - od ognja, dima i sumpora što sukljahu konjima iz usta."},{"v":19,"t":"Doista, snaga je ovim konjima u ustima i repovima: repovi im kao u zmija, s glavama kojima ude."},{"v":20,"t":"Ipak, preostali ljudi, što ne poginuše od tih zala, ne obratiše se od djela ruku svojih, da se više ne klanjaju zlodusima i kumirima - ni zlatnima, ni srebrnima, ni mjedenima, ni kamenima ni drvenima koji niti vide niti čuju nit hodaju -"},{"v":21,"t":"i ne obratiše se od svojih ubojstava ni od svojih čaranja ni od svoga bluda niti od svojih krađa."}]},"10":{"hr":[{"v":1,"t":"I vidjeh drugoga jednog, snažnog anđela: silazio s neba ogrnut oblakom, na glavi mu duga, lice mu kao sunce, a noge kao ognjeno stupovlje;"},{"v":2,"t":"u ruci drži otvorenu knjižicu. I zakorači desnom nogom na more, lijevom na zemlju pa povika iza glasa kao kad lav riče."},{"v":3,"t":"I kad povika, oglasi se sedam gromova tutnjavom."},{"v":4,"t":"A kad se oglasi sedam gromova, htjedoh pisati, ali začujem glas s neba: “Zapečati to što prozbori sedam gromova! Toga ne piši!”"},{"v":5,"t":"I onaj anđeo što ga vidjeh gdje stoji na moru i zemlji, podiže k nebu desnicu"},{"v":6,"t":"i zakle se Živim u vijeke vjekova, koji stvori nebo i sve što je na njemu, zemlju i sve što je na njoj, more i sve što je u njemu: “Neće više biti vremena!"},{"v":7,"t":"Nego - u dane kad se oglasi sedmi anđeo, čim zatrubi, dovršit će se otajstvo Božje kao što on to navijesti slugama svojim prorocima.”"},{"v":8,"t":"I glas što ga začuh s neba opet prozbori sa mnom: “Idi, uzmi otvorenu knjigu iz ruke anđela što stoji na moru i na zemlji!”"},{"v":9,"t":"Pristupim k anđelu i zamolim ga da mi dade knjižicu. A on će mi: “Uzmi je i progutaj! Zagorčit će ti utrobu, ali će ti u ustima biti slatka kao med.”"},{"v":10,"t":"Uzeh knjižicu iz ruke anđelove i progutah je. I bijaše mi u ustima kao med slatka, ali kad je progutah, zagorči mi utrobu."},{"v":11,"t":"I rečeno mi je: “Treba da ponovno prorokuješ proti pucima i narodima i kraljevima mnogim!”"}]},"11":{"hr":[{"v":1,"t":"I dana mi je trska slična palici i rečeno mi je: “Ustani i izmjeri hram Božji i žrtvenik i poklonike u njemu!"},{"v":2,"t":"Vanjsko dvorište hrama mimoiđi, ne mjeri ga jer je dano poganima: gazit će svetim gradom četrdeset i dva mjeseca."},{"v":3,"t":"I ja ću poslati dva svoja svjedoka da, obučeni u kostrijet, prorokuju tisuću dvjesta i šezdeset dana."},{"v":4,"t":"Oni su dvije masline i dva svijećnjaka što stoje pred Gospodarom zemlje."},{"v":5,"t":"Ako im tko hoće nauditi, oganj suče iz usta njihovih i proždire njihove neprijatelje. Doista, htjedne li im tko nauditi, tako treba da pogine."},{"v":6,"t":"Oni imaju vlast zaključati nebo da ne pada kiša dok prorokuju; imaju vlast pretvoriti vode u krv i udariti zemlju kojim god zlom kad god htjednu."},{"v":7,"t":"A kada dovrše svoje svjedočanstvo, Zvijer koja izlazi iz Bezdana zaratit će s njima, pobijediti ih i ubiti."},{"v":8,"t":"I njihova će trupla ležati na trgu grada velikoga koji se duhovno zove Sodoma i Egipat, gdje je i Gospodin njihov raspet."},{"v":9,"t":"Ljudi iz svih puka i plemena i jezika i naroda gledat će njihova trupla tri i pol dana i neće dopustiti da im se trupla u grob polože."},{"v":10,"t":"Pozemljari će se radovati i veseliti zbog njihove nesreće i darivati jedan drugoga jer su ta dva proroka zadavala muku pozemljarima."},{"v":11,"t":"Ali nakon tri i pol dana duh životni od Boga uđe u njih i stadoše na noge te strah velik obuze one koji ih promatrahu."},{"v":12,"t":"I začuše glas s neba silan: “Uziđite ovamo!” I uziđoše na oblaku u nebo na očigled svojih neprijatelja."},{"v":13,"t":"U taj čas nasta velik potres: pade desetina grada, a u potresu poginu sedam tisuća ljudi. Preživjele spopade strah te proslaviše Boga nebeskoga."},{"v":14,"t":"Drugi Jao prođe. Evo, treći Jao dolazi ubrzo!"},{"v":15,"t":"I sedmi anđeo zatrubi. I na nebu odjeknuše silni glasovi: “Uspostavljeno je nad svijetom kraljevstvo Gospodara našega i Pomazanika njegova i kraljevat će u vijeke vjekova!”"},{"v":16,"t":"Tada dvadeset i četiri starješine, što pred Bogom sjedoše na prijestolja,"},{"v":17,"t":"padoše ničice i pokloniše se Bogu govoreći. “Zahvaljujemo ti, Gospodaru, Bože, Svevladaru, koji jesi i koji bijaše, zato što uze u ruke moć svoju veliku i zakralji se!"},{"v":18,"t":"Gnjevili se narodi, ali dođe srdžba tvoja i čas da se sudi mrtvima i naplata dade slugama tvojim prorocima i svetima i svima koji se boje imena tvojega, malima i velikima; i da se unište oni koji kvare zemlju.”"},{"v":19,"t":"I otvori se hram Božji na nebu i pokaza se Kovčeg saveza njegova u hramu njegovu te udare munje i glasovi i gromovi i potres i tuča velika."}]},"12":{"hr":[{"v":1,"t":"I znamenje veliko pokaza se na nebu: Žena odjevena suncem, mjesec joj pod nogama, a na glavi vijenac od dvanaest zvijezda."},{"v":2,"t":"Trudna viče u porođajnim bolima i mukama rađanja."},{"v":3,"t":"I pokaza se drugo znamenje na nebu: gle, Zmaj velik, ognjen, sa sedam glava i deset rogova; na glavama mu sedam kruna,"},{"v":4,"t":"a rep mu povlači trećinu zvijezda nebeskih - i obori ih na zemlju. Zmaj stade pred Ženu koja imaše roditi da joj, čim rodi, proždre Dijete."},{"v":5,"t":"I ona porodi sina, muškića, koji će vladati svim narodima palicom gvozdenom. I Dijete njeno bi uzeto k Bogu i prijestolju njegovu."},{"v":6,"t":"A Žena pobježe u pustinju gdje joj Bog pripravi sklonište da se ondje hrani tisuću dvjesta i šezdeset dana."},{"v":7,"t":"I nasta rat na nebu: Mihael i njegovi anđeli zarate se sa Zmajem. Zmaj uđe u rat i anđeli njegovi,"},{"v":8,"t":"ali ne nadvlada. I ne bijaše im više mjesta na nebu."},{"v":9,"t":"Zbačen je Zmaj veliki, Stara zmija - imenom Ðavao, Sotona, zavodnik svega svijeta. Bačen je na zemlju, a s njime su bačeni i anđeli njegovi."},{"v":10,"t":"I začujem glas na nebu silan: “Sada nasta spasenje i snaga i kraljevstvo Boga našega i vlast Pomazanika njegova! Jer zbačen je tužitelj braće naše koji ih je dan i noć optuživao pred Bogom našim."},{"v":11,"t":"Ali oni ga pobijediše krvlju Jaganjčevom i riječju svojega svjedočanstva: nisu ljubili života svoga - sve do smrti."},{"v":12,"t":"Zato veselite se, nebesa i svi nebesnici! A jao vama, zemljo i more, jer Ðavao siđe k vama, gnjevan veoma, znajući da ima malo vremena!”"},{"v":13,"t":"Kad Zmaj vidje da je zbačen na zemlju, stade progoniti Ženu koja rodi muškića."},{"v":14,"t":"No Ženi bijahu dana dva velika krila orlujska da odleti u pustinju, u svoje sklonište gdje se, sklonjena od Zmije, hrani jedno vrijeme i dva vremena i polovicu vremena."},{"v":15,"t":"I Zmija iz usta pusti za Ženom vodu poput rijeke da je rijeka odnese."},{"v":16,"t":"Ali zemlja priteče u pomoć Ženi: otvori usta i popi rijeku što je Zmaj pusti iz usta."},{"v":17,"t":"I razgnjevi se Zmaj na Ženu pa ode i zarati se s ostatkom njezina potomstva, s onima što čuvaju Božje zapovijedi i drže svjedočanstvo Isusovo."},{"v":18,"t":"I stade na morski žal."}]},"13":{"hr":[{"v":1,"t":"I vidjeh: iz mora Zvijer izlazi sa deset rogova i sedam glava; na rogovima joj deset kruna, na glavama bogohulna imena."},{"v":2,"t":"Ta Zvijer što je vidjeh bijaše nalik na leoparda, noge joj kao medvjeđe, usta kao usta lavlja. Zmaj joj dade svoju silu i prijestolje i vlast veliku."},{"v":3,"t":"Jedna joj glava bijaše kao na smrt zaklana, ali joj se smrtna rana zaliječila. Sva se zemlja, začuđena, zanijela za Zvijeri"},{"v":4,"t":"i svi se pokloniše Zmaju koji dade takvu vlast Zvijeri. Pokloniše se i Zvijeri govoreći: “Tko je kao Zvijer! Tko bi smio ratovati s njom?”"},{"v":5,"t":"I dana su joj usta da govori drskosti i hule i dana joj je vlast da to čini četrdeset i dva mjeseca."},{"v":6,"t":"I ona otvori usta da huli Boga, da huli ime njegovo, njegov Šator i nebesnike."},{"v":7,"t":"I dano joj je da se zarati sa svecima i da ih pobijedi. Dana joj je vlast nad svakim plemenom i pukom i jezikom i narodom:"},{"v":8,"t":"da joj se poklone svi pozemljari, oni kojima ime nije zapisano u knjizi života zaklanog Jaganjca, od postanka svijeta."},{"v":9,"t":"Tko ima uho, nek posluša!"},{"v":10,"t":"Je li tko za progonstvo, u progonstvo će ići! Je li tko za mač, da bude pogubljen, mačem će biti pogubljen! U tom je postojanost i vjera svetih."},{"v":11,"t":"I vidjeh: druga jedna Zvijer uzlazi iz zemlje, ima dva roga poput jaganjca, a govori kao Zmaj."},{"v":12,"t":"Vrši svu vlast one prve Zvijeri, u njenoj nazočnosti. Prisiljava zemlju i sve pozemljare da se poklone prvoj Zvijeri kojoj ono zacijeli smrtna rana."},{"v":13,"t":"Čini znamenja velika: i oganj spušta s neba na zemlju naočigled ljudi."},{"v":14,"t":"Tako zavodi pozemljare znamenjima koja joj je dano činiti u nazočnosti Zvijeri: svjetuje pozemljarima da načine kip Zvijeri koja bijaše udarena mačem, ali preživje."},{"v":15,"t":"I dano joj je udahnuti život kipu Zvijeri te kip Zvijeri progovori i poubija sve koji se god ne klanjaju kipu Zvijeri."},{"v":16,"t":"Ona postiže da se svima - malima i velikima, bogatima i ubogima, slobodnjacima i robovima - udari žig na desnicu ili na čelo,"},{"v":17,"t":"i da nitko ne mogne kupovati ili prodavati osim onog koji nosi žig s imenom Zvijeri ili s brojem imena njezina."},{"v":18,"t":"U ovome je mudrost: u koga je uma, nek odgoneta broj Zvijeri. Broj je to jednog čovjeka, a broj mu je šest stotina šezdeset i šest."}]},"14":{"hr":[{"v":1,"t":"I vidjeh: gle, Jaganjac stoji na gori Sionu, a s njime sto četrdeset i četiri tisuće - na čelima im napisano ime njegovo i ime Oca njegova!"},{"v":2,"t":"I začujem s neba glas, kao šum voda mnogih i tutnjavu silna groma; glas taj koji začuh bijaše kao glas citraša što sviraju na citrama."},{"v":3,"t":"Pjevali su pjesmu novu pred prijestoljem i pred četiri bića i pred starješinama. Nitko ne mogaše naučiti te pjesme doli one sto četrdeset i četiri tisuće - otkupljeni sa zemlje."},{"v":4,"t":"Ti se ne okaljaše sa ženama, djevci su! Oni prate Jaganjca kamo god pođe. Otkupljeni su od ljudi kao prvine Bogu i Jaganjcu;"},{"v":5,"t":"na ustima se njihovim laž ne nađe, neporočni su."},{"v":6,"t":"I vidjeh: drugi jedan anđeo leti posred neba s evanđeljem vječnim da ga proglasi svim pozemljarima, svakom narodu i plemenu i jeziku i puku."},{"v":7,"t":"Viče iza glasa: “Bojte se Boga i dajte mu slavu jer dođe čas suda njegova! I poklonite se njemu koji stvori nebo i zemlju i more i izvore voda!”"},{"v":8,"t":"Za njim eto drugog anđela koji govori: “Pade, pade Babilon, veliki koji vinom gnjeva i bluda svojega opi sve narode!”"},{"v":9,"t":"Za njima eto i trećeg anđela koji vikaše iza glasa: “Tko god se klanja Zvijeri i kipu njezinu te primi žig na čelo ili ruku,"},{"v":10,"t":"pit će vino gnjeva Božjega, nerazvodnjeno, natočeno već u čaši srdžbe njegove! I bit će udaren na muke u ognju i sumporu svetim anđelima naočigled i naočigled Jaganjcu."},{"v":11,"t":"Dim muke njihove suklja u vijeke vjekova. Ni danju ni noću nemaju počinka oni koji se klanjaju Zvijeri i kipu njezinu i tko god primi žig s imenom njezinim.”"},{"v":12,"t":"U tom je postojanost svetih - onih što čuvaju zapovijedi Božje i vjeru Isusovu."},{"v":13,"t":"I začujem glas s neba: “Piši! Od sada blaženi mrtvi koji umiru u Gospodinu! Da, govori Duh, neka otpočinu od svojih trudova! Jer prate ih djela njihova!”"},{"v":14,"t":"I vidjeh: gle, bijel oblak, a na oblak sjede Netko kao Sin Čovječji; na glavi mu zlatan vijenac, u ruci oštar srp."},{"v":15,"t":"I drugi jedan anđeo iziđe iz hrama vičući iza glasa onomu što sjedi na oblaku: “Mahni srpom i žanji jer dođe čas žetvi, zrela je žetva zemaljska!”"},{"v":16,"t":"I onaj što sjedi na oblaku baci srp na zemlju i zemlja bi požnjevena."},{"v":17,"t":"I drugi jedan anđeo iziđe iz hrama nebeskoga. I on imaše oštar srp."},{"v":18,"t":"I od žrtvenika iziđe drugi anđeo - onaj koji ima vlast nad ognjem - pa povika iza glasa onomu, s oštrim srpom: “Mahni oštrim srpom i poberi grozdove u vinogradu zemaljskom jer sazri grožđe!”"},{"v":19,"t":"I anđeo baci srp na zemlju i obra vinograd zemaljski, a obrano baci u veliku kacu gnjeva Božjega."},{"v":20,"t":"Gazila se kaca izvan grada te poteče krv iz kace konjima do uzda, tisuću i šest stotina stadija uokolo."}]},"15":{"hr":[{"v":1,"t":"I vidjeh drugo znamenje na nebu, veliko i čudesno: sedam anđela sa sedam zala posljednjih - s njima se navršuje gnjev Božji."},{"v":2,"t":"I vidjeh kao neko more od prozirca pomiješano s ognjem. Oni koji pobijediše Zvijer i kip njezin i broj imena njezina stoje u moru od prozirca s citrama Božjim u ruci."},{"v":3,"t":"Pjevaju pjesmu Mojsija, sluge Božjega, i pjesmu Jaganjčevu: “Velika su i čudesna djela tvoja, Gospodine, Bože, Svevladaru! Pravedni su i istiniti putovi tvoji, Kralju naroda!"},{"v":4,"t":"Tko da te se ne boji, Gospodine, tko da ne slavi ime tvoje! Ti si jedini svet! I zato svi će narodi doći i klanjati se pred tobom jer se očitovahu pravedna djela tvoja!”"},{"v":5,"t":"Nakon toga vidjeh: otvori se hram Šatora svjedočanstva na nebu!"},{"v":6,"t":"Iziđe sedam anđela sa sedam zala iz hrama; odjeveni bijahu u blistav bijeli lan, oko prsiju opasani zlatnim pojasom."},{"v":7,"t":"Jedno od četiri bića dade sedmorici anđela sedam zlatnih čaša, punih gnjeva Boga koji živi u vijeke vjekova."},{"v":8,"t":"I hram se napuni dimom od Slave Božje i od njegove snage te nitko ne mogaše ući u hram dok se ne navrši sedam zala sedmorice anđela."}]},"16":{"hr":[{"v":1,"t":"I začujem iz hrama jak glas koji viknu sedmorici anđela: “Hajdete, izlijte sedam čaša gnjeva Božjega na zemlju!”"},{"v":2,"t":"Ode prvi i izli svoju čašu na zemlju. I pojavi se čir, koban i bolan, na ljudima što nose žig Zvijerin i klanjaju se kipu njezinu."},{"v":3,"t":"Drugi izli svoju čašu na more. I ono posta krv kao krv mrtvačeva te izginu sve živo u moru."},{"v":4,"t":"Treći izli svoju čašu na rijeke i izvore voda. I postadoše krv."},{"v":5,"t":"I začujem anđela voda gdje govori: “Pravedan si, Ti koji jesi i koji bijaše, Sveti, što si tako dosudio!"},{"v":6,"t":"Oni su prolili krv svetih i proroka i stoga ih krvlju napajaš! Zavrijedili su!”"},{"v":7,"t":"I začujem žrtvenik kako govori: “Da, Gospode, Bože, Svevladaru! Istiniti su i pravedni sudovi tvoji!”"},{"v":8,"t":"Četvrti izli svoju čašu na sunce. I suncu je dano da pali ljude ognjem."},{"v":9,"t":"I silna je žega palila ljude te su hulili ime Boga koji ima vlast nad tim zlima, ali se ne obratiše da mu slavu dadu."},{"v":10,"t":"Peti izli svoju čašu na prijestolje Zvijeri. I kraljevstvo joj prekriše tmine. Ljudi su grizli jezike od muke"},{"v":11,"t":"i hulili Boga nebeskoga zbog muka i čireva, ali se ne obratiše od djela svojih."},{"v":12,"t":"Šesti izli svoju čašu na Eufrat, rijeku veliku. I presahnu voda te načini prolaz kraljima s istoka sunčeva."},{"v":13,"t":"I vidjeh: iz usta Zmajevih i iz usta Zvijerinih i iz usta Lažnoga proroka izlaze tri duha nečista, kao žabe."},{"v":14,"t":"To su dusi zloduha što čine znamenja, a pođoše sabrati kraljeve svega svijeta na rat za Dan veliki Boga Svevladara."},{"v":15,"t":"Evo dolazim kao tat! Blažen onaj koji bdije i čuva haljine svoje da ne ide gol te mu se ne vidi sramota!"},{"v":16,"t":"I skupiše ih na mjesto koje se hebrejski zove Harmagedon."},{"v":17,"t":"I sedmi izli svoju čašu na zrak. Uto iz hrama, s prijestolja, iziđe jak glas i viknu: “Svršeno je!”"},{"v":18,"t":"I udariše munje i glasovi i gromovi i nasta potres velik, kakva ne bijaše otkako je ljudi - tako bijaše silan potres taj."},{"v":19,"t":"I prasnu natroje grad veliki i gradovi naroda padoše. Spomenu se Bog Babilona velikoga da mu dade piti iz čaše vina gnjevne srdžbe Božje."},{"v":20,"t":"I pobjegoše svi otoci, iščezoše gore,"},{"v":21,"t":"a iz neba se spusti na ljude tuča velika, poput talenta. Ljudi su hulili Boga zbog zla tuče jer zlo njezino bijaše silno veliko."}]},"17":{"hr":[{"v":1,"t":"I dođe jedan od sedam anđela što nose sedam čaša i prozbori mi: “Dođi pokazat ću ti sud nad Bludnicom velikom što sjedi nad vodama velikim,"},{"v":2,"t":"s kojom su bludničili kraljevi zemlje i pozemljari se opiše vinom bluda njezina.”"},{"v":3,"t":"I odnese me u duhu u pustinju. Tu vidjeh Ženu koja sjede na skrletnu Zvijer, punu bogohulnih imena, sa sedam glava i deset rogova."},{"v":4,"t":"Žena bijaše odjevena u grimiz i skrlet, sva u zlatu, dragom kamenju i biserju. U ruci joj zlatna čaša puna gnusobe i nečisti bluda njezina."},{"v":5,"t":"Na čelo joj napisano ime - tajna: “Babilon veliki, mati bludnica i gnusoba zemljinih.”"},{"v":6,"t":"I vidjeh: Žena je pijana od krvi svetih i od krvi svjedoka Isusovih. Kad je vidjeh, čudom se silnim začudih."},{"v":7,"t":"Nato će mi anđeo: “Što se čudiš? Ja ću ti kazati tajnu te žene i Zvijeri koja je nosi, Zvijeri sa sedam glava i deset rogova.”"},{"v":8,"t":"“Zvijer koju vidje bijaše i više nije; zamalo izlazi iz Bezdana i ide u propast. I zapanjit će se pozemljari - oni kojima ime, od postanka svijeta, nije zapisano u knjigu života - kad vide da Zvijer bijaše i više nije, a opet je tu."},{"v":9,"t":"Tu se hoće mudre pameti! Sedam glava sedam je bregova na kojima žena sjedi. A i sedam kraljeva:"},{"v":10,"t":"pet ih već pade, jedan jest, a jedan još ne dođe: kada dođe, ostati mu je zamalo."},{"v":11,"t":"I Zvijer koja bijaše i više nije, osma je, a iz broja je njih sedmero, i ide u propast."},{"v":12,"t":"Deset rogova što ih vidje deset je kraljeva; oni još ne primiše kraljevstva, ali će - samo za jedan sat - primiti vlast kao kraljevi zajedno sa Zvijeri."},{"v":13,"t":"Jedne su misli: svu svoju silu i vlast predati Zvijeri."},{"v":14,"t":"Ratovat će protiv Jaganjca, ali će ih pobijediti Jaganjac - i njegovi pozvanici, izabranici, vjernici - jer on je Gospodar gospodara i Kralj kraljeva.”"},{"v":15,"t":"I reče mi anđeo: “Vode što ih vidje, na kojima Bludnica sjedi, to su puci i mnoštva i narodi i jezici."},{"v":16,"t":"I onih deset rogova što ih vidje i Zvijer - oni će zamrziti Bludnicu, opustošiti je i ogoliti, najesti se mesa njezina i ognjem je spaliti."},{"v":17,"t":"Jer Bog im u srce stavi izvršiti naum njegov: da jednodušno predadu kraljevstvo svoje Zvijeri dok se ne ispune riječi Božje."},{"v":18,"t":"Žena koju vidje grad je veliki što kraljuje nad kraljevima zemaljskim.”"}]},"18":{"hr":[{"v":1,"t":"Nakon toga vidjeh: jedan drugi anđeo silazi s neba s moći velikom! Sva se zemlja zasvijetlila od njegova sjaja."},{"v":2,"t":"On povika iza glasa: “Pade, pade Babilon veliki - Bludnica - i postade prebivalištem zloduha, nastambom svih duhova nečistih, nastambom svih ptica nečistih mrskih"},{"v":3,"t":"jer se gnjevnim vinom bluda njezina opiše narodi; s njom su bludničili svi kraljevi zemaljski, a trgovci se zemaljski obogatiše od silna raskošja njezina.”"},{"v":4,"t":"Začujem i drugi glas s neba: “Iziđite iz nje, narode moj, da vas ne zadese zla njezina te ne budete suzajedničari grijeha njezinih!"},{"v":5,"t":"Jer njezini grijesi do neba dopriješe i spomenu se Bog zločina njezinih."},{"v":6,"t":"Vratite joj milo za drago, naplatite joj dvostruko po djelima! U čašu u koju je ona natakala natočite dvostruko!"},{"v":7,"t":"Koliko se razmetala sjajem i raskoši, toliko joj zadajte muka i jada! Jer u srcu je svome govorila: 'Na prijestolju sjedim kao kraljica i nikad neću obudovjeti, jad me nikada zadesiti neće!'"},{"v":8,"t":"Stoga u isti će je dan zla zadesiti: smrt i jad i glad te će sva u ognju biti spaljena. Jer silan je Gospod, Bog, Sudac njezin!”"},{"v":9,"t":"I plakat će i naricati za njom kraljevi zemlje što su s njome bludničili i raskošno živjeli kad gledali budu dim požara njezina."},{"v":10,"t":"Prestrašeni mukama njezinim, izadaleka će stajati i naricati: “Jao, jao, grade veliki, Babilone, grade silni! Kako li te u tren oka stiže osuda!”"},{"v":11,"t":"I trgovci zemaljski plaču nad njom i tuguju jer im trga nitko više ne kupuje:"},{"v":12,"t":"ni zlata, ni srebra, ni dragoga kamenja, ni biserja, ni tanana lana, ni grimiza, ni svile, ni skrleta: nit ikakva mirisava drveta, nit ikakva predmeta od slonove kosti, nit ikakva predmeta od skupocjena drveta, nit od mjedi, nit od željeza, nit od mramora;"},{"v":13,"t":"ni cimeta, ni balzama, ni miomirisa, ni pomasti, ni tamjana, ni vina, ni ulja, ni bijeloga brašna, ni pšenice; ni goveda, ni ovaca, ni konja, ni kočija, ni roblja nit ikoje žive duše."},{"v":14,"t":"“Voće za kojim ti duša žudjela pobježe od tebe, sav raskoš i sjaj propade ti - ne, nema ga više!”"},{"v":15,"t":"Trgovci što svim tim trgovahu, što ih ona obogati, izdaleka će stajati, prestrašeni mukama njezinim, plakat će i tugovati:"},{"v":16,"t":"“Jao, jao, grade veliki, odjeveni nekoć u lan tanan i grimiz i skrlet, nakićeni zlatom i dragim kamenjem i biserjem!"},{"v":17,"t":"U tren oka opustje toliko bogatstvo!” I svi kormilari i putnici, svi mornari i moreplovci izdaleka stoje"},{"v":18,"t":"i, gledajući dim njezina požara, zapomažu: “Koji li je grad sličan gradu ovom velikom?”"},{"v":19,"t":"I posuše glavu pepelom te plačući i tugujući viknuše: “Jao, jao, grada li velikoga! Dragocjenostima se njegovim obogatiše svi posjednici morskih brodova, a evo - u tren oka opustje!”"},{"v":20,"t":"Veseli se nad njom, nebo, i svi sveti i apostoli i proroci jer Bog osudivši nju, vama pravo dosudi!"},{"v":21,"t":"I jedan snažan anđeo uze kamen, velik poput mlinskoga kamena, i baci ga u more govoreći: “Tako će silovito biti strovaljen Babilon, grad veliki, i nikada ga više biti neće!”"},{"v":22,"t":"“Glas citraša i pjevača i svirača i trubljača u tebi se više neće čuti! Obrtnik vješt kojem god umijeću u tebi se više neće naći! Klopot žrvnja u tebi se više neće čuti!"},{"v":23,"t":"Svjetlost svjetiljke u tebi više neće sjati! Glas zaručnika i zaručnice u tebi se više neće čuti! Jer trgovci tvoji bijahu velikaši zemlje i čaranja tvoja zavedoše sve narode;"},{"v":24,"t":"i u tebi se našla krv proroka i svetaca i svih zaklanih na zemlji.”"}]},"19":{"hr":[{"v":1,"t":"Nakon toga začujem kao jak glas silnoga mnoštva na nebu: “Aleluja! Spasenje i slava i moć Bogu našemu!"},{"v":2,"t":"Doista, istiniti su i pravedni sudovi njegovi jer osudi veliku Bludnicu, što pokvari zemlju bludom svojim, i osveti na njoj krv slugu svojih!”"},{"v":3,"t":"I ponove: “Aleluja! Dim njezin suklja u vijeke vjekova!”"},{"v":4,"t":"Nato starješine, njih dvadesetčetvorica, i ona četiri bića padoše ničice i p okloniše se Bogu, koji sjedi na prijestolju, govoreći: “Amen! Aleluja!”"},{"v":5,"t":"I s prijestolja iziđe glas: “Hvalite Boga našega, sve sluge njegove, svi koji se njega bojite, i mali i veliki!”"},{"v":6,"t":"I začuh kao glas silna mnoštva i kao šum voda mnogih i kao prasak gromova silnih: “Aleluja! Zakraljeva Gospod, Bog naš Svevladar!"},{"v":7,"t":"Radujmo se i kličimo i slavu mu dajmo jer dođe svadba Jaganjčeva, opremila se Zaručnica njegova!"},{"v":8,"t":"Dano joj je odjenuti se u lan tanan, blistav i čist!” A lan - pravedna su djela svetih."},{"v":9,"t":"I reče mi: “Piši! Blago onima koji su pozvani na svadbenu gozbu Jaganjčevu!” I reče mi: “Ove su riječi istinite, Božje.”"},{"v":10,"t":"Padoh mu pred noge da mu se poklonim. A on će mi: “Nipošto! Sluga sam kao i ti i braća tvoja koja imaju svjedočanstvo Isusovo. Bogu se pokloni!” Jer svjedočanstvo Isusovo duh je proročki."},{"v":11,"t":"I vidjeh: nebo otvoreno - i gle, konj bijelac, a na nj sjeo On, zvani Vjerni i Istiniti, a sudi i vojuje po pravdi;"},{"v":12,"t":"oči mu plamen ognjeni, na glavi mu mnoge krune; nosi napisano ime kojeg nitko ne zna doli on sam;"},{"v":13,"t":"ogrnut je ogrtačem krvlju natopljenim; ime mu: Riječ Božja."},{"v":14,"t":"Prate ga na bijelcima Vojske nebeske, odjevene u lan tanan, bijel i čist."},{"v":15,"t":"Iz usta mu izlazi oštar mač kojim će posjeći narode. Vladat će njima palicom gvozdenom. On gazi u kaci gnjevne srdžbe Boga Svevladara."},{"v":16,"t":"Na ogrtač, o boku, napisano mu ime: “Kralj kraljeva i Gospodar gospodara.”"},{"v":17,"t":"I vidjeh jednog anđela: stajaše na suncu vičući iza glasa svim pticama što nebom lete: “Ovamo! Skupite se na veliku gozbu Božju"},{"v":18,"t":"da se najedete mesa kraljeva, i mesa vojvoda, i mesa mogućnika, i mesa konja i konjanika njihovih, i mesa svih mogućih ljudi, slobodnjaka i robova, malih i velikih!”"},{"v":19,"t":"I vidjeh: Zvijer i kraljevi zemlje i vojske njihove skupiše se u boj da se zarate s Onim što sjedi na konju i s vojskom njegovom."},{"v":20,"t":"I Zvijer bi uhvaćena, a s njom i Lažni prorok koji je u njenoj nazočnosti činio znamenja i njima zavodio one što su primili žig Zvijeri i klanjali se njezinu kipu. Živi su oboje bačeni u ognjeno jezero što gori sumporom."},{"v":21,"t":"A drugi su posječeni mačem što iziđe iz usta Onoga koji sjedi na konju i sve se ptice nasitiše mesa njihova."}]},"20":{"hr":[{"v":1,"t":"I vidjeh anđela: siđe s neba s ključima Bezdana i s velikim okovima u ruci."},{"v":2,"t":"Zgrabi Zmaja, Staru zmiju, to jest Ðavla, Sotonu, i okova ga za tisuću godina."},{"v":3,"t":"Baci ga u Bezdan koji nad njim zatvori i zapečati da više ne zavodi narode dok se ne navrši tisuću godina. Nakon toga ima biti odriješen za malo vremena."},{"v":4,"t":"I vidjeh prijestolja - onima što sjedoše na njih dano je suditi - i duše pogubljenih zbog svjedočanstva Isusova i zbog Riječi Božje i sve koji se ne pokloniše Zvijeri ni kipu njezinu te ne primiše žiga na čela svoja ni na ruke. Oni oživješe i zakraljevaše s Kristom tisuću godina."},{"v":5,"t":"Drugi mrtvi ne oživješe dok se ne navrši tisuću godina. To je ono prvo uskrsnuće."},{"v":6,"t":"Blažen i svet onaj tko je dionik toga prvog uskrsnuća! Nad njim druga smrt nema vlasti: oni će biti svećenici Božji i Kristovi i s njime će kraljevati tisuću godina."},{"v":7,"t":"A kad se navrši tisuću godina, Sotona će iz svoga zatvora biti pušten:"},{"v":8,"t":"izići će zavesti narode sa četiri kraja zemlje, Goga i Magoga, i skupiti ih u boj. Bit će ih kao pijeska morskoga."},{"v":9,"t":"Skupiše se na prostrano polje zemlje i opkoliše tabor svetih i ljubljeni grad. Ali oganj siđe s neba te ih proguta."},{"v":10,"t":"A njihov zavodnik, Ðavao, bačen bi u jezero ognjeno i sumporno, gdje se nalaze i Zvijer i Lažni prorok: ondje će se mučiti danju i noću u vijeke vjekova."},{"v":11,"t":"I vidjeh veliko bijelo prijestolje i Onoga što sjede na nj: pred licem njegovim pobježe zemlja i nebo; ni mjesta im se više ne nađe."},{"v":12,"t":"I vidjeh mrtve, velike i male: stoje pred prijestoljem, a knjige se otvoriše. I otvori se jedna druga knjiga, knjiga života. I mrtvi bijahu suđeni po onome što stoji napisano u knjigama, po djelima svojim."},{"v":13,"t":"More predade svoje mrtvace, a Smrt i Podzemlje svoje: i svaki bi suđen po djelima svojim."},{"v":14,"t":"A Smrt i Podzemlje bili su bačeni u jezero ognjeno. Jezero ognjeno - to je druga smrt:"},{"v":15,"t":"tko se god ne nađe zapisan u knjizi života, bio je bačen u jezero ognjeno."}]},"21":{"hr":[{"v":1,"t":"I vidjeh novo nebo i novu zemlju jer - prvo nebo i prva zemlja uminu; ni mora više nema."},{"v":2,"t":"I Sveti grad, novi Jeruzalem, vidjeh: silazi s neba od Boga, opremljen kao zaručnica nakićena za svoga muža."},{"v":3,"t":"I začujem jak glas s prijestolja: “Evo Šatora Božjeg s ljudima! On će prebivati s njima: oni će biti narod njegov, a on će biti Bog s njima."},{"v":4,"t":"I otrt će im svaku suzu s očiju te smrti više neće biti, ni tuge, ni jauka, ni boli više neće biti jer - prijašnje uminu.”"},{"v":5,"t":"Tada Onaj što sjedi na prijestolju reče: “Evo, sve činim novo!” I doda: “Napiši: Ove su riječi vjerne i istinite.”"},{"v":6,"t":"I još mi reče: “Svršeno je! Ja sam Alfa i Omega, Početak i Svršetak! Ja ću žednomu dati s izvora vode života zabadava."},{"v":7,"t":"To će biti baština pobjednikova. I ja ću njemu biti Bog, a on meni sin."},{"v":8,"t":"Kukavicama pak, nevjernima i okaljanima, ubojicama, bludnicima, vračarima i idolopoklonicima i svim lažljivcima udio je u jezeru što gori ognjem i sumporom. To je druga smrt.”"},{"v":9,"t":"I dođe jedan od sedam anđela što imaju sedam čaša punih zala konačnih te progovori sa mnom: “Dođi, pokazat ću ti Zaručnicu, Ženu Jaganjčevu!”"},{"v":10,"t":"I prenese me u duhu na goru veliku, visoku i pokaza mi sveti grad Jeruzalem: silazi s neba od Boga,"},{"v":11,"t":"sav u slavi Božjoj, blistav poput dragoga kamena, kamena slična kristalnom jaspisu;"},{"v":12,"t":"okružen zidinama velikim i visokim, sa dvanaest vrata: na vratima dvanaest anđela i napisana imena dvanaest plemena Izraelovih."},{"v":13,"t":"Od istoka vrata troja, od sjevera vrata troja, od juga vrata troja, od zapada vrata troja."},{"v":14,"t":"Gradske su zidine imale dvanaest temelja, a na njima dvanaest imena dvanaestorice apostola Jaganjčevih."},{"v":15,"t":"Moj subesjednik imaše mjeru, zlatnu trsku, da izmjeri grad, vrata njegova i zidine."},{"v":16,"t":"Grad se stere u četvorini: dužina mu jednaka širini. On izmjeri trskom grad: dvanaest tisuća stadija - dužina mu i širina i visina jednaka."},{"v":17,"t":"Izmjeri i njegove zidine: sto četrdeset i četiri lakta po čovjekovoj mjeri kojom je mjerio anđeo."},{"v":18,"t":"Zidine su gradske sagrađene od jaspisa, a sam grad od čistoga zlata, slična čistu staklu."},{"v":19,"t":"Temelji su gradskih zidina urešeni svakovrsnim dragim kamenjem: prvi je temelj od jaspisa, drugi od safira, treći od kalcedona, četvrti od smaragda,"},{"v":20,"t":"peti od sardoniksa, šesti od sarda, sedmi od krizolita, osmi od berila, deveti od topaza, deseti od krizopraza, jedanaesti od hijacinta, dvanaesti od ametista."},{"v":21,"t":"Dvanaest vrata - dvanaest bisera: svaka od svoga bisera. A gradski trg - čisto zlato, kao prozirno staklo."},{"v":22,"t":"Hrama u gradu ne vidjeh. Ta Gospod, Bog, Svevladar, hram je njegov - i Jaganjac!"},{"v":23,"t":"I gradu ne treba ni sunca ni mjeseca da mu svijetle. Ta Slava ga Božja obasjala i svjetiljka mu Jaganjac!"},{"v":24,"t":"Narodi će hoditi u svjetlosti njegovoj, a kraljevi zemaljski u nj donositi slavu svoju."},{"v":25,"t":"Vrata mu se ne zatvaraju obdan, a noći ondje i nema."},{"v":26,"t":"U nj će se donijeti slava i čast naroda."},{"v":27,"t":"Ali u nj neće unići ništa nečisto i nijedan tko čini gadost i laž, nego samo oni koji su zapisani u Jaganjčevoj knjizi života."}]},"22":{"hr":[{"v":1,"t":"I pokaza mi rijeku vode života, bistru kao prozirac: izvire iz prijestolja Božjeg i Jaganjčeva."},{"v":2,"t":"Posred gradskoga trga, s obje strane rijeke, stablo života što rodi dvanaest puta, svakog mjeseca svoj rod. A lišće stabla za zdravlje je narodima."},{"v":3,"t":"I neće više biti nikakva prokletstva. I prijestolje će Božje i Jaganjčevo biti u gradu i sluge će mu se njegove klanjati"},{"v":4,"t":"i gledati lice njegovo, a ime će im njegovo biti na čelima."},{"v":5,"t":"Noći više biti neće i neće trebati svjetla od svjetiljke ni svjetla sunčeva: obasjavat će ih Gospod Bog i oni će kraljevati u vijeke vjekova."},{"v":6,"t":"I reče mi: “Ove su riječi vjerne i istinite jer Gospod Bog, nadahnitelj proroka, posla svoga anđela da on pokaže slugama njegovim što se ima dogoditi ubrzo."},{"v":7,"t":"I evo, dolazim ubrzo! Blago onomu koji čuva riječi proroštva ove knjige!”"},{"v":8,"t":"Ja, Ivan, čuo sam i vidio sve ovo. I kad sam to vidio i čuo, padoh pred noge anđelu koji mi to pokaza da mu se poklonim."},{"v":9,"t":"A on će mi: “Nipošto! Sluga sam kao i ti i braća tvoja proroci i svi koji čuvaju riječi ove knjige. Bogu se pokloni!”"},{"v":10,"t":"A zatim će mi: “Ne zapečati riječi proroštva ove knjige jer - vrijeme je blizu!"},{"v":11,"t":"Nepravednik neka samo i dalje čini nepravdu! Okaljan neka se i dalje kalja! Pravednik neka i dalje živi pravedno! Svet neka se i dalje posvećuje!”"},{"v":12,"t":"“Evo, dolazim ubrzo i plaća moja sa mnom: naplatit ću svakom po njegovu djelu!”"},{"v":13,"t":"“Ja sam Alfa i Omega, Prvi i Posljednji, Početak i Svršetak!"},{"v":14,"t":"Blago onima koji peru svoje haljine: imat će pravo na stablo života i na vrata će smjeti u grad!"},{"v":15,"t":"Vani pak ostaju psi i vračari, bludnice, ubojice i idolopoklonici i tko god ljubi i čini laž.”"},{"v":16,"t":"“Ja, Isus, poslah anđela svoga posvjedočiti ovo po crkvama. Ja sam korijen i izdanak Davidov, sjajna zvijezda Danica.”"},{"v":17,"t":"I Duh i Zaručnica govore: “Dođi!” I tko ovo čuje, neka rekne: “Dođi!” Tko je žedan, neka dođe; tko hoće, neka zahvati vode života zabadava!"},{"v":18,"t":"Ja svjedočim svakomu tko sluša riječi proroštva u ovoj knjizi: Tko ovomu što doda, Bog će njemu dodati zla napisana u ovoj knjizi."},{"v":19,"t":"I tko oduzme od riječi proroštva u ovoj knjizi, Bog će mu oduzeti udio na stablu života i na svetom gradu - na svemu što je napisano u ovoj knjizi."},{"v":20,"t":"Svjedok za sve ovo govori: “Da, dolazim ubrzo!” Amen! Dođi, Gospodine Isuse!"},{"v":21,"t":"Milost Gospodina Isusa sa svima!"}]}}});
